const DISCOVERY={"2869":[{"rank":"1","note":"小さな花の地図","exp":"160","type":"植物","name":"フサフジウツギ","desc":"主に中国に生息する、枝先に房状の小さな花を咲かせる植物。\nその芳香に誘われて、チョウがよく集まってくる。"}],"1013":[{"rank":"1","note":"クエスト「民衆による十字軍」<br/>発見物カード:30","exp":"60","type":"歴史遺物","name":"隠者ピエールの杖","desc":"11世紀末、民衆十字軍の中でも最大規模の集団を率いた修道士ピエールの杖。2万人以上の民衆軍は統率が取れず、トルコ軍に敗れて瓦解した。"}],"5650":[{"rank":"5","note":"クエスト「航海に欠かせない星座」<br/>発見物カード:475","exp":"970","type":"天文","name":"らしんばん座","desc":"ラカーユが制定した南天の星座のひとつ。羅針盤をかたどっているとされる。この星座の近くにはとも座とほ座があり、それらの位置関係から船のマストにあたるともいわれる。"}],"569":[{"rank":"2","note":"後継者争い","exp":"350","type":"歴史遺物","name":"デメトリオス1世の鎧","desc":"デメトリオス1世は、アレクサンドロス大王の後継者の一人アンティゴノス1世の息子。大王亡き後、分割された領土を再統一しようとするが、捕らわれて死んだ。"}],"3736":[{"rank":"4","note":"赤い額の鳥","exp":"610","type":"鳥類","name":"ベニヒワ","desc":"寒冷地や高山地帯に生息する小型の鳥。額の辺りが赤く色づいているのが特徴。雑食で、種子や昆虫などを幅広く食べる。"}],"5311":[{"rank":"5","note":"","exp":"930","type":"小型生物","name":"パフアダー","desc":"アフリカ中南部に生息する毒ヘビ。太い体に矢筈模様があり、全長は2ｍ近くになることがある。危険を察知すると「パフ、パフ」と空気を噴いて威嚇し、それが名前の由来だという。大きい毒牙と多量の毒を持ち、非常に危険。"}],"5989":[{"rank":"3","note":"アイスランド海盆　19世紀<br/>発見物カード:235","exp":"470","type":"天文","name":"フォボス","desc":"火星の衛星。もっとも内側の軌道を公転している第一衛星である。徐々に火星に接近しており遠い未来には衝突が予想されている。"}],"590":[{"rank":"1","note":"黒い瞳の海獣","exp":"33","type":"中型生物","name":"アザラシ","desc":"世界中の広い海域に生息する動物。皮下脂肪が非常に厚いため、海水の冷たさに耐えられるようだ。魚をとるために海に潜り、素晴らしい速度で泳ぐ。陸上での活動は苦手だ。"}],"2363":[{"rank":"4","note":"尾の長いニワトリ","exp":"620","type":"鳥類","name":"オナガドリ","desc":"日本原産のニワトリの一種。突然変異で生まれたという。\n雄の尾羽の一部は、生え変わることがないため、極めて長く伸びている。"}],"5502":[{"rank":"5","note":"蒸気機関研究の始まり <br/><br/>発見時経験値1000　発見物カード経験値500","exp":"1000","type":"歴史遺物","name":"プネウマティカ","desc":"アレクサンドリアのヘロンが記した文献。古代エジプトの神殿に設置された、聖水の自動販売機の仕組みを記している。"}],"1784":[{"rank":"1","note":"「書きかけの地図」<br/>発見物カード:75<br/>　","exp":"150","type":"地理","name":"パリニャス岬","desc":"南米大陸最西端の岬。赤道に近く、また付近を流れる寒流の影響を受けて乾燥し、不毛地帯となっている。"}],"1601":[{"rank":"1","note":"足の長い虫の地図","exp":"180","type":"虫類","name":"タテヅノカブト","desc":"上下対になった長い角と、きわめて長い前足が特徴。えさ場での争いでは、この前足を振り回して相手を追い払う。"}],"4808":[{"rank":"3","note":"安土城（上層隠し部屋）","exp":"","type":"財宝","name":"法螺貝笛","desc":"東の国の戦において、進退の合図のために使用されていた楽器。大きな巻貝を加工した楽器で音を出すには訓練が必要なようだ。"}],"5727":[{"rank":"2","note":"2017.02.07新規追加","exp":"370","type":"宗教建築","name":"シャクパック・アタ","desc":"イスラム教の宣教師であるシャクパック・アタによって作られたモスク。ウスチュルト台地にはこのような岩窟モスクが複数存在するようだ。"}],"5249":[{"rank":"2","note":"雲台山西　再調査報酬","exp":"","type":"宗教遺物","name":"碧霞元君像","desc":"読みは「へきかげんくんぞう」。七天女の一人、泰山玉女とも呼ばれる女神の像である。神々の中で最も心優しい女神とされ、泰山信仰で人気がある。"}],"3749":[{"rank":"4","note":"黄道の女神","exp":"650","type":"天文","name":"おとめ座","desc":"黄道十二星座の1つ。正義の女神アストライア、春の女神ペルセポネ、豊穣の女神デメテルなど、さまざまな女神になぞらえられている。古代メソポタミアでは、麦穂とナツメヤシの葉を持つ2人の女性だといわれている。"}],"1008":[{"rank":"5","note":"魔物の骨","exp":"1118","type":"化石","name":"トカゲのような鳥の骨","desc":"頭から体にかけてはトカゲのようで、腕が鳥の翼のような動物の骨である。なぜか石のように変化している。体のまわりには羽のような模様があり、全身に羽が生えていたと思われる。こんな動物は見たことも聞いたこともない。新種だろうか？"}],"820":[{"rank":"1","note":"大理石の男性像の地図","exp":"120","type":"美術品","name":"勝利","desc":"ミケランジェロ作の大理石像。ユリウス2世の墓標のために作られた像の一つだが、未完成のまま打ち捨てられた。老人を組み敷き、体をねじらせた若者の像である。"}],"4836":[{"rank":"2","note":"変わった鳥の地図","exp":"290","type":"鳥類","name":"ワライフクロウ","desc":"忍び笑いや口笛のような変わった鳴き声が特徴の鳥。かつては特に珍しくなかったが、生息環境の変化によってか急速に数を減らしており、絶滅が心配される。"}],"1708":[{"rank":"1","note":"牛に似た動物の地図","exp":"110","type":"大型生物","name":"バンテン","desc":"体長2mほどのウシ。体色は白や茶色など様々で、オスの角は70cmほどにもなる。家畜としても飼育されている。"}],"767":[{"rank":"3","note":"赤い宝石の鉱脈の地図","exp":"580","type":"財宝","name":"ピジョンブラッド","desc":"最上級のルビー。ハトの血のような、鮮やかな紅色のものをいう。ルビーは大きな石が見つかりにくく、大粒のピジョンブラッドは大変な値打ちがある。"}],"3541":[{"rank":"","note":"ジャンヌ・アシェットの斧　入手","exp":"","type":"レリック","name":"もう一人のジャンヌ","desc":"ブルゴーニュ軍の旗を奪ってボーヴェを救った勇敢な少女は、奇しくもラ・ピュセルと同じジャンヌという名だったという。"}],"5561":[{"rank":"4","note":"妖艶な植物<br/><br/>発見時経験値620　発見物カード経験値310","exp":"620","type":"植物","name":"サイコトリア・ペッピギアーナ","desc":"中南米に群生する低木で、唇のように見える苞が特徴。見た目とは裏腹に、古くから痛み止めとしても使用されており、頭痛や捻挫に効果がある。"}],"613":[{"rank":"1","note":"「山猫の地図」<br/>発見物カード:14","exp":"28","type":"中型生物","name":"オオヤマネコ","desc":"ヤマネコとしては大型で、体に斑点があり耳の先に飾り毛がある。かなり広い範囲で観察される。"}],"4837":[{"rank":"2","note":"神の家","exp":"300","type":"史跡","name":"ハトラ","desc":"パルティア帝国の要塞都市。100を超える防御塔を有する堅固な造りで、ローマ帝国の攻撃を幾たびも防いだ。また、要塞内の都市にはイスラムの神殿とギリシャ神殿が並び立っているという特徴がある。"}],"6997":[{"rank":"5","note":"","exp":"1500","type":"歴史遺物","name":"法令の木簡","desc":"日本最古の律令「飛鳥浄御原令」に関する記述が残る木簡。飛鳥浄\n御原令は、天武天皇と持統天皇により制定された日本初の法典であ\nり、これにより刑法と民法が初めて体系的に整備された。"}],"354":[{"rank":"3","note":"英傑たる皇妃","exp":"430","type":"財宝","name":"テオドラの舞衣装","desc":"ビザンツ皇帝・ユスティニアヌス1世の妃である、テオドラの舞衣装。テオドラは庶民出身で、皇妃になる前は踊り子などをしていたそうだ。ユスティニアヌス1世は、彼女と結婚するために法律を変えた。"}],"6262":[{"rank":"5","note":"","exp":"1340","type":"伝承","name":"雪姫","desc":"夜の雪山に現れるという、若い娘の姿をした雪の化身。\n山に入った者の前に現れて生き肝を食らったり、凍死させたりするなどの言い伝えが残っている。一方で、人間と結ばれて子を成し、最期まで夫に添い遂げたという話もある。"}],"2045":[{"rank":"2","note":"多才な詩人、トルコ語が無くてもアラビア語で可","exp":"260","type":"財宝","name":"七説話","desc":"ルーミーの著書。\nイスラムの説話をまとめたものと思われる。ルーミーは詩の形式で多くの著書を残しており、この話は散文形式で書かれている。"}],"1726":[{"rank":"2","note":"ジャワの影絵芝居","exp":"270","type":"財宝","name":"ワヤン・クリ","desc":"ジャワ島で古くから上演される伝統的な影絵芝居。革の人形を用いる。現地語でワヤンは影、クリは革を指す。「マハーバーラタ」や「ラーマーヤナ」が上演演目になるワヤン・クリ・プルウォが一般的だが、ジャワの伝説や昔話も上演される。"}],"3179":[{"rank":"5","note":"メディチ家の薬","exp":"940","type":"財宝","name":"メディチ家の秘薬","desc":"薬の商売を行っていたメディチ家秘蔵の薬。服用すれば、たちまち体調がよくなるという噂がある。"}],"3924":[{"rank":"2","note":"天文学者の観測記録<br/>発見物カード:120","exp":"240","type":"天文","name":"さんかく座の渦巻星雲","desc":"さんかく座から少し西にある、渦巻きの形をした星雲。淡く広がっているため、肉眼で見ることは難しいといわれる。"}],"6758":[{"rank":"5","note":"発見物カード：900","exp":"1800","type":"財宝","name":"飛魚服","desc":"明代の特務機関、錦衣衛の制服。功績者に皇帝から下賜される装束\nの一つ。飛魚とは蟒蛇(うわばみ)にヒレが生え、尾が魚の形に似\nた霊獣で『山海経』に記された怪物が元といわれている。"}],"2603":[{"rank":"4","note":"装飾経の追加調査","exp":"710","type":"宗教遺物","name":"厳島装飾経","desc":"厳島神社に納められた装飾経のうちの一つ。意匠を凝らした、華やかな装飾経で、有力者の戦勝や繁栄の祈りが込められている。"}],"118":[{"rank":"1","note":"ギリシャの女神像の地図","exp":"30","type":"宗教遺物","name":"アテナ像","desc":"ギリシャ神話の女神の像である。アテナは産業、芸術、知恵、戦争の女神であり、ローマ神話ではミネルヴァという。都市国家アテナイの守護神であり、アテネのパルテノン神殿はアテナの神殿だ。"}],"3659":[{"rank":"3","note":"ダンジョン","exp":"510","type":"歴史遺物","name":"古代のアムフォラ","desc":"古代の地中海地域で広く使われた陶器の壷。二つの持ち手がついており、7世紀頃までワインやオリーブ油などの貯蔵や輸送に利用された。このアムフォラはカタコンベでの儀式に使うために持ち込まれたと思われる。"}],"1051":[{"rank":"3","note":"緑の宝石の鉱脈の地図","exp":"440","type":"財宝","name":"ろうかん","desc":"透明感のある、最上級の翡翠。明るい緑をしており、傷もない。このような石はめったに出ない。大変な価値がある。"}],"5327":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"タドラルト・アカクスの岩絵","desc":"先史時代に描かれたと思われる壁画。馬に乗る人々や、キリン、ゾウ、ラクダなどが描かれており、大昔の付近の様子がうかがえる。タドラルトは現地の言葉で「山」を意味する。"}],"6023":[{"rank":"2","note":"カード経験150","exp":"300","type":"財宝","name":"料理の形式","desc":"14世紀イングランドの王侯貴族向けの料理本で、フランス語由来の調理用語が使われている。リチャード2世の料理長によって編纂されたといわれ、当時はまだ珍しかった砂糖やインド・アジア・中東産の香辛料やハーブを使った料理が多い。"}],"6512":[{"rank":"2","note":"","exp":"350","type":"史跡","name":"ラニ・キ・ヴァヴ","desc":"インド北西部にある、巨大な階段状の井戸。「王妃の階段井戸」を意味する。11世紀ごろ亡き王を偲んだ王妃によって建てられたが、近くの河川の氾濫により埋もれていた。深さは七階層に及び、美しい彫刻が柱や壁を飾っている。"}],"939":[{"rank":"1","note":"美女の舞い","exp":"155","type":"虫類","name":"キベリタテハ","desc":"羽の周りを縁取る鮮やかな黄色と、その横に並んだ青がとても美しいチョウ。その美しさから、ある地方では美女と呼ばれるほどである。"}],"1253":[{"rank":"1","note":"目印を探せ","exp":"180","type":"地理","name":"サンアントニオ岬","desc":"ラプラタ川南岸の岬。沿岸部は湿地帯になっている。近くには、ブエノスアイレスという街がある。"}],"5193":[{"rank":"2","note":"到達する","exp":"335","type":"港・集落","name":"澳門","desc":"読みは「マカオ」。大きな港を擁する街。\n漁業を中心とした小さな村だったが、ポルトガル人が居留するようになってからは、ヨーロッパと東アジア間の貿易の要衝となった。"}],"3190":[{"rank":"5","note":"霧と氷が漂う海","exp":"920","type":"地理","name":"ラブラドル海流","desc":"グリーンランド南西岸から北米大陸北東岸に沿って南下する寒流。濃霧が発生しやすく、気温が上がる春先はグリーンランド方面から氷山が流れてくるためこの海域の航行には危険が伴う。"}],"6168":[{"rank":"2","note":"","exp":"330","type":"歴史遺物","name":"エーリンナの詩","desc":"古代ギリシャの女流詩人エーリンナの詩の写し。エーリンナは詩の女神の召使と称され、サッフォーの友人または弟子ともされるが、真偽は不明。若くして死んだ友人バウキスへの追憶と嘆きが、英雄叙事詩の韻律をもって綴られている。"}],"1256":[{"rank":"4","note":"地図にない島","exp":"780","type":"地理","name":"セバルド島","desc":"近年、その存在が確認された島。気候は冷涼で、樹木はほとんど見られない。海岸線は複雑で、周囲には無数の小島が点在している。"}],"5656":[{"rank":"4","note":"","exp":"680","type":"小型生物","name":"シャベルカナヘビ","desc":"ナミブ砂漠に生息しているトカゲ。砂漠の熱砂から身を守るため、脚を交互に持ち上げて休憩する習性がある。"}],"5457":[{"rank":"2","note":"発見時経験値250　発見物カード経験値125","exp":"250","type":"海洋生物","name":"ヨツメウオ","desc":"アマゾン川付近の、海水と淡水が混じり合う河口付近に群れで生息する魚。目の上半分を水面上に出して泳ぐという特徴がある。"}],"3803":[{"rank":"5","note":"生けるトンボ玉","exp":"1330","type":"小型生物","name":"ポリミータ","desc":"キューバ島の一部の地方に生息するカタツムリの一種。軟体部分は紺色で、個体ごとにさまざまな色の殻を持っている。"}],"2270":[{"rank":"5","note":"島の儀式","exp":"930","type":"宗教建築","name":"ナントゥワス","desc":"ナンマドール遺跡で最も立派な建造物。「首長の口の中」という名を持つ。神聖な場所であり、参道は高貴な者用と一般人用に分けられている。"}],"1819":[{"rank":"1","note":"精巧な加工の地図","exp":"140","type":"財宝","name":"留めピン","desc":"女性のケープ、ショールなどを留める金製のピン。高貴な身分の人物が身に付けたピンは装飾も豊かで芸術性に富む。"}],"1737":[{"rank":"5","note":"人を選びし宝石","exp":"1040","type":"財宝","name":"輝ける星","desc":"丸く磨き上げられた中に、白い星が見えるルビー。太陽光にあてると浮かび上がるその星は、遠い空の星を封じたものなのかもしれない…。"}],"6807":[{"rank":"5","note":"発見物カード:455","exp":"910","type":"虫類","name":"トビイロカゲロウ","desc":"日本などに広く生息する、カゲロウの一種。水のきれいなところを好んで繁殖し、幼虫は水底で成長する。羽化すると地上に出て、辺りを飛び回るが、成虫になって数日で命を落とし、儚いものの象徴とされる。"}],"226":[{"rank":"5","note":"トロイ","exp":"1027","type":"史跡","name":"トロイ考古学地区","desc":"ホメロス作の叙事詩「イリアス」で語られるトロイの遺跡。別名はイリオス。トロイの木馬でギリシャ軍に城内に進入され、滅んだと伝えられる。"}],"5739":[{"rank":"2","note":"メキシコ湾　メリダとヴェラクルスの間の砂浜海岸線　日中","exp":"","type":"気象・現象","name":"積乱雲","desc":"垂直方向に著しく発達した巨大な雲。雲の下では激しい嵐や雷雨などが発生することもある。夏場での観測情報が多い。"}],"495":[{"rank":"1","note":"古代エジプト遺物の地図","exp":"36","type":"歴史遺物","name":"エジプト文字の石板","desc":"エジプトの古代象形文字・ヒエログリフが記された石板。鳥や獣、体の一部などが文字になっている。いったい何が書かれているのだろうか。"}],"1913":[{"rank":"1","note":"光のへその地図","exp":"170","type":"歴史遺物","name":"テ・ピト・クラ","desc":"「光のへそ」と呼ばれている場所。周りにモアイが立ち並ぶ中、白く滑らかな楕円の石がたたずんでいる。どんな意味があるのかは分からないが、神聖さを感じる。"}],"5822":[{"rank":"4","note":"","exp":"710","type":"植物","name":"ヤレータ","desc":"アンデス山脈の高地に生息する多年生植物。一つ一つは小さいが、寄り集まって自生するため、大きな塊のように見える。"}],"73":[{"rank":"1","note":"インド洋の大きな島","exp":"150","type":"地理","name":"マダガスカル島","desc":"南アフリカの東沖に位置する巨大な島。標高3000m近い山々があり気候は多様だ。他の場所から切り離されているせいか特有の動植物が多い。"}],"6979":[{"rank":"3","note":"発見物カード:250","exp":"500","type":"歴史遺物","name":"ウルグ・ベク天文表","desc":"サマルカンドの君主であり天文学者でもあったウルグ・ベクと、彼が招致した学者たちによって編纂された天文表。1000を超える星の位置などが記されており、その高い精度は後世の天文学に大きな影響を与えた。"}],"554":[{"rank":"1","note":"古代ローマの復興者","exp":"95","type":"歴史遺物","name":"アウレリアヌス帝の兜","desc":"ローマ帝国衰退期の皇帝・アウレリアヌス帝の兜。名君でパルミラを始めとする反乱勢力をよく抑え、厳格な統治を行った。遠征中に暗殺されたという。"}],"2746":[{"rank":"2","note":"繊細な屏風絵の地図<br/><br/>発見時経験値210　発見物カード経験値105","exp":"210","type":"美術品","name":"申師任堂の屏風絵","desc":"朝鮮の女性画家・申師任堂によって描かれた屏風絵。\n安堅の影響を受け、精緻な画風である。人物や動物をあまり描かないのが特徴で、この屏風にも、草と虫を美しく描いている。"}],"3543":[{"rank":"","note":"発見時経験値2820　発見名声1125","exp":"2820","type":"レリック","name":"ビザンツ帝国の女傑","desc":"貧しい踊り子からビザンツ帝国の皇后にまで上り詰めたテオドラは、優れた助言者として皇帝を支える聡明な人物であったという。"}],"6685":[{"rank":"5","note":"","exp":"1100","type":"宗教建築","name":"パドマナーバスワーミ寺院","desc":"インド南部トリバンドラムにあるヒンドゥー教の寺院。ヴィシュヌ神を祀っている。地下に莫大な宝が眠るといわれている。開かずの扉があり、ナーガの封印が施されているため選ばれし者が呪文を唱えなければ開けられないという。"}],"5292":[{"rank":"4","note":"","exp":"620","type":"中型生物","name":"パタスザル","desc":"アフリカのサバンナに生息するサル。樹上でも素早いが、地上でも非常に速く走れ、時速で55kmにも達する。昼間は地表で生活し、夜は低木の上で休むことが多いようだ。"}],"1475":[{"rank":"4","note":"アプサラの舞","exp":"732","type":"財宝","name":"天女の舞衣","desc":"伝統あるアプサラダンスでアプサラ役が着る衣装。踊り子の服の色は、赤・青・緑・白とあるのだが、アプサラ役の衣装は白と決まっている。精緻な刺繍と豪華な装飾が踊り子を天女のように見せるのだろう。"}],"3639":[{"rank":"2","note":"カリブの鉱石の地図<br/><br/>発見時経験値380　発見物カード経験値190","exp":"380","type":"財宝","name":"カリブの景色","desc":"バハマ近辺で見られる淡い青色の石。まるでカリブ海を見ているような美しい青色は、見る者の心を安らげてくれる。"}],"3792":[{"rank":"2","note":"視認<br/><br/>発見時経験値380　発見物カード経験値190","exp":"380","type":"天文","name":"オリオンのベルト","desc":"オリオン座の中ほどにある3つの星。2等星が3つ並ぶため見つけやすい。星座図ではオリオンのベルトに見立てられる。右端にある星はミンタカと呼ばれ、ほぼ天の赤道の上にあるため、春分や秋分の日の太陽と同様の軌道に見える。"}],"2673":[{"rank":"2","note":"歴史と神話の書","exp":"330","type":"歴史遺物","name":"三国遺事","desc":"高麗の高僧・一然が編さんしたといわれる、全五巻の歴史書。\n三国史記とは違い、故事や伝承、仏教についても記されている。"}],"1318":[{"rank":"2","note":"クエスト「富を生む小島」<br/>発見物カード:165","exp":"330","type":"地理","name":"テルナーテ島","desc":"貴重な香辛料であるクローブを産する島。島には、このクローブの交易により莫大な富を得たテルナーテ王国が存在する。隣島のティドレ王国とは敵対関係にあり、各国が動向をうかがっている。"}],"5723":[{"rank":"2","note":"2017.02.07新規追加","exp":"","type":"気象・現象","name":"カプチーノコースト","desc":"強い風や波などにより海中のプランクトンなどが撹拌され、細かな泡が生じる現象。世界各地で観測できるが、大規模なものは非常に珍しい。"}],"3011":[{"rank":"3","note":"人類の歴史","exp":"490","type":"歴史遺物","name":"クローヴィス尖頭器","desc":"先史時代、クローヴィス文明で使用されていたと思われる石器。独特の浅い溝が基部に施されている。マンモスやバイソンの狩猟に広く用いられていたようだ。"}],"1167":[{"rank":"3","note":"美しい羽のチョウ","exp":"484","type":"虫類","name":"ニジイロシジミタテハ","desc":"新大陸の南に生息する美しいチョウ。表と裏で模様の違う羽は、まるで宝石のように美しい。"}],"3314":[{"rank":"2","note":"書きかけの地図","exp":"250","type":"地理","name":"アイラ島","desc":"ブリテン島北部、西側にある島。海流の影響を受け、本島より気候が穏やかである。"}],"956":[{"rank":"2","note":"変わった鳥の話","exp":"220","type":"鳥類","name":"ラケットヨタカ","desc":"翼の部分に、さらに長い羽が付いている。地面からかなりの高度を飛び、昆虫を主食とする。"}],"3174":[{"rank":"1","note":"書きかけの地図","exp":"140","type":"地理","name":"ロングレンジ山脈","desc":"北米北東部沿岸の、テラ・ノヴァ西部に位置する山脈。北米大陸の東側に横たわるアパラチア山脈の北端にあたる。"}],"2493":[{"rank":"1","note":"書きかけの地図","exp":"130","type":"地理","name":"石雨傘","desc":"台湾島の海岸にある、海の浸食で削れた岩。一本の細長い岩が、大きな岩石を支えておりその姿は傘の形によく似ている。"}],"6475":[{"rank":"5","note":"レガシー・港湾都市ロードス　下","exp":"2475","type":"歴史遺物","name":"ロードスの商船","desc":"ロードスの港に出入りした商船。軍船とは違い、櫂や漕ぎ手は配置せず、より多くの荷を積めるようになっている。ギリシャとエジプトの中ほどに位置するロードス島は古来より東地中海の貿易路の要所だった。"}],"1769":[{"rank":"2","note":"［勅命］[[新大陸西岸方面の動物探索","exp":"310","type":"小型生物","name":"マーラ","desc":"南米の草原に生息するネズミ。ぴょんぴょん飛び跳ねて移動する。オスとメスは常に行動を共にし、一生つがいのままである。\nまた、オスはメスに対して、とても従順である。"}],"1039":[{"rank":"3","note":"遊牧民族の西進","exp":"495","type":"歴史遺物","name":"バトゥの財宝","desc":"バトゥとは、チンギス・ハンの長子であるジュチの子。大規模なヨーロッパ遠征を行いキプチャク・ハン国を興した。これはバトゥの財産の一部であるらしい。"}],"190":[{"rank":"5","note":"その驚くべき姿","exp":"910","type":"鳥類","name":"ホウオウジャク","desc":"自分の体長ほどの、長い尾を持った鳥。ただし、メスはオスの半分くらいの長さである。"}],"1464":[{"rank":"4","note":"クエスト「鄭和の船の大きさ」<br/>発見物カード:372","exp":"744","type":"歴史遺物","name":"鄭和艦隊の船首像","desc":"鄭和が乗っていた明の船の船首像。記録では鄭和の船は宝船といわれる巨大なもので、その大きさはかのコロン提督やガマ艦隊の船とは比べ物にならないほどだという。この船首像を見る限り、その話はあながち嘘でもないようだ。"}],"6555":[{"rank":"5","note":"レガシー『英知の灯アレクサンドリア』真上","exp":"","type":"地理","name":"在りし日のファロス島","desc":"ファロス島のかつての姿。航海の守護神ともされた女神イシスを祀る神殿がある。島の沖合にはアレクサンドリアの大灯台が建てられその巨大さを近くで体感できる。夜には灯台の最上部に巨大な炎が灯されていた。"}],"1024":[{"rank":"4","note":"夜しか現れない美人","exp":"720","type":"植物","name":"ゲッカビジン","desc":"普段は厚みのある葉しか目に付かないが、夜になると20cmにもなる白い大輪の花を咲かせる。透き通るような純白の花弁が美しく、開花すると甘く強い香りが周囲に漂う。"}],"5223":[{"rank":"1","note":"","exp":"160","type":"植物","name":"アーティチョーク","desc":"直径15cmほどの紫色の球のような花を付ける植物。茎の高さは成人男性以上になり、葉は大きくギザギザしている。ヨーロッパでは古くから食用にされ、食欲不振の改善や二日酔い防止として愛用されていた。"}],"5010":[{"rank":"2","note":"コーカサス地方再調査","exp":"","type":"財宝","name":"アレキサンドライトキャッツアイ","desc":"希少な宝石。中央に光の筋が入ったアレキサンドライト。ダイヤモンドより高価とされる場合がある。"}],"1637":[{"rank":"2","note":"クエスト「海の楽園」<br/>発見物カード:135","exp":"270","type":"地理","name":"アンダマン海","desc":"アンダマン諸島の東側に位置する海。透明度が高く、極彩色のサンゴや魚が数多く見られる。\n海域には数多くの島が点在し、モーケン人と呼ばれる海の民が島々を移動しながら暮らしている。"}],"664":[{"rank":"2","note":"焼き尽くされた遺跡","exp":"240","type":"歴史遺物","name":"アパダーナのレリーフ","desc":"アパダーナとはアケメネス朝ペルシャの大宮殿・ペルセポリスの謁見の間のことである。広大な大広間には、精巧なレリーフが一面に施されている。"}],"3625":[{"rank":"5","note":"太りすぎのガチョウのような鳥","exp":"1105","type":"鳥類","name":"ドードー","desc":"モーリシャス諸島にしか生息しない、特殊な鳥である。ニワトリよりかなり大きく、翼は小さくて飛べない。足は太くてしっかりしているが、速く走ることはできない。島に捕食者がいないため、のんびりした鳥になったのだろう。"}],"1490":[{"rank":"1","note":"赤い目のカエルの地図","exp":"70","type":"小型生物","name":"アカメアマガエル","desc":"大きな赤い目玉、緑色の体にわき腹の青と白の縞模様が特徴。その鮮やかな体色を隠すため、肢を折り曲げて葉の上で休息をとる。"}],"1331":[{"rank":"2","note":"勅命クエスト「[香料諸島方面進出の要衝」<br/>勅命代替クエスト「東国へ続く狭き道」<br/>発見物カード:160","exp":"320","type":"地理","name":"マラッカ海峡","desc":"マレー半島と、スマトラ島の間に横たわる海峡。東西交易において重要な通過点となるが海峡の幅は狭く、その上水深が非常に浅い。さらに、暗礁や浅瀬も多いため、航行には細心の注意が必要だ。"}],"6098":[{"rank":"1","note":"ギリシャ近海の地形","exp":"70","type":"地理","name":"コリント地峡","desc":"バルカン半島とペロポネソス半島をつなぐ、幅わずか7kmの地峡。この地域は平地が少なく乾燥気味で、オリーブ栽培や牧畜が盛んである。"}],"926":[{"rank":"1","note":"美しいつぼの地図","exp":"34","type":"財宝","name":"金彩の水差し","desc":"金彩が施された豪華な水差し。凝った装飾がされているが、実用性もある。高貴な人の日用品だったのかもしれない。"}],"5461":[{"rank":"3","note":"南米の賢者<br/><br/>発見時経験値490　発見物カード経験値245","exp":"490","type":"中型生物","name":"フサオマキザル","desc":"南米北東部などに生息するサル。非常に高い知能を持っており、石で木の実を割ったり、木を叩いて中にいる虫を探したりすることができる。"}],"2619":[{"rank":"2","note":"道教の少年像の地図","exp":"300","type":"宗教遺物","name":"中壇元帥の銅像","desc":"読みは「ちゅうだんげんすいのどうぞう」。道教で崇められている少年神の像。台北に納められていた。\n中壇元帥はナタ太子とも呼ばれ、魔力を秘めた布や、火を放つ槍を持って戦う姿で表されている。"}],"1294":[{"rank":"2","note":"陸の魚","exp":"270","type":"中型生物","name":"センザンコウ","desc":"ウロコがある哺乳類。危険を感じるとボールのように丸まって敵から身を守るようだ。とても長い舌を持っており、これでアリをなめとっている。アリしか食べないのだろうか？"}],"6110":[{"rank":"5","note":"","exp":"970","type":"伝承","name":"不死鳥の復活","desc":"フェニックスはその見た目や特徴から、不死鳥や火の鳥とも呼ばれている。また「復活する」という特徴がキリストの復活とも結び付けられ、多くの人々から象徴的な存在として重要視された。そのため、伝承の生物の中でも高い認知度を持つ。"}],"534":[{"rank":"1","note":"古代の道具の地図","exp":"104","type":"歴史遺物","name":"象嵌青銅器","desc":"「ぞうがん」青銅器。象嵌細工を施した青銅器。貴金属や宝石と、高度な技術が必要となるためか、王族の副葬品や、裕福な貴族の調度品などとして出土する。"}],"6421":[{"rank":"5","note":"追究クエスト「サトウカエデの追加調査」<br/>発見物カード:445","exp":"860","type":"植物","name":"紅葉したサトウカエデ","desc":"サトウカエデが秋頃に黄色や赤に紅葉した状態。木の高さは30メートルを超えるといわれる。群生域で、特徴的な形をした葉が一面に広がる景観は素晴らしいという。"}],"2055":[{"rank":"2","note":"クエスト「人を守護するメデューサの目」<br/>発見物カード:175","exp":"350","type":"財宝","name":"ナザールボンジュウ","desc":"ガラスなどを使って目をかたどったトルコのお守り。目はメデューサの目を表している。トルコでは、悪意は目から放たれると考えられ、持ち主の身に危険が迫ると、悪意を跳ね返して割れるという。"}],"1610":[{"rank":"1","note":"脚の長い動物の地図","exp":"75","type":"鳥類","name":"レア","desc":"ダチョウによく似た大型のトリ。飛ぶことはできず、草原や低木地に生息し、植物の葉や種子を好んで食べる。"}],"5720":[{"rank":"4","note":"2017.02.07新規追加","exp":"660","type":"気象・現象","name":"反薄明光線","desc":"地平線近くの太陽が霧で隠れた際に見られる現象。雲の隙間から漏れ出た帯状の光が、太陽の反対側で収束して見える。"}],"108":[{"rank":"2","note":"カリカットへの道標","exp":"220","type":"地理","name":"セントマリー岬","desc":"マダガスカル島最南端に位置する岬。そこに広がる砂丘は、島に生息する巨大生物が卵を孵（かえ）す場所として利用している。"}],"3942":[{"rank":"1","note":"クエスト「ゼウスのしもべ」<br/>発見物カード:190","exp":"190","type":"天文","name":"わし座","desc":"ゼウスがトロイの王子ガニュメデスをさらう際、変身したワシが天に昇った姿とされる。星座図ではガニュメデスが姿を変えたとされるみずがめ座を、横から狙うワシの姿で描かれる。"}],"2611":[{"rank":"5","note":"土地公","exp":"950","type":"宗教遺物","name":"福徳正神像","desc":"読みは「ふくとくせいしんのぞう」。五穀豊穣や蓄財祈願の信仰から生まれた自然神の像で、土地公とも呼ばれる。\n主に人々に財を与える福の神として、台湾島で親しまれている。"}],"2598":[{"rank":"3","note":"仏界の絵図","exp":"480","type":"宗教遺物","name":"曼荼羅図","desc":"読み方は、「まんだらず」。古代インドを起源とする、日本の宗教絵画の一つ。\n曼荼羅とは、仏教の世界観を表現したものである。この図では、阿弥陀如来を中心とした極楽浄土の様子が描かれている。"}],"6603":[{"rank":"4","note":"","exp":"640","type":"海洋生物","name":"チャイニーズバハバ","desc":"中国に生息する巨大魚の一種。海水と淡水が混じり合う河口付近に多いとされ、小魚やエビ、カニなどを捕食する。食用や薬用など多くの使い道がある。"}],"2454":[{"rank":"3","note":"着物の意匠","exp":"460","type":"虫類","name":"オオムラサキ","desc":"東アジア各地に分布するチョウ。雄は、光沢のある青紫色の羽を持つ。\n飛翔能力に長け、近くにいれば羽ばたく音が聞こえるほどである。"}],"3822":[{"rank":"3","note":"斑模様のエイの地図","exp":"470","type":"海洋生物","name":"イエロースティングレイ","desc":"カリブ海などに生息するエイの一種。体は円形に近く、尾は短い。体表の斑模様が特徴。"}],"5898":[{"rank":"5","note":"","exp":"1400","type":"史跡","name":"アラム・ムルの神の門","desc":"チチカカ湖周辺にある遺跡。扉のように見える窪みがある。古代の王アラム・ムルはこの窪みを通って姿を消すと、二度と戻ってこなかったと伝えられる。"}],"5064":[{"rank":"2","note":"到達する","exp":"240","type":"港・集落","name":"サントドミンゴ","desc":"イスパニョーラ島の南東部にある街。開拓されたばかりの街だが、航海の便がよく、カリブの交易の中心地として栄えている。カリブ特有の農作物のほか、サトウキビの栽培が広く行われている。"}],"2901":[{"rank":"2","note":"街娘のための花探し<br/><br/>発見時経験値280　発見物カード経験値140","exp":"280","type":"植物","name":"ウンナンサクラソウ","desc":"中国南部で見つかった淡い紫色や桃色の花を咲かせる植物。\n長い期間、花が咲いており、香りも良い。\n春を告げる花という意味で、報春花とも呼ばれる。"}],"6629":[{"rank":"2","note":"「真っ黒な昆虫の地図」<br/>発見物カード:160","exp":"320","type":"虫類","name":"ハグロトンボ","desc":"黒色のトンボ。体は黒く緑色の金属光沢がある。特徴的なのは翅で他のトンボのように透明でなく黒色をしている。動かし方も他と異なり、蝶のようにひらひら舞うように羽ばたいたり、翅を立ててとまったりする。"}],"6224":[{"rank":"3","note":"","exp":"500","type":"気象・現象","name":"ファイヤーデビル","desc":"炎の竜巻。山火事などで大規模な火災が発生し、周囲に風を遮るものがない場合に発生することがある。上昇気流によって炎が竜巻になった姿は見る者に恐怖を与えるが、奇妙な美しさを感じる者もいるという。"}],"2330":[{"rank":"1","note":"書きかけの地図","exp":"130","type":"地理","name":"壱岐","desc":"読みは「いき」。九州北西部の玄界灘に位置する島。\n暖流である対馬海流の影響で、気候は比較的温暖である。\n古くから海路上の中継地点として、朝鮮半島と九州をつないできた場所でもある。"}],"4955":[{"rank":"3","note":"クエスト「天満の誕生とその後」<br/>発見物カード:255","exp":"510","type":"天文","name":"ペガスス座","desc":"ギリシャ神話に登場する天馬・ペガサスが天に上った姿とされる星座。比較的明るい星が多く、ヨーロッパでは秋の代表的な星座とされる。"}],"4963":[{"rank":"4","note":"クエスト「ネーデルラントで作られた星座」<br/>発見物カード:345","exp":"690","type":"天文","name":"つる座","desc":"16世紀にオランダの航海者ペーテル・ケイセルとフレデリック・デ・ハウトマンが作った星座。かつては北にある、みなみうお座の一部だった。"}],"6934":[{"rank":"4","note":"発見物カード:325","exp":"650","type":"鳥類","name":"非繁殖羽のブロンズトキ","desc":"非繁殖期のブロンズトキ。繁殖期とは異なり羽に光沢がなく、黒みがかった体色をしている。また、幼鳥も同様に体全体が暗い色である。"}],"4349":[{"rank":"3","note":"釣り","exp":"480","type":"海洋生物","name":"ノーザンパイク","desc":"カワカマスの一種で、淡水域または汽水域に生息する魚。北半球の高緯度の地域に、広く分布する。体長1mを超える大型肉食魚で、鋭い牙を持つ。"}],"6955":[{"rank":"1","note":"発見物カード:75","exp":"150","type":"虫類","name":"レッドフラットバークビートル","desc":"北米に生息する赤い甲虫。体長は15mm程度。非常に平らな体をしており、樹皮の下に潜んで木材を食べる他の小さな虫を補食する。また、極寒の地に適応しており、幼虫は生存が不可能な低温にも耐えるという。"}],"5697":[{"rank":"4","note":"","exp":"700","type":"財宝","name":"シャーマンたちの貨幣","desc":"シャーマン岩周辺の水底に沈んでいた貨幣。岩に奇跡を起こす力があると信じたシャーマンたちは、貨幣を岩の周辺に投げ入れ、なんらかの儀式を行っていたようだ。"}],"6640":[{"rank":"5","note":"発見物カード1,350","exp":"2700","type":"歴史遺物","name":"ポンペイラクシュミー","desc":"ポンペイの遺跡で発見された、象牙で掘られた女性の小像。その造形から、ヒンドゥー教の美と豊穣の女神ラクシュミーではないかといわれる。インドでも同様の小像が発見されたため、この小像はインド・ローマ貿易の裏付けとなった。"}],"3616":[{"rank":"4","note":"凍土の森林","exp":"650","type":"地理","name":"タイガ","desc":"シベリア地方に広がる針葉樹林。\nどうやら地域によっては樹林の種類が異なるらしく、遠くから見ると色が違って見える。"}],"1178":[{"rank":"5","note":"魔神を貫く武器","exp":"1222","type":"宗教遺物","name":"ヴァジュラ","desc":"ヒンドゥーの神・インドラの武器。悪龍・ヴリトラを倒すために、ダディーチャという仙人の骨から作られたものである。金剛杵ともいう。"}],"5511":[{"rank":"2","note":"クエスト「マンチェスターの起源」<br/>発見物カード:330","exp":"363","type":"歴史遺物","name":"マンクニウムの砦の石","desc":"ブリテン島の中西部で砦の建材に使用された石の欠片。古代ローマ帝国が築いた前哨陣地「マンクニウム」のものと見られる。"}],"2280":[{"rank":"5","note":"クエスト「街の奥にあったもの」<br/>発見物カード:520","exp":"1040","type":"史跡","name":"コパン遺跡","desc":"大雨による川の氾濫で発見された、マヤの大都市遺跡。他のマヤ遺跡には見られない独特の石像彫刻や壁画が見られ、彫刻技術の高さを感じさせる。"}],"6632":[{"rank":"4","note":"","exp":"660","type":"鳥類","name":"アフリカツリスガラ","desc":"アフリカ原産の鳥。樹木に袋状の柔らかい巣を作ることが名前の由来。捕食者を欺くため、本当の入口とは別に、本物より本物らしい見せかけの入口を作る。まさに天敵が多い鳥の知恵である。"}],"1841":[{"rank":"4","note":"ニューギニアの精霊信仰","exp":"720","type":"宗教遺物","name":"精霊の像","desc":"ニューギニアで信仰されている精霊を形にした像。この島では精霊を称え、木像で具現化する。"}],"6015":[{"rank":"2","note":"","exp":"360","type":"財宝","name":"マビノギオン","desc":"ウェールズに古くからある伝承を一冊にまとめた写本。\n古い神話を元にしたといわれる「マビノギ四枝」や、アーサー王伝説の原型とされる「アルスルの宮廷の三つのロマンス」などが収められている。"}],"2732":[{"rank":"4","note":"朝鮮香炉の歴史","exp":"620","type":"歴史遺物","name":"金銅製の香炉","desc":"百済王の墓と思われる場所から発見された大型の香炉。\n龍とハチと鳳凰の装飾が施されており、百済の工芸技術の高さがうかがえる。"}],"1545":[{"rank":"2","note":"地の果ての断崖","exp":"330","type":"地理","name":"グレートオーストラリア湾","desc":"オーストラリアの南に広がる湾｡1000kmにも及ぶ長い海岸線と広い遠浅の海が続く。湾の沿岸部には海に突き出た断崖が数百kmに渡って続いている場所がある。この断崖は南から吹き付ける強風によって形作られたようだ。"}],"5110":[{"rank":"1","note":"到達する","exp":"14","type":"港・集落","name":"ハンブルク","desc":"北ドイツの重要な交易港として栄えている都市。内陸に豊富な鉱脈があり、鉛、スズ、銅や鉄など、多種の鉱石が産出する。"}],"2818":[{"rank":"3","note":"高尚な娘のための絵画","exp":"530","type":"美術品","name":"唐の宮廷画","desc":"宮中の女性が楽の練習をしている風景を描いた絵画。その風俗から唐代に描かれたものと思われる。\n描いた人物の詳細は不明。"}],"3914":[{"rank":"2","note":"「木星の観測記録」<br/>発見物カード:120","exp":"240","type":"天文","name":"ガリレオ衛星","desc":"木星の周囲を回る四つの衛星を指す。ガリレオ衛星は5等星から6等星程度の明るさで、単独であれば肉眼でも見えるはずだが、木星があまりに明るいために見られない。"}],"6264":[{"rank":"3","note":"","exp":"480","type":"歴史遺物","name":"メンダーニャの航海誌","desc":"１６世紀のイスパニア人探検家アルバロ・デ・メンダーニャ・デ・ネイラが南米やオセアニアを回った時に残した記録。財宝を求めて航海を続け、ソロモン諸島を発見するが、財宝を見つけることはできなかったという。"}],"6520":[{"rank":"5","note":"クエスト「染め上げられた樹木」<br/>発見物カード:595","exp":"1190","type":"植物","name":"レインボーユーカリ","desc":"その名の通り、色とりどりの樹皮を持つのが特徴的な高木樹。年を経るごとに外側の樹皮がはがれ落ちていき、内側に新しい樹皮が現れる。これを繰り返す過程で樹皮の色が変化していくといわれている。"}],"6813":[{"rank":"3","note":"発見物カード経験値:225","exp":"","type":"小型生物","name":"マツテン","desc":"ヨーロッパの森林に生息するテンの一種。全身の毛は濃褐色だが、喉の部分だけ黄色い。夜行性で雑食。主に樹上で活動をするが、地面を速く走ることもできる。木のほらや茂みの中などに巣を作る。"}],"2789":[{"rank":"4","note":"ラウトゥの気になる子<br/><br/>文化貢献度45","exp":"790","type":"中型生物","name":"チャウチャウ","desc":"番犬や家畜として飼育されてきたイヌ。口の中や舌が青黒いため、黒舌犬と呼ぶ地域もあるようだ。\n唐の皇帝も飼育していたといわれている。"}],"6874":[{"rank":"2","note":"発見物カード:175","exp":"370","type":"中型生物","name":"コサックギツネ","desc":"中央アジアから東アジアにかけて生息する、キツネの一種。なわばりを持たず、移動しながら生活する習性を持つ。名前はロシア語での名称「コルサック」に由来している。"}],"1983":[{"rank":"2","note":"釣り","exp":"340","type":"海洋生物","name":"シビレエイ","desc":"体内に左右一対の発電器官を持ち、それにより小魚やエビなどを電気で麻痺させて捕食する。"}],"2052":[{"rank":"4","note":"放浪アリ","exp":"680","type":"虫類","name":"サスライアリ","desc":"サバンナなどに生息し定住せずに食料を求めて放浪する。他のアリに比べ、頭が大きく、目は退化している。\n100万匹近い集団で行動し、行く手を遮る動物を襲い、骨になるまで食べ尽くす。"}],"1306":[{"rank":"3","note":"図鑑に載せたい","exp":"451","type":"虫類","name":"アトラスオオカブト","desc":"三本の長い角が特徴である虫。黒くてつやのある大きな体をしている。攻撃性が強く、すばやい動きをする。"}],"1826":[{"rank":"5","note":"未開の土地の妙なもの","exp":"1030","type":"史跡","name":"フマナ平原","desc":"南米大陸の中腹、アンデス山脈の西側の裾野にある高原。砂漠が広がっており、ところどころにくぼみがある。なにやらただのくぼみではなさそうだが…。"}],"1843":[{"rank":"2","note":"毛のないネズミ","exp":"300","type":"小型生物","name":"ハダカデバネズミ","desc":"無毛で大きな前歯を持つネズミ。大人の個体でも哺乳類の赤ちゃんに似た姿をしている。地下に巣穴を作り集団で生活。出産する雌と多数の労働する雄とに役割が分かれており、ひとつの社会を作っている。東アフリカの乾燥地帯に生息。"}],"4812":[{"rank":"3","note":"宋山里遺跡群 （中層隠し部屋）読み:「ひのし」","exp":"","type":"財宝","name":"火熨斗","desc":"「ひのし」と呼ばれる布地の皺を伸ばすための道具。器状の部分に熱した炭を入れ、器の底を布地に当てて皺を伸ばしたと思われる。"}],"5849":[{"rank":"5","note":"","exp":"1360","type":"美術品","name":"ピクウェのアクセサリー","desc":"ピクウェと呼ばれる技法で作成されたアクセサリー。母材として柔らかい素材が使われているのが特徴である。"}],"3416":[{"rank":"2","note":"ハムレットの毒","exp":"230","type":"植物","name":"イチイ","desc":"ヨーロッパの庭園でよく見られる針葉樹。赤い実は食用になるが、種に毒がある。イングランドやアイルランドでは教会によく植えられている。"}],"2390":[{"rank":"3","note":"渓流に潜む巨大な影","exp":"600","type":"中型生物","name":"オオサンショウウオ","desc":"主に西日本の河川の上流に生息する、太ったトカゲのような生物。体長が1mを超えるものもいる。\n陸上での行動は鈍いが水中では機敏な動きを見せる。"}],"120":[{"rank":"1","note":"ギリシャの神像の地図","exp":"60","type":"宗教遺物","name":"ヘパイストス像","desc":"ギリシャ神話の火と鍛冶の神の像。醜い姿をしているとされるが、妻はもっとも美しい女神・アフロディテである。彼の鍛冶場はシチリア島の地下にあるとされている。"}],"1149":[{"rank":"2","note":"新大陸東岸の調査","exp":"280","type":"地理","name":"メキシコ湾","desc":"フロリダ半島とユカタン半島の西奥に存在する湾。温かい海流で、ハリケーンといわれる嵐がよく発生する。"}],"2976":[{"rank":"5","note":"虫か、魚か<br/><br/>発見時経験値1130　発見物カード経験値565","exp":"1130","type":"海洋生物","name":"ダイオウグソクムシ","desc":"大西洋の海底に棲む巨大甲殻類。体長は最大で50cmにもなり、体重は1kgを超える。背面を海底に向けながら体をくねらせて泳ぐ。"}],"2117":[{"rank":"2","note":"［勅命］[[現地における思想についての調査","exp":"310","type":"宗教遺物","name":"宣教師の遺品","desc":"異国の地で教えを広めようとしていた宣教師の遺品。ヨーロッパでは見慣れた物だ。"}],"5294":[{"rank":"1","note":"","exp":"170","type":"小型生物","name":"ケープアラゲジリス","desc":"アフリカ南部の乾燥した地域に広く生息するリスの仲間。地面に巣穴を掘って生活する。樹上で生活するリスと違って食物を貯め込まず、一日の大半を食事に費やす。危険に気づくと、鳥のさえずりのような鳴き声で仲間に知らせる。"}],"3899":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:105","exp":"210","type":"天文","name":"大マゼラン星雲","desc":"マゼランが世界周航する際に記録を残していたため、この名で呼ばれるようになる。マゼラン以前のヨーロッパの航海者はケープの雲と呼んでいた。北半球では赤道近くまで南下しないと見られない。"}],"1575":[{"rank":"1","note":"書きかけの地図","exp":"110","type":"地理","name":"アラフラ海","desc":"ニューギニア島の南西部に広がる遠浅の海。この海域を南下すれば広大な陸地があるというが…。"}],"6795":[{"rank":"3","note":"","exp":"","type":"天文","name":"アルシャイン","desc":"わし座の星の一つ。ワシの頭と体の中心であるアルタイルの間に位置する。名はペルシャ語で「襲う鷲」を意味しているともいわれ、元は星座全体を指す言葉であったという。"}],"513":[{"rank":"1","note":"古代の貨幣の地図","exp":"14","type":"歴史遺物","name":"古代の銀貨","desc":"銀で作られた、古代の貨幣。通常、銀は金に次ぐものとされるが、古代では金より採取量が少なく、金より珍重されていたという。"}],"2545":[{"rank":"5","note":"船乗りの言い争い","exp":"930","type":"鳥類","name":"ルリチョウ","desc":"台湾島にのみ生息する鳥。体長は30cmほどあるが、尾は短い。\n脚とくちばしががっしりとしているのが特徴である。"}],"1947":[{"rank":"2","note":"奇妙な石の地図","exp":"220","type":"化石","name":"二本足の小さなトカゲの骨","desc":"全長40cm程のトカゲの骨のような石。ただし後足が異様に長い。これほど後足が長い生物なら、四本足よりも、後足二本のみで移動したほうが早いのではないだろうか。"}],"1605":[{"rank":"3","note":"御姿を形に","exp":"484","type":"宗教遺物","name":"カニシカ王の舎利容器","desc":"クシャーナ朝に最盛期をもたらしたカニシカ王の遺骨が納められたとされる容器。青銅製の容器のふたには仏陀梵天、帝釈天の三尊像が据えられている。この像は、ガンダーラ地方で作られた仏像の様式の中でも最初期のものである。"}],"2051":[{"rank":"2","note":"奇妙な詩集","exp":"350","type":"財宝","name":"ルバイヤート","desc":"オマル・ハイヤームの著した四行詩集。\nペルシャ語で四行詩を意味する。美酒と酒姫に対する賛歌を歌い続け、刹那的快楽主義を主張している。"}],"1484":[{"rank":"1","note":"紫の花の地図","exp":"105","type":"植物","name":"カトレア","desc":"濃く色づいた筒状の花びらを中央に、そこから放射状に形の異なる花びらが出ている。華やかでとても美しい。"}],"6731":[{"rank":"5","note":"楽の叡智・心に響く楽器　上","exp":"","type":"財宝","name":"ダヴィデのハープ","desc":"ダヴィデとは旧約聖書に登場する古代イスラエルの王。少年のダヴィデはこのハープを弾き、悪霊に取りつかれた先王サウルを癒したという。"}],"5015":[{"rank":"1","note":"到達する","exp":"127","type":"港・集落","name":"アデン","desc":"アラビア半島の南端にある、歴史ある良港。中国・インドとイスラム・ヨーロッパ諸国の重要な交易中継点。乳香をはじめとする何種類もの香料や、コーヒーなどが産物。"}],"1614":[{"rank":"1","note":"英雄の碑文の地図","exp":"140","type":"歴史遺物","name":"ラームカムヘーン王碑文","desc":"スコータイ王ラームカムヘーンが書いたとされる碑文。スコータイの当時をしのばせる内容が書かれている。口語で読みやすいので、多くの人に広まった。"}],"5343":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:160","exp":"320","type":"天文","name":"かじき座","desc":"大マゼラン雲近くにある星座。16世紀の末にネーデルラントの航海者ペーテル・ケイセルとフレデリク・デ・ハウトマンが考案した。"}],"6411":[{"rank":"5","note":"追究発見物","exp":"415","type":"地理","name":"サハラのオアシス","desc":"サハラ砂漠の地下深くには水を通しにくい粘土の層がある。ここに地下水が蓄えられており、水が蒸発すると、砂に塩が残って白くなる。これがオアシスの目印になる。"}],"5667":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:115","exp":"230","type":"天文","name":"パラス","desc":"火星の軌道の外側にある小惑星帯に位置する天体。同様の天体の中では、ケレスに次ぐ大きさとされている。"}],"1235":[{"rank":"2","note":"黒い大きな石","exp":"220","type":"宗教遺物","name":"鏡","desc":"黒曜石の平らな面を磨いて作った鏡。メソアメリカのシャーマンたちが、神々の国との交信するために用いたという。"}],"871":[{"rank":"1","note":"凍る海","exp":"80","type":"地理","name":"ボスニア湾","desc":"バルト海北部の広大な湾。南北に長く、多数の川が流れ込む。そのためか塩分が薄く、冬になると凍ってしまうこともあるという。"}],"5196":[{"rank":"2","note":"到達する","exp":"350","type":"港・集落","name":"長崎","desc":"九州北西部に位置する街。海岸線が複雑に入り組んでいるため、古くから港湾都市として発展してきた。\n東アジアやヨーロッパ諸国との交易も盛んな街である。"}],"5258":[{"rank":"3","note":"","exp":"600","type":"海洋生物","name":"ウミヒゴイ","desc":"体長50cmに達することもある魚で、鮮やかな体色が特徴。死んだり驚いたりすると体色が変化し、それゆえに古代ローマ人に珍重されていた。ヒメジの仲間で、身は白身で美味。"}],"6318":[{"rank":"3","note":"","exp":"500","type":"虫類","name":"ブルーアーガス","desc":"東南アジアなどの温暖な地域に生息する美しいチョウ。前後の羽それぞれにある大きな二対の目玉模様が特徴。雄の羽は青いが雌の羽は茶褐色で、目玉模様も雄より大きい。"}],"6392":[{"rank":"2","note":"","exp":"380","type":"地理","name":"ドーバーの白い崖","desc":"ドーバー海峡に面する白い崖。石灰岩でできているため白い。イングランドの玄関口だけでなく要塞としての役割もある。ブリテン島の通称である「アルビオン」は、ラテン語で白色を意味する言葉が語源であり、その由来はこの崖だとされる。"}],"5007":[{"rank":"1","note":"西シベリア平原<br/>コーカサス地方の再調査報酬","exp":"","type":"小型生物","name":"ロシアデスマン","desc":"河川や湿地に生息するモグラ。泳ぎが得意で貝類なども捕食する。毛皮目的の乱獲で生息数が減っている。"}],"915":[{"rank":"2","note":"白鯨","exp":"220","type":"海洋生物","name":"シロナガスクジラ","desc":"大きなもので30mにもなる、巨大なクジラ。体色が白っぽいため、さらに大きく見える。口の様子からすると、小さなエビなどをこしとって食べているようだ。"}],"5190":[{"rank":"2","note":"到達する","exp":"355","type":"港・集落","name":"浦項","desc":"読みは「ポハン」。\n朝鮮半島東岸に位置する。街の近くには、美しい山が広がる。"}],"1799":[{"rank":"1","note":"文字のない格言集","exp":"110","type":"美術品","name":"ネーデルラントの諺","desc":"ピーテル・ブリューゲル（父）の作。ネーデルラントに伝わる諺を90種以上描きこんでいる。例えば右下の粥をこぼしている男性がいる。これは「こぼした粥は器に戻らない」つまりは取り返しのつかないことを意味する諺である。"}],"3626":[{"rank":"3","note":"ローマの歴史書の地図","exp":"490","type":"歴史遺物","name":"ローマ建国史","desc":"四散した資料や文献から再編纂された、ローマ建国史。\n原本とされるリヴィウスの著書は100巻以上あるので、まだまだ足りてはいないようだ。"}],"2666":[{"rank":"3","note":"宮廷医学の書","exp":"480","type":"財宝","name":"東医宝鑑","desc":"許浚により記された、全25巻の医学書。\n道教の影響を受けたこの医学書は、基礎の部分こそ明の李朱医学であるが、朝鮮独自の医学も存分に織り込まれている。今後の医学の発展に大きく寄与するだろう。"}],"1286":[{"rank":"2","note":"古い法典の地図","exp":"240","type":"宗教遺物","name":"華厳経","desc":"けごんきょう。仏教経典のひとつ。仏陀の悟った世界について書かれている。"}],"5784":[{"rank":"3","note":"","exp":"540","type":"気象・現象","name":"火山雷","desc":"火山の噴火によって発生する雷。観測が困難なため、詳細な発生原因や過程は不明。ただし、各国の古い文献にも、その存在は記録されている。"}],"5718":[{"rank":"2","note":"2017.02.07新規追加","exp":"320","type":"気象・現象","name":"火山砕屑物","desc":"火山から噴出された石や泥などの総称。噴火後、空から舞い落ちることがある。火山弾などの場合、周囲に深刻な被害をもたらす可能性がある。"}],"6418":[{"rank":"4","note":"追究クエスト「アザラシの追加調査」<br/>発見物カード:385","exp":"770","type":"中型生物","name":"産毛のアザラシ","desc":"アザラシは、世界中の広い海域に生息している。その中でも、海氷上に生息する種の子供は、白色の産毛を持って生まれるといわれ、とても可愛らしい姿をしている。"}],"1102":[{"rank":"2","note":"「首の長い動物の地図」<br/>発見物カード:155","exp":"310","type":"大型生物","name":"キリン","desc":"アフリカのサバンナ地帯に生息する、背の高い動物。首が非常に長く、頭の高さは5mを超える。ほかの動物が食べられない高い枝の葉を食べているようだ。体には独特の模様があり、頭には短い2本の角がある。"}],"3944":[{"rank":"1","note":"「天文学者の観測記録」<br/>発見物カード:100","exp":"200","type":"天文","name":"こと座の環のような星雲","desc":"こと座にある星雲。中心部がやや暗く、色の違ういくつかの環があるように見える。"}],"2731":[{"rank":"1","note":"朝鮮の遺物の地図","exp":"130","type":"宗教遺物","name":"百済の舎利容器","desc":"仏教が盛んだった百済時代のものと思われる舎利容器。ある寺院に保管されているものは入れ子の設計になっており、青銅の容器の中に銀の容器が、銀の容器の中に金の容器が収められているという。"}],"297":[{"rank":"3","note":"ミケランジェロの絵画","exp":"495","type":"美術品","name":"聖家族","desc":"ミケランジェロ作の絵画。ほかの画家の作品に比べて肉体や衣服が立体的に感じるのは、彼が彫刻を得意とするからだろう。聖母にさほど聖性が感じられないのは、彼の所属している宗派の教義によるものだと思われる。"}],"809":[{"rank":"1","note":"大型のシカの地図","exp":"25","type":"大型生物","name":"トナカイ","desc":"寒冷地に生息する大型のシカ。オスは非常に大きな角を持つ。家畜として飼われているものもいる。"}],"11":[{"rank":"1","note":"アスモダイの宝玉<br/><br/>発見時経験値100　発見物カード経験値50","exp":"100","type":"財宝","name":"アスモダイの宝玉","desc":"聖書のソロモン王が、悪魔や精霊72体を封じ込めたという宝玉の一つ。この宝石にはアスモダイが封じられているという。真偽の程は不明だ。\n宝玉はよく見ると傷があり、「アトランティス」と彫られている。"}],"2572":[{"rank":"3","note":"阿里山の動物調査","exp":"490","type":"鳥類","name":"アリサンヒタキ","desc":"全長12cmほどの小さな鳥。標高の高い山中に生息し、阿里山でよく目撃されることから、この名前が付いた。"}],"6711":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:175<br/>東アジア西部","exp":"350","type":"天文","name":"プレセペ星団","desc":"かに座の甲羅の中央にある星団。名はラテン語で「かいば桶」を意味する。かつては1つの天体だと考えられていたが、ガリレオ・ガリレイが星の集まりだと見抜いた。"}],"1670":[{"rank":"1","note":"虫を捕まえる植物の地図","exp":"75","type":"植物","name":"モウセンゴケ","desc":"温暖な湿原に生息する植物。葉から生えた無数の毛から粘液を分泌する。粘液に虫が引っかかると、葉はゆっくりと収縮し、虫をくるんでしまう。こうして葉に捕らえられた虫は次第に溶けてなくなってしまう。"}],"1891":[{"rank":"2","note":"サルベージ","exp":"310","type":"歴史遺物","name":"コンセイサウン号","desc":"正式名は、ノッサ・セニョーラ・ダ・コンセイサウン号。\nポルトガルの東インド貿易船で、王室の財宝をインドに輸送していた。チャゴス諸島付近で沈没。"}],"1671":[{"rank":"1","note":"書きかけの地図","exp":"140","type":"地理","name":"ビスマーク諸島","desc":"ニューギニア島の北東沖にある諸島。最大の島は、諸島の南部から東部にかけて横たわるニューブリテン島である。島々の多くは火山島であり、噴火による被害も少なくない。"}],"637":[{"rank":"1","note":"クエスト「修道院長の副葬品」<br/>発見物カード:25","exp":"50","type":"美術品","name":"アルペの聖体器","desc":"北フランスのリムザン地方リモージュ出身の細工師・G.アルペが作ったという、祭礼用の器。モンマジュール修道院院長の墓室に納められていたが、あまりに美しいためマルセイユの教会に移されたと伝えられる。"}],"615":[{"rank":"5","note":"思い出に残ったもの","exp":"1144","type":"鳥類","name":"キエリボタンインコ","desc":"赤いくちばしと、目を縁取る白い模様が特徴的。活動する時間のほとんどをつがいで過ごす。種子や果実などを主食とする。"}],"2018":[{"rank":"2","note":"［勅命］[[黄金郷の信仰","exp":"310","type":"宗教遺物","name":"神官の首飾り","desc":"神官のみが着けることを許されるという首飾り。細工が細かく、美術的価値も高いが、信仰的要素が大きい。"}],"588":[{"rank":"1","note":"黒い森の島","exp":"110","type":"地理","name":"スカンジナビア半島","desc":"北海の北にある巨大な半島。西岸には独特の地形が続く。寒冷な気候で冬は厳しい。森林が多いため林業が盛んである。鉱山も多いという。"}],"1522":[{"rank":"1","note":"工芸品のような花の地図","exp":"180","type":"植物","name":"アイス・ブルー","desc":"たくさんの青みがかった白い苞（ほう）を円柱状につけ、工芸品のような美しい形になる植物。高さ1mほどに成長する。"}],"6718":[{"rank":"5","note":"楽の叡智・心に響く楽器　右上","exp":"","type":"財宝","name":"火焔太鼓","desc":"雅楽で用いられる左右一対の大型の太鼓。\nそれぞれ周囲が龍と鳳凰の彫刻で飾られている。鎌倉幕府の初代将軍・頼朝が寄進したとされるものが有名。"}],"5659":[{"rank":"3","note":"","exp":"460","type":"史跡","name":"ギルフ・ケビール","desc":"サハラ東部に位置する砂岩の台地。枯れ川がいくつも走っており、それに沿った岩壁には古代の人々が描いたとされる壁画が残されている。"}],"58":[{"rank":"3","note":"インドのゾウ","exp":"506","type":"大型生物","name":"インドゾウ","desc":"インドに生息するゾウである。体重は5tにもなり、体高は3mに達する。おとなしく力が強いので、古くから飼いならされて運搬などに使役されてきた。オスには大きな牙があるがメスにはないようだ。"}],"1618":[{"rank":"2","note":"奇妙な頭蓋骨の地図","exp":"255","type":"歴史遺物","name":"穴の開いた頭蓋骨","desc":"南米で多く見つかる頭蓋骨。なにかの儀式のときに、死者の頭蓋骨をくりぬいたのか、それとも生きた人間の頭に穴を開けたのだろうか？"}],"3269":[{"rank":"2","note":"クエスト「荒野の砂漠」<br/>発見物カード:195","exp":"390","type":"地理","name":"カラハリ砂漠","desc":"アフリカ南部に大きく広がる砂漠。砂は暗赤褐色であり、水場は少ない。浅い窪地が多く半草原地帯ともいえ、生息動物も多い。"}],"3000":[{"rank":"2","note":"「書きかけの地図」<br/>発見物カード:130","exp":"260","type":"地理","name":"アウター・バンクス","desc":"北米東端に並ぶ半島および砂州の連なり。南北に500km以上も延びている。この周辺海域は二つの海流がぶつかるため、航海は困難を極める。"}],"1278":[{"rank":"2","note":"大帝国の足音","exp":"290","type":"歴史遺物","name":"フビライ・ハンの鞍","desc":"元朝皇帝であるフビライが使っていたという馬の鞍。騎馬民族であるモンゴル人は一般的に木の鞍を使うが、これは長期行軍用になめし革で作られている。"}],"6349":[{"rank":"2","note":"","exp":"300","type":"歴史遺物","name":"大灯台が刻まれたコイン","desc":"古代アレクサンドリアで製造されたコイン。世界七不思議のひとつとされるアレクサンドリア大灯台とともに、広く信仰された航海の守護女神イシスが刻まれたものなど、様々な意匠が凝らされたものがある。"}],"5714":[{"rank":"3","note":"2017.02.07新規追加","exp":"","type":"地理","name":"チョモランマ","desc":"何物をも拒む急峻さを持つ、巨大な山。神ならぬ身である人間が、その頂を制覇するのは、いつになるだろうか。"}],"411":[{"rank":"2","note":"奇妙なカエル","exp":"220","type":"小型生物","name":"ツメガエル","desc":"アフリカ南部に生息する、独特の姿をしたカエル。黒い爪があり、目が小さく埋まっていて、一般的なカエルとはかなり異なった容姿をしている。暑さが厳しい時期は、土に潜って夏眠する。"}],"756":[{"rank":"3","note":"青い宝石の鉱脈の地図","exp":"595","type":"財宝","name":"ブルーダイヤ","desc":"青いダイヤモンド。美しい青のダイヤは非常に希少で、めったに出ない。"}],"3669":[{"rank":"4","note":"ダンジョン","exp":"710","type":"歴史遺物","name":"クレオパトラの像","desc":"プトレマイオス朝最後のファラオとなったクレオパトラのものと思われる石像。プトレマイオス朝を滅ぼしたアウグストゥスが神殿を改修した際に撤去されたようだ。"}],"578":[{"rank":"2","note":"豪華な衣装の来歴","exp":"360","type":"歴史遺物","name":"チャンドラグプタ王の剣","desc":"グプタ朝第3代、別名「超日王」と呼ばれるチャンドラグプタ2世の剣。軍事力と政略結婚により、インドをほぼ統一した。"}],"1641":[{"rank":"5","note":"マール・パシフィコ","exp":"1053","type":"地理","name":"太平洋","desc":"マゼラン海峡を抜けたマゼランが、「大西洋とは比べ物にならない穏やかな海だ」といったことから名づけられた海。\nその広さは、マゼランが航海した当時の予測よりはるかに広大である。"}],"303":[{"rank":"1","note":"クエスト「もう一枚のバベルの塔」<br/>発見物カード:85","exp":"170","type":"美術品","name":"バベルの塔（小）","desc":"ピーテル・ブリューゲル（父）作の、もう一枚のバベルの塔の絵。大きな絵と違い、建築の様子は描かれていない。なぜか全体が強い赤で描かれており、神の怒りで砕かれる前触れを思わせる。"}],"1919":[{"rank":"5","note":"釣り","exp":"910","type":"海洋生物","name":"ブラックマーリン","desc":"シロカジキ。太くて短いクチバシを持つ大型のカジキ。"}],"952":[{"rank":"2","note":"復活したイエスの彫刻","exp":"290","type":"美術品","name":"キリストの復活","desc":"ジェルマン・ピロン作の大理石像。処刑後、復活したキリストの姿を表したもの。本来は数体の彫像からなる作品のはずだが、未完成のままだという。"}],"5813":[{"rank":"2","note":"","exp":"300","type":"地理","name":"ボスジラ","desc":"ウスチュルト台地に存在する奇妙な形をした岩山。「白い谷」という意味。石灰に守られた白い層と、そうでない層とが存在する。"}],"5345":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:315","exp":"310","type":"天文","name":"たて座","desc":"1684年にポーランドの天文学者ヘヴェリウスが国王ヤン3世ソビエツキを称えて作った星座。ヤン3世は第二次ウィーン包囲戦で活躍して勇名を馳せた。いて座の北西にある。"}],"3182":[{"rank":"3","note":"赤茶色の台地","exp":"450","type":"地理","name":"グロスモーン山","desc":"北米北東部沿岸の、テラ・ノヴァ西部に位置する標高約800mの山。島の傍らを流れる寒流の影響で気温が低く、高山植物が生息する。"}],"749":[{"rank":"2","note":"西海域の治安","exp":"360","type":"地理","name":"カリブ海","desc":"北米大陸と南米大陸の間に広がる海域。多くの島が浮かんでおり、人々は豊かな自然に恵まれて暮らしている。欧州やアフリカ、インドとはまったく異なる生態系を持つ。"}],"1161":[{"rank":"3","note":"硬い守り","exp":"473","type":"中型生物","name":"アルマジロ","desc":"頭から背中、尾にかけての皮膚が鎧のように変化している動物。危険を感じると丸くなり外敵の牙や爪から身を守れるようだ。大きさや模様がさまざまだが別種なのか個体差なのかは不明だ。"}],"418":[{"rank":"1","note":"奇妙な石の地図","exp":"30","type":"化石","name":"不気味な花の石","desc":"気味の悪い植物のような模様がある石。形がぐにゃぐにゃしていて筋が入っている。こんな花は見たことがないが、どこかに生えているのだろうか？"}],"594":[{"rank":"1","note":"黒海へそそぐ川","exp":"180","type":"地理","name":"ドナウ川","desc":"ヨーロッパを貫く大河で、黒海に注ぐ。全長は3000km近いともいわれる。古くから交易や軍事に使われ、流域には多くの都市が発展している。"}],"1721":[{"rank":"1","note":"釣り","exp":"160","type":"海洋生物","name":"カウアイ","desc":"アオテアロアの近海に生息する魚。スズキとサケの合いの子のような姿をしている。大きいものは全長で90cm程になる。身は厚く脂がのっていて美味。"}],"2899":[{"rank":"2","note":"大きなヒツジの地図","exp":"250","type":"中型生物","name":"アルガリ","desc":"中国を中心に、主に高原地帯に生息する、体長120cm前後の大型のヒツジ。\n雌雄共に角を持ち、雄の角は1mを超すほどの長さにまで成長する。"}],"5031":[{"rank":"2","note":"到達する","exp":"242","type":"港・集落","name":"カイエンヌ","desc":"南米大陸北東沿岸に位置する港町。年間を通じて温暖だが、雨量が多い。"}],"582":[{"rank":"1","note":"豪華な武器の地図","exp":"59","type":"財宝","name":"祭事用の短剣","desc":"祭事に用いられたと思われる短剣。宝石や金の豪華な装飾が施されており、実用性は低そうである。"}],"6895":[{"rank":"5","note":"発見物カード:605","exp":"1210","type":"海洋生物","name":"ナガスクジラ","desc":"クジラの仲間の中ではシロナガスクジラの次に大きく、体長は20mを越える。背中から尾にかけては暗灰色で、腹は白く、いくつもの畝がある。下顎の左右で色が異なり、独特の模様を成す。遊泳速度は時速35kmに達することもあるという。"}],"1496":[{"rank":"2","note":"統一と教化","exp":"230","type":"宗教遺物","name":"イェリング石碑","desc":"10世紀にデンマーク王であるハーラル青歯王によって建立された石碑。石碑にはハーラル青歯王のデンマーク統一とノルウェー獲得、さらにデーン人をキリスト教に改宗させた偉業がルーン文字によって記されている。"}],"1921":[{"rank":"2","note":"釣り","exp":"350","type":"海洋生物","name":"セミホウボウ","desc":"美しく大きな胸びれを持つ魚。その胸びれで滑空するように泳ぐ。"}],"3178":[{"rank":"4","note":"語りの地、その手がかり","exp":"780","type":"財宝","name":"グリーンランド人のサガ","desc":"エイリーク達のグリーンランド入植と、その子ども達やソルフィンの西方探索を描いた物語。赤毛のエイリークのサガを元にした部分が見られる。赤毛のエイリークのサガに比べて、やや誇張が多い点が大きな違いである。"}],"996":[{"rank":"1","note":"冒険者のバイブル","exp":"55","type":"財宝","name":"東方見聞録","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。"}],"3624":[{"rank":"5","note":"伝説との出会い","exp":"950","type":"中型生物","name":"シベリアンハスキー","desc":"シベリアや北米の寒冷な地域で生育する大型犬。豊かな毛並みで寒さに強い。従順で頭が良く、体力にも優れているため、狩猟や運搬など、人間の活動の中で活躍している。"}],"5941":[{"rank":"2","note":"","exp":"320","type":"地理","name":"聖アンデレ島","desc":"アフリカ西部を流れる川に位置する島。入植したヨーロッパ人が要塞を建造し、貿易拠点として発展した。その領有をめぐって様々な国が争い、所有国が変わるたびに名を変えた。"}],"6456":[{"rank":"5","note":"追究クエスト","exp":"","type":"史跡","name":"蛇の頭が置かれた神殿階段","desc":"「チチェンイッツァ」の神殿にある階段の再下段にはマヤの最高神であるククルカンの頭部の彫刻がある。春分の日と秋分の日には、ピラミッドの影が階段に映り、うねったククルカンの胴体のように見える神秘的な現象が見られるという。"}],"1489":[{"rank":"1","note":"角のあるカエルの地図","exp":"105","type":"小型生物","name":"ツノガエル","desc":"幅の広い口と目の上にある角状の突起物が特徴。体の一部を地中に埋め、獲物を待ち伏せする。繁殖期には、ウシのような声で鳴いてメスを求める。"}],"1314":[{"rank":"1","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40","type":"宗教遺物","name":"聖母のステンドグラス","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。"}],"1560":[{"rank":"1","note":"変わった太鼓の地図","exp":"150","type":"財宝","name":"スリットドラム","desc":"中身をくりぬいた木を叩いて音を出す楽器。世界のどこでも見られる。ニューギニアのスリットドラムは祭りの演奏や仲間への合図に用いられるようだ。"}],"6320":[{"rank":"2","note":"","exp":"370","type":"中型生物","name":"インドオオコウモリ","desc":"果汁を主食とする大型のコウモリ。飛ぶ時は視覚に頼るため目が大きい。横から見た顔がキツネに似ていることから「空飛ぶキツネ」とも呼ばれる。"}],"5472":[{"rank":"1","note":"発見時経験値120　発見物カード経験値60","exp":"120","type":"小型生物","name":"パカ","desc":"中南米に生息している体長60～80cmの動物。体は明るい赤茶色で、両脇には薄い点線が並んでいる。\nずんぐりとした体型だが、俊敏で泳ぎがうまい。"}],"4863":[{"rank":"3","note":"クエスト「海の角」<br/>発見物カード:265","exp":"530","type":"史跡","name":"ボルシッパ","desc":"シュメール文明の古代都で、名前は「海の角」という意味。「舌の塔」と呼ばれる大規模なジッグラトの遺跡があり、バベルの塔の遺跡であると考えられている。"}],"5476":[{"rank":"1","note":"大型のシカの地図<br/><br/>発見時経験値100　発見物カード経験値50","exp":"100","type":"大型生物","name":"アメリカヌマジカ","desc":"パンタナル湿原でよく見られる動物。\n南米に生息するシカの中で最も大きいといわれている。\n二本に枝分かれした太い角は最長で約60cmにもなる。"}],"6967":[{"rank":"4","note":"発見物カード:325","exp":"650","type":"中型生物","name":"アカオザル","desc":"アフリカ中部の熱帯雨林などに広く生息するサル。鼻先にハート形の白い毛を持つ黒い顔と、体長の倍におよぶこともある赤茶色の尾が特徴。尾の色が名前の由来とされている。"}],"6662":[{"rank":"2","note":"リスボン南西沖","exp":"","type":"歴史遺物","name":"ペッパーレック","desc":"ポルトガルの交易船。インド産のコショウを積んでいた。インド航路開拓後、多くの交易商が香辛料を求めインドへ出航したという。ペッパーレックもその1隻だったのだろう。17世紀初頭、リスボン付近を流れるテージョ川の河口で難破。"}],"910":[{"rank":"1","note":"白い花の地図","exp":"43","type":"植物","name":"マドンナリリー","desc":"筒状の美しい花が咲く植物。香りが強い。白いユリは、キリスト教の祭礼で使われる。花粉が服につくと、なかなか取れない。"}],"1711":[{"rank":"1","note":"拍子木の地図","exp":"160","type":"財宝","name":"クラップスティック","desc":"オーストラリア先住民が儀式のときに、ディジュリドゥの合いの手として鳴らす拍子木。ディジュリドゥを伴奏にクラップスティックを両手に持った歌い手が儀式の歌を歌い上げる。"}],"6738":[{"rank":"5","note":"カード経験:520","exp":"1040","type":"中型生物","name":"タイワンヤマネコ","desc":"台湾島の固有種とされるヤマネコ。耳の先が丸く後ろには白い斑点がある。日本のイリオモテヤマネコとは非常に種が近い。獲物を捕らえると前足で叩いて弱らせる習性を持つ。"}],"2952":[{"rank":"3","note":"大陸の内側へ","exp":"540","type":"地理","name":"セントローレンス川","desc":"北米内陸から東岸へと流れ出る大河。川幅がとても広く、川の途中には大小様々な島が浮かぶ。"}],"3760":[{"rank":"4","note":"天の牡牛","exp":"720","type":"天文","name":"おうし座","desc":"黄道十二星座の1つ。ゼウスがエウロペに近づくために変身した牡牛とされる。古代メソポタミアでは天の牡牛と呼ばれていた。1等星アルデバランは牡牛の目にあたる。"}],"6692":[{"rank":"2","note":"「変わった鳥の地図」<br/>発見物カード:115","exp":"230","type":"鳥類","name":"アカアシカツオドリ","desc":"インド洋、大西洋、太平洋の熱帯および亜熱帯の海域に分布する海鳥。群れを形成して生活する習慣がある。眼の周囲の青みがかった灰色の皮膚と、真っ赤な足が特徴。"}],"562":[{"rank":"1","note":"古代文明の伝説","exp":"20","type":"地理","name":"サントリニ島","desc":"クレタ島のカンディアから北北東にある小さな島である。中央に火山があり、はるか昔に大噴火を起こしたと伝えられている。伝説の古代文明・アトランティスがあったという説もある。"}],"2442":[{"rank":"4","note":"ダンジョン","exp":"640","type":"宗教遺物","name":"戦勝の碑","desc":"古代エジプトのファラオであるラムセス2世が、戦勝の記念として残した碑。\nカデシュの戦いをはじめ、数多くの戦争にあけくれた人物に似つかわしい遺物である。"}],"249":[{"rank":"1","note":"クエスト「バレアレス諸島の地形調査」<br/>発見物カード:10","exp":"20","type":"地理","name":"メノルカ島","desc":"バレアレス諸島東部の島。西の大きな島はマジョルカ島という。名の由来は、スペイン語のマヨール（大きい）とメノール（小さい）である。気候がよく、静かな島である。"}],"2882":[{"rank":"3","note":"クエスト「不老不死を求めて」<br/>発見物カード:240","exp":"480","type":"地理","name":"青城山","desc":"重慶付近の山の一つで道教の発祥地。\n樹齢の古い木々が多く一年を通して緑に覆われていることから、この名前が付いたといわれる。"}],"5053":[{"rank":"1","note":"到達する","exp":"43","type":"港・集落","name":"コッコラ","desc":"ボスニア湾中央に面するフィンランドの街。グスタフ2世アドルフが築いた。工業品取引のための港だったが、やがて造船の重要拠点となって繁栄した。"}],"581":[{"rank":"1","note":"豪華な武器の地図","exp":"53","type":"財宝","name":"さびた宝剣","desc":"刃がさびついてしまった宝剣。宝石や金で装飾が施されている。刃はそれほどよいものではないので、装飾用だと思われる。"}],"1831":[{"rank":"2","note":"羽根が生えた魚","exp":"350","type":"海洋生物","name":"ビキール・ビキール","desc":"円筒形で鱗に覆われたヘビのような体に、15本程の羽状の背びれ、大ぶりな尾びれ、前ひれを持つ。体長1m程で茶褐色や深緑のまだらな体色が多い。熱帯アフリカの河川、及びナイル川で稀に目撃される。"}],"1659":[{"rank":"1","note":"書きかけの地図","exp":"110","type":"地理","name":"プレンティ湾","desc":"アオテアロアの北部にある湾。東西に岬を持ち、波は穏やかで、魚も豊富に獲れる。"}],"154":[{"rank":"1","note":"コブのある動物の地図","exp":"11","type":"大型生物","name":"ヒトコブラクダ","desc":"背中のコブが一つのラクダ。家畜として飼われ、乗用や荷役などに使われる。砂漠地帯では必要不可欠な動物である。"}],"3305":[{"rank":"2","note":"クエスト「模様の鳥」<br/>発見物カード:200","exp":"400","type":"鳥類","name":"シマセゲラ","desc":"北米の東部に生息するキツツキの一種。体長は25cm程度。背中の白と黒の縞模様と、頭頂部の鮮やかな朱色が目を引く。"}],"5167":[{"rank":"2","note":"到達する","exp":"327","type":"港・集落","name":"ヤーデイン","desc":"メコン川流域に建設された街。長くチェンラ王国の支配を受けてきた。川の上流にはチェンラ王国の古都があるといわれている。"}],"3384":[{"rank":"5","note":"クエスト「旧約聖書の逸話の元」<br/>発見物カード:530","exp":"1060","type":"史跡","name":"チョガ・ザンビール","desc":"古代エラム人が築いた宗教的中心地の遺構。連結した壁で三層に仕切られており、その最も内側にはジッグラトが建てられている。保存状態がかなり良いという特徴がある。"}],"5404":[{"rank":"3","note":"「天文学者の観測記録」<br/>発見物カード:220","exp":"440","type":"天文","name":"りゅうこつ座","desc":"全天で2番目に明るい星、カノープスを含む星座。ギリシャ神話に登場するアルゴ船の竜骨に例えられる。"}],"519":[{"rank":"1","note":"古代の祭祀場の地図","exp":"53","type":"宗教遺物","name":"古代の祭壇","desc":"祭祀を行うための台。文明や宗教によってさまざまなものがある。"}],"2740":[{"rank":"1","note":"貴重な書物の地図","exp":"160","type":"財宝","name":"朝鮮経国典","desc":"経国大典より以前に使用されていたという法典。\n鄭道伝はこの法典を記すことで、朝鮮王朝の法制の基礎を作った。"}],"6401":[{"rank":"5","note":"レガシー：砂漠に栄えた巨石文明","exp":"2250","type":"宗教建築","name":"屈折ピラミッド","desc":"クフ王の父であるスネフェル王のピラミッドと伝わる。横から見ると頂上へ向かう角度が途中から緩やかになっている。同時期に作っていたピラミッドが完成直前に崩壊したため対策として途中から屈折させたという説も。"}],"1972":[{"rank":"2","note":"白い鳥の地図","exp":"210","type":"鳥類","name":"カグー","desc":"ニューカレドニアに生息する鳥。危険を感じると冠羽を逆立て、翼を広げて、敵を威嚇する。大きな翼を持っているが、飛ぶことはできない。"}],"319":[{"rank":"3","note":"ラファエロの聖母子画","exp":"440","type":"美術品","name":"聖母子と聖ヨハネ","desc":"ラファエロ作の絵画。別名があり、「美しき女庭師」という。由来は、聖母子の背景に描かれた美しい田園風景であろう。柔らかな筆致の名作である。"}],"2957":[{"rank":"3","note":"船を守護する木","exp":"440","type":"植物","name":"メイフラワー","desc":"ヨーロッパから北アフリカにかけて広く分布する植物。セイヨウサンザシとも呼ばれる。五月ごろ、五枚の花弁を持つ花を咲かせる。"}],"3599":[{"rank":"4","note":"キエフ大公国の全盛期","exp":"640","type":"歴史遺物","name":"ウラジーミル1世の金貨","desc":"キエフ大公国を治めたウラジーミル1世の肖像と紋章が彫られた金貨。ウラジーミル1世は、東ローマ帝国皇帝バシレイオス2世の妹と結婚し、キエフ大公国の権威を大きく高めるなど、政治的手腕に優れていた。"}],"4796":[{"rank":"1","note":"書きかけの地図","exp":"80","type":"地理","name":"キラウエア火山","desc":"ハワイ島東南部の活火山。活発で溶岩が頻繁に出ているため、現地の言葉の中では、山名が「散発」している。"}],"6385":[{"rank":"5","note":"","exp":"980","type":"財宝","name":"カール大帝の指輪","desc":"カール大帝を魅了したと噂される指輪。もともとはカール大帝の愛人のひとりが身につけていたとされる。指輪を身につけると不思議な魔力で、相手を魅了するという言い伝えがある。"}],"1764":[{"rank":"1","note":"アフリカの神像の地図","exp":"140","type":"宗教遺物","name":"ノンモ像","desc":"ノンモとは、アフリカ北西部に居住する民族ドゴンの地上における創造神のことである。上半身は人間、下半身は蛇の姿で描かれる。"}],"6778":[{"rank":"5","note":"カード経験値　540","exp":"1080","type":"史跡","name":"カルマル城","desc":"12世紀、スウェーデンのカルマルに建てられた城。周囲を海に囲まれており、正面の門から伸びる1本の橋で。陸地と繋がる。1397年カルマル同盟がここで結ばれた。"}],"1533":[{"rank":"2","note":"釣り","exp":"260","type":"海洋生物","name":"ホオジロザメ","desc":"巨大な体と凶暴さで恐れられる海の暴君。人喰いザメとしても恐れられる。"}],"6724":[{"rank":"2","note":"「天文学者の観測記録」 アイスランド海盆視認<br/>発見物カード:145<br/>    <br/>    <br/>※特定できないが前提ある可能性高そう。「きりん座」「キリン：大型生物」だけではなさそうです。","exp":"290","type":"天文","name":"きりん座の渦巻星雲","desc":"きりん座にある渦巻のような形をした星雲。キリンの前足辺りに位置する。"}],"931":[{"rank":"1","note":"美の女神の像","exp":"60","type":"宗教遺物","name":"アフロディテ像","desc":"ギリシャ神話の、愛と美の女神の像。ローマ神話ではヴィーナスという。ギリシャ神話でトロイ戦争はアフロディテとアテナとヘラの争いから端を発したと伝えられる。"}],"2042":[{"rank":"2","note":"希少な医学書","exp":"360","type":"財宝","name":"医学全書","desc":"アル・ラージーが著した医学知識についての百科事典。\nギリシャやアラビア、インドの医学の集大成に、著者の経験と意見を加えてあるようだ。外科医療道具についても記されている。"}],"1719":[{"rank":"2","note":"釣り","exp":"250","type":"海洋生物","name":"アカマンボウ","desc":"熱帯、温帯の海に広く分布する。2mを超える円盤形の大きな体をしている。"}],"7007":[{"rank":"3","note":"","exp":"","type":"美術品","name":"レパントの海戦の寓意","desc":"パオロ・ヴェロネーゼ作の油彩画。絵画の下部にはレパントの海戦が、上部には聖母のもとに集った聖人が連合艦隊に祝福を与える様子が描かれている。聖母の前に跪く女性は、ヴェネツィアの擬人像とされる。"}],"5551":[{"rank":"3","note":"","exp":"600","type":"植物","name":"ヒドノラ・アフリカーナ","desc":"アフリカ南部の乾燥地帯に生息する植物。光合成するための葉がないため、他の植物の根に寄生し、養分や水分のすべてを奪って生きる植物である。"}],"1110":[{"rank":"1","note":"手足の長いサルの地図","exp":"75","type":"中型生物","name":"クモザル","desc":"黒っぽい体色で、手足と尾がとても長いサルである。手足と尾を使い、木から木へ飛び移る姿は大きなクモのようだ。サルは手が人間に似ていて器用なものが多いが、このサルは親指がない。"}],"6185":[{"rank":"5","note":"禁域に関する伝承","exp":"1480","type":"伝承","name":"燃える柴","desc":"神がみずからの領域を示すために、時折人に見せるという現象。創世記ではケルビムに持たせたという「回る炎の剣」、出エジプト記では「燃える柴」と神の使いに関する記述があり、神が示す境界線として炎が用いられる例は多い。"}],"6954":[{"rank":"4","note":"発見物カード:350","exp":"700","type":"宗教建築","name":"ウナス王のピラミッド","desc":"古代エジプトの王、ウナスのピラミッド。規模は小さく、石材の持ち出しや、風化などにより、大半が崩れている。内部には死者の書の基礎となった「ピラミッド・テキスト」と呼ばれる最古の葬送碑文が刻まれている。"}],"1158":[{"rank":"2","note":"メガネをかけた生物","exp":"275","type":"鳥類","name":"メガネフクロウ","desc":"目を縁取る白い羽毛が眼鏡のように見える。止まり木から、地面や葉むらにいる獲物に一気に襲いかかり捕食する。"}],"6406":[{"rank":"5","note":"","exp":"","type":"宗教建築","name":"キュロス2世の墳墓","desc":"アケメネス朝ペルシャの初代国王であり大帝国を築いたキュロス2世の墓と伝わる遺跡。切石を階段状に積んだ基壇の上に、石造りの巨大な家型墓室が載っている。のちにこの形に倣ったと思われる巨大建築が造られた。"}],"860":[{"rank":"2","note":"天国のような無人島","exp":"320","type":"地理","name":"セーシェル諸島","desc":"アフリカとインドの間に点在する諸島。島の数は100を超える。サンゴ礁が多くとても美しい島々だが、その半分は淡水が得られないため人が住めない。"}],"1749":[{"rank":"5","note":"天空の王者<br/><br/>発見時経験値1163　発見物カード経験値581","exp":"1163","type":"鳥類","name":"ハルパゴルニスワシ","desc":"アオテアロアに生息している大型のワシ。\n大きなものになると、広げた翼が3mにもなりワシの中でも傑出した体躯を誇っている。\nモアを主食にしているようだ。モアの減少に伴い、数が減っているらしい。"}],"5042":[{"rank":"1","note":"到達する","exp":"7","type":"港・集落","name":"カレー","desc":"ドーバー海峡に面する北フランスの街。過去に幾度もイングランドとフランスの争いの種となり、頑強な要塞都市となった。産物は加工食品のほかに香料、高級織物などがある。"}],"74":[{"rank":"1","note":"インド洋の島","exp":"150","type":"地理","name":"コモロ諸島","desc":"マダガスカル島の北端とアフリカ大陸の間にある諸島。中世からアラブの勢力が進出していた。気温が高く、雨季と乾季があるため森林は少ない。独特の動植物が見られる。"}],"906":[{"rank":"1","note":"白い花の地図","exp":"12","type":"植物","name":"カスミソウ","desc":"白い花が群れて咲く植物。これだけでも可憐で愛らしい花だが、花束に加えるととても見栄えがするだろう。"}],"5596":[{"rank":"2","note":"文化貢献度15","exp":"230","type":"気象・現象","name":"オーロラ","desc":"北極や南極の周辺で光の帯もようなものが観測される現象。\n色は薄い黄色のようなものから赤いものまでさまざまである。\n遥か昔から空に浮かぶ光についての伝説があるが、もしかするとこの現象が関係しているのかもしれない。"}],"6410":[{"rank":"2","note":"","exp":"320","type":"気象・現象","name":"アーチ雲","desc":"雲がアーチ状になっている現象。積乱雲から吹き出した冷たい空気と温かい空気が衝突した部分にできる。アーチ雲が発生した場合、強い突風や雷雨が発生することが多い。"}],"2329":[{"rank":"2","note":"平和を願う軍記物語","exp":"360","type":"財宝","name":"太平記","desc":"日本における南北朝の動乱を題材としている物語。軍記物であるため合戦の記述が多い。当時の社会の風潮に対し、批判的な立場が取られている。"}],"912":[{"rank":"1","note":"白い鳥の地図","exp":"31","type":"鳥類","name":"ペリカン","desc":"下のくちばしに大きな袋を持つ水鳥。かなり大型である。くちばしの袋は、捕らえた魚を貯めるのに使うのだろうか。"}],"2888":[{"rank":"2","note":"緑色の虫の地図","exp":"250","type":"虫類","name":"アオマツムシ","desc":"中国南部に生息している虫。一生のうち一度も地上に降りないといわれる。\n樹木の葉の上や飛んでいるところをよく見かける。"}],"6084":[{"rank":"2","note":"古代エジプト遺物の地図","exp":"300","type":"歴史遺物","name":"アマルナ文書","desc":"古代エジプトの外交文書アメンホテブ4世がファラオだった時代のもの。近隣諸国のエジプトが支配する国の高官たちからファラオに宛てた外交文書籍が多くその大半は当時の公用語であったアッカド語で\n書かれている"}],"2358":[{"rank":"4","note":"クエスト「堺の評判」<br/>発見物カード:390","exp":"780","type":"財宝","name":"宣教師の書簡","desc":"ポルトガル人宣教師である、ガスパル・ヴィレラが書いた書簡。\n堺という日本の港街について、ヴェネツィアのようだと評する記述が見られる。"}],"6589":[{"rank":"2","note":"紅海で発見。セイラ付近。アデンからスエズへの委任航海中","exp":"340","type":"海洋生物","name":"ソハールタング","desc":"紅海やペルシャ湾海域に生息する魚。魚体は楕円形で頭が小さく、尾に短剣のような鋭い棘がある。鮮やかな色の珊瑚礁に棲む。"}],"1147":[{"rank":"2","note":"［勅命］[[新大陸進出の脅威","exp":"280","type":"大型生物","name":"ボア","desc":"草原から森林まで幅広い環境に棲む大蛇。鳥や大型のトカゲを襲うとき、太い胴で獲物を窒息させてから丸ごと飲み込む。"}],"6132":[{"rank":"2","note":"","exp":"240","type":"財宝","name":"プサルテリウム","desc":"薄い台形の共鳴箱に24本の弦を張った楽器。指や羽根、ばちで演奏する。古代ギリシャの楽器プサルテリオンが中東からヨーロッパへと伝わったものと考えられる。ビンゲンのヒルデガルトも、師である修道女から演奏法を習っていた。"}],"6024":[{"rank":"5","note":"","exp":"1230","type":"化石","name":"奇妙なエビの石","desc":"北米北西部のバージェス頁岩から見つかった奇妙な石。エビの腹部のようでもあり、なんらかの生物の触手のようにも見える。"}],"6157":[{"rank":"5","note":"","exp":"1480","type":"伝承","name":"海坊主","desc":"夜の海に現れ、船を破壊するとされる怪物。主には黒い坊主頭\nの巨人だとされる。伝承によって様々な形、大きさがあり、\n行動も異なる。海坊主が現れた後は、天候が荒れ、船が沈む\nなどの怪異が起きるといわれている。"}],"184":[{"rank":"1","note":"セウタの仮面の噂","exp":"30","type":"宗教遺物","name":"祭礼用マスク","desc":"祭礼で使われる仮面。威厳を持たせるためか奇妙な表情だ。鳥の羽や色石などで美しく飾られている。"}],"360":[{"rank":"3","note":"王の還る地","exp":"506","type":"歴史遺物","name":"アレクサンドロス大王の鎧","desc":"マケドニアの王にして地中海からペルシャまでの巨大な版図を築いた、アレクサンドロス大王の鎧。エジプトやペルシャの宝石を使った、豪奢な造りだ。"}],"2812":[{"rank":"3","note":"祭に関する疑問","exp":"480","type":"財宝","name":"獅子舞","desc":"楽に合わせ、獅子に扮して舞い踊る、伝統的な民間芸能。\n唐代に広く発展し、現在では新年を迎える日などに人前で披露される。"}],"614":[{"rank":"1","note":"姿の見えないファラオ","exp":"180","type":"歴史遺物","name":"クフ王の象牙の像","desc":"ギザの第1ピラミッドの主である、クフ王の姿を彫った象牙の小さな像。クフ王の姿を表した物は、ほかに見つかっていない。"}],"3295":[{"rank":"5","note":"巨人の積み上げた石","exp":"820","type":"史跡","name":"巨人のテーブル","desc":"バレン高原に存在する古代史跡。新石器時代に建てられた墓だと思われる。この巨大な岩を、どのように運んだのだろうか…。"}],"6583":[{"rank":"1","note":"(2300, 3825)","exp":"175","type":"港・集落","name":"マナーマ","desc":"ペルシャ湾に浮かぶ、バーレーン島北東の都市。その立地から、海上交通の拠点として栄えた。近海で採れる真珠は非常に高品質であり、ヨーロッパでも珍重される。"}],"377":[{"rank":"2","note":"海に棲むカメの地図","exp":"250","type":"海洋生物","name":"タイマイ","desc":"やや小型のウミガメ。上のくちばしがタカのように曲がっている。甲羅は東洋で細工に使われるという話だ。"}],"1534":[{"rank":"2","note":"釣り","exp":"250","type":"海洋生物","name":"アオザメ","desc":"外洋に生息し、高速で泳ぎ獲物を捕らえる。人喰いザメとしても恐れられる。"}],"413":[{"rank":"1","note":"奇妙な石の地図","exp":"28","type":"化石","name":"巨大な卵の形の石","desc":"まるで卵のような、奇妙な石。殻もあり、本当に卵のようだ。しかし、こんなに大きな卵を産む生物はいない。ドラゴンの卵だとでもいうのだろうか。"}],"5":[{"rank":"2","note":"アケメネス朝の黄金時代","exp":"380","type":"歴史遺物","name":"ダレイオス1世の兜","desc":"アケメネス朝ペルシャ第3代の王、ダレイオス1世の兜。近隣諸侯の反乱を制圧し、ペルシャを大国に育てた。ペルセポリスの建造を始めたのもこの王である。"}],"1627":[{"rank":"2","note":"珍しい鳥はいないか<br/><br/>発見時経験値320　発見物カード経験値160","exp":"320","type":"鳥類","name":"オカメインコ","desc":"長い冠羽と眼の下にあるオレンジ色の毛が特徴の鳥。冠羽は状況により立ったり寝たりする。"}],"2384":[{"rank":"2","note":"小さな毛玉","exp":"270","type":"小型生物","name":"ヤマネ","desc":"日本にのみ生息する、6～8cmのネズミのような小動物。集団で冬眠し、その期間は半年近くにも及ぶ。\n敵に襲われると尻尾の毛を残して逃げるが、抜けた毛が再生することはない。"}],"263":[{"rank":"1","note":"フランス西部の湾","exp":"20","type":"地理","name":"ガスコーニュ湾","desc":"フランスの西部に広がるビスケー湾の、南東部である。イスパニアとフランスの国境に接している。"}],"6324":[{"rank":"2","note":"","exp":"350","type":"中型生物","name":"スカンク","desc":"北米から南米にかけて広く生息する動物。白と黒の体毛が特徴。危険を感じると警告の体勢を取り、最終手段として悪臭の分泌液を肛門から出す。射程は5mほど。臭いに鈍感な猛禽類には効果が薄く、捕食されてしまう。"}],"2320":[{"rank":"2","note":"僧侶の行方","exp":"330","type":"地理","name":"高野山","desc":"紀伊山地を形成する、山々の一つ。\n平安時代、空海が修行したとされる。「山」と呼ばれるが、山そのものの名ではないとのこと。\n日本仏教における聖地とされ、現在も修行のために多くの僧侶が訪れるらしい。"}],"1273":[{"rank":"3","note":"新たな技法","exp":"462","type":"美術品","name":"赤いターバンの男の肖像","desc":"ヤン・ファン・エイク作。諸説あるが、エイク本人を描いたものといわれている。彼はそれまでの画法を改良して、この絵のように細部まで描き込むことを可能にし、深く多彩な光陰を表現することに成功した。"}],"1316":[{"rank":"1","note":"書きかけの地図","exp":"160","type":"地理","name":"スンダ海峡","desc":"スマトラ島とジャワ島の間に横たわる海峡。海峡の幅はとても狭いため、航行は困難を極める。周囲には火山島を含む多くの小島が点在する。"}],"1950":[{"rank":"1","note":"鮮やかな花の地図","exp":"160","type":"植物","name":"ジャカランダ","desc":"南米の熱帯に原生する紫色の花の木。大きいものは15mにもなる。開花の頃には木全体が薄紫になる程、多くの美しい花を咲かせる。花名はスペイン語で、「楽しい歌」の意味。"}],"3641":[{"rank":"4","note":"遊牧民たちの住居","exp":"730","type":"歴史遺物","name":"ゲル","desc":"遊牧民が用いる、木と布でできた移動式の住居。ザナドゥ内で見られる。円形に組んだ骨組みの上に布をかける仕組みで、分解と組み立てが簡単に行える。"}],"5833":[{"rank":"5","note":"","exp":"1370","type":"財宝","name":"ショファール","desc":"雄のヒツジの角から作られた角笛。旧約聖書にも登場する。"}],"3922":[{"rank":"3","note":"島の星座","exp":"470","type":"天文","name":"さんかく座","desc":"シチリア島の守護神で農業を司る女神ケレスがゼウスに頼んでシチリアの形を天に上げた星座とされる。小さい星座で明るい星はないが周囲に明るい星がなく見分けやすい。"}],"6026":[{"rank":"4","note":"","exp":"720","type":"歴史遺物","name":"ヒュパティアの著作","desc":"ローマ帝国末期の女性ヒュパティアの著作の断片。彼女は学術都市アレクサンドリアで優れた学者として活動したとされるが、暴徒化したキリスト教徒に殺され、その著作のほとんどが失われた。"}],"6861":[{"rank":"2","note":"発見物カード:155","exp":"310","type":"天文","name":"ヴィンデミアトリックス","desc":"おとめ座のイプシロン星。３等星で、この星座の恒星の中ではポリマについで３番目に明るい。名はラテン語で「ぶどうを摘む女」を意味し、ギリシャ語を語源としている。"}],"2083":[{"rank":"3","note":"洞窟で見た恐怖","exp":"500","type":"史跡","name":"手形で描かれた壁画","desc":"先住民によって作られた洞窟壁画。「多くの手の洞窟」という意味を持つ。\n赤い顔料によって残された手形の他に、この近辺で見られる野生動物を模した絵も一緒に描かれている。"}],"6465":[{"rank":"5","note":"","exp":"1680","type":"虫類","name":"脱皮したチリアンコモン","desc":"「チリアンコモン」の脱皮直後のとても美しい姿。過酷な地に生息しているため丈夫で強いクモで、毒を持つが比較的おとなしい性質ということもあり、飼育しやすい生物といわれる。脱皮前などしばしば長期的に拒食する性質があるという。"}],"571":[{"rank":"1","note":"光る虫","exp":"20","type":"虫類","name":"ホタル","desc":"腹部が光る小型の昆虫である。森の中で、ほうぼうが点滅している様子は大変美しい。なぜ腹が光るのかは不明だ。"}],"1813":[{"rank":"5","note":"イングランド王国を護る宝石","exp":"1190","type":"財宝","name":"黒太子のルビー","desc":"300カラットを超える宝石で、ルビーではなくスピネルである。黒い甲冑を身につけ軍神のような強さを誇ったイングランドの黒太子エドワードがカスティリヤ王国の内乱を支援したとき、報酬として得たものだといわれている。"}],"2665":[{"rank":"4","note":"新羅を研究するために","exp":"780","type":"財宝","name":"新羅の金冠","desc":"新羅時代のものと思われる金の冠。豪華な装飾と細工が目を引く。この時代は金が豊富だったのだろうか？"}],"211":[{"rank":"4","note":"デュランダル","exp":"756","type":"歴史遺物","name":"デュランダル","desc":"聖騎士ローランが愛用したと伝えられる、水晶をあしらった名剣。鍛え抜かれた刀身は岩をも砕くという。多くの変遷を経て、アムステルダムの教会に安置されていたところを発見された。"}],"5043":[{"rank":"1","note":"到達する","exp":"18","type":"港・集落","name":"カンディア","desc":"クレタ島にある街。緯度がかなり低いため、気温が高い。ギリシャ神話に登場するミノス王の宮殿・ラビュリントスがあったという。オリーブ栽培と漁業が盛んなほか、高級な染料も採れる。"}],"5703":[{"rank":"4","note":"2017.02.07新規追加<br/>視認R9では「発見するにはスキルランクが不足」とのメッセージがでました。R11で発見。<br/>R10で発見できました。確定かと。","exp":"780","type":"気象・現象","name":"ブロッケンの妖怪","desc":"太陽などの光が後方から差し込み、影に周囲に虹に似た光の輪が発生する現象。発生するには広範囲の霧と日の光を遮らない開けた場所が必要である。そのため、山などの高地での観測例が多い。"}],"23":[{"rank":"1","note":"アフリカの巨木","exp":"130","type":"植物","name":"バオバブ","desc":"アフリカの乾燥地帯に広く分布する落葉樹。高さはさほどではないが、幹が太りやすい。水を多く含むため、乾季にはゾウが水を求めて倒してしまうことがある。"}],"2003":[{"rank":"5","note":"クエスト「失われた文化」<br/>発見物カード:260","exp":"520","type":"宗教遺物","name":"チムー王族の黄金飾り","desc":"アンデス山脈の北側でインカ帝国以前に栄えていた、チムー王国王族の副葬品。その高度な冶金の技術は、帝国以前から伝わるものだった。"}],"3630":[{"rank":"","note":"","exp":"","type":"レリック","name":"イタリアの剣","desc":"ハンニバルを追い、果敢に戦いを仕掛け続けた猛将マルケルス。その勇猛さはハンニバル軍に引けを取らなかったという。"}],"2729":[{"rank":"5","note":"闇の中の光","exp":"810","type":"宗教遺物","name":"石窟庵の仏像","desc":"石窟庵内部に鎮座している仏像。\n額にガラスが埋め込まれており、太陽光が石窟内を満たすと、そのガラスが輝くという。新羅は石造建築だけでなく、石仏彫刻の技術力も高かったようだ。"}],"5382":[{"rank":"5","note":"古代ギリシャの海賊王<br/><br/>発見時経験値1170　発見物カード経験値585","exp":"1170","type":"財宝","name":"ポリュクラテスの指輪","desc":"古代ギリシャで活躍した海賊で、サモス島の僭主だったポリュクラテスの指輪とされる。ポリュクラテスは指輪を海に捨てたが、数日後に献上された大魚の腹から指輪が出てきたという。金の台座にエメラルドがはまっている。"}],"1804":[{"rank":"2","note":"ダ・ヴィンチの人体図","exp":"340","type":"美術品","name":"ウィトルウィウス的人体図","desc":"古代ローマの建築家であるウィトルウィウスが示した人体の比率をダ・ヴィンチが再考察し、図式化したもの。ダ・ヴィンチはこの図によって人物をより写実的に描こうとしたという。"}],"3655":[{"rank":"5","note":"ロシアの始まり","exp":"1100","type":"史跡","name":"リューリクの墓","desc":"『原初年代記』によると、リューリクはロシア帝国の基盤となる最初の国家を建設したという。元はヴァイキングであったようだ。彼は死ぬまで人々の指導者として、国家を統治したらしい。"}],"6074":[{"rank":"1","note":"『生神女』は『しょうしんじょ』と読む。","exp":"","type":"宗教遺物","name":"パナギア","desc":"生神女であるマリアやキリストのイコンが描かれた首飾り。　マリアの称号の一つであり、ギリシャ語で「完全な聖」を意味する「パナギア」の名で呼ばれ、正教会では主教以上の聖職者が身につけるという。"}],"451":[{"rank":"1","note":"教会の宗教画の地図","exp":"40","type":"美術品","name":"聖母戴冠（アンジェリコ）","desc":"フラ・アンジェリコ作の祭壇画の一部。名前は「天使のような」という意味で、死後にそう呼ばれるようになったという。非常に敬虔な修道士で、壁画や祭壇画を多く製作した。当時最先端の技術だった遠近法が取り入れらた作風。"}],"6666":[{"rank":"","note":"1.オーストラリア北西岸　北東の哺乳類の骨の南西付近。<br/><br/>※曇り、昼から夕方に発生<br/>　","exp":"300","type":"気象・現象","name":"波状雲","desc":"雲が波状になる現象。\n大気の波が雲を動かすことによって発生する。温暖前線、低気圧の接近時によく見られ、天候が崩れる前兆ともいわれている。"}],"1805":[{"rank":"1","note":"凝った装飾の地図","exp":"110","type":"財宝","name":"アラベスクの水筒","desc":"マムルーク朝時代に作られた、聖地巡礼者用の水筒。水筒は巡礼者にとって必需品でありながら、工芸品としても素晴らしい。"}],"5810":[{"rank":"2","note":"","exp":"390","type":"宗教遺物","name":"マニ車","desc":"筒状の仏具。外側にマントラが刻まれ、中には経文が納められている。チベット仏教でよく使われ、一回転させると中の経文を一度読んだのと同じだけの功徳を得られるという。"}],"6746":[{"rank":"2","note":"","exp":"","type":"気象・現象","name":"黒雪","desc":"雪や氷が黒や灰色に色づく現象。その原因などについて確たる情報はないが、一説には石炭が関係しているとされる。"}],"6179":[{"rank":"3","note":"","exp":"500","type":"植物","name":"メジャー・オーク","desc":"ノッティンガム郊外のシャーウッドの森にあるオークの古木。数百年も昔から森に根付いているとされており、ロビン・フッドと森の仲間たちがここで集会を開いていたという言い伝えが残っている。"}],"718":[{"rank":"5","note":"星の宿る場所","exp":"1066","type":"歴史遺物","name":"ギルガメシュ叙事詩","desc":"古代メソポタミアの叙事詩。人類最古の文学と言える。ギルガメシュ王の冒険譚が語られているが、その中には洪水伝説の原型と思われる部分がある。"}],"6255":[{"rank":"4","note":"","exp":"700","type":"宗教建築","name":"創設者の礼拝堂","desc":"バターリャ修道院の敷地内に作られた礼拝堂のひとつで、ポルトガル初のパンテオンでもある。ジョアン１世と王妃フィリパの墓のそばにペドロ王子とエンリケ航海王子、異郷で捕虜として死んだフェルナンド王子たちの棺が安置されている。"}],"713":[{"rank":"1","note":"水辺に住む牛の地図","exp":"26","type":"大型生物","name":"スイギュウ","desc":"左右に延びた巨大な角を持つウシ。水辺で生活する。小規模な群れと、1000頭を超える大規模な群れがある。大規模な群れはメスと子供のようだ。"}],"5600":[{"rank":"2","note":"","exp":"244","type":"港・集落","name":"オマハ","desc":"北米大陸中西部の街。ゴールドラッシュの発生以降、開拓と東西の往来の拠点として急激に発展した。"}],"2830":[{"rank":"4","note":"明の民に好まれる本","exp":"660","type":"財宝","name":"水滸伝","desc":"民衆によく読まれていた明代の通俗小説。\n108人の好漢たちが築いた要塞に集まり悪徳官吏を打倒し、国を救わんとする物語。"}],"4791":[{"rank":"2","note":"クエスト「常夏の島の火山神」<br/>発見物カード:160","exp":"320","type":"宗教遺物","name":"ペレ像","desc":"ハワイ島の火山の女神で、はるか南の島で生まれたと言われる。\n数多くの兄弟神とともにハワイに移り住み、島の南東にある火山を住まいとしたとされる。"}],"1320":[{"rank":"4","note":"王朝を支える川","exp":"636","type":"地理","name":"チャオプラヤ川","desc":"ヤーデインの西に広がる湾の最奥に河口を持つ大河。下流域では、その豊かな水量を利用し、浮稲による稲作が行われている。運河としても広く利用されているようだ。"}],"4972":[{"rank":"4","note":"","exp":"720","type":"史跡","name":"ミュケナイ遺跡","desc":"ペロポネソス半島の北東部にある遺跡。紀元前に栄えていた、ミュケナイ文明の中心地。数々の黄金細工が発見されており、当時は金がよく利用されていたとみられる。"}],"5082":[{"rank":"1","note":"到達する","exp":"178","type":"港・集落","name":"セイロン","desc":"インド南端にある島の街。島は高地が多く、茶の栽培が盛んだ。また、宝石の鉱脈が非常に豊富で、さまざまな宝石が産出される。"}],"159":[{"rank":"1","note":"サメの生息地調査","exp":"30","type":"海洋生物","name":"シュモクザメ","desc":"ハンマーのような、独特の頭部をしたサメ。性質は凶暴で、人が襲われることもある。目が両側に張り出しているため、他のサメより視野が広く、さらに危険だという。"}],"3427":[{"rank":"","note":"","exp":"","type":"レリック","name":"テンプル騎士団","desc":"中世に活躍し、巨額の資産を持っていた騎士団。聖地からいくつかの秘宝を持ち帰ったという伝説があるが真実は闇の中である。"}],"1240":[{"rank":"2","note":"水の上に立つ鳥","exp":"370","type":"鳥類","name":"レンカク","desc":"長い脚と、きわめて大きな足が特徴。足指も長く、水面に浮いた葉の上を歩ける。湿原や草地に生息し、昆虫を餌としている。"}],"2965":[{"rank":"3","note":"大洞窟調査依頼","exp":"600","type":"地理","name":"マンモス・ケーブ","desc":"北米大陸に位置する、石灰岩の洞窟群。その全長は500kmをゆうに超える。石灰岩の層の上にはさらに砂岩の層が重なっており、非常に頑丈な洞窟である。"}],"5886":[{"rank":"5","note":"","exp":"1330","type":"大型生物","name":"フリージアン","desc":"欧州北西部が原産地とされる馬で、黒い体色と長い毛が特徴。力が強いため、荷物の牽引役や戦馬としても使用されてきた。"}],"352":[{"rank":"5","note":"永遠の矢車菊","exp":"1131","type":"歴史遺物","name":"ツタンカーメン王の黄金のマスク","desc":"古代エジプトのツタンカーメン王の墳墓から出土した、純金のマスク。ラピスラズリなどで豪華な装飾が施されている。その上には、矢車菊の花束が添えられていた。"}],"5825":[{"rank":"4","note":"","exp":"690","type":"天文","name":"かんししゃメシエ座","desc":"フランスの著名な天文学者であるシャルル・メシエをモデルとした星座。フランスはともかく、他の国で定着するのであろうか…。"}],"2256":[{"rank":"2","note":"クエスト「現地調達のすすめ」<br/>発見物カード:180","exp":"360","type":"地理","name":"ケプロイの滝","desc":"ポンペイ島最大の山から流れ落ちる滝。\nポンペイ島は雨が多いため滝の水量も多く、迫力がある。滝つぼにはウナギが生息している。"}],"5523":[{"rank":"2","note":"","exp":"150","type":"気象・現象","name":"海底火山","desc":"海底の火山が活動する現象。水深が浅く、噴火の力が強いと海面から煙などが噴出する。特に噴火活動が活発な場合は島の形成に繋がることもある。"}],"1261":[{"rank":"5","note":"失われた右腕","exp":"1053","type":"美術品","name":"ラオコーンの右腕","desc":"ローマで出土したラオコーン像の、折れた右腕。ラオコーン像には天をつかむような伸ばした右腕がつけられていたが、これは曲げられている。"}],"928":[{"rank":"1","note":"美しい木の地図","exp":"11","type":"植物","name":"シラカバ","desc":"幹が白い落葉樹。暖かな地方では見かけないが、寒冷地ではよく群生している。シラカバの林は大変美しい。"}],"810":[{"rank":"1","note":"大西洋の真ん中","exp":"90","type":"地理","name":"アゾレス諸島","desc":"イベリア半島南西端から西に1300kmほどに位置する諸島。これまでの航海技術では大陸を離れた航海が困難だったため、存在が認識されていなかった。年間を通して温暖なので、耕作に向いていると思われる。"}],"1437":[{"rank":"3","note":"パレンケの王","exp":"440","type":"歴史遺物","name":"パカル王の盾","desc":"パレンケ王・パカルが所持していたといわれる盾。パカルは、カラクムルによって滅亡寸前にまで陥っていたムトゥプルを、奇跡的に復興させた。"}],"3748":[{"rank":"3","note":"空に輝く穂先","exp":"510","type":"天文","name":"スピカ","desc":"おとめ座で最も明るく輝く、青白い星。名は「穂先」を意味し、星座図では、女神が持つ麦穂の先に位置する。アルクトゥルスとともに夫婦星と呼ばれることがあり、アルクトゥルスは男性を、スピカは女性を象徴する。"}],"3821":[{"rank":"5","note":"桃色の浜辺<br/><br/>発見時経験値1180　発見物カード経験値590","exp":"1180","type":"地理","name":"ピンクサンドビーチ","desc":"カリブ海のハーバー島にある浜辺。バハマ諸島のエルーセラ島北部に位置する。\n白い砂に赤みがかった貝殻やサンゴが砕けたものが混じっており、ピンク色に見える。"}],"2038":[{"rank":"2","note":"［勅命］[[運河開通場所に潜むもの","exp":"310","type":"大型生物","name":"ナイルオオトカゲ","desc":"トカゲのような生物だが、体長がヒトより大きい個体も存在する。どうやら肉食らしく、ワニの卵や幼生すらも食べてしまうという。名前にナイルとあるがナイル川周辺以外でも目撃情報が寄せられている。"}],"555":[{"rank":"1","note":"古代ローマの暴君","exp":"90","type":"歴史遺物","name":"カラカラ帝の大理石像","desc":"カラカラ浴場で有名なカラカラ帝の大理石像である。弟をはじめとして政敵はことごとく殺し、絶え間なく戦争を起こしていた暴君である。"}],"5538":[{"rank":"4","note":"視認R7でスキル不足表示。<br/>視認R8で発見確認。","exp":"315","type":"気象・現象","name":"流星雨","desc":"火球が一定の短時間に複数出現する現象。流星雨には放射点が存在するため、夜間にそれが天頂近くに上る場所でのみ観測できる。"}],"3765":[{"rank":"3","note":"クエスト「コペルニクスの依頼」<br/>発見物カード:225","exp":"450","type":"天文","name":"水星","desc":"夕暮れと明け方のわずかな時間にのみ見られる惑星。古代ギリシャでは宵の水星をヘルメス、明けの水星をアポロンと読んでいた。金星に比べると暗く、太陽に近いため、観測はやや難しい。"}],"1770":[{"rank":"2","note":"細長い砂漠","exp":"210","type":"地理","name":"アタカマ砂漠","desc":"南米西岸中部を覆う南北に細長い砂漠。降雨は数十年に一度という地域もあり、世界でも有数の乾燥地帯といえるだろう。そのため樹木の姿を見ることはできないが、銅や銀、そして硝石と豊富な鉱物資源を有している。"}],"2427":[{"rank":"2","note":"飛べない鳥の地図","exp":"260","type":"鳥類","name":"ヤンバルクイナ","desc":"沖縄本島北部の森林地域にのみ生息する鳥。翼が小さく、飛ぶことはできない。\nその代わりに脚が発達し、茂みの中を走り回れる。"}],"2050":[{"rank":"2","note":"名宰相の帝王学","exp":"270","type":"財宝","name":"政治の書","desc":"セルジューク朝の名宰相、ニザーム・アルムルクが書いた書。スルタンに求められる帝王学を、逸話などを含めて分かりやすく書いている。"}],"627":[{"rank":"1","note":"鹿に似た動物の地図","exp":"57","type":"中型生物","name":"インパラ","desc":"ねじれた長い角を持った、鹿のような動物。角は鹿のように枝分かれしていない。群れで生活し、跳ねるように走る。"}],"119":[{"rank":"1","note":"ギリシャの女神像の地図","exp":"60","type":"宗教遺物","name":"ヘスチア像","desc":"ギリシャ神話の炉の女神の像。ゼウスの姉で逸話こそ少ないものの古代ギリシャでは広く信仰されていた。ローマ神話ではウェスタという。"}],"5863":[{"rank":"5","note":"","exp":"1340","type":"美術品","name":"ラブサヨン","desc":"特徴的な形をした、黒い壺。マレー半島で作られる伝統的な工芸品で、地元の人々に愛されている。"}],"6266":[{"rank":"2","note":"","exp":"220","type":"中型生物","name":"オウゴンヤマネコ","desc":"中国南部、インド、ネパールからスマトラ島にかけて生息している中型のネコで、中国では「彪（ひょう）」と呼ばれている。\n主に毛皮が珍重されており、骨に薬効があるという噂もあるが、その真偽は不明である。"}],"3905":[{"rank":"","note":"","exp":"","type":"レリック","name":"ほらふき男爵","desc":"巧みな話術と機知で知られたミュンヒハウゼン男爵。彼の冒険譚は今も人々を楽しませている。"}],"320":[{"rank":"2","note":"ラファエロの名画","exp":"240","type":"美術品","name":"ヒワの聖母","desc":"ラファエロ作の絵画。同じ題材の絵が複数あるため、この絵は通称でこう呼ばれる。由来は、左の聖ヨハネが小鳥のヒワをつれているからである。"}],"1825":[{"rank":"3","note":"先王の支配の証","exp":"500","type":"財宝","name":"ワイナ・カパックの財宝","desc":"インカ帝国の北方、キト周辺の制圧に執心したインカ皇帝ワイナ・カパックの財宝。制圧完了の暁に、皇帝自らかの地に納めた品のようだが、その後のヨーロッパ人の来訪による混乱で、存在を忘れられていたようだ。"}],"5999":[{"rank":"1","note":"太陽のあふれる浜辺","exp":"20","type":"地理","name":"コスタデルソル","desc":"マラガを中心とした、300kmにおよぶ海岸線を指す。意味はスペイン語で「太陽の海岸」である。1年を通して温暖な気候で、保養地には最適だ。"}],"2592":[{"rank":"1","note":"大きな島の地図","exp":"150","type":"歴史遺物","name":"台湾全島図","desc":"台湾島の全体図と思われる絵図。\n台湾地域の地図は三つの諸島として描かれたものが多かったが、この地図では一つの島になっている。"}],"4811":[{"rank":"3","note":"宋山里遺跡群 （上層隠し部屋）","exp":"","type":"歴史遺物","name":"古代の銅鏡","desc":"遺跡の中から発見された古い銅鏡。人やものを映すだけではなく、祭祀や呪術などにも使用されていたようだ。"}],"6288":[{"rank":"5","note":"","exp":"1230","type":"史跡","name":"古蜀の遺跡","desc":"紀元前に栄えていた古蜀文化の遺跡。長江の上流に位置する。非常に広大な遺跡で、縦目仮面の他にも貴重な物が眠っていると思われる。"}],"2522":[{"rank":"2","note":"龍の目に似た果実","exp":"270","type":"植物","name":"リュウガン","desc":"台湾島や中国南部などの暖かい地域で、初夏に黄白色の小花をたくさん付ける植物。\n直径2cmほどの果実が実る。\n果実を半分に切った時の見た目が龍の目玉に見えることから、この名前が付いた。"}],"487":[{"rank":"2","note":"ホートリ祭官の聖典","exp":"390","type":"宗教遺物","name":"リグ・ヴェーダ","desc":"ヒンドゥー教の聖典の一つ。神々への賛歌（リチュ）をまとめたもので、祭事にホートリ祭官が詠唱し、神々を招くといわれる。"}],"3377":[{"rank":"4","note":"古代伝承の山脈","exp":"700","type":"地理","name":"ザグロス山脈","desc":"ホルムズの近くから、トルコの周辺までに及ぶ巨大な山脈。山脈内にはかつて栄えた王朝の遺跡が残る。\n伝説にある、洪水を免れることができた船はこの山脈のどこかに存在しているともいわれているが、真相は不明だ。"}],"2345":[{"rank":"5","note":"クエスト「和歌に詠まれた高嶺」<br/>発見物カード:415","exp":"830","type":"地理","name":"富士山","desc":"優美な裾野を引く、日本を代表する活火山。火山活動の記録が残っており、今後も噴火の可能性がある。\nまた、古来より信仰の対象でもあり、霊峰とも呼ばれる。"}],"2352":[{"rank":"2","note":"［勅命］[[島国にある山の調査","exp":"270","type":"地理","name":"紀伊山地","desc":"日本の紀伊地方に存在する霊場及びその山々の総称。\n地形が険しいため、山岳仏教や修験道（しゅげんどう）を信仰する僧侶の修行の場として栄えている。"}],"285":[{"rank":"5","note":"マーリンの杖","exp":"1118","type":"歴史遺物","name":"マーリンの杖","desc":"アーサー王伝説に登場する魔法使い・マーリンの杖。マーリンはアーサーを育て、王になってからも補佐した人物。湖の精霊に自分の魔法の秘密を教え、捕らわれた。"}],"5529":[{"rank":"2","note":"夜　7590,5600で視認","exp":"250","type":"気象・現象","name":"バイオルミネセンス","desc":"夜などに、海洋生物の発光で海が輝いて見える現象。発光する生物の種類は多く、魚類以外にも甲殻類やクラゲなどの発光が確認されている。"}],"1269":[{"rank":"4","note":"眠れる女神","exp":"720","type":"美術品","name":"眠れるビーナス","desc":"ジョルジョーネ作。ヴェネツィアの貴族の結婚祝いに依頼されたもの。弟弟子のティツィアーノに影響を与え、後に同じ構図の絵が描かれている。静謐な空間で眠るヴィーナスからは、無垢の美しさが滲み出している。"}],"468":[{"rank":"5","note":"激闘の果てに<br/><br/>発見時経験値1209　発見物カード経験値604","exp":"1209","type":"歴史遺物","name":"ソロモンの鍵","desc":"古代ユダヤ王国のソロモン王が記したとされる魔術書。72の悪魔を召喚し、使役する方法が書かれていると言われる。"}],"1640":[{"rank":"5","note":"第二の世界周航","exp":"923","type":"地理","name":"ドレイク海峡","desc":"イングランドの提督、フランシス・ドレイクが発見したといわれる海峡。近海は波が高く強風が止まないため、航海の難所として知られる。さらに、冬は海が氷に覆われる。"}],"1473":[{"rank":"5","note":"別世界","exp":"1274","type":"史跡","name":"テノチティトラン","desc":"アステカ帝国の首都。テスココ湖の中心にある島に作られた都で、岸に向けて3本の橋が架かるさまは壮麗。コルテスも「あまりに広く美しいので半分しか報告しません」と報告書に記している。"}],"539":[{"rank":"1","note":"古代の墳墓の地図","exp":"190","type":"歴史遺物","name":"ミイラ","desc":"死体に防腐処置を施し保存したもの。特に古代エジプトでは死者の復活が信じられていたため、非常に高度な技術が発展した。"}],"5892":[{"rank":"1","note":"","exp":"","type":"美術品","name":"ベレスタ","desc":"ロシアで作られる小物入れ。白樺の皮を利用して作られている。繊細な装飾は芸術品としても評価が高い。"}],"1449":[{"rank":"5","note":"悪魔と呼ばれる生物","exp":"923","type":"中型生物","name":"タスマニアンデビル","desc":"肉食の有袋類。昆虫から小型の哺乳類、大きいものはワラビーまで捕食する。しばしば餌の奪い合いをし、興奮すると皮膚の部分が紅潮する。"}],"2098":[{"rank":"2","note":"異国の古代通貨","exp":"250","type":"財宝","name":"ディレム銀貨","desc":"ササン朝時代に製造された銀貨。\n表面に「右向きの王の胸像」、裏面には礼拝に使用された「聖なる火」が刻まれている。"}],"7001":[{"rank":"5","note":"レガシー法の叡智・正義の象徴 左上","exp":"","type":"宗教遺物","name":"シャマシュの剣","desc":"メソポタミア神話に登場する、太陽神シャマシュが持つ武器。刃がのこぎり状をしている剣とされ、シャマシュの力の象徴ともいわれる。シャマシュは太陽神のみならず、正義と法の神としても長く崇拝された。"}],"2708":[{"rank":"3","note":"ダンジョン","exp":"500","type":"財宝","name":"百済王の勾玉","desc":"百済の遺跡で発見された勾玉（まがたま）。豪華な装飾が施されているため、とても目を引く。"}],"5146":[{"rank":"1","note":"到達する","exp":"19","type":"港・集落","name":"ボルドー","desc":"先史時代の壁画が見つかるほど、太古から人が住んでいた街。長くイングランドの支配下にあったが、100年戦争でフランスの領土となった。水に恵まれた地勢で、農業が非常に盛ん。特に良質のワインを作っている。"}],"6158":[{"rank":"2","note":"","exp":"210","type":"宗教遺物","name":"貧者の聖書","desc":"聖書中に出てくる出来事を抜粋して描いた木版印刷。13世紀中頃に東南ドイツ・オーストリアで成立すると、活版印刷の普及に伴ってヨーロッパ中に広がった。当時の教会で主流であった予型論に基づいて制作された。"}],"6031":[{"rank":"4","note":"カード経験365","exp":"730","type":"財宝","name":"和氏の璧","desc":"春秋戦国時代の中国北方の国・趙に伝わる宝物。「かしのへき」と読む。楚の卞和(べんか)という人物によって原石が発見された。のちに趙に伝わり「完璧」という言葉の由来にもなったいわくつきの宝物である。"}],"356":[{"rank":"2","note":"英雄神の妻","exp":"310","type":"宗教遺物","name":"ラクシュミー像","desc":"インド神話の女神の像である。ラクシュミーは幸福と富をもたらす女神で、ヴィシュヌ神の妃だとされる。"}],"3615":[{"rank":"4","note":"広大すぎる湖","exp":"740","type":"地理","name":"ラドガ湖","desc":"サンクトペテルブルク北東に位置し、重要な水源となっている湖。湖には多数の島が点在し、大きな島には人も住んでいるようだ。冬になると凍結する。"}],"5117":[{"rank":"2","note":"到達する","exp":"328","type":"港・集落","name":"パタニ","desc":"イスラム教を国教とするマレー人の国であるパタニ王国の首都。\nマレー王朝の中でもいち早くイスラム化を果たした。"}],"5463":[{"rank":"1","note":"","exp":"60","type":"地理","name":"パンタナル湿原","desc":"パラグアイ川上流に位置する広大な湿原。\n雨季には川が氾濫し、全体の八割近くが水没してしまうという。\n過酷な自然環境に見えるが、この大地の変化が豊かな土壌を育み、数多くの動植物の生態系を支えている。"}],"5592":[{"rank":"2","note":"ワンガヌイ西（ワンガヌイ郊外）で発見。<br/>郊外に出たすぐの場所で発見できました。<br/>東の奥、行き止まりで現象見れます。","exp":"270","type":"気象・現象","name":"間欠泉","desc":"一定周期で地中から水蒸気や熱湯が噴き上がる現象。地中でどのような現象が発生しているかはわからないが、高温の噴出物であることから、火山活動との関係性がうかがえる。"}],"724":[{"rank":"2","note":"精霊の舞い","exp":"360","type":"中型生物","name":"シファカ","desc":"後ろ足で跳ねるように地上を移動する。その姿は踊っているようにも見える。脚力が優れており、樹木のあいだを約10メートルも跳びこえる。おもに昼間に活動をする。"}],"6545":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"アレクサンドリア大図書館の蔵書","desc":"古代世界で最大の知の集積地、アレクサンドリア大図書館が所蔵していたとされる巻物。大図書館ではアレクサンドリアに寄港した船の書物をすべて提出させ、写本のほうを返したという。こうして収集した書物は何十万巻に及んだと伝わる。"}],"6593":[{"rank":"5","note":"レガシー伝説の王都バビロン　上","exp":"4000","type":"史跡","name":"在りし日のバビロンの大城壁","desc":"新バビロニア王国の王ネブカドネザル2世が首都バビロンの街を守るために建造させた大城壁。街を取り囲む城壁は、青い彩釉レンガや数多のレリーフが施された絢爛豪華な造りで、北部にはイシュタル門とよばれる壮麗な門が備わる。"}],"1657":[{"rank":"1","note":"書きかけの地図","exp":"110","type":"地理","name":"氷河","desc":"山間部に堆積した雪が長い年月をかけて融解と凍結の反復、または自重による圧縮で氷となったものが氷河である。氷河は非常にゆっくりとした速度ながら下方に移動している。"}],"3804":[{"rank":"5","note":"南米北東部の地理情報","exp":"810","type":"地理","name":"カイエトゥール滝","desc":"南米北東部に位置する滝。落差は約220mで、一段の滝としてはかなりの規模である。"}],"3621":[{"rank":"3","note":"過去が抜け落ちた書物","exp":"550","type":"歴史遺物","name":"ラヴレンチー写本","desc":"14世紀に修道士ラヴレンチーにより転写された、『原初年代記』の写本。\n一部の年代の記録が除かれているが、理由は不明である。"}],"1539":[{"rank":"1","note":"メソアメリカの容器の地図","exp":"110","type":"歴史遺物","name":"三脚容器","desc":"三脚がついた円筒形の容器。材質は土器や陶器が多く、金属のものはまず見られない。細かな彫刻が施されているものが多い。"}],"6972":[{"rank":"1","note":"発見物カード:315","exp":"630","type":"小型生物","name":"キエリテン","desc":"アジアに広く生息するテンの一種。主に胸周りの体毛が鮮やかな橙色であることが名前の由来になっている。体は黄褐色で、頭や四肢は黒く、顎下の体毛は白いなど、体毛の色合いが特徴的である。"}],"960":[{"rank":"2","note":"宝石を生む貝","exp":"370","type":"海洋生物","name":"クロチョウガイ","desc":"熱帯の海に生息する、大きめの二枚貝。黒真珠が取れる。真珠はまれにしか見つからないため、古代から非常な貴重品だった。クレオパトラはこの黒真珠を酢に溶かして飲んだといわれている。"}],"2986":[{"rank":"3","note":"虹色を求めて","exp":"480","type":"鳥類","name":"パープル・ガリヌール","desc":"熱帯の湿地でよく見られる鳥。青みがかった羽毛が鮮やかである。細い脚で水草の上を歩くさまは、まるで水面を歩いているようだ。"}],"5462":[{"rank":"5","note":"","exp":"1080","type":"鳥類","name":"オオホウカンチョウ","desc":"南米の熱帯雨林に生息する中型の鳥。頭にはカールしたような特徴的な冠羽が観られる。\n飛翔能力が弱いようで常に地上または低い木の上で生活している。"}],"2419":[{"rank":"1","note":"島にすむシカの地図","exp":"90","type":"中型生物","name":"ヤクシカ","desc":"屋久島に生息するシカの一種。日本本土に生息するシカと比べると一回り小さい。\n角の枝分かれも二つがほとんどで本土のシカより一つ少ない。"}],"3916":[{"rank":"1","note":"明るい星の観測記録<br/><br/>発見物カード:90<br/>　","exp":"120","type":"天文","name":"デネブ","desc":"はくちょう座で最も明るい星で、名はアラビア語の「尾」に由来する。夏の大三角の一角を構成する1等星。"}],"5269":[{"rank":"2","note":"","exp":"360","type":"歴史遺物","name":"ヴァイキングの鉄盾","desc":"ヴァイキングが使用していた鉄盾。かつてこの地に入植したヴァイキングが残したと見られる。付近には溶鉱炉の跡があり、鉄釘などの道具も多く見つかっている。"}],"2361":[{"rank":"2","note":"高級木材の調査","exp":"340","type":"植物","name":"ヒノキ","desc":"日本と台湾に生育する常緑針葉樹。乾燥した場所でよく育つ。\n材は耐久性が高く、かつ光沢と芳香があるため、高級建築材として名高い。"}],"785":[{"rank":"3","note":"太陽のチョウ","exp":"473","type":"虫類","name":"アポロチョウ","desc":"後ろ羽に赤くて丸い斑紋がある。それが太陽に似ているからかはわからないが、太陽が照りつける間だけ活動する。山岳の乾燥した草原に棲む。"}],"3170":[{"rank":"5","note":"祖父の肖像","exp":"1030","type":"財宝","name":"コジモのメダル","desc":"ロレンツォの祖父、コジモの横顔が彫られた金のメダル。コジモは芸術や学術への援助を惜しまず、メディチ家ひいてはフィレンツェの発展に大きく貢献した。その功績を称えているのだろう。"}],"1305":[{"rank":"5","note":"子供ほどの小さなクマ","exp":"923","type":"大型生物","name":"マレーグマ","desc":"1.5mほどと、クマの中では小型。首の周りの皮膚が緩んでおり、捕食者に背後から襲われたときでも体をくねらせて逃れ、反撃に転じることができる。"}],"3791":[{"rank":"2","note":"視認","exp":"340","type":"天文","name":"リゲル","desc":"オリオン座で最も明るい、青白い星。オリオン座の右下に位置し、星座図ではオリオンの左膝にあたる。リゲルという名はアラビア語で足を意味するリジルからきている。冬のダイヤモンドの一角。"}],"1579":[{"rank":"1","note":"箱のような魚の地図","exp":"160","type":"海洋生物","name":"コンゴウフグ","desc":"箱のように角張った体が特徴。目の上には小さな突起がある。海底の砂に水を吹きかけ、エサを追い出して食べる。"}],"6634":[{"rank":"5","note":"レガシー商の叡智・財貨の交易路　中央","exp":"","type":"歴史遺物","name":"ポイティンガー図","desc":"ローマ帝国の時代の地図。当時の道路や河川などが描かれている。原図はすでに散逸したが、アウクスブルクのポイティンガーによる写本が伝わっている。"}],"5129":[{"rank":"1","note":"到達する","exp":"25","type":"港・集落","name":"フランクフルト","desc":"神聖ローマ帝国の中心都市として発展した、ドイツ中西部に位置する街。名前の由来は5世紀にフランク王国がマイン川を渡る地点として選んだためとされる。バルトロメウス大聖堂は皇帝選挙の地と定められ、戴冠式も執り行われている。"}],"3677":[{"rank":"5","note":"氷海の天使","exp":"1350","type":"海洋生物","name":"クリオネ","desc":"寒流域に生息する海洋生物。半透明の体で、内臓が見えている。\n海中をふわふわと漂うように泳ぐさまは幻想的だ。ギリシャ神話の女神が名前の由来とされている。"}],"143":[{"rank":"2","note":"クレオパトラの化粧","exp":"300","type":"歴史遺物","name":"クレオパトラの香水瓶","desc":"絶世の美女と伝えられるクレオパトラ7世が使っていた香水瓶。古代エジプトでは、さまざまな香油や香水が使われていたという。"}],"5628":[{"rank":"1","note":"","exp":"160","type":"地理","name":"カプリ島","desc":"ナポリの南に位置する島。かつてローマ帝国の皇帝の別荘地とされていた。島の外周の大部分は絶壁に囲まれており、海蝕洞が存在する。"}],"2744":[{"rank":"2","note":"風景画の地図","exp":"210","type":"美術品","name":"安堅の風景画","desc":"朝鮮の画家・安堅による水墨画。\n季節を表現した八つの風景が描かれている。早春と晩春、初夏と晩夏、初秋と晩秋、初冬と晩冬と、二つずつ対となっている。"}],"546":[{"rank":"1","note":"古代の宝石細工の地図","exp":"67","type":"歴史遺物","name":"宝石細工の装身具","desc":"さまざまな宝石をあしらった装身具。古代文明では、宝石には不思議な力が備わっていると考えられ、護符の意味もあった。"}],"2705":[{"rank":"1","note":"書きかけの地図","exp":"140","type":"地理","name":"済州海流","desc":"朝鮮半島と済州島の間を流れる海流。\n暖流の対馬海流とつながっているため、海流上に浮かぶ島の気候は暖かい。"}],"6832":[{"rank":"3","note":"","exp":"","type":"美術品","name":"エスコリアルの無原罪の御宿り","desc":"「無原罪の御宿り」を主題とし描かれた油彩画。イスパニアの画家ムリーリョの作。彼はこの主題で多くの作品を残しているが、美しい聖母マリアと、身にまとう白と青の衣が共通した特徴。幻想的な作風は後の芸術に多大な影響を与えた。"}],"6066":[{"rank":"4","note":"","exp":"740","type":"財宝","name":"プロコピオスの秘史","desc":"東ローマ帝国の名将ベリサリウスに仕えた書記官であるプロコピオスの著作。　「戦史」とは真逆の内容であり、ユスティニアヌス1世と皇妃、ベリサリウスとその妻らの醜聞や批判が辛辣に綴られている。"}],"2246":[{"rank":"2","note":"真っ赤な顔のトカゲ","exp":"140","type":"小型生物","name":"ヨウガントカゲ","desc":"ガラパゴス諸島の島々でよく見られる小型のトカゲ。島ごとに見た目が少しずつ違う。\n雄のほうが体が大きく雌は喉の周りが鮮やかな赤色をしているのが特徴である。"}],"2428":[{"rank":"2","note":"球技好きからの調査依頼","exp":"340","type":"財宝","name":"鹿皮製の鞠","desc":"蹴鞠（けまり）に用いられた鞠。\n蹴鞠とは、中国から日本に伝来した遊戯である。数人が鞠を地面に落とさないよう交互に蹴り続けるもので、貴族や武士に好まれた。"}],"1666":[{"rank":"5","note":"伝説の立証<br/><br/>発見時経験値1053　発見物カード経験値526","exp":"1053","type":"歴史遺物","name":"ハウマカの杖","desc":"ホツ・マツア王を、ラパ・ヌイへ誘った賢者ハウマカが使用した杖といわれている。彼は太陽の昇る方向へ飛んでいく夢を見て、たどり着いた島の美しさ、豊かさを知り、「我が王の治めるにふさわしい土地だ」と、王に移住を勧めたという。"}],"83":[{"rank":"5","note":"エクスカリバー","exp":"1235","type":"歴史遺物","name":"エクスカリバー","desc":"アーサー王伝説に登場する聖剣。アーサー王が湖の精霊から授かったと言われる。剣は鉄をも切り裂き、鞘は持ち主の傷を癒し不死にするという。"}],"6160":[{"rank":"4","note":"","exp":"640","type":"海洋生物","name":"カラチョウザメ","desc":"中国各地に古くから生息するチョウザメの仲間。長江で多く見られており、産卵の時期には上流の金沙江まで遡上するという。「本草綱目」で滋養強壮に良いとされるが、そもそも水揚げ自体が珍しく、生息数もはっきりしない。"}],"2103":[{"rank":"5","note":"連鎖する好奇心<br/><br/>発見時経験値1060　発見物カード経験値530","exp":"1060","type":"歴史遺物","name":"ティソナ","desc":"「我がシードの歌」では、金1000マルコの価値があるとされる名剣で、モロッコのブカル将軍を討ちとって獲得した。燃える剣という意味を持つ。"}],"3668":[{"rank":"4","note":"ダンジョン","exp":"640","type":"宗教遺物","name":"セクメト像","desc":"雌ライオンの頭を持つ女神像。太陽神ラーが自分を崇めない人間を滅ぼすために地上に派遣したという伝説がある。伝染病を司るとされ、カルナック神殿の一角でよく発掘されるという。"}],"5799":[{"rank":"5","note":"","exp":"1450","type":"宗教建築","name":"バールベック","desc":"ローマの三神を祭る三つの神殿で構成されている遺跡。名前の由来はフェニキアの神であり、時代の変遷を目の当たりにするようだ。"}],"3756":[{"rank":"2","note":"クエスト「南の空に輝く星」<br/>発見物カード:165","exp":"330","type":"天文","name":"シリウス","desc":"太陽を除くと、全天で最も明るい恒星。冬の大三角を構成する星の1つで、おおいぬ座に属する。ナイル川の氾濫時期を知らせる星として古代エジプトで重視された。名はギリシャ語の「焼き焦がすもの」に由来する。"}],"2805":[{"rank":"2","note":"歌う鳥","exp":"310","type":"鳥類","name":"ガビチョウ","desc":"中国南部から東南アジアまで、広い範囲で生息している鳥。地上を走ることが多く、高く飛ぶことがない。\n眼の周りにある眉状の模様が特徴的で、「画眉鳥」と書く。"}],"5794":[{"rank":"5","note":"","exp":"","type":"史跡","name":"コンドアの岩絵群","desc":"数千年にわたり蓄積されてきた岩絵。赤い絵と白黒の絵があり、赤い絵のほうが、より古い時代に描かれたもののようだ。"}],"1740":[{"rank":"1","note":"祭礼用台座の地図","exp":"160","type":"宗教遺物","name":"神像付き台座","desc":"精霊堂に安置された台座。集会の際に叩いて音を出す。ニューギニアには大小さまざまな部族があり、そのほとんどが精霊信仰のための精霊堂を部族内に持っていた。"}],"290":[{"rank":"5","note":"マダガスカルの王者","exp":"923","type":"中型生物","name":"フォッサ","desc":"マダガスカル島に生息する最強の肉食獣。主に単独行動をとり、昼夜を問わず、追跡か待ち伏せで狩りをする。体は筋肉質で、木登りが得意。"}],"5878":[{"rank":"5","note":"クエスト「クリスマスの星」<br/>発見物カード:725","exp":"1450","type":"天文","name":"ベツレヘムの星","desc":"キリスト生誕を東方の三賢者に知らせたと伝えられる伝説の星。\n…なのだが、報告を仕上げて空を見上げると同じ星は二度と見つからなかった。自分が見たものが本当に伝説の星だったのか、確かめるすべはない。"}],"5413":[{"rank":"1","note":"茶葉にする植物の地図（パラグアイ川上流再調査報酬）","exp":"","type":"植物","name":"イェルバ・マテ","desc":"南米に生息する植物。葉は茶葉として加工され、広く飲用されている。成長には長い年月を要するが、その分、収穫も数十年間続けて行えるという。"}],"5753":[{"rank":"2","note":"2017.02.07新規追加","exp":"360","type":"気象・現象","name":"球電","desc":"空中を光の球が浮遊する現象。色は赤や黄、青など多岐にわたる報告がある。雷雨の際に目撃されることが多いが、風雨のない状況での目撃例もある。"}],"6151":[{"rank":"4","note":"クエスト「祈りと贖罪」<br/>発見物カード:400","exp":"800","type":"財宝","name":"メリッサの船首像","desc":"かつて沈没したポルトガル王族船の船首像。ジョゼの父親が贖罪の念と祈りを込めて造った。「この船を造る私に罰を。この船に乗る者に救いを。そして、我が娘に幸いを。守りたまえ、メリッサ──我が妻よ」という文字が刻まれている。"}],"5334":[{"rank":"3","note":"クエスト「聖書に由来する星座」<br/>発見物カード:240","exp":"480","type":"天文","name":"はと座","desc":"16世紀末に作られた星座で、聖書のノアの方舟に登場するハトに由来する。ノアは方舟からハトを放ち、大洪水の水が引いていくことを知ったといわれる。"}],"2049":[{"rank":"2","note":"［勅命］[[運河開通事業の技術書","exp":"310","type":"財宝","name":"ダ・ヴィンチノート","desc":"ダ・ヴィンチ直筆の著書。天文学や医術に関する知識や考察から、デッサンやスケッチまで幅広く記述されている。しかし文字はすべて鏡文字で書かれており、読むことは容易ではない。"}],"1943":[{"rank":"1","note":"メソアメリカの像の地図","exp":"200","type":"宗教遺物","name":"シウコアトル像","desc":"アステカ神話における火の蛇の神。アステカ独自の暦によると、太陽を日の出から天の頂点まで届ける役目を担っているという。"}],"1653":[{"rank":"3","note":"島と陸との間に","exp":"473","type":"地理","name":"バス海峡","desc":"オーストラリア大陸とタスマニア島との間にある海峡。幅が狭く水深が浅いため、船の難所として知られる。\nオーストラリア先住民は、この海峡が形成される過程を伝承によって語り継いでいる。"}],"6645":[{"rank":"2","note":"","exp":"230","type":"植物","name":"アデニウム","desc":"アラビア半島原産の植物。美しい花を咲かせ「砂漠の薔薇」と呼ばれる。花びらは鮮やかで大きいが、寒さに弱い。"}],"3015":[{"rank":"1","note":"貝製の装身具の地図","exp":"140","type":"歴史遺物","name":"貝製の喉あて","desc":"北米のエトワー川付近の墳墓から発見された貝製の装飾品。\n幾何学的な文様を含んだ、独特な図が彫り込まれている。"}],"3690":[{"rank":"4","note":"聖人列伝の異説","exp":"760","type":"宗教遺物","name":"ボリスとグレブの聖像","desc":"後に聖人となったキエフ大公国の2人を描いた絵画。異教徒の兄による圧迫に屈することなく、キリスト教信仰を貫いた彼らを敬う者は多い。"}],"5141":[{"rank":"2","note":"到達する","exp":"303","type":"港・集落","name":"ペグー","desc":"ベンガル湾の東岸に位置する街。東南アジアに住む民族のひとつ、モン人により建造された街であり、ペグー朝の首都でもある。"}],"1248":[{"rank":"2","note":"二つの美を持つ鳥","exp":"270","type":"鳥類","name":"コウカンチョウ","desc":"頭部は赤、胸は白、背中は灰色の羽毛に覆われた鳥。地上に降りて植物の種子などをついばむ。水辺近くの開けた林に生息する。"}],"2693":[{"rank":"2","note":"王朝の花<br/><br/><br/>発見時経験値370　発見物カード経験値185","exp":"370","type":"植物","name":"ヒロハハシドイ","desc":"朝鮮王朝の徳寿宮で珍重されている植物。\n薄い桃色の花が密集して咲く。"}],"6161":[{"rank":"3","note":"","exp":"460","type":"歴史遺物","name":"長信宮灯","desc":"宮女の姿をかたどった燭台。漢代の中山王劉勝夫妻の墳墓から発見された副葬品の一つでもある。油を燃やして明かりにする。青銅製の像の内部は空洞であり、煙や煤を外に出さないように工夫されている。"}],"5751":[{"rank":"5","note":"2017.02.07新規追加","exp":"1380","type":"地理","name":"ワイベン島","desc":"オーストラリアの北方のアラフラ海に位置する島の一つ。周囲の海には真珠貝が多く生息している。"}],"1918":[{"rank":"5","note":"恋愛事情<br/><br/>発見時経験値936　発見物カード経験値468","exp":"936","type":"鳥類","name":"フウチョウ","desc":"ニューギニア周辺に生息する鳥。オスは美しい飾り羽を持つ。繁殖期になるとオスは一カ所に集まって踊り、メスを誘う。メスはそれを見てつがいとなるオスを選ぶ。"}],"6911":[{"rank":"5","note":"","exp":"630","type":"鳥類","name":"ルリオーストラリアムシクイの雄","desc":"雄のルリオーストラリウアムシクイ。通常期は雌と同じ灰色や茶褐色の姿をしているが、繁殖期になると鮮やかな青色の羽へ換羽する。花を使った求愛行動を行うことでも知られている。"}],"647":[{"rank":"1","note":"書きかけの地図","exp":"190","type":"地理","name":"ソコトラ（地理）","desc":"アデンの東に浮かぶ島である。歴史は古く、軍事的に重要な場所。"}],"2386":[{"rank":"2","note":"カタツムリの殻を被る虫","exp":"340","type":"虫類","name":"マイマイカブリ","desc":"平地から山地にかけて生息する、日本固有の昆虫。\nマイマイの殻へと頭を突っ込み、消化液で溶かして捕食する。その際の格好が、名前の由来となっている。"}],"1778":[{"rank":"2","note":"［勅命］[[新大陸西岸進出の先人の記録","exp":"310","type":"歴史遺物","name":"マゼラン南米冒険記","desc":"マゼランが南米で航海を中断していた時に記したと思われる書物。先住民族などについて記載されている。"}],"497":[{"rank":"1","note":"古代ギリシャの傑作","exp":"130","type":"美術品","name":"御者の像","desc":"デルフォイ遺跡で発見された御者の青銅像。競技会で優勝した御者の功績を讃えるために奉納されたものであろう。均整の取れたすばらしい像である。"}],"6071":[{"rank":"5","note":"","exp":"1660","type":"伝承","name":"ブギーマン","desc":"子どもの心から生まれるといわれる、恐ろしい幽霊。共通の見た目は持たず、多くの地域に伝承が残っている。それぞれの地域で親が子どもをしつけるためにその存在を口にしたのだろう。"}],"2435":[{"rank":"4","note":"ダンジョン","exp":"690","type":"財宝","name":"天下布武の印","desc":"「天下布武」の四文字が刻まれた印章。近世の日本では、文書上の署名の代わりにこうした印が用いられた。\n使用者の政治思想を表しているとされるが、詳細は不明である。"}],"6526":[{"rank":"2","note":"","exp":"","type":"財宝","name":"ケプラー式望遠鏡","desc":"ケプラーが原理を考案した屈折式望遠鏡。のちにシャイナーによって製作された。対物と接眼、いずれも凸レンズを使う。ガリレオ式よりもさらに高倍率で広視野だが、上下逆に映るため、主として天体観測に用いられたとされる。"}],"6002":[{"rank":"4","note":"","exp":"690","type":"気象・現象","name":"ブルーファイア","desc":"インドネシアのジャワ島で見られる、青い炎が噴きあがる現象。岩の間から噴き出す硫黄ガスが燃焼する際に青く光ったものと考えらている。また、ガスが液体化して燃焼しながら流れることもあるという。"}],"6181":[{"rank":"2","note":"","exp":"270","type":"宗教遺物","name":"聖地への旅","desc":"4世紀ローマ帝国のヒスパニア属州であったイベリア半島南部出身の女性、エゲリアが書き残した聖地巡礼の記録。\nイベリア半島からイェルサレム、シナイ半島などへ巡礼に出向いた時の出来事を記している。"}],"1544":[{"rank":"2","note":"奇怪な風景","exp":"330","type":"地理","name":"シャーク湾","desc":"オーストラリア西部に広がる湾。湾内の海水は塩分が非常に高いため、ある種の藻しか生息できない。\n他にも白色の貝殻のみで構成された砂浜があるなど、狭い地域でありながら、特異な環境が各所に見られる。"}],"6947":[{"rank":"3","note":"発見物カード:245<br/>中央大西洋 視認","exp":"490","type":"天文","name":"シェラタン","desc":"おひつじ座のベータ星で、3等星。名はアラビア語で「2つ」を意味すると言われているが、その2つが何を指しているかは分かっていない。"}],"6104":[{"rank":"2","note":"","exp":"380","type":"宗教遺物","name":"トマス・アクィナスの神学大全","desc":"ドミニコ会修道士で神学者のトマス・アクィナスが書いた神学書。当時哲学でのみ論じられていた「理性」で神の存在を証明するという手法で記され、彼の名声を確たるものとした。一方で、その思想を危険視する者もいたという。"}],"6836":[{"rank":"5","note":"発見物カード:470","exp":"940","type":"美術品","name":"オレイテュイアを略奪するボレアス","desc":"ギリシャ神話の一幕を題材とし、17世紀初頭に描かれた油彩画。フランドル派の画家ルーベンスの作。古代ローマの詩人オウィディウスの『変身物語』を取材した内容で、ほぼ正方形の画板に描かれた構図は創意的で、迫力にあふれる。"}],"5105":[{"rank":"2","note":"到達する","exp":"226","type":"港・集落","name":"ナッソー","desc":"フロリダ半島の南、西インド諸島北部ニュープロビデンス島の街。西インド諸島と呼ばれるのは、15世紀末、クリストバル・コロンの航海により発見されたがインドと誤認されたため。"}],"6325":[{"rank":"5","note":"","exp":"1010","type":"海洋生物","name":"イロワケイルカ","desc":"南米やインド洋の海域に生息するイルカ。体の色が白と黒に分かれている。その体色から「パンダイルカ」とも呼ばれる。雄はお腹の模様がしずくのような形で、雌は丸い形をしている。"}],"1011":[{"rank":"3","note":"魅惑の毛皮","exp":"478","type":"小型生物","name":"ヨーロッパミンク","desc":"被毛はこげ茶から黒をしていて、唇には白い筋がある。夜行性で、鳥や哺乳類、魚などの小型生物をエサとしている。"}],"218":[{"rank":"1","note":"トゲのある魚の地図","exp":"13","type":"海洋生物","name":"ハリセンボン","desc":"警戒するとふくらんで多数の針が立つ魚。おそらくフグの仲間であろう。温暖な海でよく見られる。"}],"5086":[{"rank":"1","note":"到達する","exp":"124","type":"港・集落","name":"ソコトラ","desc":"アデンの東に浮かぶ島である。歴史は古く、軍事的に重要な場所。"}],"4855":[{"rank":"1","note":"「明るい星の観測記録」<br/><br/>発見物カード:90","exp":"180","type":"天文","name":"アケルナル","desc":"エリダスヌス座の中で最も明るい星。エリダヌス座の南端に位置している。南半球では目立つ星だが、北半球で観測できる場所は限られている。"}],"6553":[{"rank":"5","note":"レガシー『英知の灯アレクサンドリア』右上","exp":"","type":"史跡","name":"ヘラクレスの塔","desc":"イベリア半島北西部に建つ古代ローマ時代の灯台。アレクサンドリアの大灯台をモデルに造られたといわれ、ギリシャ神話の英雄ヘラクレスにちなんで名づけられた。この地の伝説の王ブレオガンの逸話からブリガンティウムの塔とも呼ばれる。"}],"516":[{"rank":"1","note":"古代の金細工の地図","exp":"39","type":"歴史遺物","name":"古代の金の器","desc":"金で作られたり、金めっきを施した器。実用品より、祭器や特別な用途に使われていたようである。"}],"1837":[{"rank":"1","note":"古の書物の地図","exp":"140","type":"宗教遺物","name":"エノク書","desc":"旧約聖書の偽典のひとつ。エノクとは「従う者」という意味を持ちノアの曽祖父に当たる人物だとされる。エノク書によれば、エノクは神によって天に連れられた後に天使メタトロンに変容させられたとある。"}],"6926":[{"rank":"2","note":"追究クエスト<br/>発見物カード:180","exp":"360","type":"宗教遺物","name":"踊るシヴァ神の像","desc":"ヒンドゥー教のシヴァ神が踊っている姿をかたどった像。ナタラージャと呼ばれる。三つの目と四本の腕を持ち、その姿は世界の輪廻を表すと言われている。"}],"2946":[{"rank":"5","note":"歴史小説における証明","exp":"1120","type":"財宝","name":"青龍偃月刀","desc":"中国・後漢の武将、関羽が使ったといわれる長柄の武器。刃に大きな龍が刻み込まれている。偃月刀の形ができあがったのは明の時代で、実戦より演舞向きの武器だった。実際にこれを関羽が扱ったとは考えにくいが…。"}],"3738":[{"rank":"4","note":"極北の地のウシ","exp":"750","type":"大型生物","name":"ジャコウウシ","desc":"グリーンランドなどの極北の陸地に生息するウシの一種。体長は2m程度で、柔らかい下毛の上に硬くて長い毛が生えている。"}],"2688":[{"rank":"2","note":"伽耶の記録","exp":"210","type":"歴史遺物","name":"古代の鉄塊","desc":"朽ちかけた鉄の塊。\n伽耶時代、鉄の延べ棒は、貨幣として使われていたらしい。"}],"5593":[{"rank":"2","note":"カリカット北","exp":"340","type":"気象・現象","name":"雹","desc":"空から小さな氷晶が降り注ぐ現象"}],"5374":[{"rank":"2","note":"","exp":"240","type":"植物","name":"アカツメクサ","desc":"ヨーロッパ原産の草で、ピンクの花をつける。\n牧草やハーブとして利用され、土壌を肥沃にする効果もある。"}],"2334":[{"rank":"1","note":"古代の道具の地図","exp":"150","type":"歴史遺物","name":"縄文土器","desc":"日本で発見された、縄目の模様が特徴的な土器。強度が低く、壊れやすい。\n土器を焼く技術が未発達だった時代に作られたものと思われる。"}],"545":[{"rank":"1","note":"古代の墳墓の地図","exp":"11","type":"歴史遺物","name":"木の棺","desc":"古くから埋葬に使われた木の棺。直方体の物から、人の形に加工した、手の込んだ物までさまざまである。"}],"5339":[{"rank":"5","note":"クエスト「揺れる天王星」<br/>発見物カード:575","exp":"1170","type":"天文","name":"海王星","desc":"天王星の軌道の揺れから存在が予測された惑星。\n大きさは天王星とほぼ同じだが、より深い青色をしている。"}],"2268":[{"rank":"3","note":"遺跡に響く石音","exp":"490","type":"歴史遺物","name":"シャカオ叩き台","desc":"シャカオとは、木の根を潰して作られた飲料のこと。\n人々はこの場所でシャカオを製造し、儀式に臨んだのだろう。"}],"1346":[{"rank":"1","note":"小さな花の地図","exp":"110","type":"植物","name":"トレニア","desc":"花径が2cmほどの小さな花。中心を包み込むように花弁を付ける。色は淡青、桃、黄など様々である。"}],"6274":[{"rank":"2","note":"","exp":"370","type":"宗教遺物","name":"スーリヤの仮面","desc":"インド神話に登場する太陽神スーリヤの顔をかたどった仮面。\nインドではこうして金属や石などで作った神の顔を寺院や家庭の各所に飾ることが多いらしい。太陽の光と熱を現地の人々の感覚で表現した顔つきとなっている。"}],"5467":[{"rank":"1","note":"「黒い腹を持つ鳥の地図」<br/>発見物カード:90","exp":"180","type":"鳥類","name":"クロハラトキ","desc":"パンタナル湿原でよく見られるトキの一種。\n飛びながら甲高い声で鳴く。胸より下の体表面が黒いのが特徴。"}],"5939":[{"rank":"2","note":"","exp":"210","type":"史跡","name":"シエガ・ベルデの岩絵遺跡群","desc":"ポルトガル北部のコア渓谷からイスパニア西部のシエガ・ベルデにかけて広がる遺跡。数千に及ぶ線刻画で動物や人などが描かれている。二万年前から存在していると見られ、この地域の野外にある古代の岩絵としては最大規模である。"}],"5854":[{"rank":"5","note":"","exp":"1420","type":"化石","name":"巨大な草食動物の化石","desc":"非常に巨大な四足歩行型の動物の骨。ユーラシア大陸の全域で化石が発見されており、研究が進められている。生態は謎に包まれているが、犬歯より切歯が発達しているため草食だったと思われる。"}],"2597":[{"rank":"4","note":"絵で楽しむ恋物語","exp":"640","type":"美術品","name":"源氏物語絵巻","desc":"源氏物語を題材とした日本の絵巻物の一つ。文と絵を交互に楽しめるように構成されている。物語文の後に、物語の一場面を描いた絵が添えられている。"}],"5400":[{"rank":"1","note":"古代文明の伝説","exp":"20","type":"地理","name":"サントリニ島","desc":"クレタ島のカンディアから北北東にある小さな島である。中央に火山があり、はるか昔に大噴火を起こしたと伝えられている。伝説の古代文明・アトランティスがあったという説もある。"}],"3790":[{"rank":"2","note":"視認","exp":"340","type":"天文","name":"ベテルギウス","desc":"冬の大三角を構成する1等星で、オリオン座の左上に位置する赤い星。星座図では、オリオンの右肩にあたる。「ジャウザーの手」という意味のアラビア語が名前の由来のようだが、「ジャウザー」が何者なのかも分かっていない。"}],"5260":[{"rank":"2","note":"タンジャーウール地方　再調査報酬","exp":"","type":"宗教遺物","name":"カーリーのレリーフ","desc":"寺院の壁に数多く彫られているレリーフの一つ。本尊シヴァ神の妻であるカーリーが、夫の腹の上で踊る様子が見事な手法で彫られている。"}],"6537":[{"rank":"5","note":"","exp":"1060","type":"伝承","name":"ノーム","desc":"土の精。四大元素のうち、土をつかさどるとされる精霊。ヒゲを貯えた小さな老人のような姿で、豊かな土壌を好むらしい。埋蔵物を探知する能力を持ち、貴金属や財宝を容易に掘り出せる。非常に賢く器用で、細工品を作るのが得意だという。"}],"542":[{"rank":"1","note":"古代の墳墓の地図","exp":"16","type":"歴史遺物","name":"古代の副葬品","desc":"故人を葬るときに一緒に埋葬された道具類。古代文明では、死後の世界で使うための物として、日用品や武具、装飾品などを墓室に納めた。"}],"6182":[{"rank":"2","note":"","exp":"340","type":"歴史遺物","name":"アラム語の書簡","desc":"紀元前5世紀、エジプト南部の街エレファンティネに住んでいたユダヤ人が書いたものらしい書簡のパピルス。当時のエジプトはペルシャ王国の支配下にあり、多数のユダヤ人傭兵たちの居住区も当地にあった。"}],"6402":[{"rank":"5","note":"レガシー：砂漠に栄えた巨石文明","exp":"4000","type":"宗教建築","name":"在りし日のギザのピラミッド","desc":"ギザの地にそびえる巨大なピラミッド。クフ王の墓と伝わる。膨大な数の四角い石を人力で積み上げた。表面は磨いた白い大理石で覆われて輝いている。建設中は周囲に労働者たちの住宅が並び、食物や麦酒も支給されていたという。"}],"2100":[{"rank":"3","note":"インドの奥義書","exp":"500","type":"宗教遺物","name":"ウパニシャッド","desc":"ヒンドゥー教の聖典の一つ。哲学を記したものであり、奥義書とも呼ばれている。\n師が弟子に物事を教示する様から、そのように呼ばれるようになったらしい。"}],"1679":[{"rank":"5","note":"謎の光","exp":"1014","type":"虫類","name":"プラチナコガネ","desc":"最大の特徴は、宝石のように金銀に光り輝く羽。このような光沢を持った種は、稀にしか見られない。"}],"5717":[{"rank":"2","note":"2017.02.07新規追加","exp":"370","type":"気象・現象","name":"レンズ雲","desc":"山や山脈の上空に発生する平たい形状の雲。上空の風が強い時に発生しやすいことから、悪天候になる前触れとしても各地で知られている。"}],"5638":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:140","exp":"280","type":"天文","name":"水がめの流星群","desc":"みずがめ座の水がめの部分の方角から飛び出すように現れる流星群。ハレー彗星が母体と推定される。"}],"6276":[{"rank":"2","note":"","exp":"210","type":"地理","name":"テルセイラ島","desc":"アゾレス諸島にある島のひとつ。発見当初は「ブラジル島」と呼ばれ、ピッツィガーノの海図にも描かれた。\n「英雄の港」を意味するアングラ・ド・エロイズモの港町があるほか、海賊に備えて数々の砦が築かれている。"}],"1317":[{"rank":"2","note":"海峡に横たわる島","exp":"220","type":"地理","name":"ビリトゥン島","desc":"マラッカ海峡東部に位置する島。古くから良質なスズの産地として知られている。そのため島でははるか北の国からもたらされた皿や器などが見つかる。"}],"5156":[{"rank":"2","note":"到達する","exp":"241","type":"港・集落","name":"マラカイボ","desc":"カリブ海・大西洋につながる湾ともいえる塩分を含んだ南米最大の湖、マラカイボ湖に面した街。この湖では時折、音を出さない雷が発生することがある。"}],"5069":[{"rank":"1","note":"到達する","exp":"76","type":"港・集落","name":"ザンジバル","desc":"東アフリカに浮かぶ島にある街。アフリカとアラビア・インドとの交易の中継点として栄えている。農作物のほか、貴金属や宝石が産出する。"}],"6773":[{"rank":"4","note":"発見物カード:340","exp":"680","type":"海洋生物","name":"カクレウオ","desc":"別名「真珠魚」。各大洋の熱帯域に広く生息している。隙を見てナマコやカキの内部に侵入し、そのまますみかとして利用する習性を持つ。基本宿主には害をなさないが、益をなすこともない。"}],"1668":[{"rank":"2","note":"ラノ・ララクの調査","exp":"350","type":"宗教建築","name":"ホツ・マツア王のモアイ","desc":"ラパ・ヌイの伝説上の王であるホツ・マツア王の像。王は賢者ハウマカの見た夢を信じ、航海の旅に出て、やがてこの地にたどり着いた。この像自体がどんな意味を持って建てられているのかはよく分からない。"}],"1636":[{"rank":"2","note":"クエスtp「第二補給港候補地の選定」<br/>発見物カード:170","exp":"340","type":"地理","name":"フィジー諸島","desc":"バヌアツの東に位置する諸島。大小合わせて300を超える島々で構成されているが、最大の島は、南西に位置するヴィティレブ島である。ヨーロッパ人としては初めて、ネーデルラントのアベル・タスマンがフィジー諸島の北部を発見した。"}],"1332":[{"rank":"1","note":"書きかけの地図","exp":"160","type":"地理","name":"カリマタ海峡","desc":"カリマンタン島の西に横たわる海峡。遠浅で波は穏やか。近年はこのあたりに、海賊の報告が多く寄せられている。"}],"1992":[{"rank":"2","note":"釣り","exp":"340","type":"海洋生物","name":"バルチックチョウザメ","desc":"ほのかに金色がかった茶色の体が特徴のチョウザメ。ヨーロッパ北部に分布するようだ。"}],"5895":[{"rank":"1","note":"","exp":"150","type":"宗教遺物","name":"マニ石","desc":"お経やマントラが刻まれた石。チベット仏教が信仰されている地域で見られる。横を通る際には、右肩を石に向けて歩くのが良いとされている。"}],"2689":[{"rank":"3","note":"大陸の山","exp":"530","type":"地理","name":"金剛山","desc":"東西南北に峰が連なっている山々。\n朝鮮王朝初期の政治家である鄭道伝の、その父親が十年間、修行のためこの山々にこもっていたらしい。"}],"1453":[{"rank":"4","note":"第5の世界","exp":"648","type":"宗教遺物","name":"黒曜石のナイフ","desc":"黒曜石でできた小型のナイフ。神々に捧げる生贄の心臓を生きたままえぐったといわれている。強度はないが、鋭利で切れ味は良い。"}],"4842":[{"rank":"4","note":"クエスト「勝負の行方」<br/>発見物カード:315","exp":"630","type":"天文","name":"うみへび座","desc":"ギリシャ神話に登場する怪物・ヒュドラが天に上げられたとされる星座。ヘラクレスと、その従者であるイオラオスによって退治されたといわれる。"}],"180":[{"rank":"1","note":"スルタンという存在","exp":"180","type":"財宝","name":"スルタンの装束","desc":"スルタンとは、イスラム勢力の最高権力者のことである。これは昔のスルタンが身につけていたとされる衣装。中国産の絹を惜しげもなく使い、使われている染料も非常に高価なものだ。"}],"1093":[{"rank":"2","note":"クエスト「キューバ近辺の島」<br/>発見物カード:180","exp":"365","type":"地理","name":"ピノス島","desc":"キューバ島西部の南に浮かぶ島。名はスペイン語で「松」の意味。比較的、大きな島だ。キューバ島は耕作に向いているので栄えているが、ピノス島はあまり人がいないようだ。"}],"6105":[{"rank":"3","note":"クエスト「奇しき縁」<br/>発見物カード:235","exp":"470","type":"宗教遺物","name":"フランシスコ・ボルハのロザリオ","desc":"イエズス会の第3代総長、フランシスコ・ボルハが生前持っていた簡素なロザリオ。彼はチェーザレ・ボルジアを大伯父に持ち、神聖ローマ皇帝カール5世のもとでひとかどの地位を得ていたが、そのような人物の所持品には到底見えない。"}],"6612":[{"rank":"5","note":"レガシー美の叡智　右下","exp":"2650","type":"歴史遺物","name":"ジョワユーズ","desc":"ローランの歌で登場するシャルルマーニュが所持している聖剣。後にフランスにおいては国王の王権を象徴する剣となった。国王の戴冠式にも使われたことがある。"}],"2422":[{"rank":"1","note":"釣り","exp":"200","type":"海洋生物","name":"オオウナギ","desc":"通常のウナギの倍以上にまで成長することがある魚。\nただし、ウナギとは別種で、ややずんぐりとした体形と斑模様により見分けられる。"}],"6029":[{"rank":"4","note":"","exp":"990","type":"宗教遺物","name":"聖大公妃オリガの洗礼着","desc":"キエフ大公イーゴリ1世の妃であるオリガがコンスタンティノープルで洗礼を受けた時に着ていたと言われる洗礼着。\n簡素な造りの洗礼着だが、独特の刺繍が施されている。"}],"5737":[{"rank":"2","note":"バイカル湖周辺再調査地図","exp":"","type":"宗教遺物","name":"古儀式派祈祷法本","desc":"ロシア正教会での古い祈祷様式を記した本。ロシア正教会での奉神礼改革を機に主流派から分離した諸教派を古儀式派と呼ぶ。"}],"1162":[{"rank":"1","note":"クエスト「最も美しい海」<br/>発見物カード:60","exp":"120","type":"地理","name":"ホンジュラス湾","desc":"ユカタン半島の東に渡る湾。広大な面積にサンゴ礁が広がる。美しいカリブの海の中でも格別に美しい。"}],"6381":[{"rank":"3","note":"","exp":"440","type":"歴史遺物","name":"クセルクセス王のつぼ","desc":"アケメネス朝ペルシャの王、クセルクセスの名が刻まれた壺。古代都市ハリカルナッソスがあった地で発見された。庶民が手に入れられるようなものではないため、この地を治めていた者が遺したものであろう。"}],"1574":[{"rank":"2","note":"猛毒","exp":"320","type":"大型生物","name":"タイパン","desc":"最大で3mを超すヘビ。獲物に遭遇すると、すばやい動きで攻撃をしかけ、強力な毒で仕留める。人間も、噛まれれば死は免れないだろう。"}],"5619":[{"rank":"5","note":"","exp":"990","type":"海洋生物","name":"タカアシガニ","desc":"東アジアの深海に生息するカニの一種。脚が非常に長く、成長したオスが鋏足を広げると4m近くに達することがある。"}],"6803":[{"rank":"5","note":"発見物カード:460","exp":"920","type":"小型生物","name":"ユキウサギ","desc":"北極圏など寒いところに生息する、ウサギの一種。冬毛は真っ白であり、雪に紛れるのに適している。季節によって姿を変える。"}],"124":[{"rank":"1","note":"ギリシャ最高神の像","exp":"60","type":"宗教遺物","name":"ゼウス像","desc":"ギリシャ神話の最高神の像。ローマ神話ではジュピターという。天空の神で雷を操る支配神である反面、多情で人間の女に次々と手を出す逸話が多い。オリンピアの神殿が有名である。"}],"77":[{"rank":"2","note":"ヴェールをかぶった女の肖像","exp":"310","type":"美術品","name":"ヴェールの女","desc":"ラファエロ作の、女性の肖像画。ラファエロの恋人に貴族の婚礼衣装を着せた姿だとも言われている。多忙なラファエロは弟子に手伝わせることが多かったが、この絵は一人で描きあげたという。"}],"5894":[{"rank":"2","note":"","exp":"350","type":"鳥類","name":"ヒメコンドル","desc":"中南米に生息する大型の鳥。鳥類にしては珍しく嗅覚が発達しており、餌である動物の死がいを遠くから探すことができる。"}],"5466":[{"rank":"1","note":"「リスに似た中型動物の地図」<br/>発見物カード:90","exp":"180","type":"小型生物","name":"アグーチ","desc":"パンタナル湿原でよく見られる体長50～70cmの動物。\nリスのような外見をしているが、大型で足が細長く、尻尾が短い。動きは俊敏で。走るのが速く、6mほど跳躍するといわれている。"}],"3903":[{"rank":"2","note":"天文学者の観測記録","exp":"330","type":"天文","name":"いっかくじゅう座のバラ状の星雲","desc":"いっかくじゅう座の北にあるバラのような形をした星雲。天の川の中にある。肉眼では見られない。"}],"834":[{"rank":"2","note":"地下への入口の地図","exp":"340","type":"歴史遺物","name":"死者の街","desc":"ネクロポリスともいい大規模な集団墓地のこと。形態や埋葬方法は文明により異なるが、死者の街の造営は複数の文明で見られる。"}],"1807":[{"rank":"2","note":"聖マルコを救う信者の絵","exp":"330","type":"美術品","name":"聖マルコの遺体の運搬","desc":"ヴェネツィアのグランデ・ディ・サン・マルコ同信会館のために描かれた連作「聖マルコ伝」の代表作とされる絵画。人物には強烈な明暗がつけられ、巧みな遠近法と相まって絵画に臨場感と緊張感を与えている。"}],"116":[{"rank":"1","note":"ギニア湾の島","exp":"105","type":"地理","name":"ビオコ島","desc":"アフリカ西岸、赤道直下に浮かぶ島。ブビ人が住んでいる。山がちで森林におおわれ、年間を通じて高温で降水量も多い。"}],"5835":[{"rank":"3","note":"","exp":"480","type":"中型生物","name":"サイベリアン","desc":"シベリアの名を冠する猫。丸みを帯びた体は長い毛に覆われ、その名前のとおり、極寒のシベリア地方に適応している。"}],"6594":[{"rank":"5","note":"レガシー伝説の王都バビロン　左下","exp":"","type":"史跡","name":"チャン・チャン遺跡","desc":"南米、チムー王国の都市跡といわれる広大な古代遺跡。日干し煉瓦で作られた建物の外壁と網目状の部屋仕切りが特徴的な遺跡で、その名には「輝ける太陽」の意味があるという。"}],"2979":[{"rank":"3","note":"流浪のチョウ","exp":"480","type":"虫類","name":"オオカバマダラ","desc":"羽全体を覆う黒いふちと、白い斑点が特徴のチョウ。飛行能力に優れており、渡り鳥のように、数千キロにも及ぶ大移動を行うともいわれている。"}],"6932":[{"rank":"5","note":"発見物カード:425","exp":"850","type":"海洋生物","name":"タテジマキンチャクダイ","desc":"インド洋や太平洋などの暖流域に生息する美しい魚。幼魚から成魚にかけて大きく色や模様が変化する。成魚は深い青色の体に鮮やかな黄色の縞を持つ。縄張り意識が強く、同種とも争う。"}],"6275":[{"rank":"5","note":"伝承航路(リヴァイアサン)","exp":"1660","type":"伝承","name":"ロードス島の巨像","desc":"太陽神ヘリオスへの感謝の証として建造された大彫像。建造後、数十年後に地震によって倒壊したとされる。彫像の大きさは、像の親指を腕で抱えることはほとんどできず、指はあらゆる彫像よりも大きいとされる。"}],"686":[{"rank":"2","note":"クエスト「森の中の黒い影」<br/><br/>発見時経験値:350　発見物カード経験値:175","exp":"350","type":"大型生物","name":"ゴリラ","desc":"西アフリカの熱帯地域に生息する、極めて大型のサルである。非常に発達した筋肉を持ち集団で生活してるようだ。行動を見る限りでは、かなり高い知能を持っているようだ。人間に近いのだろうか。"}],"5231":[{"rank":"2","note":"クエスト「ガリレオの著作」<br/>発見物カード:180","exp":"360","type":"財宝","name":"星界の報告","desc":"ガリレオ・ガリレイが出版した最初の書籍。望遠鏡の仕組みや作成方法から月を始めとした天体観測の結果が記されている。美しい文体でも知られ、ガリレオの詩才を遺憾なく発揮した一作である。"}],"5369":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"ナルメル王のパレット","desc":"浮き彫りが施された盾状の黒い石。大きさから儀式用と思われる。浮き彫りの中には、敵と戦うナルメル王とおぼしき人物がある。"}],"520":[{"rank":"1","note":"古代の集落の地図","exp":"9","type":"歴史遺物","name":"ガラスの破片","desc":"古代に用いられたガラス器の破片。文明により、色や透明度、加工技術に違いがある。"}],"2764":[{"rank":"2","note":"ダンジョン","exp":"240","type":"宗教遺物","name":"洞窟のような墓地","desc":"地下に作られた墓地。カタコンベとも呼ばれローマにある教会のものが最初といわれる。シラクサにもいくつかのカタコンベがあり、大きいものは天然の洞窟を思わせる、入り組んだ構造が特徴的である。"}],"4798":[{"rank":"1","note":"「書きかけの地図」<br/>発見物カード:65","exp":"130","type":"地理","name":"ダイヤモンドヘッド","desc":"ハワイ島の北西の島に位置する山脈。巨大な火山烟云に上っていた火口の迹が残っている。山頂付近で発見された透明な石は、ダイヤモンドを連想させる。"}],"5998":[{"rank":"1","note":"クエスト「民衆による十字軍」<br/>発見物カード:30","exp":"60","type":"歴史遺物","name":"隠者ピエールの杖","desc":"11世紀末、民衆十字軍の中でも最大規模の集団を率いた修道士ピエールの杖。2万人以上の民衆軍は統率が取れず、トルコ軍に敗れて瓦解した。"}],"6348":[{"rank":"2","note":"","exp":"300","type":"歴史遺物","name":"大灯台のトリトン像","desc":"全高130メートルを超える大灯台の四方に飾られていたとされるトリトンの像。最頂部には父であるポセイドンの像も飾られていたとされ、大灯台は海を象徴する神々の加護をうけた。"}],"3805":[{"rank":"4","note":"緑色の巨大魚","exp":"800","type":"海洋生物","name":"グリーンモレイ","desc":"大西洋の西部などの浅い海に生息するウツボの一種。大型で、全長が2mを超えることもある。身体は黄褐色で模様はなく、体色と海中の色の兼ね合いで鮮やかな緑色に見える。"}],"5486":[{"rank":"2","note":"","exp":"260","type":"虫類","name":"スカシジャノメチョウ","desc":"中南米などの熱帯雨林で見られるチョウ。\nガラスのような透明な羽を持ち、後羽には赤や紫色のぼかしのような模様が入っている。"}],"6530":[{"rank":"5","note":"レガシー星の叡智　下","exp":"2550","type":"史跡","name":"ティコ・ブラーエの壁面四分儀","desc":"天体の高度を観測する機器で、巨大な目盛り付きの真鍮板が壁面に設置されている。ティコ・ブラーエが建設したウラニボリ天文台にあった。真鍮板近くに接眼孔、正対する壁面上部に対物孔があり、これらを通して目視で観測する。"}],"6130":[{"rank":"2","note":"","exp":"380","type":"宗教遺物","name":"タルムード","desc":"モーセが伝えたもう一つの律法とされる「口伝律法」をまとめた書物集。「ミシュナー」や「ゲマーラー」などで構成されている。「未完の律法書」とも呼ばれ、ユダヤ教における信仰と生活面での規範の一つとなっている。"}],"1689":[{"rank":"2","note":"釣り","exp":"250","type":"海洋生物","name":"タンバキー","desc":"黒い魚体の魚。大きさは1mほどもある。ピラニアの仲間のようだ。"}],"1548":[{"rank":"1","note":"書きかけの地図","exp":"160","type":"地理","name":"モーニントン島","desc":"オーストラリア北東部に存在するカーペンタリア湾最南奥の島。さらにその南部はいくつもの中型河川の河口を持ち、よい漁場となっている。"}],"5764":[{"rank":"2","note":"","exp":"","type":"地理","name":"カトマンズ盆地","desc":"ヒマラヤ山脈に囲まれた盆地。近辺に三つの王国が存在し、複雑な政治事情が展開されているようだ。"}],"6528":[{"rank":"2","note":"","exp":"","type":"気象・現象","name":"川霧","desc":"川を覆うように発生する蒸気霧と呼ばれる霧の一種。寒冷地でよく見られ、水温が周囲の気温より高い状態で川の水が蒸発し、その後冷たい空気に冷やされることで、霧となる。"}],"2426":[{"rank":"2","note":"気品ある鳥の地図","exp":"270","type":"鳥類","name":"タンチョウ","desc":"東アジアの湿原に生息する鳥。一部は人里近くで越冬する。\nほっそりとした白地の体に、黒と赤の二色が映えている。その上品な姿は、東洋の美術品にも多く見られる。"}],"261":[{"rank":"2","note":"ファラオの装身具","exp":"220","type":"歴史遺物","name":"ラムセス2世の頭飾り","desc":"ラムセス2世は古代エジプトのファラオで、多数の建造物を作ったことで知られる。ラムセス2世の墓は墓泥棒に荒らされていたので所持品は珍しい。"}],"5212":[{"rank":"2","note":"公州北　陸地再調査報酬","exp":"","type":"歴史遺物","name":"武寧王の誌石","desc":"百済の武寧王が崩御した際の記録が描かれた石碑。当時百済は高句麗に攻められて衰退していたが、寧東大将軍とも呼ばれる武寧王は高句麗を破って梁王朝へ属し、百済を強国にした。"}],"2553":[{"rank":"2","note":"ダンジョン","exp":"330","type":"財宝","name":"人面のつぼ","desc":"台湾島で見つかった、腹部に人の顔が描かれたつぼ。\nうっすらと描かれた眉や切れ長の目など、その表現力は当時の人々が高い製陶技術を持っていたことを示している。"}],"2377":[{"rank":"2","note":"日暮れの情趣を醸す声","exp":"250","type":"虫類","name":"ヒグラシ","desc":"東アジアの薄暗い林に生息する、カナカナカナ…、と鳴くセミ。\n日暮れ時によく鳴くことから、日を暮れさせるセミとして名付けられた。"}],"3317":[{"rank":"4","note":"交易所店主からの協力依頼","exp":"700","type":"植物","name":"ムラサキバレンギク","desc":"北米東部から中南部にかけて生息する植物。夏から秋にかけて赤紫色の花を咲かせる。根には薬効があり、薬としても利用される。"}],"3620":[{"rank":"5","note":"クエスト「過ぎし年月の物語」<br/>発見物カード:465","exp":"930","type":"歴史遺物","name":"原初年代記","desc":"キエフ大公国の歴史を記した書物。12世紀ごろに年代記者ネストルにより編纂されたとされる。キエフ大公国の成り立ちや宗教について、幅広く記されている。"}],"2840":[{"rank":"1","note":"水墨画の地図","exp":"160","type":"美術品","name":"黄公望の水墨画","desc":"元代末期の画家・黄公望が描いた水墨画。\n墨の濃淡でさまざまな風景を描き表しており絵の全長は6m以上にも及ぶ。"}],"375":[{"rank":"5","note":"怪鳥","exp":"1163","type":"大型生物","name":"エピオルニス","desc":"マダガスカル島に生息する巨大な鳥。高さが3mもあり、体重はなんと500kgを超える。10kgにもなる卵を砂地に産み、太陽熱を利用して孵化（ふか）させるようだ。羽毛や肉を目当てに狩られており、このままでは絶滅するかもしれない。"}],"3694":[{"rank":"5","note":"師匠が遺した物","exp":"1110","type":"財宝","name":"スコモローフの仮面","desc":"ロシアで活動する芸人たちを、「スコモローフ」と呼ぶ。彼らはこの仮面を被り、楽器を奏でて詩を歌い、人々に娯楽を提供していたという。"}],"6717":[{"rank":"2","note":"追究クエスト　発見物カード:115","exp":"230","type":"鳥類","name":"コクマルガラス","desc":"東アジアに広く分布するカラス。小柄で、全長は約33cm。毛色の色は黒に限らず、首周りから腹にかけてが白い個体も多い。越冬のために長距離を移動する渡り鳥である。"}],"1984":[{"rank":"5","note":"生きた石の魚<br/><br/>発見時経験値1124　発見物カード経験値562","exp":"1124","type":"海洋生物","name":"シーラカンス","desc":"ほかの魚とはなにかが違う、奇妙な魚。ヒレの根元にもウロコが生えていたり、尾ビレの形が変わっていたり、浮き袋に脂肪が詰まっていたりなど…。勘に過ぎないが、とてつもない存在のように思えてならない。"}],"5570":[{"rank":"2","note":"リマ北の地図　財宝鑑定・開錠・探索","exp":"280","type":"財宝","name":"チャフチャス","desc":"アンデス地方の伝統的な楽器。マイチルという植物の実や、リャマの爪などが複数付いている。手や足首に装着し、振って音を出す。"}],"6720":[{"rank":"2","note":"","exp":"448","type":"財宝","name":"ディルハム銀貨","desc":"古代ペルシャで鋳造された銀貨。中東地域で広く流通し、イスラム帝国の勢力拡大と共に流通範囲をさらに広げた。表面には、イスラム教の信仰を表すアラビア文字が刻まれている。"}],"7019":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"マグナ・カルタ","desc":"13世紀初頭のイングランドで作成された、全63条からなるラテン語の憲章。「自由の大憲章」とも呼ばれ、ジョン王の統治に反発した貴族たちが、王権を法の下に制限するために起草した。ジョン王が貴族の要求を受け入れて署名し、発布した。"}],"5169":[{"rank":"1","note":"到達する","exp":"25","type":"港・集落","name":"ラスパルマス","desc":"マディラの南方に浮かぶカナリア諸島の街。年中温暖な気候で過ごしやすく、美しい景観に恵まれている。温かい気候はサトウキビの栽培に向いており、近海ではサンゴが採れるようだ。"}],"6880":[{"rank":"5","note":"発見物カード:730","exp":"1460","type":"虫類","name":"ニコヤカヒメグモ","desc":"ハワイ諸島にのみ生息する珍しいクモ。体長はおよそ5mmで、細長い脚と半透明の黄色い体を持つ。人間の笑顔を思わせる変わった模様から、その名が付いた。"}],"812":[{"rank":"3","note":"大地の躍動<br/><br/>発見時経験値467　発見物カード経験値233","exp":"467","type":"大型生物","name":"アフリカスイギュウ","desc":"大きな体と太い角が特徴。普段は50頭ほどの群れで行動するが、その群れ同士が集まって2000匹以上の巨大な群れを作ることもある。オスは、メスや地位を得るために争ったりする。"}],"2010":[{"rank":"3","note":"サルベージ","exp":"460","type":"歴史遺物","name":"ブエン・ヘスス号","desc":"フランシスコ・デ・イバラ船長の船で、イスパニアの新大陸貿易船の一隻。\nバルパライソ沖でネーデルラント海軍のオリヴァー・ヴァン・ノールト提督に襲撃され、沈没した。"}],"6193":[{"rank":"2","note":"","exp":"210","type":"財宝","name":"ビリンバウ","desc":"アフリカから入ってきた、いわゆる打弦楽器の一種らしい。弓のような形をしており、「バケタ」という棒で弦を叩いて演奏する。中身をくり抜き乾燥させたヒョウタンを共鳴板としており、その他の装飾などは特にない。"}],"790":[{"rank":"1","note":"クエスト「対になった天馬の像」<br/>発見物カード:60","exp":"120","type":"美術品","name":"天馬にまたがるメルクリウス","desc":"「天馬にまたがる名声の女神」と対になっている巨大な大理石像。ペガサスにローマ神話の神・メルクリウスがまたがっている。対にして置けば、豪華な眺めだろう。"}],"1325":[{"rank":"2","note":"マニラ南の巨島","exp":"210","type":"地理","name":"ミンダナオ島","desc":"東南アジアの中でも北東に位置する島。古くからアラブ商人との交流があり、イスラムの影響下にあるが、マゼランのセブ島上陸よりイスパニアの干渉も受けている。"}],"3264":[{"rank":"5","note":"岩壁の絵","exp":"970","type":"史跡","name":"トゥウェイフルフォンテーン","desc":"西アフリカに位置する遺跡。2000点を超える線画が岩石に描かれている。主にゾウやキリンなどの動物が描かれており、中には人間の足型なども見られる。"}],"5742":[{"rank":"5","note":"2017.02.07新規追加","exp":"","type":"宗教遺物","name":"ファフニールの財宝","desc":"出所不明の財宝。誰が置いたのか、いつから置かれているのか、一切不明である。ファフニールが守っていた呪いの財宝ではないか、という噂を恐れ、盗賊さえ持ち去ろうとしない。"}],"6334":[{"rank":"4","note":"クエスト「トゲのあるカエル」<br/>発見物カード:315","exp":"630","type":"小型生物","name":"角怪","desc":"東アジアの山間部に生息するカエル。雄のみ口の周りにトゲ状の突起があり、その大きさを比べることで雄同士の優劣を決めているようだ。"}],"72":[{"rank":"2","note":"インド東の湾","exp":"350","type":"地理","name":"ベンガル湾","desc":"インドの東に広がる広大な湾。ガンジス川をはじめ、大河がいくつも流れ込んでいる。沿岸には天然の良港がいくつもある。"}],"6252":[{"rank":"3","note":"","exp":"540","type":"歴史遺物","name":"グラゴル文字の石碑","desc":"東ヨーロッパ最古の文字と言われるグラゴル文字で記された石碑。グラゴル文字は９世紀にテサロニキ出身の聖職者キュリロスとメトディオスによってギリシャ文字をもとに考案され、キリル文字の原型になったとされている。"}],"6496":[{"rank":"5","note":"レガシー女神信仰の地エフェソス　右上","exp":"1650","type":"歴史遺物","name":"記録抹消刑の記録","desc":"ある者が記録抹消刑を受けたという記録。有名になりたいがためにエフェソスのアルテミス神殿に放火し、焼失させた男は、処刑ののちあらゆる記録から名前を抹消された。しかし、他国の歴史家がその名を書き残してしまい、今に伝わる。"}],"139":[{"rank":"5","note":"クラウ・ソナス","exp":"1222","type":"歴史遺物","name":"クラウ・ソナス","desc":"ケルト神話四大秘宝の一つで不敗の剣と言われる。ダーナ神族の王・ヌァザの持ち物で、一度さやから抜かれると、逃れられる敵はいないという。"}],"1903":[{"rank":"1","note":"メソアメリカの盃の地図","exp":"190","type":"歴史遺物","name":"ひすいの盃","desc":"ひすいで作られた大型の盃。これだけ大きなものを作れるということはひすいの産出が豊富だったのであろう。"}],"6853":[{"rank":"3","note":"発見物カード:225","exp":"450","type":"天文","name":"おおいぬ座散開星団","desc":"おおいぬ座の中にある星団。シリウスの南に複数の星が集まっているため目視も可能。精度の高い望遠鏡であれば星雲状の光の中に明るく輝く複数の星が確認できる。"}],"2858":[{"rank":"5","note":"いつか帰るところ","exp":"1250","type":"財宝","name":"玉璽","desc":"読みは「ぎょくじ」。皇帝が用いる印章で、始皇帝が定めた。\n史書では玉でできていると伝えられるが、なんらかの事情があって金で覆われたと思われる。伝国の玉璽であると思われるが、今となっては定かではない。"}],"6860":[{"rank":"1","note":"クエスト「続・科学の星座」<br/>発見物カード:190","exp":"380","type":"天文","name":"ポリマ","desc":"おとめ座のガンマ星。この星座の恒星の中ではスピカに次いで\n２番目に明るい３等星。名前はカメーネと呼ばれるローマ神話\nの女神の一人「ポリマ」に由来すると言われている。"}],"2494":[{"rank":"1","note":"珍しい屏風絵の地図","exp":"130","type":"美術品","name":"唐絵屏風","desc":"読みは「からえびょうぶ」。中国伝来の技法や画風で描かれた、日本の屏風。有力者の邸宅や宮中などで、調度品として用いられた。"}],"6399":[{"rank":"5","note":"レガシー：砂漠に栄えた巨石文明","exp":"1500","type":"歴史遺物","name":"イムホテプの設計図","desc":"パピルスに古代エジプトの文字と図面らしきものが書かれている。初のピラミッドといわれるジェセル王の階段ピラミッドを築いた、宰相イムホテプによるピラミッドの設計図かもしれない。"}],"3675":[{"rank":"2","note":"※釣り<br/>※発見物カード:140","exp":"280","type":"海洋生物","name":"キングサーモン","desc":"別名はマスノスケ。北太平洋に分布し、産卵の時は生まれ育った川を遡上するという習性を持つ。体長が大きく最大で1.5m程度にも及ぶ。身には脂肪分が多く、美味である。"}],"955":[{"rank":"2","note":"変わった構図の聖母子画","exp":"280","type":"美術品","name":"聖アンナと聖母子","desc":"レオナルド・ダ・ヴィンチ作の絵。聖アンナの膝にマリアが座り、幼いイエスを抱こうとしている。アンナはマリアの母であるが、ここではマリアと同じくらいの年齢で描かれている。この絵は未完成だそうだ。"}],"1691":[{"rank":"2","note":"大きな羽の虫の地図","exp":"255","type":"虫類","name":"テイオウゼミ","desc":"体長10cmほど、羽を広げると20cmにもなる最大級のセミ。"}],"1954":[{"rank":"4","note":"鳥の名を持つ花","exp":"700","type":"植物","name":"ファイアーバード","desc":"新大陸の熱帯に生息するバショウの一種。鮮やかな紅い花を咲かせる。花弁の形は火の鳥を思わせる。"}],"6192":[{"rank":"2","note":"","exp":"370","type":"史跡","name":"カタ・ジュタ","desc":"地元の言葉で「多くの頭」という意味の岩山で、ウルルと同じく現地人たちの聖地の一つでもある。夜間にさまざまな儀式が行われており、罪人を罰する刑場としての役割も果たしているようだ。"}],"3665":[{"rank":"5","note":"ダンジョン","exp":"1080","type":"歴史遺物","name":"トトメス3世の年代記","desc":"古代エジプトの領土を大きく広げたファラオトトメス3世の事績を記したレリーフ。トトメス3世は度々シリア方面に遠征し、ミタンニ王国などと争い、戦利品や貢物をアメン神殿に寄進したという。"}],"6891":[{"rank":"","note":"","exp":"","type":"レリック","name":"古の交易都市へと続く道","desc":"華南には東西交易によって繁栄を極めた、長安という都市があった。そこへと続く道には、様々な国の商人が行き交っていたという。"}],"2831":[{"rank":"4","note":"平和を求める気持ち","exp":"660","type":"美術品","name":"李迪の絵画","desc":"宋代の宮廷画人・李迪が描いた牛画。\n家畜の牛を画題にした絵は、戦乱のない平和な農村を謳歌するという意味を持つことが多い。"}],"3775":[{"rank":"4","note":"夜空の秤","exp":"790","type":"天文","name":"てんびん座","desc":"黄道十二星座の1つ。正義の女神アストライアが持つ、正邪を量る天秤だとされる。てんびん座には「北の爪」「南の爪」とさそり座に由来するような名の星があるため、元々はさそり座の一部であったと考えられる。"}],"3154":[{"rank":"2","note":"パリに建てられた宝石","exp":"340","type":"宗教建築","name":"サント・シャペル","desc":"パリのシテ島に建てられた、キリスト教の礼拝堂。数々の聖遺物が納められている。壮麗なステンドグラスが窓を覆う、ゴシック建築の輝かしさを表した建築物である。"}],"4859":[{"rank":"2","note":"「明るい星の観測記録」<br/>発見物カード:225","exp":"250","type":"天文","name":"アルファルド","desc":"うみへび座の中で最も明るい星。アラビア語て゜「孤独なるもの」を意味する。うみへび座の心臓にあたる位置にあるため、ヘビの心臓という意味の「コル・ヒドラエ」という名で呼ばれることもある。"}],"5518":[{"rank":"2","note":"","exp":"480","type":"地理","name":"セノーテ","desc":"ユカタン半島の石灰岩地帯で見られる、陥没した地面に地下水かだ溜まってできた泉。水底に鍾乳洞か沈んでいる場合がある。"}],"2860":[{"rank":"3","note":"虞美人草","exp":"540","type":"植物","name":"ヒナゲシ","desc":"中国からヨーロッパにかけて広い地域で生息する、寒さに強い一年草。四枚弁の薄い花びらを持つ。秦時代の将軍・項羽の愛姫・虞美人に由来する「虞美人草」という名でも呼ばれる。彼女の墓には、この花がよく咲いたといわれている。"}],"5669":[{"rank":"3","note":"","exp":"270","type":"海洋生物","name":"ゴブリンシャーク","desc":"見た目から、邪悪な聖霊にたとえられるサメの一種。大きく突出した特徴的な吻を持っているが、非常に柔らかい。生存時は両顎は口の中に収納されているが、死亡時、時間が経過すると剥き出しになる。"}],"3876":[{"rank":"2","note":"北米の歌","exp":"240","type":"財宝","name":"ヤンキードゥードゥルの詞","desc":"アメリカ独立戦争時に北米で流行した民謡の詞が記された手記。\n替え歌が多く存在し、その詞が持つ意味もさまざまである。"}],"6346":[{"rank":"2","note":"","exp":"300","type":"史跡","name":"ヘプタスタディオン","desc":"アレクサンドリア大灯台が建設されたファロス島とアレクサンドリアの街との距離およそ1キロメートルを結ぶ長大な堤防。その長さ（ヘプタ=7）と距離の単位（スタディオン）からヘプタスタディオンといわれる。"}],"6482":[{"rank":"5","note":"","exp":"1000","type":"小型生物","name":"ファイアサラマンダー","desc":"ヨーロッパの比較的高地で見られる、まだらが黄色いイモリ。毒腺を持っており、そこから発せられる毒が火を思わせることから、四大元素の火を司る精霊サラマンダーの名を冠している。"}],"1504":[{"rank":"1","note":"斑模様のチョウの地図","exp":"140","type":"虫類","name":"ホソバオオゴマダラ","desc":"大型で飛び方が優雅な美しいチョウ。森林の水辺に生息する。"}],"816":[{"rank":"1","note":"大理石のマリア像","exp":"60","type":"美術品","name":"受胎告知のマリア","desc":"リーメンシュナイダー作の彩色大理石像。受胎告知を受けたマリアの像である。イタリア方面のマリア像とは違う魅力があり、清楚な美しさが印象的だ。"}],"6131":[{"rank":"5","note":"","exp":"1040","type":"歴史遺物","name":"ポルトガル王子の剣","desc":"ポルトガル国王、ジョアン1世の妃であったフィリパ・デ・レンカストレが病床にて、セウタ攻略戦に赴く息子たちに授けた剣の一振り。攻略戦の勝利後に、いずれかの王子によって教会に献納されたようだ。"}],"1485":[{"rank":"1","note":"赤い葉の植物の地図","exp":"45","type":"植物","name":"ポインセチア","desc":"苞（ほう）と呼ばれる赤い葉の中央に、小さな黄色い花を付ける。花よりも、葉に特徴のある植物である。"}],"2854":[{"rank":"3","note":"兵法の極意","exp":"530","type":"財宝","name":"孫子兵法","desc":"春秋時代の将軍・孫武が著した兵法書。天運に左右されると考えられていた戦争の勝因、敗因について分析している。"}],"1989":[{"rank":"5","note":"釣り","exp":"816","type":"海洋生物","name":"ターポン","desc":"大きなニシンのような見た目に、銀色に輝く魚体をもつ。凶暴な大魚である。"}],"3375":[{"rank":"4","note":"聖書にまつわる香","exp":"690","type":"植物","name":"オオウイキョウ","desc":"中東に分布する植物。草丈は約2mで、茎の先に黄色の花を付ける。樹脂から作られる精油は、香料や薬として利用される。"}],"6167":[{"rank":"2","note":"","exp":"320","type":"宗教遺物","name":"レゲンダ・アウレア","desc":"13世紀のジェノヴァ大司教であったドミニコ会士、ヤコブス・デ・ウォラギネによって記された聖人伝。「黄金伝説」とも呼ばれる。聖人たちの伝承のほかに主要な祭日についての記述もあり、分量としては旧・新約聖書にも匹敵するという。"}],"1775":[{"rank":"2","note":"クエスト「近場の漁場」<br/>発見物カード:150","exp":"300","type":"地理","name":"パナマ湾","desc":"パナマ地峡の南部に広がる湾。地峡の北にはメキシコ湾・カリブ海が広がる。この地峡をうまく通り抜ける手段があれば、南北の往来が賑わうのだが…。"}],"1621":[{"rank":"3","note":"青色に染まった鳥","exp":"495","type":"鳥類","name":"アオコンゴウインコ","desc":"銀青色の頭と、細長い尾をした鳥。背の高い木のてっぺんで羽を休め、毎日同じ道筋を飛ぶ。種子、木の実などを食べる。"}],"708":[{"rank":"3","note":"人魚の涙","exp":"495","type":"財宝","name":"人魚の涙","desc":"直径2cmもの真珠。しかも純白で素晴らしい光沢を持っている。ほかの真珠とは明らかに格の違う美しさがあり人魚の涙だと信じられたのもうなずける。"}],"6998":[{"rank":"5","note":"","exp":"900","type":"宗教遺物","name":"テミスの天秤","desc":"ギリシャ神話の女神テミスの像がかつて左手に持っていたとされる天秤。正邪や善悪を量る道具とされ、正義や公平の象徴とされている。"}],"568":[{"rank":"1","note":"五賢帝の大理石像","exp":"70","type":"歴史遺物","name":"ハドリアヌス帝の大理石像","desc":"ハドリアヌス帝は、古代ローマ五賢帝の三人目である。防衛策に徹して制度を整え、ローマを発展させた。"}],"6639":[{"rank":"5","note":"レガシー商の叡智・財貨の交易路　右下","exp":"","type":"財宝","name":"琥珀の埋葬品","desc":"琥珀をふんだんに使用して作った首飾り。ハルシュタット文明時代の墓から発掘された副葬品の一つ。貴族の持ち物ではないかと考えられる。"}],"5729":[{"rank":"5","note":"インドの人気者","exp":"1470","type":"歴史遺物","name":"カルナの耳環","desc":"『マハーバーラタ』に登場する英雄カルナが身に着けていたという黄金の耳環。鎧と共に身に着けると、不死身の力を得ると伝えられている。"}],"5575":[{"rank":"1","note":"","exp":"190","type":"財宝","name":"ガンバン","desc":"インドネシア地方の打楽器。橋名板の上にさまざまな大きさの木や竹を並べ、叩いて旋律を奏でる。"}],"484":[{"rank":"4","note":"古代インドの「法」","exp":"684","type":"宗教遺物","name":"ダルマの石柱","desc":"ダルマとは、古代インドのサンスクリット語で「法」を意味する。宇宙の法則、真理のことであるが、仏教では根本的概念とされた。この石柱は仏教に帰依したアショーカ王が、領土に建てたものだとされている。"}],"5880":[{"rank":"5","note":"クエスト「残りの守護神獣」<br/>発見物カード:685","exp":"1370","type":"天文","name":"北方七宿玄武","desc":"中国星座において、天の赤道を28に分割した二十八宿のうち北方の七宿をまとめたもの。みずがめ座やペガスス座などが含まれる。"}],"6847":[{"rank":"2","note":"発見物カード:105","exp":"210","type":"天文","name":"ニハル","desc":"うさぎ座で2番目に明るいベータ星。3等星であり、黄色味を帯びた輝きをもつ。名はアラビア語で「喉の渇きを癒やし始めたラクダたち」を意味する。"}],"15":[{"rank":"1","note":"アナトリア半島の古い文明","exp":"180","type":"歴史遺物","name":"リディアの貨幣","desc":"アナトリア半島の古代国・リディアのものと見られる貨幣。有史で最古の貨幣鋳造と思われる。"}],"3891":[{"rank":"3","note":"クエスト「古代エジプトの星座」<br/>発見物カード:300","exp":"600","type":"天文","name":"かみのけ座","desc":"古代エジプトでプトレマイオス朝の王妃ベレニケが女神アフロディテに捧げた髪の毛とされる。ベレニケの髪の毛は美しさで名高く、喜んだ女神アフロディテはこれを天に上げたといわれる。"}],"1234":[{"rank":"5","note":"［勅命］[未知なる危険]","exp":"910","type":"大型生物","name":"ピューマ","desc":"がっしりとした体と長い尾、そして金色の目を持つ。様々な環境に適応し、高い身体能力でネズミやウサギなどを捕食する。"}],"2441":[{"rank":"2","note":"ダンジョン","exp":"300","type":"宗教遺物","name":"プタハ像","desc":"古代エジプトの神の一つ。職人の守護神。闇や冥界の神とも呼ばれる。アブ・シンベル神殿の至聖所は、この像にのみ光が当たらない構造になっている。"}],"5695":[{"rank":"5","note":"2017.02.07新規追加","exp":"1110","type":"史跡","name":"ムスタンの洞窟群","desc":"ネパール地方の、とある断崖に掘られた謎の洞窟群。仏教壁画が存在し、宗教的施設だった可能性がある。しかしいまだ解明されていない謎も多く、なんのために掘られたのかを断定することはできない。"}],"171":[{"rank":"2","note":"ズールーの神話","exp":"220","type":"宗教遺物","name":"ウンクルンクル像","desc":"南アフリカに住むズールーの天空神の像。ウンクルンクルはズールーの言葉で「先祖」を意味する。死ぬことになった人間に、子を作ることを許し、火を与えた。"}],"340":[{"rank":"3","note":"違う色の同じ鳥","exp":"539","type":"鳥類","name":"ヤツガシラ","desc":"見る角度によって深い緑色や黒に変わる、光沢のある羽が特徴。紅色のくちばしと、白い斑模様の尾を持つ。グループで活動し、主に昆虫を食べる。"}],"5025":[{"rank":"2","note":"到達する","exp":"246","type":"港・集落","name":"ウィレムスタッド","desc":"カリブ海最南端、キュラソー島東南部に位置する街。15世紀末、アロンソ・オヘーダとアメリゴ・ヴェスプッチによって発見された。"}],"3008":[{"rank":"2","note":"奇妙な石の地図","exp":"230","type":"化石","name":"キバのあるトカゲのような石","desc":"ジョギンズで出土したトカゲに似た石。\nトカゲにしては、アゴの部分が細長い気もするが、古代にはこんな生物が生息していたのだろうか？"}],"6492":[{"rank":"5","note":"追究クエスト","exp":"1720","type":"植物","name":"プヤ・ライモンディの花","desc":"百年に一度、花を咲かせるといわれるプヤ・ライモンディの花。その巨体一面に咲く花をたまたま目にすることができるのは、時の運に恵まれた者だけなのだろう。"}],"2483":[{"rank":"3","note":"崖に埋もれた堂","exp":"520","type":"宗教遺物","name":"達谷窟","desc":"読みは「たっこくのいわや」。平安時代の武官・坂上田村麻呂が、戦勝を記念して東北地方に建てた堂。建物の半分が崖に埋まり込んだような、独特の外観を持つ。毘沙門天が祀られている。"}],"5821":[{"rank":"3","note":"","exp":"","type":"宗教遺物","name":"出エジプト記","desc":"旧約聖書の第二の書。モーゼがイスラエル人を連れてエジプトを脱出した話が中心となっている。"}],"1678":[{"rank":"5","note":"金色のサル","exp":"1118","type":"小型生物","name":"ライオンタマリン","desc":"体長25cmほどしかない小型のサル。全身を金色の毛で覆われ、ライオンに似たたてがみを持つ。果実や花、昆虫などを食べる。"}],"7000":[{"rank":"5","note":"","exp":"","type":"宗教建築","name":"グリトニルの館","desc":"北欧神話に登場する、裁きの神フォルセティの館。エッダでは、この館での裁きはすべての諍いを鎮め、神々と人間が認める最良の法廷であったとされる。館は金と銀で造られ、遠くからでもその輝きを見ることができたと伝わっている。"}],"5910":[{"rank":"5","note":"クエスト「最後の守護神獣」<br/>発見物カード:665","exp":"1330","type":"天文","name":"南方七宿朱雀","desc":"中国星座において、天の赤道を28に分割した二十八宿のうち南方の七宿をまとめたもの。ふたご座やかに座などが含まれる。"}],"2709":[{"rank":"1","note":"大きな土器の地図","exp":"180","type":"歴史遺物","name":"炉形土器","desc":"火鉢のような形をしている土器。伽耶時代によく使用されたといわれる。\n土器製作技術が発達するにつれ大型化し、三角や半円形などの多様な文様が描かれるようになったという。"}],"103":[{"rank":"1","note":"クエスト「カナリア諸島の調査」<br/>発見物カード:20","exp":"40","type":"地理","name":"テネリフェ島","desc":"カナリア諸島の中で一番大きな島である。長さは100km、幅は50km程度で土地はよく肥えている。しかし、標高3700mにもなるテイデ火山があり、定住には充分な調査が必要となるだろう。"}],"5627":[{"rank":"1","note":"","exp":"180","type":"地理","name":"ヴォルガ川","desc":"ロシア西部を流れる、全長3500km以上にも及ぶ川。流域は肥沃であり、麦などが多く栽培される。"}],"5417":[{"rank":"2","note":"奇妙なカエルの地図（アマゾン奥地再調査報酬）","exp":"","type":"小型生物","name":"グラスフロッグ","desc":"主に南米の多湿帯に生息するカエルの珍種。腹部が半透明になっており、心臓や消化管などの内臓が透けて見える。生息範囲は非常に狭いようだ。"}],"5299":[{"rank":"4","note":"","exp":"700","type":"小型生物","name":"クロクビコブラ","desc":"アフリカ中部に生息する毒ヘビ。頭の後ろが黒いことが、名前の由来とされる。背面は暗褐色。攻撃の際に敵の目を狙って毒液を飛ばすことがあり、その飛距離は3mにも達する。毒も強力で、咬まれた部位が壊死(えし)するほどである。"}],"2300":[{"rank":"4","note":"クエスト「広場にある斜面」<br/>発見物カード:360","exp":"720","type":"史跡","name":"古代の闘技場","desc":"古代の球技「トラチトリ」が行われていたと思われる球場。\n他のマヤ文明の遺跡でも球場は見られるが、コパンのものは最大級であることから、当時の勢力の大きさが窺える。"}],"3156":[{"rank":"3","note":"古代遺跡の歩き方","exp":"540","type":"史跡","name":"フォロ・ロマーノ","desc":"古代ローマの政治・経済・宗教の中心地だったとされる遺跡。広場や議事堂、神殿などの遺構が並び、隆盛を極めた古代ローマの有様をうかがい知れる。"}],"414":[{"rank":"1","note":"奇妙な石の地図","exp":"28","type":"化石","name":"靴底のような虫の石","desc":"平らな虫のような生物の形をした石。フナムシに似ているように思うが、大きすぎる。この近くに、同じような生き物がいるのだろうか？　それより、この石はどうしてこんな模様なのだろう？"}],"5087":[{"rank":"1","note":"到達する","exp":"78","type":"港・集落","name":"ソファラ","desc":"東アフリカ南東部に位置する街。付近の交易の中心地である。大河に接しているため、農業が盛んである。また近郊の山地から産出する金と木材が流通している。"}],"6688":[{"rank":"3","note":"発見物カード:275","exp":"550","type":"天文","name":"ドゥーべ","desc":"おおぐま座アルファ星で、おおぐま座で最も明るい２等星。北斗七星のひしゃくの先端にあたる。ベータ星メラクと合わせて北極星を探す手がかりとなる。"}],"5091":[{"rank":"1","note":"到達する","exp":"22","type":"港・集落","name":"ダブリン","desc":"アイルランド最大の都市である。かつてヴァイキングが砦を築き、その後城が築かれた。ダブリンという名は「黒い水たまり」という意味である。産物は豚の加工品やウイスキーのほか、石炭や石墨を産出する。"}],"5635":[{"rank":"2","note":"","exp":"250","type":"鳥類","name":"シロハヤブサ","desc":"北米大陸の高山帯や、ユーラシア大陸の北部などに生息する鳥。\n全長は50cmあまりで、翼を広げると幅が1mを超える。"}],"1247":[{"rank":"3","note":"動きの遅い生物<br/><br/>発見時経験値473　発見物カード経験値236","exp":"473","type":"中型生物","name":"ナマケモノ","desc":"のろのろと動きの遅い動物。糞をするときなどは地上に降りるが、それ以外は、ほとんどの時間を木の上で過ごす。木の葉や芽、虫を食べる。"}],"5908":[{"rank":"5","note":"","exp":"1370","type":"宗教建築","name":"ヤサヴィ廟","desc":"12世紀に活躍したイスラム教の聖者、アフマド・ヤサヴィの墓が納められた廟。造営した人物が途中で死んだため、未完成である。"}],"6021":[{"rank":"5","note":"クエスト「かの姿を星空に」<br/>発見物カード:415","exp":"830","type":"天文","name":"ねこ座","desc":"猫好きの、猫好きによる、猫好きのための星座。\n大の猫好きとしても有名なフランスの天文学者であるラランドが「星空への仕返し」として考案したということだが、呼び名としてはいまいち定着していないようだ。"}],"5900":[{"rank":"5","note":"","exp":"1430","type":"大型生物","name":"マーコール","desc":"中央アジアに生息するヤギの仲間。長くねじれた一対の角と白く長い髭が特徴。主に高山地帯の草原や岩場で活動し、冬には標高の低い位置に移動する。一部の地域では角が薬用とされ、狩猟の対象になっている。"}],"3322":[{"rank":"3","note":"歌うイヌ<br/><br/>発見時経験値500　発見物カード経験値250","exp":"500","type":"中型生物","name":"コヨーテ","desc":"北米に生息するイヌの一種。「コヨーテ」とは、ナワトル語で「歌うイヌ」という意味であり、よく遠吠えをすることに由来する。姿はオオカミに似ているが、体長は約1mでオオカミより小型である。"}],"758":[{"rank":"1","note":"青銅の男性像の地図","exp":"57","type":"財宝","name":"ブロンズの男性像","desc":"青銅の男性像。古代ギリシャ風の、威厳のある像だ。当時のものではなく、最近の作だと思われる。"}],"6849":[{"rank":"2","note":"発見物カード:180","exp":"360","type":"天文","name":"クルサ","desc":"エリダヌス座のベータ星で、3等星。川の上流にあたる、北東の端に位置する。名はアラビアの伝承に登場する人物、ジャウザーの足元の足台が語源と言われている。"}],"4833":[{"rank":"3","note":"サカタザメ","exp":"470","type":"海洋生物","name":"サカタザメ","desc":"エイのような頭とサメのような体を持つ魚。サメと名がつくがエイの仲間に分類される。インド洋や太平洋の暖かい海に棲み、他の魚や甲殻類を餌とする。"}],"500":[{"rank":"1","note":"古代ギリシャの風景","exp":"110","type":"財宝","name":"ギリシャ案内記","desc":"パウサニアスが書いた古代ギリシャ案内書。実際に見て歩いた情景を、詳細に記録している。この案内記のおかげで、古代ギリシャの研究が進んでいる。"}],"6272":[{"rank":"5","note":"","exp":"960","type":"史跡","name":"カーリバンガン遺跡","desc":"インド西部にあるインダス文明の都市遺跡。古代には流れていた大河の左岸に築かれた都市だったという。\n焼きレンガを用いた区画が少なく、大半に日干しレンガを使っているのが、モヘンジョダロなどと大きく異なる点である。"}],"6630":[{"rank":"3","note":"追究クエスト<br/><br/>ログ見るとコンゴクジャクのようですので替えました<br/>2022/11/10","exp":"","type":"鳥類","name":"コンゴクジャク","desc":"アフリカの熱帯雨林に生息するクジャク。雌雄は体色こそ異なるものの他の違いはさほど見られず、いずれも鮮やかな飾り羽はない。果実や昆虫を主食とする。"}],"6171":[{"rank":"4","note":"","exp":"660","type":"財宝","name":"棺に入った動物ミイラ","desc":"末期王朝期のエジプトの神殿周辺で作られていた動物のミイラ。元来は貴人たちが自分の愛玩した動物や家畜たちの死後の楽園での復活を願ったものだったがこの時代には形骸化し、単なる縁起物として扱われることが多かったという。"}],"3912":[{"rank":"1","note":"「天文学者の観測記録」<br/>発見物カード:95","exp":"190","type":"天文","name":"小マゼラン星雲","desc":"南半球で見られる星雲で、大マゼラン星雲よりやや暗い。肉眼で見られる。天の南極に近い場所にあるため、北半球では低緯度地帯でしか見られない。"}],"6941":[{"rank":"2","note":"マディラ沖 視認","exp":"","type":"天文","name":"ハマル","desc":"おひつじ座のアルファ星。この星座の中では最も明るい2等星で、羊の頭に当たるところに位置する。名はアラビア語で「子羊」を意味する。"}],"3890":[{"rank":"2","note":"クエスト「エチオピアの王女」<br/>発見物カード:185","exp":"370","type":"天文","name":"アンドロメダ座","desc":"エチオピアの王女アンドロメダが死後に天に昇った姿とされる。アンドロメダはペルセウスとの間に六人の子をもうけ、長子ペルセスはペルシャ王家の祖となったといわれる。"}],"1152":[{"rank":"5","note":"［勅命］[未知なる危険]","exp":"910","type":"大型生物","name":"ピューマ","desc":"がっしりとした体と長い尾、そして金色の目を持つ。様々な環境に適応し、高い身体能力でネズミやウサギなどを捕食する。"}],"1592":[{"rank":"1","note":"黄色い花の地図","exp":"100","type":"植物","name":"マリーゴールド","desc":"強い香りのする、黄色い花を咲かせる。その鮮やかな花は、染料としても用いられる。"}],"3270":[{"rank":"4","note":"砂の花","exp":"610","type":"財宝","name":"砂漠のバラ","desc":"砂漠でまれに見られるバラの形に似た、石の塊のようなもの。おそらく砂が固まったものだと思われるが、中には半透明のものもありまるで水晶のようにも見える。"}],"5373":[{"rank":"5","note":"","exp":"","type":"史跡","name":"グイマーのピラミッド","desc":"カナリア諸島のテネリフェ島にある、長方形の階段状ピラミッド。積み上げられた石には加工が施されているが誰がなんの目的で作ったかは謎である。"}],"4800":[{"rank":"3","note":"クエスト「ハワイの雪神」<br/>発見物カード:250","exp":"504","type":"宗教遺物","name":"ポリアフ像","desc":"ハワイ島の雪の女神。冬になると雪に閉ざされるマウナ・ケア山に住むとされる。かつて火山の女神ペレと争って彼女を島の南側にある火山に追いやったという伝説がある。"}],"1718":[{"rank":"2","note":"釣り","exp":"260","type":"海洋生物","name":"マゼランアイナメ","desc":"南の海に生息する魚。非常に大きな口をしていて、タラのようにも見える。"}],"478":[{"rank":"4","note":"見果てぬ夢","exp":"612","type":"史跡","name":"ヴェルギナ遺跡","desc":"古代マケドニアの都・アイガイがあったとされる遺跡。マケドニア王のものと考えられる古墳がある。"}],"3169":[{"rank":"2","note":"東ローマの書物の地図","exp":"230","type":"財宝","name":"ヘルメス文書","desc":"コジモが入手し、マルシリオ・フィチーノがラテン語に翻訳した書物。東ローマ帝国で編集されたが、元々はエジプトで作成された哲学書のようだ。"}],"1565":[{"rank":"1","note":"メソアメリカの遺物の地図","exp":"150","type":"歴史遺物","name":"香炉","desc":"アステカの土地で見つかった土器製の香炉。祭祀道具に用いたのだろうか。"}],"6012":[{"rank":"2","note":"","exp":"320","type":"財宝","name":"エリュトゥラー海案内記","desc":"1世紀頃、古代ローマの属州だったエジプトで、ギリシャ人航海者により著された記録。エジプト・インド間の交易に携わる貿易業者向けに書かれたものであり、東の果てである中国も絹の産地として紹介されている。"}],"632":[{"rank":"2","note":"実在した理想郷","exp":"275","type":"歴史遺物","name":"エパメイノンダスの鎧","desc":"エパメイノンダスは、古代ギリシャ、テーベの政治・軍事家。新戦術を編み出し、スパルタの密集戦術を打ち破った。"}],"3917":[{"rank":"3","note":"クエスト「牛飼いに連れられた星座」<br/>発見物カード:250","exp":"500","type":"天文","name":"りょうけん座","desc":"うしかい座の牛飼いが連れている猟犬とされる星座。二頭の猟犬からなり、北側の犬はアステリオン、南側の犬はカラという。"}],"1926":[{"rank":"1","note":"高原の白い花の地図","exp":"150","type":"植物","name":"エーデルワイス","desc":"欧州の山脈に自生する高山植物。星型に開く白い花びらは繊毛で覆われているため、雪がかぶっているように見える。枯れてもあまりしおれずに、清らかな白い花が残る。希少なため現地では高貴な花として愛されている。"}],"3894":[{"rank":"4","note":"クエスト「すみかを造る動物」<br/>発見物カード:185","exp":"660","type":"中型生物","name":"ビーバー","desc":"北米などの森林地方の水辺に生息する動物。手に水かきがあり、水中生活に適している。泥やかじり倒した木で川の水を堰き止め、その中に巣を作る。巣に限らず、住みやすいように周囲の環境まで変える習性がある。"}],"6":[{"rank":"1","note":"アケメネス朝の最後","exp":"160","type":"歴史遺物","name":"ダレイオス3世の鎧","desc":"アケメネス朝ペルシャの最後の王、ダレイオス3世の鎧。アレクサンドロス大王に攻め込まれて連敗し、敗走先の総督に殺されてペルシャは滅びた。"}],"5861":[{"rank":"5","note":"","exp":"1410","type":"財宝","name":"平家物語","desc":"日本の有力武士であった平家の興亡を描いた軍記物語。琵琶法師と呼ばれる盲目の僧が語り伝えている。"}],"5044":[{"rank":"1","note":"到達する","exp":"69","type":"港・集落","name":"カーボヴェルデ","desc":"西アフリカのヴェルデ岬から西にある諸島。もとは無人島で、ヴェルデ岬にちなんで名づけられた。意味は「緑の岬」である。自然環境が厳しく、産業は漁業が中心である。周辺の海からサンゴが採れるようだ。"}],"5581":[{"rank":"3","note":"","exp":"600","type":"気象・現象","name":"太陽柱","desc":"日没や日の出の際に、太陽の上方に光の柱のようなものが見える現象。色は太陽と同じオレンジや赤色で観測される。"}],"3751":[{"rank":"3","note":"クエスト「獅子の尾」<br/>発見物カード:255","exp":"510","type":"天文","name":"デネボラ","desc":"獅子の尾という意味の名を持つ、白く輝くしし座の2等星。星座図では、文字どおり獅子の尾にあたる場所に位置する。アルクトゥルス、スピカとともに春の大三角を構成し、他の星座の目印となる。"}],"5746":[{"rank":"1","note":"","exp":"","type":"鳥類","name":"ソデグロヅル","desc":"全長およそ1mのツルの一種。翼の先が真っ黒なことが名前の由来になっている。止まって翼を畳むと黒い羽根がすべて隠れ、全身が真っ白に見える。"}],"1979":[{"rank":"2","note":"グアナコに似た動物","exp":"360","type":"大型生物","name":"ビクーニャ","desc":"アンデスの高地に生息する褐色の動物。姿はラクダに似ているが、体長が1.5mと小柄で、首の付け根から白くて長い髭のような毛が生えている。細くてとても柔らかな体毛は希少価値が高く、珍重されている。"}],"1542":[{"rank":"2","note":"クエスト「東西交易の要衝」<br/>発見物カード:135","exp":"270","type":"地理","name":"マレー半島","desc":"スマトラ島の北に位置する半島。マレー人の根拠地であり、古くから交易の要衝として栄えた。内陸部は広大な密林が広がり、他の地域では見られない動植物が数多く生息している。"}],"1521":[{"rank":"1","note":"奇妙な塊の地図","exp":"110","type":"歴史遺物","name":"ゴムボール","desc":"古代の球技「トラチトリ」で用いられた総ゴム製のボール。非常に重く素手や生身では怪我をするため、「トラチトリ」は防具を身に付けて行われた。"}],"1015":[{"rank":"1","note":"冥府の王","exp":"90","type":"宗教遺物","name":"ハデス像","desc":"ギリシャ神話の冥府の神の像。ハデスは冥府を治める厳格な神であると同時に、鉱物や宝石をつかさどる富の神としても知られる。"}],"5313":[{"rank":"1","note":"","exp":"150","type":"地理","name":"ウニアンガ湖群","desc":"サハラ砂漠に点在する湖。それぞれ大きさや深さ、水面の色合いが異なる。降雨量は少ないが、地下からの湧き水が豊富なため枯れることがないようだ。"}],"1420":[{"rank":"3","note":"古代の戦士たち","exp":"450","type":"歴史遺物","name":"トルテカの戦士像","desc":"中央アメリカで繁栄したといわれるトルテカ人の戦士の像。神殿の柱として造られたりもした。トルテカ人は戦闘色の強い民族だったという。"}],"1254":[{"rank":"2","note":"嵐に近い場所","exp":"280","type":"地理","name":"カトチェ岬","desc":"ユカタン半島の最先端にある岬。新大陸へ夢を追い求めたヨーロッパ人が、カリブの無慈悲な嵐によって流れ着くことが多いのが、この岬だ。"}],"3228":[{"rank":"3","note":"ヴァイキングの生活","exp":"470","type":"歴史遺物","name":"古代の糸巻き","desc":"ランス・オ・メドーの居住跡で見つかった糸巻き。作りが古欧風であることから、ヴァイキングが持ち込み、ここで生活を営んでいたことがわかる。"}],"1153":[{"rank":"3","note":"アステカの文化神","exp":"539","type":"宗教遺物","name":"ケツアルコアトル像","desc":"アステカ神話における文化神。アステカの神には珍しい、生贄を求めない平和を愛する神だといわれている。テスカトリポカの罠に嵌められ、中央を去るときに「葦の1の年に戻る」と言い残したという。"}],"3509":[{"rank":"","note":"","exp":"","type":"レリック","name":"アーサー","desc":"吟遊詩人たちに愛される、イングランドの伝説の王、アーサー。アーサーが眠るアヴァロンを再び訪れることはあるのだろうか。"}],"91":[{"rank":"1","note":"エジプトの壁画の地図","exp":"33","type":"歴史遺物","name":"エジプトの壁画","desc":"古代エジプトの神殿や墓所などでよく見られる壁画。多くは美しく彩色された神聖文字で神やファラオの栄光を讃える内容である。"}],"1602":[{"rank":"4","note":"美しい巻貝","exp":"624","type":"海洋生物","name":"オウムガイ","desc":"鎧姿の人の顔に似た形をしている生物。\n数十もある触手を使ってエサを捕食する。口と思われる場所から水を噴出して、水中を移動する。"}],"6463":[{"rank":"5","note":"","exp":"","type":"宗教建築","name":"モンテ・アルバンの天文台","desc":"要地を支配するため丘の上に建設された、防衛能力を有する集落が元となったという「モンテ・アルバン」。遺跡には他とは毛色の異なる建造物、天文台があり、征服した地名などが刻まれた石板がはめ込まれている。"}],"3685":[{"rank":"3","note":"書きかけの地図","exp":"480","type":"地理","name":"バイカル湖","desc":"ロシア南東部とモンゴル北部の間に位置する巨大な湖。多くの河川が流入するため、水量が豊富で生物の生息数も多い。"}],"1300":[{"rank":"3","note":"透明な魚","exp":"451","type":"海洋生物","name":"グラスキャットフィッシュ","desc":"体色を透明にすることで外敵から身を守っている魚。はっきりと見えるのは、骨、目、消化器官だけである。"}],"6067":[{"rank":"4","note":"","exp":"650","type":"歴史遺物","name":"フリードリヒ2世の剣","desc":"神聖ローマ皇帝であった、フリードリヒ2世が愛用していたという宝剣。彼は６カ国語を操り、西ヨーロッパの開明的な君主と称えられた。しかし、生涯を通してテンプル騎士団や教皇派と対立し、何度も破門された。"}],"6994":[{"rank":"","note":"","exp":"","type":"美術品","name":"トゲを抜く少年像","desc":"足裏に刺さったトゲを抜こうとする少年をかたどった彫刻。紀元前一世紀ごろに作られたブロンズ像。息づくような繊細な表現は、後世に多くの芸術家を魅了し、模刻のみならず絵画の題材としても多く取り上げられた。"}],"3742":[{"rank":"5","note":"氷海の永住者","exp":"1200","type":"海洋生物","name":"ホッキョククジラ","desc":"極北の海に生息するクジラの一種。大きく湾曲した下顎が特徴。頭蓋骨が頑強であり、その頭で流氷を砕き、海面に出る。"}],"6428":[{"rank":"5","note":"追究クエスト　発見物カード:560","exp":"1120","type":"財宝","name":"アゾット剣","desc":"錬金術師パラケルススが所有していたといわれる剣。柄頭には、宝石でも石でもない正体不明の物質が組み込まれ、表面に「Azoth」という文字が刻まれていたといわれる。"}],"5183":[{"rank":"1","note":"到達する","exp":"30","type":"港・集落","name":"ヴェネツィア","desc":"地中海最大の貿易都市として、非常に栄えている街。扱われている産物も、高価な物がほとんどである。しかし栄華の極みにあったこの街も、ほかの新興勢力に押されて傾きはじめているといわれる。"}],"380":[{"rank":"2","note":"クエスト「海賊のたまり場」<br/>発見物カード:160","exp":"320","type":"地理","name":"ラッカジブ諸島","desc":"インド南部の西に浮かぶ島々。40近い島からなる。少数だが人が住み、ヤシを栽培したり漁業をしたりして生活しているようだ。"}],"703":[{"rank":"1","note":"クエスト「針山のような動物」<br/>発見物カード:60","exp":"120","type":"中型生物","name":"ヤマアラシ","desc":"全身に長いトゲが生えている動物。アフリカで見られる。普段はおとなしいが、危険を感じると全身のトゲを逆立て、後ろ向きに突進してくる。大量のノミがついており、トゲも痛いがノミも困る。"}],"6277":[{"rank":"2","note":"","exp":"340","type":"鳥類","name":"アゾレスウソ","desc":"アゾレス諸島のサン・ミゲル島東部にのみ生息してる鳥で、現地の住民からは「プリオロ」と呼ばれている。島の森林地帯を中心に生息しているが、ここ最近は移民たちの開拓の影響で数が減っているという。"}],"3848":[{"rank":"2","note":"装飾された支柱","exp":"210","type":"歴史遺物","name":"トーテムポール","desc":"北米西岸の先住民の手で作られた木の彫刻。一族の歴史などに関係する動物や人が模様として刻まれ、家の柱や墓などとして立てられた。傷んでも修繕されず、朽ちて地に還されるのは、自然から生まれ自然に還るという彼らの考え方に基づく。"}],"430":[{"rank":"1","note":"巨大で凶暴なイルカ","exp":"200","type":"海洋生物","name":"シャチ","desc":"10m近い体長の、クジラの仲間。特徴のある模様と人間の身長より大きな背びれを持つ。かなり大きな群れで目撃されることもある。鳴き声で仲間と連絡をしているようだ。"}],"5127":[{"rank":"1","note":"到達する","exp":"17","type":"港・集落","name":"ファロ","desc":"リスボンの南に位置する、小都市。レコンキスタのとき、ポルトガル国内で最後までイスラム勢力が残っていた都市である。13世紀にポルトガル王がこの街を占拠し、レコンキスタは完了した。"}],"4865":[{"rank":"5","note":"夜空に輝く勇者","exp":"810","type":"天文","name":"ペルセウス座","desc":"ギリシャ神話に登場する英雄・ペルセウスが女神アテネによって天に上げられたとされる星座。片手には怪物・メデューサの首を携えているとされる。"}],"1669":[{"rank":"2","note":"ラノ・ララクの像の調査","exp":"350","type":"宗教建築","name":"アフ・トンガリキのモアイ","desc":"ラパ・ヌイの島の北東部にある、十五体のモアイ。十五体すべて同じ方向を向いている。島内のモアイの中でも大きなほうで、成人男性の三倍はある。"}],"6322":[{"rank":"4","note":"","exp":"650","type":"鳥類","name":"ニシコウライウグイス","desc":"夏と冬ですみかを変える渡り鳥。ヨーロッパをはじめアフリカ、西アジアなどに広く分布する。体と翼の色が異なるのが特徴で、特に雄は黄色い体と黒い翼のコントラストが美しいという。"}],"1313":[{"rank":"3","note":"思い出の花","exp":"600","type":"植物","name":"アマリリス","desc":"鮮やかな赤色がとても美しい。この花には、どことなく気品を感じる。"}],"4813":[{"rank":"4","note":"宋山里遺跡群 （深層隠し部屋）","exp":"","type":"歴史遺物","name":"金環の耳飾り","desc":"金製の特殊な耳飾り。切れ込みの入った部分があり、そこに耳を挟むなどして身につけると思われる。"}],"616":[{"rank":"1","note":"思い出の首飾り","exp":"110","type":"財宝","name":"王妃の首飾り","desc":"とある王妃の持ち物であったと伝えられる首飾り。巨大なルビーと大粒のサファイヤ、そして多数のダイヤモンドがちりばめられており、王家の権力を象徴している。"}],"2366":[{"rank":"1","note":"火のような花の地図","exp":"100","type":"植物","name":"ヒガンバナ","desc":"東アジアに広く分布する、放射状に花弁を開かせる花。マンジュシャゲとも呼ばれる。毒があり、害虫よけのために植えられることも多い。"}],"1335":[{"rank":"2","note":"書きかけの地図","exp":"220","type":"地理","name":"チェンドラワシ湾","desc":"ニューギニア島北西にある湾。蓋をするような位置に島がある。海賊の襲撃に対する注意が必要だろう。"}],"5455":[{"rank":"3","note":"渦巻き模様の土器","exp":"540","type":"歴史遺物","name":"マラジョ島の土器","desc":"アマゾン川河口に位置するマラジョ島で見つかった彩色土器。先住民が作った物とみられる。渦巻き模様など、幾何学的な文様が描かれている。"}],"817":[{"rank":"1","note":"大理石のレリーフの地図","exp":"69","type":"財宝","name":"大理石の彫刻タイル","desc":"大理石にレリーフを施したタイル。壁や床にはめ込んで装飾するためのものである。"}],"1236":[{"rank":"2","note":"縮む体<br/><br/>発見時経験値255　発見物カード経験値127","exp":"255","type":"小型生物","name":"アベコベガエル","desc":"他のカエルと違い、幼生の期間が長いため、成体の4倍近い大きさまで成長する。その後の変態の過程で体が縮む。"}],"88":[{"rank":"1","note":"エジプトの女神","exp":"110","type":"宗教遺物","name":"イシス像","desc":"エジプトの、豊穣と母性の女神の像。地母神ともされる。兄であるオシリスの妻であり、天空神・ホルスを産んだ。オシリスがセトに殺されると、ホルスを助けてセトを倒した。"}],"6405":[{"rank":"5","note":"","exp":"","type":"史跡","name":"円形劇場","desc":"古代ギリシャ風の野外劇場。ハリカルナッソスの背後の丘を掘り込む形で建造された。マウソロス王の時代に建てられたと伝わる。客席最前列の中央には、ギリシャの神ディオニソスの祭壇が置かれている。"}],"3262":[{"rank":"5","note":"闘士の二つ名<br/><br/>発見時経験値820　発見物カード経験値410","exp":"820","type":"中型生物","name":"ラーテル","desc":"アフリカからアジア西部および南部まで、広く分布する生物。サバンナや草原などに生息する。皮膚が厚く伸縮性に富んでおり、特に背中は肉食動物の牙も通さない。コブラなどのヘビの毒に対して耐性があり、捕食対象とすることもある。"}],"515":[{"rank":"1","note":"古代の金細工の地図","exp":"74","type":"歴史遺物","name":"金の装身具","desc":"金で作られた装身具。形や使い方が文明によってさまざまで、古代文明の交流や流通を知る手がかりになる。"}],"3730":[{"rank":"5","note":"文字資料収集","exp":"960","type":"歴史遺物","name":"蒙古字韻","desc":"モンゴルの文字であるパスパ文字を、東アジアの言語で解説したとされる書物。作者は不明。多くの写本が作られたと思われる。"}],"524":[{"rank":"1","note":"古代の集落の地図","exp":"12","type":"歴史遺物","name":"古代の木材","desc":"古代文明の建造物に用いられた木材。木材は加工しやすいのでよく用いられるが、多くが腐食しているため、原型がわかりづらい。"}],"6663":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"スクーダレヴ沈没船","desc":"ヴァイキング時代末期のヴァイキング船。敵を阻む防壁とするためデンマークの当時の首都・ロスキレ付近の海域に沈められた。"}],"2047":[{"rank":"2","note":"歴史調査の下調べ","exp":"320","type":"地理","name":"ケルチ海峡","desc":"黒海とアゾフ海を繋ぐ狭い海峡。\nかつて、この周辺にはボスポラス王国という古代都市が栄えていたという。"}],"3530":[{"rank":"","note":"","exp":"1680","type":"レリック","name":"ピュロス","desc":"エピロスのピュロス王はアレクサンドロス大王のあとを継がんとした戦術の天才である。その名は空しい苦闘と共に記憶されている。"}],"5390":[{"rank":"1","note":"","exp":"","type":"美術品","name":"サイクロプス像の頭部","desc":"ギリシャ神話に登場する単眼の巨人、サイクロプスの石像の頭部。ミュケナイ文明の遺跡には大きな石材を用いたものが多く、サイクロプスが積んだという伝説もある。"}],"1781":[{"rank":"2","note":"優れた芸術家たちの本","exp":"300","type":"美術品","name":"画家・彫刻家・建築家列伝","desc":"ジョルジョ・ヴァザーリによって記された芸術家の列伝。133人もの芸術家の生涯が綴られている。著者自身も絵画に建築にと多彩な才能を発揮した人物で芸術家の評価面においても信頼性が高い。美術史における一級の資料である。"}],"5725":[{"rank":"1","note":"2017.02.07新規追加","exp":"","type":"財宝","name":"コムズ","desc":"ユーラシア大陸中央部の伝統的な弦楽器。独特な形状と木製のきめ細かな装飾が非常に美しい。"}],"6518":[{"rank":"5","note":"","exp":"","type":"小型生物","name":"オリオフリネラ","desc":"特定の高地にしか生息しておらず、その環境にあわせ独自の進化を遂げたとされるカエルの一種。オタマジャクシの期間がなく、卵から直接カエルの姿で孵化することや、水かきを持たず、泳いだり飛び跳ねたりできないことが特徴といわれる。"}],"3318":[{"rank":"5","note":"ローマ帝国の政策転換","exp":"950","type":"史跡","name":"ハドリアヌスの長城","desc":"ローマ帝国の時代に、皇帝ハドリアヌスの命により築かれた防塁。帝国領土への、ケルト人の侵入を阻止することが目的とされる。\n10年もの歳月をかけ、110km余りの距離にわたって建設された。"}],"90":[{"rank":"1","note":"エジプトの天空神","exp":"110","type":"宗教遺物","name":"ホルス像","desc":"エジプトの神の像。ホルスはオシリスとイシスの息子で、天空の神である。セトに殺害された父の敵を、母の助けにより果たした。隼の姿、もしくは隼の顔をした姿で表される。"}],"789":[{"rank":"2","note":"太陽神を祀る寺院","exp":"260","type":"宗教建築","name":"コナーラク太陽神寺院","desc":"太陽神スーリヤを祀る寺院。寺院全体がスーリヤの乗る馬車に見立てられている。ガンガ朝のナラシンハ・デーヴァ1世がイスラム教徒との戦いに勝利した記念に建造したと言われている。"}],"6684":[{"rank":"1","note":"オスロとコペンハーゲンの間<br/>535，2077","exp":"40","type":"港・集落","name":"ヨーテボリ","desc":"スカンジナビア半島のイェータ川河口の街。\n貿易の拠点として繁栄している。グスタフ2世アドルフによって作られオランダ様式の建築物が並ぶ。ヨーテボリは「ゴートの都市」という意味。"}],"5021":[{"rank":"1","note":"到達する","exp":"21","type":"港・集落","name":"アンコナ","desc":"ヴェネツィアの南に位置する街。古代ローマ時代から港町として栄えた。12世紀にはローマ教皇から自由都市の特許を得ている。"}],"5563":[{"rank":"4","note":"クエスト「夜空の六分儀」<br/>発見物カード:325","exp":"650","type":"天文","name":"ろくぶんぎ座","desc":"ヘヴェリウスが制定した星座。火災で焼けてしまった、彼の愛用の六分儀が名前の由来である。"}],"269":[{"rank":"5","note":"ブリューナク","exp":"1209","type":"歴史遺物","name":"ブリューナク","desc":"ケルト神話四大秘宝の一つで太陽神・ルーの持ち物。光を放つ槍で同時に五人の敵を倒せるという。この槍をふるう姿からルーは「長き腕のルー」と呼ばれる。"}],"512":[{"rank":"1","note":"古代の貨幣の地図","exp":"14","type":"歴史遺物","name":"古代の金貨","desc":"金やその合金で作られた、古代の貨幣。金ははるか昔から貴重なものとされていた。"}],"3909":[{"rank":"5","note":"発見物カード:470<br/>　","exp":"940","type":"天文","name":"へびつかい座の新星","desc":"1604年にへびつかい座に現れた新星。最盛期には金星を除くどの星よりも明るくなった。ドイツの天文学者ヨハネス・ケプラーがくわしく研究したため、ケプラーの星と呼ばれることもある。"}],"2908":[{"rank":"3","note":"想いにまつわる鳥探し<br/><br/>発見時経験値480　発見物カード経験値240","exp":"480","type":"鳥類","name":"ソウシチョウ","desc":"中国南部やインド北部などに生息する小型の鳥。赤いくちばしと黄色い喉元が鮮やかである。\nつがいで行動することが多いため「相思鳥」という名前が付いたといわれる。"}],"6180":[{"rank":"2","note":"","exp":"390","type":"財宝","name":"アルスター物語の異本","desc":"アルスター物語に登場する英雄である、クーフーリンの伝承の一つを記したもの。物語の内容はキリスト教の教義を色濃く反映しており、他のアルスター物語での描写とは明らかに異色である。"}],"6169":[{"rank":"4","note":"","exp":"660","type":"小型生物","name":"アスプコブラ","desc":"アフリカ大陸から、アラビア半島にかけて生息しているコブラの一種。危険な毒蛇として畏怖の対象とされるだけでなく、ネズミを捕食する農業の守り神として昔から信仰の対象にもなっていた。"}],"5452":[{"rank":"3","note":"","exp":"470","type":"鳥類","name":"チョピ","desc":"黒い姿をした、小型の鳥。集団で生活をすることが多い。透き通った美しい声でさえずって、多くの人を魅了する。だが、なんのためにさえずるのかは定かではないようだ。"}],"2536":[{"rank":"2","note":"書きかけの地図","exp":"290","type":"地理","name":"太魯閣峡谷","desc":"淡水の南東に広がる、大理石が浸食されて築かれた大峡谷。\n周囲に連なる山々は、3000mを超える高さを誇る。\n大自然が作り上げた断崖が見どころ。"}],"1288":[{"rank":"2","note":"組まれた女神","exp":"280","type":"宗教遺物","name":"ラクシュミーのレリーフ","desc":"アンコール遺跡にあるラクシュミー像。アンコールには多数の女神像が見られる。この女神像はレンガ造りの柱に彫りこまれている。"}],"998":[{"rank":"1","note":"冒険者のバイブル","exp":"55","type":"財宝","name":"東方見聞録","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。"}],"5314":[{"rank":"4","note":"","exp":"660","type":"財宝","name":"リビアングラス","desc":"サハラの北東部で見つかる天然ガラス。古代エジプト時代から宝石として装身具などに使われてきた。火山のような高温の熱源がないこの地域で、ガラスがどのように生成されたかは不明である。"}],"3602":[{"rank":"2","note":"書きかけの地図","exp":"220","type":"地理","name":"ジャマイカ海峡","desc":"ジャマイカ島の北東にある海峡。この周辺は小島が多く、海賊たちの格好のねぐらとなっている。航海の際には警戒が必要。"}],"808":[{"rank":"2","note":"大海原の真ん中","exp":"380","type":"地理","name":"チャゴス諸島","desc":"インド洋の中央付近に点在する島々。ほとんどがサンゴ礁におおわれている。インドからは1600kmあまり離れている。耕作は不可能で人が定住するのは無理だろう。"}],"138":[{"rank":"1","note":"クセルクセス１世の遺物","exp":"180","type":"歴史遺物","name":"クセルクセス1世の石像","desc":"クセルクセス1世は、アケメネス朝ペルシャの王。ダレイオス1世の息子で、ペルセポリスの建造を引き継いで行った。"}],"5694":[{"rank":"4","note":"","exp":"630","type":"史跡","name":"プスカリニ池","desc":"釈迦の生誕地とされるルンビニにある池。釈迦はこの池で沐浴をした生母の脇の下から生まれ、産湯にはこの池の水が使われたと伝えられている。"}],"2910":[{"rank":"3","note":"ダンジョン","exp":"460","type":"財宝","name":"淡水語辞典","desc":"イスパニア人が編さんした、淡水で使用されていた言語の辞典。\n台湾島の先住民や移住民にカトリックを布教するために使われた。"}],"3660":[{"rank":"3","note":"ダンジョン<br/><br/>発見時経験値510　発見物カード経験値255","exp":"510","type":"歴史遺物","name":"アルキメデスの大理石像","desc":"古代ギリシャ・ローマ時代に『てこの原理』を始めとする優れた業績を残した数学者・物理学者アルキメデスの大理石像。アルキメデスはシラクサの出身でかつてはシラクサの門の側にその墓が建っていたといわれる。"}],"6377":[{"rank":"4","note":"","exp":"800","type":"気象・現象","name":"逆さ虹","desc":"鮮やかな虹が逆さまに弧を描く現象。太陽の真上に現れることが多いとされる。色の順番も通常の虹とは逆で、下側が赤色になる。空中に浮かぶ氷の結晶が太陽光を屈折させることで発生する。"}],"78":[{"rank":"1","note":"ヴェネツィアのガラス細工","exp":"105","type":"美術品","name":"行列寓意図飾杯","desc":"「ぎょうれつぐういずしょくはい」。ヴェネツィアの工房で作られたという器。瑠璃色のガラス器にエマイユが施されている。ガラスのエマイユ技術は、ヴェネツィアで多用された。これほどの作品はヴェネツィアでなければ作れないだろう。"}],"476":[{"rank":"2","note":"権威の象徴","exp":"290","type":"財宝","name":"オットー1世の宝冠","desc":"オットー1世が、初代神聖ローマ帝国皇帝に即位したときの帝冠だとされる。黄金と宝石をふんだんに使った、豪華な作りである。"}],"1196":[{"rank":"2","note":"生贄の像","exp":"230","type":"宗教建築","name":"チャックモール","desc":"チャックモールとは、「赤いジャガー」という意味。マヤの人々はこの像の腹部に生贄の心臓を乗せて、神に祈っていたという。"}],"1002":[{"rank":"1","note":"北欧の毒蛇の調査","exp":"150","type":"小型生物","name":"クサリヘビ","desc":"頭部が三角形をしている猛毒のヘビ。多くの種類がおり、熱帯から北極圏近くまで広く生息する。卵ではなく子を産む。"}],"6805":[{"rank":"3","note":"発見物カード：205","exp":"","type":"地理","name":"オプティミスティチナ洞窟","desc":"黒海北西にある巨大な洞窟群。世界で最も長い石膏洞窟とされる。洞窟同士が複雑につながっており、「洞窟の迷路」とも呼ばれる。洞窟内の温度は一定に保たれ、鍾乳石や色づいた巨大な水晶など、美しく神秘的な地下世界が広がる。"}],"763":[{"rank":"1","note":"赤い花の地図","exp":"12","type":"植物","name":"カーネーション","desc":"ひだの多い花が咲く植物。よい香りがする。園芸用の植物として品種改良もされている。"}],"3776":[{"rank":"5","note":"クエスト「ヤギと魚の星座」<br/>発見物カード:550","exp":"1100","type":"天文","name":"やぎ座","desc":"黄道十二星座の1つ。星座図では上半身が山羊、下半身が魚の姿で描かれることが多い。怪物テュポンの出現に驚き、山羊頭の神パンが化けた姿とされる。明るい星がないため、黄道十二星座の中では見つけるのが難しい。"}],"225":[{"rank":"2","note":"トリスタンの剣","exp":"350","type":"歴史遺物","name":"トリスタンの剣","desc":"イングランドの騎士トリスタンのものといわれる剣。彼の墓と思われる場所から発見された。トリスタンはイゾルデ姫との悲恋物語で知られる。"}],"1573":[{"rank":"4","note":"南東の大陸にすむワニ","exp":"624","type":"大型生物","name":"クロコダイル","desc":"細長い口先が特徴的なワニ。体長は2.5mほどで、地上をすばやく動くことができる。"}],"2697":[{"rank":"1","note":"朝鮮の仏像の地図","exp":"100","type":"宗教遺物","name":"金銅観音菩薩立像","desc":"朝鮮でよく見られる形状の菩薩像。\n木像に金銅を塗ったものや、鋳造で作られたものなど、さまざまな手法で作られたものがあるようだ。"}],"1794":[{"rank":"3","note":"栄枯盛衰の狭き海","exp":"490","type":"地理","name":"ボスポラス海峡","desc":"ヨーロッパとアナトリア半島の間にある二つのうち、北側の海峡。コンスタンティノープルの攻防では、流れの速い海峡部から砲撃をするために、金角湾を巡る激戦が繰り広げられた。トルコ軍は両岸に二つの城砦を建設し攻略の糸口とした。"}],"1210":[{"rank":"1","note":"クエスト「新大陸西岸への道」<br/>発見物カード:60","exp":"120","type":"地理","name":"ダリエン湾","desc":"カリブ海南方の湾。コロン提督が訪れ、以後イスパニア人の手によって港が建造された。天然の良港として知られる。"}],"6154":[{"rank":"2","note":"","exp":"330","type":"植物","name":"オジギソウ","desc":"南アメリカ原産の植物で、本来の名は「ミモザ」という。手や風、熱などによる刺激で葉を閉じた後に枝が垂れ下がる性質を持つため、「オジギソウ」と呼ばれるようになった。今では正式名で呼ばれることのほうが稀である。"}],"409":[{"rank":"5","note":"奇跡を起こすトカゲ","exp":"1033","type":"小型生物","name":"グリーンバシリスク","desc":"川に面した樹上に生息していて、襲われると水に飛び込んで難を逃れる。後肢で水の上を走ることもある。オスには頭部、背中、尾の三カ所にたてがみがある。"}],"29":[{"rank":"2","note":"アフリカの南端","exp":"235","type":"地理","name":"喜望峰","desc":"アフリカ南部の岬。周囲の気象が荒く、ディアスはこれ以上の航海を断念した。ディアスは「嵐の岬」と名づけたが、その後ポルトガル王によって喜望峰と改められた。"}],"6395":[{"rank":"2","note":"ヒマラヤ山脈周辺、北西の果からわずか上方、二またで分れる道で右の崖。夜に出るよう。","exp":"330","type":"気象・現象","name":"地吹雪","desc":"一度降り積もった雪が強風により吹き上げられる現像。空に吹き上げられた雪で視界が悪くなり、時には太陽を隠すほどにもなる。強い地吹雪に巻き込まれると、方向感覚を失ってしまう場合がある。"}],"813":[{"rank":"2","note":"大帝の追憶","exp":"360","type":"財宝","name":"フリードリヒ1世の鎧","desc":"フリードリヒ1世は、「赤髭王」と呼ばれた神聖ローマ皇帝。第3回十字軍に従軍したがキリキア付近で渡河中に落馬し、溺死した。"}],"6588":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"地理学","desc":"紀元前のギリシャの学者で、「地理学の父」と呼ばれるエラトステネスが編纂した地理学の書物。その時期の地理学の最高水準であるといわれている。"}],"1556":[{"rank":"1","note":"小さな鳥の地図","exp":"140","type":"鳥類","name":"アオバズク","desc":"がっちりとした小型のフクロウ。夕暮れになると活動を始め、昆虫やネズミなどを捕食する。"}],"3581":[{"rank":"2","note":"陸地の白帆","exp":"233","type":"宗教遺物","name":"ロノマクア","desc":"ハワイの神の一つで、豊穣や気候などに関する諸事を司る「ロノ」神を象徴した飾り。収穫祭で飾られる。白布を垂らした木の中央にロノを模した顔が彫られている。"}],"6439":[{"rank":"2","note":"視認ランク７では不足、１１で観測できたため、必要な視認ランクは８から１１の間です。<br/><br/>R10で発見できました。<br/><br/>曇りの日が少ないため、かなり待つことになりがちです。","exp":"340","type":"気象・現象","name":"尾流雲","desc":"雨や雪、あられなどが雲から落下する途中で蒸発する時に発生する雲の一種。雲の下に、薄い筋状や柱状の靄が尾のようにぶら下がって見える。広い地域で観測される。"}],"6596":[{"rank":"2","note":"","exp":"350","type":"史跡","name":"バールバール神殿","desc":"バーレーン島の北部にある古代の神殿。メソポタミアの神エンキとその妻ニンフルサグへの礼拝のために作られたとされる。神殿は時代ごとにその上に積み重ねるように作られ、3段階になっている。"}],"5715":[{"rank":"2","note":"アフリカ北岸より奥地　サハラ　斜め岩付近<br/>日中","exp":"","type":"気象・現象","name":"砂竜巻","desc":"砂漠地帯で発生する竜巻。多く砂を舞い上げるため、通常の竜巻とは色が異なって見える。また、大規模な砂竜巻は、小さな街をのみ込むほどの大きさになるという。"}],"3629":[{"rank":"","note":"","exp":"","type":"レリック","name":"イタリアの盾","desc":"ハンニバルの恐るべき用兵を、戦略で封じ込めた知将ファビウス。だが、ローマの勝利を見ることなく没したという。"}],"6326":[{"rank":"2","note":"","exp":"310","type":"中型生物","name":"ヘアリーブッシュバイパー","desc":"中央アフリカに生息するヘビ。全身を逆立ったうろこが覆っているため、植物などに這い上がりやすい。相手の動きを止める神経毒と、大量出血を促す出血毒の二種類の毒を使って獲物を仕留める。"}],"1674":[{"rank":"2","note":"民家の地図","exp":"305","type":"歴史遺物","name":"ポンペイのパン","desc":"火山の噴火によって滅びたポンペイの街で見つかったパン。火山灰に覆われて、奇跡的に朽ち果てず残った。\n食べやすいように八等分にナイフを入れた状態で、カチカチに乾燥し、真っ黒になっている。まさしく食事の直前だったのだろう…。"}],"2558":[{"rank":"5","note":"台湾島の鳥調査再び","exp":"930","type":"鳥類","name":"ミカドキジ","desc":"台湾島の、標高が高い山地にのみ生息する希少な鳥。体長は約70cmと大型で、長い尾が特徴である。"}],"5991":[{"rank":"1","note":"巨大で凶暴なイルカ","exp":"200","type":"海洋生物","name":"シャチ","desc":"10m近い体長の、クジラの仲間。特徴のある模様と人間の身長より大きな背びれを持つ。かなり大きな群れで目撃されることもある。鳴き声で仲間と連絡をしているようだ。"}],"5385":[{"rank":"1","note":"発見物カード:95","exp":"190","type":"宗教遺物","name":"ビブリオテーケー","desc":"世界の起源からトロイ戦争までのギリシャ神話を系統立ててまとめた書物。ローマ神話の影響を受ける前の古いギリシャ神話が記されている。"}],"2570":[{"rank":"2","note":"クエスト「姉妹の運命」<br/><br/>発見時経験値320　発見物カード経験値160","exp":"320","type":"地理","name":"姐妹潭","desc":"阿里山の山中にある、大きさが違う二つの湖の総称。\nかつて、阿里山に住む二人の娘がこの地で命を絶ったという伝説がある。"}],"5668":[{"rank":"4","note":"","exp":"320","type":"海洋生物","name":"オオクラゲダコ","desc":"耳のような形のひれを持つタコ。他のタコよりも深海に生息しているため、このひれを使用して移動しているのだろう。"}],"1576":[{"rank":"3","note":"自由な海藻<br/><br/>発見時経験値451　発見物カード経験値225","exp":"451","type":"海洋生物","name":"シードラゴン","desc":"海藻によく似た生物。周囲の海藻に擬態して身を守る。小型のエビや魚を捕食する。"}],"872":[{"rank":"1","note":"東ローマの皇帝","exp":"100","type":"歴史遺物","name":"ユスティニアヌス帝の王杖","desc":"ユスティニアヌス帝はビザンツ帝国の皇帝で衰退しかかっていた帝国を再興した。ローマ法大全の編纂（へんさん）、ソフィア大聖堂の建設など、功績は数多い。"}],"4951":[{"rank":"3","note":"","exp":"500","type":"歴史遺物","name":"リュトン","desc":"古代の器の一種。底部に小さな穴が空いており、そこから酒を他の容器に注ぎ分けるという。リュトンから注がれる酒には、神聖な力が宿ると信じられており、主に儀式で使われていたようだ。"}],"6730":[{"rank":"5","note":"楽の叡智・心に響く楽器　右下","exp":"","type":"財宝","name":"ティン・ホイッスル","desc":"6つの指穴があり、リコーダー同様の吹き口を持つ縦笛。アイルランド発祥とされ、伝統音楽で使用される。"}],"5594":[{"rank":"4","note":"アゾレスの浜辺やや東側で視認<br/>夜間に晴れが条件","exp":"380","type":"気象・現象","name":"漁火光柱","desc":"洋上などで光の柱が空に浮いているように見える現象。\n発生要因など詳細はわからないが、柱の方向には街や漁船などがあることから、それらの明かりが何らかの形で影響しているのかもしれない。"}],"4794":[{"rank":"2","note":"真紅の鳥","exp":"260","type":"鳥類","name":"ベニハワイミツスイ","desc":"ハワイ諸島に生息する鳥で、大きさはスズメ程度。花の蜜を餌とする。現地ではイーウィと呼ばれ、その羽毛は支配者の衣服の飾りとして使われる。"}],"5066":[{"rank":"2","note":"到達する","exp":"236","type":"港・集落","name":"サンフアン","desc":"カリブ海の東部にある街。比較的新しい街だが、ヨーロッパとの交易の窓口に当たる位置なので栄えている。サトウキビのほか、カリブ特有の農作物やサンゴが流通している。"}],"3750":[{"rank":"4","note":"春のトライアングル","exp":"670","type":"天文","name":"春の大三角","desc":"春の大曲線を構成する2つの1等星、うしかい座のアルクトゥルスとおとめ座のスピカ、しし座の2等星のデネボラを結んで描く三角形。さまざまな星座を見つける目印となる。"}],"3777":[{"rank":"5","note":"クエスト「双魚宮の調査」<br/>発見物カード:550","exp":"1100","type":"天文","name":"うお座","desc":"黄道十二星座の1つ。2匹の魚がリボンで結ばれた姿で描かれる。怪物テュポンに襲われた女神アフロディテとその子エロスが、魚に変化して逃げた姿だとされる。明るい星がなく、黄道十二星座の中では見つけにくい星座である。"}],"6388":[{"rank":"2","note":"","exp":"210","type":"植物","name":"ホウライショウ","desc":"中米などに分布する多年草。別名「モンテスラ」。成長に合わせて葉には穴が開く。その穴が連結し大きな切れ込みとなる。果実は食用にもなる。完熟していないものは口に強い刺激を与える。"}],"2335":[{"rank":"1","note":"葬送用の焼き物の地図","exp":"140","type":"歴史遺物","name":"埴輪","desc":"読みは「はにわ」。日本で作られた素焼の焼き物。人や馬、家をかたどったものの他、円筒形のものもある。\n有力者の墓の周りや、墓室内に置かれる場合が多い。"}],"2389":[{"rank":"4","note":"東方の鉱脈<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740","type":"地理","name":"石見銀山","desc":"読みは「いわみぎんざん」。日本の中国地方に位置する山。\n膨大な銀を産出しており、多方面から注目されている。\n佐摩銀山という別名から、ここの銀はソーマ銀とも呼ばれることがある。"}],"5689":[{"rank":"2","note":"古代からのメッセージ","exp":"380","type":"歴史遺物","name":"シギルの偶像","desc":"世界で最も古いとされる木製の彫像。細長い体に刻まれた模様は暗号のようでもあるが、その意味を理解することは困難である。"}],"3826":[{"rank":"3","note":"夏の終わりの香り","exp":"500","type":"植物","name":"ジンジャーリリー","desc":"夏の終わり頃に白い花を咲かせる植物。\n強いがすっきりとした芳香で香料としてもよさそうだ。"}],"5163":[{"rank":"1","note":"到達する","exp":"77","type":"港・集落","name":"モザンビーク","desc":"アフリカ南東岸に位置する街。天然の良港でアフリカ東部の交易拠点として栄えてきた。耕作が盛んでさまざまな産物が流通するほか鉱山資源が非常に豊富である。"}],"5316":[{"rank":"5","note":"","exp":"810","type":"海洋生物","name":"アフリカハイギョ","desc":"アフリカ南部の湖沼に棲む魚。胸や腹のヒレがムチのような形をしている。時々水面で空気を吸う必要がある一方で、乾期に湖沼が干上がっても地中に潜って繭（まゆ）を作り、休眠状態で生き延びられる。"}],"6878":[{"rank":"3","note":"発見物カード:280","exp":"560","type":"小型生物","name":"ジュウジメドクアマガエル","desc":"南米に生息するカエルの一種。青白い体に暗褐色の縞模様が特徴。樹上性で、虫などを食べる。毒を持ち、身の危険を感じた時には、皮膚から白く粘つく毒液を分泌する。"}],"2991":[{"rank":"2","note":"虫取り草再び<br/><br/>発見時経験値360　発見物カード経験値180","exp":"360","type":"植物","name":"ハエトリソウ","desc":"北米大陸の東沿岸部に自生する食虫植物。トゲのついた葉は二枚で一組となっており、葉の内側には数本の毛が生えている。この毛に触れると葉が閉じ、捕らえた虫を消化して養分とする。"}],"1580":[{"rank":"5","note":"姿を見せぬ生物","exp":"923","type":"鳥類","name":"ヒクイドリ","desc":"体高が1.7mにもなる大きな鳥。体に対して翼が小さいため、飛ぶことができない。その代わりに脚力が発達している。それは、人を蹴り殺すほどである。"}],"1068":[{"rank":"3","note":"始まりにいる神","exp":"484","type":"宗教遺物","name":"ヴィシュヌ像","desc":"インド神話三大神の一人の像である。10もの化身（アヴァターラ）をもつが、4本の腕を持つ男性として描かれることが多い。世界の均衡が崩れると、さまざまな姿で現世に現れると伝えられる。"}],"925":[{"rank":"1","note":"美しいつぼの地図","exp":"57","type":"財宝","name":"ペルシャ風のつぼ","desc":"ペルシャ独特の文様が描かれた美しいつぼ。イスラム教では生き物の姿を描くことを避けるため、植物の文様が多い。"}],"2343":[{"rank":"2","note":"大切なお守り","exp":"290","type":"宗教遺物","name":"鎮魂の勾玉","desc":"読みは「たましずめのまがたま」。日本の陰陽師たちが儀式に使うという特別な勾玉。\n日本の神道では、鎮魂とは、生者の不安定な魂を体につなぎ留めておくための行為を指すらしい。"}],"635":[{"rank":"4","note":"樹上の狩人","exp":"612","type":"大型生物","name":"ヒョウ","desc":"サバンナなどで見られる大型の猛獣。独特の模様があり、美しいが危険な動物だ。木の上で待ち伏せて狩りをするようだ。捕らえた獲物は木の上に引きずりあげて、ハイエナなどに奪われないようにしている。"}],"5857":[{"rank":"5","note":"","exp":"1340","type":"財宝","name":"バラフォン","desc":"西アフリカ一帯で演奏される楽器。木琴の下に瓢箪を敷き詰めた独特な形状をしている。瓢箪の中には蜘蛛の巣やコウモリの羽が貼り付けてあり、振動を増幅させる効果がある。"}],"2317":[{"rank":"2","note":"［勅命］[[献上品の産地調査","exp":"320","type":"地理","name":"金門島","desc":"かつて鄭成功の拠点となっていた島。\n貢糖と呼ばれる、砂糖とピーナッツを原料にした産物が有名。"}],"3622":[{"rank":"4","note":"ロシア皇帝徹底調査","exp":"790","type":"歴史遺物","name":"ピョートル1世の手形","desc":"ロシア皇帝ピョートル1世が遺した手形。海軍創設のため、自ら船大工に弟子入りしてかなづちを振るったという彼の手は、皇帝のものとは思えぬ屈強さがうかがえる。"}],"2364":[{"rank":"4","note":"命を与えられた紙片","exp":"690","type":"宗教遺物","name":"式神札","desc":"式神を呼ぶための札。式神とは、陰陽師の命令で不思議な現象を起こすとされる霊的存在のこと。｢式｣とは｢用いる｣の意味である。昔、陰陽道を極めたある人物は、この札を使いさまざまな式神を呼び出せたというが…。"}],"5913":[{"rank":"2","note":"釣りで発見。間宮海峡から日本海にかけてのあたりで釣れました。<br/>オホーツク海(6533,2497付近)","exp":"370","type":"海洋生物","name":"トリカジカ","desc":"東アジア近海に生息するスズキの仲間。体に比べて頭が大きく、逆に尾のほうは細く短くなっている。大きな頭にある目も大きく、それが鳥の顔に似ていることが、名前の由来だろう。"}],"3268":[{"rank":"2","note":"炎を咲かす樹木<br/><br/>発見時経験値390　発見物カード経験値195","exp":"390","type":"植物","name":"カエンボク","desc":"西アフリカでよく見られる花木。赤い花がまるで炎のように見え、非常に華やかなため目を惹く。樹高は10mを超える。"}],"2452":[{"rank":"4","note":"話題を呼ぶ羽飾り","exp":"610","type":"鳥類","name":"ヤマドリ","desc":"日本の本州以南の山林に生息する鳥。雄は、翼で胸を叩いて音を出す。\nその長い尾羽は、物事の長いことの例えとして、文学作品などの中で用いられてきた。"}],"5938":[{"rank":"3","note":"","exp":"600","type":"植物","name":"アルファローバ","desc":"ポルトガルにおけるイナゴマメの別名。\nその果実は甘く、栄養価も高いため、お菓子などの材料として珍重される。"}],"3843":[{"rank":"3","note":"絶壁の聖地","exp":"480","type":"地理","name":"イーグルリッジ・ブラフ","desc":"北米西岸にある山の絶壁。岩壁ばかりでなく緑豊かな場所でもある。ハクトウワシの生息地でもあり、先住民からは聖地とあがめられている。"}],"4852":[{"rank":"","note":"","exp":"","type":"レリック","name":"星の記録","desc":"アレクサンドリア図書館の破壊を免れ、隠されていた古代の天文観測記録。古代人は天を見て国家の命運を知ろうとしていた。"}],"3158":[{"rank":"5","note":"「最果て」に迫る","exp":"1100","type":"地理","name":"グリーンランド","desc":"アイスランドの北西に位置する島。氷床と万年雪に阻まれ、島の細部は確認不能。\n沿岸部の、氷がないほんの一部でのみ居住できる。しかしヴァイキングは、この地を「緑の国」と名づけて移住者を募った。"}],"266":[{"rank":"1","note":"ブリテン島西の調査","exp":"20","type":"地理","name":"アイリッシュ海","desc":"ブリテン島とアイルランドの間にある海域。それほど水深はないようで、穏やかである。"}],"577":[{"rank":"1","note":"高貴なる花","exp":"70","type":"植物","name":"ダマスカスローズ","desc":"古くからダマスカス地方で品種改良されたバラの一種。バラの中でも特に香りが優れるといわれ、香料の原料として珍重される。質のよいバラの株は、大変な高値で取引される。"}],"6259":[{"rank":"2","note":"","exp":"270","type":"歴史遺物","name":"ギリシャ詞華集","desc":"10世紀のビザンツ帝国の文学者、コンスタンティノス・ケファラスが編纂したギリシャ語詩選集。紀元前から当時までのおよそ300人にわたる詩人の短い詩を4500篇ほどまとめており、長い間、優れた詩選集の代名詞的な書とされてきた。"}],"1783":[{"rank":"1","note":"「書きかけの地図」<br/>発見物カード:70","exp":"140","type":"地理","name":"ブエナベントゥラ湾","desc":"パナマの南、南米の北西岸に位置する湾。湾の南部にはマングローブの林が存在する。南からの冷たい海流は、湾の以南で西に流れを変えるため、水温は比較的高い。"}],"1642":[{"rank":"5","note":"旅の終わり","exp":"1170","type":"地理","name":"セブ島","desc":"ルソン島とミンダナオ島の中間にある南北に細長い島。西回りで周航中のマゼランが、この島を拠点として活動した。マゼランはセブ島の東に位置するマクタン島の首長・ラプラプと交戦し、命を落とした。"}],"5205":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"クレタ文字の粘土板","desc":"古代クレタ文明で使われていた文字が刻まれた粘土板。クレタ島の広範囲で確認できる。象形文字を発展させたような文字だが、なにが書かれているかは読み取れない。"}],"5644":[{"rank":"2","note":"","exp":"","type":"海洋生物","name":"エレファントノーズフィッシュ","desc":"ナイル川などに生息している魚。ゾウの鼻にたとえられる顔の突起はは下顎で、食物とする泥の中の生物を探すために進化した結果と思われる。そのため、捕食の動作が他の魚類と比べて遅い。"}],"5606":[{"rank":"5","note":"","exp":"940","type":"財宝","name":"虹の巻貝石","desc":"ロッキー山脈の東側で見つかった、オパールのような石。巻貝のような形をしている。"}],"2797":[{"rank":"5","note":"太上老君","exp":"1180","type":"宗教建築","name":"老君岩","desc":"道教の神・太上老君を模した巨大な石像。\n周囲の民の間では、この像のひげに触ると幸運が訪れると信じられている。"}],"1497":[{"rank":"2","note":"遊戯にも贅沢を","exp":"330","type":"財宝","name":"ルイスのチェス駒","desc":"セイウチの牙に精巧な彫刻を施したチェスの駒。その形状から12世紀のノルウェーまたはスウェーデンで制作されたものと思われる。"}],"260":[{"rank":"2","note":"ファラオの巨大な像","exp":"330","type":"歴史遺物","name":"アブ・シンベルの巨像","desc":"アブ・シンベル神殿の入り口にそびえる、四体の巨像。すべてラムセス2世の像である。高さは20mあり足元にはファラオの親族が彫られている。"}],"1036":[{"rank":"1","note":"「野生の羊の地図」<br/>発見物カード:6","exp":"12","type":"中型生物","name":"ムフロン","desc":"羊に似た動物。羊と同じような角があり、家畜の羊の祖先ではないかと思われる。非常に警戒心が強く、近づくのは難しい。"}],"6714":[{"rank":"5","note":"","exp":"","type":"海洋生物","name":"キンチャクガニ","desc":"主にインド洋と太平洋の沿岸地帯に分布する体長わずか2cmほどの小型のカニ。イソギンチャクをはさみにつけその刺胞で捕食者を撃退する習性があり、まるでボクシンググローブを付けたかのように見える。別名ボクサークラブ。"}],"839":[{"rank":"1","note":"跳ねるネズミの地図","exp":"56","type":"小型生物","name":"トビネズミ","desc":"長く発達した後ろ足で飛び跳ねるネズミ。耳が長く鼻が短く、目がとても大きい。"}],"6529":[{"rank":"5","note":"レガシー星の叡智　右上","exp":"1500","type":"歴史遺物","name":"デンデラの天体図","desc":"プトレマイオス朝エジプトで建設された、デンデラのハトホル神殿天井にあるレリーフ。ギリシャと同じ黄道十二宮の星座などがエジプト風の絵柄で表されている。天体の位置が異なるのは神殿建設当時の星を反映しているのかもしれない。"}],"2696":[{"rank":"3","note":"鉄の国の名残","exp":"530","type":"歴史遺物","name":"伽耶の短甲","desc":"伽耶時代に作られた鉄の短甲。\n短甲とは、主に胴体を保護するための武具のこと。これは三角形の鉄板が鋲で固定され、胸と背中に渦巻状の鉄板が取り付けられている。"}],"5148":[{"rank":"1","note":"到達する","exp":"177","type":"港・集落","name":"ポンディシェリ","desc":"インド東岸に位置する街。東南アジアへの主要な中継点である。香辛料と香料を中心に、宝石も扱われている。"}],"3619":[{"rank":"2","note":"鼻の長い動物の地図","exp":"340","type":"小型生物","name":"ソレノドン","desc":"ハイチなど、カリブの熱帯雨林に生息する夜行性の動物。\n体長は30cm程度で、鼻が細く伸びているのが特徴。狭い所に鼻を差し込み、獲物の昆虫などを捕える。"}],"4806":[{"rank":"3","note":"紅毛城（中層隠し部屋）","exp":"","type":"財宝","name":"笙","desc":"竹を主な材料として作られた楽器。吸っても吹いても同じ音が出るため、息継ぎの必要はない。側面に複数の穴が設けられており、押さえ方を変えて様々な音を出す。"}],"6802":[{"rank":"3","note":"サルベージ<br/>発見物カード:225","exp":"495","type":"歴史遺物","name":"カルマル・ニッケル号","desc":"ネーデルラントで建造されたピンネース船。第一次英蘭戦争中に、スコットランド沖でイングランド海軍の攻撃を受け、沈没した。"}],"5905":[{"rank":"5","note":"","exp":"1370","type":"美術品","name":"大聖堂のステンドグラス","desc":"とある聖人の生涯を描いた一連のステンドグラス。その数は何十とあり、聖堂の内側を飾っている。"}],"3529":[{"rank":"","note":"初回発見時経験値1550　初回発見時名声1240(名声2万越えのため620*2しています)","exp":"1550","type":"レリック","name":"スパルタクス","desc":"古代ローマを震撼させた、大規模な反乱。一説によると、反乱を率いた剣闘士はトラキアの王子だったともいわれる。"}],"2879":[{"rank":"1","note":"古の書物の地図","exp":"160","type":"宗教遺物","name":"阿弥陀経残巻","desc":"極楽浄土の様子を経文と絵画で表した作品。元となる経文は「仏説阿弥陀経」で、六朝時代の僧・鳩摩羅什が翻訳したもの。"}],"6336":[{"rank":"2","note":"","exp":"370","type":"宗教建築","name":"モンテ・アルバン遺跡","desc":"北米南部で栄えたサポテカ文化の中心地。山の頂上を平坦にして築かれた遺跡で、中には天体観測所や球技場まである。大きく発展したが、人口の減少と共に衰退したという。"}],"496":[{"rank":"3","note":"クエスト「古代エジプト語の研究」<br/>発見物カード:225","exp":"456","type":"歴史遺物","name":"ロゼッタストーン","desc":"ナイルのほとりで発見された玄武岩でできた石碑。古代エジプト神聖文字と民衆文字、ギリシャ文字で書かれている。内容は祭事の制定を告知するもの。"}],"4995":[{"rank":"2","note":"","exp":"330","type":"宗教遺物","name":"蛇使いの女神像","desc":"クレタ島で発見された女神像。両手に蛇を握り、帽子の上に獅子を乗せている。かつて女性と蛇は神聖であったという話や、蛇と獅子は地母神の象徴だったという話から、崇拝の対象であったことがわかる。"}],"2322":[{"rank":"2","note":"名物土産物","exp":"260","type":"財宝","name":"京人形","desc":"日本の堺近辺で作られる人形。土産物として江戸の町によく運ばれてくるらしい。\n元々は、子供の身代わりに災いを引き受けるものとして用いられたという。"}],"2975":[{"rank":"2","note":"炎の花<br/><br/>発見時経験値270　発見物カード経験値135","exp":"270","type":"植物","name":"フロックス","desc":"花弁が鮮やかな花。赤い花はまるで炎のようである。日当たりの良い場所に生息する。"}],"5139":[{"rank":"1","note":"到達する","exp":"19","type":"港・集落","name":"ベンガジ","desc":"古代ギリシャ時代に建設された都市が起源。街の名は、街の繁栄に貢献した人物に由来する。"}],"195":[{"rank":"2","note":"クエスト「ダ・ヴィンチ最初の大作」<br/>発見物カード:110","exp":"220","type":"美術品","name":"マギの礼拝","desc":"レオナルド・ダ・ヴィンチ作の絵画だが、未完成である。彼が最初に手がけた大作だとされるが、製作中にほかの土地へ転居したため未完成となった。絵の題材は、誕生したイエスを三人の賢人が礼拝に訪れた情景である。"}],"5219":[{"rank":"1","note":"ビブロス郊外　再調査報酬","exp":"","type":"歴史遺物","name":"ビブロス文字の石碑の破片","desc":"古代文字が刻まれている石碑の破片。文字は古代ビブロスで使われていたと思われ、丁寧に彫られている。ばらばらになった破片をつなぎ合わせると読めるようになるのだろうか。"}],"248":[{"rank":"5","note":"バルムンク","exp":"1183","type":"歴史遺物","name":"バルムンク","desc":"北欧の伝説の英雄ジークフリードが愛用したといわれる剣。所有する者に英雄としての栄光と、壮絶な最期をもたらすとされる。霧深き最果ての地で発見された。"}],"6338":[{"rank":"2","note":"","exp":"280","type":"史跡","name":"ディキスの石球","desc":"中南米の密林で発見された石球群。大きさはまちまちであり、最も大きいものは直径2mを超える。製作の目的や手法は不明。"}],"5986":[{"rank":"1","note":"光る虫","exp":"20","type":"虫類","name":"ホタル","desc":"腹部が光る小型の昆虫である。森の中で、ほうぼうが点滅している様子は大変美しい。なぜ腹が光るのかは不明だ。"}],"2075":[{"rank":"2","note":"勅命クエスト「[香料諸島方面進出の要衝」<br/>勅命代替クエスト「東国へ続く狭き道」<br/>発見物カード:160","exp":"320","type":"地理","name":"マラッカ海峡","desc":"マレー半島と、スマトラ島の間に横たわる海峡。東西交易において重要な通過点となるが海峡の幅は狭く、その上水深が非常に浅い。さらに、暗礁や浅瀬も多いため、航行には細心の注意が必要だ。"}],"5122":[{"rank":"2","note":"到達する","exp":"300","type":"港・集落","name":"ヒバオア","desc":"マルキーズ諸島南部にあるヒバオア島の街。独特の山並みが特徴の火山島である。熱帯圏でありながら、冷涼な南赤道海流の影響を受け、年間を通じて温暖快適な気候である。"}],"5733":[{"rank":"5","note":"死ぬほど気持ちいい棺<br/>2017.02.07新規追加","exp":"1360","type":"宗教遺物","name":"オシリスの棺","desc":"オシリスが謀殺された時に用いられた棺。川に流され、着いた先で木に包まれ、そのまま柱に使われ、中の遺体はバラバラにされた。これほど波乱万丈な生涯を送った棺も珍しいだろう。"}],"1558":[{"rank":"1","note":"書きかけの地図","exp":"135","type":"地理","name":"スペンサー湾","desc":"オーストラリアの南岸エア半島の東に位置する鋭角にくぼんだ湾。湾の近郊には豊富な埋蔵量をもった銀鉱脈があるらしい。"}],"3256":[{"rank":"3","note":"対話する音色","exp":"500","type":"財宝","name":"ジャンベ","desc":"西アフリカ一帯で演奏されている楽器。ジェンベとも呼ばれる。\n鼓面の直径は約30cm、胴の深さは約60cmの、片面の太鼓である。\n両脚に挟んで素手で叩き、その手の形と叩く位置によって、高音から低音まで多様な音を出すことができる。"}],"6126":[{"rank":"5","note":"","exp":"1330","type":"伝承","name":"虹蛇","desc":"太陽が神に見立てられるように、虹も偉大な存在の象徴として見なされる。創造主としての性質を持つ「虹蛇」は、強大な存在として語られることの多い蛇や龍の中でも、頭一つ抜けた存在と言えるだろう。"}],"631":[{"rank":"1","note":"失われた冥府の神","exp":"110","type":"宗教遺物","name":"オシリス像","desc":"古代エジプトの死と復活の神の像。オシリスは弟のセトに殺されたが、妻のイシスと息子のホルスがセトを倒した。のちに、オシリスは冥府の王となったという。"}],"1135":[{"rank":"2","note":"教会の宗教画の地図","exp":"255","type":"美術品","name":"聖母子と幼児ヨハネ","desc":"ラファエロ作の絵画。別名を、「小椅子の聖母」という。ラファエロのそれまでの聖母像と異なり、生気にあふれている。恋人であるマルゲリータをモデルにしているとうわさされている。"}],"419":[{"rank":"1","note":"奇妙な模様の動物の地図","exp":"34","type":"中型生物","name":"シマウマ","desc":"体全体に黒と白のしま模様がある動物。馬を小さくしたような体つきをしている。多数の群れで生活しているようだ。"}],"6648":[{"rank":"5","note":"","exp":"1660","type":"伝承","name":"九尾の狐","desc":"東アジアに伝わる九本の尾の霊獣。優れた君主の治世を表す瑞獣とされている。一方で、絶世の美女に化け人をたぶらかす悪意ある個性も持ち合わせている。"}],"5533":[{"rank":"4","note":"北米大陸東岸（上陸地点）　日中？　晴天？　南東の浜辺の南の端付近　視認R9以上必要かも？<br/>経験値は冒険職で７６０と登録してあるのを修正してあるようですね。","exp":"380","type":"気象・現象","name":"環水平アーク","desc":"太陽の下の薄い雲に虹色の光の帯が重なって見える現象。他の光学現象とは異なり、円形ではなく水平な帯状で現れる。"}],"824":[{"rank":"1","note":"誰でも釣れる浅瀬はないか","exp":"70","type":"地理","name":"グレートフィッシャーバンク","desc":"北海中央付近の、広い浅瀬である。古くからよい漁場だったので、この名がある。"}],"129":[{"rank":"1","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40","type":"宗教遺物","name":"聖母のステンドグラス","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。"}],"1546":[{"rank":"2","note":"クエスト「眼前にある海峡」<br/>発見物カード:160","exp":"320","type":"地理","name":"クラレンス海峡","desc":"オーストラリア北部、アーネムランドとバサースト島、メルヴィル島の間にある海峡。熱帯の気候であり、付近は年間通して暑く、熱帯特有の暴風雨の被害も受けやすい。"}],"2385":[{"rank":"3","note":"傷薬の素","exp":"460","type":"植物","name":"オトギリソウ","desc":"東アジアの草地や山野に自生し、夏に黄色の花を咲かせる植物。\n葉を食べてから日光に当たると、皮膚炎になる。一般的には生薬や傷薬として利用されることが多い。"}],"276":[{"rank":"1","note":"クエスト「ペルシャの海」<br/>発見物カード:100","exp":"200","type":"地理","name":"ペルシャ湾","desc":"アラビア半島とペルシャにはさまれた海域である。クロチョウガイなどの生息に適した環境で、古代から真珠が採れたという記録がある。真珠は今でも大変な貴重品である。"}],"3743":[{"rank":"5","note":"元朝の歴史書","exp":"1200","type":"歴史遺物","name":"元朝秘史","desc":"モンゴルの歴史書。著者は不明。\nチンギス・ハンの生き様を中心に、後継者であるオゴデイの治世にも一部触れている。"}],"3733":[{"rank":"4","note":"ダンジョン","exp":"680","type":"歴史遺物","name":"王の弔文","desc":"古代エジプトのファラオ・ラムセス2世が妻のネフェルタリに贈った弔文。深い悲しみの言葉が綴られており、ラムセス2世の愛の深さが読み取れる。"}],"6263":[{"rank":"2","note":"おしゃれさん","exp":"330","type":"海洋生物","name":"キマユペンギン","desc":"アオテアロアの南島にあるフィヨルドを中心に生息するペンギン。マオリたちの間ではタワキと呼ばれる。\n頭部に長くて鮮やかな黄色の冠羽が生えており、キマユ（黄眉）ペンギンと呼ばれる由来になっている。"}],"6557":[{"rank":"5","note":"追究クエスト","exp":"1600","type":"鳥類","name":"メジロ","desc":"東アジアに分布する小鳥。鮮やかな緑色の羽と目の周りの白い輪が特徴で、同じ春を告げる鳥のウグイスとよく間違えられる。体を押し合うように枝に止まる習性があり、その姿はとても可愛らしい。"}],"3637":[{"rank":"2","note":"書きかけの地図","exp":"330","type":"地理","name":"ノールカップ岬","desc":"スカンジナビア半島の北に浮かぶ小島の岬。断崖絶壁だが、上からの眺めは絶景だ。"}],"3576":[{"rank":"","note":"","exp":"","type":"レリック","name":"アルヴィダ","desc":"麗しきスウェーデンの王女でありながら女海賊となったアルヴィダ。今なお、スカンジナビアの人々に愛され続ける存在である。"}],"4968":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:220","exp":"240","type":"天文","name":"アルナイル","desc":"つる座で最も明るい星で、名はアラビア語で「尾の光り輝くもの」という意味を持つ。かつてはみなみのうお座の一部だった。"}],"2249":[{"rank":"2","note":"クエスト「軽快に動くカニ」<br/>発見物カード:115","exp":"230","type":"海洋生物","name":"ベニイワガニ","desc":"ガラパゴス諸島の海岸でよく見られる真っ赤なカニ。岩から岩へ飛び移ったり、前へ歩いたりと、通常のカニとは異なる行動をとる。海岸の岩に張り付いた海藻をハサミで取って食べる。"}],"2053":[{"rank":"4","note":"追放の欠片","exp":"660","type":"歴史遺物","name":"オストラコン","desc":"文字や絵が描いてある陶器の破片。ギリシャ語で「陶片」の意味を持つ。独裁者を追放するための投票に用いられた。この制度により当時のアテネが衰退したとの見方もある。"}],"553":[{"rank":"1","note":"古代ローマの都市跡","exp":"105","type":"史跡","name":"レプティス・マグナの遺跡","desc":"ローマのセプティミウス・セウェルス帝が建造した大都市の遺構。大理石をふんだんに使った施設跡が並び、当時の興隆が見えるようだ。"}],"1776":[{"rank":"2","note":"クエスト「北と南を分かつ場所」<br/>発見物カード:110","exp":"220","type":"地理","name":"パナマ地峡","desc":"中米にある地峡。最も狭い場所はカリブ海から太平洋まで64kmしかない。運河の建設も夢ではない距離だが、山がちで降水量が多い上に、密林に覆われている。加えて高熱を発する病に冒される地域でもあるため建設は容易ではないだろう。"}],"1284":[{"rank":"2","note":"［勅命］[[ジャワ思想調査","exp":"340","type":"宗教遺物","name":"般若経","desc":"はんにゃきょう。多くの仏教経典の総称。般若とはサンスクリット語でプラジューナー、「悟りの智慧」を意味する。"}],"5728":[{"rank":"5","note":"2017.02.07新規追加","exp":"970","type":"大型生物","name":"カスピトラ","desc":"カスピ海周辺から東の高地にかけて生息するとみられるトラ。その骨には薬効があるとの噂があるが、その真偽は不明である。"}],"646":[{"rank":"1","note":"書きかけの地図","exp":"105","type":"地理","name":"サントメ島","desc":"西アフリカ中央部のギニア湾に浮かぶ島。赤道が近い、熱帯雨林気候の島。"}],"6448":[{"rank":"5","note":"","exp":"1650","type":"歴史遺物","name":"ハンガリー王妃の水","desc":"中世ヨーロッパで作られていたローズマリーの薬酒。香りが良く、香水としても用いられた。病身の老いたハンガリー王妃が服用したところ、病が癒えただけでなく美しく若返ったため、他国の王子から求婚されたとの伝説が語り継がれている。"}],"5607":[{"rank":"2","note":"","exp":"","type":"地理","name":"ヒューロン湖","desc":"北米大陸北東部に位置する湖のひとつ。世界で第四位の面積を誇る広大な湖である。"}],"5508":[{"rank":"1","note":"座標　16258,2576","exp":"16","type":"港・集落","name":"ルアーブル","desc":"フランス北部の港湾都市。セーヌ川の河口に位置する。貿易で栄えている。"}],"1660":[{"rank":"1","note":"書きかけの地図","exp":"145","type":"地理","name":"ガイナス岬","desc":"ベネズエラ湾西岸に突き出した半島の先端部にある岬。近年、ヨーロッパ人の進出が盛んな場所である。"}],"1192":[{"rank":"4","note":"アステカの夜の神","exp":"612","type":"宗教遺物","name":"テスカトリポカ像","desc":"アステカ神話における夜の神。その名は「濁った鏡」という意味である。ケツアルコアトルとともに世界を作ったといわれるが彼を追い払い、一人で世界を治めるようになった。非常に美しい男の姿をしていたといわれる。"}],"3658":[{"rank":"2","note":"ダンジョン","exp":"400","type":"歴史遺物","name":"埋もれたガラス器","desc":"ローマのカタコンベに埋もれていたガラスの器。紀元前1世紀に近東で吹きガラスの技術が生まれ、ローマ帝国時代には広く作られるようになった。この器は初期のキリスト教徒が使っていたものと思われる。"}],"408":[{"rank":"2","note":"奇岩の宗教都市","exp":"350","type":"史跡","name":"カッパドキア","desc":"長い間、風雨にさらされた奇岩がそびえたつ地域。かつて迫害を避けた人々が岩をくりぬいて作った街が残っている。"}],"339":[{"rank":"3","note":"異常なドラゴンの骨","exp":"506","type":"化石","name":"首の長いドラゴンの骨","desc":"首の長さが体と同じほどもある、巨大な生物の骨。全長は20mを超える。ただ、形は骨だが石のように変化している。本当にこんな生物がいるのだろうか？ドラゴンの骨にしては角や翼がなく、ほかの伝説で語られる生物なのかもしれない。"}],"2723":[{"rank":"4","note":"黄金の飛翔物体<br/><br/>発見時経験値350　発見物カード経験値175","exp":"750","type":"小型生物","name":"クロアカコウモリ","desc":"洞窟のような暗い場所に生息するコウモリ。コウモリといえば地味な色合いを連想するがこれは橙色に見える。朝鮮の人々は、その橙色を金色と呼んだ。"}],"6106":[{"rank":"3","note":"","exp":"540","type":"宗教遺物","name":"道を知れ","desc":"11世紀ドイツの修道女であるビンゲンのヒルデガルトの著作で、預言めいた文章と、寓意画のような挿絵が特徴的。内容は教会や信仰に関するものであり、いずれも神の啓示のもとに記されたものと言われている。"}],"5692":[{"rank":"2","note":"2017.02.07新規追加","exp":"370","type":"中型生物","name":"パミールアルガリ","desc":"アルガリの亜種とされる生物。山地や高原に生息する。マルコポーロが発見したという逸話があり、マルコポーロシープという別名を持つ。"}],"6971":[{"rank":"5","note":"発見物カード:660","exp":"1320","type":"植物","name":"オオベニウチワ","desc":"南米大陸の熱帯雨林に自生する植物。ハート型の花びらに見える部分は、苞（ほう）と呼ばれる葉が進化したもので、中心の棒状の部分が花である。色鮮やかでさまざまな種類が存在するが、有毒のため注意が必要だ。"}],"1888":[{"rank":"3","note":"サルベージ","exp":"451","type":"歴史遺物","name":"シャガス号","desc":"正式名称は、ラス・シンク・シャガス号。\nポルトガルの東インド貿易船の一隻。\nインドからの帰路の途中、アゾレス諸島付近でイングランド海賊に襲われ、沈没した。"}],"1246":[{"rank":"2","note":"［勅命］[[新大陸進出の脅威","exp":"280","type":"大型生物","name":"ボア","desc":"草原から森林まで幅広い環境に棲む大蛇。鳥や大型のトカゲを襲うとき、太い胴で獲物を窒息させてから丸ごと飲み込む。"}],"2804":[{"rank":"1","note":"命短き花","exp":"200","type":"植物","name":"シャガ","desc":"中国や日本に生息する春に群青色の花を咲かせる植物。\n暗い場所でも生育するが、花は一日しか持たず、開花した翌日には萎んでしまう。"}],"2498":[{"rank":"4","note":"名画の奪還","exp":"620","type":"美術品","name":"雪舟の山水画","desc":"室町時代の禅僧・雪舟の筆による水墨画。\nどっしりとした安定感のある構図と、力強い筆使いが特徴。"}],"1354":[{"rank":"3","note":"阿しゅく如来像","exp":"517","type":"宗教遺物","name":"阿しゅく如来","desc":"あしゅくにょらい。仏教における、如来のひとり。サンスクリット語の名には「不動である」「堅固な」という意味がある。そこから転じているのか、この如来には、力強く堅固な意思と、猛けき力が宿っているという。"}],"1506":[{"rank":"1","note":"魚の石の地図","exp":"110","type":"化石","name":"魚の形をした石","desc":"二匹の魚がつながっているように見える石。魚がこのような状態になるにはどれほどの月日が必要なのか。"}],"6751":[{"rank":"5","note":"","exp":"","type":"天文","name":"ペガスス座の球状星団","desc":"ペガスス座にある球状星団で、ペガススの鼻先にあたる位置の前端にあるため、比較的探しやすい。"}],"6897":[{"rank":"5","note":"","exp":"","type":"小型生物","name":"冬毛のイイズナ","desc":"毛色が真っ白に生え替わったイイズナ。夏毛は腹部を除いて茶色だが、冬になると白く生え変わり、雪の中では見分けがつかないほどになるという。"}],"6527":[{"rank":"5","note":"レガシー星の叡智　上","exp":"2700","type":"史跡","name":"チャンキーヨの太陽観測塔","desc":"南米北西部の沿岸砂丘にある古代遺跡。紀元前4世紀ごろに建設されたとされる。13基の石造りの塔が丘の尾根に一列に並んでいる。かつてはかなりの高さがあったようだ。太陽がどの塔の位置から昇るかを観測し、日付を割り出したという。"}],"5250":[{"rank":"5","note":"クエスト「勇者の最後」<br/>発見物カード:465","exp":"930","type":"天文","name":"ヘルクレス座","desc":"ギリシャ神話の勇者、ヘラクレスが死後に天に昇った姿といわれる星座。こと座とかんむり座の間にある、かなり大きな星座だが、あまり明るい星はない。"}],"5722":[{"rank":"","note":"オホーツク西岸より奥地 バイカル湖周辺 南の凍った湖","exp":"","type":"気象・現象","name":"ヤコブの梯子","desc":"雲の切れ目から太陽光が帯状に降り注いで見える現象。太陽が低くなる早朝や夕方に観測されることが多い。名前はヤコブが見た夢に由来するとされる。"}],"2088":[{"rank":"5","note":"クエスト「伝承の未来」<br/>発見物カード:535","exp":"1070","type":"宗教遺物","name":"ワロチリ文書","desc":"アンデスに伝わる神話や伝承をまとめた、ある宣教師の著書。\n水の神パリアカカと炎の神との戦いを始め、様々な神話や伝承が記されている。"}],"5384":[{"rank":"2","note":"パラグアイ川上流　再調査報酬","exp":"","type":"鳥類","name":"アカノガンモドキ","desc":"南米に生息する地上性の鳥。首と脚が長く、頭部には特徴的な冠状の羽が生えている。危険を感じると、人が追いつけないほどの速さで走って逃げる。"}],"6404":[{"rank":"5","note":"","exp":"2850","type":"史跡","name":"ネレイドモニュメント","desc":"リュキアに建てられた大理石の記念堂。海神の娘ネレイドたちの流麗な彫像が、古代ギリシャ式の石柱の間に立ち並ぶ。この形式はハリカルナッソスにあった建築物に影響を受けたといわれる。"}],"2667":[{"rank":"2","note":"伝統ある青磁","exp":"380","type":"財宝","name":"高麗青磁","desc":"高麗時代に多く作られていた青磁のつぼ。\nまるでひすいのような色合いが美しく、名品として扱われている。"}],"6598":[{"rank":"5","note":"レガシー伝説の王都バビロン　下","exp":"2250","type":"史跡","name":"シーギリヤ","desc":"セイロン島の中央付近にある遺跡。アヌラーダプラ王国の王となったカッサパ1世が弟による王権奪取を恐れ、高さ200m近い切り立った突岩の上に王宮を建設し、その周辺に遷都したといわれる。"}],"2360":[{"rank":"2","note":"ベルベットの羽","exp":"330","type":"虫類","name":"ジャコウアゲハ","desc":"東アジアに広く生息するチョウ。細長く伸びた後ろ羽を持つ。\n雄はベルベットのような光沢を帯びた黒色の羽を持つのに対し、雌は比較的地味な褐色の羽を持つ。"}],"6114":[{"rank":"3","note":"","exp":"600","type":"財宝","name":"トンコリ","desc":"ロシア極東から日本の北部にかけての少数民族、樺太アイヌの間に伝わる五弦琴。平たい形状で先端が細くなっている。樺太アイヌの慣習に従って、楽器の各部分を人体の各部になぞらえて呼ぶという。"}],"44":[{"rank":"2","note":"イスラム文化の工芸品","exp":"280","type":"財宝","name":"金のアラビア風ランプ","desc":"黄金造りの、アラビア風ランプ。全体に美しいアラベスクが施されており、地金は18金である。ひんぱんに使われた形跡があり、これほどの物でありながら日用品だったようだ。"}],"2239":[{"rank":"4","note":"クエスト「迷い込んだ島の調査」<br/>発見物カード:375","exp":"750","type":"地理","name":"ガラパゴス諸島","desc":"赤道直下に位置する、複数の島々から成る火山群島。他では見られないような動物がたくさん生息しているようだ。"}],"1009":[{"rank":"1","note":"埋もれたローマ遺跡","exp":"100","type":"史跡","name":"ポンペイ遺跡","desc":"ヴェスヴィオ火山の大噴火によって一瞬で滅びた、古代ローマの都市。火山灰に埋もれていたため当時の生活の様子が生々しく残る。"}],"345":[{"rank":"5","note":"一撃！","exp":"1118","type":"大型生物","name":"ジャガー","desc":"「一度の跳躍で獲物を殺す」という名のとおり、獲物を一撃で噛み砕く力を持っている。その力はカメの甲羅をも割り、ときにはワニまで捕食するという。木登りが得意で、泳ぎもうまい。主に単独で行動する。"}],"1469":[{"rank":"2","note":"マヤ人になったイスパニア人","exp":"270","type":"財宝","name":"ゲレロの装束","desc":"アギラールと共に遭難したイスパニア人。彼と同様にとらわれの身となるが、やがて彼らと共に暮らし、マヤ人の娘を娶った。コルテスの招集にも応じず生涯マヤ人として祖国の兵と戦ったという。これは、そのときの戦装束のようだ。"}],"3717":[{"rank":"4","note":"コブが二つのラクダ<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740","type":"大型生物","name":"フタコブラクダ","desc":"背中のコブが二つのラクダ。ヒトコブラクダと比べ四肢が短く、移動や運搬以外にも様々な用途で重宝されいるという。"}],"5023":[{"rank":"2","note":"到達する","exp":"350","type":"港・集落","name":"アンボイナ","desc":"モルッカ諸島南方に位置する小島にあり、クローブなどの香辛料を産する街。香辛料を求め、ヨーロッパからの進出が相次いだ。"}],"5009":[{"rank":"2","note":"","exp":"","type":"地理","name":"カスピ海","desc":"世界でも類を見ないほど巨大な湖。流入する河川は100を超える。チョウザメが多く生息しているなど特有の生態系を保っている。"}],"6455":[{"rank":"2","note":"コロラド高原北西のとんがり岩付近","exp":"140","type":"気象・現象","name":"多重渦竜巻","desc":"複数の竜巻が、一つにまとまってできる竜巻群。大型のものは、広範囲に甚大な被害を与える場合がある。大きな竜巻の周りを、小さな竜巻が取り巻くような構造を有することも多い。"}],"5337":[{"rank":"2","note":"クエスト「星と愛の詩」<br/>発見物カード:175","exp":"370","type":"天文","name":"や座","desc":"ギリシャ神話の愛の神エロスがゼウスに放った黄金の矢が天に上った姿とされる。ゼウスはこの矢によってトロイの王子ガニュメデスに心を奪われた"}],"6483":[{"rank":"5","note":"追究クエスト","exp":"1080","type":"史跡","name":"ジンバブエ遺跡のアクロポリス","desc":"アフリカ南方にある石造の建造物群「ジンバブエ遺跡」。その遺跡は「大囲壁」と「谷の遺跡」、そして北側の丘にある「アクロポリス」と大きく3つの区域に分けられる。"}],"6081":[{"rank":"2","note":"「航海士の観測記録」<br/>発見物カード:150","exp":"300","type":"天文","name":"カメレオン座","desc":"南天星座の一つ。南天の星図作成に尽力した航海者ペーテル・ケイセルらの残した観測記録を元に制定され、同時代に南半球で発見されたカメレオンの名をつけられた。"}],"1257":[{"rank":"1","note":"メソアメリカの祭器の地図","exp":"110","type":"宗教遺物","name":"メソアメリカの祭器","desc":"土器で作られた祭器。メソアメリカでは信仰や祈祷、祭礼が非常に尊ばれており、このような祭器がたくさん見つかる。"}],"6504":[{"rank":"4","note":"","exp":"760","type":"虫類","name":"クジャクグモ","desc":"オーストラリアの特定の地域に生息されるとされるクモ。オスは腹部にあるきれいでカラフルな腹膜を広げ、踊るようにメスに求愛行動をとる。"}],"214":[{"rank":"1","note":"ドイツを開拓した騎士団","exp":"140","type":"財宝","name":"ドイツ騎士団長の剣","desc":"ドイツ騎士団は、十字軍時代の三大騎士団の一つ。紋章は白地に黒十字。プロイセン地方の開拓に貢献した。独自の領土を持つ。"}],"6855":[{"rank":"5","note":"発見物カード:465","exp":"930","type":"財宝","name":"虫入り琥珀","desc":"中に虫などを含んでいる琥珀。樹液が昆虫や葉などを包み込んだまま固まり、何千万年もの時を経て化石化、琥珀となって産出したもの。偶然の産物で、希少価値がある。"}],"2415":[{"rank":"2","note":"ダンジョン","exp":"365","type":"宗教遺物","name":"ハトホル像","desc":"古代エジプトの神の一つ。諸神の母と呼ばれる他にも、天空の神や死者の守護神といった多様な面を持ち合わせている。"}],"1262":[{"rank":"5","note":"蘇るトロイ戦争","exp":"1183","type":"美術品","name":"ラオコーン（腕曲げ）","desc":"ローマで出土したラオコーン像の完全な姿。体をよじり苦痛に耐える表情から、天罰の恐ろしさがまざまざと伝わってくる。"}],"801":[{"rank":"2","note":"大きなサルの地図","exp":"260","type":"中型生物","name":"マントヒヒ","desc":"岩山で大きな規模の群れを作るサル。オスは長い飾り毛が目立つ。牙が大きく、近づくのは危険だろう。"}],"5887":[{"rank":"5","note":"","exp":"1430","type":"大型生物","name":"ジプシーバナーホース","desc":"イングランド原産の馬で、小柄ながら力が強いため馬車などに古くから用いられてきた。たてがみや尾などの毛が長く、足首にも同様の毛が生えている。性格は比較的温厚。"}],"1791":[{"rank":"3","note":"メガネをかけるクマ","exp":"540","type":"大型生物","name":"メガネグマ","desc":"南米に生息するクマ。顔に、メガネのような白い模様がある。人の背丈ほどの大きさで、標高2000m前後の高地の森に棲む。木登りが得意で夜行性。"}],"206":[{"rank":"1","note":"タペストリーの地図","exp":"70","type":"美術品","name":"旧約聖書のタペストリー","desc":"シモン・ブーエの原画をもとにした連作タペストリーの一つ。旧約聖書をもとにした内容で、全部で八枚あるという。分厚く豪華なゴブラン織りのタペストリーである。"}],"6988":[{"rank":"2","note":"","exp":"","type":"鳥類","name":"繁殖期のトキ","desc":"東アジアに生息し、白い体と淡紅色の翼を持つトキは、繁殖期に頭から翼にかけて灰黒色に変わる。黒くなった首付近の分泌物を自ら塗りつけるためで、この体色は抱卵中に保護色となると考えられている。"}],"1973":[{"rank":"5","note":"優雅に舞う巨大鳥","exp":"1080","type":"鳥類","name":"コンドル","desc":"とても大きな鳥。中には翼を広げると3mになるものもいる。大きな翼を広げたまま、高所を滑空する姿がよく見られる。高地の断崖の岩陰に巣を作り、死んだ大型動物の肉を好んで食べる。50年以上生きる長寿の鳥。"}],"2913":[{"rank":"3","note":"ダンジョン","exp":"470","type":"歴史遺物","name":"九十六文字の石版","desc":"びっしりと図形らしきものが彫られた石版。規則性があることから文字である可能性が高い。もしかしたらパレンケ王朝史が刻まれているのかもしれない。"}],"6655":[{"rank":"2","note":"","exp":"230","type":"植物","name":"フクシア","desc":"中南米原産の植物。花が美しく鑑賞に供される。花が下を向いて咲く姿から「貴婦人のイヤリング」とも称される。"}],"1543":[{"rank":"2","note":"マニラ東の海域調査","exp":"220","type":"地理","name":"フィリピン海","desc":"ミンダナオ島、ルソン島の東に位置する海。色とりどりの魚が映える美しい海だが、夏になると猛烈な豪雨に見舞われることがある。"}],"764":[{"rank":"1","note":"赤い花の地図","exp":"27","type":"植物","name":"シクラメン","desc":"大きな花弁の花が下を向いて咲く植物。ピンクや紅色があり、大変優雅で美しい。"}],"2009":[{"rank":"2","note":"サルベージ","exp":"280","type":"歴史遺物","name":"エストレラ号","desc":"ノッサ・セニョーラ・ダ・エストレラ号。\n大西洋のアセンション島北西で難破したポルトガルの東インド貿易船。"}],"5104":[{"rank":"1","note":"到達する","exp":"75","type":"港・集落","name":"ナタール","desc":"インド洋に面した、アフリカ南部沿岸に位置する港町。ナタールとはポルトガル語でクリスマスという意味である。"}],"5924":[{"rank":"3","note":"","exp":"600","type":"史跡","name":"エルミナ城","desc":"アフリカとの交易を保護する、という目的でポルトガルにより建設された城。かの地は黄金海岸と称されるほどの金の産出量を誇り、この城も交易において大きな役割を果たしていた。"}],"629":[{"rank":"5","note":"七色の鳥","exp":"910","type":"鳥類","name":"コンゴウインコ","desc":"極彩色の大型インコ。尾までいれると1m以上あり、非常に美しい。赤が基調のものがほとんどだが、青い種類もいるようだ。インコの例にもれず、飛ぶのはあまりうまくない。"}],"5480":[{"rank":"4","note":"アマゾン川河口より一本目の支流　奥で釣り<br/>経験　:640<br/>カード:320","exp":"640","type":"海洋生物","name":"ヨロイナマズ","desc":"アマゾン川を中心とした熱帯地域に生息するナマズ。鱗が鎧のように硬いのが特徴。食用にもされており、見た目とは裏腹に非常に美味。"}],"5218":[{"rank":"1","note":"パフォス郊外　再調査報酬","exp":"","type":"歴史遺物","name":"カトパフォスのネクロポリス","desc":"アテネのパルテノン神殿と同じ建築様式で造られている地下墓地。王家の墓と呼ばれている。近年では住居として住み着く者が現れているようだ。"}],"5192":[{"rank":"2","note":"到達する","exp":"370","type":"港・集落","name":"漢陽","desc":"読みは「ハンヤン」。「漢水より北の大地」という意味がある。\n百済時代の都があったため歴史は古く、遺物が多く発見される。"}],"3888":[{"rank":"2","note":"先住民族の装身具の地図","exp":"240","type":"財宝","name":"トルコ石の装身具","desc":"トルコ石の欠片を繋ぎ合わせて作られた装身具。北米の南西部ではトルコ石がよく採れ、加工や取引が盛んだった。先住民の間では、トルコ石には特別な力か備わっているとされる。"}],"6901":[{"rank":"3","note":"","exp":"","type":"美術品","name":"牛乳を注ぐ女","desc":"ネーデルラントの画家フェルメールが描いた油彩絵画。一人の女性が牛乳を器に注ぐ様子が描かれている。厚みのある色彩と柔らかな陰影表現が、絵画全体に静謐な印象を生んでいる。"}],"6624":[{"rank":"3","note":"発見物カード 253","exp":"506","type":"地理","name":"ギリ・トラワンガン","desc":"サンゴ礁が美しい南太平洋の小島。小スンダ列島に属するギリ三島の一番西に位置する。"}],"2015":[{"rank":"1","note":"アンデスの儀式道具の地図","exp":"170","type":"歴史遺物","name":"祭事用の金細工","desc":"豊かな金を使って作った祭器。インカではあまり頓着されていないが、異国の心無い人間が見れば奪ってでもほしいお宝だろう…。"}],"5246":[{"rank":"1","note":"","exp":"200","type":"史跡","name":"トフェ","desc":"古代カルタゴの遺跡。\nバアル・ハモン神やタニト神の聖域とされており、多数の墓石などが見つかってる。"}],"2418":[{"rank":"4","note":"ダンジョン","exp":"640","type":"宗教遺物","name":"アメン像","desc":"古代エジプトの神の一人。アメン＝ラーとしてラー神と一体化し、エジプト神の中心として存在した。テーベにおける大気の神でもあり、カルナック神殿の主神として祭られている。"}],"1041":[{"rank":"1","note":"洋上の危険物","exp":"20","type":"海洋生物","name":"カツオノエボシ","desc":"透き通った青い体を持つクラゲ。体部は水面に浮かんでおり、その周辺に数十mもの長さがある触手が伸びている。激烈な毒があり、人が死ぬことも珍しくない。切れた触手だけが浮遊して、被害が出ることもある。"}],"6072":[{"rank":"4","note":"","exp":"740","type":"伝承","name":"ベテスダの池","desc":"「神の恩寵」を意味するベテスダという土地にある池。神の御使いが池の水を「動かす」と、池にはいかなる病も癒す力が一時的にだが備わったと伝えられている。"}],"6893":[{"rank":"5","note":"","exp":"","type":"宗教建築","name":"大雁塔","desc":"西安の寺院内に建てられた四角いレンガ造りの仏塔。インドから持ち帰った経典や仏像を保管するため、玄奘三蔵が皇帝に願い出て建立されたという。"}],"6076":[{"rank":"4","note":"","exp":"","type":"伝承","name":"カリュブディスの渦潮","desc":"古来、自然現象を元にして神話が作られる例は枚挙に暇がない。航海の難所であるメッシナ海峡もその例に漏れず、渦潮を発生させる大食いの怪物が潜んでいるとされ、船乗りたちを恐れさせた。"}],"6426":[{"rank":"4","note":"","exp":"","type":"鳥類","name":"夏羽のライチョウ","desc":"夏羽に生え変わったライチョウ。褐色を帯びている。羽の生え変わりは一ヶ月ほどで行われる。あまり飛ばずに歩いて移動する。暑い日などは熱気を避けるためか、木々や洞窟、雪の中に隠れることもあるという。"}],"6202":[{"rank":"4","note":"草原の民の足跡","exp":"630","type":"史跡","name":"マダラの騎士像","desc":"ブルガリア北東部にある、マダラ高原の崖に刻まれた巨大なレリーフ。周りに足場のない高さに刻まれているという特色がある。周囲に古いギリシャ語の銘文があるため、かつてこの地を支配したブルガール人が作ったという説がある。"}],"6796":[{"rank":"2","note":"「亜寒帯動物の生息地図」<br/>発見物カード:110","exp":"220","type":"大型生物","name":"シェトランドポニー","desc":"イングランドの北東にあるシェトランド諸島原産の馬。体は小さいが丈夫で、力も強い。灰、青、茶、黒、白など様々な毛色が存在する。農耕や荷運びに古くから使われている。"}],"2998":[{"rank":"4","note":"太古の崖","exp":"800","type":"史跡","name":"ジョギンズの化石の崖群","desc":"不思議な石が多く見られる崖。もともとは、ただの石崖だったが、潮の浸食により、動物の骨が石化したものが多く見つかるようになった。"}],"2956":[{"rank":"3","note":"古の生命","exp":"470","type":"化石","name":"キバのある動物の骨","desc":"巨大なキバが特徴的な動物の骨。チーターやトラに似た形なことから、俊敏な動きで獲物を追い、このキバで捕食したのだろう。"}],"6536":[{"rank":"5","note":"レガシー星の叡智　右下","exp":"2550","type":"史跡","name":"登封観星台","desc":"元代の学者・郭守敬が建設した、巨大な天文台。日陰の長さから季節や緯度の高低などを計算する。元国各地に置かれた観測拠点の中心であり、授時暦はこれら観測拠点から集めた記録を参考にしたといわれる。"}],"1971":[{"rank":"3","note":"長い長いくちばし","exp":"480","type":"鳥類","name":"ヤリハシハチドリ","desc":"くちばしの長い、小さな鳥。槍のような形状のくちばしは、体長の約4割を占めている。毛づくろいは、くちばしが使えない代わりに長い足を使う。空中で静止するように飛び、花の蜜を吸う。"}],"564":[{"rank":"2","note":"古代民族の武具","exp":"270","type":"歴史遺物","name":"海の民の鎧","desc":"ヒッタイトを滅ぼし、古代エジプトを苦しめた正体不明の古代民族「海の民」が使っていたと思われる鉄の鎧。製鉄技術は、ヒッタイトしか持っていなかったはずだが…。"}],"5532":[{"rank":"3","note":"","exp":"260","type":"気象・現象","name":"黄砂","desc":"ユーラシア大陸内の陸部から微小な砂が風に乗って移動し、周辺地域へ降りそそぐ現象。農作物や周辺住民の健康にも影響を及ぼし、海を越えて被害を発生させることもある。"}],"1727":[{"rank":"5","note":"恒久なる星々","exp":"1183","type":"財宝","name":"恒久なる星々","desc":"オーストラリアでのみ見つかる、黒いオパール。地が黒であるためさらに遊色が映える。月のない夜に輝く幾千の星を思わせる美しさで、見ていると月のない夜に一人たたずんだときに空に吸い込まれてしまうような、あの感覚に陥る。"}],"5244":[{"rank":"4","note":"クエスト「南の目印」<br/>発見物カード:350","exp":"700","type":"天文","name":"みなみじゅうじ座","desc":"ケンタウルス座の南にある、全天で一番小さな星座。1等星を2つ含み、天の南極を探す際によく利用される。"}],"705":[{"rank":"4","note":"人を惑わせる竪琴","exp":"696","type":"財宝","name":"セイレーンの竪琴","desc":"歌声で船乗りをまどわせる妖怪・セイレーンのものだという竪琴。金や宝石を多く使った豪華な竪琴であるが、本当にセイレーンのものかどうかは確かめようがない…。"}],"3010":[{"rank":"5","note":"怒涛の大瀑布<br/><br/>発見時経験値1100　発見物カード経験値550","exp":"1100","type":"地理","name":"ナイアガラの滝","desc":"北米大陸きっての壮大さを誇る大滝。\nナイアガラ川の流れが二つの島によって三つに分かたれ、エリー湖からオンタリオ湖へ流れ込んだものである。絶えず巻き上がる水煙が、その荘厳な風景を引き立てる。"}],"4809":[{"rank":"","note":"安土城（中層隠し部屋）","exp":"","type":"財宝","name":"金唐傘の馬印","desc":""}],"5734":[{"rank":"5","note":"2017.02.07新規発見<br/><br/>意外なことに！？大型生物でも海洋生物でもなく、中型生物。","exp":"","type":"中型生物","name":"バイカルアザラシ","desc":"バイカル湖周辺にのみ生息するアザラシ。淡水のみに棲む珍しい種で、バイカル湖の生態系の頂点に立つとされる。獲物を探すための大きな目を有する。"}],"3552":[{"rank":"","note":"","exp":"","type":"レリック","name":"アリババと盗賊","desc":"アラビア語やペルシャ語ではアリババの「ババ」は「お父さん」という意味らしい。アリババは意外と年配だったのだろうか。"}],"5272":[{"rank":"","note":"","exp":"","type":"レリック","name":"滅びし国の物語","desc":""}],"754":[{"rank":"2","note":"青い獣の調査","exp":"315","type":"中型生物","name":"ブルーバック","desc":"アフリカ南部の草原地帯に住むレイヨウ。青灰色の毛並みがとても美しい。角を含めた高さは2mにもなり、レイヨウの中では大型のほうだろう。特異な色の毛皮が珍重されているようで、このままでは絶滅しそうだ。"}],"6250":[{"rank":"1","note":"","exp":"180","type":"宗教建築","name":"サンティアゴ大聖堂","desc":"正式名は「サンティアゴ・デ・コンポステーラ大聖堂」といい、フランスからイベリア半島におよぶ「聖ヤコブの巡礼路」の終着点にあたる。\n伝承によればキリストの弟子である使徒ヤコブの遺体が安置されているという。"}],"6856":[{"rank":"5","note":"追究クエスト<br/>発見物カード:475","exp":"950","type":"美術品","name":"女史箴図","desc":"じょししんず。東晋の画家・顧愷之が描いたとされる絵巻物。原画は散逸し、写本のみが伝わっている。西晋の政治家・張華の記した宮廷女官を戒めるための詩を絵にした。宮中の様々な場面を描き、女官の心得を独特の画風で表現している。"}],"1890":[{"rank":"2","note":"サルベージ","exp":"310","type":"歴史遺物","name":"ボン・ジェズス号","desc":"ポルトガルの東インド貿易船。\nリスボンからインド方面に向かう途中、マダガスカル島から東の地点で暗礁に乗り上げ、沈没した。"}],"6682":[{"rank":"5","note":"発見物カード:410","exp":"820","type":"天文","name":"メンカル","desc":"クジラ座の鼻先にあたる赤色巨星。名はアラビア語で「鼻の孔」を意味する。\n\nカード：経験値410"}],"704":[{"rank":"3","note":"人の言葉を話す鳥","exp":"462","type":"鳥類","name":"ヨウム","desc":"全身が灰色で、尾の先が赤い、地味なインコである。しかし、非常に知能が高いようで、よく教えると物まねではなく簡単な会話が可能だという。飛ぶ様子はたどたどしい。"}],"308":[{"rank":"4","note":"ヨルバの創世物語","exp":"720","type":"宗教遺物","name":"オドゥドゥア像","desc":"アフリカのヨルバ人の神の像。最高神であるオロルンが海と交わってオドゥドゥアを産みオドゥドゥアが大地と人間を作ったと伝えられている。"}],"2953":[{"rank":"4","note":"襟付きドラゴンの調査<br/><br/>発見時経験値700　発見物カード経験値350","exp":"700","type":"化石","name":"穴の開いたドラゴンの骨","desc":"新大陸北部で発見された、耳に大きな穴が開いたドラゴンの骨。穴は聴力を増すためのものだろうか。それとも別の用途で開いているのだろうか。"}],"6328":[{"rank":"2","note":"","exp":"320","type":"小型生物","name":"アフリカマイマイ","desc":"東アフリカなどに生息する最大級のカタツムリの一種。植物はもちろん砂や石まで食べるほどの雑食性。調理すれば食べられるが、直接触れたり、這った跡に触れたりすると寄生虫に感染する恐れがある。"}],"1481":[{"rank":"5","note":"死者の見る夢","exp":"1183","type":"財宝","name":"水晶髑髏","desc":"総水晶製のドクロ。いつ、どこで作られたのか、全くの謎に包まれている。水晶は硬いため、研磨が難しいとされている。もし、この技術が既に失われているとしたら、非常に残念なことだ。"}],"2905":[{"rank":"2","note":"古代の絹織物","exp":"360","type":"宗教遺物","name":"帛画","desc":"読みは「はくが」。\n帛とは絹布のことであり、帛画とはそうした絹布に描かれた、古代中国の絵画を指す。\n絹という脆い素材であるため、良い保存状態で発見されることは稀である。"}],"2601":[{"rank":"3","note":"異端の名画","exp":"490","type":"美術品","name":"長谷川等伯の屏風絵","desc":"日本の絵師・長谷川等伯の筆による屏風絵。江戸時代初期の主流である狩野派に対抗し、独自の作風で生み出した作品の一つである。"}],"1321":[{"rank":"2","note":"クエスト「モルッカ海追加調査」<br/>発見物カード:160","exp":"320","type":"地理","name":"モルッカ海峡","desc":"セレベス島の北部の東側に横たわる海峡。複雑な地形を生かして、かなり古くから海賊が活動しているようだ。"}],"5743":[{"rank":"5","note":"女教皇の伝説<br/>2017.02.07新規追加","exp":"1450","type":"宗教遺物","name":"女教皇ヨハンナの像","desc":"女教皇ヨハンナのものとされる像。とはいえ彼女が実在した確たる証拠はなく、この像が本当にヨハンナをモデルにしているかは不明。"}],"1217":[{"rank":"1","note":"テキーラの原料","exp":"135","type":"植物","name":"リュウゼツラン","desc":"大きく厚い葉を放射状につけ、数mにも伸びた茎に花を咲かせる植物。根はテキーラの原料となる。その繊維はロープなどを作る際にも利用される。"}],"781":[{"rank":"1","note":"尊厳者","exp":"160","type":"歴史遺物","name":"アウグストゥスの宝玉","desc":"オクタヴィアヌス・アウグストゥス帝を彫った巨大なカメオ。女神と並んで座り、王冠を戴いている。アウグストゥスはカエサルの養子で、ローマ初代皇帝になった人物。"}],"3937":[{"rank":"1","note":"「明るい星の観測記録」<br/><br/>発見物カード:35","exp":"70","type":"天文","name":"アルタイル","desc":"わし座で最も明るい星で白く輝く1等星。夏の大三角の一角を構成する。名はアラビア語で「飛翔する鷲」を意味する。"}],"2792":[{"rank":"5","note":"酒場マスターの悩み事","exp":"830","type":"大型生物","name":"ジャイアントパンダ","desc":"主に中国南西部に生息する動物。白と黒に、はっきりと分かれた体毛が特徴。尾は、あまり成長しないため、目立たない。\n群れや家族を形成せず単独で行動する。"}],"1044":[{"rank":"2","note":"陸にあってはいけないもの","exp":"230","type":"化石","name":"巨大なサメの骨","desc":"10mを軽く超える、大型のサメの骨格。歯ははっきりと残っているが、それ以外は痕跡程度である。サメは骨が柔らかいからだろう。それはともかく、こんな巨大なサメの骨がなぜ陸地で発見されたのだろう？"}],"6993":[{"rank":"5","note":"レガシー法の叡智・正義の象徴　右上","exp":"","type":"歴史遺物","name":"ヘラクレアの青銅板","desc":"ローマの古代都市ヘラクレアの自治法規が刻まれた、二枚の青銅板碑文。ギリシャ語とラテン語が用いられ、内容は道路や土地の区分から、集会の規則などにまで多岐にわたり、ローマ法の強い影響が随所にみられる。"}],"6806":[{"rank":"5","note":"発見物カード:420","exp":"840","type":"宗教建築","name":"クトゥブ・ミナール","desc":"インドのデリーにあるインド最古のミナレット。デリー・スルタン王朝を建国したアイバクが、デリーをイスラム都市として整備する中で着工した。石造りで、その美しさを称えられる。"}],"2571":[{"rank":"3","note":"鹿皮の持ち主","exp":"540","type":"中型生物","name":"バイカロク","desc":"台湾島に多く生息するシカ。梅の花に似た白い斑点が体にあることからバイカロク（梅花鹿）と呼ばれる。\n古来、角や鹿皮が珍重されており、狩猟の対象となっていた。"}],"113":[{"rank":"2","note":"カリブ最大の島","exp":"360","type":"地理","name":"キューバ島","desc":"カリブ海でもっとも大きいと思われる島。最近になって開拓が進められ、タバコなどのカリブ特有の作物が栽培されている。"}],"4882":[{"rank":"4","note":"発見物カード:320","exp":"640","type":"天文","name":"ペルセウス座流星群","desc":"ペルセウス座の方角から、飛び出してくるように見える流星群。一年のうち約一カ月、出現する。流れる星の数が多く、光も強いことが多いため、観測しやすい"}],"6001":[{"rank":"2","note":"発見物カード:120","exp":"240","type":"気象・現象","name":"副虹","desc":"虹が2つ並行して発生した際の外側のものを副虹という。原理は不明だが、2つの虹の色の並びは逆になっている。"}],"361":[{"rank":"5","note":"王家の紋章","exp":"816","type":"歴史遺物","name":"純金の小箱","desc":"ヴェルギナ遺跡から見つかった純金製の箱。表面にはマケドニアの紋章と見られる太陽の紋章が刻まれている。中には骨が入っており高貴な人物の遺骨と思われる。"}],"5335":[{"rank":"2","note":"クエスト「野獣の星座」<br/>発見物カード:140","exp":"280","type":"天文","name":"おおかみ座","desc":"ゼウスの怒りを買ったアルカディアの王リュカオンがオオカミに姿を変えられ、天に上った姿とされる。おおかみ座とケンタウルス座は古代メソポタミアの時代から対とされることが多かった。"}],"5811":[{"rank":"3","note":"","exp":"","type":"財宝","name":"マナス","desc":"キルギス地方に伝わる長大な叙事詩。マナスという名の英雄と、その子孫たちの活躍が描かれている。マナスチという語り部が口伝でのみ伝承している。"}],"5077":[{"rank":"1","note":"到達する","exp":"127","type":"港・集落","name":"ジョファール","desc":"アラビア海沿岸に位置する港町。モンスーンの季節には大量の雨が降る。"}],"3424":[{"rank":"","note":"","exp":"","type":"レリック","name":"オジェ・ル・ダノワ","desc":"多くの武勲詩の主人公で、シャルルマーニュに仕えたとされる騎士。デンマークではホルガー・ダンクスの名で親しまれている。"}],"784":[{"rank":"1","note":"太陽のあふれる浜辺","exp":"20","type":"地理","name":"コスタデルソル","desc":"マラガを中心とした、300kmにおよぶ海岸線を指す。意味はスペイン語で「太陽の海岸」である。1年を通して温暖な気候で、保養地には最適だ。"}],"127":[{"rank":"1","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40","type":"宗教遺物","name":"聖母のステンドグラス","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。"}],"5890":[{"rank":"2","note":"","exp":"240","type":"中型生物","name":"ジャックウサギ","desc":"体長が40cmを超える、大型のウサギ。北米に生息する。脚が発達しており、時速30km以上で走ることができる。"}],"2873":[{"rank":"2","note":"宗教書の地図","exp":"300","type":"宗教遺物","name":"太平青領書","desc":"道教の経典の一つ。張角が得たことから、彼が起こした太平道の経典となった。\n別名、太平経。"}],"1365":[{"rank":"2","note":"荘厳の聖母","exp":"220","type":"美術品","name":"荘厳の聖母","desc":"アンブロージョ・ロレンツェッティ作の祭壇画。ロレンツェッティが生涯に手がけた荘厳の聖母の一作。彼が描いた聖母子画の中で、特に評価が高い。互いに視線を交ぜ合わせる聖母子の姿は深い愛を感じさせる。"}],"2906":[{"rank":"2","note":"長江に現れた小動物","exp":"240","type":"小型生物","name":"コツメカワウソ","desc":"中国南部やインドネシアなどに分布する、とても小さなカワウソ。泳ぎに適した平たい体をしている。\n群れで生息し、人にもよく慣れる。"}],"875":[{"rank":"2","note":"逃れられない毒蛇","exp":"270","type":"小型生物","name":"ブラックマンバ","desc":"アフリカに生息する、猛毒のヘビ。移動が速く、走る人間に追いつくほどだという。非常に危険な生物だといえるだろう。"}],"5414":[{"rank":"1","note":"海神の像","exp":"60","type":"宗教遺物","name":"ポセイドン像","desc":"ギリシャ神話の海神の像。ポセイドンは多くの愛人を持ち、その子供にはポリュフェモスなど、凶暴な怪物が多い。有名なメデューサもポセイドンの愛人でその子供がペガサスである。"}],"2615":[{"rank":"4","note":"鄭成功についての再調査","exp":"800","type":"財宝","name":"鄭氏の印","desc":"「鄭氏」と刻まれた金属製の印。\n鄭氏が貿易の際に認印として使用していたものと思われる。"}],"1617":[{"rank":"4","note":"職人好みの装飾品","exp":"612","type":"美術品","name":"タラのブローチ","desc":"8世紀にアイルランドで作られたブローチ。金の準環状ブローチで宝石と共にケルト文様が彫り込まれている。僧衣などのマントを留めるために使われた。アイルランド金細工の至宝といわれている。"}],"5189":[{"rank":"2","note":"到達する","exp":"340","type":"港・集落","name":"泉州","desc":"読み方は、「チュワンチョウ」。かつて海上貿易の拠点として繁栄した街。\n晋末に中原から多くの移民が流入したため、中原の技術や文化が伝わっている。"}],"1352":[{"rank":"5","note":"海中の虹","exp":"1040","type":"財宝","name":"海中の虹","desc":"遊色効果の高いムーンストーン。澄んだ青いベースカラーの中で、時折七色にきらめいている部分がある。それを見た人が「まるで海の中で虹を見ているようだ」と言ったことからこの名前がついた。"}],"2617":[{"rank":"5","note":"大地にたたずむ石柱","exp":"1210","type":"歴史遺物","name":"月形石柱","desc":"台湾島の古代文化の集落があった場所に残されていた、厚さ20cmほどの柱。\n祭祀用の石であったとの説や、建築物の壁であったという説など、諸説ある。"}],"125":[{"rank":"1","note":"クエスト「ギリシャ神話が題材の絵」<br/>発見物カード:55","exp":"110","type":"美術品","name":"ネッソスにさらわれるディアネイラ","desc":"グイド・レーニ作の、ヘラクレスを題材とした連作の一枚。ヘラクレスの妻・ディアネイラが、ネッソスというケンタウロスにさらわれるシーンである。素晴らしい躍動感にあふれた作品だ。"}],"6213":[{"rank":"4","note":"サルベージ","exp":"710","type":"歴史遺物","name":"デ・アトーチャ号","desc":"イスパニアのガレオン船。新大陸の貴金属、宝石などを満載し帰国途中、嵐に遭い、フロリダ沖で沈没した。"}],"6777":[{"rank":"4","note":"","exp":"800","type":"財宝","name":"納め太刀","desc":"木製の大太刀。大山詣りに使われた。源頼朝が刀を奉納した故事に由来し、願い事を書いた木太刀を神社に奉納する行事。商売繁盛、勝負運のご利益があるという。江戸からの参拝客で宿場町が繁盛するという。"}],"5781":[{"rank":"5","note":"","exp":"1380","type":"地理","name":"死海","desc":"水中の塩分が非常に高い塩湖。流れ出る川がなく、流入する水より蒸発する水のほうが多いため、高い塩分濃度を保っている。魚が棲めない環境のため、死の湖と呼ばれている。"}],"547":[{"rank":"1","note":"古代ペルシャの印章の地図","exp":"67","type":"歴史遺物","name":"円筒印章","desc":"古代メソポタミア近辺で使われていた、円筒形の印章。粘土板の上を転がして押印する。"}],"5387":[{"rank":"2","note":"発見物カード:150","exp":"300","type":"宗教遺物","name":"アルゴナウティカ","desc":"ギリシャ神話の英雄イアソンが王位継承の条件としてコルキスにあるという金羊毛皮を求める物語。全ギリシャから集まった50人の勇士が巨大な船アルゴ号に乗り組み、各地で冒険を繰り広げる。"}],"1242":[{"rank":"2","note":"贈り物には","exp":"365","type":"小型生物","name":"メキシコサンショウウオ","desc":"この生物は、完全に成体に成長することなく繁殖する。平たい尾と赤く大きな外鰓（がいさい＝羽状のエラ）を持つ。"}],"2994":[{"rank":"4","note":"白の叡智","exp":"780","type":"鳥類","name":"シロフクロウ","desc":"大型のフクロウ。真っ白な羽毛が美しい。\n高所にはあまり生息しておらず、寒冷地帯の草原でよく見られる。"}],"1710":[{"rank":"1","note":"古い法典の地図","exp":"160","type":"宗教遺物","name":"維摩経","desc":"ゆいまきょう。仏教経典のひとつ。内容は般若経の多くに似通っているが、維摩と文殊菩薩の対話により究極の達成地を導き出すなど物語的な構成になっている。"}],"459":[{"rank":"5","note":"金色の生物","exp":"1105","type":"小型生物","name":"キンイロアデガエル","desc":"捕食者に対し有毒だと警告するために鮮やかな色をしている。地上で活動し、卵も地上に産む。"}],"6969":[{"rank":"4","note":"追究クエスト<br/>発見物カード:360","exp":"720","type":"中型生物","name":"アビシニアコロブスの幼体","desc":"アビシニアコロブスの幼体は成体と異なり、全身が真っ白な毛に覆われている。生後三カ月ほど経つと、徐々に親と同じ黒い体毛へと変化していく。"}],"3265":[{"rank":"4","note":"歴史を奏でる者たち<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740","type":"財宝","name":"コラ","desc":"西アフリカ一帯に伝わる弦楽器。弦の数は21本で、親指と人差し指で爪弾いて音を出す。音楽家はこのコラを用い、歴史や情報を弾き語ることにより伝統を紡いできたようだ。"}],"417":[{"rank":"1","note":"奇妙な石の地図","exp":"120","type":"化石","name":"半竜半魚の骨","desc":"ドラゴンのような長い首と、イルカのようなヒレを持った生き物の骨。骨とはいっても石になっている。どうして骨が石になるのだろう？　未知の呪術か何かだろうか。"}],"1773":[{"rank":"4","note":"鳥が集う場所","exp":"620","type":"地理","name":"アタカマ塩湖","desc":"アタカマ砂漠にある広大な塩湖。湖岸の岩が塩で白く染まっている様は、まるで雪が積もっているかのようだ。この塩湖は、フラミンゴの羽休めの場所ともなっている。"}],"1441":[{"rank":"2","note":"違いを探る","exp":"320","type":"小型生物","name":"フクロムササビ","desc":"滑空する有袋類。爪は長く、指は枝をしっかりとつかむように向かい合っている。大きな耳と前方に付いた目で距離を測り、暗闇でも100mを超える滑空を行う。"}],"181":[{"rank":"2","note":"スルタンの宝冠","exp":"240","type":"財宝","name":"スルタンの宝冠","desc":"イスラム勢力の君主であるスルタンが所有していたという宝冠。スルタンはいわゆる冠を着けないので、これはほかの勢力から納められた宝物なのだろう。"}],"591":[{"rank":"2","note":"黒い毛の生物","exp":"210","type":"中型生物","name":"クロキツネザル","desc":"オスは黒、メスは赤や茶色、灰色の被毛をしている。ともに、耳に長い房毛がある。木々の間で果実などを食べる。"}],"5329":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"チョンゴニの岩絵","desc":"アフリカ南東部の広い範囲にある洞窟や岩に描かれた絵。特に狩人が描かれた絵は非常に古く、長く儀式の場として用いられてきたようである。"}],"6451":[{"rank":"5","note":"","exp":"","type":"財宝","name":"オスマン帝母の金銀香炉","desc":"古くから中東で使われた、手持ちの柄が付いた香炉。オスマン帝国のスルタンの母君が聖地の寺院へ奉納するために送った品という。鉄製で金銀の豪華な象嵌が施されている。"}],"5095":[{"rank":"2","note":"到達する","exp":"310","type":"港・集落","name":"ディリ","desc":"ティモール島の東部北岸に位置する街。ティモール島は古くから白檀の産地として知られ多くの交易船が来航している。近年は、ヨーロッパの交易船の来航が目立つようだ。"}],"1962":[{"rank":"2","note":"アンデスの儀式道具の地図","exp":"220","type":"宗教遺物","name":"儀式用土器","desc":"アンデスの神殿で、神器として使われていたという土器。トウモロコシの酒・チチャを注いでいたのだろうか。"}],"6473":[{"rank":"2","note":"","exp":"280","type":"歴史遺物","name":"テオファネスの年代記","desc":"ビザンツ帝国の修道士テオファネスが9世紀初頭にまとめたとされる年代記。ロードス島の巨像の最期について記述がある。ギリシャ語で書かれ、のちにラテン語訳も作られた。現存しない当時の歴史書の引用もあり、貴重なものとされる。"}],"2653":[{"rank":"3","note":"巨大な身体と声","exp":"460","type":"鳥類","name":"キタタキ","desc":"朝鮮半島から中国、インドまで、広く生息するキツツキの一種。\n巨大な枯れ木に営巣する。頭頂部と頬の赤い羽毛が特徴的。また、上半身は黒、下半身は白と鮮やかな配色も目を引く。"}],"205":[{"rank":"1","note":"タペストリーの地図","exp":"70","type":"美術品","name":"スキピオ伝のタペストリー","desc":"ジュリオ・ロマーノの原画をもとに織られた連作タペストリーの一枚である。内容は、古代ローマ時代のカルタゴ戦争を舞台に、スキピオの事績を追うものである。"}],"6837":[{"rank":"5","note":"追究クエスト<br/>発見物カード:480","exp":"960","type":"美術品","name":"レウキッポスの娘たちの略奪","desc":"ギリシャ神話の一幕を題材とし、17世紀初頭に描かれた油彩画。フランドルの画家ルーベンスの作。「オレイテュイアを略奪するボレアス」の後に描かれた。ルネサンス期の絵画から学んだ、多くの技巧が凝らされているバロック絵画の傑作。"}],"3649":[{"rank":"5","note":"ユニコーンの角","exp":"1010","type":"海洋生物","name":"イッカククジラ","desc":"北極海に生息するクジラの一種。雄のほとんどが、長く伸びた一本の牙を持っているのが特徴。牙には螺旋状の溝が入っている。"}],"3304":[{"rank":"3","note":"モクレンに似た花木","exp":"500","type":"植物","name":"タイサンボク","desc":"北米の中南部を原産地とする花木。初夏に白い花を咲かせる。葉の表面は光沢がある緑色だが、裏は細かい毛に覆われており、茶色がかっている。"}],"6928":[{"rank":"5","note":"発見物カード:610","exp":"1220","type":"宗教遺物","name":"関聖帝君の像","desc":"中国の神像。三国時代の武将・関羽が「三国志演義」や民間伝承などにより神格化し、像が祀られるようになった。武運と財運の神として中国のみならず、東アジアで広く信仰を集め、多くの関帝廟が建てられたという。。"}],"450":[{"rank":"1","note":"教会の宗教画の地図","exp":"40","type":"美術品","name":"受胎告知（マルティーニ）","desc":"シモーネ・マルティーニ作の祭壇画。製作当時は複数の絵からなる大規模なものだったという。この時代の宗教画としては人物が表情豊かで、新しい時代の到来を思わせる。"}],"1069":[{"rank":"4","note":"殺戮の女神","exp":"624","type":"宗教遺物","name":"カーリー像","desc":"インド神話の女神の像である。三大神のシヴァの妻の一人である。黒い肌にドクロをつなげた首飾りを下げた姿で描かれる。殺戮と破壊をつかさどる女神である。"}],"6862":[{"rank":"2","note":"発見物カード:195","exp":"390","type":"天文","name":"ズベン・エス・カマリ","desc":"てんびん座のベータ星で、この星座の中では最も明るい3等星。\n青白い星であるが、肉眼では緑色に見える唯一の恒星として知\nられている。名はアラビア語で「北の爪」を意味し元々はさそ\nり座の爪にあたる部分であった名残りと言われている。"}],"5216":[{"rank":"2","note":"","exp":"","type":"宗教遺物","name":"十字架の首飾り","desc":"キリスト教でよく見られる十字架の首飾り。かつてこの地に逃れた人々が身につけていたものだと思われる。太陽の光が届かないこの地下都市で中の人々はなにを祈っていたのだろうか。"}],"6710":[{"rank":"5","note":"発見物カード:450","exp":"900","type":"天文","name":"プラエキプア","desc":"こじし座で最も明るい星。約4等星の暗い星で、小ライオンの尻に位置する。ラテン語で「主要なもの」を意味する名だが、今ではこの名称自体があまり使われなくなった。"}],"2000":[{"rank":"2","note":"笑いの画家","exp":"300","type":"美術品","name":"リュートを弾く道化師","desc":"フランス・ハルス作の単身人物画。ハルスは様々な人々の表情を描写した作品を数多く発表している。風俗画の主流であったカラヴァッジョ派の明暗法の影響は少なく、道化の表情を生き生きと描き出している。"}],"4975":[{"rank":"2","note":"クエスト「ヘラクレスの出生地」<br/>発見物カード:140","exp":"280","type":"史跡","name":"ティリンス遺跡","desc":"ペロポネソス半島の東部にあるミケナイ文明の遺跡。分厚く強固な城壁には大きな石材が使われており、ギリシャ神話のサイクルロプスが積んだともいわれている。またヘラクレスヘラクレスの出生地という逸言もある。"}],"4856":[{"rank":"2","note":"「明るい星の観測記録」<br/>発見物カード:105","exp":"210","type":"天文","name":"エラキス","desc":"ケフェウス座に含まれる赤い星。その輝きの美しさから、後世には「ガーネットスター」と呼ばれた。"}],"3688":[{"rank":"4","note":"世界の環","exp":"630","type":"歴史遺物","name":"ヘイムスクリングラ","desc":"古代ノルド語で「世界の輪」の意味。13世紀頃に編纂されたとされる、サガの一種。\nこのサガによると、アイスランドの各方角には守護者が存在しているという。"}],"6397":[{"rank":"5","note":"レガシー：砂漠に栄えた巨石文明","exp":"1950","type":"歴史遺物","name":"クフ王時代のパピルス","desc":"クフ王の時代の文書。世界最古のパピルスと考えられている。パピルスの茎を打ち伸ばした紙片に、ピラミッドの建造や使用された石の運搬に携わった労働者たちの日々の生活が書かれているらしい。"}],"5899":[{"rank":"5","note":"","exp":"1510","type":"史跡","name":"兵馬俑坑","desc":"巨大な陵墓。副葬品として、兵馬俑と呼ばれる将兵や馬などを象った人形が大量に埋められている。あまりに規模が大きいため、いまだ全容を把握する者は存在しない。"}],"1588":[{"rank":"3","note":"砂漠の東端","exp":"462","type":"地理","name":"レヴェーク岬","desc":"オーストラリアの北西にある岬。南部は砂漠化している。南南西に伸びる海岸線は100kmに及び、青い海と白銀の砂浜が美しい。"}],"1571":[{"rank":"2","note":"二本足で走るトカゲ","exp":"330","type":"小型生物","name":"エリマキトカゲ","desc":"オーストラリアに生息するトカゲ。体長は、長い尾を含めると1mにも達する。首を覆う襟が特徴で、敵に遭遇したときなどに広げ、口を大きく開けて威嚇する。そして、相手がひるんだ隙に二足走行で逃げる。"}],"2069":[{"rank":"3","note":"青く化粧した鳥","exp":"500","type":"鳥類","name":"カンムリシロムク","desc":"バリ島の北西部にのみ生息する。羽毛は白く翼と尾羽の先端部のみ黒い。目の周囲は化粧をしたように鮮やかな青色でとても美しい。木の洞の中に枯れ草や小枝で巣を作り生活をする。"}],"1328":[{"rank":"3","note":"クエスト「列島の東端」<br/>発見物カード:235","exp":"473","type":"地理","name":"ティモール島","desc":"小スンダ列島の中でも最東部に位置する島。雨が少なく、農業に向いている土地とは言い難い。\nしかし、高価な香料である白檀を産するようだ。"}],"5990":[{"rank":"4","note":"中央大西洋<br/>18世紀-3では発見できないため装備品必須<br/>×：16世紀・紀元前","exp":"710","type":"天文","name":"ティターニア","desc":"天王星の最も大きな衛星。妖精の女王であるティターニアの名を冠している。なお、この名は衛星の発見者の死後、その息子が付けたものである。"}],"5081":[{"rank":"1","note":"到達する","exp":"124","type":"港・集落","name":"セイラ","desc":"アラビア半島の対岸、アフリカ東北部側にある港町。アデン湾から紅海へ向かう途中に位置する。"}],"6673":[{"rank":"4","note":"発見物カード:355","exp":"710","type":"天文","name":"シェダル","desc":"カシオペア座で最も明るいオレンジ色の星。エチオピアの王妃カシオペヤの胸にあたり、アラビア語で「胸」を意味する。"}],"899":[{"rank":"1","note":"クエスト「熱帯の巨大な魚」<br/>発見物カード:40","exp":"80","type":"海洋生物","name":"ジンベエザメ","desc":"15mを超える大型のサメである。背中には独特の白斑がある。サメとはいっても、鋭い歯もなく泳ぎも遅くて、まったく害のない魚である。ほかの魚がついていることが多く、このサメがいると大漁が見こめるという。"}],"559":[{"rank":"2","note":"古代人の生活","exp":"290","type":"歴史遺物","name":"コート・ディジーの魚鱗彩文土器","desc":"「ぎょりんさいもんどき」。インダス川下流に広がる遺跡から出土する、魚鱗模様の彩文土器。インダス文明のさきがけとも言える。"}],"5253":[{"rank":"4","note":"クエスト「もう一人のケンタウロス 」<br/>発見物カード:315","exp":"630","type":"天文","name":"ケンタウルス座","desc":"エリュマントスの猪の生け捕りに赴いたヘラクレスと知り合い、歓待したポロスというケンタウロスが天に上った姿とされる星座。古代ギリシャから存在する星座だが、歳差運動で地軸の向きが変わり現在のギリシャで見ることは困難である"}],"93":[{"rank":"2","note":"エジプト最後の王朝","exp":"280","type":"歴史遺物","name":"プトレマイオス1世の王錫","desc":"プトレマイオス1世はアレクサンドロス大王の側近であった。大王亡き後エジプトのファラオとなり、ムセイオンを建設して学術の発展に大きく貢献した。"}],"2794":[{"rank":"2","note":"ダンジョン","exp":"370","type":"財宝","name":"百済王の冠飾り","desc":"百済の遺跡で発見された、冠を飾るためのもの。百済王が使用していたものと思われる。金で作られており、とても豪華だ。"}],"5354":[{"rank":"4","note":"クエスト「インドの鳥の星座」<br/>発見物カード:330","exp":"660","type":"天文","name":"くじゃく座","desc":"天の南極近くにある星座。２等星のピーコック以外は暗い星が多いが、形が整っていて見つけやすい。"}],"856":[{"rank":"5","note":"哲学者と悪妻","exp":"1040","type":"歴史遺物","name":"ソクラテスの盃","desc":"ソクラテスが獄中で毒ニンジンをあおって自殺したときの盃。ソクラテスは古代ギリシャ最大の哲学者で、弟子にプラトンがいる。"}],"2670":[{"rank":"3","note":"朝鮮王朝初期の調査","exp":"490","type":"歴史遺物","name":"鄭道伝の辞世の句","desc":"鄭道伝は、高麗末期朝鮮王朝初期の学者であり、政治家。李成桂に重用された。\n鄭道伝は遼東出兵を計画した矢先、政敵に暗殺されてしまう。その際にこの詩が詠まれたという。"}],"6599":[{"rank":"5","note":"レガシー伝説の王都バビロン　中央","exp":"4000","type":"史跡","name":"在りし日のバビロンの空中庭園","desc":"新バビロニア王国の王ネブカドネザル2世が技術の粋を集めて作ったとされる建造物。階段状に何層にも連なった庭園は、その様から空中庭園と呼ばれ、王妃の緑豊かな故郷を懐かしむ心を癒すために建造したともいわれている。"}],"1598":[{"rank":"4","note":"未知の生物の像","exp":"744","type":"歴史遺物","name":"未知の生物の像","desc":"不思議な生き物をかたどった像。これが出土した地域の人も、ヨーロッパ人も、このような姿をした生き物は見たことがないという。すでに死に絶えてしまった生き物をかたどっているのだろうか？"}],"5298":[{"rank":"4","note":"","exp":"740","type":"小型生物","name":"サハラツノクサリヘビ","desc":"サハラに棲む毒へビ。目の上にある2本の角状の突起が特徴。突起がないものもいる。背には斑紋があり、砂の中に隠れて獲物を待ち伏せする。斜めに進む独特の動きで砂地を素早く移動できる。"}],"2490":[{"rank":"2","note":"風景画の地図","exp":"250","type":"美術品","name":"雪舟の風景画","desc":"室町時代の禅僧・雪舟が描いた水墨画。\n見事な景観が、力強く自由な筆致で、開放感たっぷりに表現されている。"}],"5131":[{"rank":"2","note":"到達する","exp":"269","type":"港・集落","name":"ブエノスアイレス","desc":"街名は「良い空気」の意味。南米東岸、広大で肥沃な平原の広がるラプラタ川河口に位置する街。四季を持つ。ウィチ人が暮らしている。"}],"1952":[{"rank":"1","note":"袋状の植物の地図","exp":"140","type":"植物","name":"トパトパ","desc":"細長い茎先に、小さな巾着状の花が２つついている植物。南米大陸のパタゴニアに生息。"}],"1595":[{"rank":"2","note":"実在する楽園","exp":"280","type":"地理","name":"サンゴ海","desc":"オーストラリアの東岸に位置する海域で、サンゴが発達し、非常に美しい海である。数えられないほど無数の島が存在し、ウミガメや渡り鳥の繁殖地にもなっている。"}],"5103":[{"rank":"1","note":"到達する","exp":"15","type":"港・集落","name":"ドーバー","desc":"ブリテン島南東に位置する街。ドーバー海峡に面している。フランスとの争いの最前線でヴァイキングの時代に防衛のための城が築かれた。"}],"1252":[{"rank":"2","note":"面白い特技","exp":"210","type":"中型生物","name":"ヤブイヌ","desc":"平べったい顔に小さい耳、長い胴と短い肢を持つ。ずんぐりとした体型が愛らしい。前に走るのと同じ速さで、後ろ向きに走れる。泳ぎや潜水も得意。"}],"2713":[{"rank":"2","note":"赤と黒の虫の地図","exp":"210","type":"虫類","name":"モンクロベニカミキリ","desc":"朝鮮半島及び、日本を含む東アジア圏に分布する、派手な外見のカミキリムシ。\n黒の模様で染められた赤い羽が目立つ。"}],"2958":[{"rank":"1","note":"金の鎖","exp":"200","type":"植物","name":"キングサリ","desc":"ヨーロッパ南部原産の植物。初夏にチョウのような形の黄色い花を房状に咲かせる。\n全体に毒があるため、注意が必要である。"}],"2267":[{"rank":"5","note":"積み石の都","exp":"930","type":"宗教建築","name":"ナンマドール遺跡","desc":"ポンペイ島に存在する謎の建築物。人力では運べそうにない巨大な石が積み上げられ、城壁となっている。\n潮が満ちていないと訪れることができないため「海上都市」とも呼ばれている。"}],"1134":[{"rank":"2","note":"教会の宗教画の地図","exp":"245","type":"美術品","name":"受胎告知（ダ・ヴィンチ）","desc":"レオナルド・ダ・ヴィンチ作の絵画。遠近法で描かれているが、マリアの右手など部分的に狂っている箇所もある。意図的だろうか。地面の花々は丁寧に描かれ、天使の翼は鳥のそれを解剖学的に研究したものである。"}],"5128":[{"rank":"1","note":"到達する","exp":"38","type":"港・集落","name":"フィレンツェ","desc":"製造業と交易、金融業により発展した街。金融業で有名になったメディチ家をはじめ、多くの商人と職人が集いその結びつきを強くしている。古代ローマ時代、フロレンティアと名づけられたことから現在の街名となったといわれている。"}],"4974":[{"rank":"4","note":"","exp":"740","type":"美術品","name":"テセウスとミノタウロスの像","desc":"ギリシャ神話に登場する英雄テセウスがミノタウロスと戦う様を表した像。テセウスはアテネの危機を救うためクレタ島のクノッソス宮殿にある迷宮ラビュリントスに向かい、ミノタウロスを討伐したという。"}],"6037":[{"rank":"5","note":"","exp":"1340","type":"美術品","name":"初花肩衝","desc":"天下三大名物とされる茶入。歴代の天下人が持っていたとされ、その価値は計り知れない"}],"466":[{"rank":"5","note":"軍神対軍神","exp":"988","type":"歴史遺物","name":"スキピオの兜","desc":"カルタゴの将軍ハンニバルと戦った、大スキピオの兜。大スキピオはハンニバルに奪われた領土を奪還し、ザマの戦いでハンニバルを完全に打ち破った。"}],"921":[{"rank":"2","note":"緋色のハンター","exp":"265","type":"鳥類","name":"アカトビ","desc":"うろこのように見える羽の重なりが美しく、群をなして低空を飛行する。翼を部分的に曲げて、尾を船の舵のように使って常に傾斜姿勢で飛びながら獲物を探す。"}],"1519":[{"rank":"4","note":"不思議な奏法","exp":"636","type":"財宝","name":"ディジュリドゥ","desc":"オーストラリア先住民が儀式の際に演奏する木笛。「イダキ」「マゴ」など地方によって呼び方が違う。シロアリによって中を食い開けられた、特定のユーカリを使う。筒の端に唇を当てて唇の振動で音を出す。"}],"3164":[{"rank":"4","note":"クエスト「山の意味」<br/>発見物カード:335","exp":"670","type":"地理","name":"モナドノック","desc":"北米にある平坦な山。「モナドノック」とは平坦な山を意味する、北米の先住民の言葉に由来しているという。"}],"1881":[{"rank":"5","note":"ラパ・ヌイの鳥人","exp":"1079","type":"宗教遺物","name":"鳥人の絵","desc":"ラパ・ヌイでは、マケマケという神の化身である鳥人（タンガタ・マヌ）信仰がある。\n鳥人は非常に強い霊力を持つとされ、儀式により鳥人の称号を得た者は、その一年間、島の全権を握ることができる。"}],"3652":[{"rank":"2","note":"書きかけの地図","exp":"360","type":"地理","name":"チュクチ半島","desc":"ベーリング海峡に接する半島。極寒の土地だが、氷の大地の下に豊富な資源が眠っているのか、人が生活していた形跡がある。"}],"61":[{"rank":"2","note":"インドの古代叙事詩","exp":"230","type":"財宝","name":"マハーバーラタ","desc":"インド最古の書物の一つである。十万の詩からなる、大規模な叙事詩。バーラタ人の戦争を語ったもので、神や神の子、仙人が登場して活躍する。"}],"2048":[{"rank":"2","note":"［勅命］[[運河開通への記録","exp":"310","type":"歴史遺物","name":"メルエンプタハ碑文","desc":"古代エジプトのファラオ、メルエンプタハ王の時代に残されたと思われる碑文。\n損傷が激しく読み辛いが、「シェケン運河」や「エティ運河」と読める部分がある。"}],"6875":[{"rank":"4","note":"発見物カード:350","exp":"700","type":"大型生物","name":"ジャワサイ","desc":"東南アジアやインドの密林に生息する、サイの一種。他のサイと比べて小柄で。皮膚がたるんで重なっており鎧のように見える。オスと比べて、メスは角が発達しにくい。"}],"6519":[{"rank":"5","note":"","exp":"1000","type":"植物","name":"ヒスイカズラ","desc":"ルソン島に自生するツル植物。ひすいのような美しい青緑色の花を咲かせる。上向きの爪のような形の花が多数付いている。ひすい色の花は他に類を見ないという。ごく限られた地域ににのみ自生しているらしい。"}],"5229":[{"rank":"3","note":"","exp":"470","type":"財宝","name":"アルマゲスト","desc":"２世紀後半にアレクサンドリアのクラウディオ・プトレマイオスが著した数学と天文学に関する専門書。古代ギリシャで発達した数学や天文学を知る上で欠かせない存在である。"}],"2365":[{"rank":"1","note":"額縁がある花の地図","exp":"110","type":"植物","name":"ガクアジサイ","desc":"小さな花が密集して咲く、日本原産の植物。土壌や開花からの日数によって、花の色が変化する。\n大きな装飾花が中央の小さな花々を囲んでおり、額に入った絵画を思わせる。"}],"6725":[{"rank":"5","note":"","exp":"550","type":"宗教建築","name":"ジェンネの大モスク","desc":"ニジェール川沿いの交易都市ジェンネに建つ大きなモスク。川を流れてきた泥をこねて日干しレンガを作り、それらを積んだ表面にさらに泥を塗って完成させた。屋内にも泥で作られた、畳1畳ほどの太さの柱が100本程度存在する。"}],"5829":[{"rank":"5","note":"","exp":"1470","type":"財宝","name":"ギガス写本","desc":"ラテン語で書かれた聖書の写本。確認されている限り世界最大の写本であり、悪魔が製作に手を貸したとの噂もある。"}],"6391":[{"rank":"2","note":"","exp":"290","type":"宗教建築","name":"懸空寺","desc":"中国の北東部の断崖に建造された木造寺院。かつては「玄空閣」とも呼ばれていた。中には仏教、儒教、道教の開祖の像三体が並べられている。この地を訪れた詩人の李白は、岩に「壮観」の文字を残したという。"}],"688":[{"rank":"2","note":"真の最南端","exp":"230","type":"地理","name":"アガラス岬","desc":"アフリカ最南端の岬。喜望峰はここから数十km北西にある。本来なら、こちらを喜望峰とするべきではないか？"}],"6035":[{"rank":"1","note":"","exp":"140","type":"植物","name":"クチナシ","desc":"日本、中国、台湾、インドシナ半島などに分布する植物。主に\n森林に群生し、初夏から夏にかけて強い芳香を放つ白い花を咲かせるのが特徴。果実は漢方薬に使われるほか、食材や染料としても用いられる。"}],"6408":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"ペルシャのスフィンクス","desc":"古代ペルシャのスフィンクス像。人の顔、鷲の翼、獅子の体を持つという。エジプトのものとは異なり有翼である。ハリカルナッソスにもこのスフィンクス像がおかれていたのだろうか。"}],"5285":[{"rank":"3","note":"","exp":"550","type":"大型生物","name":"アダックス","desc":"コルク抜きのような形状の角が特徴の動物。砂漠の気候に適応しており、強烈な日差しに耐えられる分厚い皮膚や、砂に埋まりにくい幅広の蹄を有する。また、水を飲まずに一カ月以上、生き延びられる。"}],"5402":[{"rank":"4","note":"発見物カード:330<br/>　","exp":"660","type":"天文","name":"カノープス","desc":"おおいぬ座のシリウスに次ぎ、全天で2番目に明るい星。白い星だが、北半球では南天の低い位置にあるため赤い色に見え、「南極老人星」と呼ばれる。"}],"2086":[{"rank":"5","note":"彼女が見つめる山","exp":"820","type":"地理","name":"ネバド・パリアカカ","desc":"アンデス山脈に連なる山。水の神パリアカカが姿を変えたといわれるだけあって、山頂には雪が積もっている。この山で採れた氷は、リマにも運ばれているらしい。"}],"2978":[{"rank":"5","note":"畏怖と勇壮の大翼<br/><br/>発見時経験値1210　発見物カード経験値605","exp":"1210","type":"鳥類","name":"ハクトウワシ","desc":"新大陸に生息する大型のワシ。広げると成人男性の背丈ほどにもなる立派な翼を持つ。\n濃茶色の羽毛とは対照に頭部が白いことが特徴。新大陸の先住民はこのワシを聖なる鳥として敬い、衣服や飾りにその羽を付けるなどして親しんでいる。"}],"550":[{"rank":"2","note":"クエスト「古代メソポタミアの都市」<br/>発見物カード165","exp":"330","type":"史跡","name":"ウル","desc":"古代メソポタミアで、政治と経済の中心地だったと言われるシュメール人の都市。ウル・ナンム王が建造したという、ジッグラトと呼ばれる建造物が大きな特徴。"}],"3006":[{"rank":"4","note":"轟く雷鳴","exp":"750","type":"地理","name":"モシ・オ・トゥニャ","desc":"アフリカ大陸の南部に位置する大滝。\nモシ・オ・トゥニャとは現地の言葉で「雷鳴轟く水煙」という意味である。その名のとおりに、水量が増える雨季には雷鳴のような水音を轟々と響かせる。"}],"3941":[{"rank":"2","note":"クエスト「伝説の吟遊詩人」<br/>発見物カード:110","exp":"220","type":"天文","name":"こと座","desc":"ギリシャ神話に登場するオルフェウスの竪琴が空に上がった姿とされる星座。オルフェウスは竪琴の名手で、その旋律は嵐をも静めるほどだったという。"}],"526":[{"rank":"1","note":"古代の青銅具の地図","exp":"36","type":"歴史遺物","name":"青銅の武具","desc":"古代の青銅でできた武具。青銅は加工が容易なので古代文明でもよく用いられたが、柔らかいため武具には向かない。"}],"1350":[{"rank":"2","note":"空飛ぶヘビ","exp":"280","type":"小型生物","name":"トビヘビ","desc":"樹上性でトカゲやカエルなどを食べるヘビ。敵から逃れるときなど肋骨を広げて扁平な体にして、体をくねらせて滑空する。"}],"6432":[{"rank":"5","note":"レガシー　数の叡智・世界の計算機　中央","exp":"","type":"歴史遺物","name":"サラミスのアバカスタブレット","desc":"紀元前300年ごろの古代ギリシャで使用されていたという計算盤。現存する最古の線ソロバンとされる。テーブルくらいの大きさと厚みがある白い大理石の板で、表面に刻まれた線に沿って小石などの珠を置き、計算を行った。"}],"5994":[{"rank":"1","note":"地の果ての岬","exp":"20","type":"地理","name":"ランズエンド岬","desc":"ブリテン島南西端の岬である。意味は英語で「地の果て」。細長い岬で対岸が見えないため、このように呼ばれるのだろう。"}],"2717":[{"rank":"1","note":"山の魚の地図","exp":"130","type":"海洋生物","name":"ヤナギナマズ","desc":"朝鮮の渓流に生息する珍しいナマズ。\n地元では、山のナマズを意味する、「サンメギ」という名で呼ばれている。"}],"7010":[{"rank":"2","note":"","exp":"","type":"大型生物","name":"ガウルの幼体","desc":"ガウルの幼体は成体と異なり、前進が薄茶色の毛に覆われている。成長するにつれて毛の色は濃くなり、下肢に白い毛が現れ始める。"}],"1450":[{"rank":"5","note":"アリ食いの親玉","exp":"828","type":"大型生物","name":"オオアリクイ","desc":"歯を持たず、非常に長い舌と、大きく鋭い爪を使って、アリ塚に生息するアリを食べる。休憩のときには、ふさふさした大きな尾を保温のために使用する。"}],"5815":[{"rank":"4","note":"","exp":"620","type":"気象・現象","name":"ウィル・オ・ウィスプ","desc":"夜の湖畔や墓場などに現れるという怪光。色は青、緑など複数の報告がある。名前は、悪行を重ねて死んだ男の魂が現世をさまよっているという伝承に由来している。"}],"6753":[{"rank":"5","note":"追究クエスト<br/>発見物カード:780","exp":"1560","type":"海洋生物","name":"ブラックマンタ","desc":"メラニズム現象によって黒色素が溜まり、黒化したオニイトマキエイ。発生の原因などについては、未だ究明されないままである。各地で目撃が報告されているが、ニューカレドニア島の近くでは遭遇率が高いようだ。"}],"6656":[{"rank":"2","note":"","exp":"300","type":"小型生物","name":"キマダラチズガメ","desc":"ミシシッピ流域のパスカグーラ川に生息する亀。背甲にはトゲ状の突起があり、黄色や橙色のまだら模様が入っている。"}],"5872":[{"rank":"5","note":"","exp":"1430","type":"鳥類","name":"ナナイロフウキンチョウ","desc":"南米に生息する鳥。頭や腹、背中が鮮やかに色づき、その配色の美しさで知られる。大きさは十数cmほどで、肉食。他のフウキンチョウ類も雄は美しい配色のものが多い。"}],"6219":[{"rank":"1","note":"","exp":"200","type":"財宝","name":"北方民族文化誌","desc":"16世紀のスウェーデン人司教、オラウス・マグヌスが記した北欧文化地誌。北欧各地の生活文化・自然・伝承などの情報が記されている。全22巻で情報量も多く、挿絵として481点の木版画が添えられている。"}],"864":[{"rank":"4","note":"伝説の王","exp":"780","type":"歴史遺物","name":"ピトハナ王の冠","desc":"ピトハナ王は息子のアニッタ王と共に、ヒッタイトの伝説上の高祖である。神の力を借りて、諸都市を支配下に置いたとされる。"}],"6573":[{"rank":"5","note":"クエスト「古代ローマ皇帝の遺物の追加調査」","exp":"","type":"歴史遺物","name":"自省録","desc":"マルクス・アウレリウスは「五賢帝」のひとり。皇帝にして、偉大なストア派の哲学者であったことから「哲人君主」の名で呼ばれている。彼の哲学的な思索は、著書『自省録』に日記や散文の形でまとめられて、後世に伝わっている。"}],"6871":[{"rank":"5","note":"発見物カード:425","exp":"850","type":"美術品","name":"デューラーの自画像","desc":"神聖ローマ帝国の画家デューラーの作。数ある自画像のうちの一作で、デューラーが26歳の時のものとされる。画家の地位向上と、自身の着道楽を表した、豪奢な姿で描かれている。"}],"2728":[{"rank":"4","note":"焼け跡に見る歴史","exp":"650","type":"宗教建築","name":"仏国寺跡","desc":"新羅時代に建立されたといわれる仏教寺院の跡地。\n石垣で固めた盛土の上に、三区域に分かれた伽藍（がらん）が配置されていたらしい。\n朝鮮王朝四代王・世宗の時代に破壊されてしまったという。"}],"2903":[{"rank":"3","note":"美装された経箱","exp":"520","type":"宗教遺物","name":"鎗金経箱","desc":"読みは「そうきんきょうばこ」。仏教の経典を収めるための箱。鎗金とは、漆器の装飾技法の一つ。この箱には経典が説く極楽の世界が描かれている。"}],"5470":[{"rank":"1","note":"発見時経験値120　発見物カード経験値60","exp":"120","type":"鳥類","name":"ズグロハゲコウ","desc":"パンタナル湿原の象徴と呼ばれる鳥。\n全長1.2m、翼を広げると2mにも達する。\n頭部の黒い皮膚がむき出しになっていることから、ズグロハゲコウの呼び名がついたといわれている。"}],"5816":[{"rank":"2","note":"","exp":"220","type":"地理","name":"エルズミーア島","desc":"カナダの最北に位置する島。世界最北の山脈を擁し、フィヨルドや氷河がいくつも存在する。"}],"700":[{"rank":"1","note":"神秘的な燭台","exp":"100","type":"財宝","name":"白銀の燭台","desc":"銀は金属の中でも特に白く輝くものだが、この燭台はひときわ白く輝いている。銀に混ぜる金属の種類と割合に秘密があるというが、解明することはできないだろう…。"}],"5934":[{"rank":"1","note":"到達する","exp":"30","type":"港・集落","name":"サグレス","desc":"ポルトガルのとある王族が建設したと伝えられる村。イベリア半島の先端に位置し、外洋を航行する船団を見守る地であると同時に、他国との紛争における重要な要塞の役目も果たすという。"}],"1535":[{"rank":"1","note":"古代の土器の地図","exp":"110","type":"歴史遺物","name":"彩文水がめ","desc":"インドシナ半島の内陸には多くの焼き釜があり、古くから焼き物が盛んだったという。これは形がなめらかで芸術品として優れている上、日用品としての使いやすさにも優れている。"}],"1763":[{"rank":"1","note":"英雄の像の地図","exp":"140","type":"美術品","name":"ガッタメラータ将軍騎馬像","desc":"ガッタメラータとは12世紀後半から13世紀前半にかけて活躍した傭兵隊長である。ヴィスコンティ家との戦いでヴェネツィアを勝利に導くなど数々の軍功を上げた。この青銅像はその功績を讃え、ドナテッロによって作成されたものである。"}],"6808":[{"rank":"2","note":"発見物カード:175","exp":"","type":"海洋生物","name":"オオイカリナマコ","desc":"ナマコの一種。珊瑚礁の浅い海底に見られ、その細長い形状から蛇と間違われることがある。水を吸うと体長が伸び、3mを越えるという。先端には十数本の触手が生え、見た目を不気味に感じる者も少なくない。"}],"5097":[{"rank":"2","note":"到達する","exp":"280","type":"港・集落","name":"トゥンベス","desc":"フランシスコ・ピサロがインカ帝国へ向かおうとした時に立ち寄った街。甲冑に身を包み陽の光を受けて輝くピサロの姿を見て、現地の人々は彼を神聖な者と考え、歓迎したという。"}],"2487":[{"rank":"2","note":"集落の痕跡","exp":"310","type":"財宝","name":"瑠璃珠の首飾り","desc":"台湾島先住民の一部に家宝として代々伝えられていた首飾り。\n瑠璃珠には神聖な力が宿ると信じられ、病気治療の儀式にも使用される。"}],"3911":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:155","exp":"310","type":"天文","name":"オリオン座の馬の頭のような星雲","desc":"オリオン座の三ツ星の東端の星からやや南にある星雲。明るい雲の手前に馬の頭のような形の黒い雲が見える。"}],"771":[{"rank":"1","note":"先史時代の史跡の地図","exp":"15","type":"歴史遺物","name":"石器","desc":"石を削って作った、先史時代の道具類。木の棒にしばりつけて槍にしたり、そのまま手に持って包丁やナイフのように使ったりしたと考えられる。"}],"6485":[{"rank":"5","note":"追究クエスト","exp":"","type":"財宝","name":"翼型のグースリ","desc":"ロシアの伝統的な弦楽器。グースリは時代を経るごとに形状や弦の数に改良が加えられ仕様されたといわれる。きっとこの翼型のグースリもロシアの吟遊詩人たちとともに伝統を次の世代へ繋いでいくのだろう。"}],"5431":[{"rank":"1","note":"大西洋の真ん中","exp":"90","type":"地理","name":"アゾレス諸島","desc":"イベリア半島南西端から西に1300kmほどに位置する諸島。これまでの航海技術では大陸を離れた航海が困難だったため、存在が認識されていなかった。年間を通して温暖なので、耕作に向いていると思われる。"}],"5624":[{"rank":"3","note":"秘境に立つ塔","exp":"","type":"史跡","name":"スヴァネティの塔","desc":"コーカサス山脈の谷間にある、スヴァネティ地方の村々で見られる不思議な塔。建てられた年代によって、形状が少しずつ異なる。"}],"446":[{"rank":"4","note":"クエスト「恐ろしい顔のサル」<br/>発見物カード:300","exp":"612","type":"中型生物","name":"マンドリル","desc":"1m近い大きさのサル。20頭ほどの群れで生活しているようだ。雌雄で見た目がかなり異なり、オスはとても派手な顔をしている。この顔と大きな声のためか地元では恐れられているようだ。"}],"204":[{"rank":"1","note":"タペストリーの地図","exp":"64","type":"財宝","name":"金糸を使ったタペストリー","desc":"壁に掛ける豪華な布。金糸を使い、織り目はとても詰んでいる。まるで絵画のようだ。"}],"5629":[{"rank":"2","note":"クエスト「科学の星座」<br/>発見物カード:175","exp":"350","type":"天文","name":"けんびきょう座","desc":"ラカーユが制定した南天の星座のひとつ。科学実験などに使われる顕微鏡の形を表している。"}],"5755":[{"rank":"5","note":"2017.02.07新規追加","exp":"1370","type":"地理","name":"ハロン湾","desc":"多数の小島が浮かび、美しい景観を備えた大きな湾。漢字で書くと「下竜湾」であり、竜が造ったという伝説がある。"}],"5699":[{"rank":"2","note":"2017.02.07新規追加","exp":"340","type":"地理","name":"ヒマラヤ山脈","desc":"雪が住まいし地、という意味の名前を持つ山脈。世界有数の山脈の一つで非常に高い峰々と豊かな水源を持つ。巨大な山々は長きにわたって人々の移動を妨げてきたため、この山脈がなければ、周辺地域の歴史は大きく変わっていただろう。"}],"1964":[{"rank":"3","note":"新大陸の祭事笛","exp":"480","type":"財宝","name":"ケーナ","desc":"竹やアシ、動物の骨など様々な材料で作られる縦笛。インカにおいて儀式に音楽は欠かせず、楽器は祭具としての側面も強い。構造は単純だが演奏は非常に難しい。"}],"644":[{"rank":"1","note":"書きかけの地図","exp":"110","type":"地理","name":"キプロス","desc":"地中海の東部に浮かぶ巨大な島。キプロスはギリシャ語で、トルコ語ではクブルスというそうだ。先史時代から文明が栄え、地理的な理由からさまざまな勢力に支配された。"}],"6424":[{"rank":"5","note":"","exp":"","type":"化石","name":"凍り付いた幼いマンモス","desc":"幼いマンモスが凍り付いた姿。成体と比べて体はかなり小さく、特徴的な長い体毛や大きな牙が生えそろう前に凍り付いた個体のようだ。いつからこの地に眠っていたのかは分からない。"}],"1951":[{"rank":"5","note":"大輪の花","exp":"1170","type":"植物","name":"スマトラオオコンニャク","desc":"人の背丈をゆうに越え地上3m、直径1.5mまでに成長する巨大な花。生息地は、スマトラ島やインドネシアなどの熱帯雨林。花は数年に一度、数日だけ咲く。また、花の異臭から別名「死体の花」とも呼ばれている。"}],"1498":[{"rank":"1","note":"奇妙な模様のチョウの地図","exp":"130","type":"虫類","name":"ウズマキタテハ","desc":"羽の裏面には、数字のような渦巻状の模様が入っている。色は、赤や水色など、まちまちである。"}],"6174":[{"rank":"4","note":"","exp":"650","type":"鳥類","name":"ワタリガラス","desc":"「レイヴン」とも呼ばれ、 通常のカラスよりひと回り大きい。約聖書や北歐神話にも登場するほかロンドンでも飼育されており、「ロンドン塔からワタリガラスがいなくなるとイングランドは滅びる」と言い伝えられているそうだ。"}],"2383":[{"rank":"3","note":"極東の青い鳥","exp":"440","type":"鳥類","name":"ルリカケス","desc":"日本南方の小島に生息する、色鮮やかなカラス。瑠璃色の翼、白いくちばし、赤褐色の胴体が特徴。\n美しい外見に反して、鳴き声はしわがれており、うるさい。"}],"1699":[{"rank":"5","note":"バビロン捕囚","exp":"949","type":"歴史遺物","name":"ゼルバベルの粘土板","desc":"楔形文字で書かれた粘土板。石板ではないので長期保存用に書かれたものではないと思われる。粘土板には、ユダ王国の王族でイェルサレム神殿の再建を指揮したゼルバベル王の名前が見られる。"}],"2795":[{"rank":"5","note":"華北の建造物調査","exp":"1190","type":"史跡","name":"万里の長城","desc":"全長6000km以上にも及ぶ堅固な大城壁。\n秦の始皇帝が、国の北側に建造された城壁をつなぎ合わせて造ったのが始まりである。"}],"193":[{"rank":"3","note":"ダ・ヴィンチの祭壇画","exp":"440","type":"美術品","name":"岩窟の聖母（祭壇画）","desc":"読みは「がんくつのせいぼ」。レオナルド・ダ・ヴィンチ作の絵画である。ミラノの聖堂の依頼で描かれた絵画が報酬で折り合わず、複製であれば安くてよいということで描かれたものである。この絵の製作には弟子の手も入っているそうだ。"}],"6912":[{"rank":"5","note":"","exp":"","type":"美術品","name":"清明上河図","desc":"せいめいじょうがず。北宋の宮廷画家である張択端が12世紀に描いた風俗画。長さ5mを越える画巻には、清明節で賑わう都の光景が描かれている。精緻な筆致から、当時の人々の活気に満ちた豊かな生活が窺える。"}],"2959":[{"rank":"1","note":"書きかけの地図","exp":"110","type":"地理","name":"ナンタケット島","desc":"北米の沖合いに浮かぶ小さな島。一年を通して気温が低く、冬は雪が積もる。周辺の海域ではクジラの目撃情報が多い。"}],"2087":[{"rank":"5","note":"クエスト「畑の女神盗難事件」<br/>発見物カード:530","exp":"1060","type":"宗教遺物","name":"チョコ・カリャ像","desc":"アンデス神話に登場する、畑と水路の女神。水の神パリアカカの妻であるチョゲ・スソが神格化したものと思われる。"}],"1487":[{"rank":"1","note":"白いチョウの地図","exp":"80","type":"虫類","name":"コロリンデシロチョウ","desc":"鮮やかな黄色が差した前羽が美しい。また、白い羽には、黄色で縁取られた黒い斑点が一つずつある。"}],"1193":[{"rank":"4","note":"アマゾン川に潜むもの","exp":"624","type":"大型生物","name":"カイマン","desc":"カイマンとは現地の言葉で「ワニ」を指す。主に淡水に生息する。両眼の間に盛り上がる筋があり、眼鏡をかけているように見える。水中で獲物を巧みに追い込む狩りをする。"}],"6494":[{"rank":"5","note":"レガシー女神信仰の地エフェソス　左上","exp":"2805","type":"宗教建築","name":"聖母晩年の家","desc":"聖母マリアが晩年を過ごしたという石壁の小さな家。アナトリア半島西部のエフェソスにある。老境のマリアを使徒の一人が世話をしていたとも伝わる。のちにエフェソスは公会議が開かれるなどキリスト教が盛んな土地となった。"}],"5302":[{"rank":"2","note":"発見時経験値230　発見物カード経験値115","exp":"230","type":"鳥類","name":"ホオカザリヅル","desc":"アフリカ南部の湿原に生息するツル。頭が白く、体は暗い色の羽毛で覆われる。顔は特徴的に、頬の下部からトカゲ状の肉が垂れている。また、くちばしの付け根から顔にかけては羽毛がなく、赤い地肌が露出している。"}],"1676":[{"rank":"5","note":"クペの木槍","exp":"1040","type":"歴史遺物","name":"クペの木槍","desc":"クペの名を冠した、木の槍。クペとは、ハワイキよりアオテアロアに移住してきたといわれる、マオリの祖先である。クペがアオテアロアを発見してから、多くのハワイキの民が移住してきた。"}],"5545":[{"rank":"2","note":"","exp":"220","type":"海洋生物","name":"フレームエンゼルフィッシュ","desc":"太平洋の中部や西部に生息する魚。岩礁やサンゴ礁に住む。体は鮮やかで濃いオレンジ色をしており、黒い縦縞が入っている。"}],"2604":[{"rank":"3","note":"船乗りたちを見守る像","exp":"500","type":"宗教遺物","name":"媽祖像","desc":"読みは「まそぞう」。道教の女神像で、航海や漁業の守護神として信仰を集めている。\n大陸からの移民が台湾島に到着した際も、媽祖に感謝したといい、広く信奉されている。"}],"2886":[{"rank":"2","note":"奇妙な石の地図","exp":"330","type":"化石","name":"カメのような動物の石","desc":"黄河の南で発見されたカメと思われる生物の石。頭と思われる部分は見当たらないが、欠けてしまったのだろうか？"}],"1915":[{"rank":"2","note":"他の神を知らず","exp":"","type":"史跡","name":"アマルナの遺跡","desc":"古代エジプトのフォラオ、アメンホテプ4世の造営した都。彼の死後すぐにテーベへの遷都が行われ、まもなく住民がいなくなったという。古い言葉で「アテン神の地平」を意味する「アケトアテン」とも呼ばれる。"}],"1914":[{"rank":"3","note":"古代文字の地図","exp":"506","type":"歴史遺物","name":"コハウ・ロンゴロンゴ","desc":"ラパ・ヌイ独自の文字であるロンゴロンゴ文字を書きつけた板。名は「物言う木」という意味である。ラパ・ヌイ島民でも特殊な職業の者でないと読むことができず、解読できる者も年々減っているそうだ。"}],"1216":[{"rank":"5","note":"空の支配者<br/><br/>発見時経験値1131　発見物カード経験値565","exp":"1131","type":"鳥類","name":"オウギワシ","desc":"頭にある黒い扇形の冠羽が特徴のワシ。熱帯林の中を高速で飛び回り、力強い脚と大きな爪でサルなどの中型の動物、さらには大型の鳥をも捕食する。"}],"1183":[{"rank":"2","note":"望郷の念を抱きつづけて<br/><br/>発見時経験値260　発見物カード経験値130","exp":"260","type":"財宝","name":"アギラールの聖書","desc":"コルテスより以前にメソアメリカの地に上陸してきたイスパニア人聖職者。現地人によりとらわれの身となる。その際身に付けたマヤ語を用いてコルテスの通訳として活躍する。この聖書はとらわれている間ずっと腰につけていたというもの。"}],"2845":[{"rank":"5","note":"読めない手紙","exp":"820","type":"財宝","name":"関帝詩竹","desc":"三国時代の英傑・関羽が、君主である劉備に自身の忠誠心を伝えるために書いた詩。\n竹の絵で文面を隠すことで、他者に内容を気付かれることを防いだという。"}],"5028":[{"rank":"1","note":"到達する","exp":"39","type":"港・集落","name":"オスロ","desc":"11世紀中ごろ、ヴァイキングの王・ハーラルにより建設された街。オスロとは、ノルド語で「神の牧場」という意味である。酪農、林業、水産業が盛ん。"}],"3647":[{"rank":"4","note":"スラブの太陽神","exp":"650","type":"宗教遺物","name":"ダジボーグのレリーフ","desc":"スラブ神話に登場する太陽神の像。「イーゴリ遠征物語」内では、ロシア側の人々はダジボーグの孫とされた。"}],"1607":[{"rank":"5","note":"精霊と人々の風景","exp":"936","type":"宗教遺物","name":"古代の岩絵","desc":"アボリジニたちが住んでいる洞窟などに描かれている岩絵。アボリジニが、この地に住み始めたはるか太古の時代から書き綴られている。アボリジニ独特の世界観、「ドリーミング」を伝える手段なのだという。"}],"1514":[{"rank":"4","note":"宝生如来像","exp":"720","type":"宗教遺物","name":"宝生如来","desc":"ほうしょうにょらい。仏教における如来のひとり。全てのものに価値があり、その存在は平等であると説く。"}],"3191":[{"rank":"5","note":"悪夢を醒ます夢","exp":"1270","type":"史跡","name":"ランス・オ・メドー","desc":"新大陸北部、テラ・ノヴァにある史跡。北欧のヴァイキングが移住した場所と考えられている。いくつかの建物が良い状態で残っておりこれらは作業場として使われたと考えられている。"}],"3298":[{"rank":"4","note":"研究員への助力","exp":"610","type":"地理","name":"メサ","desc":"テーブルのような形状の台地。北米の西部に多い。柔らかい地層の上に、水平な硬い地層がある場合、下部の柔らかい地層のみが浸食されて、テーブル状になったとみられる。"}],"5856":[{"rank":"5","note":"","exp":"1430","type":"鳥類","name":"ガマグチヨタカ","desc":"東南アジアを中心に広域に生息する鳥。大きく平たいくちばしが特徴で、口を開いた姿が日本の「がまぐち」に似ていることからこの名で呼ばれている。"}],"1550":[{"rank":"1","note":"書きかけの地図","exp":"140","type":"地理","name":"グルートアイランド島","desc":"オーストラリアの北部にある島。オランダ語で「大きな島」を意味する。その名の通り、カーペンタリア湾に浮かぶ島の中で最大のものである。"}],"3923":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:110","exp":"220","type":"天文","name":"アンドロメダ座の渦巻星雲","desc":"アンドロメダ座にある渦巻きのような形をした星雲。アンドロメダの腰の右側に当たる位置にあり、肉眼でも見られる。"}],"477":[{"rank":"3","note":"見てはいけないもの","exp":"506","type":"宗教遺物","name":"カッパドキアの壁画","desc":"カッパドキアの内部のいたるところに見られる壁画。長い年月に渡って次々に描かれたため、いろいろなタイプのものがある。"}],"7020":[{"rank":"5","note":"","exp":"","type":"小型生物","name":"セイブシシバナヘビ","desc":"小型のヘビ。北米大陸の内陸部に分布し、乾燥した草原や砂漠に生息している。ブタに似た上向きの鼻が特徴。身体は黄褐色で、黒い斑点模様が入っている。牙から分泌される微毒性の唾液で、獲物を痺れさせる。"}],"1233":[{"rank":"2","note":"危険への対処","exp":"380","type":"大型生物","name":"バク","desc":"頭から肩にかけて生えるたてがみが特徴。泳ぎが得意で、襲われると水中へ逃げ込む。木の葉や果実、水草などを食べる。"}],"3306":[{"rank":"2","note":"農夫の娘の親孝行","exp":"340","type":"植物","name":"シロツメクサ","desc":"ヨーロッパを原産地とする植物。春から秋にかけて白い花を咲かせる。痩せた土地でもよく育つ上に、根付いた土地の地味を豊かにする働きを持つ。"}],"2614":[{"rank":"5","note":"鄭成功についての調査　　発見場所：安平の酒場主人向かって右横辺り","exp":"1040","type":"財宝","name":"台南の地図","desc":"読みは「タイナンのちず」。ネーデルラント軍が占領していた港や道路を示した台南の地図。鄭芝龍の部下だった何斌が鄭成功に献上した。台湾島へ安全に上陸するために、大きく役立った。"}],"1197":[{"rank":"1","note":"偽りの真実","exp":"1","type":"財宝","name":"謎の石板","desc":"「ひすいの仮面はいただいたぜ。あんたへの恨み、これでたっぷり晴らさせてもらった。あんたは最高の冒険者だよ。\n　　シュレッテンワルダー」\n石板はヨーロッパ風で新しいものである。"}],"5051":[{"rank":"1","note":"到達する","exp":"74","type":"港・集落","name":"ケープ","desc":"アフリカ南部、喜望峰近辺に作られた街。近辺は暴風域で、危険である。鉱山に恵まれた地帯で、銅や鉄のほかに金、ダイヤモンドが産出する。"}],"1904":[{"rank":"2","note":"聖なる亜麻布","exp":"230","type":"宗教遺物","name":"聖骸布","desc":"キリストの遺体を包んだとされる亜麻布。布にははっきりと傷ついた男性の姿が見て取れる。驚くべきことに、この傷が聖書にあるキリストの受難とぴたりと符号している。"}],"4950":[{"rank":"1","note":"","exp":"140","type":"地理","name":"オリンポス山","desc":"サロニカの南西にあるギリシャ最高峰の山。山麓と海が近く、ヨーロッパの中で最も比高のある山でもある。ギリシャ神話では、オリンポス十二神と呼ばれる神々が住まう山とされている。"}],"2346":[{"rank":"3","note":"不思議な場所の調査","exp":"460","type":"宗教遺物","name":"岩戸の注連縄","desc":"読みは「いわとのしめなわ」。注連縄とは、わら製の縄に紙垂を付けたもの。魔除けや神が降りる場である拠り代として使われる。\n日本神話では天照大神が岩戸から引き出された際、二度と中へ入らぬよう注連縄で岩戸の入口を塞いだという。"}],"3664":[{"rank":"5","note":"ダンジョン","exp":"966","type":"宗教遺物","name":"クヌム像","desc":"古代エジプトで信仰されていた羊頭の創造神の像。ナイル川を司る神でもあり、クフ王の名はこの神に由来するといわれる。"}],"301":[{"rank":"5","note":"メソポタミア文明への探求","exp":"949","type":"歴史遺物","name":"ハンムラビ法典","desc":"古代バビロンのハンムラビ王が発布した、成文法典。\n「目には目を」とあるが、これは公正な処罰を与えるという意味である。"}],"1159":[{"rank":"2","note":"口論の原因","exp":"370","type":"鳥類","name":"チュウハシ","desc":"鮮やかな色の長いくちばしが特徴。森林の周縁部に生息し、小さな集団で食事をしたり、身を寄せ合って眠ったりする。"}],"1798":[{"rank":"1","note":"書きかけの地図","exp":"160","type":"地理","name":"ダリエン山脈","desc":"南米大陸北西岸から中米にかけて走る山脈。高温多湿であり、山間部は常に霧に覆われた密林が広がっている。密林は蘭の花だけでも1000種以上という多様性をもつなど、まさに動植物の楽園である。"}],"1694":[{"rank":"4","note":"森に棲むドラゴン","exp":"624","type":"大型生物","name":"ハナブトオオトカゲ","desc":"体長が4mを超える大型のトカゲ。体は細身だが体長が長く、尾が体の2/3を占める。\n樹上に棲み、かつ獰猛な性格から、生息地では森のワニと呼ばれている。"}],"924":[{"rank":"1","note":"美しいつぼの地図","exp":"34","type":"財宝","name":"アラバスターの花瓶","desc":"アラバスターを削りだして作った花瓶。アラバスターには透明感があるので、独特の美しさがある。"}],"5171":[{"rank":"2","note":"到達する","exp":"268","type":"港・集落","name":"リオデジャネイロ","desc":"16世紀初頭、探検家ガスパール・デ・レモスによって発見され、大きな湾を河口と間違えて「一月の川」を意味する「リオデジャネイロ」と名づけられた。"}],"492":[{"rank":"3","note":"古代エジプトの女王","exp":"484","type":"歴史遺物","name":"ハトシェプスト女王の胸飾り","desc":"トトメス2世の妻で、古代エジプト初の女性ファラオ・ハトシェプストの胸飾り。彼女はファラオでいる間、男装していたという。"}],"2721":[{"rank":"3","note":"紛れ込んだ魚","exp":"550","type":"海洋生物","name":"キコウライケツギョ","desc":"地元では「ファンソガリ」と呼ばれる魚。\n「ソガリ」とはコウライケツギョの意味らしい。本来、コウライケツギョは褐色の個体らしく、黄色の個体は珍しいとのこと。"}],"1505":[{"rank":"1","note":"手の長い動物の地図","exp":"75","type":"中型生物","name":"テナガザル","desc":"主に樹上で生活しているサル。長い手で枝をつかみ、体を振り子のように揺らして移動する。果物を食べる。"}],"1578":[{"rank":"4","note":"愛しき妻へ","exp":"624","type":"植物","name":"ブルー・オーキッド","desc":"青紫色の大きな花。太陽を好み、砂漠でも花を咲かせる。"}],"3150":[{"rank":"2","note":"聖母に捧ぐ大聖堂","exp":"400","type":"宗教建築","name":"ノートルダム大聖堂","desc":"聖母マリア崇拝に基づいて建立されたキリスト教の聖堂。「ノートルダム」とはフランス語で「我らの貴婦人」という意味であり、イエスの母・マリアを指す。同名の聖堂がフランス語圏の各地に建てられている。"}],"803":[{"rank":"3","note":"クエスト「大きな川という名の川」<br/>発見物カード:235","exp":"473","type":"地理","name":"ミシシッピ川","desc":"北米大陸を縦断する大河。流域に住むオジブウェ民族の言葉で「大きな川」を意味するミシシッピという名で呼ばれるように、その流れは地の果てまで続くようである。"}],"6447":[{"rank":"5","note":"","exp":"","type":"財宝","name":"公妃の香り付き革手袋","desc":"フランスのグラース地方で作られた貴婦人用の手袋。皮革のにおいを消すために香料を染みこませてあり、芳香を放つ。中でもオレンジの花の精油の香りは、ネロラの公妃が好んだとされ、ネロリと呼ばれるようになったという。"}],"1650":[{"rank":"2","note":"知られざる島","exp":"330","type":"地理","name":"ニューカレドニア島","desc":"オーストラリアの東にある細長い島。周囲はサンゴ礁で覆われており、島の内陸部は山がちで、丘陵となっている。気候は穏やかで、島には白檀が自生しているため、商人の注目を集めそうだ。"}],"2359":[{"rank":"5","note":"クエスト「覇業の残光」<br/>発見物カード:560","exp":"1120","type":"史跡","name":"安土城","desc":"五層七階の天守を備えた日本の城郭。その壮麗な姿は、築城主の勢威を物語る。\n火災が起こって以来、天守は使用されていない。"}],"6211":[{"rank":"2","note":"海岸の怪物","exp":"270","type":"化石","name":"鯨骨","desc":"海岸に流れついたクジラの骨。クジラや大きな魚の死骸は、通常であれば海中に住んでいるさまざまな生き物によって分解されていくが、その過程で腐敗した死骸や骨格が海岸に打ち上げられることがあるという。"}],"3735":[{"rank":"5","note":"ダンジョン","exp":"1050","type":"歴史遺物","name":"ラムセス2世の壁画","desc":"古代エジプトのファラオであるラムセス2世の、カデシュの戦いでの活躍を描いた壁画。戦車を駆り弓を構えるその姿から、王の勇敢さがうかがえる。"}],"6317":[{"rank":"3","note":"","exp":"480","type":"鳥類","name":"ジュウニセンフウチョウ","desc":"東南アジアなどに生息する鳥。雄のみ、お尻から細い針金状の尾羽が12本生えている。繁殖期になると、この尾羽を雌の顔にかすめるようにして求愛する。"}],"6458":[{"rank":"5","note":"追究クエスト　発見物カード:1075","exp":"2150","type":"美術品","name":"楢柴肩衝","desc":"天下三肩衝の一つと称される茶入。その価値から名だたる人物のもとを渡ったとされる一品。江戸の大火事の際に破損し、修繕されたのち、所在不明になったといわれる。"}],"3779":[{"rank":"5","note":"視認","exp":"810","type":"天文","name":"フォーマルハウト","desc":"ヨーロッパの秋の夜空でひときわ目立つ1等星。アラビア語で「大魚の口」という意味のファム・アル・フートが名の由来で、みなみのうお座の口の位置にある。ヨーロッパ北部では、南国へのあこがれを誘う星とされる。"}],"6885":[{"rank":"3","note":"発見物カード:330","exp":"660","type":"地理","name":"ヘラルド島","desc":"チュクチ海のウランゲリ島近くにある小島。無人島であり、北風が吹きすさぶ極寒の気候が特徴。島周辺の切り立った崖と、海氷により、船での上陸は非常に難しい。"}],"258":[{"rank":"3","note":"ピンクの宝石の鉱脈の地図","exp":"590","type":"財宝","name":"ピンクダイヤ","desc":"ピンク色のダイヤモンド。透明度が高く、色が美しいほど高い価値がある。"}],"2982":[{"rank":"1","note":"房状の花の地図","exp":"170","type":"植物","name":"アメリカフジ","desc":"北米南部に分布する、フジの一種。\n本種に比べて花が小さく、花房も15cm程度の長さである。"}],"6727":[{"rank":"4","note":"小さな鳥の地図 発見物カード:305","exp":"610","type":"鳥類","name":"オオムジアマツバメ","desc":"南米にある巨大なイグアスの滝の裏側に生息する鳥。長い翼を持つため、高速な水平飛行が可能で、滝を簡単に突破できる。"}],"1553":[{"rank":"1","note":"「書きかけの地図」<br/>発見物カード:65","exp":"130","type":"地理","name":"フロレス海","desc":"セレベス島の南に広がる海。水温が高く、塩気の強い海水のため独特の海洋生物が見られる。また、この地域の小島にも変わった生物が多く、興味深い。"}],"525":[{"rank":"1","note":"古代の食品の地図","exp":"27","type":"歴史遺物","name":"古代のコーヒー","desc":"コーヒーはエチオピア原産で古代から薬として飲まれていた。当時は、実を干し、煮出して飲んでいたようだ。"}],"6732":[{"rank":"5","note":"楽の叡智・心に響く楽器　左下","exp":"","type":"財宝","name":"サンポーニャ","desc":"南米アンデス地方の伝統的な管楽器。竹または葦などでさまざまな長さの管を作り、それを束ねて製作する。ナスカ文化の遺跡などから出土していることから、インカ帝国以前の古代アンデス文明が起源といわれる。"}],"271":[{"rank":"1","note":"プレステ・ジョアンの国","exp":"190","type":"宗教建築","name":"アクスム石柱群","desc":"かつて栄えたアクスム王国の遺跡。独特の様式の石柱は百本以上ある。現在見つかっているものの中ではもっとも高い石柱がある。基部には石室があるところから、王族などの墓だと思われる。"}],"3786":[{"rank":"3","note":"視認","exp":"450","type":"天文","name":"アルデバラン","desc":"おうし座で最も明るいオレンジ色の星。星座図では、牡牛の目にあたる。オリオンのベルトを成す3つの星を結んだ線を右に伸ばした位置にある。占星術では富の幸福の前兆とされる。冬のダイヤモンドの一角。"}],"27":[{"rank":"1","note":"アフリカの装身具の地図","exp":"56","type":"財宝","name":"ズールーの装身具","desc":"アフリカ南部に居住する民族の装身具。色とりどりのビーズを使った、複雑な模様のものである。ズールーの名は「楽園の民」を意味する。非常に勇敢な民族である。"}],"6316":[{"rank":"5","note":"クエスト「百年に一度だけの花」<br/>発見物カード:535","exp":"1070","type":"植物","name":"プヤ・ライモンディ","desc":"アンデスの高山帯に分布する巨大な植物。百年ほど経つと巨大な花を一度咲かせ、その後は枯れてしまう。大きく細長い葉には、硬く鋭いトゲが多く生えている。別名「アンデスの女王」。"}],"6565":[{"rank":"5","note":"追究クエスト","exp":"1040","type":"地理","name":"ミシガン湖","desc":"北米大陸北東部に位置する湖のひとつ。世界で第五位の面積を誇る広大な湖である。海峡を隔てて隣接しているヒューロン湖とは、水面の高さが一致しているため、同じ湖という見方もできる。"}],"2726":[{"rank":"2","note":"ある船乗りの願い","exp":"260","type":"宗教建築","name":"新羅の石仏","desc":"新羅時代初期に作られたと思われる石仏。\n新羅では、仏教が盛んだったため、多くの石仏が残っている。朝鮮で最古の石仏とされるものは、鼻を削って飲めば病気が治るという伝承があり、鼻が欠けているらしい。"}],"1502":[{"rank":"1","note":"赤いカメの地図","exp":"100","type":"小型生物","name":"アカアシガメ","desc":"脚に赤い斑点があるカメ。湿度の高い環境を好み、木の葉や果実などを食べる。成長すると甲羅の中央がくびれてくる。"}],"2714":[{"rank":"1","note":"紫色の花の地図","exp":"180","type":"植物","name":"カラムラサキツツジ","desc":"主に朝鮮に生息する、春に桃紫色の花を咲かせる植物。\n春告げの花として人々に慕われている。"}],"3686":[{"rank":"5","note":"ウランゲリ島での生物調査","exp":"810","type":"中型生物","name":"セイウチ","desc":"極北の沿岸に群れで生息する大型の動物。体毛がなく体は脂肪に覆われている。大きく発達した、上あごの牙が特徴的だ。"}],"1768":[{"rank":"3","note":"ある巫女の物語","exp":"530","type":"宗教遺物","name":"アクリャの調理用具","desc":"アクリャとは、インカ帝国の宗教行事に従事していた女性たちである。容姿端麗な10歳に満たない少女から選ばれ、家柄・血筋は関係なかった。アクリャの作る生産品は、インカ帝国の経済の根本を支えていた。"}],"951":[{"rank":"1","note":"風変わりな宗教画","exp":"185","type":"美術品","name":"キリスト磔刑","desc":"「たっけい」。エル・グレコ作の絵画。イエスが十字架に架けられた情景で、左右対称の構図の中でイエスが白い体をよじって天を仰いでいる。彼の宗教画は光輪を描かないなど定石を無視したところがあるため、初期には認められなかった。"}],"6767":[{"rank":"2","note":"発見３２０，発見物カード１６０","exp":"480","type":"中型生物","name":"サプサルケ","desc":"朝鮮半島の固有犬種。番犬としての素質が高く、新羅時代には王室で飼われ、悪鬼を追い払う霊力があるといわれた。朝鮮半島ではサブサリなどとも呼ばれる。"}],"1204":[{"rank":"3","note":"巨大海獣<br/><br/>発見時経験値506　発見物カード経験値253","exp":"506","type":"海洋生物","name":"オタリア","desc":"大型のアシカのような海獣。オスには、たてがみ状の毛が生えていて、体重はメスの2倍にもなる。"}],"6768":[{"rank":"2","note":"発見物カード　経験値:140","exp":"280","type":"宗教建築","name":"聖ヨハネ大聖堂","desc":"16世紀後半、ヨハネ騎士団長カシエールにより、マルタの首都ヴァレッタに建てられた礼拝堂。マルタ島特産の石灰岩を使用しており堂内には歴代の騎士団長が埋葬されている。"}],"1439":[{"rank":"4","note":"貝の宝石","exp":"624","type":"化石","name":"美しい貝の石","desc":"貝殻が宝石となったもの。白や黒など、さまざまな色がある。"}],"6712":[{"rank":"2","note":"クエスト「不老不死の秘法」 発見物カード:140","exp":"280","type":"財宝","name":"チャラカ・サンヒター","desc":"インドの伝統医学であるアーユル・ヴェーダを代表する、古典医学書の1つ。クシャーナ朝カニシカ王の侍医、チャラカの著作が元になった。熱病、癇癪、腫瘤に対する研究が特にくわしい。"}],"1955":[{"rank":"1","note":"虫を捕まえる植物の地図","exp":"110","type":"植物","name":"フクロユキノシタ","desc":"オーストラリアのみに生息。小瓶にふたが付いた形の葉を複数付けている。この瓶の形の葉の中に落ちた虫は、しばらくすると溶けてなくなってしまう。\nこの植物は虫から養分を吸収しているのかもしれない。"}],"3820":[{"rank":"5","note":"隠された財宝","exp":"1090","type":"財宝","name":"海賊の隠し財宝","desc":"ある海賊が収奪した金銀財宝を詰め、隠しておいたもの。\n長らく放置されていたらしく箱は古びているが、中身はきれいに保たれている。"}],"5622":[{"rank":"4","note":"クエスト「ベーリング海峡付近の地理調査」<br/>発見物カード:325","exp":"650","type":"地理","name":"セントローレンス島","desc":"ベーリング海峡の南にある島。多くの海鳥やセイウチなどの動物の生息地となっている。"}],"6358":[{"rank":"2","note":"","exp":"370","type":"地理","name":"ジャイアンツ・コーズウェー","desc":"アイルランド北東部にある海岸。溶岩が冷えて固まってできた石柱がいくつも並ぶ。石柱は六角柱の形をしたものが多い。伝承では、アイルランドの巨人が戦いに行く際に作ったともいわれる。"}],"502":[{"rank":"1","note":"古代ギリシャ遺物の地図","exp":"14","type":"歴史遺物","name":"ギリシャ文字の石板","desc":"ギリシャ文字が刻まれた石板。長く残すための銘文が刻まれているのだろう。"}],"179":[{"rank":"1","note":"ストーンヘンジの調査","exp":"90","type":"宗教建築","name":"ストーンヘンジ","desc":"イングランドにある、先史時代の遺跡。祭祀場（さいしじょう）だったと考えられる。夏至の日の出の方向に入り口があり、全体は正確な円を描いている。"}],"2883":[{"rank":"3","note":"華北の古代文明","exp":"530","type":"地理","name":"黄河","desc":"雲台山の北部を流れる大河。\n下流域は「中原」と呼ばれ古代文明が発祥した地である。\n古来、よく氾濫し川の流れが変わっている。"}],"24":[{"rank":"1","note":"アフリカの高貴な花<br/><br/>発見時経験値90　発見物カード経験値45","exp":"90","type":"植物","name":"クンシラン","desc":"南アフリカで見られる多年生の植物。赤やオレンジの豪華な花が美しい。つやがあり規則的に並ぶ葉も大変見ごたえがある。観賞用として高い評価が得られるだろう。"}],"3531":[{"rank":"","note":"","exp":"","type":"レリック","name":"ヌマ・ポンピリウス","desc":"古代地中海世界に覇を唱えたローマ帝国。その基盤を作ったのは、意外にもローマの外から招かれた賢王であった。"}],"6799":[{"rank":"5","note":"発見物カード:420","exp":"840","type":"史跡","name":"オファの防塁","desc":"ブリテン島に8世紀ごろに築かれたという土塁。小国が林立していた七王国時代、ウェールズからの侵攻と、領土防衛のため、マーシア国の王、オファが築いたとされる。"}],"1609":[{"rank":"1","note":"時計のような花の地図","exp":"175","type":"植物","name":"トケイソウ","desc":"時計のような形の花を咲かせる。花は10cmほどに成長し、毎日咲いてしぼむという性質を持つ。"}],"5147":[{"rank":"2","note":"到達する","exp":"244","type":"港・集落","name":"ポルトベロ","desc":"中米、南米との交易の中継地としての役割を果たす、カリブ海に面する港町。ポルトベロとは「美しい港」という意味である。"}],"2240":[{"rank":"4","note":"森の奥の謎","exp":"750","type":"地理","name":"ダーウィン湖","desc":"ガラパゴス諸島の中で一番大きな島にある塩湖。海よりも水面が高く、雨もほとんど降らないにもかかわらず、湖水が枯れることはないという。"}],"6120":[{"rank":"5","note":"","exp":"970","type":"植物","name":"リュウケツジュ","desc":"竜血と呼ばれる樹脂を分泌する樹木で、幹の一定の高さから無数の枝を伸ばしているのが特徴的。インド洋にあるソコトラ島産の竜血が古代より有名だが、アフリカのカナリア諸島周辺にも竜血が採れる近縁種があるらしい。"}],"2983":[{"rank":"3","note":"釣り","exp":"530","type":"海洋生物","name":"ビンナガ","desc":"胸ビレが長いマグロの仲間。真上から見ると羽を広げているように見える。脂がよく乗っており食用としても利用価値が高い。"}],"800":[{"rank":"2","note":"大いなる石の家","exp":"260","type":"史跡","name":"ジンバブエ遺跡","desc":"アフリカ南方にある、石造の建造物群。ショナ語で「石の家」という意味で、モノモタパ王国の都であった。アフリカで石造建築物を持つ文化は珍しい。"}],"1940":[{"rank":"2","note":"サルベージ<br/>発見物カード:195","exp":"390","type":"歴史遺物","name":"カネテの難破船","desc":"南米から本国へ向かう途中だった、イスパニアの貿易船。\nスピルヴァーゲン船長が率いるネーデルラント船との戦いで沈没した。"}],"5923":[{"rank":"2","note":"","exp":"","type":"美術品","name":"金細工の版画","desc":"金細工の技術を用いて製作された、当時最先端の版画。ドイツで発明され、細やかな線が用いられているのが特徴。\n印刷技術の普及と共にヨーロッパに広く伝播し、美術史において重要な役割を果たすこととなった。"}],"5873":[{"rank":"5","note":"発見物カード:635","exp":"1370","type":"天文","name":"イカルス","desc":"小惑星の一つ。その軌道がかなり太陽の近くを通っていることからギリシャ神話のイカロスの名にちなんで名づけられた。十数年ごとに地球の近くも通り過ぎるようだ。"}],"5930":[{"rank":"2","note":"","exp":"300","type":"史跡","name":"アルメンドレスの環状列石","desc":"ポルトガル各地にあるクロムレック（環状列石）の一つ。リスボンの東にある古都エヴォラの郊外にあり、規模も古さもポルトガル随一だという。"}],"5121":[{"rank":"2","note":"到達する","exp":"310","type":"港・集落","name":"パレンバン","desc":"スマトラ島南部北岸にある街。東西交易に権勢を振るったシュリーヴィジャヤ王国の首都があった。"}],"49":[{"rank":"1","note":"イル・ハン国の財宝","exp":"175","type":"歴史遺物","name":"フラグの財宝","desc":"フラグはフビライ・ハンの弟で、中東を攻めてイル・ハン国を興した。この財宝はフラグの命令で隠してあったもののようだ。"}],"1275":[{"rank":"3","note":"クエスト「根源地を探せ」<br/>発見物カード:240","exp":"484","type":"地理","name":"モルッカ諸島","desc":"セレベス島東部に位置する諸島。\n長らく不明であった香辛料・クローブの原産地がこのモルッカ諸島であったため、香料諸島とも呼ばれる。"}],"5489":[{"rank":"2","note":"アマゾン奥地再調査報酬の発見物「アサイー」が前提の可能性大。","exp":"","type":"植物","name":"グアバ","desc":"中南米などの熱帯、亜熱帯地域で見られる低木。\nグアバの実は紀元前から中米の先住民の間で食用とされていたが、16～17世紀に東南アジアに伝わるとグアバの葉を茶葉として使うようになった。"}],"6587":[{"rank":"2","note":"","exp":"","type":"宗教遺物","name":"シュルバ・スートラ","desc":"古代インドの数学に関する書物。祭壇などの修築が主題であり、祭壇を採寸する際に使用する幾何学を始め、当時の様々な知識が記されている。"}],"3731":[{"rank":"5","note":"草原地帯の生活道具","exp":"1045","type":"財宝","name":"ウルガ","desc":"モンゴルの伝統的な生活道具。\n長い棒の先に輪にした縄をつけたもので、小型のウマなどを捕えるために使う。"}],"5789":[{"rank":"5","note":"イスラム建築に魅せられて","exp":"1360","type":"宗教建築","name":"ディヴリーイの大モスクと病院","desc":"モスク、病院、霊廟が併設された建築物。当時の王の命令でモスクが建造される際、その妻が病院の併設を願ったという。扉口や柱、壁などに多くの精密な模様が刻まれており、当時の建築技術の高さが窺い知れる。"}],"5663":[{"rank":"2","note":"南米南東岸やや北東","exp":"390","type":"気象・現象","name":"空中竜巻","desc":"渦巻の下端部分が空中にあり、地上や洋上に接していない現象。接点がないため、地上や洋上で被害が生じることはない。発生日時などの条件は、普通の竜巻とほぼ同じと思われる。"}],"6925":[{"rank":"5","note":"発見物カード:560","exp":"1120","type":"地理","name":"アンドロメダの岩","desc":"ヤッファの海岸に浮かぶ岩。ギリシャ神話では、海神ポセイドンの怒りを鎮めるために、エチオピアの王女アンドロメダが生贄として鎖で繋がれた場所だといわれている。"}],"3292":[{"rank":"3","note":"ブリテン島の保養地","exp":"510","type":"地理","name":"タンメル湖","desc":"ブリテン島の北部に位置する、東西に延びた細長い湖。深い青の湖水の周りを、緑の木立や田園風景が取り巻いている。特に、北東岸からの景観がひときわ美しい。"}],"1871":[{"rank":"5","note":"失われた万能薬","exp":"1120","type":"宗教遺物","name":"カジャワヤの薬草壷","desc":"カジャワヤとは、アンデスの山間部に住まう呪術師である。その役割は医師、賢人と幅広く、アンデスの人々にとって身近な存在である。カジャワヤの薬草の知識は深く、野山に育つ雑草から、患者に合った薬を処方する。"}],"2616":[{"rank":"4","note":"淡水周辺の安全調査","exp":"620","type":"歴史遺物","name":"鶯歌石","desc":"読み方は、「おうかせき」。\n台北（タイペイ）の山にある巨石。瘴気を吐き、人々に害をもたらしていた怪鳥が鄭成功に撃ち落とされて石となったという伝説が残っている。"}],"1440":[{"rank":"2","note":"二つの顔","exp":"280","type":"小型生物","name":"フクロモモンガ","desc":"滑空する有袋類。長くてふさふさした毛で覆われた尾を持つ。滑空する際に、その尾は舵の役割を果たす。小さな群れで生活し、樹液や種子を食べる。"}],"5101":[{"rank":"1","note":"到達する","exp":"46","type":"港・集落","name":"トレビゾント","desc":"黒海南岸に位置する街である。過去には独立した帝国だった。農業に適した気候で耕作・畜産・漁業いずれも盛んである。"}],"5885":[{"rank":"1","note":"","exp":"130","type":"地理","name":"クヴァルケン群島","desc":"バルト海に位置する群島。かつて存在した氷河が融解することで地形が変化し、複雑に隆起している。"}],"6616":[{"rank":"5","note":"レガシー美の叡智　左下","exp":"3150","type":"財宝","name":"九鼎","desc":"古代中国における王権の象徴。伝説によれば中国最古の王朝「夏」の始祖である禹が、九つの州に命じて集めさせた青銅で鋳造したという。鍋釜のような三本足の金属器具で、祭器として使われた。"}],"5830":[{"rank":"1","note":"","exp":"","type":"財宝","name":"集史","desc":"イル・ハン国の王の命により編纂された歴史書。主にモンゴル帝国の発展について記されているが、その他の民族の歴史も集められているため、「集史」と呼ばれる。"}],"535":[{"rank":"1","note":"古代の道具の地図","exp":"29","type":"歴史遺物","name":"青銅器","desc":"古代文明で使われていた青銅の器。青銅は加工が容易で扱いやすいため、多くの古代文明で用いられた。"}],"2877":[{"rank":"3","note":"父と子の証","exp":"470","type":"宗教遺物","name":"折れた剣の欠片","desc":"高句麗初代王・朱蒙が息子の類利に残したとされる剣の欠片。\n父を知らずに育った類利は、ある時、母から「隠された剣を探し出せれば我が子だ」という父の言葉を伝えられる。類利は見事に剣を探し当て、高句麗二代王となったという。"}],"940":[{"rank":"1","note":"美人画の先駆け","exp":"190","type":"美術品","name":"聖母子と二天使","desc":"フラ・フィリッポ・リッピ作の聖母子と天使の絵。宗教画は形式を重視した象徴的な描き方をされるのが常であったが、彼は生気に満ちた人物で宗教画を描いた。この聖母のモデルは彼の妻だといわれる。"}],"1980":[{"rank":"2","note":"釣り","exp":"220","type":"海洋生物","name":"カンムリブダイ","desc":"大きなくちばしを持ちフンを土煙のように撒き散らして泳ぐブダイの仲間。"}],"6595":[{"rank":"2","note":"","exp":"350","type":"宗教建築","name":"ボジャナコンダ","desc":"ヴィシャーカパトナムから少し離れた丘の上にある仏教遺跡。岩を切り出して作られた岩窟がいくつかあり、内部には座する仏像が祀られている。隣接する丘の上にはリンガラコンダという仏教遺跡もある。"}],"1856":[{"rank":"5","note":"危険な若い峰","exp":"1110","type":"地理","name":"ワイナピチュ","desc":"マチュピチュの北側にそびえる峰。マチュピチュが「年老いた峰」を意味するのに対し、ワイナピチュは「若い峰」を意味している。同様にマチュピチュには太陽神を奉る神殿があり、ワイナピチュには月の神を奉る神殿があるという。"}],"835":[{"rank":"2","note":"地上の楽園","exp":"320","type":"地理","name":"モルジブ諸島","desc":"インドの南西に分布する島々。1000を超える島が南北に散らばっている。土地はそれなりに肥沃で、ココヤシなどの栽培に向くと思われる。"}],"75":[{"rank":"1","note":"クエスト「ヴァイキングの国」<br/>発見物カード75","exp":"150","type":"歴史遺物","name":"ロロの兜","desc":"ヴァイキングの首領・ロロが使っていたといわれる兜。彼は北フランス沿岸をしばしば襲撃した。西フランク王はこれを抑えるため、ロロをノルマンディー公に任じた。"}],"6953":[{"rank":"5","note":"","exp":"","type":"海洋生物","name":"ヒロオウミヘビ","desc":"青い体色と黒の縞模様が特徴的なウミヘビ。尾が広く、平らな形をしていることからこの名がついた。捕食の際に海に潜る以外は陸上で生活する。性格は穏やかだが非常に強い毒を持つ。琉球では燻製にされ、薬膳料理の食材として使われる。"}],"518":[{"rank":"1","note":"古代の銀細工の地図","exp":"37","type":"歴史遺物","name":"古代の銀の器","desc":"銀で作られた器。実用品より、祭器や特別な用途に使われていたようである。"}],"379":[{"rank":"1","note":"海神の像","exp":"60","type":"宗教遺物","name":"ポセイドン像","desc":"ギリシャ神話の海神の像。ポセイドンは多くの愛人を持ち、その子供にはポリュフェモスなど、凶暴な怪物が多い。有名なメデューサもポセイドンの愛人でその子供がペガサスである。"}],"954":[{"rank":"2","note":"仏教の開祖","exp":"290","type":"宗教遺物","name":"仏像","desc":"仏教で信仰されるさまざまな仏の姿を表した像である。仏は悟りを開いた釈迦をモデルにするので、衣だけの質素な姿が基本である。また、手足に法輪の模様があるなどの三十二相がある。"}],"2679":[{"rank":"2","note":"朝鮮の絵画を追え","exp":"310","type":"美術品","name":"安堅の水墨画","desc":"朝鮮の画家・安堅による水墨画。\n朝鮮王・世宗の三男である安平大君が夢に見たという桃源郷が、淡墨で描かれている。\n安堅は、この桃源郷をたった三日で描き上げたという。"}],"6852":[{"rank":"3","note":"発見物カード:240","exp":"480","type":"美術品","name":"真珠の耳飾りの少女","desc":"別名「ターバンを巻いた少女」とも呼ばれるネーデルラントの画家フェルメールの作。青いターバンを巻いた少女が大きく描かれ、かすかに微笑んで見えることから「北のモナリザ」とも呼ばれる。"}],"5047":[{"rank":"2","note":"到達する","exp":"328","type":"港・集落","name":"クチン","desc":"カリマンタン島の中部西岸に位置する街。北東にあるブルネイを本拠地とするブルネイ王国の支配下にある。クチンは現地の言葉でネコを意味する。"}],"6481":[{"rank":"5","note":"レガシー　港湾都市ロードス　左下","exp":"","type":"歴史遺物","name":"カレスの巨像設計図","desc":"ロードス島の巨像のものと思われる設計図。巨像は鉄枠に青銅の板を張り付けて作られ、安定のため足の内部には石材が使用されたらしい。建造を指揮したとされるカレスの作と思われるが、彼は巨像の完成前に亡くなったという伝承もある。"}],"6144":[{"rank":"1","note":"","exp":"130","type":"宗教遺物","name":"フェルナンドの聖書","desc":"フェルナンド王子が普段使っている聖書の写本。ページの紙自体は古びているが、大きな傷などはまったく見当たらない。随分長く、丁寧に読まれてきたようだ。「忠義ある限り尽くさん」と書かれたメモが二枚挟まれている。"}],"3913":[{"rank":"3","note":"立派な角を持つウシ","exp":"500","type":"大型生物","name":"ビッグホーン","desc":"北米西部に生息する大きなヒツジ。鼻などを除いた体の大半を覆う茶色い毛並みと、半月状に弧を描く大きな角が特徴。この角はメスよりもオスのほうが大きくなる。"}],"5276":[{"rank":"","note":"発見時経験値2440　発見物カード経験値なし","exp":"2440","type":"レリック","name":"深海の歯車","desc":""}],"102":[{"rank":"1","note":"カナリア諸島の大きい島","exp":"40","type":"地理","name":"フエルテベントゥラ島","desc":"カナリア諸島の東部に浮かぶ島。カナリア諸島の中でアフリカ大陸に最も近い。島のほとんどが乾燥しており、南部にはプエルト・ブランカと呼ばれる美しい白い砂浜が続く。"}],"916":[{"rank":"2","note":"白黒のサル","exp":"260","type":"中型生物","name":"アビシニアコロブス","desc":"黒と白の毛並みが美しいサル。完全に草食性のようで、樹上で葉をもりもり食べている。同じようなサルがほかにもいるようだが、毛並みはこのサルが一番で美しい。"}],"6693":[{"rank":"2","note":"台湾島南東岸で上陸。<br/>南島の赤い花付近。","exp":"210","type":"植物","name":"クワズイモ","desc":"サトイモ科の植物で、大きな葉をつける。その名の通り食用には向かず、毒性があって激しい腹痛を引き起こす。中国では、毒を以て毒を制すの考え方から、薬として用いられた。"}],"2310":[{"rank":"2","note":"［勅命］[[現地における生物の調査","exp":"310","type":"小型生物","name":"カエルクイコウモリ","desc":"中米の熱帯雨林に生息するコウモリで、その名のとおりカエルを捕食する。カエルの鳴き声で毒を持つか持たないかさえ判断してしまう能力は、頭より大きな耳のおかげだろう。"}],"5152":[{"rank":"1","note":"到達する","exp":"176","type":"港・集落","name":"マスリパタム","desc":"インド東岸に位置する街。交易の中継点として開発された。熱帯性の農作物のほか、インド特有の織物や繊維が豊富に流通している。"}],"2716":[{"rank":"1","note":"縞模様のある魚の地図","exp":"180","type":"海洋生物","name":"チョウセントゲドジョウ","desc":"朝鮮周辺に生息する淡水魚。\n白地に黒縞の模様が入った、美しいドジョウである。"}],"1296":[{"rank":"2","note":"愛を感じる花","exp":"330","type":"植物","name":"シンビジューム","desc":"ギリシャ語で「船」と「形」の意。船に似た唇弁の形にちなむ。中心を包むように、たくさんの色の花を咲かせる。"}],"2369":[{"rank":"1","note":"シカに似た動物の地図","exp":"150","type":"中型生物","name":"ニホンカモシカ","desc":"山林に生息する、日本固有のカモシカ。雌も雄と同様の角を持ち、いずれも生え変わることはない。\n毛皮は保温効果と耐水性に優れており、広く重宝されている。"}],"6744":[{"rank":"5","note":"発見物カード:525","exp":"1050","type":"鳥類","name":"アンナハチドリ","desc":"別名「飛ぶ宝石」と讃えられる、華麗な色彩を持つハチドリ。オスは東部の羽毛が光を反射するため、角度が変わると変色したように見える。繁殖期になると、オスは頻繁に冠羽を変色させ、メスを惹きつける。"}],"5702":[{"rank":"2","note":"2017.02.07新規追加","exp":"240","type":"地理","name":"イムジャ湖","desc":"チョモランマのふもとにある湖。氷河の後退により溶けた水がせき止められ、湖が形成されている。せき止めている部分が決壊した場合、大きな被害をもたらすのではと考えられている。"}],"5207":[{"rank":"2","note":"","exp":"250","type":"宗教遺物","name":"ズメエヴィク","desc":"中世に使用された肖像入りの首飾り。片面にはキリスト教徒の聖人と蛇、もう片面には祈祷の言葉が刻まれる。"}],"5874":[{"rank":"5","note":"クエスト「巨大星雲」<br/>発見物カード:650","exp":"1370","type":"天文","name":"イータカリーナ星雲","desc":"りゅうこつ座にある星雲。他の星雲と比べて巨大なものに分類されるが、喜望峰など南方の高緯度地域でしか観測できないため、知名度は高くない。ラカーユによって発見されたとされる。"}],"6737":[{"rank":"5","note":"発見物カード:560<br/>北大西洋","exp":"1120","type":"天文","name":"ミルファク","desc":"ペルセウス座で最も明るい星。黄白色に輝いて見える。名前はアラビア語で「ひじ」を意味する。かつては「わき腹」を意味するアルゲニブの名で呼ばれていた。"}],"652":[{"rank":"1","note":"書きかけの地図","exp":"20","type":"地理","name":"マルタ島","desc":"イタリア半島とシチリア島の南に浮かぶ島。イタリアと北アフリカの間にあることから、支配勢力がしばしば変わった。先史時代から人が住んでいたようである。"}],"1701":[{"rank":"5","note":"未来を守る力","exp":"1183","type":"宗教遺物","name":"ゴリアテの剣","desc":"ゴリアテとは、旧約聖書に登場する、ペリシテ人の戦士。ペリシテ人がイスラエル王国を攻めたとき、羊飼いの少年・ダヴィデが石を投げてゴリアテを倒しこの剣を奪ってゴリアテにとどめを刺したという。"}],"5662":[{"rank":"2","note":"","exp":"240","type":"化石","name":"背骨が上に伸びたトカゲの骨","desc":"アフリカ大陸北部で発見された、巨大なトカゲのような生物の骨。全長は約15mで、背骨から上方へと伸びる突起が特徴的である。"}],"6949":[{"rank":"4","note":"発見物カード:350","exp":"700","type":"海洋生物","name":"ライオンタテガミクラゲ","desc":"ライオンのたてがみのように見える触手を持つ大型のクラゲ。冷たい海に生息するものは傘の直径が2m、全長は30mを越えることもある。長い触手は粘着性で千本近くあり、海を漂うその姿から、別名キタユウレイクラゲとも呼ばれる。"}],"5409":[{"rank":"2","note":"","exp":"","type":"宗教遺物","name":"ネイト像","desc":"ネイトは戦いと織物を司る古代エジプトの女神。織り機へ横糸を通す道具｢杼（ひ）｣を頭上に乗せ、弓矢を持つ姿で描かれる。ライオンの頭を持つ姿で描かれることもある。"}],"2019":[{"rank":"2","note":"［勅命］「新大陸西岸進出への道標」<br/>リマ冒険「南米地形調査」","exp":"310","type":"地理","name":"デセアド岬","desc":"南米大陸南西岸にある岬。この周辺の地形は氷河によって造成されたフィヨルド地形であり、他の地域と大きく異なる。"}],"6754":[{"rank":"5","note":"","exp":"1170","type":"宗教建築","name":"アンコナ大聖堂","desc":"アンコナの港全体を見渡せる丘、ドゥオーモ広場に建つ大聖堂。航海を守護する女神アフロディテを祀っていたギリシャ神殿の跡地に建てられたという。アンコナの守護聖人である聖キリアクスにちなみ、聖チリアコ大聖堂とも呼ばれる。"}],"5893":[{"rank":"5","note":"極東のドラゴンスレイヤー","exp":"1360","type":"財宝","name":"八塩折之酒","desc":"八頭八尾の竜が殺された、と伝わる場所に落ちていた酒。ずいぶん古いもののように見えるが、中の酒は嘘のように新鮮なままである。"}],"6721":[{"rank":"2","note":"","exp":"","type":"財宝","name":"快雪時晴帖","desc":"東晋時代の書家・王羲之による作品。全文28字。彼が引退し、俗世のいざこざから離れた後、友人あての手紙として書かれた。行書体の作品において最高峰とされている。"}],"5580":[{"rank":"5","note":"","exp":"","type":"地理","name":"ケスタ","desc":"北米大陸北東部などで見られる地形の一種。硬い地層と軟らかい地層が交互に重なった斜面が浸食されることによって、緩い斜面と急な崖が連続する地形となっている。ナイアガラの滝は、この急な崖の部分にあたるとみられる。"}],"1359":[{"rank":"5","note":"手のひらの戦士<br/><br/>発見時経験値923　発見物カード経験値461","exp":"923","type":"虫類","name":"コーカサスオオカブト","desc":"三本の長い角を持つ大きな虫。10cmを超える体はがっしりとしており、光沢が強い。爪は鋭く、好戦的である。"}],"1055":[{"rank":"1","note":"列をなす巨石","exp":"95","type":"史跡","name":"カルナック巨石群","desc":"先史時代の巨石群。4000を超える巨石が立ち並ぶが、なんのために並べたのか、まったく謎である。付近には巨石遺構が多く、墓のようなものもある。"}],"2800":[{"rank":"2","note":"薬になる植物","exp":"270","type":"植物","name":"サンザシ","desc":"中国に生息する植物。キリストの冠にも使用されたといわれる。\n盆栽や庭木にも用いられ、果実は食用や薬用に使われる。"}],"6390":[{"rank":"2","note":"","exp":"340","type":"化石","name":"頭が扁平なトカゲの骨","desc":"北米東部で見つかった大きなトカゲのような生物の骨。頭骨が平たいのが特徴。骨には鋭い歯がついている。"}],"5450":[{"rank":"3","note":"クエスト「奇妙な噂話調査」<br/>発見物カード:235","exp":"470","type":"中型生物","name":"タテガミオオカミ","desc":"南米で最も大きいイヌ科動物。脚力はチーターに匹敵するといわれ、短距離走なら90kmで走れる。民話では、ニワトリを睨んだだけで殺せる動物とされる。"}],"157":[{"rank":"1","note":"コンゴ王国の玄関","exp":"90","type":"地理","name":"コンゴ川","desc":"アフリカの大河。大西洋に注ぐ。河口の規模からして相当な流域面積があると思われる。内陸の探検へのルートとして有望だが、気候が厳しく困難である。"}],"6383":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:145","exp":"290","type":"天文","name":"トレミー星団","desc":"さそり座にある恒星の集団。肉眼でも確認できるほど明るい星々。48星座を分類した、プトレマイオスことトレミーが記述を残していることから「トレミー星団」と呼ばれる。"}],"576":[{"rank":"2","note":"香料を産む猫","exp":"260","type":"中型生物","name":"ジャコウネコ","desc":"タヌキと猫の間のような動物。目のまわりが黒く、体には斑点がある。肛門の近くの腺から悪臭のする分泌物が取れ、これを希釈すると高価な香料になる。夜行性で樹上で活動することが多いため、目撃するのは困難だ。"}],"1120":[{"rank":"3","note":"サンジョルジュの数奇な宝石","exp":"506","type":"財宝","name":"呪われた指輪","desc":"見る者を魅了する、素晴らしい細工が施された指輪だ。しかし、これまで所有したすべての者が、悲惨な運命に見舞われている。何か恐ろしい呪いがかかっているとしか考えられない…。"}],"1169":[{"rank":"2","note":"魔の海域","exp":"380","type":"地理","name":"バミューダ海域","desc":"北大西洋西部にある海域。150ほどの小島が点在している。この海域は難破事故が多く、魔の海域といわれている。"}],"5868":[{"rank":"5","note":"クエスト「新大陸の鳥の星座」<br/>発見物カード:670","exp":"1340","type":"天文","name":"きょしちょう座","desc":"南天の星座の一つ。16世紀に制定された。元となる巨嘴鳥(きょしちょう)はオオハシ科の鳥類だとされるが、複数人が制定に携わったためか、モチーフとなった鳥にも複数の説があるようだ。"}],"5393":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:140","exp":"280","type":"天文","name":"みなみのさんかく座","desc":"ケンタウルス座の近くにある星座。2等星と3等星が三角形を成すため見つけやすい。オランダのプランシウスによって初めて星座図に掲載された。"}],"5793":[{"rank":"5","note":"王の荷車","exp":"1380","type":"歴史遺物","name":"ゴルディアスの荷車","desc":"ゴルディアスの結び目が柱に結びつけていた荷車。「解いた者がアジアの覇者となる」と予言された結び目が、剣で断たれて解かれたと聞けば、ゴルディアスはどう思うだろう。"}],"2016":[{"rank":"2","note":"アンデスの儀式道具の地図","exp":"155","type":"歴史遺物","name":"黄金の円盤","desc":"インカ帝国を興したケチュア民族の太陽神インティを模した黄金の円盤。インカ帝国の各地にある「コリカンチャ」と呼ばれる太陽の神殿には、必ずこの円盤を奉った。黄金の円盤は装飾品にも使われ王のみが身に着けられた。"}],"5876":[{"rank":"5","note":"クエスト「伝説の霊獣」<br/>発見物カード:705","exp":"1410","type":"天文","name":"きりん座","desc":"北天の星座で、北極点の近くにある。一年を通して観測できる地域もあるが、目立つ星はなく知名度も低い。元となっているのは中国の神獣である麒麟ではなく、アフリカに生息するキリンである。"}],"902":[{"rank":"4","note":"破壊神の像","exp":"624","type":"宗教遺物","name":"シヴァ像","desc":"インド神話のシヴァ神の像。破壊と再生、踊りをつかさどる神で、三大神の一人である。ほかにも多くの妻を持ち、シヴァにまつわる神話は豊富にある。"}],"3414":[{"rank":"1","note":"北方の要衝","exp":"110","type":"地理","name":"エーレ海峡","desc":"コペンハーゲンのあるシェラン島とスカンジナビア半島の間の海峡で、最も狭いところでは幅が7kmほど。北海とバルト海を結ぶ交易の要衝である。"}],"2076":[{"rank":"2","note":"鄭和の航海誌 / 香料諸島方面進出の指標(勅命クエ)","exp":"360","type":"歴史遺物","name":"鄭和の航海誌","desc":"明の提督・鄭和の航海誌。鄭和は七度航海を行い、アフリカからキリンを持ち帰るなどした。この航海誌は散り散りになったものの一部で、内容を全て把握することはできない。"}],"2519":[{"rank":"1","note":"※不気味な魚の地図<br/><br/>※発見物カード100<br/>　","exp":"200","type":"海洋生物","name":"コウタイ","desc":"台湾島や中国に分布している、体長30cmほどの魚。食用、薬用に用いられる。\n赤、茶、緑など、いろいろな体色の個体がいる。"}],"1179":[{"rank":"4","note":"水のない文明","exp":"624","type":"史跡","name":"チチェンイッツァ","desc":"ユカタン半島に花開いたマヤの遺跡。「チチェンイッツァ」とは、「泉のほとり」という意味らしい。非常に広大な土地に展開し、ピラミッド型神殿を中心に、聖なる泉、戦士の神殿、天文台などがある。"}],"1466":[{"rank":"4","note":"変わった打楽器","exp":"624","type":"財宝","name":"水太鼓","desc":"男子が成人する際に行われる儀式で使用される楽器。地面に穴を掘り水を張って、そこへこの太鼓を沈めて上下させることで音を変える。"}],"2412":[{"rank":"3","note":"ダンジョン","exp":"530","type":"宗教遺物","name":"ハートスカラベ","desc":"スカラベをかたどった護符のうち、特殊なもの。裏面には、死者の書が刻まれている。\n復活の祈りを込めて、ミイラの心臓の上に置かれた。"}],"6779":[{"rank":"2","note":"発見物カード経験値：200","exp":"400","type":"地理","name":"大山","desc":"別名「阿夫利山」。標高1252mの山頂からは相模湾を望める。古くから祈雨・止雨の神として信仰され、江戸時代になると大山参拝は江戸庶民の一大行事となった。"}],"3258":[{"rank":"3","note":"クエスト「巨神の山脈」<br/>発見物カード:230","exp":"460","type":"地理","name":"アトラス山脈","desc":"北アフリカ沿岸、アルジェからカサブランカ付近まで続く山脈。標高が高い部分は積雪が見られる。\n山脈の名称は、ゼウスの命令により西の天界を支えることとなったギリシャ神話に登場する神・アトラスが由来となっている。"}],"2973":[{"rank":"5","note":"波間にたゆたう銀の怪火","exp":"1160","type":"海洋生物","name":"メガマウス","desc":"太平洋やインド洋の比較的暖かい海に生息しているサメ。巨大な体躯をしているが、目撃例が少ないため、これが大人なのか子供なのかはわからない。大きな口で、あらゆるものを吸い込むようにして食事をするようだ。"}],"3312":[{"rank":"2","note":"書きかけの地図","exp":"250","type":"地理","name":"モハーの断崖","desc":"アイルランド南部、西側の海に面する断崖絶壁。アイルランドの言葉では「破滅の崖」を意味する。晴れた日の景色は絶景である。"}],"2381":[{"rank":"2","note":"極東の鬼火","exp":"320","type":"植物","name":"ツキヨタケ","desc":"広葉樹の枯れ木に群生する毒キノコ。誤って食べてしまうと、視界が青くなるような幻覚症状を引き起こしてしまう。\n日本では古くから毒キノコとして知られており、今昔物語にも登場する。"}],"70":[{"rank":"2","note":"インドの母なる川","exp":"270","type":"地理","name":"インダス川","desc":"インド西部を流れ、アラビア海に注ぐ大河。下流域は小型船が行き来している。流域の灌漑（かんがい）用水でもあり、この川がなければ広大な土地が砂漠と化すだろう。"}],"5052":[{"rank":"1","note":"到達する","exp":"174","type":"港・集落","name":"コチン","desc":"南インドの街。南国の穏やかな気候に恵まれており、独特の産物が見られる。インドらしい染料や織物のほか、南国系の香料や果物、宝石が産物として扱われる。"}],"2710":[{"rank":"2","note":"大きな魚の地図","exp":"230","type":"海洋生物","name":"カムルチー","desc":"朝鮮半島から中国まで広範囲に分布する、肉食系の大型淡水魚。水草の多い池や沼に生息する。\n大きな口と、鋭い歯を持っている。"}],"6059":[{"rank":"1","note":"到達する","exp":"73","type":"港・集落","name":"ガボン","desc":"アフリカ中部、大西洋のギニア湾に面する地域。豊かな森林に恵まれ、大型の哺乳類が多く生息している。様々な鉱物資源の産出地としても有名"}],"1003":[{"rank":"1","note":"北欧の覇","exp":"150","type":"財宝","name":"覇王の宝冠","desc":"所有するものに覇をもたらすと伝えられる、豪華な宝冠。しかし、言い伝えは作られたものらしい。ハンザ同盟の富をつぎ込んで作られたという。"}],"2699":[{"rank":"2","note":"見慣れぬ石像","exp":"290","type":"宗教遺物","name":"トルハルバン","desc":"「石の爺さん」という意味を持つ石像。元は済州島で作られていたものらしい。\n魔除けのために、街角や建物の入口などに置くそうだ。"}],"6694":[{"rank":"3","note":"昼間から夕方まで出現","exp":"520","type":"気象・現象","name":"つるし雲","desc":"レンズ雲の一種で、楕円や鉢状など、さまざまな形をしている。山岳の頂上から離れたところに出現する雲を指す。雨天の前兆をといわれている。"}],"3892":[{"rank":"4","note":"ドイツで作られた星座","exp":"660","type":"天文","name":"いっかくじゅう座","desc":"冬の大三角にかかる位置にある星座。一角獣は額の上に一本の角を持つ、馬に似た動物とされる。この星座を誰が設定したかは諸説があって定かではない。"}],"6748":[{"rank":"5","note":"","exp":"","type":"伝承","name":"アイトワラス","desc":"バルト海東岸の都市で信仰されている蛇の精霊。一度家にすみつくと追い出しにくいが、家の者に富を授けると伝わる。部屋の中では黒猫や雄鶏、外ではドラゴンや尾の燃えているヘビなどに姿を変えるといわれる。"}],"5459":[{"rank":"5","note":"肉食獣が恐れるアリ<br/><br/>発見時経験値820　発見物カード経験値410","exp":"820","type":"虫類","name":"グンタイアリ","desc":"中南米の熱帯雨林に多く生息するアリ。一般のアリとは異なり軍隊のように隊列を組んで移動する。性格は獰猛そのもので、昆虫や鳥類などに集団で襲いかかり、瞬く間に食い殺してしまう。"}],"752":[{"rank":"4","note":"青い羽の生えた花","exp":"708","type":"植物","name":"クレロデンドルム","desc":"青く美しい花びらは、チョウや妖精に例えられるほどである。花が咲く様は、それらが寄り集まっているようにも見える。"}],"5741":[{"rank":"1","note":"","exp":"","type":"化石","name":"コブのある獣の化石","desc":"巨大なコブが頭蓋にある獣の化石。何のためのコブだったのかはわからないが、骨以外の器官が存在していたかもしれない。"}],"5372":[{"rank":"2","note":"発見経験値240 カード経験値120","exp":"240","type":"地理","name":"サモス島","desc":"エーゲ海東部の島。ギリシャ神話の女神ヘラが生まれた場所ともされ、ヘラを祀る神殿の遺跡がある。また、古代ギリシャを代表する数学者ピタゴラスの故郷でもある。"}],"6765":[{"rank":"4","note":"追究クエスト<br/>発見物カード:170","exp":"340","type":"地理","name":"ジェリーフィッシュレイク","desc":"パラオ諸島中部、マカラカル島にある塩湖。わずかな亀裂と洞穴により、外海と繋がるが生物の往来は隔絶している。ゴールデンジェリーフィッシュなどのクラゲが数百万匹も生息していることから名付けられた。"}],"92":[{"rank":"1","note":"エジプトの壁画の地図","exp":"97","type":"宗教遺物","name":"ラーの眼","desc":"エジプトの遺跡で見つかる、大きな目の形のまじない。太陽神ラーの眼を指すが、ラーの一部ではなくセクメト女神を表すとも言われる。"}],"1308":[{"rank":"3","note":"無数の瞳","exp":"462","type":"鳥類","name":"セイラン","desc":"人によく慣れ、飼育も容易な鳥。オスとメスは大変仲がよく、オスは長い尾羽を立てて揺らしメスを誘う。その姿は見るものを魅了する。"}],"1772":[{"rank":"5","note":"神が降り立つ湖","exp":"830","type":"地理","name":"チチカカ湖","desc":"標高3800mの位置にある湖。天空の湖とも呼ばれ、その昔、創造神であるヴィラコチャが降り立った湖と言い伝えられている。湖の周りには、多くの遺跡が残されている。"}],"1357":[{"rank":"5","note":"美しく奇妙な石","exp":"1170","type":"財宝","name":"魅惑の果実","desc":"淡い緑と鮮やかな赤が混在するトルマリン。その色味からスイカに例えられる。トルマリンは実にさまざまな色をもつ宝石であり、ひとつの原石に複数の色が混在しているものが多い。"}],"1297":[{"rank":"2","note":"輝くヘビ","exp":"320","type":"中型生物","name":"サンビームヘビ","desc":"光の加減で、虹のように輝くうろこを持つヘビ。土の中に巣穴をつくり、カエルや小型の哺乳類を食べる。"}],"5312":[{"rank":"2","note":"","exp":"","type":"小型生物","name":"レインボーアガマ","desc":"頭から背にかけてが赤色や黄色、背から尾の先までが青色や紫色の奇妙なトカゲ。昼行性で岩場などの開けた場所に生息している。"}],"3546":[{"rank":"","note":"","exp":"","type":"レリック","name":"ガリアの英雄","desc":"ガリア人を率いて果敢にカエサル率いるローマ軍と対したウェルキンゲトリクスは、フランス最初の英雄といってよいだろう。"}],"2374":[{"rank":"1","note":"イヌ顔の魚の地図","exp":"130","type":"海洋生物","name":"チンアナゴ","desc":"浅い海の底に生息する魚。チンという犬に顔が似ていることから、この名が付いた。\n群れになって砂の中から頭をのぞかせ、潮が流れてくる方向に顔を向けている姿がよく見られる。"}],"2367":[{"rank":"1","note":"浜辺に咲く花の地図","exp":"150","type":"植物","name":"ヒメハマナデシコ","desc":"海岸の砂浜や岩場に生育する、日本固有の植物。紅紫色の可憐な花を咲かせ、潮風に耐えつつ岩肌を彩る。"}],"353":[{"rank":"1","note":"泳げるドラゴン","exp":"170","type":"化石","name":"ヒレのあるドラゴンの骨","desc":"頭から体にかけては巨大なトカゲのようで、手足がウミガメのようなヒレになっている動物の骨。体長は2mほどで、石のように変化している。ヒレがあるのだから、海か湖にいたのだろう。なぜ陸で見つかったのだろうか。"}],"6173":[{"rank":"2","note":"","exp":"260","type":"財宝","name":"アルスター物語の写本","desc":"「アルスター物語群」とも呼ばれ、アイルランド神話の一つとされている伝承をまとめたもの。アルスター国の王や戦士たちの物語が多く収められており、物語のほとんどがキリストの生涯と同時代の出来事であるとされている。"}],"589":[{"rank":"1","note":"黒い水鳥の地図","exp":"39","type":"海洋生物","name":"ケープペンギン","desc":"頭からのどにかけて独特の模様があるペンギン。南アフリカに生息する。何羽いるのかわからないほどの大群で生息している。"}],"897":[{"rank":"2","note":"二本足で立ち上がる猫","exp":"210","type":"小型生物","name":"ミーアキャット","desc":"アフリカ南部に生息する、猫ほどの大きさの動物。集団で巣穴に住んでおり、器用に立ち上がってまわりを警戒する習性がある。"}],"5992":[{"rank":"2","note":"ファラオの装身具","exp":"220","type":"歴史遺物","name":"ラムセス2世の頭飾り","desc":"ラムセス2世は古代エジプトのファラオで、多数の建造物を作ったことで知られる。ラムセス2世の墓は墓泥棒に荒らされていたので所持品は珍しい。"}],"5469":[{"rank":"2","note":"発見時経験値210　発見物カード経験値105","exp":"210","type":"虫類","name":"ヒカリコメツキ","desc":"中南米に生息する夜行性の昆虫。\n発光する昆虫の中で最も強い光を放つといわれており、胸部にある白い斑紋から薄緑色、体の付け根から橙色を発光する。"}],"3830":[{"rank":"5","note":"東洋の占い道具","exp":"1130","type":"財宝","name":"式盤","desc":"東洋の占いの一種である式占で用いられる道具。円形の天盤と、方形の地盤で構成されている。二つの盤には文字や記号が記され、それらの配置を見ながら操作して、占いに必要な情報を得る。"}],"5721":[{"rank":"4","note":"2017.02.07新規追加","exp":"","type":"植物","name":"サラソウジュ","desc":"幹高が30mにも達する巨大な木。釈迦が入滅した際、その四方にこの木が二本ずつ生えていたといわれている。そのため二本一組で沙羅双樹と呼ばれるようになった。"}],"3689":[{"rank":"4","note":"ロシアの伝統楽器","exp":"750","type":"財宝","name":"グースリ","desc":"ロシアの伝統的な弦楽器。翼型、兜型、箱型と、時代を経るごとに形状や弦の数に改良が加えられた。\nロシアの吟遊詩人たちが使用したという。"}],"6729":[{"rank":"5","note":"","exp":"1210","type":"宗教建築","name":"バイヨン","desc":"アンコール遺跡の中央付近にある寺院跡。名はクメール語で「美しい塔」の意味。石材の質や積み方が統一されておらず、何代にも渡り王の命令で少しずつ建てられていったと見られる。中央の四面像など、塔の各所に掘られた人面像が有名。"}],"4847":[{"rank":"4","note":"蓼食う酒場娘も好き好き","exp":"770","type":"宗教遺物","name":"ムシュフシュの壁画","desc":"バビロンのイシュタル門に描かれている聖獣の図。ムシュフシュは都市神マルドゥクとその子ナブーの随獣として崇められている。"}],"2241":[{"rank":"2","note":"飼い主の心配","exp":"230","type":"小型生物","name":"ハナガエル","desc":"卵を口の中で育てる、変わったカエル。卵が成長すると、子ガエルが父親ガエルの口からはい出てくる。尖った頭と鼻が特徴。"}],"5761":[{"rank":"2","note":"2017.02.07新規追加","exp":"","type":"宗教遺物","name":"テルマ","desc":"チベット仏教に伝わる聖典群。パドマサンバヴァらが後世のために様々な場所に隠した霊的な宝物とされる。"}],"3844":[{"rank":"3","note":"危険生物調査","exp":"520","type":"大型生物","name":"グリズリー","desc":"北米に生息する大型のクマ。雑食で、木の実や植物の葉などを主に食べるが、ほかの動物も捕食する。巨体だが動きは俊敏で、足も速く泳ぎも得意。人を襲うこともあるため、注意が必要である。"}],"6903":[{"rank":"5","note":"","exp":"","type":"史跡","name":"大明宮遺跡","desc":"唐代の首都である、長安城の北東に建てられた大宮殿の跡。634年に建造され、政治の中心地となった。広大な丘陵をはじめ、多くの宮殿が建ち並んでいたが、戦火で全て消失した。"}],"654":[{"rank":"5","note":"女王の心","exp":"1079","type":"財宝","name":"ソウルオブクイーン","desc":"1000カラット以上ある大きなエメラルド。エメラルドは内包物やひびが多いものだが、この石は目立ったそれがなく、非常に透明度が高い。名前は、かのクレオパトラがエメラルドを好んだことにちなむようだ。"}],"5048":[{"rank":"2","note":"到達する","exp":"295","type":"港・集落","name":"グァテマラ","desc":"太平洋に面した中米の港街のひとつで、コーヒーの産地として知られる。沿岸の熱帯低地と、内陸の高原地帯では気温の差が激しい。"}],"5241":[{"rank":"5","note":"クエスト「予言された彗星出現」<br/>発見物カード:505","exp":"1010","type":"天文","name":"ハレー彗星","desc":"イングランドの天文学者エドモンド・ハレーが記録から周期的に現れることを予言した彗星。およそ76年ほどの周期で目撃され、時には大接近が記録されている。1066年のノルマン・コンクエストの前に現れた彗星もハレー彗星だとされる。"}],"2350":[{"rank":"2","note":"土中に眠る塊","exp":"360","type":"歴史遺物","name":"漆紙文書","desc":"読みは「うるしがみもんじょ」。紙に漆が染み込み、土の中でも腐らずに残ったもの。\n漆液は、保存時に紙蓋で容器を密閉する必要がある。だが、当時の日本では紙が貴重だったため、不要になった文書を蓋として用いていた。"}],"2544":[{"rank":"2","note":"淡水付近の地理調査","exp":"250","type":"地理","name":"淡水河","desc":"淡水近くを流れる穏やかな川。\n豊かな水量を誇り、台湾島北部の主要な水源である。"}],"1590":[{"rank":"1","note":"メソアメリカの鉢の地図","exp":"150","type":"歴史遺物","name":"無紋鉢","desc":"紋様のない鉢。アステカで見られる鉢は多くが土器のようだ。"}],"2062":[{"rank":"2","note":"［勅命］[[運河開通場所の地形調査","exp":"310","type":"地理","name":"グレートビター湖","desc":"カイロとスエズの狭間にある、比較的大きな湖。この他にも、小中の湖が存在しているらしい。これらの湖は、スエズ運河の一部となるだろう。"}],"3752":[{"rank":"4","note":"クエスト「天空の獅子」<br/>発見物カード:325","exp":"650","type":"天文","name":"しし座","desc":"黄道十二星座の1つ。ヘラクレスの12の冒険の最初に倒された、ネメアの獅子が天に上げられた姿とされる。ネメアの獅子の毛皮は武器で貫けず、ヘラクレスは3日間も獅子の体を締め続けて倒したという。"}],"2743":[{"rank":"2","note":"ある大名の兜の地図","exp":"365","type":"財宝","name":"変わり前立て","desc":"日本のある武将が身につけたといわれる兜。前面に「愛」と書かれた立物（たてもの）をつけている。立物は本来大将しか身につけられず、形も決まっていたが、近年は下級兵士にも開放され、意匠も多様化している。"}],"5060":[{"rank":"2","note":"到達する","exp":"270","type":"港・集落","name":"サンアントニオ","desc":"南米東岸、ブエノスアイレスの南、サンマティアス湾に位置する温暖な港街。さらに南にはパタゴニアという乾燥地帯が広がる。"}],"343":[{"rank":"1","note":"クエスト「医師の誓い」<br/>発見物カード:95","exp":"190","type":"歴史遺物","name":"医師の誓い","desc":"ギリシャの医聖ヒポクラテスが誓いを刻んだ石板。その誓いは、医学に生涯を捧げるという崇高なものである。当代きっての名医パレが所蔵していたもので彼自身も同時代の医学者たちに多大な影響を及ぼした。"}],"5045":[{"rank":"1","note":"到達する","exp":"76","type":"港・集落","name":"キルワ","desc":"東アフリカのスワヒリ海岸に位置する港町。季節風にのってやってくるアラブやペルシャ商人たちの一時的な居留地として次第に発展した。"}],"1706":[{"rank":"2","note":"風景画の地図","exp":"240","type":"美術品","name":"トレドの風景","desc":"エル・グレコ作の風景画。風景画は絵画としての価値をあまり認められないものだが、この絵が素晴らしいことは誰の目にも明らかだろう。彼は誰の依頼によるものでもなく、自分の意思によってこの絵を制作した。暗く明るい、不思議な絵だ。"}],"6770":[{"rank":"4","note":"発見物カード：340","exp":"680","type":"中型生物","name":"プンサンゲ","desc":"豊山犬。朝鮮固有の犬種で読み方は「プンサンゲ」。古くから猟犬として使われた。自身より大きな相手にも怯まないという。力が強く、一度咬みつくと放さないことで有名。"}],"5175":[{"rank":"1","note":"到達する","exp":"33","type":"港・集落","name":"リューベック","desc":"かつて、ハンザ同盟の中心都市として、「ハンザの女王」と呼ばれた街。非常に繁栄していたが、近年はアムステルダムなどに押されて、かつての勢いはない。鉱山資源が豊富にあるほか、塩が特産である。"}],"217":[{"rank":"1","note":"トゲだらけのネズミ","exp":"130","type":"小型生物","name":"ハリネズミ","desc":"背面にトゲが生えている小さな生物。目が小さく鼻がとがり、愛嬌のある顔をしている。捕まえようとすると、丸まってトゲだらけになる。動作は遅い。"}],"265":[{"rank":"1","note":"ブリテン西の小島","exp":"70","type":"地理","name":"マン島","desc":"アイリッシュ海北部に浮かぶ島。気候が穏やかなためか古代から人が住み、耕地が多い。ここにしかいない、尾のない猫が見られる。住人はケルト系の独特の言語を話す。"}],"5185":[{"rank":"2","note":"到達する","exp":"360","type":"港・集落","name":"堺","desc":"大阪湾に面した、交易の盛んな港街。商人たちの集まる、自由な気風の土地である。\nこの街の優れた経済構造に、日本の有力者も注目しているようだ。"}],"3650":[{"rank":"4","note":"北東航路の目印","exp":"790","type":"地理","name":"タイミル半島","desc":"北極海に大きく突き出た半島。半島の中央を山脈が走り、その東西の低地を河が流れる。永久凍土であるが、人が生活していた形跡がある。"}],"1613":[{"rank":"1","note":"人物画の地図","exp":"180","type":"美術品","name":"放蕩息子の酒宴","desc":"レンブラント作の人物画。聖書の一節、富豪の息子が娼婦と豪遊する場面を描いたといわれる。レンブラントらしからぬ明暗のはっきりしないタッチは、題材の向こうに現実的ななにかを見ているからかもしれない。"}],"503":[{"rank":"1","note":"古代ギリシャ遺物の地図","exp":"30","type":"歴史遺物","name":"古代ギリシャのつぼ","desc":"古代ギリシャ時代に作られたと思われるつぼである。ギリシャ神話のさまざまな場面が描かれている。"}],"6210":[{"rank":"3","note":"七不思議のはじまり","exp":"470","type":"歴史遺物","name":"世界の七つの景観","desc":"古代ギリシャの数学者フィロンの著作。当時の地中海世界に存在していた必見の建造物七つを紹介している。「世界七不思議」の元になったとされているが、彼が執筆時に居住していたアレクサンドリアにある大灯台は紹介していない。"}],"1272":[{"rank":"2","note":"クエスト「闘士の首を持つ男」<br/>発見物カード:170","exp":"340","type":"美術品","name":"ゴリアテの首を持つダヴィデ","desc":"グイド・レーニ作。羊飼いのダヴィデが、巨人ゴリアテを投石器で倒し、その首をとるという聖書の一節を表現している。古典的な構図でありながら、レーニの独特の斬新な表現を垣間見ることができる。"}],"6212":[{"rank":"4","note":"サルベージ","exp":"650","type":"歴史遺物","name":"マルス号","desc":"スウェーデンで建造された軍艦。バルト海でデンマーク、ドイツと激しい戦闘を行った際に大砲が暴発し、そのまま沈没した。"}],"3631":[{"rank":"5","note":"約束がくれた未来","exp":"1440","type":"史跡","name":"ザナドゥ","desc":"モンゴル高原南部の都市。元朝の皇帝が建設し、夏の間、都として政務を行った。\n『東方見聞録』では技術の粋を尽くした優美な都市と紹介され、多くの航海者の憧れの的となった。"}],"776":[{"rank":"3","note":"クエスト「船ほどもある巨大魚」","exp":"484","type":"海洋生物","name":"大カジキ","desc":"カジキは遠洋性の大型魚だが、この個体は並外れて大きい。口吻部が固くとがっている上に高速で泳ぐため、船に衝突すると沈没させられる。捕らえるのはとても無理だろう。"}],"5631":[{"rank":"4","note":"","exp":"710","type":"財宝","name":"ロシアンカーフ","desc":"18世紀頃にロシアで生産されていた皮革。トナカイの皮をなめした後に型押しし、木から抽出した油などを塗って仕上げてある。型押しで出来た小さな菱形の凸凹と、独特の仕上げ材の香りが特徴。"}],"1289":[{"rank":"2","note":"英雄の妃","exp":"330","type":"宗教遺物","name":"プラジューナーパーラミタ像","desc":"ジャヤヴァルマン7世の妃がモデルの像。頭部にアミターバ（阿弥陀如来）の化仏（けぶつ）が見られることから、仏像であることがうかがえる。"}],"5510":[{"rank":"1","note":"座標　16256,2488","exp":"15","type":"港・集落","name":"ポーツマス","desc":"ブリテン島南部の街。十字軍やフランスとの戦争において、軍港として機能した。その後の産業革命を経て造船業を中心に発展した。"}],"6363":[{"rank":"3","note":"","exp":"440","type":"虫類","name":"チリクワガタ","desc":"南アメリカに生息する大型のクワガタ。雄は巨大な顎が特徴。頭部が小さいため顎の挟む力は弱く、相手を投げ飛ばすために使う。性格は雌雄を問わず非常に好戦的。"}],"10":[{"rank":"1","note":"アスタロトの宝玉","exp":"100","type":"財宝","name":"アスタロトの宝玉","desc":"聖書のソロモン王が、悪魔や精霊72体を封じ込めたという宝玉の一つ。この宝石にはアスタロトが封じられているという。真偽の程は不明だ。\n宝玉はよく見ると傷があり、「西」と彫られている。"}],"5049":[{"rank":"2","note":"到達する","exp":"370","type":"港・集落","name":"グアム","desc":"マリアナ諸島の最南端に位置するグアム島の街。高温多湿の常夏で年中海水浴ができる。また、マゼランは世界周航の折、この地を訪れている。"}],"6495":[{"rank":"5","note":"レガシー　女神信仰のエフェソス　下","exp":"","type":"財宝","name":"エフェソスのコイン","desc":"古代都市エフェソスのコイン。女神アルテミスを象徴する鹿や蜂の意匠が刻まれている。交易の要所であったエフェソスは、巨大神殿の参拝者だけでなく商人やキリスト教の伝道者たちも訪れる、活気に満ちた街だったという。"}],"3608":[{"rank":"5","note":"海賊論<br/><br/>発見時経験値1110　発見物カード経験値555","exp":"1110","type":"財宝","name":"海賊の約定書","desc":"ある海賊がしたためた約定書。無法者の海賊たちが取り交わす約定に、どれほどの効力があるのかは不明。"}],"5657":[{"rank":"3","note":"","exp":"490","type":"財宝","name":"サロン","desc":"インドネシアの民族音楽「ガムラン」で用いられる楽器。半月形に盛り上った青銅板が金具で留めてあり、水牛の角や小さな木槌で打って演奏する。"}],"870":[{"rank":"2","note":"土地開発の期待","exp":"370","type":"地理","name":"ハドソン川","desc":"北米大陸東部を流れる大河。流れが緩やかで航行に適しているため地域の重要な交通路である。"}],"3651":[{"rank":"2","note":"スラブ地方の石版の地図","exp":"330","type":"宗教遺物","name":"スヴァローグのレリーフ","desc":"スラブ神話に登場する神の像。スヴァローグは太陽神・ダジボーグの父であり、かまどや火を司るとされた。"}],"456":[{"rank":"2","note":"襟の色","exp":"260","type":"中型生物","name":"エリマキキツネザル","desc":"襟を付けたような長い毛を持つ。白毛と赤毛の二種類がおり、そのどちらも、うるさいくらいの声で鳴く。果実をよく食べる。"}],"1870":[{"rank":"3","note":"神をかたどった黄金","exp":"500","type":"宗教遺物","name":"ナイムラップの黄金仮面","desc":"インカ以前にもランバイェケ周辺には高度な文明をもった都市国家が存在していた。ナイムラップとはこの都市国家で語り継がれている伝説的な王のこと。南方から船団で現れ、死して後は翼が生えて飛び去ったと伝えられている。"}],"6963":[{"rank":"1","note":"発見物カード:100","exp":"200","type":"史跡","name":"シリア北部の古代村落群","desc":"古代ローマ時代からビザンツ帝国時代にかけてシリア北部に存在した村落の遺跡。「忘れられた街」とも呼ばれる。豊かな農業生活を示す施設や、教会、防塁などが多く残されている。"}],"2417":[{"rank":"2","note":"ダンジョン","exp":"385","type":"宗教遺物","name":"ジェド柱","desc":"「永遠の安定」を象徴する柱。古代エジプトの神・オシリスの背骨ともいわれる。\n再生の力を意味し、壁画や護符という形で表現されている。"}],"6502":[{"rank":"5","note":"","exp":"","type":"美術品","name":"オリンピア大祭の勝者の像","desc":"オリンピアで4年に1回開催されていた競技祭で勝利した選手の像。勝者は神と並ぶ栄誉を与えられ、神域に自らの像を立てることを許された。参加資格はギリシャ人である男子に限られていたという。"}],"1869":[{"rank":"4","note":"風の大地に咲く花","exp":"620","type":"植物","name":"ノートロ","desc":"寒冷な風の大地、南米パタゴニアを代表する花。雪原や植物相の少ない土地で見る機会が多いためか、真紅の花が特に印象深い。連なる茎状の花が特徴。"}],"6409":[{"rank":"5","note":"","exp":"","type":"財宝","name":"天馬が刻まれた古代のコイン","desc":"カリア地方で使われていたらしい硬化。ペガサスの頭部が描かれている。アケメネス朝ペルシャは各地方に太守を置いて統治しており銀貨や銅貨は各太守によっても発行された。カリアは事実上の独立状態で、マウソロスが統治していた。"}],"3648":[{"rank":"5","note":"壺の正体","exp":"820","type":"美術品","name":"銅の手桶","desc":"12世紀頃に作製されたらしい銅製の桶。\nこの桶が作製されたであろう地域の名前と、年代が刻まれているが持ち主は不明だ。"}],"5018":[{"rank":"1","note":"到達する","exp":"60","type":"港・集落","name":"アルギン","desc":"エンリケ航海王子により商館が建設された、西アフリカの街。農業が盛んなほか、鉱物資源が豊富なようだ。"}],"5168":[{"rank":"1","note":"到達する","exp":"9","type":"港・集落","name":"ラグーザ","desc":"イタリア半島の東対岸にある街。古代ローマ人が街を作って以来、支配勢力が変わりながらも交易港として栄えてきた。各種農業が盛んで、多くの農作物やその加工品が流通している。"}],"4958":[{"rank":"1","note":"","exp":"","type":"歴史遺物","name":"クレタ島の陶器","desc":"古代のクレタ島で作られたとみられる陶器。風化のせいで色が薄くなってはいるが、よく見ればウシの絵が描かれているのがわかる。"}],"6191":[{"rank":"5","note":"","exp":"1110","type":"史跡","name":"ムティジュルの泉","desc":"ウルルのふもとにある池で、岩山から伝ってくる雨水によって、決して涸れることがないという。クニヤという名のニシキヘビの祖先が虹色の蛇に姿を変えて、今もなお池に棲むという伝承が現地人たちの間に残っている。"}],"6400":[{"rank":"5","note":"レガシー：砂漠に栄えた巨石文明","exp":"1500","type":"歴史遺物","name":"アル・アジーズの計画書","desc":"エジプトを支配したアイユーブ朝スルタンであるアル・アジーズの時代の書類。巨大な石積みを崩すための手法が書かれているとされる。アル・アジーズがピラミッドの破壊を試みた時の計画書かもしれない。"}],"2591":[{"rank":"2","note":"古代の装飾品の地図","exp":"380","type":"財宝","name":"人獣型耳飾","desc":"台湾島先住民の集落から発掘された耳飾り。人間の頭に獣が乗っている形をしており、人間と聖なる動物との関わりを示すという。"}],"6752":[{"rank":"5","note":"","exp":"","type":"天文","name":"タランチュラ星雲","desc":"かじき座にある星雲で大マゼラン雲の最先端に位置する。1751年、ラカーユが喜望峰へ遠征した時に初めて発見したとされる。"}],"3177":[{"rank":"2","note":"小さな鳥の地図","exp":"230","type":"鳥類","name":"アメリカコガラ","desc":"北米の北部に生息する小鳥。\n危険に敏感で、危険度によって鳴き声を使い分け、他種の鳥にも知らせているらしい。"}],"601":[{"rank":"1","note":"再生された聖典","exp":"190","type":"宗教遺物","name":"アヴェスター","desc":"ゾロアスター教の聖典である。原典はアレクサンドロス大王によって焼かれたが、その後再び編纂（へんさん）され、ササン朝の国教にされた。拝火教ともいい、死後の裁判、および終末の最後の審判などがある。"}],"2260":[{"rank":"4","note":"太平の果て","exp":"630","type":"地理","name":"グアム島","desc":"マニラの東、ニューギニアの北に位置する小さな島。マゼランが太平洋を航海して99日目に、初めて見つけた島だといわれている。"}],"5750":[{"rank":"5","note":"2017.02.07新規追加","exp":"1340","type":"地理","name":"マクドナルド諸島","desc":"オーストラリアの南西方向に位置する島々。岩で出来た小さな島であり、多数のアザラシやアシカなどが生息している。"}],"1243":[{"rank":"2","note":"大河の調査","exp":"330","type":"地理","name":"オリノコ川","desc":"南米北東岸に河口を持つ大きな川。調査は進んでいないが、かなり長大な川であると思われる。河口付近は、いくつもの支流に分かれている。"}],"5349":[{"rank":"5","note":"発見物カード:465","exp":"930","type":"天文","name":"たて座の散開星団","desc":"たて座にある散開星団で、かなりの数の星が密集している。"}],"1027":[{"rank":"1","note":"野生のオーロックスの調査","exp":"180","type":"大型生物","name":"オーロックス","desc":"家畜の牛の祖先だと思われる動物。肩までの高さが2m、オスの体重は1000kgにもなる。家畜の牛の牧草を確保するため追われ、今ではごく限られた地域にしかいないようだ。"}],"1302":[{"rank":"3","note":"浅瀬の王者","exp":"462","type":"海洋生物","name":"スナメリ","desc":"イルカによく似た膨らんだ前頭部が特徴。主に沿岸部に生息し、河口や川の上流部でも見られる。"}],"250":[{"rank":"1","note":"バレアレス諸島西部の調査","exp":"20","type":"地理","name":"イビサ島","desc":"バレアレス諸島の西部の島。古代から人が住み、アフリカとイスパニア間の中継点となっていた。青い空と海が美しい島である。"}],"4802":[{"rank":"3","note":"海面を飛ぶ生物の調査","exp":"460","type":"海洋生物","name":"トビイカ","desc":"暖かい海に住むイカの一種。敵に襲われたり、驚いたときに足を広げて翼の代わりとし、漏斗から海水を吹いて空を飛ぶことがある。 その距離が数十ｍに及ぶという。"}],"6834":[{"rank":"5","note":"追究クエスト<br/>発見物カード:440","exp":"880","type":"鳥類","name":"ゴイサギの幼鳥","desc":"ゴイサギの幼鳥は、褐色の翼に白い羽が反転のように入る。これが星のように見えるため「ホシゴイ」とも呼ばれる。成鳥とは外見が異なり、別の鳥と誤解されることもあるという。"}],"5818":[{"rank":"5","note":"","exp":"1370","type":"財宝","name":"金瓶梅","desc":"明代の通俗小説。水滸伝の番外編的作品であり、当時の生活や文化が窺い知れる緻密な描写が評価されている。"}],"1814":[{"rank":"2","note":"ダンテの長編叙事詩","exp":"280","type":"財宝","name":"神曲","desc":"イタリアの詩人、ダンテ・アリギエーリの長編叙事詩。地獄編、煉獄編、天国編の三部から成る。主人公はダンテ自身であり、地獄、煉獄を遍歴し、ついには天界に至るという内容。イタリア古典文学の代表作ともいえる一作である。"}],"6063":[{"rank":"2","note":"","exp":"210","type":"美術品","name":"聖クリストフォロス像","desc":"西ヨーロッパで伝えられている聖人、聖クリストフォロスを描いた絵。幼児の姿をしたキリストを背負った男性の姿で描かれ、水難や嵐、あらゆる旅の危険から守る聖人として、広く崇敬されている。"}],"5326":[{"rank":"2","note":"","exp":"220","type":"宗教遺物","name":"ニャミニャミ像","desc":"魚の頭と蛇の体を持つ神を模した像。現地の人々から信仰されており、ニャミニャミの怒りに触れた者には大いなる災いが訪れるという。"}],"5370":[{"rank":"2","note":"","exp":"300","type":"宗教建築","name":"ディオスクーリ神殿","desc":"ローマ最後の王であるタルクィニウス・スペルブスと共和政ローマが戦った際、ギリシャ神話の英雄のカストルとポルックスが共和政側に助力したという伝説により建てられた神殿。柱三本のみが現存する。"}],"6206":[{"rank":"4","note":"","exp":"630","type":"財宝","name":"カルタ・マリナ","desc":"16世紀のスウェーデン人司教、オラウス・マグヌスが作成した北欧の海図。各地の地形が詳細に描かれ、図中のところどころに珍しい生物や怪物も描かれている。古今東西の書物や、船乗りたちから丹念に聞き出した話をもとに作成したらしい。"}],"6600":[{"rank":"4","note":"","exp":"","type":"宗教遺物","name":"シヴァとパールヴァティーの石像","desc":"インド神話の創造と破壊の神シヴァと、妻であるパールヴァティーを模した石像。パールヴァティーはシヴァの膝に座り、足元には彼らを象徴する神聖な動物がいる。"}],"5350":[{"rank":"2","note":"","exp":"","type":"地理","name":"ヘクラ山","desc":"アイスランド南部にある火山。\nヘクラとは地元の言葉で頭巾を意味する。\nアイスランドで最も活動的な火山で、何度も噴火が記録されている。"}],"366":[{"rank":"2","note":"黄色く美しい円","exp":"275","type":"植物","name":"アステリスカス","desc":"整った円をした黄色い花。その形は、太陽のようでもあり、コインのようでもある。"}],"1113":[{"rank":"1","note":"中型のサルの地図","exp":"185","type":"中型生物","name":"チンパンジー","desc":"黒くて人間よりひとまわり小さなサル。群れで生活し、かなり高い知能を持つようだ。道具を使う個体もおり、もしかしたら人間にかなり近い動物なのかもしれない。"}],"6980":[{"rank":"5","note":"発見物カード:700","exp":"1400","type":"宗教建築","name":"ビビハニム・モスク跡","desc":"サマルカンドの統治者であるティムールが、妃ビビ・ハニームの名をつけたとされるモスク跡。かつては世界最大規模とされ、屋根や壁には東西文化の融合を示す青いタイルがふんだんに使われていたという。"}],"6509":[{"rank":"2","note":"","exp":"352","type":"史跡","name":"キロキティア","desc":"地中海の東部に浮かぶ巨大な島・キプロスにある先史時代の遺跡。遺跡内に残った石造りの土台は、円筒形の住居跡とされ、周りには集落を守るための外壁が張り巡らされていたとされる。"}],"2067":[{"rank":"1","note":"不気味な魚の地図","exp":"60","type":"海洋生物","name":"ウツボ","desc":"温暖で浅い海に生息。細長でヒレが小さく、太いヘビのような姿をしている。近くに敵が来ると口を大きく開けて威嚇し、鋭い歯で噛みつくこともある。\n体の模様や色は決まっておらず、多彩であるようだ。"}],"1283":[{"rank":"2","note":"ペグーの女王","exp":"280","type":"歴史遺物","name":"シンソープ女王の耳飾り","desc":"ペグー朝のシンソープ女王の耳飾り。シンソープ女王は自らの体重と等しい金箔を貼り付けてシュエジゴンパゴダを改修した。この耳飾りも、その力を誇示するように絢爛豪華できらびやかだが、女性らしい繊細さもうかがえる。"}],"6022":[{"rank":"2","note":"新郎の見栄にかけて","exp":"230","type":"財宝","name":"白砂糖のデザート","desc":"白砂糖「だけ」を材料に作られた、屋敷や城の模型。古くからヨーロッパ各地の王侯貴族たちの宴席で供されており、見て楽しんだ後に粉々にして列席者に振る舞われた。\n家の財力を誇示するため、豪華な装飾をつけることもあるようだ。"}],"5123":[{"rank":"1","note":"到達する","exp":"24","type":"港・集落","name":"ヒホン","desc":"ボルドーの西、ビスケー湾南岸にある小都市である。発祥は古代ローマ軍の軍営地だという。"}],"2770":[{"rank":"3","note":"ダンジョン","exp":"440","type":"宗教遺物","name":"地下墓地の棺","desc":"カタコンベに安置されている棺。カタコンベでは、壁に穴を掘るといった独特な埋葬方法を用いることが多く、棺を利用して埋葬する場合も穴の中に置かれていることが多い。"}],"5342":[{"rank":"4","note":"サルベージ","exp":"355","type":"歴史遺物","name":"ウィダ号","desc":"演説好きで知られる海賊、サミュエル・ベラミーの船。一味は積荷の酒で泥酔している隙を突かれ、捕虜に船を座礁させられ、一網打尽となった。"}],"1244":[{"rank":"2","note":"沈みかけの大地","exp":"370","type":"地理","name":"フロリダ半島","desc":"カリブ海とメキシコ湾の玄関口になっている半島。平坦な地形で、沼や湿地で覆われている。今にも海に沈んでしまいそうなほどだ。"}],"5013":[{"rank":"2","note":"到達する","exp":"290","type":"港・集落","name":"アチン","desc":"スマトラ島の北端に位置する街。マジャパヒト王国より独立した、アチェ王国の首都である。"}],"2735":[{"rank":"2","note":"謎の塔の歴史","exp":"350","type":"歴史遺物","name":"瞻星台","desc":"読みは、「せんせいだい」。新羅時代の末期に建てられたといわれる塔のようなもの。\n言い伝えでは、これは天文台であるらしく、占星術などに使われていたという。"}],"2796":[{"rank":"3","note":"幼い子供のお勉強","exp":"540","type":"美術品","name":"顧愷之の訓画","desc":"東晋の画家・顧愷之によって描かれた訓画。道徳書を絵画で表現したものである。\n教育のためか、後世において摸本が複数作成されたようだ。"}],"4867":[{"rank":"2","note":"クエスト「親子の間に横たわるもの」<br/>発見物カード:170","exp":"340","type":"天文","name":"りゅう座","desc":"ギリシャ神話に登場する竜が天に上ったとされる星座。この星座のいわれについては、黄金のリンゴを守るラドンのことを指すという説の他、さまざまな説がある。"}],"6375":[{"rank":"4","note":"発生時間短いです。夏でした。","exp":"690","type":"気象・現象","name":"スーパーセル","desc":"超巨大な積乱雲と、それが起こす激しい嵐のこと。豪雨や雷、大量の雹が長時間にわたって降る。水平方向に回転する空気が積乱雲を巨大化させ、上昇気流と下降気流の分離により嵐の持続時間がながくなる。"}],"6222":[{"rank":"5","note":"","exp":"1030","type":"地理","name":"ガッガル・ハークラー川","desc":"古代にはインダス川と並行して流れていたとされる川。今は雨季に流れるだけだが、「リグ・ヴェーダ」にもサラスバティー川として賛歌が残っている。一説にはヒンドゥー教の女神サラスバティーはこの川の神格化であるという。"}],"2885":[{"rank":"2","note":"小さなトカゲの地図","exp":"250","type":"化石","name":"翼の生えた小さなドラゴンの骨","desc":"雲台山近辺で見つかった、スズメほどの小さな生物の骨。細い翼や湾曲した脚のつま先がとても特徴的だ。"}],"1163":[{"rank":"2","note":"蛇をかたどった神像","exp":"330","type":"宗教遺物","name":"蛇の彫像","desc":"マヤによく見られる蛇の像。ガラガラヘビと思われる。ガラガラヘビは脱皮ごとに節が増えるため、時を重視したマヤ人たちに尊ばれたという。"}],"6269":[{"rank":"5","note":"","exp":"1030","type":"宗教遺物","name":"アヴァクームの書簡","desc":"ロシア古儀式派の指導者のひとりであった司祭、アヴァクームが信徒に送った書簡のひとつ。\n彼は皇帝アレクセイらによる教会の改革に異議を唱えて15年間投獄されており、当時の口語で自伝や書簡を記していたという。"}],"6728":[{"rank":"5","note":"楽の叡智・心に響く楽器　左上","exp":"","type":"財宝","name":"アウロス","desc":"古代ギリシャの木管楽器。本体は二本に分かれ、両手でそれぞれの指孔を押さえて演奏する。ギリシャ神話に登場する女神アテナが発明したという伝説がある。"}],"5056":[{"rank":"1","note":"到達する","exp":"175","type":"港・集落","name":"ゴア","desc":"インド西岸にある街。交易で栄えており、高価な香料や染料、宝石が産物として扱われている。また、鉄鉱石が豊富に産出する。"}],"182":[{"rank":"2","note":"セイロン島の最南端","exp":"250","type":"地理","name":"ドンドラ岬","desc":"セイロン島最南端に位置する岬。島の人間もめったに近寄ることはないようだ。"}],"6050":[{"rank":"3","note":"","exp":"490","type":"宗教建築","name":"聖カタリナ修道院","desc":"シナイ山のふもとにある修道院。ビザンツ帝国の初期に建造され、古代の写本や聖像破壊運動より前の時代のイコンが残っていることで名高い。十字軍が滞在して以来、重要な巡礼地の一つとされているようだ。"}],"2263":[{"rank":"3","note":"クエスト「可愛い変わり者」<br/>発見物カード:245","exp":"490","type":"鳥類","name":"アオアシカツオドリ","desc":"鮮やかな青い足が特徴の体長80cmほどの鳥。オスがメスに向かって足を交互に持ち上げたり、翼を広げたりして興味をひく様が見られる。主にガラパゴス諸島に生息する。"}],"6876":[{"rank":"2","note":"","exp":"","type":"海洋生物","name":"ムラサキカムリクラゲ","desc":"世界中の深海に生息する、クラゲの一種。円盤状の傘の周りに、20本を超える長い触手を持つ。外敵に襲われそうになると体から強い光を放ち、その光で外敵にとっての敵を呼び集めるという珍しい習性を持つ。"}],"5860":[{"rank":"4","note":"発見物カード:350","exp":"700","type":"天文","name":"北アメリカ星雲","desc":"はくちょう座の尾部にある散光星雲。形が北米大陸に似ていることから名付けられた。暗いため、肉眼での観測は困難である。"}],"1058":[{"rank":"1","note":"楔文字の遺物の地図","exp":"64","type":"歴史遺物","name":"楔形文字の石板","desc":"「くさびがたもじ」。楔形文字が刻まれた石板。楔形文字は古代メソポタミアを中心として用いられた。石板に刻んだということは、長期間残す目的で作られたのだろう。"}],"416":[{"rank":"1","note":"奇妙な石の地図","exp":"34","type":"化石","name":"二本足のトカゲの骨","desc":"大きなトカゲの骨の模様の石。二本足で立っていたと思われる。人間より小さいが、もし襲われたら無事ではすまないだろう。こんな生物がどこかにいるのだろうか？"}],"4814":[{"rank":"","note":"楽山大仏 （中層隠し部屋）","exp":"","type":"歴史遺物","name":"藩鎮帳","desc":""}],"5240":[{"rank":"4","note":"神殿の真実","exp":"640","type":"史跡","name":"アルテミス神殿跡","desc":"紀元前から紀元3世紀ごろにかけて存在した神殿。女神アルテミスを奉った総大理石の神殿であったが、放火や破壊に遭い、現在は原型を留めていない。世界七不思議の一つ。"}],"299":[{"rank":"5","note":"ミュケナイの王","exp":"1144","type":"歴史遺物","name":"アガメムノンの黄金の仮面","desc":"ギリシャ神話に登場する、ミュケナイ王・アガメムノンの副葬品ではないだろうか。イリアスは絵空事ではなくアガメムノンもアキレウスも実在したに違いない！"}],"1270":[{"rank":"3","note":"姿を見せない生物<br/><br/>発見時経験値511　発見物カード経験値255","exp":"511","type":"中型生物","name":"オセロット","desc":"名前は「野生の虎」を意味する現地の言葉に由来する。森林地帯や乾燥した荒地など、様々な環境に生息する。主に地上で活動するが木登りも得意である。その姿はなかなか目撃できない。"}],"5828":[{"rank":"5","note":"","exp":"1600","type":"財宝","name":"マンモスの牙の笛","desc":"マンモスの牙で作られた笛。現存する中では世界最古の管楽器である。"}],"4850":[{"rank":"4","note":"ダ・ヴィンチ氏からのおつかい<br/><br/>発見時経験値760　発見物カード経験値380","exp":"760","type":"史跡","name":"テペ・ガウラ","desc":"古代メソポタミアの考古遺跡。新石器時代から高アッシリア時代まで、幅広の年代の住居が残っている。また、ギリシア建築やイタリア建築にみられる付け柱とアーキボルトで裝飾された世界最古の神殿がある。"}],"6460":[{"rank":"5","note":"追求クエスト<br/>発見物カード500","exp":"1000","type":"地理","name":"ヴァッレ・デル・ボーヴェ","desc":"シチリア島火山、エトナ山の東斜面にある大きなくぼ地。エトナ山はヨーロッパで最も高い活火山だが、標高が頻繁に変わるほど火山活動が活発だとされる。このくぼ地ができた原因も噴火なのか、大規模な山崩れや陥没なのか、諸説ある。"}],"3939":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:165","exp":"330","type":"天文","name":"かみのけ座の渦巻星雲","desc":"かみのけ座にある渦巻きのような形をした星雲。はっきりとした黒い雲を伴うのが特徴である。"}],"2354":[{"rank":"2","note":"学問の神","exp":"390","type":"歴史遺物","name":"菅公の御霊廟","desc":"読みは「かんこうのごれいびょう」。菅公とは、菅原道真のことを指す。\n恨みを抱いて死んだとされる道真は、かつては祟りをもたらすと恐れられていた。現在は学問の神として祀られている。"}],"3745":[{"rank":"2","note":"クエスト「北極星とひしゃく」<br/>発見物カード:185","exp":"370","type":"天文","name":"北斗七星","desc":"7つの星がひしゃくの形を作る、北斗星の目印として有名な星列。2等星が6つ、3等星1つと明るい星が多く、見つけやすい。世界各地で様々な神話が作られている。"}],"3656":[{"rank":"3","note":"別の原初年代記","exp":"550","type":"財宝","name":"イパーチー写本","desc":"15世紀に編纂された、『原初年代記』の写本のひとつ。\n原本だけでなく、その後に編纂された書物からも情報が追加されているようだ。"}],"2971":[{"rank":"2","note":"太陽の花","exp":"260","type":"植物","name":"ドルステニア・フォエチダ","desc":"アラビア半島原産の多肉植物。太陽のような形をしたものの中心には、ごく小さな雄花と雌花が多数集まっている。"}],"2898":[{"rank":"2","note":"変わった鳥の地図","exp":"220","type":"鳥類","name":"コジュケイ","desc":"中国南部や台湾島に生息する、変わった鳴き声を持つ鳥。\n用心深い性格で、めったに姿を見せない。早朝になると群れで餌を探しに行くようだ。"}],"1975":[{"rank":"4","note":"歌うネズミ","exp":"740","type":"小型生物","name":"デグー","desc":"ネズミをひと回り大きくしたような、リスに似た動物。多彩な鳴き声で仲間と交流する姿は、歌を歌っているように見える。警戒心がないのか、人によくなれる。寒冷なアンデス高地の、岩場や断崖に生息する。"}],"485":[{"rank":"1","note":"古代インドの印章の地図","exp":"120","type":"歴史遺物","name":"インダス式角型印章","desc":"インダス文明で使われていた角型の印章。幾何学模様や動物などの図柄と共に、インダス文字が記されている。"}],"2988":[{"rank":"4","note":"壮大なる水<br/><br/>発見時経験値680　発見物カード経験値340","exp":"680","type":"地理","name":"イグアスの滝","desc":"およそ4kmという幅を持つ、南米の大滝。\nイグアスとは現地の言葉で「壮大なる水」という意味である。世界最大級の幅で流れ落ちる奔流の様子は、名に違わず圧巻である。"}],"3670":[{"rank":"5","note":"ダンジョン","exp":"1010","type":"歴史遺物","name":"ハトシェプスト女王の像","desc":"古代エジプト最初の女性ファラオであるハトシェプストは、破壊されていたカルナック神殿を修復し、巨大なオベリスクを始めとする建築物を増築した。その際にこの像が作られたと考えられる。"}],"6531":[{"rank":"5","note":"レガシー星の叡智　左下","exp":"1500","type":"財宝","name":"アーミラリー天球儀","desc":"複数の金属輪を接続した天球儀。輪はそれぞれ赤道、子午線、緯線などを示す。当初は地球の周囲を回る天体の動きを表していたが、のちに太陽が中心に置かれた。望遠鏡の登場以前は広く使われ、知性の象徴とされていたらしい。"}],"6443":[{"rank":"2","note":"クエスト「2つの空に挟まれて」<br/>発見物カード:120","exp":"240","type":"地理","name":"ウユニ塩湖","desc":"かつてアンデス山脈が隆起した際、取り残された大量の海水によって形成された広大な塩原。雨が降ると冠水して湖のようになり、水面が空を映し出すため「天空の鏡」とも呼ばれる。"}],"5083":[{"rank":"1","note":"到達する","exp":"6","type":"港・集落","name":"セウタ","desc":"紀元前にフェニキア人によって築かれたと伝えられる街。その後イスラムの支配下にあったが、15世紀初めにポルトガルが奪った。バジルなどが作られているほか、近海でサンゴが採れる。"}],"1045":[{"rank":"1","note":"流行した宗教画","exp":"110","type":"美術品","name":"聖ドニの殉教","desc":"アンリ・ベルショーズ作の祭壇画。当時、金地に鮮やかな色彩で描く手法が流行し、これもそれにならった作風である。"}],"5595":[{"rank":"2","note":"","exp":"300","type":"地理","name":"レッドベイ","desc":"北米大陸北東部に位置する湾。天然の良港であり、捕鯨などの基地として利用される。"}],"6365":[{"rank":"3","note":"","exp":"440","type":"宗教建築","name":"ブッダガヤの大菩提寺","desc":"インドの北東部にある巨大な寺院。瞑想の末に釈迦が悟りを開いた場所とされる。52mもの高さの塔はレンガ造りで九つの層があり、その頂上の四方に小塔が立つ「五堂形式」となっている。"}],"1536":[{"rank":"1","note":"古代の集落の地図","exp":"140","type":"歴史遺物","name":"古代の水田跡","desc":"インドシナ半島沿岸は水量の豊かな川が多く流れ、古代から稲作が盛んだった。これがいつごろのものか特定できれば、この地域に人が住み始めた時期も分かるのだろうが…。"}],"821":[{"rank":"1","note":"大理石の調度の地図","exp":"61","type":"財宝","name":"大理石のテーブル","desc":"大理石を使った豪華なテーブル。美しい装飾が施されている。相当な財力がなければ、こんな調度品はそろえられないだろう。"}],"5145":[{"rank":"2","note":"","exp":"342","type":"港・集落","name":"ホロ","desc":"15世紀半ば、このホロを中心にスールー王国というイスラム王国が誕生した。近年、イスパニアが同地域に進出しているが、スールー王国の強い抵抗に遭っている。"}],"5186":[{"rank":"2","note":"到達する","exp":"345","type":"港・集落","name":"安平","desc":"読みは「アンピン」。台湾島の政治や軍事の中心地である街。\n船を停泊させるのに適した場所と判断され、大きな港になった。"}],"4860":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:155","exp":"310","type":"天文","name":"みずがめ座の丸い星雲","desc":"みずがめ座にある環状の星雲。天体望遠鏡では、あまり明るくはないが、大きく見える。"}],"469":[{"rank":"1","note":"穴を掘る動物の地図","exp":"13","type":"中型生物","name":"アナグマ","desc":"クマのような、タヌキのような、ずんぐりした動物。穴を掘って群れで生活し、その巣穴はあまりに広くて調査できないほどである。"}],"602":[{"rank":"5","note":"最高の黒真珠","exp":"990","type":"財宝","name":"ピーコックカラー","desc":"虹色に輝く、最上級の黒真珠。真円でこの色を持つものは、非常に希少である。"}],"5534":[{"rank":"1","note":"発見時経験値180　発見物カード経験値90","exp":"180","type":"気象・現象","name":"月虹","desc":"通常の虹とは異なり、夜間の月の光によって生じる虹。月光は太陽光よりも弱いため、白みがかって見える。通常の虹と同様、降雨後の発生が多い。"}],"2116":[{"rank":"2","note":"［勅命］[[ある調査の追加調査","exp":"310","type":"歴史遺物","name":"コロン提督の手記","desc":"ポルトベロに到達したコロン提督による報告書の一部。どうやら調査の途中で紛失してしまった物のようだ。"}],"5197":[{"rank":"2","note":"到達する","exp":"350","type":"港・集落","name":"雲台山","desc":"読み方は、「ユンタイシャン」。春秋時代には越の王・勾践がこの地を首都とした、歴史のある街。平坦な地が続く農作地で、茶の産地としても有名。"}],"3785":[{"rank":"3","note":"発見物カード:225","exp":"450","type":"天文","name":"プロキオン","desc":"シリウスやベテルギウスと共に冬の大三角を構成する星。こいぬ座に属する星で、名は犬の先駆けという意味。古代エジプトでは、洪水を知らせるシリウスに先立って昇るとして重視された。"}],"376":[{"rank":"2","note":"海から生まれた女神","exp":"300","type":"美術品","name":"ヴィーナスの誕生","desc":"ボッティチェリ作の絵画。ヴィーナス、つまりギリシャ神話のアフロディテが、海の泡から生まれたときの様子を描いている。左の二人はゼフュロスとフローラ、右は時の女神のホーラである。"}],"1923":[{"rank":"1","note":"凛々しい目つきの鳥","exp":"180","type":"海洋生物","name":"イワトビペンギン","desc":"目の上に黄色い飾り羽があるペンギン。群れで生活し、岩場を器用にジャンプしながら移動する。陸上での動作はにぶいが、水中では魚のように泳げる。"}],"5000":[{"rank":"2","note":"","exp":"","type":"地理","name":"コーカサス山脈","desc":"ギリシャ神話にも登場する巨大な山脈。黒海からカスピ海にかけて高山が連なっており、地域によって景観の変化が大きい。"}],"6975":[{"rank":"5","note":"発見物カード:550","exp":"1100","type":"宗教建築","name":"黄陵廟","desc":"長江のほとりにある寺院。夏王朝の王、禹の治水を助けた神牛を祀るための廟であり、その歴史は春秋時代にまで遡るという。創建の由来にちなんで当初は「黄牛廟」と呼ばれていた。"}],"1751":[{"rank":"5","note":"驚天動地","exp":"1209","type":"中型生物","name":"カモノハシ","desc":"カワウソのような体にカモのくちばしを持つ生物。卵を産み、孵化した子を、母乳で育てる。オスは後ろ足にある蹴爪から敵に毒を打ち込むことができる。"}],"2261":[{"rank":"5","note":"遥かなるハワイキ","exp":"1070","type":"地理","name":"マルキーズ諸島","desc":"タヒチ島から約1500km北東の海域に位置する南太平洋の諸島。\n先住民の言葉で諸島の名前を、テ・ヘヌア・エナナという。"}],"6554":[{"rank":"5","note":"追究クエスト","exp":"1760","type":"化石","name":"角のような貝の化石","desc":"北米の金鉱掘りが、金脈を探している際に偶然見つけた化石。そのとてつもない大きさから、見つけた当人は竜の角の化石と言い張っているが…恐らく巨大な直角貝の化石と思われる。"}],"1662":[{"rank":"2","note":"書きかけの地図","exp":"210","type":"地理","name":"マカッサル海峡","desc":"カリマンタン島と、セレベス島の間に横たわる海峡。古くからの交通の要衝であり、特にマカッサルは巨大な港を持ち、交通の要として栄えている。"}],"5691":[{"rank":"5","note":"2017.02.07新規追加","exp":"1340","type":"地理","name":"サラミス島","desc":"エーゲ海に位置する島の一つ。サラミスの海戦の際、ギリシャ艦隊の集結地となった。"}],"384":[{"rank":"3","note":"害をなす猛獣","exp":"484","type":"大型生物","name":"人食いトラ","desc":"トラの中でも特に凶暴で、人を襲うもの。体重が300kg近くありそうな、トラの中でも特に体の大きな個体だ。トラはもともと森の奥深くに生息する動物だが、容易に捕まえられる人間を狙うようになり、人里近くに現れたのだろう。"}],"6270":[{"rank":"1","note":"","exp":"130","type":"鳥類","name":"ステラーカケス","desc":"カナダから北米西岸にかけて生息する鳥で、山岳地帯に多く見られる。\n雑食性で果実や虫、鳥の卵などを食べる。頭に黒く立派な冠羽を生やしているが、首から下の羽毛は鮮やかな青で、鳴き声はやや騒がしい。"}],"6020":[{"rank":"2","note":"税金代わり","exp":"300","type":"中型生物","name":"永州の異蛇","desc":"えいしゅうのいだ。中唐の詩人・柳宗元の書いた「捕蛇者の説」に記述があるヘビ。植物を枯らし、人が噛まれればひとたまりもないほどの猛毒を持つ。難病に効く薬の原料になるともされ、租税の代わりに納められていた時代もあるという。"}],"6062":[{"rank":"1","note":"到達する","exp":"180","type":"港・集落","name":"マンガロール","desc":"インド南西部の港湾都市。古くから重要な港であり、多くの王朝が支配権を争った。都市内にあるマンガラデーヴィー寺院と同じく、ヒンドゥー教の神の名に由来する。"}],"6814":[{"rank":"5","note":"追究クエスト<br/>発見物カード:470","exp":"940","type":"小型生物","name":"夏毛のユキウサギ","desc":"夏毛になったユキウサギ。茶褐色の毛は、灌木などに隠れるのに適している。冬になるにつれて、毛が生え変わり、全身が白くなる。"}],"6513":[{"rank":"5","note":"レガシー競技の聖地オリンピア　左下","exp":"2145","type":"財宝","name":"オリーブ冠","desc":"オリンピア大祭で各競技の優勝者に与えられた冠。特別なオリーブの若木を編んで作られている。参加者は、この冠と名誉だけを賞品として競い合った。その精神に敵対していたペルシャ人たちも感嘆したと伝わる。"}],"1893":[{"rank":"2","note":"［勅命］[[ある調査の追加調査","exp":"310","type":"歴史遺物","name":"コロン提督の手記","desc":"ポルトベロに到達したコロン提督による報告書の一部。どうやら調査の途中で紛失してしまった物のようだ。"}],"3553":[{"rank":"","note":"","exp":"","type":"レリック","name":"アラジンと魔法のランプ","desc":"アラジンのランプや指輪に宿る魔人は、イスラム教誕生以前の時代に神に準じる存在で、崇拝の対象だったといわれる。"}],"6329":[{"rank":"3","note":"","exp":"480","type":"虫類","name":"アズチグモ","desc":"アジアに広く生息するクモ。つり上がったような形の目が特徴的。雌は体が白色でまだら模様があり、周囲の環境に合わせて体色が変化する。また雄の三倍ほど大きい。雄の体は褐色で雌には似ていない。"}],"1969":[{"rank":"3","note":"白ひげ鳥<br/><br/>冒険経験470　カード経験235","exp":"470","type":"鳥類","name":"インカアジサシ","desc":"南米の西岸に生息する海鳥。濃い灰色の体に赤いくちばし、口ひげのような白い飾り羽根が特徴。何千羽という群れで生活し、海岸の岩場で集団で佇んでいるのがよく見られる。上空から海へ一直線に飛び込み、上手に魚を捕まえる。"}],"5864":[{"rank":"5","note":"発見物カード:685<br/>　","exp":"1370","type":"天文","name":"おおぐま座の細長い銀河","desc":"おおぐま座にある、細長い形状で観測される銀河。肉眼での観測は難しいため、専門の機具を用いて観測する必要がある。"}],"6608":[{"rank":"2","note":"レガシーテーマ　美の叡智・伝承のレガリア獲得","exp":"350","type":"歴史遺物","name":"アルダシール1世のレリーフ","desc":"ペルシャ湾北岸にある巨岩に刻まれたササン朝時代の巨大なレリーフ。アフラマズダー神から王権の象徴を授受されるアルダシール1世が描かれている。"}],"6735":[{"rank":"3","note":"発見物カード:255","exp":"510","type":"天文","name":"エルナト","desc":"おうし座で2番目に明るい星で、北側の角の先端に位置する。名前の由来はアラビア語で「角で突くこと」。おうし座とぎょしゃ座の間にあるため、一時期ぎょしゃ座の星とされていたこともある。"}],"1647":[{"rank":"5","note":"星を見る島","exp":"949","type":"地理","name":"ラパ・ヌイ","desc":"太平洋の東側に存在する、絶海の孤島。沿岸に巨大な像が屹立していることから、ここが「星を見る島」であることは間違いない。ラパ・ヌイとは現地の言葉で「大きい島」という意味。"}],"1936":[{"rank":"4","note":"アステカの冥府に眠る神","exp":"620","type":"宗教遺物","name":"ミクトランテクトリ像","desc":"ミクトランテクトリとはアステカの神話における冥府の主のことである。血まみれの骸骨や歯をむき出しにした姿など、どれも恐ろしい姿として描かれる。"}],"541":[{"rank":"1","note":"古代の墳墓の地図","exp":"38","type":"歴史遺物","name":"黄金の副葬品","desc":"墓に故人と共に納められた黄金の副葬品。多くの場合、死後の生活のためにと、生前使っていた物や豪華な物が納められる。"}],"5652":[{"rank":"2","note":"クエスト「続・科学の星座」<br/>発見物カード:190","exp":"380","type":"天文","name":"ポンプ座","desc":"ラカーユが制定した南天の星座のひとつ。真空のポンプをモデルにしている。"}],"3316":[{"rank":"4","note":"戴冠の地<br/><br/>発見時経験値750　発見物カード経験値375","exp":"750","type":"史跡","name":"ガムラ・ウプサラ","desc":"ストックホルムより北に位置する地域名。\n中世まで北欧の中心地として栄え、歴代のスウェーデン王の墳墓と居城があった。近くには北欧最古のウプサラ大学があり、グスタフ2世アドルフの右腕であるオクセンシェルナなどを輩出している。"}],"1004":[{"rank":"3","note":"北米沿岸の調査","exp":"528","type":"地理","name":"ロングアイランド","desc":"北米大陸の東部にある細長い島。かなり大きな島で、長さは200km近い。住んでいる民族はアルゴンキンというそうだ。"}],"1282":[{"rank":"2","note":"浮き彫りの石","exp":"280","type":"歴史遺物","name":"押し型","desc":"土器でできた、紋様をつけるための押し型。多くの紋様がデザインされたようだ。"}],"6194":[{"rank":"5","note":"伝承航路","exp":"1660","type":"伝承","name":"アレクサンドリア大灯台","desc":"プトレマイオス1世の時代にエジプトのアレクサンドリアに建造された灯台。ファロス島の大灯台とも呼ばれ、ギザの大ピラミッドに次ぐほどの高さを誇ったが数度の地震によって倒壊した。"}],"6386":[{"rank":"","note":"","exp":"1150","type":"伝承","name":"ペリの羽衣","desc":"ペルシャに伝わる精霊ペリが持つとされている羽衣。この羽衣をまとうと鳩の姿になれるといい、ペリが下界で水浴びを楽しんでいたところ、人間の男に羽衣を奪われ、強引に妻にされてしまった伝承がある。"}],"3915":[{"rank":"2","note":"天文学者の観測記録<br/><br/>発見物カード:140<br/>　","exp":"280","type":"天文","name":"いて座の三つに裂けた星雲","desc":"いて座にある星雲。明るい雲が、黒い雲で三つに分かれているように見える。"}],"6296":[{"rank":"1","note":"","exp":"200","type":"中型生物","name":"細犬","desc":"中国産の猟犬。ほっそりとした姿が特徴。古代の絵画にも、細犬と思われる犬の姿が描かれていることがある。"}],"4998":[{"rank":"2","note":"テラ・ノヴァ沖　視認<br/>「天文学者の観測記録」<br/>発見物カード:145","exp":"290","type":"天文","name":"ケフェウス座の花のような星雲","desc":"ケフェウス座の腰にあたる星の近くにある星雲。雲の形状が美しい青い花を思わせる。"}],"1742":[{"rank":"1","note":"古い法典の地図","exp":"160","type":"宗教遺物","name":"法華経","desc":"ほっけきょう。仏教経典のひとつ。全てのものは縁起をもって仏たりえるという、仏教独自の因果関係について書かれている。"}],"6032":[{"rank":"5","note":"","exp":"990","type":"化石","name":"顎が大きな魚の頭骨","desc":"強靭な顎を持つ、巨大な生物の頭骨。非常に重厚な骨で覆われている。魚のようであるが、体の後部の骨は見つかっていない。"}],"1991":[{"rank":"2","note":"釣り","exp":"350","type":"海洋生物","name":"バラマンディ","desc":"東南アジアからオーストラリア沿岸に広く分布する巨大なスズキの一種。"}],"3672":[{"rank":"3","note":"手に取れない花","exp":"470","type":"植物","name":"セイヨウオニシバリ","desc":"南ヨーロッパからロシアに至るまで、広く分布する低木。早春に花を咲かせる。果実や枝には毒を持っている。"}],"5085":[{"rank":"1","note":"到達する","exp":"42","type":"港・集落","name":"セヴァストポリ","desc":"黒海に面し、クリミア半島に位置する港湾都市。"}],"2875":[{"rank":"2","note":"勝敗決する詩文","exp":"290","type":"歴史遺物","name":"乙支文徳の詩文","desc":"乙支文徳は、高句麗の将軍。\n隋軍が攻めてきた時、乙支文徳は停戦を促すこの詩文を送った。\n隋軍が油断したところで反撃に出、そのまま隋軍を追い払い、国を守った。"}],"5322":[{"rank":"3","note":"","exp":"","type":"史跡","name":"ツォディロの岩絵","desc":"カラハリ砂漠の丘陵地帯にある岩に描かれた絵。非常に狭い範囲に鮮やかな数千もの絵が描かれており、この地の歴史を知る手がかりとなりそうだ。"}],"1096":[{"rank":"2","note":"カリブの果て","exp":"375","type":"地理","name":"ユカタン半島","desc":"キューバ島につらなるように突き出した大きな半島である。石灰岩質だが熱帯性の気候で雨量が多く、耕作は可能だろう。内陸には巨大な建造物のようなものが見える。強大な勢力が存在するのだろうか…。"}],"1976":[{"rank":"5","note":"森の小さなおじいさん","exp":"1020","type":"小型生物","name":"コウテイタマリン","desc":"南米北部の熱帯の森林に棲む、小さなサル。立派な髭をたくわえた姿から「皇帝」の名前がついた。樹上で生活し、果物を食べる。"}],"7017":[{"rank":"3","note":"","exp":"","type":"歴史遺物","name":"内乱記","desc":"ユリウス・カエサルがローマ内戦の経過を報告書としてまとめた著作。「ガリア戦記」に続く作品にあたる。紀元前49年から約二年\nにわたり、内戦初期の状況を簡潔な筆致で克明に記録している。"}],"6297":[{"rank":"1","note":"","exp":"200","type":"史跡","name":"ワカ・プクヤーナ","desc":"リマにある古代遺跡。日干しレンガを縦に積み重ねた、大きなピラミッドがある。かつて辺り一帯を治めていた宗教都市であり、数々の祭事が行われていたとされる。"}],"6964":[{"rank":"2","note":"発見物カード:140","exp":"280","type":"地理","name":"ルシェルシュ諸島","desc":"オーストラリア南西に位置する諸島。約100の島と1000を超える小島からなる。島の原始林や美しい海には、地域固有の生物も多く、さまざまな種を観察できる。"}],"1443":[{"rank":"5","note":"追跡再び","exp":"910","type":"中型生物","name":"カンガルー","desc":"最大の大きさを誇る有袋類。その大きさはワラビーの倍以上で、一度の跳躍で8m以上も移動する。群れで生活しオス同士はケンカをする。その際、太い尾で体を支えながらの蹴りが大きな武器となる。"}],"1898":[{"rank":"1","note":"サルベージ","exp":"120","type":"歴史遺物","name":"バルバリーゴの貿易船","desc":"ニコロ・バルバリーゴが指揮していたガレー商船団の一隻。\nアレクサンドリアを出発しクリスマスのヴェネツィアへ向かう途中ウルボ島付近で沈没。"}],"6480":[{"rank":"5","note":"レガシー港湾都市ロードス　左上","exp":"1650","type":"財宝","name":"攻城者デメトリオスのコイン","desc":"戦に長け、攻城者の異名を持つデメトリオス1世のコイン。アレクサンドロス大王没後のディアドコイ戦争で活躍したが、ロードス包囲戦では島民の抵抗に遭って撤退。島民は彼らの残した武具を利用し、戦勝記念の巨像を建てたという。"}],"2328":[{"rank":"2","note":"説話集の地図","exp":"230","type":"財宝","name":"今昔物語集","desc":"読みは「こんじゃくものがたりしゅう」。日本・インド・中国の説話が千話以上収められた日本の書物。\n話の書き出しが、すべて「今は昔」となっているのが特徴である。"}],"1301":[{"rank":"2","note":"島に棲むサル","exp":"320","type":"中型生物","name":"テングザル","desc":"ボルネオ島に生息するサル。オスは大きく垂れ下がった鼻を持つ。水辺を好み、足には水かきがある。"}],"804":[{"rank":"1","note":"大きな木の地図","exp":"47","type":"植物","name":"ナナカマド","desc":"目の詰まった硬い木でかまどで7回燃やしても燃え尽きないといわれる。木工細工によく用いられる。秋になると美しく紅葉する。"}],"5140":[{"rank":"1","note":"到達する","exp":"73","type":"港・集落","name":"ベンゲラ","desc":"大西洋に面し、アフリカ南西に位置する街。近くを流れる海流の影響で、近郊の土地は乾燥している。"}],"5157":[{"rank":"1","note":"到達する","exp":"5","type":"港・集落","name":"マラガ","desc":"フェニキア人によって築かれ、支配勢力が変わりながら、発展を続けてきた街。イベリアにあるほかの街と同じく、イスラムと欧州の文化が融合した街並みである。農作物のほかに、サフランや辰砂（しんしゃ）、サンゴを産する。"}],"501":[{"rank":"1","note":"古代ギリシャの歴史書<br/><br/>発見時経験値120　発見物カード経験値60","exp":"120","type":"財宝","name":"ヒストリアイ","desc":"古代ギリシャの歴史家・ヘロドトスが記した史書。古代ペルシャとの戦争を中心に書かれており、ヨーロッパとアジア世界を常に対立するものと定義している。"}],"2115":[{"rank":"3","note":"サルベージ","exp":"490","type":"歴史遺物","name":"マルティネンガ号","desc":"ヴェネツィアの貿易船の一隻。イスタンブールからの帰路の途中、ボスポラス海峡付近で沈没した。"}],"5726":[{"rank":"2","note":"2017.02.07新規追加","exp":"250","type":"地理","name":"イエローバンド","desc":"チョモランマにある3つの地層の内の1つ。\n地層からは複数の化石が見つかっている。この化石を研究すると、過去の付近の様子を探れるだろう。"}],"919":[{"rank":"2","note":"悲劇の追悼","exp":"230","type":"歴史遺物","name":"スパルタ兵の墓碑","desc":"テルモピレーの戦いでペルシャ軍に殲滅（せんめつ）されたスパルタ兵を悼（いた）んで建てられた墓碑。裏切った兵がペルシャ軍に道を教えたため挟撃にあい全滅したという。"}],"792":[{"rank":"1","note":"戴冠石","exp":"170","type":"宗教遺物","name":"戴冠石","desc":"運命の石、リア・ファイルとも呼ばれる。真実の王が触れると叫び声をあげると伝えられる。伝説のアーサー王は石に刺さった剣を抜いて王となったが、剣が刺さっていたのがこの石だともいわれる。"}],"2500":[{"rank":"4","note":"伝来の弦楽器","exp":"690","type":"財宝","name":"五弦の琵琶","desc":"読みは、「ごげんのびわ」。日本で作られた質素な作りの琵琶。ある宝物庫には、昔インドから日本に贈られたとされる美しい五弦の琵琶が保管されているらしいが詳細は不明。実物を見られる者は限られているようだ。"}],"5003":[{"rank":"4","note":"ハワイ沖<br/>発見物カード:385","exp":"770","type":"天文","name":"タイタン","desc":"ガリレオ衛星に次いで発見された、土星の衛星。土星の衛星の中では最大で、惑星である水星をしのぐほど。"}],"1293":[{"rank":"3","note":"不揃いなつがい","exp":"451","type":"鳥類","name":"オオハナインコ","desc":"雌雄によって全く異なる羽色をもつ鳥。オスは鮮やかな緑、メスは深い赤である。非常に賢く、気性も穏やかであるため、容易に飼育できる。"}],"6380":[{"rank":"2","note":"","exp":"270","type":"歴史遺物","name":"クフ王が描かれたレリーフ","desc":"古代エジプトのファラオ、クフ王が描かれたレリーフの一部。カルトゥーシュと呼ばれるヒエログリフの曲線がファラオの名を囲んでいる。同様のレリーフには、生贄とされた牛が描かれたものや、弓を引く王が描かれたものなどがある。"}],"284":[{"rank":"2","note":"ホロホロチョウの羽","exp":"340","type":"鳥類","name":"ホロホロチョウ","desc":"斑点のある羽と骨質のとさかが特徴。古くから食用として家禽（かきん）化された。自然界ではアフリカ熱帯域の開けた草原に生息しており、群れを作って生活している。"}],"775":[{"rank":"1","note":"川に潜む巨大生物","exp":"200","type":"大型生物","name":"カバ","desc":"水辺に生息する、大型の動物。ずんぐりとした体に太く短い足が特徴である。頭、特に口がとても大きい。それに対して目や耳は小さく、独特の容貌をしている。"}],"1629":[{"rank":"5","note":"芸術か異端か","exp":"1118","type":"美術品","name":"最後の審判（ミケランジェロ）","desc":"ミケランジェロのフレスコ画。巨大にして素晴らしい芸術作品である。描かれているのは最後の審判の様子。中央にイエスがおり、救われた者は左手から昇天し、罰を宣告された者は右手から地獄に落ちる。"}],"772":[{"rank":"1","note":"先史時代の史跡の地図","exp":"19","type":"歴史遺物","name":"先史時代の焚き火跡","desc":"人間が火を使った跡。火は人間の文化的営みの象徴であり、これがあれば人間が何らかの活動を行っていたと推測できる。"}],"5901":[{"rank":"5","note":"","exp":"1400","type":"植物","name":"デス・カマス","desc":"新大陸の西部に分布する有毒植物。名前のとおり毒性が強く、少量でも口にすると臓器不全などに陥り死亡することがある。カマスという食用の植物に非常に似ているため、特に注意が必要。"}],"3388":[{"rank":"4","note":"メソポタミアの魔術神<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740","type":"宗教遺物","name":"エアのレリーフ","desc":"エアとはバビロニア神話に登場する神の名であり、かつてウルの南にあったとされる都市エリドゥの守護神である。洪水伝説において船の作り方を教えたという伝承がある。\nメソポタミア神話では「エンキ」と呼ばれていたようだ。"}],"3847":[{"rank":"2","note":"北米のツルの生態調査<br/><br/>発見時経験値240　発見物カード経験値120","exp":"240","type":"鳥類","name":"アメリカシロヅル","desc":"北米からカナダにかけて、湿潤な草原に生息するツル。ツルにしては体が大きく、真っ白な毛に覆われている。"}],"5506":[{"rank":"1","note":"座標　15770,3052","exp":"16","type":"港・集落","name":"ヴィアナドカステロ","desc":"イベリア半島西部に位置する街。外洋を目指す船の母港として重要な拠点である。"}],"1630":[{"rank":"3","note":"人を恐れぬ生物<br/><br/>発見時経験値462　発見物カード経験値231","exp":"462","type":"鳥類","name":"ケア","desc":"森林限界近くの高山に生息する鳥。オリーブのような緑色の羽に覆われているが、翼の裏はきれいなオレンジ色をしている。とても人懐っこい性格をしている。"}],"2749":[{"rank":"2","note":"［勅命］[[災害の事前観測","exp":"380","type":"地理","name":"漢拏山","desc":"済州島のほぼ中央に位置する火山。山の頂上には様々な伝説が残る湖もあるそうだ。\n記録によると、高麗時代に噴火があったようだ。"}],"701":[{"rank":"1","note":"クエスト「神話を題材にした裸婦画」<br/>発見物カード:80","exp":"160","type":"美術品","name":"狩人のディアナ","desc":"作者不詳の絵画。ローマ神話のディアナが、猟犬をともなって狩りに出かける様子を描いている。柔らかで自然な裸体が美しい。モデルはフランス王の愛妾だといわれる。"}],"1124":[{"rank":"2","note":"平たい生物の調査<br/><br/>発見時経験値355　発見物カード経験値177","exp":"355","type":"小型生物","name":"ピパ","desc":"扁平な身体と、三角形の頭を持つ。メスは自分の背中の皮膚内で卵を育てる。約二ヵ月後に、子供は小型のカエルの姿で現れる。"}],"6419":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"聖剣の鞘","desc":"聖剣エクスカリバーを収めていた魔法の鞘。身につけた者の傷を癒やし、不死の力を与えるという。アーサー王の姉モーガンにより持ち去られ湖へと投げ込まれた。鞘を失ったのちにアーサー王は傷を負い、命を落とすことになったという。"}],"2865":[{"rank":"1","note":"日陰に咲く花の地図","exp":"90","type":"植物","name":"シュウカイドウ","desc":"主に中国に生息する植物。夏の終わりから秋にかけて、紅色の花を咲かせる。\n日陰や湿り気を好み、さまざまな場所で咲いているのが見られる。"}],"2539":[{"rank":"2","note":"お菓子の原材料","exp":"330","type":"植物","name":"アイギョクシ","desc":"台湾島の山中にのみ生息する貴重な植物。\nこの果実から、アイギョクと呼ばれるお菓子が作られている。"}],"3633":[{"rank":"3","note":"ある聖人たちの記憶","exp":"480","type":"宗教遺物","name":"ある聖人の生涯記","desc":"後に聖人となったキエフ大公国の人物の生涯を記した書物。年代記者ネストルの著書とされ、『原初年代記』にも記述が見られる。"}],"6696":[{"rank":"2","note":"漢陽 書庫　産業技術書の地図　財宝　R8","exp":"280","type":"財宝","name":"天工開物","desc":"明の学者・宋応星の著作。中国全土を歴遊し「座学より実学で学ぶべし」の精神で作られた産業技術書。明代の産業を網羅している。中国では評判されず、散逸してしまったが、日本では貝原益軒らに珍重にされて残った。"}],"6083":[{"rank":"5","note":"","exp":"1480","type":"伝承","name":"ヴァルプルギスの夜","desc":"主に中欧や北欧で行われる行事。死者と生者との境界が曖昧になるという夜に、魔女たちが集会を開き、かがり火を囲んで悪魔を崇拝するとされるが、その真偽は定かではない。"}],"2525":[{"rank":"1","note":"黒いチョウの地図","exp":"190","type":"虫類","name":"クロアゲハ","desc":"台湾島や中国を含め、広い地域に生息するチョウ。艶やかな黒い羽を持つが、雄の後羽には時間と共に変色していく模様がある。\n他のアゲハチョウより暗い場所を好む。"}],"21":[{"rank":"5","note":"アフリカのシャーマン","exp":"962","type":"宗教遺物","name":"ヨルバ王国の神官の仮面","desc":"西アフリカ中央部で栄えているヨルバ人の仮面。これは、託宣（たくせん）を行う高位の神官の物である。ヨルバ人は木工や青銅細工に優れ、この仮面にも精巧な細工が施されている。"}],"2114":[{"rank":"2","note":"サルベージ","exp":"360","type":"歴史遺物","name":"サルベッタ号","desc":"ヴェネツィアの商船の一隻。\nベイルートの沖を航海中、海賊に襲われ沈没した。"}],"1211":[{"rank":"2","note":"クエスト「神殿の壁画調査」<br/>発見物カード:125","exp":"250","type":"宗教建築","name":"鷲とジャガーのレリーフ","desc":"チチェンイッツァの神殿のひとつに彫られていたレリーフ。左にジャガー、右の鷲は心臓をつかんでいる。"}],"5293":[{"rank":"4","note":"","exp":"680","type":"鳥類","name":"ケープハゲワシ","desc":"アフリカ南部に生息する大型の鳥。木の枝を組み合わせて断崖に巣を作る。巣作りに適した地形が少ないため、同じ場所に巣が集中したり、数世代にわたって同じ場所に巣が作り続けられたりすることもある。"}],"2252":[{"rank":"2","note":"小島と山","exp":"350","type":"地理","name":"ナナラウド山","desc":"ポンペイ島のほぼ中心に位置する山。\n標高は約800mで、ポンペイ島では一番高い。滝も多く存在するようだ。"}],"1656":[{"rank":"1","note":"書きかけの地図","exp":"75","type":"地理","name":"スールー海","desc":"周囲をルソン島、カリマンタン島、ミンダナオ島に囲まれた閉鎖的な海。水温は高く、この海でしか見られない生物もいるようだ。また、サンゴ礁も多く見られる。"}],"4815":[{"rank":"","note":"楽山大仏 （深層隠し部屋）","exp":"","type":"財宝","name":"春望","desc":""}],"5263":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:150","exp":"300","type":"天文","name":"ケンタウルス座の球状星団","desc":"ケンタウルス座の馬の背にあたる位置にある星が球状に集まった星団。肉眼で見ることができ、星団とわかる以前にはケンタウルス座ω星と呼ばれていた。"}],"5853":[{"rank":"5","note":"","exp":"1380","type":"美術品","name":"ザクロの陶器","desc":"ザクロの絵付けが施された磁器。ヨーロッパの人々の多くはザクロを知らなかったため、この絵付けをブルーオニオンと呼んだ。"}],"5557":[{"rank":"5","note":"薬効多き低木<br/><br/>発見時経験値1040　発見物カード経験値520","exp":"1040","type":"植物","name":"ギョリュウバイ","desc":"オーストラリア大陸南東部およびニュージーランド列島原産の木。マオリの言葉では「マヌカ」と呼ばれる。蜜や葉にさまざまな薬効がある。"}],"1047":[{"rank":"2","note":"竜殺しの紋章<br/><br/>発見時経験値350　発見物カード経験値175","exp":"350","type":"財宝","name":"竜殺しの紋章","desc":"竜を討つ伝説で知られる勇者ゲオルグの末裔の家に伝わる紋章旗。帆布に染め抜いて掲げれば、さぞ勇壮な眺めになることだろう。"}],"6208":[{"rank":"5","note":"王者の風","exp":"1350","type":"大型生物","name":"バーバリライオン","desc":"アフリカ北部のアトラス山脈を中心に生息しているライオン。別名アトラスライオン。通常のライオンよりひと回り大きいうえ、たてがみが非常に黒く胴まで達する。その特異な容貌のため、古代から戦利品や見世物として乱獲されたという。"}],"5324":[{"rank":"1","note":"経験値修正","exp":"190","type":"地理","name":"マカディカディ塩湖","desc":"アフリカ南部の乾燥地帯にある、世界屈指の広さを誇る塩類平原。いくつかの川が流れ込んでおり、雨季の間のみ水が溜まって塩湖になる。水と塩、草を求めてさまざまな種類の動物が集まる。"}],"3783":[{"rank":"1","note":"視認","exp":"150","type":"天文","name":"明けの明星","desc":"夜明け前に東の空に明るく輝く惑星。古代ギリシャ語ではポスポロス、ラテン語ではルシフェルと呼ばれた。仏教説話でも悟りを開く際に明けの明星が登場することがある。"}],"2607":[{"rank":"2","note":"城の俯瞰図の地図","exp":"290","type":"歴史遺物","name":"熱蘭遮城図","desc":"読みは「ゼーランディアじょうず」。熱蘭遮城を俯瞰して描いたと思われる絵図。\n誰が描いたものなのかは不明だが、きれいな状態で保存されていたようだ。"}],"6618":[{"rank":"5","note":"レガシー美の叡智　中央","exp":"1800","type":"歴史遺物","name":"ジャムシードの杯","desc":"ゾロアスター教の神話に登場する、伝説の王ジャムシードの杯。多くのペルシャ文学に登場し、ペルシャ帝国の王位継承の象徴とされた。未来を占えるという伝説がある。"}],"6368":[{"rank":"5","note":"幻の空中都市に関する伝承","exp":"990","type":"伝承","name":"サイレントシティ","desc":"世界各地で語られる空中に浮かぶ都市。その街並みは現れるたびに変化し、住人が見える場合もあるという。幻にしては、あまりに輪郭がはっきりと見えるとされている。"}],"556":[{"rank":"1","note":"古代ローマ五賢帝","exp":"90","type":"歴史遺物","name":"ネルヴァ帝のブロンズ像","desc":"古代ローマ五賢帝の一人、ネルヴァ帝の像。前帝と血縁になく彼自身もトラヤヌスを養子にして後継者とした。以降、優れた人物を養子にして後継者とすることが続いた。"}],"2589":[{"rank":"2","note":"軍記物語にまつわる絵","exp":"370","type":"美術品","name":"合戦絵巻","desc":"ある武家の来歴がまとめられた、日本の絵巻物。合戦の描写が主軸となっている。\n鮮やかな色彩で描き出された光景は、武士の活躍を目の当たりにさせると共に、戦の凄惨さをも物語っている。"}],"5897":[{"rank":"5","note":"","exp":"1400","type":"植物","name":"ギンピ・ギンピ","desc":"オーストラリアなどに分布する有毒植物。高さはおおよそ1mほど。植物全体が細かな刺毛に覆われており、素肌に触れると激しい痛みを伴う。最悪の場合、痛みが数年続くこともあるという。"}],"1970":[{"rank":"2","note":"長く美しい尾羽","exp":"330","type":"鳥類","name":"ラケットハチドリ","desc":"尾羽が美しい、小さな鳥。雄の特徴である、長い棒の先にラケットが付いたような尾羽は雌をひきつけるためといわれている。寒冷地の鳥らしく、足の周りにはふさふさした羽毛が生えている。南米のアンデス山脈の一部の地域にのみ生息。"}],"1299":[{"rank":"2","note":"動きの遅いサル","exp":"340","type":"小型生物","name":"ロリス","desc":"樹上で生活する動物。夜行性で目が丸く、尾はほとんどない。サルともそのほかの動物ともつかない、不思議な姿をしている。普段の動作はかなり緩やかだが、エサを捕らえる一瞬だけは驚くほど素早い。"}],"2513":[{"rank":"3","note":"風変わりな果物","exp":"490","type":"植物","name":"バンレイシ","desc":"ネーデルラント人によって台湾島に持ち込まれた植物。\n果実の表面が仏像の頭部に似ていることから釈迦頭とも呼ばれる。"}],"6991":[{"rank":"2","note":"","exp":"","type":"宗教遺物","name":"ホルスを抱くイシス像","desc":"末期王朝期のエジプトで制作された像。女神イシスが息子のホルスに授乳している姿がかたどられている。子を守る母の愛を表したこの像は、キリスト教の聖母子像の在り方にも影響を与えたと考えられている。"}],"98":[{"rank":"2","note":"カエサルとクレオパトラ","exp":"250","type":"歴史遺物","name":"カエサルの黄金の杯","desc":"クレオパトラ7世からユリウス・カエサルに贈られたという、黄金の杯。エジプトはナイル川から砂金が取れたため、金が豊富だったといわれる。"}],"5245":[{"rank":"1","note":"","exp":"168","type":"歴史遺物","name":"青銅の儀礼用剣","desc":"アクロポリスと呼ばれる丘の近辺で見つかった儀礼用の青銅剣。首長の権威を象徴する道具と見られる。首長が政治と共に祭祀を行っていたのだろうか。"}],"6797":[{"rank":"4","note":"追究クエスト<br/>発見物カード:320","exp":"640","type":"歴史遺物","name":"瀛涯勝覧","desc":"鄭和の航海に随行した馬歓によって書かれた文書。「えいがいしょうらん」と読む。鄭和の航海の航路、寄港した国々の風土などが詳細に記録されている。鄭和を研究する上で、最も重要な文献の一つとされる。"}],"768":[{"rank":"1","note":"赤子を抱く神像","exp":"100","type":"宗教遺物","name":"オリンピアのヘルメス像","desc":"オリンピアのヘラ神殿にあったというヘルメスの像。幼児のディオニソスを抱いている。当時最高の彫刻家とされたプラクシテレスの作だといわれる。"}],"4952":[{"rank":"1","note":"経験値修正した","exp":"170","type":"地理","name":"ピンドス山脈","desc":"ギリシャ地方の西側にある山脈。\n約160kmの長さに2000m級の山々が連なっている。バルカン半島を縦断するようにそびえているため、ギリシャの屋根、またはギリシャの背骨といわれる。"}],"5933":[{"rank":"1","note":"","exp":"113","type":"財宝","name":"ジョゼの父への脅迫状","desc":"くしゃくしゃになった紙束。かろうじて「娘の命……船……王族……殺……」といった単語が読み取れる。細かい状況まではわからないが、これは脅迫状のたぐいだろうか。"}],"6716":[{"rank":"2","note":"クエスト「忍び寄る鋭い花」<br/>発見物カード:160","exp":"320","type":"虫類","name":"ハナカマキリ","desc":"東南アジアに生息するカマキリ。熱帯雨林を住処とする。その姿を活かしてランの花に擬態し、寄ってきた他の昆虫を食べて過ごす。"}],"5504":[{"rank":"1","note":"座標　16164,2271","exp":"15","type":"港・集落","name":"マンチェスター","desc":"ブリテン島西部に位置する街。1世紀頃、古代ローマ帝国軍が築いた前哨砦「マンクニウム」を起源とする。18世紀末から、蒸気機関を用いた綿織物工業が盛んになり、急成長を遂げる。"}],"1345":[{"rank":"1","note":"黒い鳥の地図","exp":"140","type":"鳥類","name":"ヤシオウム","desc":"熱帯雨林や、開けた森林などに生息する鳥。黒色の羽で覆われ、頬の部分には赤い皮膚が見える。頭頂部には長い冠羽がある。大きく丈夫なくちばしで、ヤシの実の固い殻なども割って食べることができる。"}],"5759":[{"rank":"5","note":"2017.02.07新規追加","exp":"1400","type":"地理","name":"エオリア諸島","desc":"シチリア島の北方に位置する島々。火山活動によって出来た諸島であり、中でもストロンボリ島は盛んに噴火している。"}],"6445":[{"rank":"1","note":"","exp":"","type":"財宝","name":"君主論","desc":"フィレンツェの外交官ニッコロ・マキャヴェリが執筆した政治思想書。道徳や宗教を排除した現実主義の視点で書かれ、君主には残酷さが必要と主張した。権謀術数の書として危険視され禁書指定を受けたが、現実主義的政治学の源流となった。"}],"6831":[{"rank":"5","note":"発見物カード:455","exp":"910","type":"鳥類","name":"ルリサンジャク","desc":"南米の中南部に生息する鳥。頭と胸、翼が黒く、腹と尾羽の先が乳白色ときれいに分かれている。目の上に人の眉毛のような青い眉斑があり、愛嬌のある表情に見える。"}],"183":[{"rank":"1","note":"ゼウスに捧げる祭典","exp":"100","type":"史跡","name":"オリンピア遺跡","desc":"多数の神殿や競技場がある古代ギリシャの遺跡。オリンピック競技が行われていたため、各種競技に関連する建造物が多い。"}],"5558":[{"rank":"2","note":"書きかけの地図<br/><br/>発見時経験値250　発見物カード経験値125　文化貢献度40","exp":"250","type":"地理","name":"プナルウ黒砂海岸","desc":"ハワイ島にある、黒い砂浜。火山から噴出した溶岩が細かく砕けて黒い砂となり、堆積している。ウミガメの生息地としても有名。"}],"6500":[{"rank":"2","note":"","exp":"280","type":"歴史遺物","name":"ゼウスの錫杖の金鷲像","desc":"オリンピアの巨大なゼウス像が手に持つ錫杖についていたとされる金の鷲の像。この彫像は世界の七不思議の一つに数えられている。鷲はゼウスの象徴であり、ゼウスが鷲に変身した神話も伝わっている。"}],"1334":[{"rank":"2","note":"書きかけの地図","exp":"210","type":"地理","name":"ベラウ湾","desc":"ニューギニア島の西端に突き出た、鳥のくちばし状の地形に挟まれた湾。西には無数の島々を望める。"}],"6438":[{"rank":"5","note":"レガシー　数の叡智・世界の計算系　右下","exp":"","type":"歴史遺物","name":"関将軍の算盤","desc":"古代中国の算盤（スアンバン）。三國志で有名な武将・関羽が発明したという伝説があるが、それ以前の古代から仕様されていたという。串に珠を通した形式の算盤は後代の発明とされ、珠は楕円形で天（上段）に2珠、地（下段）に5珠ある。"}],"5406":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:165","exp":"330","type":"天文","name":"りゅうこつ座の花のような星雲","desc":"りゅうこつ座にある散光星雲。オリオン星雲より四倍ほど大きく明るいが、天の南極に近い場所にあるため、南半球の緯度が高い地域行かないと見ることが難しい。"}],"1188":[{"rank":"2","note":"鳥を襲う鳥","exp":"270","type":"鳥類","name":"サンショクウミワシ","desc":"その名の通り、濃い茶と黒の羽毛、白い頭と胸、黄色の嘴（くちばし）が目立つ。魚を主食としているが、まれにカモなどをおそうこともある。頭を後ろにそらせてかん高い大きな鳴き声を上げる。"}],"6339":[{"rank":"2","note":"ペルー海盆12960:5734","exp":"320","type":"地理","name":"フアン･フェルナンデス諸島","desc":"南米南部の沖合、太平洋に浮かぶ群島。三つの島で構成される。島の地形は険しく、火山島となっている。自然豊かで多くの動物が生息している。"}],"537":[{"rank":"1","note":"古代の道具の地図","exp":"20","type":"歴史遺物","name":"土器","desc":"粘土を練って成形し、焼いた器。強度はないが、製作が容易で目的に応じた形にできることから、多くの古代文明で見られる。"}],"1338":[{"rank":"2","note":"マラッカ東の大陸調査","exp":"280","type":"地理","name":"カリマンタン島","desc":"マラッカ海峡の東に位置する巨大な島。全体的に山がちで、生息する生物は、大型生物から昆虫まで多岐にわたる。鉱物資源も豊富でダイヤモンドの鉱脈も存在するようだが、島は密林に覆われており開発は進んでいない。"}],"2907":[{"rank":"2","note":"長江の女神","exp":"320","type":"海洋生物","name":"ヨウスコウカワイルカ","desc":"長江の下流域に生息するイルカ。濁った川で暮らすためか、目が退化しているようだ。\n別名、長江女神。"}],"5396":[{"rank":"1","note":"","exp":"200","type":"地理","name":"エトナ山","desc":"シチリア島北東部にある、ヨーロッパ最大の火山。非常に活発で、何度も噴火が記録されている。ギリシャ神話の怪物テュポンが封印された場所ともいわれている。"}],"2288":[{"rank":"4","note":"クエスト「刻まれた歴史」<br/>発見物カード:315","exp":"630","type":"宗教建築","name":"階段のレリーフ","desc":"コパン王朝の歴史が絵文字で記されているという巨大な階段。\n川の氾濫に巻き込まれたためか損傷が酷く、段差がちぐはぐになっている。描かれている絵文字を解読するには手間がかかりそうだ。"}],"2111":[{"rank":"2","note":"サルベージ","exp":"310","type":"歴史遺物","name":"フラメンゴ号","desc":"ポルトガルの東インド貿易船の一隻。\nインドからの帰路、喜望峰沖の嵐は切り抜けたが、サントメ沖で難破し、沈没した。"}],"5389":[{"rank":"2","note":"","exp":"","type":"財宝","name":"古代エジプトの儀式用剣","desc":"ケペシュと呼ばれる鎌形の剣を儀式用にしたもの。ケペシュは湾曲した刀身の内側に刃があり、相手の盾に引っかけて攻撃するが、儀式用には刃がついていない。"}],"2981":[{"rank":"2","note":"川に棲むサメの地図","exp":"240","type":"海洋生物","name":"ヘラチョウザメ","desc":"北米に生息するチョウザメの仲間。鼻先が突出しているのが特徴的だが、機能的にはよくわかっていない。キャビアと呼ばれる、卵を塩漬けにしたものは珍味として多くの人に愛されている。"}],"6992":[{"rank":"5","note":"","exp":"","type":"海洋生物","name":"オウサマペンギンの幼鳥","desc":"茶色の幼綿羽が全身を覆っているオウサマペンギンの幼鳥。孵化直後は灰色の短い毛に覆われているが、成長と伴にふわふわとした茶色の毛に換羽する。親のそばを離れずに育ち、数カ月親と同じ見た目になる。"}],"5286":[{"rank":"2","note":"","exp":"240","type":"中型生物","name":"リカオン","desc":"アフリカ中南部のサバンナや草原に棲むイヌに似た生物。体は黒・白・オレンジの三色がまだら模様を描き、丸く大きな耳を持つ。数十頭ほどの非常に社会性に富んだ群れを作って生活している。仲間同士で巧みに連携して狩りを行う。"}],"267":[{"rank":"1","note":"ブリテン北の群島","exp":"70","type":"地理","name":"シェトランド諸島","desc":"スコットランドの北に浮かぶ島々。かつてはヴァイキングの支配下にあったので、北欧に近い雰囲気がある。牧羊が行われており、小型で毛の長い牧羊犬が見られる。"}],"5050":[{"rank":"2","note":"到達する","exp":"244","type":"港・集落","name":"グランドケイマン","desc":"西インド諸島西部、ケイマン諸島最大の島にある街。難破船の船員や海賊達も住み着き始めているようだ。"}],"6141":[{"rank":"1","note":"名将軍の采配","exp":"120","type":"歴史遺物","name":"ハンニバルの大理石像","desc":"ハンニバルはカルタゴの将軍で、共和制ローマを攻めて功績があった。一時はイタリア半島まで攻め込んだが、ザマの戦いで大スキピオに敗れた。"}],"2496":[{"rank":"2","note":"人々の暮らしの調査法","exp":"260","type":"美術品","name":"市中風俗絵巻","desc":"都に住む人々の様子を描いた日本の絵巻物。人々の服装や街並み、祭りの光景などが、克明かつ生き生きと描き出されている。美術品であると同時に、描かれた当時の文化を示す貴重な史料でもある。"}],"3166":[{"rank":"3","note":"古代遺跡と闘技場","exp":"470","type":"史跡","name":"コロッセウム","desc":"古代ローマの帝政期に築かれた円形闘技場。四万人余りの観客を収容でき、幾度もの剣闘士競技が繰り広げられた場所である。皇帝・ネロの巨像（コロッスス）が近くにあったため、コロッセウムと呼ばれるようになったという。"}],"6827":[{"rank":"3","note":"発見物カード:260","exp":"520","type":"中型生物","name":"アライグマ","desc":"北米の森林や湿地などに広く生息する動物。体毛は灰褐色で、目の周囲と頬が黒い。足先の指が長く、器用に物を掴むことができる。太く長い尾には、黒い縞模様が入っているのが特徴。"}],"3323":[{"rank":"2","note":"書きかけの地図","exp":"300","type":"地理","name":"プレーリー","desc":"北米の中央部に広がる広大な草原。自生している草の丈は長めである。肥沃な土壌で、耕作に向いている。"}],"16":[{"rank":"1","note":"アナトリア半島の狩猟生活","exp":"160","type":"歴史遺物","name":"石の鏃","desc":"やじり。石器時代のもので、どの文明にも見られる形状である。どこも同じような狩猟法であったということであろうか。"}],"5904":[{"rank":"5","note":"","exp":"1410","type":"宗教遺物","name":"鉄王冠","desc":"イエスを十字架に打ち付けた釘を、再加工して取り付けた王冠。そのため鉄王冠と呼ばれ聖遺物とされている。"}],"2077":[{"rank":"2","note":"［勅命］[[香料諸島方面からの献上品","exp":"330","type":"植物","name":"コチョウラン","desc":"チョウが群がって飛んでいるように見えるほど、多くの花を咲かせる。密林の木々に張り付くように自生している。"}],"162":[{"rank":"1","note":"サンゴの採れる海域の地図","exp":"15","type":"海洋生物","name":"サンゴ","desc":"熱帯の海で広く見られる美しい生物。一見植物のようだが、近くでよく見ると、ごく小さいイソギンチャクのようなものがびっしりと並んでいる。地元の人間に聞くと、ゆっくり成長するそうだ。"}],"3755":[{"rank":"1","note":"クエスト「南の空の巨人」<br/>発見物カード:55","exp":"110","type":"天文","name":"オリオン座","desc":"ヨーロッパでは冬の南の空に見られる星座。ギリシャ神話に登場する狩人オリオンが、サソリに刺されて死んだあとに天に昇った姿とされる。2つの1等星やオリオンのベルトと呼ばれる三ツ星があり、見つけやすい。"}],"4949":[{"rank":"2","note":"フレスコ画の研究<br/><br/>発見時経験値220　発見物カード経験値110","exp":"","type":"宗教建築","name":"キプロス島の壁画聖堂群","desc":"キプロス島の山岳地帯にある聖堂群。木や石の外壁に切妻屋根という簡素な外観の造りだが、内壁や天井にはビザンツ様式のフレスコ画が華麗に描かれている。"}],"5195":[{"rank":"2","note":"到達する","exp":"350","type":"港・集落","name":"釜山","desc":"読みは「プサン」。\n元は漁村であったが、貿易の拠点として発展を遂げた。"}],"3155":[{"rank":"3","note":"女神の神殿","exp":"510","type":"宗教建築","name":"パエストゥム遺跡","desc":"古代ギリシャおよび古代ローマの遺跡。イタリアのカンパーニャ地方に位置する。神殿などの宗教施設の他に、広場や市場らしき跡も見られる。"}],"1581":[{"rank":"2","note":"褐色の海獣<br/><br/>発見時経験値220　発見物カード経験値110","exp":"220","type":"中型生物","name":"アシカ","desc":"アザラシに似た、黒い体毛の動物。生息地が温暖なので、アザラシよりスマートな体をしている。近い種類なのだろうか？"}],"493":[{"rank":"5","note":"古代エジプトの信仰","exp":"1001","type":"宗教遺物","name":"太陽の船","desc":"ギザにあるクフ王のピラミッド近くから発掘された、木製の船。全長が40m以上ある。死んだファラオの魂を太陽神のもとへ運ぶための、儀式用の船だと思われる。"}],"1460":[{"rank":"1","note":"白いモグラの地図","exp":"80","type":"小型生物","name":"フクロモグラ","desc":"モグラに似た有袋類。砂漠に生息し、地中を掘り進んで移動する。その際に出合った生物はなんでも捕食する。"}],"460":[{"rank":"1","note":"金色の動物の地図","exp":"32","type":"小型生物","name":"キンモグラ","desc":"地中にトンネルを掘って住んでいる動物。目は小さく、あまり見えないようだ。前足の爪が大きく発達し、土を掘りやすい。"}],"2962":[{"rank":"2","note":"クエスト「食器の木」<br/>発見物カード:130","exp":"260","type":"植物","name":"カルミア","desc":"北米に生息する花。つぼみの形が多角形で、星に似ている。花の一つ一つは小さいが、集団で咲くと大きな球体のように見える。"}],"6676":[{"rank":"4","note":"発見物カード:400","exp":"800","type":"天文","name":"デネブ・カイトス","desc":"くじら座で最も明るいオレンジ色の星。くじらの尾に輝く。アラビア語で「2匹目の蛙」の意味。みなみのうお座のフォーマルハウトが1匹目の蛙にあたる。名はアラビア語の「海の怪物の南の尾」に由来する。"}],"5325":[{"rank":"1","note":"","exp":"","type":"歴史遺物","name":"ホモ・ハビリスの石器","desc":"大昔に使われていたと思われる石製の道具。加工の跡がないため、他の地域で見つかる石器よりも古い時代のものと考えられる。主に狩猟に用いられたのだろう。"}],"2425":[{"rank":"3","note":"釣り","exp":"510","type":"海洋生物","name":"イトウ","desc":"日本最北部の河川に棲む淡水魚。サケのように海へ降る。\n日本の淡水域に生息する魚類の中で最も大きくなるといわれ、魚はいうまでもなく、ヘビやネズミまでも食べてしまう。"}],"3293":[{"rank":"4","note":"ブリテン島の温泉場","exp":"610","type":"地理","name":"バースの鉱泉地","desc":"ブリテン島の南西部に位置する地域。古来より温泉がわく場所として有名である。ローマ帝国時代には皇帝の支配下に置かれて発展したこともあり、浴場などローマ式の建造物が残っている。"}],"3193":[{"rank":"4","note":"好漁場の噂","exp":"640","type":"地理","name":"グランドバンクス","desc":"テラ・ノヴァの南東沖に広がる、海底の台地群。寒流のラブラドル海流と暖流のメキシコ湾流がぶつかって潮目を形成しているため、好漁場として名高い。"}],"1728":[{"rank":"5","note":"妖精が住む宝石<br/><br/>発見時経験値1170　発見物カード経験値585","exp":"1170","type":"財宝","name":"妖精のささやき","desc":"2000カラットをゆうに超える、巨大なオパール。透明感があり中まで美しくきらめいているのが見える。この石には妖精がすんでいて持ち主を気に入ると願いを叶えてくれるという伝説があるそうだ。"}],"2864":[{"rank":"4","note":"杭州付近の地理調査","exp":"650","type":"地理","name":"長江","desc":"古くから中心的な交通路として利用されてきた杭州北部を流れる大河。この流域では稲作が盛んである。\n下流部は「揚子江」とも呼ばれる。"}],"4854":[{"rank":"1","note":"「明るい星の観測記録」<br/>発見物カード:55","exp":"110","type":"天文","name":"アルビレオ","desc":"星座図上で、はくちょう座のくちばしに位置する星。天体望遠鏡で見ると、金色と青色の二つの星が並んでいるのがわかる。"}],"2868":[{"rank":"1","note":"魚の骨の地図","exp":"160","type":"化石","name":"目がくぼんだ魚の骨","desc":"黄河の近くで発見された、魚と思われる生物の骨。目のくぼみが大きいのが特徴。"}],"1816":[{"rank":"1","note":"金細工の地図","exp":"150","type":"財宝","name":"金杯","desc":"アンデスの各地で、こういった貴金属製品が見つかる。かなり古い時代から貴金属の製法が確立されていたようで、各地で地方色豊かに、そして変遷の色濃い金細工が見つかる。"}],"5211":[{"rank":"1","note":"朝鮮半島北岸　陸地再調査報酬","exp":"","type":"植物","name":"オオバオオヤマレンゲ","desc":"中国東北部から朝鮮半島にかけて分布する植物。初夏には良い香りのする純白の花を咲かせる。恥じらうようにやや下向きに咲く姿が可憐とされ、天女花とも呼ばれる。"}],"595":[{"rank":"1","note":"黒死病の歴史","exp":"180","type":"地理","name":"クリミア半島","desc":"黒海の北部に張り出している半島。北東の囲まれた海域はアゾフ海という。半島の南部は温暖で過ごしやすい。14世紀の黒死病の大流行は、ここから始まったのだそうだ。"}],"3532":[{"rank":"","note":"","exp":"","type":"レリック","name":"ルキウス・ブルートゥス","desc":"ローマの王政から共和政への転換期に活躍した「愚か者」。その真実の姿は私情を挟まない冷徹な改革者であった。"}],"3540":[{"rank":"","note":"","exp":"","type":"レリック","name":"ジャンヌを継ぐ者","desc":"諸侯と傭兵の寄せ集めの軍から国王の常備軍へ。リッシュモン元帥の軍制改革はフランスの大国化に大きく貢献したといえよう。"}],"653":[{"rank":"1","note":"書きかけの地図","exp":"20","type":"地理","name":"ロカ岬","desc":"リスボンの北に突き出した岬。イベリア半島の最西端にあたる。リスボンを出て、この岬を回るとオポルトだ。"}],"2421":[{"rank":"2","note":"釣り","exp":"330","type":"海洋生物","name":"アカメ","desc":"土佐沖から九州の東沿岸周辺とかなり狭い地域にのみ生息する魚。1mを超える大型魚だが外洋よりも河口付近での生活を好む。\n光の当たる角度によって目が赤く見えることからこの名が付いたといわれる。"}],"394":[{"rank":"1","note":"角のある大型獣の地図","exp":"76","type":"大型生物","name":"サイ","desc":"鼻の上に角がある、大型の草食動物。4m近くなる個体もいる。群れを作る種類と単独で生活する種類があるようだ。"}],"2248":[{"rank":"3","note":"バルディ頭取の興味","exp":"480","type":"海洋生物","name":"ガラパゴスペンギン","desc":"熱帯地域に生息する、珍しいペンギン。他のペンギンより小さく、体長は35cmほど。前屈みをしているような姿勢が特徴である。\nガラパゴス諸島にのみ生息している。"}],"665":[{"rank":"2","note":"象牙の女神像の地図","exp":"280","type":"財宝","name":"象牙の女神像","desc":"象牙を削りだして作られた女神の像。非常に緻密な細工が施されている。"}],"6449":[{"rank":"5","note":"","exp":"2550","type":"財宝","name":"三足の蛙の香炉","desc":"蛙をかたどった香炉。日本では武人も香道をたしなんでおり、この香炉も天下統一を目前にした武将が所有していたという。この武将が反乱で暗殺される前夜、香炉の蛙が鳴き声を上げたという伝説がある。"}],"2084":[{"rank":"2","note":"［勅命］[[運河開通場所の地形調査","exp":"310","type":"地理","name":"グレートビター湖","desc":"カイロとスエズの狭間にある、比較的大きな湖。この他にも、小中の湖が存在しているらしい。これらの湖は、スエズ運河の一部となるだろう。"}],"2002":[{"rank":"4","note":"画家の適材適所","exp":"650","type":"美術品","name":"花輪の聖母","desc":"ルーベンスとヤン・ブリューゲルの合作。ブリューゲルが花輪を、ルーベンスが人物を描いた。ブリューゲルは「花のブリューゲル」とも呼ばれるほど静物画に定評があり、各々が得意分野を生かした作品となっている。"}],"2855":[{"rank":"2","note":"勉強に必要な頼み事","exp":"260","type":"歴史遺物","name":"漢書","desc":"前漢時代について記した歴史書。\n皇帝など、人物ごとに焦点を当てて書かれているのが特徴である。"}],"6747":[{"rank":"5","note":"","exp":"","type":"伝承","name":"相柳","desc":"古代中国神話に伝わる怪物。人の頭を持ち、九つの山を喰らう大蛇として描かれる。四罪の一つに数えられる悪神の共工に仕えていた。『山海経』によると、夏王朝の初代君主である禹に退治されたという。"}],"1593":[{"rank":"1","note":"大型のイタチの地図","exp":"100","type":"中型生物","name":"オオカワウソ","desc":"アマゾン川流域に生息する大型のイタチ。体長は1.5mにもなり、魚やカニなどを捕えて食べる。"}],"6647":[{"rank":"5","note":"冥府の番犬の伝承","exp":"990","type":"伝承","name":"ケルベロス","desc":"ギリシャ神話に登場する、冥府の番犬。三つの頭を持ち一つが眠っている間、他二つの頭が見張りにつく。冥府の入口を固く守り、亡者の冥界からの逃走を決して見逃さないという。"}],"1312":[{"rank":"3","note":"鳥の後を追う鳥","exp":"506","type":"鳥類","name":"カラカラ","desc":"胸元と背中にある細い縞模様と、オレンジ色の顔が特徴。日常の大半は地面を歩いて過ごす。獲物は腐肉、魚、野菜、昆虫などなんでも食べる。"}],"6301":[{"rank":"5","note":"","exp":"1130","type":"財宝","name":"トゥアレグのペンダント","desc":"サハラ西部の遊牧民族であるトゥアレグ民族が身に着ける装身具。銀でできている。家系や出身地によってさまざまな形があり、親から子へ代々受け継がれる。砂漠で方角を示すコンパスをかたどっているとされる。"}],"5590":[{"rank":"3","note":"クエスト「お菓子のようなカニ」<br/>発見物カード:275","exp":"530","type":"海洋生物","name":"スベスベマンジュウガニ","desc":"インド洋から太平洋西部にかけて分布する小型のカニ。滑らかで丸い甲が特徴。毒を持っており、その成分や量は生息場所によって異なる。"}],"3662":[{"rank":"3","note":"ダンジョン","exp":"450","type":"歴史遺物","name":"カノプス壷","desc":"古代エジプトでミイラを作る際に心臓の次に重要とされた臓器を保存したといわれる壷。ホルスの息子と呼ばれる四柱の神々の姿をかたどっている。"}],"404":[{"rank":"1","note":"岩場の動物の地図","exp":"28","type":"小型生物","name":"ハイラックス","desc":"岩の多い所に住む、丸い体をした動物。別名はイワダヌキ。巣穴を掘って集団生活をしているようだが、非常に臆病なので生態はよくわからない。"}],"2828":[{"rank":"5","note":"大型生物の骨をめぐる論争","exp":"1120","type":"化石","name":"巨大なゾウの骨","desc":"黄河付近で発見された大型のゾウの骨。\n左右の牙の間が狭く、鼻を通すことはできそうもない。"}],"5654":[{"rank":"4","note":"","exp":"740","type":"虫類","name":"キリアツメゴミムシダマシ","desc":"南西アフリカのナミブ砂漠に生息する虫。背の凹凸は水を引き寄せやすい性質を持ち、霧から水分を集めて飲めるようになっている。"}],"5625":[{"rank":"3","note":"","exp":"470","type":"宗教建築","name":"エチミアジン大聖堂","desc":"アルメニアの大主教がキリスト降臨のビジョンを見て建てさせたという世界最古の教会。"}],"1982":[{"rank":"1","note":"釣り","exp":"160","type":"海洋生物","name":"ゴマフエダイ","desc":"熱帯のマングローブ林に多く見られるフエダイの仲間。体は赤く、鋭い歯を持っている。"}],"2966":[{"rank":"2","note":"クエスト「高速の毛玉」<br/>発見物カード:125","exp":"250","type":"小型生物","name":"ワタオウサギ","desc":"尾が白く、綿のようになっていることからこの名がついたウサギ。逃げ足が速く、敵に襲われた時はジグザグに走り、その速度は時速30km以上にも及ぶ。"}],"1862":[{"rank":"2","note":"供物の彫像","exp":"230","type":"宗教遺物","name":"コノパ","desc":"南米の民族の多くが、自らの信仰する神に生贄を捧げるが、コノパは生贄となる動物をかたどった彫刻である。神に捧げられる生贄はリャマやアルパカなど土地の家畜が多く、コノパにはそれの骨や毛などを詰めたという。"}],"3642":[{"rank":"4","note":"死にきれない者の伝承","exp":"640","type":"歴史遺物","name":"吸血鬼伝説","desc":"ヨーロッパ各地に伝わる、人間の血を糧とする化け物の伝説をまとめた書物。埋葬された死者が夜中になると墓場から這い出して街を徘徊し、人間を襲うという。元はスラブ地方につたわる民話だったようだ。"}],"2356":[{"rank":"2","note":"御使いの鳥<br/><br/>発見時経験値360　発見物カード経験値180","exp":"360","type":"宗教遺物","name":"八咫烏の旗","desc":"読みは「やたがらすのはた」。三本脚のカラスが描かれた旗。\n日本神話では、このカラスは神の使いとされているらしい。\n「咫」とは長さの単位であり、日本神話には「八咫」という長さがよく登場するそうだ。"}],"1012":[{"rank":"2","note":"密林にひっそりと咲く花","exp":"250","type":"植物","name":"セントポーリア","desc":"アフリカ南部の奥地にのみ見られる小型の植物。崖の岩の隙間に根をはわせ、厚い肉質の葉と花を持つ。花弁は独特の光沢があり、美しい。変異株が多く見られるので、品種改良に適しているだろう。"}],"5546":[{"rank":"2","note":"","exp":"280","type":"海洋生物","name":"レッドリップトバットフィッシュ","desc":"ガラパゴス諸島付近に生息する魚。海底を歩くように泳ぐ。真っ赤な唇のような口が名前の由来である。"}],"5655":[{"rank":"4","note":"","exp":"690","type":"地理","name":"黒砂漠","desc":"サハラ東部に位置する砂漠。玄武岩で覆われており、全体的に黒く見える。黒いピラミッドのような山が点在している。"}],"4861":[{"rank":"4","note":"ペルセウス座の二重星団","exp":"740","type":"天文","name":"ペルセウス座の二重星団","desc":"ペルセウス座にある星団。無数の星が集まったものが二つ並んで見える。肉眼でも、そのぼんやりとした光を見てとれる。"}],"6006":[{"rank":"1","note":"トゲだらけのネズミ","exp":"130","type":"小型生物","name":"ハリネズミ","desc":"背面にトゲが生えている小さな生物。目が小さく鼻がとがり、愛嬌のある顔をしている。捕まえようとすると、丸まってトゲだらけになる。動作は遅い。"}],"5758":[{"rank":"1","note":"2017.02.07新規追加<br/>ゴロミャンカ発見が前提の可能性有り","exp":"190","type":"海洋生物","name":"オームリ","desc":"バイカル湖に生息するサケに似た魚。産卵期には湖に流れ込む河川を遡上し、産卵すると湖に戻ってくる。食すと非常に美味である。"}],"1043":[{"rank":"2","note":"翼のあるドラゴンの骨<br/><br/>発見時経験値370　発見物カード経験値185","exp":"370","type":"化石","name":"翼のあるドラゴンの骨","desc":"巨大な翼のある竜の形をした岩盤。アレクサンドリアの近隣の岩場で発見された。大きく広げた翼がまがまがしい。これこそが伝説にうたわれるドラゴンの骨かもしれない。"}],"1594":[{"rank":"4","note":"新大陸西岸の巨大山脈","exp":"624","type":"地理","name":"アンデス山脈","desc":"南米大陸西岸の山脈。南米大陸北端から南端まで貫き、6000ｍ級の高峰が連なる。北部赤道付近は冷涼で過ごしやすく、わずかながら農耕も行われている。"}],"2538":[{"rank":"2","note":"大型のシカの地図","exp":"320","type":"大型生物","name":"サンバー","desc":"台湾島やインドなどの広い地域に分布するシカ。全長150cm以上に成長し、雄には角がある。\n夜行性で、昼間は木陰などで休んでいる姿が見られる。"}],"494":[{"rank":"1","note":"古代エジプトの魔よけ","exp":"80","type":"植物","name":"ヤグルマキク","desc":"ヨーロッパ南東部に咲く花。青、白、桃などさまざまな色がある。古代エジプトでは魔よけの花として、ギリシャ神話では傷薬の花として親しまれた。"}],"3512":[{"rank":"","note":"","exp":"","type":"レリック","name":"ガウェイン","desc":"勇猛果敢で直情径行の騎士ガウェイン。彼が自戒の念をこめて身に着ける帯が名誉ある勲章の由来だといわれる。"}],"3653":[{"rank":"2","note":"極北の猛獣の地図","exp":"370","type":"大型生物","name":"アムールヒョウ","desc":"ロシア東部の沿岸に生息する大型のヒョウ。どうやら他のヒョウとは生態が異なり、獲物を樹上に運ぶ習性がないようだ。"}],"7022":[{"rank":"5","note":"","exp":"","type":"虫類","name":"ミカヅキツノゼミ","desc":"中南米の森林に生息するツノゼミの一種。植物の汁を主食とする。名のとおり、後方へ弓なりに伸びる三日月形の角が特徴。雌雄で角の形状が異なる。"}],"3294":[{"rank":"4","note":"不毛の高原","exp":"690","type":"地理","name":"バレン高原","desc":"アイルランド西部に広がる台地。アイルランドの言葉で「不毛な大地」を意味する。その名の通り、古代の岩がむきだしで転がり、荒野のようである。そのため、人間の手が及ばず、珍しい植物や古代史跡が多く見られる。"}],"42":[{"rank":"3","note":"クエ：イスラムの王制","exp":"473","type":"歴史遺物","name":"トゥグリル・ベグの王冠","desc":"トゥグリル・ベグは、セルジューク朝トルコの始祖。最初のスルタンとなった。これはアッバース朝のカリフからスルタン位を受けた際の宝冠と言われる。"}],"5613":[{"rank":"2","note":"","exp":"","type":"化石","name":"頭頂部が丸いトカゲの骨","desc":"北米西部で見つかった巨大なトカゲのような生物の骨。頭頂部が、厚さ25cmあまりのドーム状の骨に覆われているのが特徴。"}],"5541":[{"rank":"2","note":"","exp":"185","type":"気象・現象","name":"夜光雲","desc":"日没後にのみ観測される、雲が青白く見える現象。地平線下にある太陽の光が雲に当たって発生すると思われるが、詳細な原因は不明である。"}],"2984":[{"rank":"2","note":"釣り","exp":"310","type":"海洋生物","name":"オオカミウオ","desc":"比較的寒い地域の海に生息する魚。鋭く強靭な歯で貝やカニの甲羅などを割って食べる。おとなしく、こちらがいたずらをしなければ噛みつかれることはない。"}],"6628":[{"rank":"4","note":"","exp":"680","type":"気象・現象","name":"蜃気楼","desc":"東アジア西部・黄河河口付近。\n水平線の下にあるはずの風景が見える現象。海面上の温度差で光線が屈折することにより発生するといわれる。中国では霊獣の「蜃」が「気」を吐き「楼」閣を出現させるという伝説が残っている。"}],"6654":[{"rank":"5","note":"","exp":"1150","type":"中型生物","name":"グラウンドホッグ","desc":"リス科最大級の動物。別名ウッドチャック。北米の森林地帯周辺に生息する。複雑なトンネル網を構築し、巣とする。トンネルを掘る際、土をほぐしてくれるので、農家からは益獣として親しまれている。気性は荒い。"}],"69":[{"rank":"1","note":"インドの動物の地図","exp":"116","type":"中型生物","name":"インドレイヨウ","desc":"インドのレイヨウ。ウシに似ているがウシよりほっそりしている。ねじれた大きな角を持つ。"}],"1857":[{"rank":"1","note":"ガラス細工の地図","exp":"160","type":"歴史遺物","name":"フェニキアのガラスつぼ","desc":"手先が器用だったフェニキア人は、多くの工芸品を作成し、交易した。材料であるケイ素分の多い海砂を用いて優秀なガラス製品を作った。ガラスの製法はエジプトから学んでいたと見られ、二国の蜜月さが伺われる。"}],"1638":[{"rank":"3","note":"もうひとつの航路","exp":"495","type":"地理","name":"バヌアツ","desc":"オーストラリアからはるか東北東、ニューカレドニア島から北北東に位置する諸島。島の半数は火山島である。島々は山がちで、最高峰はエスピリトゥサント島のタブウェマサナ山である。島ごとに独自の文化が発達しているようだ。"}],"5093":[{"rank":"1","note":"到達する","exp":"38","type":"港・集落","name":"チュニス","desc":"かつて古代都市・カルタゴがあった場所である。7世紀後半にイスラム勢力によって街が築かれた。その後、いくつかの独立王朝の首都とされ、国際色豊かな都市となった。産物は、農作物と麻生地のほか、高級染料が採れる。"}],"1998":[{"rank":"2","note":"釣り","exp":"250","type":"海洋生物","name":"レッドエンペラー","desc":"オーストラリアの周辺に生息するフエダイの仲間。身は大変おいしい。"}],"1760":[{"rank":"1","note":"メソアメリカの土器の地図","exp":"110","type":"歴史遺物","name":"白色紋様土器","desc":"白い土器のつぼに、幾何学の紋様が施されている。この白は石英を混ぜて出したものではないだろうか。"}],"1939":[{"rank":"2","note":"サルベージ","exp":"390","type":"歴史遺物","name":"ヴィッテ・レーオ号","desc":"白い獅子を意味する、ネーデルラントの東インド貿易船の一隻。\n東アジアで香料を積んで帰国する途中、ポルトガルのキャラック船に襲撃され、セントへレナ島沖で沈没した。"}],"830":[{"rank":"1","note":"暖かな海の大きなカメ","exp":"140","type":"海洋生物","name":"アカウミガメ","desc":"熱帯から温帯にかけて生息する、大型のウミガメ。甲羅は赤褐色。大きな個体では体重が300kgを超える。"}],"1035":[{"rank":"1","note":"野生の羊の地図","exp":"13","type":"中型生物","name":"バーバリシープ","desc":"岩山に住む、羊と山羊の中間のような動物。1頭のオスと複数のメスで群れを作る。"}],"1154":[{"rank":"4","note":"アステカ戦士の戦闘法","exp":"648","type":"歴史遺物","name":"黒曜石の剣","desc":"アステカの武器に多く見られる、黒曜石でできた剣。切れ味は鋭いが強度が低い。量産されていたのだろう。"}],"3547":[{"rank":"","note":"","exp":"3050","type":"レリック","name":"プレステ・ジョアン","desc":"オン・ハンの率いたケレイト族にはキリスト教徒が多かったという。それゆれにプレステ・ジョアンの伝説に取り込まれたのだろう。"}],"4845":[{"rank":"3","note":"「ふたご座流星群」<br/>h発見物カード:255","exp":"510","type":"天文","name":"ふたご座流星群","desc":"ふたご座の方角から、飛び出して来るように見える流星群。一年のうち約15日間、出現する。流星群の中では比較的穏やかな見え方をする。"}],"1404":[{"rank":"1","note":"野生の犬の地図","exp":"110","type":"中型生物","name":"ドール","desc":"森林や草原に10頭前後の群れで生息する。嗅覚で獲物を追跡し、イノシシやレイヨウなどを捕食する。"}],"2337":[{"rank":"1","note":"古代の書き物の地図","exp":"190","type":"歴史遺物","name":"古代の木簡","desc":"日本で発見された、文字が記された木札。紙を作る技術がなかった時代のもので、中国などでも同様のものが見られる。\nつづられた文字からは当時の人々の生活がうかがい知れる。"}],"6118":[{"rank":"5","note":"","exp":"1190","type":"鳥類","name":"ニジキジ","desc":"インドなどに生息する大型のキジ。他のキジの仲間と比較して体格がよく、短い尾羽が特徴的。特にオスの羽毛は、虹を思わせる金属のような光沢があり、これが名前の由来となった。"}],"3758":[{"rank":"5","note":"クエスト「蠍を狙う射手」<br/>発見物カード470","exp":"940","type":"天文","name":"いて座","desc":"黄道十二星座の1つ。ケンタウロスの賢者ケイロンが天に昇った姿とされる。天の川にかかる部分に、ひしゃくに似た並びの6つの星があり、ヨーロッパではミルク・ディッパー東洋では南斗六星と呼ばれることがある。"}],"2610":[{"rank":"5","note":"灰の上を歩く祭り","exp":"1060","type":"宗教遺物","name":"火渡りの神輿","desc":"読みは「ひわたりのみこし」。古代から台湾島に伝わる神輿。清めの儀式で使われた。\nこの神輿を担ぎ、熱い灰の上を歩くと、穢れが取り除かれ、災いを避けられるといわれている。"}],"3423":[{"rank":"","note":"","exp":"","type":"レリック","name":"レメゲトン","desc":"かのソロモン王の秘術や、悪魔や天使の使役法が記された魔道書。数多の知識が記されているのだが、良いものばかりとも思えない。"}],"783":[{"rank":"3","note":"太陽が愛でる樹","exp":"451","type":"植物","name":"ゲッケイジュ","desc":"ギリシャ神話に登場する妖精ダフネが、アポロンの愛から逃れるために姿を変えたとされる樹。その葉は料理や魔除けなど、幅広く使われている。"}],"3737":[{"rank":"4","note":"極寒の地に咲く花","exp":"680","type":"植物","name":"モスキャンピオン","desc":"コケマンテマとも呼ばれる植物。高山帯や寒冷な土地に分布する。地面を這って成長し、1cm程度の小さなピンク色の花を咲かせる。"}],"6009":[{"rank":"3","note":"アムステルダム地図","exp":"","type":"財宝","name":"ガルス陶器","desc":"「掻き落とし」と呼ばれる技法によって作られたイスラムの陶器。\n緑釉（りょくゆう）によって文様が彩られていることが特徴的である。"}],"2811":[{"rank":"1","note":"古代の道具の地図","exp":"190","type":"歴史遺物","name":"渾天儀","desc":"読み方は、「こんてんぎ」。後漢時代に発明された天体観測機器。三つの円盤を組み合わせてあり、それぞれに細かく角度目盛が刻まれている。これにより天体の天球上の位置を読み取れる。"}],"6580":[{"rank":"5","note":"","exp":"","type":"植物","name":"ムユウジュ","desc":"仏教三大聖木の一つであり、釈迦の誕生にかかわるとされる木。\n淡い赤橙色の花を咲かせ、インドでは乙女の恋心を叶える木や幸福の木として親しまれている。"}],"3229":[{"rank":"2","note":"鍛冶場に残る物","exp":"400","type":"歴史遺物","name":"ヴァイキングの鉄釘","desc":"ランス・オ・メドーの作業場らしき跡地から発見された鉄製の釘。ヴァイキングの船などに用いられていたものと見られる。1000年代にヴァイキングによって鉄文化が北米にもたらされたことを示す遺物である。"}],"3618":[{"rank":"2","note":"釣り","exp":"340","type":"海洋生物","name":"ハーフバードパウト","desc":"北極海などの北の海の底に生息する魚。体長は20cm程度で、うろこがないのが特徴。胸びれを使って、海底を這うように泳ぐ。"}],"6960":[{"rank":"4","note":"発見物カード:390","exp":"780","type":"小型生物","name":"ヤマカガシ","desc":"水辺に生息する日本固有のヘビ。生息地域や個体によって体色の差異が大きいが、赤と黒の斑点が交互に並んだものがよく見られる。牙から注入する毒と、毒腺から飛散する毒の二種類を持つ。"}],"751":[{"rank":"1","note":"青いトンボの調査","exp":"150","type":"虫類","name":"アオマダラヤンマ","desc":"ヨーロッパの水辺でよく見られる。体が大きく、自分のなわばりを守るために他のオスを攻撃することもある。"}],"2508":[{"rank":"5","note":"中断された依頼","exp":"1120","type":"史跡","name":"紅毛城","desc":"イスパニア人が築城した赤い城。鄭成功が台湾島を平定してからは廃屋となっている。\n華やかな外観だが、地下からは異様な雰囲気が漂ってくる…。"}],"216":[{"rank":"1","note":"とがった石柱の地図","exp":"40","type":"歴史遺物","name":"オベリスク","desc":"エジプト文明で作られた、銘文が刻まれた細長い石柱。先端がとがった、特徴のある外観をしている。古代ローマでも作られた。"}],"5598":[{"rank":"2","note":"","exp":"250","type":"気象・現象","name":"竜巻","desc":"地上から上空の雲まで突風が渦巻き状に発生する現象。風は建物などを破壊するほど協力になることもある。ただ、そのほとんどが局地的なものであり、発生時間もかなり短い。"}],"6829":[{"rank":"5","note":"追究クエスト<br/>発見物カード:475","exp":"950","type":"大型生物","name":"ベンガルトラ","desc":"インドに生息する大型の肉食獣。夜行性で、森林や草原を中心に活動する。茶褐色の体毛に独特の黒い縞模様を持つ。体毛が白く変異した白変種はホワイトタイガーと呼ばれ、各地で神の使いとして崇められた。"}],"43":[{"rank":"1","note":"イスラムの歴史観","exp":"170","type":"財宝","name":"世界史序説","desc":"イブン・ハルドゥーン著の歴史書。14世紀後半に書かれたもので、王朝の興亡の法則性などを考察している。"}],"1981":[{"rank":"1","note":"釣り","exp":"160","type":"海洋生物","name":"コブシメ","desc":"南洋にすむ大型のコウイカ。カメレオンのように周りの風景に同化する。"}],"1966":[{"rank":"3","note":"アポロンの冠","exp":"460","type":"財宝","name":"月桂冠","desc":"ゲッケイジュの葉が付いたままの枝を編んで冠にしたもの。\nギリシャ神話によるとアポロンの求愛を拒んだダフネは身をゲッケイジュに変えた。失意のアポロンは、その枝を編んで冠とし、生涯被り続けたという。"}],"1555":[{"rank":"1","note":"鮮やかな色の鳥の地図","exp":"160","type":"鳥類","name":"ゴシキセイガイインコ","desc":"鮮やかな色合いの鳥。外観は多様で、群れで騒々しく鳴く。"}],"3200":[{"rank":"5","note":"空飛ぶペンギン","exp":"820","type":"鳥類","name":"パフィン","desc":"北米東岸の北部やヨーロッパ北部の沿岸で見られる海鳥。繁殖期になると目の周りにツノのような模様が現れることから、「ツノメドリ」とも呼ばれる。一見ペンギンのような容姿をしているが、飛ぶことができる。"}],"5744":[{"rank":"4","note":"","exp":"700","type":"宗教建築","name":"ショパン・アタ","desc":"ウスチュルト台地に存在する地下モスク。12世紀、ユーラシア大陸中央部へ派遣されたイスラム宣教団の1人の名を冠している。彼の師が杖を投げると杖から木が生えたといい、その木がこの地に今なお存在している。"}],"1779":[{"rank":"2","note":"古代メソポタミアの遺物","exp":"360","type":"歴史遺物","name":"シュメールの戦車","desc":"古代メソポタミアの都市国家シュメールで発明された戦車。四輪で車輪に輻がなく、ろばが牽く車体に乗った御者が槍を振り回して戦う。"}],"6943":[{"rank":"5","note":"発見物カード:710","exp":"1420","type":"虫類","name":"ベニスカシジャノメ","desc":"中南米の熱帯雨林などに生息する蝶の一種。ガラスのように透明な羽を持ち、後翅の一部にのみ赤い鱗粉によって色がついている。花の蜜や、発酵した果実などを食す。"}],"1644":[{"rank":"4","note":"先人の足跡","exp":"612","type":"地理","name":"ヴァン・ディーメンズ・ランド","desc":"オーストラリア南東部の南にある島。この島を発見したタスマンは当時の東インド会社総督ヴァン・ディーメンにちなみ、この名をつけた。この島でしか見られない動物が多いため、生物学者には垂涎の土地である。"}],"1220":[{"rank":"5","note":"炎を下さい","exp":"816","type":"財宝","name":"踊る炎","desc":"極めて強い遊色効果を持つオパール。まるで炎を封じ込めたかのようだ。アステカでは炎を司る禍の神・シウコアトル由来のものと考えられ、封印されていた。"}],"488":[{"rank":"2","note":"ウドガートリ祭官の聖典","exp":"390","type":"宗教遺物","name":"サーマ・ヴェーダ","desc":"ヒンドゥー教の聖典の一つ。リグ・ヴェーダと同じく、神々への賛歌がまとめられたもので、詠唱を歌で行うウドガートリ祭官のためのものである。"}],"5407":[{"rank":"2","note":"","exp":"320","type":"財宝","name":"蛇型記章","desc":"古代エジプトのファラオの頭を飾るコブラの記章。金のコブラに宝石の象嵌が施されている。"}],"6474":[{"rank":"2","note":"クエスト「称えよ我らが大いなる女神を」<br/>発見物カード:140","exp":"280","type":"宗教遺物","name":"銀のアルテミス小像","desc":"銀製の小さな像。女神アルテミスをかたどったものとされるが、その姿はギリシャ神話とは大きく異なる。高さのある冠をかぶり、胸に多数の丸い飾りがついている。両腕を広げて両足を揃えた姿勢はエジプトや小アジアの影響があるようだ。"}],"858":[{"rank":"5","note":"天に帰った神","exp":"949","type":"宗教遺物","name":"ンゲウォ像","desc":"アフリカのシエラレオネ付近に住む、メンデ人の神像。ンゲウォは天空神で、大地を妻とする。人の近くに住んでいたが、やがて離れたと言われる。"}],"5365":[{"rank":"1","note":"","exp":"100","type":"財宝","name":"アトランティスの謎","desc":"ジョン・トラデスカントがアトランティス調査の一環でまとめた書物。アトランティスの神話から古代エジプトやギリシャの歴史、独自の視点によるアトランティス滅亡の解釈などが理路整然とまとめられている。"}],"5620":[{"rank":"5","note":"クエスト「天体一覧」<br/>発見物カード:515","exp":"1030","type":"財宝","name":"メシエカタログ","desc":"フランスの天文学者であるシャルル・メシアが作成した、天体についての書籍。星雲や星団など、あらゆる天体の目録となっている。"}],"2340":[{"rank":"2","note":"一対の守護獣","exp":"240","type":"宗教遺物","name":"狛犬","desc":"日本の寺院に多く見られる、二体一対の像。イヌに似た、想像上の獣をかたどっている。二体のうち一体は口を開き、もう一体は口を閉じた状態で置かれている。守り神として、人々に慕われているらしい。"}],"6881":[{"rank":"5","note":"発見物カード:700","exp":"1400","type":"天文","name":"カラ","desc":"りょうけん座のベータ星。星座の中では2番目に明るい4等星。元は南側の犬の名を指していたが、のちに星の名前となった。"}],"2866":[{"rank":"1","note":"黄色と赤の花の地図","exp":"130","type":"植物","name":"ブンカンカ","desc":"主に中国で見られる植物。白い花を咲かせるが、日がたつにつれ、中心部から次第に薄い紅色に色が変化する。"}],"1583":[{"rank":"3","note":"美しい頭","exp":"451","type":"鳥類","name":"オウギバト","desc":"ニューギニア島、および周辺の小島に生息する。70cmを超える大きなハトで、飛行能力はなく、数mほど飛び上がれるだけである。"}],"2333":[{"rank":"1","note":"随筆の地図","exp":"120","type":"財宝","name":"方丈記","desc":"鴨長明が著した随筆。移り変わりゆく人の世を憂い、感慨を述べた日本文学である。\n当時の災厄についての記述と、自らの草庵生活についての記述から成る。"}],"3729":[{"rank":"5","note":"失われゆく文字","exp":"1180","type":"歴史遺物","name":"パスパ文字の石片","desc":"モンゴル帝国で使用されている文字が彫られたという石片。上から下に読むようだ。"}],"5693":[{"rank":"4","note":"2017.02.07新規追加","exp":"740","type":"地理","name":"北極ツンドラ地帯","desc":"一年中溶けることのない永久凍土が広がる地域。トナカイなどの生物が生息し、短い夏には表面付近の土壌にコケや灌木などが育つ場合もあるため、不毛の土地というわけではない。"}],"1000":[{"rank":"2","note":"膨らんだ体","exp":"240","type":"小型生物","name":"フクラガエル","desc":"主に地中に棲み、降雨のあとに姿を見せる。追いつめられると、体をぷくっと膨らませ、地面の中に入る。"}],"6510":[{"rank":"5","note":"","exp":"","type":"宗教建築","name":"在りし日のオリンピアのゼウス像","desc":"古代ギリシャの年オリンピアの巨大なゼウス神像。表面は象牙と黄金で覆われ、黒檀の玉座は貴石で飾られていたという。このゼウス像に捧げる祭典として4年に1度開かれたオリンピア大祭では、さまざまな古代競技が競われていた。"}],"743":[{"rank":"2","note":"聖人になった王","exp":"220","type":"財宝","name":"聖王の鎧","desc":"聖王と呼ばれたルイ9世の鎧。ルイ9世は第7回、第8回の十字軍に従軍したが、チュニスでペストにかかり、陣没した。"}],"2849":[{"rank":"3","note":"李迪の最高傑作","exp":"470","type":"美術品","name":"李迪の静物画","desc":"南宋の宮廷画家・李迪が描いた、花の絵画。花鳥画の中でも特に高評価を得たもののようだ。"}],"22":[{"rank":"1","note":"アフリカのドラゴン","exp":"110","type":"化石","name":"角のないドラゴンの骨","desc":"非常に大きな動物の骨の形をした石。足が4本あり体が大きく首と尾が長く、まさに伝説のドラゴンといった姿なのだが、角と翼がない。伝説のドラゴンは誇張された姿で、これが本当の姿なのだろうか。"}],"1480":[{"rank":"3","note":"最果てに灯る火","exp":"484","type":"地理","name":"フエゴ島","desc":"南米大陸南端に位置する島。フエゴとはスペイン語で「炎」を意味する。先住民のヤーガン人は、極寒の島であるにも関わらず半裸で生活していた。そのため、島では焚き火の火が絶えず、島の名の由来となっている。"}],"6749":[{"rank":"5","note":"","exp":"","type":"天文","name":"さそり座の球状星団","desc":"さそり座の背にあたる位置にある星が球状に集まった星団。肉眼でも見ることができる。"}],"2073":[{"rank":"2","note":"［勅命］[[失踪した調査隊の追跡調査","exp":"310","type":"財宝","name":"金細工の耳飾り","desc":"本国に届けられるはずだった、金で作られた耳飾り。この地域独特の細工が施されているため、ヨーロッパでの価値は高いだろう。"}],"509":[{"rank":"2","note":"古代の荷車の地図","exp":"230","type":"歴史遺物","name":"古代の荷車","desc":"一度に大量の荷物を運ぶためのもの。車輪が発明された文明で使われる。車輪がない文明では、コロが使われていたようだ。"}],"3207":[{"rank":"3","note":"甘い香りの木<br/><br/>発見時経験値440　発見物カード経験値220","exp":"440","type":"植物","name":"バルサムモミ","desc":"北米北東部を中心に広く分布する樹木。樹高は20m程度で、円錐型に枝を広げる。バニラに似たほのかな甘い香りを放つ。"}],"873":[{"rank":"1","note":"桃色の大きな鳥","exp":"80","type":"鳥類","name":"フラミンゴ","desc":"首と足が非常に長い、大型の鳥。美しいピンクの羽を持つ。数万羽にもなる群れで生活するため壮観である。ツルに似ているがくちばしが異なるのでそれほど近い種類ではないかもしれない。"}],"6437":[{"rank":"5","note":"レガシー　数の叡智・世界の計算機　左下","exp":"","type":"歴史遺物","name":"ネイピアの骨","desc":"スコットランドのジョン・ネイピアが17世紀初めに発明した計算器具。ラブドロジーとも呼ばれる。九九の表が組み込まれて掛け算を簡単にできるほか、応用として複数桁同士の掛け算や割り算、平方根を求める計算なども可能。"}],"2656":[{"rank":"3","note":"永遠の花","exp":"490","type":"植物","name":"ムクゲ","desc":"朝鮮では、国の繁栄を意味する花として慕われている植物。一つの枝にたくさんの花を咲かせ、散っても次々と花を咲かせる様が、永遠を感じさせる。\n樹皮や花を乾燥させたものは薬にもなる。"}],"17":[{"rank":"2","note":"アナトリア半島の青銅器","exp":"360","type":"歴史遺物","name":"青銅の装飾","desc":"アナトリア半島から出土した、青銅製の装飾品。なにに使ったのかは不明だ。アナトリアに興ったヒッタイトはやがて製鉄の技術を発見する。"}],"5106":[{"rank":"1","note":"到達する","exp":"28","type":"港・集落","name":"ナポリ","desc":"紀元前、ギリシャ人によって築かれた歴史ある街。かつては「新しい街」を意味するネアポリスと呼ばれた。今も、地中海の中央部に位置するため地中海交易の重要な拠点である大都市だ。"}],"5572":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:155","exp":"310","type":"天文","name":"はちぶんぎ座","desc":"ラカーユが制定した南天の星座のひとつ。天体観測に用いる八分儀をかたどっている。"}],"5019":[{"rank":"1","note":"到達する","exp":"42","type":"港・集落","name":"アルジェ","desc":"西暦980年に、イスラム勢力によって建設された街。近年、バルバリア海賊に占領され、拠点となった。紡績や鉱業のほか、農業が盛んである。"}],"2874":[{"rank":"2","note":"古い石碑の地図","exp":"250","type":"歴史遺物","name":"新羅語の碑文","desc":"高句麗時代に建てられたと思われる石碑。四面に渡り、文字が刻まれている。\n高句麗と新羅の関係について書かれているらしいが、損傷が激しく解読は難しい。"}],"755":[{"rank":"3","note":"青い宝石の鉱脈の地図","exp":"530","type":"財宝","name":"コーンフラワーブルー","desc":"最上級のサファイヤ。矢車菊のような美しい青色をしているため、こう呼ばれる。限られた地域でしか採れないという。"}],"5405":[{"rank":"3","note":"","exp":"460","type":"海洋生物","name":"ムツ","desc":"大型の深海魚で1mを超えることもある。身は脂がのっており美味。"}],"3810":[{"rank":"5","note":"欧州に伝わる海賊譚<br/><br/>発見時経験値1210　発見物カード経験値605","exp":"1210","type":"財宝","name":"海賊史","desc":"17世紀末から18世紀初頭にかけて活動していた海賊の伝記集。さまざまな海賊の生涯が克明に記されている。"}],"5271":[{"rank":"2","note":"コパン川北岸　再調査報酬","exp":"360","type":"歴史遺物","name":"祭壇のレリーフ","desc":"コパン遺跡で見つかった石製のレリーフ。コパンの歴代16人の王の姿が彫られている。初代から16代へ権威の象徴たる笏が手渡される様子を表す。"}],"5515":[{"rank":"3","note":"","exp":"470","type":"財宝","name":"ヴァリハ","desc":"マダガスカルの伝統的な竹製の楽器。東南アジアの各地に似た楽器があり、東南アジアからマダガスカルへの移住に伴って持ち込まれた楽器が起源と推測される。"}],"2039":[{"rank":"2","note":"［勅命］[[運河開通への記録","exp":"310","type":"歴史遺物","name":"メルエンプタハ碑文","desc":"古代エジプトのファラオ、メルエンプタハ王の時代に残されたと思われる碑文。\n損傷が激しく読み辛いが、「シェケン運河」や「エティ運河」と読める部分がある。"}],"48":[{"rank":"1","note":"イベリア半島の南西端","exp":"20","type":"地理","name":"サンヴィセンテ岬","desc":"イベリア半島の南西端にある岬。大西洋に突き出しており、よく航海の目安にされる。"}],"227":[{"rank":"5","note":"トロイ王家の財宝","exp":"936","type":"歴史遺物","name":"プリアモス王の財宝","desc":"ギリシャ神話に登場する、トロイの最後の王の財宝。プリアモス王の息子・パリスのために戦争が起き、トロイはギリシャに滅ぼされた。"}],"2102":[{"rank":"4","note":"語り継がれる英雄<br/><br/>発見時経験値720　発見物カード経験値360","exp":"720","type":"財宝","name":"我がシードの歌","desc":"レコンキスタの英雄といわれるエル・シードを主役にした叙情詩。史実と脚色を混ぜてある。原本は失われ、写本もところどころ欠落しているため、正確な題名、作者は不明。"}],"1855":[{"rank":"5","note":"女神の魂","exp":"1230","type":"財宝","name":"ウミナの魂","desc":"インカ皇帝・パチャクティが所持していたというダチョウの卵大のエメラルド。アンデス北部を征服した際に現地の民に授けたといわれている。現在はチブチャ民族の重要な祭具として、ソモンドコの奥深くに眠っている。"}],"5539":[{"rank":"2","note":"紅海　セイラ南東　(1972.4235付近)<br/>星空　日没後すぐ　海面変化","exp":"150","type":"気象・現象","name":"火球","desc":"流星が通常より明るく輝きながら移動する現象。発生後、稀に地表で残骸らしきものが発見される。"}],"3885":[{"rank":"3","note":"伝説の牛追い人","exp":"460","type":"財宝","name":"ラリアット","desc":"ウシなどの動物を捕まえるための投げ縄。\n罠の先が輪になっており、家畜の体に掛けて引っ張ると締まる仕組みになっている。"}],"6049":[{"rank":"1","note":"銅細工の地図","exp":"150","type":"歴史遺物","name":"兵士の群像","desc":"ビブロスのオベリスク神殿から出土した、青銅製の兵士像。エジプトからの贈呈品と思われる。エジプトは、ミイラ作成や建材用にレバノン杉を輸入しており、大量の供物をしてビブロス王の機嫌をとっていたという。"}],"5178":[{"rank":"2","note":"到達する","exp":"332","type":"港・集落","name":"ロッブリー","desc":"チャオプラヤ川流域の街。10世紀までラウォーと呼ばれていた。クメール系モン人たちの都市として知られた後に、アユタヤの重要都市として栄えた。"}],"1298":[{"rank":"2","note":"丸太のような生物<br/><br/>発見時経験値220　発見物カード経験値110","exp":"220","type":"中型生物","name":"バビルーサ","desc":"バビルーサとは現地の言葉で「ブタ、シカ」という意味。上あごから皮膚を突き破って生えた牙が特徴。牙はオス同士の戦いなどに用いられる。"}],"6929":[{"rank":"4","note":"発見物カード:325","exp":"650","type":"植物","name":"グラジオラス・アブレヴィアトゥス","desc":"古代ローマの剣闘士が用いた剣、グラディウスの名がつけられた花の一種。剣の形をした葉が由来とされる。朱色で筒状の花は独特の形状で、植物の分類を決めるまで議論を呼んだ。"}],"3588":[{"rank":"1","note":"太平洋の真ん中","exp":"120","type":"地理","name":"ハワイ島","desc":"太平洋のほぼ中心にある島群の中で、最大の広さを持つ島。火山活動が活発で、島の大半は溶岩が凝結した土地から成る。"}],"1874":[{"rank":"5","note":"黄金の筏","exp":"1070","type":"宗教遺物","name":"黄金の筏","desc":"チブチャ民族の儀式に使われる黄金製の筏。族長は、月夜の晩に全身金粉を塗って黄金の筏から湖に飛び込むという儀式を行う。"}],"4971":[{"rank":"2","note":"","exp":"210","type":"宗教建築","name":"メテオラ","desc":"ピンドス山脈麓の岩山群の上に建てられた修道院。修道僧が祈りに専念できるよう、俗世から隔絶された場所に建てられた。ギリシャ語で「宙に浮く」という意味の「メテオロス」という言葉が名に由来している。"}],"41":[{"rank":"4","note":"イスラムの英雄","exp":"648","type":"財宝","name":"サラディンの剣","desc":"アイユーブ朝の創始者サラーフ・アッディーンの剣。第3回十字軍でリチャード獅子心王（しししんおう）らと戦った。異教徒への寛容な対応で知られる。"}],"3938":[{"rank":"1","note":"「明るい星の観測記録」<br/>発見物カード:55","exp":"110","type":"天文","name":"ベガ","desc":"夏の大三角の一角を構成する、こと座で最も明るい星。白く輝く1等星で、竪琴の装飾としてつけられた宝石にあたるとされる。"}],"6576":[{"rank":"5","note":"","exp":"","type":"植物","name":"ムシトリスミレ","desc":"中米の熱帯高山に自生する食虫植物。一見するとスミレに似た花を咲かせる可愛らしい植物であるが、れっきとした食虫植物である。葉の表面に粘液で覆われた細かい毛が生え、とまった虫を捕らえて消化吸収する。"}],"5543":[{"rank":"1","note":"","exp":"75","type":"気象・現象","name":"虹","desc":"大気中に半円状の光の帯が発生する現象。5から7色ほどの複数の色の帯で構成される。雨の降った後に発生しやすいが、その関連性は不明である。"}],"648":[{"rank":"1","note":"書きかけの地図","exp":"90","type":"地理","name":"ナイル川","desc":"アフリカを流れ、地中海に注ぐ大河。毎年決まった時期に大洪水を起こし、これによって流域に肥沃な土がもたらされる。非常に長い川で、水源を突き止めるのは至難の業だと思われる。"}],"1042":[{"rank":"1","note":"洋上の交易路","exp":"160","type":"地理","name":"アラビア海","desc":"インドとアラビア半島の間の海域。ペルシャ湾や紅海とつながり、インドとアラビア、アフリカの交易の舞台である。古くから栄えている海域で、航行する船が非常に多い。"}],"4959":[{"rank":"1","note":"","exp":"","type":"史跡","name":"アポロ・エピクリウス神殿","desc":"ペロポネソス半島中央部の山中にある神殿。ギリシャ神話の太陽神アポロンのために造られたといわれている。古代ギリシャにおける三つの主要な建築様式が用いられており、現地で採れる青みを帯びた方解石が素材となっている。"}],"1130":[{"rank":"2","note":"レスカトール<br/><br/>発見時経験値330　発見物カード経験値165","exp":"330","type":"財宝","name":"闘牛場チケット","desc":"かつてバレンシアで、人気闘牛士レスカトールが登場した際、あまりに混雑したため配られた整理券。\n急きょ作られたもののようだが、レスカトールの肖像が描かれており、貴婦人たちを熱くさせたという。"}],"281":[{"rank":"1","note":"ポエニ戦争の爪跡","exp":"110","type":"史跡","name":"カルタゴ遺跡","desc":"古代フェニキア人が造った都市国家の跡。第三次ポエニ戦争でローマに滅ぼされたといわれる。カエサルによって再建されたが、7世紀末に廃墟となった。"}],"1087":[{"rank":"4","note":"東国より僧来たる","exp":"744","type":"宗教遺物","name":"玄奘三蔵の旅行手形","desc":"中国の唐からインドに留学した、玄奘三蔵という僧侶の旅行手形。玄奘三蔵はインドから657部に及ぶ膨大な経典を祖国まで持ち帰り全てを翻訳したといわれている。"}],"6353":[{"rank":"2","note":"","exp":"300","type":"史跡","name":"太陽神の彫刻","desc":"ロードス島の巨像のモチーフになった太陽神ヘリオスの彫刻。古代ギリシャでは朝に太陽が昇り夜に沈むのは、ヘリオスが毎朝、太陽の戦車をひいて東から出発し、夜になると海に入り東へ戻るからと信じされていた。"}],"6068":[{"rank":"1","note":"","exp":"190","type":"鳥類","name":"キタヒメキンメフクロウ","desc":"北米に生息するフクロウで、その名のとおり小さな体と金色の目が特徴。人里の近くでも見られ、低木や藪を住みかにする。ネズミを捕らえて食べるため、人々の間では益鳥とされてるようだ。"}],"4980":[{"rank":"1","note":"","exp":"150","type":"植物","name":"アカンサス","desc":"地中海沿岸に分布する草花。光沢のある深緑色の葉で長さは60cm以上にもなる。古代ギリシャでは神聖な草花とされ、神殿の柱に彫刻された。"}],"1540":[{"rank":"2","note":"競技道具の地図","exp":"245","type":"歴史遺物","name":"アチャ","desc":"石に顔料を塗布したもの。古代の球技「トラチトリ」に用いられたらしい。"}],"6840":[{"rank":"3","note":"発見物カード:220","exp":"440","type":"小型生物","name":"エボシカメレオン","desc":"アラビア半島南部に生息するカメレオンの一種。海沿いの山地に広がる森林にすむ。体の大部分は緑色で、黒や黄色の文様があるが、周囲の様子などに合わせて変化する。烏帽子のようにとがった頭が特徴。"}],"1596":[{"rank":"2","note":"ミノス王の時代の面影","exp":"220","type":"歴史遺物","name":"タコの絵のアムフォラ","desc":"クレタ島の遺跡で見つかった壷。アムフォラとは壷の種類の名前で酒や油の運搬や保存に使われた。\n絵は、しなやかな線の洗練された様式で描かれている。タコなどの海の生物は、海に囲まれた島民にとって食や富の象徴であった。"}],"722":[{"rank":"2","note":"生と死の感覚","exp":"320","type":"歴史遺物","name":"金とラピスラズリの牡山羊","desc":"古代メソポタミアで作られた王族の副葬品。木像に、金やラピスラズリ、貝などで装飾が施されている。当時の豊かさがしのばれる。"}],"5153":[{"rank":"1","note":"到達する","exp":"126","type":"港・集落","name":"マッサワ","desc":"アフリカ北東部の街。紅海に面しており、「紅海の真珠」とも呼ばれる。非常に歴史の古い地域で、初期のキリスト教の名残が多くある。豆や穀類を中心とした農作物のほか、この地方が原産のコーヒーが流通している。"}],"1957":[{"rank":"1","note":"日陰に咲く花の地図","exp":"160","type":"植物","name":"メガスケパスマ・エリトロクラミス","desc":"枝の先に鮮やかな赤い花をいくつも咲かせる植物。その筒状の花の連なりは、まるで炎を束ねたかのように見える。大きいものは樹高4m程に成長する。中米の熱帯に生息。"}],"6687":[{"rank":"5","note":"","exp":"1150","type":"歴史遺物","name":"イスタンブールのルーン銘文","desc":"ビザンツ帝国時代にて帝都・コンスタンティノープルに大聖堂が建てられた。その欄干にルーン文字の銘文が残る。\n傭兵として派遣された「ヴァイヤーグ隊」というヴァイキングの末裔が刻んだとされる。"}],"6572":[{"rank":"5","note":"追究クエスト","exp":"1000","type":"史跡","name":"パフォスのモザイク","desc":"古代ローマの遺跡、パフォスにある建物跡から見つかったモザイクタイルの床。ギリシャ神話の英雄テセウスとミノタウロスが対決している様子を描いているとされる。他にもパフォスでは神話にまつわるモザイク画が多く見つかっている。"}],"1532":[{"rank":"2","note":"鄭和の航海誌 / 香料諸島方面進出の指標(勅命クエ)","exp":"360","type":"歴史遺物","name":"鄭和の航海誌","desc":"明の提督・鄭和の航海誌。鄭和は七度航海を行い、アフリカからキリンを持ち帰るなどした。この航海誌は散り散りになったものの一部で、内容を全て把握することはできない。"}],"4966":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:125","exp":"250","type":"天文","name":"いて座の黒い筋の入った星雲","desc":"いて座のやや西にある星雲で、所々に暗黒星雲の塊が散らばっている。空が十分に暗い場所であれば肉眼で見ることができる。"}],"1529":[{"rank":"1","note":"巨大なクモの地図","exp":"105","type":"虫類","name":"オオツチグモ","desc":"赤と黒の毛が生えた巨大なクモ。敵から身を守るとき、腹部の毛を逆立てる。"}],"6034":[{"rank":"1","note":"","exp":"100","type":"歴史遺物","name":"東ローマ書記官の手記","desc":"ビザンツ帝国の書記官が遺した手記。著者はビザンツ皇帝コンスタンティノス11世と共にコンスタンティノープル陥落戦で戦死したらしい。皇帝がオスマントルコのメフメト2世に徹底抗戦の意志を表明したときの言葉が記されている。"}],"3813":[{"rank":"4","note":"カンペチェ湾の要塞","exp":"680","type":"史跡","name":"カンペチェ要塞","desc":"メキシコ湾に面する貿易港であるカンペチェに築かれた要塞。海賊の襲撃に対する防衛を目的としている。"}],"3901":[{"rank":"1","note":"「天文学者の観測記録」<br/>発見物カード:60","exp":"120","type":"天文","name":"オリオン座の傘のような星雲","desc":"オリオン座の三ツ星の南に連なる小三ツ星の中央にある星雲。星雲の中ではかなり明るいため、肉眼でも見られる。"}],"110":[{"rank":"2","note":"カリブへの足がかり","exp":"360","type":"地理","name":"バハマ諸島","desc":"カリブ海のキューバ島の北に点在する島々。属する島は700にもなるが、人が住めそうな島は50もない。この北には北米大陸が広がっている。"}],"1057":[{"rank":"2","note":"クエスト「老いた聖女」<br/><br/>発見物カード:140","exp":"280","type":"美術品","name":"マグダラのマリア","desc":"ドナテッロ作の木像。マグダラのマリアは、回心してイエスに従った女性で、イエスの死後は何も身につけず山にこもったとされる。この像は年老いた彼女の姿で、通常は若く美しく表される宗教像と一線を画している。"}],"6331":[{"rank":"5","note":"","exp":"1140","type":"歴史遺物","name":"チンチョロ文化のミイラ","desc":"南米のチンチョロ文化のミイラ。エジプトのミイラよりも古いと見られている。小さな子供をミイラ化したものは特に手の込んだ防腐処理が行われている。チンチョロ文化では権力者のみならず庶民もミイラ化の対象となったという。"}],"522":[{"rank":"1","note":"古代の集落の地図","exp":"17","type":"歴史遺物","name":"古代の石材","desc":"古代文明の石造建築に用いられた石材。中には巨大なものもあり、どうやって運んだり積んだりしたのかは謎である。"}],"3432":[{"rank":"","note":"","exp":"","type":"レリック","name":"ハーメルンの笛吹き男","desc":"ハーメルンの街から消えた笛吹き男と子供の伝承。\n伝承が示すものについては疫病など諸説あるが、東方への移民が真実らしい。"}],"1271":[{"rank":"1","note":"教会の宗教画の地図","exp":"110","type":"美術品","name":"聖ウェロニカ","desc":"ロベルト・カンビンの作品。油彩による着色方法を使用した最初期の画家の一人。この作品は聖女ウェロニカがイエスの顔をぬぐい、その顔が布に浮かび上がった様子を表現している。"}],"6884":[{"rank":"5","note":"追究クエスト","exp":"","type":"植物","name":"エピポギウム・アフィルム","desc":"ブリテン島で発見されたランの一種。葉を持たず、小さな花を咲かせる。見つけるのが極めて難しいことから、「幽霊ラン」と呼ばれることもある。"}],"4841":[{"rank":"2","note":"信仰の光","exp":"310","type":"宗教遺物","name":"イェルサレム第二神殿の欠片","desc":"バビロン捕囚によって破壊されたソロモンの神殿に代わり、イェルサレムに建設されたユダ人の神殿の欠片。\nヘブライ語で「放浪の場所へ」と銘打たれている。"}],"3311":[{"rank":"4","note":"傭兵に贈る兵法書<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740","type":"財宝","name":"武器の操作","desc":"ネーデルラントの総督マウリッツ伯の著作。マウリッツ伯は、軍事訓練の手法を細かく分化し、一つ一つの手順に対する理解度を高めることに成功。その情報を包み隠さずこの書物にまとめた。各軍の練度は著しく向上したという。"}],"374":[{"rank":"4","note":"画商が描いた絵画","exp":"624","type":"美術品","name":"レースを編む女","desc":"ヤン・フェルメール作の絵画。縦が24cm足らずの小さな絵画でありながら、一心にレースを編む女性が見事に描かれている。女性の手元は精密に、それ以外はあえて不明瞭に描くことで緊張感を出している。"}],"857":[{"rank":"4","note":"鉄の国","exp":"660","type":"歴史遺物","name":"ラバルナ王の剣","desc":"ラバルナ王はアナトリアを統一してヒッタイト王国を興した人物。ヒッタイトは鉄器の製造技術を独占して強国となったが、この王の治世ではまだ銅剣である。"}],"2590":[{"rank":"2","note":"古代の道具の地図","exp":"290","type":"財宝","name":"百歩蛇のつぼ","desc":"百歩蛇（ヒャッポダ）をかたどった陶器のつぼ。\n台湾島先住民であるルカイ民族やパイワン民族の制度では、貴族の身分の象徴とされ、平民は所有できない。"}],"6190":[{"rank":"2","note":"","exp":"350","type":"史跡","name":"ギョベクリ・テペの石柱群","desc":"現地の言葉で「太鼓腹の丘」の意味を持つ遺構。巨大な石柱がいくつも円を描くように並べられており、動物のようなレリーフが彫られた石柱も時折見られる。かなり大昔のものと思われるが、誰が何のために造ったのかは分からない。"}],"1830":[{"rank":"3","note":"責任と選択","exp":"600","type":"財宝","name":"キープ","desc":"インカ帝国の情報記録手段。紐に結び目を付けて数を表しているという。これを解読するには専門知識が必要だそうだ。また、これを送り届けるためのチャスキと呼ばれる飛脚がいた。"}],"1654":[{"rank":"4","note":"河口の群島","exp":"744","type":"地理","name":"メコンデルタ","desc":"メコン川の河口に位置し、無数の島を有する湿地帯。島の形成過程は三角州と同じく、メコン川が運搬した土砂が堆積してできたもののようだ。そのため、河口に存在する島の多くが低地であり、雨季になると水没する。"}],"1358":[{"rank":"4","note":"釈迦の乗る動物","exp":"624","type":"大型生物","name":"マレーバク","desc":"白と黒の二色に染まった体色が特徴。沼沢地の水辺でいろいろな植物を食べる。子供には白い縞模様がある。"}],"1156":[{"rank":"2","note":"ごつごつしたカメ<br/><br/>発見時経験値260　発見物カード経験値130","exp":"260","type":"小型生物","name":"マタマタ","desc":"ごつごつした甲羅と平たい頭部を持つ。川や池の底に生息し、先の尖った鼻のおかげで水面に上がらずに呼吸できる。"}],"2530":[{"rank":"1","note":"黄色いカメの地図","exp":"200","type":"小型生物","name":"セマルハコガメ","desc":"淡水付近に生息する、甲羅が大きなドーム状に盛り上がっているカメ。背甲と腹甲の隙間を完全に閉じることができる。頭部の色は褐色や暗緑色など、多くの種類が存在する。"}],"1631":[{"rank":"3","note":"夜のオウム<br/><br/>発見時経験値462　発見物カード経験値231","exp":"462","type":"鳥類","name":"カカポ","desc":"現地の言葉で「夜のオウム」を意味する鳥。飛ぶことができず、夕暮れ時になると活発に動き回る。"}],"5065":[{"rank":"1","note":"到達する","exp":"70","type":"港・集落","name":"サントメ","desc":"ギニア湾に浮かぶサントメ島の街。熱帯に適したサトウキビやココナツの栽培が行われている。また、近海ではサンゴなども採れるようだ。"}],"5633":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:115","exp":"230","type":"天文","name":"ケレス","desc":"火星の軌道の外側にある小惑星帯に位置する天体。惑星と似た軌道で動くが、惑星より小さい天体のようだ。"}],"7014":[{"rank":"3","note":"南太平洋海盆北視認","exp":"","type":"天文","name":"シャウラ","desc":"さそり座のラムダ星で2等星。アルファ星のアンタレスに次いで明るい。サソリの毒針の部分に位置し、名はアラビア語で「針」を意味する。"}],"1364":[{"rank":"2","note":"アステカ戦士の槍の地図","exp":"260","type":"財宝","name":"クアウテモクの槍","desc":"アステカ帝国の皇帝モクテスマの甥であるクアウテモクのものであるといわれている槍。彼は鷲の戦士として、戦場ではいつも気高くあったという。"}],"1902":[{"rank":"2","note":"［勅命］[[現地における生物の調査","exp":"310","type":"小型生物","name":"カエルクイコウモリ","desc":"中米の熱帯雨林に生息するコウモリで、その名のとおりカエルを捕食する。カエルの鳴き声で毒を持つか持たないかさえ判断してしまう能力は、頭より大きな耳のおかげだろう。"}],"533":[{"rank":"1","note":"古代の道具の地図","exp":"27","type":"歴史遺物","name":"彩文土器","desc":"「さいもんどき」。文様を描いた土器。多くの古代文明で作られ、色や文様にそれぞれ特徴がある。文様を研究すれば、文明間の交流が解明できると思われる。"}],"6541":[{"rank":"5","note":"","exp":"","type":"宗教建築","name":"エーヴベリーのストーンサークル","desc":"ブリテン島にある、先史時代の遺跡。遺跡内にある巨大な石が立ち並ぶストーンサークルはとても広大で、小さな村であればその中に収まるほどだ。遺跡の用途は不明だが、そこで儀式でも行っていたのだろうか。"}],"6340":[{"rank":"2","note":"「動物をもした金細工の像の地図」<br/>発見物カード:150","exp":"300","type":"宗教遺物","name":"金色のリャマ像","desc":"リャマの姿を模した金の像。目をはじめ、鼻や耳までも細かく再現されている。インカ帝国の儀式においては、リャマが生け贄として捧げられることがあったようだ。"}],"3693":[{"rank":"5","note":"寒冷地でのトラ調査<br/><br/>発見時経験値1090　発見物カード経験値545","exp":"1090","type":"大型生物","name":"アムールトラ","desc":"ロシア東部の沿岸に生息する大型のトラ。\n周辺に生息する大型の草食動物を捕食する。クマでさえ捕食できるため、最強の動物のうちの一種と言えるかもしれない。"}],"5507":[{"rank":"1","note":"座標　852,3030","exp":"17","type":"港・集落","name":"カッターロ","desc":"アドリア海の東側に位置する街。街並みなどにヴェネツィアの影響がうかがえる。"}],"1527":[{"rank":"2","note":"［勅命］[[香料諸島方面からの献上品","exp":"330","type":"植物","name":"コチョウラン","desc":"チョウが群がって飛んでいるように見えるほど、多くの花を咲かせる。密林の木々に張り付くように自生している。"}],"1561":[{"rank":"1","note":"石斧の地図","exp":"120","type":"財宝","name":"石斧","desc":"斧の頭部に石を用いた武器。古代から世界各地で見られる。ニューギニアでは金属器が使用されておらず、闘争の際は、石や骨、木で作られた武器を使用している。"}],"5412":[{"rank":"2","note":"","exp":"","type":"財宝","name":"ボンビーリャ","desc":"南米に住むグアラニーの人々が、茶の一種を飲むときに使用する道具。先端に複数の穴を空けた筒で、飲んだ際に茶葉が口に入らない構造になっている。"}],"3433":[{"rank":"","note":"","exp":"","type":"レリック","name":"ナスレッディン・ホジャ","desc":"トルコに実在したといわれる、裁判官にして哲学者である賢者。多くの小話の主人公となっており、ユーモアに溢れる人物である。"}],"2537":[{"rank":"2","note":"「三角模様のカエルの地図」<br/>発見物カード:120","exp":"240","type":"小型生物","name":"ムクカジカガエル","desc":"主に台湾島に生息するカエル。口の端から両目、両目から背中の間に三角模様を持つ。\n環境に応じて、淡い褐色から黒褐色まで体色を変化させる。"}],"318":[{"rank":"4","note":"ラビュリントスの伝説","exp":"708","type":"史跡","name":"クノッソス宮殿","desc":"古代クレタ文明の遺跡である。ギリシャ神話に登場する、ミノス王の居城跡。この宮殿の奥には、ミノタウロスがいたという迷宮「ラビュリントス」があったと伝えられる。"}],"2675":[{"rank":"4","note":"百済の都の名残","exp":"700","type":"史跡","name":"武寧王陵","desc":"百済25代王、武寧王の陵墓。\n武寧王は百済の国力を回復するため、中国や日本と密接な関係を築き上げたという。"}],"4862":[{"rank":"2","note":"無上の杯","exp":"350","type":"天文","name":"コップ座","desc":"大きな杯をかたどった星座。古くから各地で知られており、神の所持品や象徴などといわれている。"}],"5522":[{"rank":"1","note":"","exp":"100","type":"地理","name":"マージー川","desc":"イングランド北西部を流れる川。マンチェスターなどの用水に利用され、運河が建設されると、水運でも工業発展を支えた。"}],"5867":[{"rank":"5","note":"クエスト「星の炎上」<br/>発見物カード:715","exp":"1430","type":"天文","name":"おうし座の星雲","desc":"星の爆発によって生まれたと思われる星雲。その爆発を目撃したと思われる記録が数百年前の世界各地に残っているため、その規模の大きさがうかがえる。"}],"3303":[{"rank":"4","note":"そそり立つ岩柱","exp":"680","type":"地理","name":"ビュート","desc":"巨大な柱のような形状の地形。テーブル状の台地であるメサが、さらに浸食されて孤立したもの。北米の西部で多く見られる。"}],"947":[{"rank":"2","note":"不気味な魚の地図","exp":"295","type":"海洋生物","name":"フクロウナギ","desc":"深海に生息していると思われる、奇妙な姿の魚。ヘビのように細長い体に、とてつもなく大きな口をしている。尾の先は発光するようだ。"}],"1850":[{"rank":"5","note":"儀式の場所<br/><br/>発見時経験値1200　発見物カード経験値600","exp":"1200","type":"史跡","name":"マチュピチュ","desc":"高い峰々に囲まれたインカ帝国の都市。ケチュア語で「老いた峰」を意味する。段々畑や居住区、神殿などが計画的に配置され、インカの高度な建築技術がうかがえる。"}],"5099":[{"rank":"1","note":"到達する","exp":"36","type":"港・集落","name":"トリポリ","desc":"紀元前から栄えた古い街。時代によって、さまざまな名で呼ばれていた。十字軍の時代、十字軍の攻撃を避けるため、旧市街を放棄して内陸寄りに新しい街が築かれたという。産物は農作物のほか、繊維や医薬品である。"}],"2512":[{"rank":"2","note":"傷だらけの海洋生物","exp":"320","type":"海洋生物","name":"ハナゴンドウ","desc":"温帯や熱帯の海に生息する生き物。他の生物などと衝突することで皮膚に引っかき傷が残る。\n傷が付いた個所は、花が咲いているように見えるため、ハナゴンドウ（花巨頭）と呼ばれる。"}],"3646":[{"rank":"4","note":"草原地帯での暮らし","exp":"800","type":"大型生物","name":"蒙古牛","desc":"中央ユーラシアに生息するウシの一種。遊牧民に飼われ、放牧されていることが多い。体が小ぶりで、寒さに強いのが特徴。"}],"2079":[{"rank":"2","note":"［勅命］[[新大陸西岸方面の動物探索","exp":"310","type":"小型生物","name":"マーラ","desc":"南米の草原に生息するネズミ。ぴょんぴょん飛び跳ねて移動する。オスとメスは常に行動を共にし、一生つがいのままである。\nまた、オスはメスに対して、とても従順である。"}],"3579":[{"rank":"2","note":"［勅命］[[ジャワ思想調査","exp":"340","type":"宗教遺物","name":"般若経","desc":"はんにゃきょう。多くの仏教経典の総称。般若とはサンスクリット語でプラジューナー、「悟りの智慧」を意味する。"}],"6433":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"インカのユパナ","desc":"インカ帝国で使用されていたという計算用器具。凹みの中に小石や粒を入れ、法則にそって移動させることにより計算する。複雑な計算を素早く行い、ヨーロッパ人を驚かせたと伝わるが、詳しい使用法は不明のようだ。"}],"2253":[{"rank":"3","note":"クエスト「未発見の小島」<br/>発見物カード:235","exp":"470","type":"地理","name":"ポンペイ島","desc":"「石積みの上」という意味を持つ小島。マングローブに覆われており、島の中央には山がそびえている。\n森の奥には、建築物のような岩が見える。"}],"5851":[{"rank":"5","note":"","exp":"1360","type":"美術品","name":"レースグラスのゴブレット","desc":"レース模様のガラスで作られたゴブレット。ヴェネツィアのガラス製法は門外不出であり他のどの国であろうと同じものを再現することはできないだろう。"}],"6858":[{"rank":"1","note":"","exp":"1380","type":"天文","name":"ザヴィヤヴァ","desc":"おとめ座のベータ星。4等星で、女神の左肩あたりに位置する。\nアラビア語で「一角」を意味する言葉が名前の由来とされる。"}],"5213":[{"rank":"3","note":"","exp":"","type":"歴史遺物","name":"新港文書","desc":"平埔の人々の間で使われていた、土地売買に関する契約文書。現地の言葉であるシラヤ語をラテン語に訳して記している。この文書はネーデルラント人宣教師の教育活動の痕跡と考えられる。"}],"6033":[{"rank":"1","note":"北米の籠の地図<br/><br/>発見時経験値160　発見物カード経験値80","exp":"160","type":"美術品","name":"ナンタケット・バスケット","desc":"北米にあるナンタケッタ島の漁民たちに伝わる籠細工。鯨油の樽を作る技術を応用した製法で作られている。左右対称の形状と、木材を編んでいるとは思えないほどの緻密な網目が特徴的。最初期は蓋のないバスケットが主だったという。"}],"2126":[{"rank":"3","note":"弦なのに叩く<br/><br/>発見時経験値500　発見物カード経験値250","exp":"500","type":"財宝","name":"サントゥール","desc":"クルミ製の箱に鋼鉄製の弦を張り、それをメスラブと呼ばれる軽量の木の棒で叩いて演奏する打弦楽器。澄んだ音で聞く者を魅了するようだ。"}],"6939":[{"rank":"5","note":"発見物カード:700","exp":"1400","type":"天文","name":"シェアト","desc":"ペガスス座のベータ星白で、赤く輝く2等星。秋の四辺形を構成する星の1つ。名はアラビア語で「すね」を意味する。"}],"5531":[{"rank":"3","note":"","exp":"260","type":"気象・現象","name":"ブラックスモーカー","desc":"海底火山などと同様、海底から高温の熱水が噴出する現象。熱水に含まれる亜鉛や鉄などが海水と反応し、黒く変色する。"}],"5536":[{"rank":"2","note":"一度消えても条件合えば、上陸地点から出ずに再出現します。","exp":"140","type":"気象・現象","name":"濃霧","desc":"微細な水滴が空気中を漂うことで発生する現象。ときには数メートル先が見えなくなる場合もある。視界不良だけでなく、農作物の成長を阻害するという報告もあるようだ。"}],"3926":[{"rank":"1","note":"「天文学者の観測記録」<br/>発見物カード:95","exp":"190","type":"天文","name":"おおぐま座の丸い星雲","desc":"北斗七星のひしゃくの底にあたる部分にある星雲。丸い星雲の中にふたつの丸く暗い部分があり、フクロウの顔を思わせる。"}],"1820":[{"rank":"1","note":"金細工の地図","exp":"150","type":"財宝","name":"金の頭飾り","desc":"金とトルコ石を用いた凝った作りの頭飾り。儀式や祭事に用いたようだ。空色のトルコ石を頭に付けることで、邪悪な力を退散させようとしたのだろうか。"}],"2565":[{"rank":"2","note":"尾が割れた鳥の地図","exp":"260","type":"鳥類","name":"オウチュウ","desc":"台湾島や中国などの、農耕地や市街地に生息する黒い鳥。長い尾の先が、逆Ｙ字のように割れているのが特徴である。"}],"5173":[{"rank":"1","note":"到達する","exp":"31","type":"港・集落","name":"リスボン","desc":"フェニキア人によって築かれた、古い街。イスラム勢力に支配された時期に大きく発展して、重要な港として栄えるようになった。西ヨーロッパでもっとも美しい街だとされる。良質の陶磁器が製造されている。"}],"365":[{"rank":"3","note":"黄色い宝石の鉱脈の地図","exp":"555","type":"財宝","name":"イエローダイヤ","desc":"黄色いダイヤモンド。透明度が高いものほど価値が高い。"}],"2852":[{"rank":"4","note":"クエスト「奸雄の素顔」<br/>発見物カード:320","exp":"640","type":"財宝","name":"短歌行","desc":"三国時代の英傑・曹操が、赤壁の戦い前夜に宴席で詠んだといわれる詩。\n酒について詠んだ前半部分と、能力のある人材を求める詩を詠んだ後半部分からなる。"}],"3515":[{"rank":"","note":"","exp":"","type":"レリック","name":"ランスロット","desc":"円卓の騎士の中で最も優れた騎士ランスロット。湖の精に育てられたという「湖の騎士」はクラブのジャックのモデルといわれる。"}],"6868":[{"rank":"3","note":"発見物カード:255","exp":"510","type":"天文","name":"ズベン・エル・ゲヌビ","desc":"てんびん座のアルファ星。3等星で、4つ以上の恒星から成る多重連星。名はアラビア語で「南の爪」を意味し、元々はさそり座の爪にあたる部分であった名残といわれている。"}],"5029":[{"rank":"1","note":"到達する","exp":"40","type":"港・集落","name":"オデッサ","desc":"黒海に面している港湾都市。さまざまな物資が集散する貿易港である。"}],"1455":[{"rank":"2","note":"大砂漠","exp":"220","type":"地理","name":"サハラ","desc":"アフリカ大陸北部を覆う広大な砂漠。アラビア語で「荒れた土地」を意味する。各所で土器などが出土することから、古くからこの砂漠で暮らす民がいたことがうかがえる。またラクダを用いたキャラバンによる交易が発達している。"}],"2316":[{"rank":"2","note":"［勅命］[[現地の信仰と山の関係調査","exp":"310","type":"地理","name":"三清山","desc":"道教の名山の一つ。道教の三大神が並んで座っているように見えることから、この名が付いたとされる。"}],"2894":[{"rank":"3","note":"体内の風景","exp":"440","type":"美術品","name":"内経図","desc":"人体の側面を山水画のように描いたもので、内丹術と呼ばれる道教の修行法を絵画化したもの。\n動物や天体が象徴的な意味を持って人体図に配置されている。"}],"1168":[{"rank":"2","note":"変わった石","exp":"270","type":"歴史遺物","name":"メソアメリカの印章","desc":"土器製の円筒状印章。なにに使われたのかは定かではない。顔料を塗って体に付けたり、柔らかい状態の土器の上に転がして、模様を付けたりしたのだろうか？"}],"5170":[{"rank":"2","note":"到達する","exp":"270","type":"港・集落","name":"ランバイェケ","desc":"インカ帝国が栄える以前に繁栄していた文化の中心地。一年を通して温和な気候に恵まれているため、過ごしやすい。"}],"1901":[{"rank":"2","note":"木の葉の化け物","exp":"290","type":"虫類","name":"コノハムシ","desc":"外見が植物の葉に似ている虫。この特徴があるのはメスの成体で、産み落とす卵も植物の種に似ている。南国の果物の葉を好んで食べる。オーストラリア、東南アジア、インドの熱帯林に生息。"}],"5464":[{"rank":"2","note":"経験　:330<br/>カード:165","exp":"330","type":"地理","name":"三日月湖","desc":"アマゾン川でよく見られる三日月形の湖。\n川が極端に蛇行してしまうと、真っ直ぐ流れようとする流水が新たな流路をつくる。そのため、蛇行部分が切り離されて三日月湖ができるといわれている。"}],"2751":[{"rank":"3","note":"さまざまな水墨画<br/><br/>発見時経験値440　発見物カード経験値220","exp":"440","type":"美術品","name":"李公麟の絵画","desc":"朝鮮の画家・李公麟によって描かれたトラの絵画。\n写実的でありながら、顔をこっけいに描かれたトラは、どこかかわいらしく親しみやすい雰囲気がある。"}],"5134":[{"rank":"1","note":"到達する","exp":"21","type":"港・集落","name":"プリマス","desc":"イングランド南西部にある港町。イングランドにとって重要な位置にあるため、栄えている。産物は各種鉱石が中心で、特に石墨は重要な交易品である。"}],"5084":[{"rank":"1","note":"到達する","exp":"32","type":"港・集落","name":"セビリア","desc":"フェニキア人によって基礎が築かれ、古代ローマの時代から栄えていた。イスラム勢力に支配された間に大きく発展し、現在ではイスラムとヨーロッパの文化が混在した、独特の街並みを有する。"}],"6664":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"キレニア沈没船","desc":"古代ギリシャで活躍した貿易船。主な積荷はアンフォラ（陶器のつぼ）に入ったワイン。紀元前3世紀にサモス島を出港し、キプロス島に到着する直前に沈没した。"}],"1549":[{"rank":"1","note":"書きかけの地図","exp":"75","type":"地理","name":"ティウィ","desc":"オーストラリア北部にある島。ファン・ディーメン湾を越えるとアーネムランドがある。東のメルヴィル島、西のバサースト島のふたつを合わせてティウィと呼ぶ。ティウィ人が独特の文化を守って暮らしている。"}],"840":[{"rank":"1","note":"跳ねる魚の地図","exp":"27","type":"海洋生物","name":"イルカ","desc":"温暖な海でよく見かける大型の魚。なぜか水中で息ができず、背中にある穴で空気呼吸するようだ。魚ではないのかもしれない。"}],"2730":[{"rank":"2","note":"祈願の経典","exp":"380","type":"宗教遺物","name":"大蔵経の版木","desc":"大蔵経とは、経典の総集のこと。\n契丹からの侵略を契機に、国家防衛を祈願するため、高麗で製作が開始された。\n完成は1200年代半ば。版木は、八万余りあるという。"}],"1840":[{"rank":"2","note":"指輪が繋ぐ物語","exp":"280","type":"財宝","name":"シャクンタラー","desc":"「マハーバーラタ」をモチーフとして描かれた戯曲。グプタ朝時代にカーリダーサによって作られた。"}],"5740":[{"rank":"1","note":"2017.02.07新規追加","exp":"200","type":"地理","name":"オリホン島","desc":"バイカル湖に浮かぶ最大の島。島の東側は山地になっており、それ以外にも針葉樹林、草原、小さな砂漠、湖など、変化に富んだ地形をしている。古くからモンゴル系の民族が住んでいる。"}],"1628":[{"rank":"4","note":"間延びしていない絵","exp":"720","type":"美術品","name":"ろうそくに火を灯す少年","desc":"エル・グレコ作。ろうそくに火を灯す少年の静謐な表情と、火の一瞬のゆらめきをとらえた名画である。エル・グレコがイスパニアに渡る前に描かれたもので、彼の特徴である人物を引き伸ばして描く画法は用いられていない。"}],"4962":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:165","exp":"330","type":"天文","name":"へびつかい座の鳥形の星雲","desc":"へびつかい座といて座の中間にあり、鳥が羽を広げたような形状をしている星雲。小さな星がいくつも重なって見える。"}],"85":[{"rank":"2","note":"エジプトの王の遺物","exp":"220","type":"歴史遺物","name":"メンカウラー王のトライアド","desc":"メンカウラー王はギザのピラミッドのうち、一番小さなピラミッドの主である。これはメンカウラー王と両脇に二柱の女神を置いた石像。"}],"584":[{"rank":"2","note":"豪華な宝石細工の地図","exp":"240","type":"財宝","name":"ターコイズの護符","desc":"巨大なターコイズをはめ込んである護符。ターコイズはさまざまな文明で護符とされていた。"}],"2321":[{"rank":"2","note":"巫女の鈴探し","exp":"260","type":"宗教遺物","name":"神楽鈴","desc":"読みは、「かぐらすず」。日本で、神道の儀式に用いられる鈴。神楽と呼ばれる歌舞の中で、舞い手はこの鈴を振り鳴らす。その音が神を呼ぶといわれている。"}],"5059":[{"rank":"1","note":"到達する","exp":"20","type":"港・集落","name":"サロニカ","desc":"テッサロニキともいい古代マケドニアの首都だった街。ビザンツ帝国の領土だったが、15世紀中ごろからオスマントルコの支配下に入った。農作物のほか、大理石や香料が流通している。"}],"5032":[{"rank":"1","note":"到達する","exp":"48","type":"港・集落","name":"カイロ","desc":"もとはビザンツ帝国の要塞であったが、10世紀にイスラム勢力が都市を築いた。それ以来エジプト地域の中心地として栄えている。特色のある農作物のほか綿生地が流通する。"}],"5135":[{"rank":"1","note":"到達する","exp":"15","type":"港・集落","name":"ヘルデル","desc":"アムステルダムの北にある小都市。北海に面しており、漁業が盛んである。"}],"1787":[{"rank":"1","note":"書きかけの地図<br/><br/>コピアポの門の外","exp":"200","type":"地理","name":"タティオ間欠泉群","desc":"アタカマ砂漠内にある間欠泉。標高4500mの場所にある。熱湯が地中から噴出し、蒸気が空に登る様は、非常に幻想的だ。"}],"3167":[{"rank":"2","note":"つぎはぎの門","exp":"330","type":"史跡","name":"コンスタンティヌスの凱旋門","desc":"帝政ローマ時代、戦争後の凱旋記念のために作られた門。コンスタンティヌス帝が正帝のマクセンティウス帝の勝利を祝って、作ったといわれている。"}],"1339":[{"rank":"2","note":"それぞれの岬に","exp":"330","type":"地理","name":"セレベス島","desc":"カリマンタン島の東に位置する、複雑な形をした島。全体的に山がちで、カリマンタン島以西と異なる多種多様な生物が生息する。\n島に暮らす人々の文化は場所によって大きく異なる。"}],"6376":[{"rank":"2","note":"","exp":"300","type":"気象・現象","name":"ダストデビル","desc":"地面から渦巻状に突風が立ち上る現象。温められた空気が上昇する際に強い横風を受けるなどで発生する。主に開けた場所で見られ、土や粉塵を巻き上げるが、竜巻とは異なり雲を伴わない。「つむじ風」とも呼ばれる。"}],"38":[{"rank":"3","note":"アレクサンドリア戦役","exp":"440","type":"歴史遺物","name":"カエサルの鎧","desc":"ユリウス・カエサルの鎧。刻まれた多くの傷は、ガリアを平定している際のものか、それともルビコン川を渡ってローマを占拠したときのものであろうか。"}],"1895":[{"rank":"1","note":"サルベージ","exp":"200","type":"歴史遺物","name":"サント・ラファエル号","desc":"ヴァスコ・ダ・ガマの兄パウロ・ダ・ガマが指揮したキャラック。インドへの航路開拓の帰路、壊血病による深刻な船員不足に直面したため、モンバサ南岸で破却された。"}],"336":[{"rank":"4","note":"暗闇にうごめく影","exp":"696","type":"中型生物","name":"アイアイ","desc":"マダガスカル島にしか生息していないと思われる動物。顔つきや前歯、行動などを見ていると非常に大型のリスだろうと思われる。しかし、手の指はリスとは異なる。独立した種かもしれない…。"}],"5137":[{"rank":"1","note":"到達する","exp":"64","type":"港・集落","name":"ベニン","desc":"アフリカ西部に位置する港町。西アフリカ全域と大規模な交易を行うなど、商業の中心地として発展した。"}],"2712":[{"rank":"1","note":"小さな花の地図","exp":"100","type":"植物","name":"フキスミレ","desc":"朝鮮半島及び中国北東部にかけて生息する植物。日当たりの良い場所を好む。\n他のスミレ同様、花は素朴である。"}],"2566":[{"rank":"5","note":"生物学者の望む地","exp":"1150","type":"地理","name":"阿里山","desc":"台湾島の中南部にある山々の総称。\n珍しい動物や、熱帯地域などで自生する植物などが多く生息している。"}],"6057":[{"rank":"2","note":"","exp":"390","type":"歴史遺物","name":"ベリサリウスの宝剣","desc":"東ローマ帝国の皇帝ユスティニアヌス1世の治世に活躍した将軍、ベリサリウスが愛用したという剣。\n彼は用兵の才に優れ、少数の騎兵でたびたび勝利を収めたが、晩年は不遇であったと伝えられている。"}],"1741":[{"rank":"1","note":"祭礼用土器の地図","exp":"90","type":"宗教遺物","name":"ワシククの祭礼用土器","desc":"ワシクク地方の祭事に使われた土器。飲料などの液体を入れることはなく、神像同様に信仰の対象になった。前面・背面の両面に同じ顔がつけられている。丸い瞳と、にんまりと笑ったような口元は、ヨーロッパではあまり見ない意匠である。"}],"3872":[{"rank":"2","note":"書きかけの地図","exp":"220","type":"地理","name":"モレーン湖","desc":"北米西部の、標高の高い場所にある湖。氷河の雪解け水によって形成されるといわれる。夏季の一時期にのみ満水になり、流れ込んだ砂などが太陽光で屈折すると、水面が美しいターコイズブルーに染まる。"}],"507":[{"rank":"1","note":"古代の衣服の地図","exp":"9","type":"歴史遺物","name":"古代の衣服","desc":"古代の衣類。地域によって素材や染色、縫製が異なる。それぞれの類似点から文化の伝達などがわかる。"}],"5838":[{"rank":"5","note":"","exp":"1410","type":"財宝","name":"メンドーザ写本","desc":"樹木の繊維を使って作られた絵文書。いまだ謎の多いアステカ文明について記述されている。"}],"5909":[{"rank":"5","note":"クエスト「杭州への再々調査依頼」<br/>発見物カード:730","exp":"1460","type":"天文","name":"西方七宿白虎","desc":"中国星座において、天の赤道を28に分割した二十八宿のうち西方の七宿をまとめたもの。おひつじ座やオリオン座などが含まれる。"}],"6873":[{"rank":"3","note":"","exp":"","type":"中型生物","name":"シマダイカー","desc":"アフリカに生息する、草食動物の一種。子鹿によく似た姿だが、ウ\nシ科に属する。体高は50cm程度。腰には黒い横縞が数多く入ってお\nり、オスメス共に耳の付け根に小さな角が生えている。"}],"2674":[{"rank":"3","note":"歴史の川","exp":"460","type":"地理","name":"白馬江","desc":"かつて、百済と新羅が争った地に流れる川。広い川幅と緩やかな流れ、白い砂州と緑の山並みが調和し美しい風景を作り出している。"}],"572":[{"rank":"2","note":"広大な海原","exp":"260","type":"地理","name":"インド洋","desc":"インドとアフリカに接する、広大な海域。インドからアフリカへの交易路である。インドの南部にはひたすら海原が広がるばかりである。"}],"2532":[{"rank":"2","note":"毒蛇の脅威","exp":"240","type":"中型生物","name":"タイワンハブ","desc":"主に台湾島や中国に生息している、毒性の強いヘビ。顔が細長く、長い牙を持つため、噛まれると体の深部まで毒が回ってしまう。\n樹上での活動が多く、夜行性である。"}],"1738":[{"rank":"5","note":"思い出を胸に<br/><br/>発見時経験値1222　発見物カード経験値611","exp":"1222","type":"財宝","name":"孔雀の胸飾り","desc":"虹色に美しく輝く巨大なオパールの周りに、真珠などの宝石をふんだんにあしらった胸飾り。職人が、本物のクジャクに負けないようなものを作ろうとしたのだろう。"}],"6290":[{"rank":"5","note":"","exp":"1060","type":"地理","name":"ハレマウマウ火口","desc":"ハワイ島にあるキラウエア火山の火口。ハワイ神話にて、火山の女神「ペレ」が住む所とされている。"}],"5006":[{"rank":"2","note":"","exp":"250","type":"地理","name":"キクラデス諸島","desc":"エーゲ海の中央部にある島々。古代ギリシャの宗教の中心だった島を他の島々が囲むように位置し、名前の由来になっている。島の数は220以上ある。"}],"5513":[{"rank":"3","note":"西アフリカの綺麗な籠<br/><br/>発見時経験値470　発見物カード経験値235","exp":"470","type":"美術品","name":"文様入りの手編み籠","desc":"アフリカ西部で作られる手編みの籠。色鮮やかな文様が編み込まれており、芸術的価値もある。"}],"4804":[{"rank":"4","note":"巨大な貨幣","exp":"700","type":"財宝","name":"石貨","desc":"ダバオの北東にある島で使われているという石製の巨大な貨幣。大きいなものは直径3mに及ぶ。 その重さから動かすことはできないが、儀礼の際に讓られると所有者だけが変わるようになっている。"}],"2968":[{"rank":"4","note":"緑の落とし穴","exp":"660","type":"植物","name":"サラセニア","desc":"筒状の葉を持つ食虫植物。筒自体が落とし穴のような構造をしており、これを利用して筒の底に溜まっている消化液まで虫を落とし、分解、吸収する。"}],"6966":[{"rank":"4","note":"","exp":"","type":"歴史遺物","name":"フロール・デ・ラ・マール号","desc":"名は「海の花」という意味を持つ、ポルトガルの商船。莫大な量の黄金とダイヤモンドをはじめとした宝石を積載していたが、ポルトガルへの帰還中、嵐によりマラッカ海峡で沈没した。"}],"4810":[{"rank":"","note":"安土城（深層隠し部屋）","exp":"","type":"財宝","name":"村正","desc":""}],"2654":[{"rank":"2","note":"尻尾のあるチョウ","exp":"300","type":"虫類","name":"ホソオチョウ","desc":"朝鮮半島に生息するアゲハチョウ。後羽に長い突起があることからこう呼ばれる。\n地上の低いところを緩やかに飛翔する。"}],"65":[{"rank":"2","note":"インドの神像の地図","exp":"245","type":"宗教遺物","name":"ハヌマーン像","desc":"インド神話に登場する猿神の像。ラーマーヤナで、主人公ラーマを助けて大活躍するため広く信仰される。毛が白いとされているためインドの白い猿はハヌマーンの使いとして手厚く保護される。"}],"2802":[{"rank":"2","note":"ヒゲまみれの顔","exp":"320","type":"小型生物","name":"キノガーレ","desc":"中国南部に生息する、カワウソのような姿をした動物。\n白くて長いひげは、口の周りから目の後ろまでびっしりと生えている。"}],"149":[{"rank":"1","note":"ケルト遺物の地図","exp":"30","type":"歴史遺物","name":"ケルトの神像","desc":"ケルト文明で信仰されていた神の像。青銅製で、頭部が大きく手足が小さい、独特の形状をしている。"}],"64":[{"rank":"1","note":"インドの女神像の地図","exp":"150","type":"宗教遺物","name":"ウシャス像","desc":"古代インドの女神の像である。真紅の衣と金色のヴェールをまとった、暁の女神。リグ・ヴェーダでもっとも美しいとされ、太陽神・スーリヤの妻である。"}],"5795":[{"rank":"5","note":"","exp":"1370","type":"歴史遺物","name":"日本書紀","desc":"古代日本の歴史書。神話の時代における国の成り立ちから持統天皇の治世までを記述しており、異説の併記が特徴的である。"}],"2762":[{"rank":"4","note":"麗人の舞","exp":"650","type":"財宝","name":"白拍子の衣装","desc":"男装の舞衣装。白拍子（しらびょうし）とは平安時代末期に起こった歌舞、または舞い手のこと。歌いながら舞う。女性が舞うことが多かったが、男性の舞い手も存在した。"}],"89":[{"rank":"1","note":"エジプトの女神像の地図","exp":"80","type":"宗教遺物","name":"バステト像","desc":"古代エジプトの、猫の姿、もしくは猫の頭部を持つ女神の像。猫はヘビを捕らえることから益獣として珍重されやがて神として崇拝されるようになった。バステトは猫の守護神であり、愛の女神でもあるという。"}],"2120":[{"rank":"1","note":"甘い匂いの誘惑","exp":"180","type":"植物","name":"ニゲラ","desc":"地中海の沿岸部に咲く植物。イチゴのような甘い香りのする黒い種と、鮮やかな色を持つ花が特徴である。\nこの種は香辛料としても使用される。\n別名クロタネソウ。"}],"2832":[{"rank":"5","note":"古代王の埋葬服","exp":"960","type":"歴史遺物","name":"金縷玉衣","desc":"読みは「きんるぎょくい」。前漢時代に作られたと思われる、身分の高い者が着る喪服。四角い玉片を黄金の針金でつづって作られている。これで遺体を覆うと、腐敗を防げると考えられていた。"}],"2955":[{"rank":"1","note":"足のある魚の地図","exp":"140","type":"小型生物","name":"レッサーサイレン","desc":"ウナギのような体に、二本の肢が生えている両生類。肢は四本の指を持ち、しっかりとした構造になっている。"}],"2104":[{"rank":"5","note":"士官の結論<br/><br/>発見時経験値1070　発見物カード経験値535","exp":"1070","type":"歴史遺物","name":"コラーダ","desc":"「我がシードの歌」では銀1000マルコ以上の価値があるとされる名剣で、バルセロナ伯との戦いに勝利した時に獲得したもの。"}],"146":[{"rank":"1","note":"クロテンの生息調査","exp":"90","type":"小型生物","name":"クロテン","desc":"黒というよりは茶色の毛のテン。冬毛が大変美しく、毛皮はセーブルと呼ばれて珍重される。乱獲のせいか、近年はほとんど見られなくなったようだ…。"}],"1885":[{"rank":"4","note":"アステカ人と黒曜石","exp":"744","type":"歴史遺物","name":"黒曜石の槍","desc":"アステカの古い武器には、金属製のものがあまり見られない。青銅は使われていたようだが、武器としては用いられなかったようだ。"}],"6188":[{"rank":"1","note":"","exp":"150","type":"植物","name":"ヤドリギ","desc":"他の樹木の枝の上に寄生する植物で、古代ギリシャやローマをはじめとするヨーロッパ全土でさまざまな伝承がある。古代ケルト人の間では神聖な植物とされ、同じく神聖視されているオークに宿生するものが特に珍重された。"}],"2372":[{"rank":"1","note":"赤い顔の鳥の地図","exp":"130","type":"鳥類","name":"トキ","desc":"東アジアに分布している鳥。全身ほぼ白色だが、翼と尾羽の裏側はとき色と呼ばれる淡紅色を帯びている。\n威嚇をする際は、後ろ頭の羽を冠のように立てる。"}],"1714":[{"rank":"2","note":"［勅命］[[未知の魅力","exp":"320","type":"財宝","name":"グンデル","desc":"ジャワ島に古くからある金属楽器。バチで金属の鍵盤を叩き、手で共鳴を適度に止めて、奏でる。ワヤン・クリの伴奏として演奏されることが多いが、祭礼や儀式でも演奏されるようだ。"}],"1572":[{"rank":"2","note":"泳ぐ鳥","exp":"285","type":"海洋生物","name":"コビトペンギン","desc":"最小のペンギン。地下の穴や岩場などに巣を作り、オスとメスが交代で卵を温める。海で潜水を繰り返し、魚を捕らえる。"}],"5591":[{"rank":"4","note":"","exp":"800","type":"鳥類","name":"カタカケフウチョウ","desc":"ニューギニア周辺に生息するフウチョウの一種。オスの羽の色は黒く、胸や背中などに青みがかった飾り羽がある。メスへの求愛時には、それらの羽を広げて左右に飛び跳ねる。"}],"5008":[{"rank":"2","note":"「書きかけの地図」<br/>発見物カード:155","exp":"310","type":"地理","name":"クレタ島","desc":"エーゲ海の南に位置する、ギリシャ地方最大の島。クレタ文明が栄え、クノッソス宮殿など多くの遺跡が残っている。"}],"5366":[{"rank":"4","note":"神話における狩り<br/><br/>発見時経験値690　発見物カード経験値345","exp":"690","type":"財宝","name":"大イノシシの牙","desc":"巨大なイノシシの牙。古代のイノシシ狩りの戦利品と思われる。\nギリシャ神話のカリュドーンのイノシシ狩りのエピソードではイノシシ狩りが伴う危険と名誉が描かれている。"}],"1677":[{"rank":"5","note":"約束した空の色","exp":"828","type":"鳥類","name":"スミレコンゴウインコ","desc":"全身を覆う濃い青色の羽毛、目の周りとくちばしの付け根の黄色い皮膚の配色が美しい。熱帯林の周縁部やヤシ林に生息し、ヤシの実を主食とする。"}],"1986":[{"rank":"1","note":"釣り","exp":"150","type":"海洋生物","name":"ストライパー","desc":"体に縞模様を持つスズキの一種で、淡水・汽水・海水に生息する。"}],"1219":[{"rank":"4","note":"パレンケの女王","exp":"768","type":"歴史遺物","name":"クック女王のイヤリング","desc":"クック女王とは、パレンケ王・パカルの母。パカルが王位に就ける年齢になるまで王座に座っていた。ひすいと黒曜石、陶器でできた女性らしいイヤリングである。"}],"5120":[{"rank":"1","note":"到達する","exp":"8","type":"港・集落","name":"パルマ","desc":"地中海に浮かぶマジョルカ島にある街。歴史は古く、古代ローマ時代から栄えた。白い砂浜と青い海に囲まれた美しい島で、独特の植物も多い。産物としては、タイムなどの香辛料が豊富で、近海ではサンゴが採れる。"}],"2706":[{"rank":"2","note":"ダンジョン","exp":"210","type":"歴史遺物","name":"石獣","desc":"百済時代の遺跡に置かれていた謎の獣の像。その姿はまるで、遺跡を守っているかのようだ。"}],"5383":[{"rank":"2","note":"アマゾン奥地　再調査報酬","exp":"","type":"鳥類","name":"タチヨタカ","desc":"主に中南米に生息する中型の鳥。枝に止まる際に、垂直に立つことから名づけられた。夜行性で、夜に獲物を見つけられるよう、目が大きく発達している。"}],"6077":[{"rank":"3","note":"","exp":"480","type":"美術品","name":"ネフェルティティの胸像","desc":"古代エジプトのファラオであったアメンホテプ4世の妃、ネフェルティティをモデルにしたとされる彫刻像。発掘された職人の工房跡では同型の彫像がいくつも出土しており、弟子たちの教育や練習を目的として作られたという説がある。"}],"5706":[{"rank":"4","note":"2017.02.07新規追加","exp":"720","type":"地理","name":"トゥズバイル塩湖","desc":"ウスチュルト台地に存在する塩湖。雪解け水や雨によって形成される。様々な条件が満たされると、水面に周囲の岩山が映し出され、幻想的な光景をみることができる。"}],"5955":[{"rank":"1","note":"冒険者のバイブル","exp":"55","type":"財宝","name":"東方見聞録","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。"}],"337":[{"rank":"4","note":"偉業の先駆者","exp":"684","type":"歴史遺物","name":"ヴェルギナの宝物","desc":"アレクサンドロス大王の父・フィリッポス2世のものと思われる墓地から出土した副葬品の数々。装身具や青銅の武具など。"}],"1341":[{"rank":"2","note":"香料諸島の空白地帯","exp":"280","type":"地理","name":"セレベス海","desc":"セレベス島北部に広がる海。魚の豊富な海域として知られているが水深が深いため、波は高く、海流も複雑である。周囲の島々の交流航路として船の往来が絶えない。"}],"3386":[{"rank":"5","note":"メソポタミアの文学者<br/><br/>発見時経験値820　発見物カード経験値410","exp":"820","type":"宗教遺物","name":"ニンメシャルラ","desc":"アッカド王国の初代の王・サルゴンの娘であり、ウルの神官でもあるエンヘドゥアンナが著した詩。相次ぐ反乱で国が乱れる中、イナンナ神に助けを求めて記されたとみられる。"}],"6261":[{"rank":"2","note":"","exp":"230","type":"小型生物","name":"オオガラゴ","desc":"アフリカ南部の森林に多く生息している、小さなサルの一種。ふさふさとした長い尾が特徴。夜行性で、昼は樹上や木のうろなどに隠れて眠っていることが多い。雑食で、虫や果実をはじめ、小鳥やその卵、花や種子などまで食べる。"}],"1355":[{"rank":"4","note":"不空成就如来像","exp":"720","type":"宗教遺物","name":"不空成就如来","desc":"ふくうじょうじゅにょらい。仏教における如来のひとり。名前には「空しいことはなにもなく、成し遂げることことこそ大事」という意味がある。"}],"6581":[{"rank":"5","note":"","exp":"500","type":"大型生物","name":"アラビアヒョウ","desc":"アラビア半島の山岳地帯に生息するヒョウの亜種。他の種と同様に夜行性。毛色は灰色がかった明るい色に、黒の斑点模様が際立ち、大変美しい。"}],"6741":[{"rank":"3","note":"バンダ海　5902.5021<br/>晴れ　夕方　10秒くらい","exp":"450","type":"気象・現象","name":"毛状雲","desc":"巻雲または巻層雲の一種。毛のように細い、すじ状の雲。5000mを越える対流圏に発生する。強風で雲の形が変わりやすく、常に他の場所へ流れている。"}],"6936":[{"rank":"2","note":"発見物カード:125","exp":"250","type":"史跡","name":"ティパサの遺跡","desc":"アフリカ北岸の街、アルジェ近郊にある都市の跡。古代フェニキア人によって造られ、バシリカや大聖堂、劇場などの施設が残されている。侵攻と宗教の問題により、街は七世紀に打ち捨てられた。"}],"5181":[{"rank":"2","note":"到達する","exp":"380","type":"港・集落","name":"ワンガヌイ","desc":"アオテアロアの南岸に位置する街。古くからマオリ人が居住し、交易の拠点であった。ワンガヌイとはマオリ人の言葉で「大きな港」を意味する。"}],"62":[{"rank":"3","note":"インドの古文書の地図","exp":"410","type":"宗教遺物","name":"梵字の巻物","desc":"「ぼんじ」。インドの梵字で書かれた巻物。梵字はもともとサンスクリット語の文字だがやがて宗教的意味が強くなった。"}],"6633":[{"rank":"5","note":"","exp":"830","type":"宗教遺物","name":"ルターの95か条論題","desc":"マルティン・ルターによって提起された、カトリック教会に対する批判論文。教会の贖宥状販売による腐敗を看過できず、ルターが当地教会の門に貼りつけた。その影響は大きく西ヨーロッパ諸国のキリスト教分裂の原因となった。"}],"5232":[{"rank":"2","note":"","exp":"350","type":"美術品","name":"アポクシュオメノス","desc":"古代ギリシャ彫刻に見られる身体を拭う人を模した彫象。手にはなにか道具のようなものを持つ。なぜこのような姿勢を模したのかは不明だが、独特な魅力をかもし出している。"}],"2880":[{"rank":"5","note":"シカとウシとウマとロバ","exp":"1030","type":"大型生物","name":"シフゾウ","desc":"中国北部から中央部にかけて生息している動物。ヒヅメはウシに、頭はウマに、角はシカに、体はロバに似ている。しかし、そのいずれとも異なるため「四不像」と呼ばれる。"}],"1967":[{"rank":"3","note":"儀式の象徴<br/><br/>発見時経験値530　発見物カード経験値265","exp":"530","type":"財宝","name":"銀の首切師の装飾","desc":"半円の形をした、銀の合金でできた副葬品。振ると円の縁についた玉が音を立てる。音を使った祭事に使われていたのだろうか。"}],"369":[{"rank":"1","note":"穏やかな皇帝","exp":"150","type":"歴史遺物","name":"アントニヌス・ピウスの王錫","desc":"ローマ五賢帝の四人目アントニヌス・ピウス帝の王錫だと思われるもの。大理石と金、サンゴ、真珠などで作られた優雅なものだ。"}],"1200":[{"rank":"3","note":"王の血と神々の護り","exp":"539","type":"歴史遺物","name":"チャン・バラム王の王冠","desc":"パカル王の息子で、その跡を継いだチャン・バラム王のものといわれている。勇壮な造りで、その力を誇示するように、大きな黒曜石がついている。"}],"2825":[{"rank":"3","note":"ダンジョン","exp":"480","type":"宗教遺物","name":"武則天の偽経","desc":"仏典中の「大雲経」に武則天らが手を加えて創作した偽経。\n女帝出現を預言する内容を含ませたことで、自ら皇帝の地位を得る足掛かりとした。"}],"6189":[{"rank":"5","note":"","exp":"1310","type":"財宝","name":"二重信仰についての論文","desc":"匿名で書かれた、ロシアの二重信仰に関する記録。著者はロシアの聖職者らしい。ウラジーミル1世が異教の神殿跡を教会に転用していった経緯や、異教の習慣を教会内に取り入れた例などの興味深い報告が記載されている。"}],"309":[{"rank":"2","note":"ラーマとシーターの物語","exp":"230","type":"財宝","name":"ラーマーヤナ","desc":"「マハーバーラタ」と並ぶ古代インドの大叙事詩。ヴィシュヌ神の化身・ラーマ王子と、彼の妻をさらった羅刹（らせつ）・ラーヴァナの戦いを描いたものである。"}],"1934":[{"rank":"5","note":"伝説を追う資格","exp":"1222","type":"鳥類","name":"トキイロコンドル","desc":"翼を広げると1.8mにもなる大型の鳥。動物の死がいを餌とし、生きた動物を襲うことはない。鮮やかな体色をしていて、くちばしの上部にオレンジ色の肉垂が付いている。"}],"6915":[{"rank":"3","note":"","exp":"","type":"小型生物","name":"シロヘラコウモリ","desc":"中米の熱帯雨林などに生息する小型のコウモリ。体長は4cm程度。白い体毛に覆われ、耳と鼻が黄色い。活動しない日中は、大きな葉を屋根のように折り曲げ、その裏側に寄り集まって過ごすという。"}],"2790":[{"rank":"2","note":"ドラゴンの妙な特徴","exp":"250","type":"化石","name":"首と尾の長いドラゴンの骨","desc":"重慶付近で見つかった細長い生物の骨。首と尾の長さが目立つ。\n泳ぎに適していそうな手と足を持っているが足の大きさから、陸地を歩いていたのかもしれない。"}],"2737":[{"rank":"3","note":"花郎の将軍","exp":"540","type":"史跡","name":"金庚信の墓","desc":"新羅の将軍・金庚信の墓。\n金庚信は花郎の出身で武烈王から厚い信頼を得た。新羅の三国統一に多大な功績を残したものの、統一目前で没し、ここに葬られた。"}],"1746":[{"rank":"5","note":"ニューギニアに住む人々","exp":"910","type":"財宝","name":"バヒネモ戦士の盾","desc":"ニューギニア島に住むバヒネモ民族が、他部族との闘争の際に使用する盾。かの島には多くの部族が存在し、その間で闘争が絶えなかった。描かれた絵やペイントは、敵対する相手を威圧する。それぞれ民族・部族で描かれるものは違うという。"}],"922":[{"rank":"3","note":"飛べない鳥","exp":"517","type":"歴史遺物","name":"黄金の玉座","desc":"豪華な装飾の施された黄金の玉座。背もたれにはファラオとその王妃と見られる人物の彫刻がある。彫刻の二人は、ひと組のサンダルを片方ずつ履くなど、仲睦まじい様子だ。"}],"5779":[{"rank":"5","note":"2017.02.07新規追加","exp":"1360","type":"地理","name":"キモロス島","desc":"エーゲ海に浮かぶ島の一つ。南海岸に銀色の岩場があり、交易の場として使われているらしい。島には毒蛇が生息しているため、エキドナ島と呼ばれることもあるようだ。"}],"3771":[{"rank":"3","note":"クエスト「逆行する惑星」<br/>発見物カード:260","exp":"520","type":"天文","name":"木星","desc":"黄道をおおよそ12年かけて一巡りするため、ローマ神話のユピテルを始め、高位の神の名をつけられることが多い。中国では歳星と呼ばれ、道教において天刑星の名で神格化されている。"}],"6538":[{"rank":"5","note":"","exp":"1060","type":"伝承","name":"サラマンダー","desc":"火の精。四大元素のうち、火をつかさどるとされる精霊。破壊と創造の二つの性質を備える。炎に包まれた女性の姿で現れるといわれるが、定かではない。その体内には恐ろしい毒があるが、上手く加工できれば強力な薬になるらしい。"}],"6111":[{"rank":"2","note":"現在は｢はくしもんじゅう」の読み方が一般的ですが、平安時代～明治時代までは｢はくしぶんしゅう｣と読まれていました。。。","exp":"380","type":"財宝","name":"白氏文集","desc":"中唐の文人である白居易文集。はくしぶんしゅうと読む。\n生前から多作の詩人として知られ、身分問わず広く読まれた。\n彼の詩は日本や新羅にも早くに伝わったが、偽作の民間\n流布本も多く出回ったという。"}],"5823":[{"rank":"4","note":"","exp":"700","type":"中型生物","name":"ヒガシダイヤガラガラヘビ","desc":"乾燥した森林地帯に生息する巨大な毒蛇。ダイヤのような菱形模様が特徴的で、大きいものでは全長240㎝にも達する。"}],"355":[{"rank":"2","note":"英雄の死","exp":"280","type":"歴史遺物","name":"アレクサンドロス大王の石棺","desc":"巨大な版図を築き上げながら志半ばに倒れたアレクサンドロス大王の石棺。全面を、遠征の様子の精緻なレリーフがおおっている。"}],"6739":[{"rank":"3","note":"カード経験:250","exp":"500","type":"海洋生物","name":"ナンヨウマンタ","desc":"世界で二番目に大きいとされるエイの一種。オニイトマキエイに似ており、よく間違われるが、背中にある曲線状の白い模様や口元の色などで区別できる。インド洋、太平洋の熱帯・亜熱帯海域に広く分布している。"}],"1907":[{"rank":"3","note":"隻眼の虎","exp":"530","type":"歴史遺物","name":"バイバルスの槍","desc":"マムルーク朝のスルタンである、バイバルスのものといわれている槍。バイバルスは、十字軍やモンゴル軍との数々の戦いに勝利し、内政の基盤を作るなど功績は大きい。バイバルス自身も優れた軍人で、特に馬術に秀でていたという。"}],"6940":[{"rank":"3","note":"発見物カード:275","exp":"550","type":"天文","name":"アルゲニブ","desc":"ペガスス座のガンマ星で、青白く輝く。秋の四辺形を構成する星の中で唯一の3等星。名はアラビア語で「翼」を意味する。"}],"2990":[{"rank":"2","note":"丸く見える生物の地図","exp":"220","type":"小型生物","name":"カロリナハコガメ","desc":"北米東部に生息しているハコガメの一種。背甲がドーム状になっていて、上から見ると円形。雄は雌より頭部が大型で、後肢の爪は太く短い。"}],"918":[{"rank":"2","note":"繁栄の証","exp":"210","type":"歴史遺物","name":"ガンジナーメの碑文","desc":"「ひぶん」。山の岩肌に刻まれた碑文。二つあり、一つはダレイオス1世のもの、もう一つは息子のクセルクセス1世のものである。"}],"3654":[{"rank":"2","note":"着替える鳥","exp":"380","type":"鳥類","name":"ライチョウ","desc":"北極海の沿岸や、ユーラシア北部の高山帯などに分布する鳥。羽毛の色が、夏は褐色、冬は白に変化する。"}],"6771":[{"rank":"5","note":"追究クエスト<br/>発見物カード:430","exp":"860","type":"植物","name":"シャビアナ・トラフルズ","desc":"メキシコの砂漠地帯に原生する、エケベリアの亜種。風通しがよく乾燥した地を好む。青灰色の葉がひだ上に重なり、葉の緑だけが桃色になっている。十分な日照を得ていると、より鮮やかに色づく。"}],"6584":[{"rank":"1","note":"(3801, 4068)","exp":"193","type":"港・集落","name":"ヴィシャーカパトナム","desc":"インドの東海岸に位置する港湾都市仏教遺跡が数多く存在し、古代より仏教徒の巡礼が行われているマウリヤ朝のアショーカ王の庇護を受けて繁栄のちの統治者の変遷も、その街並みに面影を残している。"}],"874":[{"rank":"1","note":"逃げ足の速いウサギ","exp":"160","type":"小型生物","name":"トビウサギ","desc":"長くてふさふさした尾と大きな耳が特徴。一回の跳躍で、ゆうに2mを超える。夜行性で、いくつかの巣穴を掘って生活する。"}],"5843":[{"rank":"5","note":"","exp":"1360","type":"地理","name":"ローヌ川とアルヴ川","desc":"フランス東部を流れる河川。二つの河川は合流するが、水質が異なるため合流地からしばらくは混ざり合わず、2色に分かれた流れを見られる。"}],"3627":[{"rank":"4","note":"後悔のその先","exp":"720","type":"植物","name":"ムラサキツユクサ","desc":"北米原産の多年草。主に夏に花を咲かせる。花は3花弁で、青っぽい紫色をしている。花に込められた言葉は、「ひとときの幸せ」。"}],"1925":[{"rank":"1","note":"黒い鳥の地図","exp":"180","type":"鳥類","name":"コクチョウ","desc":"黒いハクチョウ。渡り鳥であるハクチョウとは違い、同じ場所で一生を過ごす。巣は、湖沼などの水辺に作る。主にオーストラリアやアオテアロアに生息する。"}],"6759":[{"rank":"2","note":"発見物カード:120","exp":"240","type":"植物","name":"エケベリア","desc":"ベンケイソウ科の多肉植物の一属。18世紀末スペインの探検隊により発見され、ヨーロッパ園芸にて一世を風靡した。名の由来は18世紀のメキシコの植物画家アタナシオ・エチェベリア。"}],"5155":[{"rank":"2","note":"到達する","exp":"360","type":"港・集落","name":"マニラ","desc":"ルソン島の南部に位置する港町。マレー人の集落が存在し、交易が盛んに行われた。16世紀後半、イスパニア人レガスピにより占領される。"}],"2453":[{"rank":"2","note":"凛と咲く青の花","exp":"330","type":"植物","name":"キキョウ","desc":"東アジアの日当たりの良い山野で育つ植物。蕾は、花びら同士がつながった風船のような形をしており、星型の花が咲く。根は生薬としても利用される。"}],"6384":[{"rank":"3","note":"","exp":"490","type":"虫類","name":"オオカマキリ","desc":"東アジアに生息する大型のカマキリ。気性が荒く、肉食性で共食いをすることもある。雌は植物の枝などに泡状の卵鞘を産み付ける。そこから200匹近い幼虫が生まれるが、そのうち成虫になれるのはわずか数匹だという。"}],"606":[{"rank":"1","note":"裁きの山犬の姿","exp":"110","type":"宗教遺物","name":"アヌビス像","desc":"エジプト神話の死者の神。山犬の姿、もしくは山犬の頭を持つ姿で表される。死後、死者の心臓の重さを真実の羽と比べ、死者の行く末を決めるという。"}],"2836":[{"rank":"4","note":"再びたどる玄奘の足跡","exp":"630","type":"財宝","name":"西遊記","desc":"「大唐西域記」を元に書かれた明代の小説。唐僧・三蔵法師が孫悟空、猪八戒、沙悟浄を供に従え、天竺へ経を取りに行くという物語である。"}],"6323":[{"rank":"3","note":"","exp":"600","type":"虫類","name":"ツマジロスカシマダラ","desc":"中南米に生息し、ガラスのように透明な羽を持つチョウ。美しい見た目とは裏腹に、自身の体重の40倍の重さのものを運ぶ力がある。植物から抽出した毒素を体内に溜め込んでいるため、有毒。雄はこの毒をフェロモンとしても使う。"}],"7008":[{"rank":"3","note":"","exp":"","type":"海洋生物","name":"トラフザメの幼魚","desc":"トラフザメの幼魚は成魚と異なり、体色が黒く、白い縞模様がはっきり入っている。成長するにつれて体色は薄くなり、縞模様は斑点模様へと変化する。"}],"628":[{"rank":"1","note":"鹿に似た動物の地図","exp":"64","type":"中型生物","name":"トムソンガゼル","desc":"鹿に似た小型の動物。大型の群れを作る。角はあるが短い。全個体に角があるので、オスメス共に角があるのだろう。"}],"2606":[{"rank":"3","note":"置かれた釣鐘","exp":"510","type":"宗教遺物","name":"道成寺の鐘","desc":"ある寺院に奉納されている、いわくつきの釣鐘。ある女に追われた僧侶が鐘の中に逃げ込んだものの、ヘビに化けた女に鐘ごと焼き殺されたという伝説がある。よく見たら、なにかが巻きついたような形跡がある…。"}],"5126":[{"rank":"1","note":"到達する","exp":"35","type":"港・集落","name":"ファマガスタ","desc":"地中海東部、キプロス島東岸に位置する街である。シェークスピアの悲劇「オセロー」の舞台だといわれる。温暖な地中海性気候で農業が盛ん。銅鉱山もある。"}],"6913":[{"rank":"5","note":"","exp":"","type":"海洋生物","name":"サーカスティックフリンジヘッド","desc":"北米西岸などに生息する魚。雄は縄張りを脅かす魚に対し、色鮮やかで巨大な口を開けて威嚇する。また、雄同士が開けた口を押しつけ合って戦うこともあるという。雌は雄より小さく、口の色は淡い。"}],"1274":[{"rank":"5","note":"血塗られた建国者","exp":"1157","type":"美術品","name":"カピトリーノの雌狼","desc":"ローマ建国神話に登場するロムルス・レムス兄弟が狼の乳を飲む姿をかたどった青銅像。双子の像はアントニオ・デル・ポッライウォーロが最近付け加えたものだが、狼の像はエトルリア時代のものである。"}],"4838":[{"rank":"2","note":"南天の川","exp":"210","type":"天文","name":"エリダヌス座","desc":"蛇行して流れる川をかたどった星座。その元となった川は、アフリカ北部のナイル川や、イタリア北部のポー川などといわれる。ギリシャ神話では、ヘリオスの息子が天を走る馬車を暴走させた際、ゼウスの落雷を受けて落ちた川ともされる。"}],"3692":[{"rank":"5","note":"サルベージ","exp":"950","type":"歴史遺物","name":"ボナ・コンフィデンタ号","desc":"ロシア皇帝のイヴァン4世がイングランドに派遣した大使船団のうちの一隻。スカンジナビア半島の北西で沈没した。"}],"1809":[{"rank":"5","note":"盗まれた金細工の彫刻","exp":"1170","type":"美術品","name":"サリエラ","desc":"豪華な彫刻が施された金細工の塩入れ。ルネッサンス期を代表する彫刻家ベンベヌート・チェリーニの作。その豪華さと精緻を極めた彫刻によって、「彫刻のモナリザ」と呼ばれている。"}],"6907":[{"rank":"3","note":"","exp":"660","type":"宗教遺物","name":"四分律","desc":"仏教の聖典「律典」の一種。全60巻、僧侶と尼僧の戒律が、数多く記されている。唐代の僧侶・道宣により教えが広がる。その後、道宣の弟子筋である鑑真の渡来により、日本にも教えが伝わった。"}],"6113":[{"rank":"5","note":"","exp":"820","type":"史跡","name":"赤壁","desc":"後漢末期に華北を平定した曹操が、孫権・劉備の連合軍に\n敗走したと伝えられる場所。連合軍が曹操軍を焼き討ちし\nたとも、疫病の蔓延した曹操軍が船を焼いて撤退したとも\nいわれているが、真相は不明である。"}],"2798":[{"rank":"5","note":"青空の下の幻","exp":"1250","type":"虫類","name":"テングアゲハ","desc":"中国南部の山岳地帯に生息しているチョウ。口ひげが長いことからテングの名が付いた。緑や赤の羽が神々しく輝き、かなりの速さで急降下したりと飛び方も雄々しい。まさに、チョウの中の王といえる。"}],"5284":[{"rank":"2","note":"","exp":"240","type":"小型生物","name":"クロアシネコ","desc":"アフリカ南部のサバンナに棲む野生のネコ。小柄な見た目に反して獰猛で、自分よりも大きい相手を仕留めることもある。サバンナに住む人々によると、キリンの首を狙って襲いかかることさえあるという。"}],"2411":[{"rank":"3","note":"ダンジョン","exp":"420","type":"歴史遺物","name":"カルトゥーシュ","desc":"古代エジプトの象形文字の一つ。ファラオの名前を囲んだ曲線であり、壁画などに描かれている。ファラオの名前を囲むことにより、これを守るものとされている。"}],"4843":[{"rank":"1","note":"嘘か錯誤か","exp":"100","type":"天文","name":"からす座","desc":"ギリシャ神話の中で、アポロンの使いの鳥が天に上げられたとされる星座。アポロンが恋人を殺す原因となる誤報をもたらしたため、罰を受けて天上界から追放され、星座になったのだという。"}],"5242":[{"rank":"5","note":"クエスト「消えた星を探せ」<br/>発見物カード:535","exp":"1070","type":"天文","name":"天王星","desc":"土星の外側を巡る惑星で、最大等級は5.6等星と肉眼で見ることも不可能ではない。惑星と認識されるまで20回以上も恒星として観測されていた。公転軸に対して自転軸が大きく傾いており、ほぼ横倒しになっている。"}],"2234":[{"rank":"1","note":"沸き立つ海","exp":"150","type":"地理","name":"ニューブリテン島","desc":"ニューギニア島の東にある大きな島。熱帯雨林に覆われた地形であるが、火山帯に属しており、ニューギニア島とはまた違った印象である。火山付近の海は煮え湯のように沸き立つという。"}],"6355":[{"rank":"","note":"トレジャーハント「古地図にまつわる伝承」","exp":"","type":"レリック","name":"古代の反射鏡","desc":"アレクサンドリア大灯台の最上部付近に設置された反射鏡は太陽光線を集め反射させ、遥か遠くの船を焼くことが可能だったという。"}],"618":[{"rank":"2","note":"死をくれた神","exp":"250","type":"宗教遺物","name":"ソコ像","desc":"西アフリカのギニア湾沿岸に住む、ヌペ人の神話における創造神の像である。この地域には多くの民族が住み、古代から栄えている。各民族の神話には互いの影響が見られ、興味深い。"}],"6207":[{"rank":"2","note":"","exp":"270","type":"歴史遺物","name":"ウォレスの剣","desc":"スコットランド王国の騎士ウィリアム・ウォレスが使った大剣。彼は圧政を敷くイングランド王エドワード1世に抵抗した末、無残にも処刑されたという。剣の長さは大人の背丈ほどもあるため、彼自身もかなりの長身だったかもしれない。"}],"6605":[{"rank":"5","note":"","exp":"1300","type":"財宝","name":"ターコイズマスク","desc":"アステカ文明の仮面。火の神を象ったものではないかといわれているがくわしくは不明。顔の表面はターコイズで装飾され、目には真珠、歯には貝殻が使われている。"}],"1226":[{"rank":"2","note":"優越王を狙う者","exp":"360","type":"歴史遺物","name":"ヤハゥ・テ・キニチ2世の装飾品","desc":"カラコル王の装飾品。ヤハゥ・テ・キニチ2世は、星の戦争でムトゥプルに攻め込んだ王である。"}],"7009":[{"rank":"5","note":"※経験値は推定値です。修正ヨロ。","exp":"2155","type":"地理","name":"ペインテッド・ヒルズ","desc":"北米大陸の西部に位置する丘陵。斜面には赤や橙、黒などの色の異なる地層が幾重にも重なり、縞模様となって浮かぶ。この周辺にはさまざまな動植物の化石が眠っているという。"}],"1418":[{"rank":"2","note":"少年王の軌跡","exp":"210","type":"歴史遺物","name":"ヤシュ・ヌーンアインのレリーフ","desc":"テオティワカンがムトゥプルを勢力下に置いた際に、送り込まれたといわれている王のレリーフである。非常に大きなもので、一面にびっしりと描かれている。"}],"1747":[{"rank":"2","note":"古代の法典の地図","exp":"315","type":"財宝","name":"ワレル・ダンマタ","desc":"ペグー朝・ワレル王が編さんした、インドシナ最古の法典。非常に分かりやすく整えられた文章で現在にも影響を及ぼしている。"}],"6927":[{"rank":"2","note":"発見物カード:165","exp":"330","type":"天文","name":"エニフ","desc":"ペガスス座のイプシロン星。オレンジ色に輝く超巨星。2等星で、天馬の頭部にあたるところに位置する。名はアラビア語で「鼻」を意味するとされているが、記述は残されていない。"}],"6466":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"古代の銀化ガラス器","desc":"虹のような色とりどりの模様が現れた古代のガラス器。砂や土の中で長年を経過したガラスは、ケイ酸や酸化アルミニウムなどの成分が周囲の物質によって化学変化を起こし、金属のように輝く。これを銀化現象という。"}],"2745":[{"rank":"1","note":"幽玄な水墨画の地図<br/><br/>発見時経験値170　発見物カード経験値85","exp":"170","type":"美術品","name":"姜希顔の水墨画","desc":"朝鮮出身の画家・姜希顔による水墨画。\n明に遊学して絵画を研究した姜希顔は、特に竹の描画に優れており高く評価された。\n山水、草花、肖像の妙手である。"}],"2368":[{"rank":"1","note":"白い海鳥の地図","exp":"100","type":"鳥類","name":"ウミネコ","desc":"日本近海に生息する海鳥。カモメの一種だが季節に合わせた大移動はしない。\n「ミャア、ミャア」と鳴く声がネコによく似ている。"}],"5519":[{"rank":"2","note":"「書きかけの地図」<br/>発見物カード:120<br/>ザンジバル沖のマダガスカル島の真北(2200.5017付近)","exp":"240","type":"地理","name":"アルダブラ環礁","desc":"マダガスカル島の北に位置する環礁。多くのゾウガメのほか、さまざまなウミガメや鳥が生息する。"}],"6578":[{"rank":"5","note":"追求クエスト「打弦楽器の追加調査」 発見物カード:600","exp":"1200","type":"財宝","name":"ダルシマー","desc":"ラテン語で「甘美な旋律」を意味する言葉が由来といわれる打弦楽器。台形の箱に金属の弦を張り、ハンマーと呼ばれる小槌の棒で叩いて演奏する。"}],"6107":[{"rank":"4","note":"クエスト「最後の「神」」<br/>発見物カード:390","exp":"780","type":"天文","name":"アンティノウス座","desc":"ローマ皇帝ハドリアヌスが側近アンティノウスの死を悼んで、わし座の南側の星を使って制定した星座。「アルマゲスト」に記述がある。わし座と隣接していたため、ギリシャ神話に登場するガニュメデスと混同されることが多かったという。"}],"5712":[{"rank":"5","note":"海の茶会","exp":"1400","type":"歴史遺物","name":"紅茶箱","desc":"ボストン沿岸に沈んでいた、紅茶の入った木箱。茶の販売人と住民との間で争いだあったようだ。"}],"279":[{"rank":"2","note":"ペルシャ寓話の語り部","exp":"320","type":"財宝","name":"女王のブローチ","desc":"とある女王のものだと伝えられるブローチ。中央には珍しい紫のサファイヤがはめこまれている。まわりにびっしりと並ぶダイヤモンドとルビーが、美しさを引きたてている。"}],"28":[{"rank":"1","note":"アフリカの地理調査<br/><br/>発見時経験値90　発見物カード経験値45","exp":"90","type":"地理","name":"ブランコ岬","desc":"西アフリカのアルギンの近くにある岬。かつては、エンリケ航海王子の艦隊もここに到達したという。大西洋にのぞむ、南洋の岬だ。"}],"2244":[{"rank":"2","note":"海に棲まうトカゲ","exp":"370","type":"中型生物","name":"ウミイグアナ","desc":"海で生活する、大型の珍しいトカゲ。背中にトゲ状の鱗がトサカのように生えており、岩のようにごつごつした黒っぽい皮膚をしている。長くて平らな尾を巧みに動かして泳ぎ、海藻を食べる。海岸で群れをなして日光浴をする姿が見られる。"}],"1707":[{"rank":"2","note":"メソアメリカの像の地図","exp":"220","type":"宗教遺物","name":"ウィツィロポチトリ像","desc":"アステカの戦いの神であり太陽神でもある。東より現れ夜の闇を打ち消し、西にて没するが、また東より復活する。太陽の運行そのものであると、神話では伝えられている。"}],"592":[{"rank":"4","note":"黒い猛獣","exp":"708","type":"大型生物","name":"クロヒョウ","desc":"全身が黒いヒョウ。普通のヒョウと違う種類というわけではないらしい。ほかのヒョウと同じように、木の上で生活することが多いようだ。黒い毛は艶があり、非常に美しい。"}],"1492":[{"rank":"5","note":"巨人の手のひら","exp":"936","type":"大型生物","name":"ヘラジカ","desc":"とても大きな体をしていて、オスの体重はメスの倍ほどもある。オスには特徴のある角があり、それを使って力比べをしたり、外敵を追い払ったりする。食物については、草より木の枝葉を好んで食べる。"}],"2664":[{"rank":"2","note":"珍しい舞","exp":"260","type":"財宝","name":"踊り子の扇子","desc":"朝鮮の踊りで使用される扇子。\n華やかで美しい装飾が施されているものから質素な柄のものまで、種類は幅広い。"}],"6153":[{"rank":"2","note":"クエスト「騎士団の命脈」<br/>発見物カード:125","exp":"250","type":"宗教建築","name":"トマールの修道院","desc":"12世紀テンプル騎士団によって建造された修道院。騎士団解体後はキリスト騎士団の総長となった航海王子エンリケが回廊を増築し、その後1世紀近くの間、さまざまな建築様式で増設された。"}],"5798":[{"rank":"5","note":"仏舎利の一種","exp":"1360","type":"宗教遺物","name":"仏歯","desc":"釈迦の歯とされている遺物。数ある仏舎利の中でも重要視されており、特に犬歯には強い力があるとして信仰されているようだ。"}],"3772":[{"rank":"4","note":"耳のある星","exp":"710","type":"天文","name":"土星","desc":"ヨーロッパではローマ神話の農耕神、サトゥルヌスに由来する名で呼ばれる惑星。約30年で黄道を一巡りする。ガリレオは望遠鏡で土星を観測したが、その形状に頭を悩ませたと伝えられている。"}],"5937":[{"rank":"4","note":"クエスト「独立を果たした王」<br/>発見物カード:345","exp":"690","type":"史跡","name":"ギマランイス城","desc":"ポルトガルの初代国王であるアフォンソ一世が生まれ育った城。かつてギマラインスは修道院と集落しか存在しない土地だったが、北方のヴァイキングの襲撃と略奪から街を守るため、城が建造された。"}],"5925":[{"rank":"3","note":"","exp":"500","type":"史跡","name":"ウルグ・ベク天文台跡","desc":"学者たちを保護し、自身も天文学者であったサマルカンドの領主ウルグ・ベクによって建造された天文台。当時のイスラム世界において先進的な研究施設であった。"}],"707":[{"rank":"4","note":"人魚の正体","exp":"708","type":"海洋生物","name":"ジュゴン","desc":"海に住む大型の動物。アザラシなどと違い、陸に上がることはないようだ。海面に出て子供に乳を与えている姿が目撃され、人魚と間違われたこともある。"}],"5756":[{"rank":"5","note":"「球場」は「球状」の間違いかもしれませんが、原文まま。<br/>→修正されました。","exp":"1400","type":"地理","name":"コンクリーション","desc":"巨大な球場の岩石。生物の死体の周りに様々な物質が集まり、このような形を形成したようだ。なぜそのような現象が起こるのかは不明である。"}],"1452":[{"rank":"5","note":"血と心臓を求める理由","exp":"1027","type":"宗教建築","name":"太陽の石","desc":"アステカは、天文学に長けており、独自の暦を持っていた。この石板によれば、世界は5回の変遷を経験し、それぞれある原因で滅亡したとある。石板によると、現在の世界は地震で滅亡するらしい。"}],"1655":[{"rank":"5","note":"流れ着いた積荷","exp":"1027","type":"地理","name":"メキシコ湾流","desc":"カリブ海・メキシコ湾などを流れる暖かい海流で、カリブを抜けて東進している。この暖流はヨーロッパまで届くほどの大きな流れであるようだ。"}],"2437":[{"rank":"1","note":"色鮮やかな鳥の地図","exp":"130","type":"鳥類","name":"キジ","desc":"明るい林や草原などに生息する、日本特産の鳥。\n雄は、胸から腹にかけて光沢のある緑色、目の周りは鮮紅色で、目の覚めるような色合いをしている。"}],"2720":[{"rank":"3","note":"王を敬う植物","exp":"520","type":"植物","name":"正二品松","desc":"大きく枝を広げたマツの木。樹齢数百年といわれ、人々に慕われている。\n朝鮮王朝7代目国王・世祖がこの木のそばを通りかかった時、伸びていた枝が持ち上がって道を開けたという。"}],"6999":[{"rank":"5","note":"","exp":"","type":"宗教遺物","name":"マアトの羽根を持つトト","desc":"古代エジプト神話における死後の審判を主題とした工芸品。トキは死者の生前の行いを記録する知恵の神トトの化身とされる。くちばしにくわえた羽根は真理と秩序の女神マアトのもので、死者の罪を量るために用いられるという。"}],"2488":[{"rank":"3","note":"ダンジョン","exp":"520","type":"財宝","name":"安土城瓦","desc":"安土城の屋根に葺かれた黒い軒瓦。前面には三つ巴の紋があり、凹んでいる部分には金箔が貼られている。\n火災により、燻された跡が残っている。"}],"1948":[{"rank":"3","note":"友に捧ぐ花<br/><br/>発見時経験値480　発見物カード経験値240","exp":"480","type":"植物","name":"アルストロメリア","desc":"南米アンデス山脈の寒い地域に生息。様々な色彩の花が存在する。華やかで花持ちが良く切花としても人気。別名「インカのユリ」。"}],"6139":[{"rank":"1","note":"冥府の王","exp":"90","type":"宗教遺物","name":"ハデス像","desc":"ギリシャ神話の冥府の神の像。ハデスは冥府を治める厳格な神であると同時に、鉱物や宝石をつかさどる富の神としても知られる。"}],"5119":[{"rank":"1","note":"到達する","exp":"38","type":"港・集落","name":"パリ","desc":"セーヌ川の中州であるシテ島から発展したとされる街。シテ島を囲むように城壁が築かれそれが拡大されて現在のパリとなった。気候は比較的温暖である。"}],"5520":[{"rank":"1","note":"「書きかけのちず」<br/>発見物カード:85","exp":"170","type":"地理","name":"クリスマス島","desc":"ハワイの南に位置する世界最大級のサンゴ礁の島。イギリスの探検家クックがこの島に到達した日がクリスマスだったため、この名が付いた。"}],"6672":[{"rank":"5","note":"クエスト「迷い猫」<br/>発見物カード:415","exp":"830","type":"中型生物","name":"リビアヤマネコ","desc":"別名、アフリカヤマネコ。北アフリカやアラビア半島の砂漠地帯に生息している。家猫の祖とされ、古代エジプト人がリビアヤマネコを飼い慣らしたものが家猫の起源だという。見た目は家猫のキジトラと酷似している。"}],"6680":[{"rank":"5","note":"","exp":"1080","type":"史跡","name":"ディオクレティアヌス宮殿","desc":"皇帝ディオクレティアヌスが帝位を退いたのち暮らした宮殿。アドリア海に面した港町スプリトに建てられた。高さ20ｍ以上の強固な城壁で囲まれている。こういった軍事施設としての側面と、宮殿としての豪奢さを持ち合わせている。"}],"6548":[{"rank":"5","note":"追究クエスト","exp":"1720","type":"中型生物","name":"テングキノボリヘビ","desc":"マダガスカル島に生息するヘビ。先端がくちばしのような形をした特徴的な頭部を持つ。擬態能力に優れ、主に樹上で生活すると考えられている。"}],"2001":[{"rank":"3","note":"フェルメールの試行錯誤","exp":"510","type":"美術品","name":"音楽の稽古","desc":"フェルメール作。彼はこの作品で透視図法による構図の歪みを克服しようとした。楽器に向かう女性は、上部の鏡では隣の男性のほうへ顔を向けているように見える。ヴァージナルには「音楽は喜びの伴侶、悲しみの薬」と書かれている。"}],"6028":[{"rank":"3","note":"","exp":"520","type":"宗教建築","name":"ヴァラーム修道院","desc":"ラドガ湖に浮かぶ島、ヴァラーム島にある修道院。その歴史はロシアのキリスト教化以前にさかのぼるが、地理的な事情から何度も戦乱に巻き込まれ、荒廃した時期もあった。\n最近は復興しつつあるという。"}],"412":[{"rank":"1","note":"奇妙な石の地図","exp":"31","type":"化石","name":"巻き貝の模様の石","desc":"非常に大きな巻貝の形の石。貝が大きくなりすぎると石になるのだろうか？　陸地で見つかるのも不思議だ。"}],"3189":[{"rank":"2","note":"書きかけの地図","exp":"240","type":"地理","name":"スピア岬","desc":"北米北東部沿岸の、テラ・ノヴァ南東部に位置する岬。しばしば北米地域の最東端とみなされる。大西洋に臨む岬であり、季節によってはクジラが泳ぐ姿を眺められる。"}],"3601":[{"rank":"5","note":"海に潜む宝石","exp":"1050","type":"地理","name":"グレートブルーホール","desc":"大昔からある、海に空いた穴だ。どうやら浅瀬の底が、その部分だけぽっかりと穴が空いたように深くなってしまっているため海の色が濃く見えてしまうのだろう。一体、この穴はどこまで繋がっているのだろうか…。"}],"2068":[{"rank":"4","note":"吸血鬼現る<br/><br/>発見時経験値650　発見物カード経験値325","exp":"650","type":"虫類","name":"ミズカマキリ","desc":"カマキリと名がついているがカマキリの仲間ではない。\n昆虫や小魚を餌とし、捕らえた獲物に消化液を送り、溶けた体液を吸う。翅があり、空を飛ぶこともできる。"}],"2017":[{"rank":"2","note":"猿の神の使い","exp":"350","type":"中型生物","name":"ハヌマンラングール","desc":"体の毛は灰色で、顔が黒いサル。それほど大きくないが、尾は体よりずっと長い。植物質のものしか食べないようである。インドではサルの顔の神・ハヌマーンの使いとして大事にされているためか、人間を恐れない。"}],"1349":[{"rank":"2","note":"空飛ぶトカゲ<br/><br/>発見時経験値220　発見物カード経験値110","exp":"220","type":"小型生物","name":"トビトカゲ","desc":"腹部の両脇に張られた皮膜で、木から木へ滑空するトカゲ。皮膜は骨で支えられている。"}],"5130":[{"rank":"1","note":"到達する","exp":"12","type":"港・集落","name":"フローニンゲン","desc":"ネーデルラント北部に位置する街。ネーデルラント内の数少ないハンザ同盟都市。"}],"1255":[{"rank":"1","note":"緑の小さな石","exp":"100","type":"宗教遺物","name":"儀式用ケルト","desc":"ひすいでできた大きなケルト。これだけの大きさであれば、日用として使ったものではなく、儀式用に飾られたものであろう。"}],"706":[{"rank":"4","note":"人間のように歩くドラゴン","exp":"744","type":"化石","name":"二本足のドラゴンの骨","desc":"鼻先から尾の先までが10mを超える、巨大な生物の骨。石化している。頭だけで大岩ほどもあり、口にはナイフのような歯が並ぶ。これが生きていて、伝説の通り炎を吐いたりしたら、街の一つくらい簡単に消え去ることだろう…。"}],"6708":[{"rank":"2","note":"発見物カード:160","exp":"320","type":"虫類","name":"モモイロヤママユ","desc":"ヤママユガの一種。主に北米東部とカナダ南部に分布する。体長はおよそ3cm。全身がピンクと黄色の綿毛に覆われているのが特徴。幼虫はカエデを主食とするが、成虫は口部が退化して接触しなくなり、夜間に繁殖行動のみを行う。"}],"6894":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"景龍観鐘","desc":"景龍観と呼ばれる道教の殿堂造られた大型の釣鐘。鐘の高さは2mを越え、鐘には皇帝の真筆による銘文が記されている。"}],"3823":[{"rank":"5","note":"桃色の理由","exp":"1100","type":"海洋生物","name":"コンクガイ","desc":"ピンクガイとも呼ばれる巻貝。殻の内側の淡いピンク色が特徴である。カリブ海全域に生息し、食用としても重宝されている。"}],"6484":[{"rank":"5","note":"追究クエスト","exp":"","type":"宗教建築","name":"トゥールーンの螺旋型ミナレット","desc":"カイロにあるイブン・トゥールーン・モスクに建てられた螺旋型のミナレット。同じ螺旋型のミナレットは、世界に3つしか現存しないといわれ、マルウィヤ・ミナレットと共にとても貴重な建造物とされている。"}],"5762":[{"rank":"3","note":"2017.02.07新規追加","exp":"","type":"気象・現象","name":"セントエルモの火","desc":"悪天候での航海時に、船のマストの先が発光する現象。時代や地域によって他の名で呼ばれることもある。発光現象が2つ同時に起こると、悪天候が収まるという伝承もある。"}],"5215":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"掃叭石柱","desc":"「さっぱせきちゅう」と呼ばれる石柱。千年の石柱とも呼ばれる。高さ約6mと4mの2本の立石が並んでいる。現地に住むアミの人々の間では、民族発祥の地とされているようだ。"}],"6327":[{"rank":"2","note":"","exp":"330","type":"植物","name":"サジー","desc":"ユーラシア大陸に広く分布する植物。果実は栄養価が高いが、酸味がありそのままでは食べにくい。また幹や枝にトゲが多く、収穫は難しい。果実は鮮やかな橙色をしているため鑑賞目的で栽培されることもある。"}],"2602":[{"rank":"2","note":"華やかな経文","exp":"370","type":"宗教遺物","name":"装飾経","desc":"装飾を施した上質の紙に風俗画を描き、その上から仏教の経文を書き写したもの。\n平安時代の華やかな貴族文化を表しており、美術品としても高く評価される。"}],"6478":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"巨像の親指","desc":"ロードス島にあった巨像の親指。青銅で作られている。大プリニウスの「博物誌」によると「倒壊した像の親指を腕で抱えられる者はほとんどおらず、指はあらゆる彫像よりも大きい」とされている。"}],"6347":[{"rank":"2","note":"","exp":"300","type":"歴史遺物","name":"ソストラトスの碑文","desc":"大灯台の建設に携わったソストラトスは、秘密裏に大灯台の礎石に自身の名前がはいった碑文をいれ、その上をモルタルで覆い統治者プトレマイオスの名を刻むという仕組みを施したことで後世に名を残したとされる。"}],"1166":[{"rank":"2","note":"石の遺物","exp":"340","type":"歴史遺物","name":"ケルト","desc":"ケルトとは儀式用の斧のことである。細かい彫刻がされていることが多い。これを使って神々に踊りを捧げたり祖先に祈ったりした。"}],"5112":[{"rank":"1","note":"到達する","exp":"128","type":"港・集落","name":"バスラ","desc":"ペルシャ湾奥に位置する街。7世紀に建設され、8世紀には交易と文化の中心地であったという。しかし、アッバース朝が衰退するにつれて重要性を失っていった。それでも、ペルシャ絨毯をはじめ重要な産物が流通している。"}],"2809":[{"rank":"3","note":"恋人に贈る花束","exp":"460","type":"植物","name":"シオン","desc":"中国、朝鮮など広い地域に生息する、秋に咲く薄紫色の花。その姿から「紫苑」と呼ばれる。\nシオンの根は漢方薬としても使われている。"}],"6552":[{"rank":"5","note":"追究クエスト","exp":"1500","type":"植物","name":"ムキタケ","desc":"広葉樹の枯れ木に群生するキノコ。毒はなく滑らかな触感とくせのない味わいで、よく食用にされる。ただし、毒キノコのツキヨタケとよく似ているため、採取時にはくれぐれも注意が必要である。"}],"5115":[{"rank":"1","note":"到達する","exp":"11","type":"港・集落","name":"バレンシア","desc":"古代ローマ時代から栄えた街。イスラム勢力に支配された時期があるため、イスラム文化とヨーロッパ文化が共存している。農作物が豊富に流通するほか、近くにある鉱山から辰砂（しんしゃ）が採れる。"}],"2669":[{"rank":"2","note":"恋の架け橋","exp":"370","type":"鳥類","name":"カササギ","desc":"朝鮮半島と日本の一部に生息するカラスの一種。\nカチカチという鳴き声のため、一部の地域では「カチガラス」とも呼ばれている。\n飛ぶと翼の白い模様が目立つ。"}],"6944":[{"rank":"3","note":"発見物カード:250","exp":"500","type":"天文","name":"フム・アル・サマカー","desc":"うお座のベータ星。青白く輝き、西の魚の口部分に位置している。名はアラビア語で「魚の口」を意する。"}],"3697":[{"rank":"2","note":"書きかけの地図","exp":"370","type":"地理","name":"ブルーマウンテン山脈","desc":"ジャマイカ東部に存在する山脈。標高が2000メートル以上あるとされ、遠目では山脈全体が青っぽく見える。"}],"6585":[{"rank":"2","note":"","exp":"280","type":"歴史遺物","name":"青い彩釉レンガ","desc":"伝承にある都市バビロンで使われていたと思われる古代の彩釉レンガ。釉薬がほどこされたレンガは耐久性に優れ、表面にはまだ青い光沢が残っている。"}],"6436":[{"rank":"5","note":"レガシー・数の叡智　右上","exp":"","type":"歴史遺物","name":"ローマ教皇のアバカス","desc":"ローマ帝国で使用されていたという計算用器具。溝ソロバン。青銅など金属製の板の溝にはめ込んだ珠を移動して計算する。西欧世界では長く忘れられていたが、10?11世紀ころのローマ教皇シルウェステル2世が改良して再導入された。"}],"1509":[{"rank":"3","note":"クエスト「伝国の名著」<br/>発見物カード:230","exp":"462","type":"財宝","name":"ナーガラクルターガマ","desc":"マジャパヒトの宮廷詩人プラパンチャが編さんした歴史書。マジャパヒトの最盛期の様子を克明に著している。"}],"2839":[{"rank":"1","note":"動物の絵画の地図","exp":"130","type":"美術品","name":"毛松の絵画","desc":"サルを描いた画。\n南宋の画家・毛松の作品であるとされ、優れた表現力を発揮した名品といわれている。"}],"2557":[{"rank":"1","note":"断崖に臨む洞穴<br/><br/>発見時経験値180　発見物カード経験値90","exp":"180","type":"地理","name":"八仙洞","desc":"海に面した断崖に形成された海食洞穴。\n洞穴数は十数個にも及び、台湾島の古代文化の一つである長浜文化の遺跡も存在する。"}],"3884":[{"rank":"4","note":"先住民の笛の追加調査","exp":"660","type":"宗教遺物","name":"ココペリの壁画","desc":"北米の先住民であるホピ民族が岩壁に描いた神の絵。ココペリは豊穣の神であり、笛を吹いて豊作や子宝をもたらすとされる。"}],"405":[{"rank":"4","note":"危険な雲","exp":"720","type":"中型生物","name":"ウンピョウ","desc":"全身に雲を浮かべたような模様と長い牙が特徴。樹上での生活に慣れており、通常は単独で行動する。"}],"6689":[{"rank":"","note":"","exp":"800","type":"中型生物","name":"カニクイイヌ","desc":"低木林や湿原などに生息する犬の仲間。乾季になると低地へ、雨季になると高地へ移動する。乾季は小型の脊椎動物やカニ、雨季は昆虫を食べる。体毛は粗く、胴は灰褐色または黄廃色で、背筋に鮮明な黒線がある。"}],"5161":[{"rank":"2","note":"到達する","exp":"252","type":"港・集落","name":"メリダ","desc":"熱帯雨林に覆われたユカタン半島の北西端に位置する街。その昔マヤ文明が栄えていたという。"}],"6908":[{"rank":"5","note":"","exp":"580","type":"鳥類","name":"ルリオーストラリアムシクイ","desc":"オーストラリア南東部などに生息する小型の鳥。仲間意識が強く、群れで活動し、子育てや危機対応は共同で行う。雑食性で、昆虫を中心に植物の小さな種子や花、果実などを食べる。"}],"5820":[{"rank":"1","note":"","exp":"190","type":"地理","name":"ブラマプトラ川","desc":"ヒマララ山脈の周辺を流れる川。ブラフマーの息子（プトラ）と呼ばれ、ガンジス川との合流地点で巨大な三角州を形成する。"}],"641":[{"rank":"4","note":"出世作","exp":"624","type":"美術品","name":"聖母被昇天（ティツィアーノ）","desc":"ティツィアーノ作の巨大な祭壇画。まさに天に引き上げられようとするマリアは、それまでの聖母とまったくことなる、生き生きとした生身の女性として描かれている。この絵をきっかけに、ティツィアーノは大成功した。"}],"1462":[{"rank":"4","note":"クエスト「アステカの豊穣神」<br/>発見物カード:360","exp":"720","type":"宗教遺物","name":"シペ・トテック像","desc":"アステカ神話における穀物・豊穣神。その名は、「生爪をはがれたもの」という意味。豊作の保証として、生贄を要求するといわれている。"}],"3910":[{"rank":"1","note":"地図「金星の観測記録」<br/>発見物カード:85","exp":"170","type":"天文","name":"金星の満ち欠け","desc":"金星は月のように満ち欠けするだけでなく、大きさも変わって見える。これは金星が地球の周りではなく、太陽の周りを回っている明確な証拠となった。"}],"5866":[{"rank":"5","note":"クエスト「うみへびとみずへび」<br/>発見物カード:700","exp":"1400","type":"天文","name":"みずへび座","desc":"南天の星座の一つ。16世紀に作られた。うみへび座と同じくラテン語で「水蛇」を意味する単語で名づけられたが、みずへび座は男性系、うみへび座は女性形という違いがある。\n\n※男性系と女性形の表記は原文ママ"}],"3260":[{"rank":"3","note":"山脈の頂上","exp":"500","type":"地理","name":"ツブカル山","desc":"アトラス山脈の西部に連なるモロッコ最高峰の山。山頂からはアトラス山脈の雄大な景色を見ることができる。"}],"2692":[{"rank":"2","note":"正しい言語を求めて","exp":"340","type":"財宝","name":"訓民正音","desc":"朝鮮王朝4代王・世宗の命により編さんされたという書物。\n朝鮮語の表記に用いられるハングルについて記されている。"}],"2318":[{"rank":"2","note":"［勅命］[[災害の事前観測","exp":"380","type":"地理","name":"漢拏山","desc":"済州島のほぼ中央に位置する火山。山の頂上には様々な伝説が残る湖もあるそうだ。\n記録によると、高麗時代に噴火があったようだ。"}],"6590":[{"rank":"2","note":"","exp":"370","type":"海洋生物","name":"アズファー","desc":"紅海に生息する魚。別名アラビアンエンゼルフィッシュ。黒青から濃紫の体色が特徴で、明るい黄色の縦縞模様が入っている。"}],"3415":[{"rank":"","note":"","exp":"","type":"レリック","name":"ピカトリクス","desc":"「賢者の極み」と題される魔術と占星術に関するアラビア語の書物。\nヨーロッパでも翻訳され、広く流布しているという。"}],"570":[{"rank":"2","note":"光のフルート","exp":"370","type":"財宝","name":"光のフルート","desc":"エジプトの王家に伝わる財宝。達人が演奏すれば人の心を惑わし争いを終結させてしまうという。ラムセス2世が建てたというアブ・シンベル神殿から発見された。"}],"3634":[{"rank":"4","note":"スラブ神話の考察","exp":"720","type":"宗教遺物","name":"ペルーンの木像","desc":"ペルーンは、スラブ神話の主神。名前は「打つ（者）」という意味の古いスラブ語に由来し、雷や嵐を司る神とされている。対立する神を、稲妻の矢で射て退けた神話から、戦勝をもたらす神として戦士たちに崇拝された。"}],"6977":[{"rank":"2","note":"発見物カード:190","exp":"380","type":"地理","name":"ヒリアー湖","desc":"オーストラリア南西部のルシェルシェ諸島に位置する塩湖。季節や天候にかかわらず湖水は鮮やかなピンク色を保ち、白い砂に囲まれた湖面は洋上からも確認することができる。"}],"788":[{"rank":"1","note":"クエスト「太陽神の馬車」<br/>発見物カード:75","exp":"150","type":"宗教建築","name":"コナーラクの車輪","desc":"コナーラクの太陽神寺院の基壇（きだん）部分にある車輪。寺院全体が馬車に見立てられている。この馬車に乗り、太陽神スーリヤが天を翔けると言われている。"}],"3302":[{"rank":"4","note":"世界でもっとも美しい本","exp":"740","type":"財宝","name":"ケルズの書","desc":"8世紀頃に製作された聖書の手写本。ケルト文様による豪華な装飾が施されており、書物とは思えない美しさである。\nマタイ、マルコ、ヨハネ、ルカの四福音書が収められている。"}],"3161":[{"rank":"2","note":"書きかけの地図","exp":"220","type":"地理","name":"アバロン半島","desc":"テラ・ノヴァ島の南東にある半島。地形が複雑であり、いくつもの湾が存在している。\n漁場としても優れている。"}],"4823":[{"rank":"2","note":"巨大な海獣の地図","exp":"370","type":"海洋生物","name":"ステラーカイギュウ","desc":"カムチャッカ半島の東にある島の周辺に生息する巨大な海洋生物。人を警戒せず、傷ついた仲間を守ろうとする習性があり、このままでは絶滅してしまいそうだ。"}],"5542":[{"rank":"4","note":"","exp":"680","type":"気象・現象","name":"ポロロッカ","desc":"海から河口へと波が押し寄せる現象。主にアマゾン川などで発生する。潮の満ち引きが原因と考えられている。「ポロロッカ」は現地では「大騒音」を意味する。"}],"2387":[{"rank":"4","note":"クエスト「未確認海洋生物」<br/>発見物カード:310","exp":"620","type":"海洋生物","name":"カブトガニ","desc":"東アジアから東南アジアにかけて、一部の沿岸域に生息する生物。これとよく似た模様を持つ石もあるという。"}],"5710":[{"rank":"5","note":"※説明文の「モチーフ『を』した」は、原文ママです。","exp":"1300","type":"天文","name":"アルゴ座","desc":"ギリシア神話に登場するアルゴ船をモチーフをした星座。あまりに巨大な星座だったためいくつかに分割されてしまった。"}],"5724":[{"rank":"2","note":"2017.02.07新規追加","exp":"","type":"地理","name":"カラ・ボガス・ゴル湾","desc":"カスピ海で最も大きな湾。カスピ海から流れ込んだ水が湾から外に流出しないため、カスピ海と比べて塩分濃度が高くなっている。そのため、カスピ海から流れてきた魚はすぐに死んでしまうという。"}],"5303":[{"rank":"1","note":"発見時経験値120　発見物カード経験値60","exp":"120","type":"海洋生物","name":"ムブナ","desc":"アフリカ南東部の湖に棲む、鮮やかな縞模様を持つ淡水魚。縄張り意識が強い魚で、個体によって微妙に違う。どうやら、より強い魚ほどはっきりした模様を持つようである。"}],"6851":[{"rank":"3","note":"発見物カード:280","exp":"560","type":"天文","name":"アルキバ","desc":"からす座のアルファ星だが、この星座の5つの恒星の中で最も暗い4等星。カラスのくちばしに位置し、名はアラビア語で「テント」を意味する。"}],"600":[{"rank":"1","note":"砂漠のキツネ","exp":"80","type":"中型生物","name":"フェネックギツネ","desc":"耳が非常に大きい、砂漠に生息する小型のキツネ。臆病で非常に素早く、危険を感じるとあっというまにいなくなってしまう。どうも穴を掘って隠れているようだが、それにしても素早すぎる。"}],"6974":[{"rank":"4","note":"発見物カード:375","exp":"750","type":"宗教遺物","name":"アルジュナの苦行","desc":"インド南東部にある巨大な岸壁彫刻。神々や動物などが一枚岩に精緻に刻まれている。叙事詩マハーバーラタの「アルジュナの苦行」を表現しているという説のほか、「ガンガーの降下」とされる説もある。"}],"486":[{"rank":"2","note":"アドヴァリユ祭官の聖典","exp":"390","type":"宗教遺物","name":"ヤジュル・ヴェーダ","desc":"ヒンドゥー教の聖典の一つ。ヤジュスという祭詞を集めたもの。祭事で供儀を担当するアドヴァリユ祭官のためのものである。"}],"2037":[{"rank":"2","note":"描かれた使徒","exp":"310","type":"美術品","name":"四人の使徒","desc":"デューラー作の絵画。四名の使徒が描かれている。\n赤と白の鮮やかな衣装は衣擦れの音すら聞こえてきそうなほどである。キリスト教では、赤は慈愛を、白は無垢を表している。"}],"759":[{"rank":"3","note":"昔からある高性能の船","exp":"473","type":"歴史遺物","name":"ヌフの船","desc":"ヌフとは、東アフリカの伝説で、人類初の船を作った人だと言われる。これは、アラビアから東アフリカで作られている船で、古代と同じ作り方をされているものだ。"}],"5786":[{"rank":"5","note":"","exp":"1200","type":"化石","name":"冷凍マンモス","desc":"巨大な牙を持つ象のような生物が凍り付いた姿。いつからこの地に眠っているかはわからないが、その肉は食べられそうなほどの新鮮さを保っている。"}],"5653":[{"rank":"3","note":"","exp":"480","type":"地理","name":"マヤベイ","desc":"アンダマン海上に浮かぶピピ諸島の一つ、ピピレイ島の名所。真っ白な砂浜と透き通る海が広がっている。"}],"1589":[{"rank":"3","note":"クエスト「始まりの地」<br/>発見物カード:240","exp":"484","type":"地理","name":"アーネムランド","desc":"オーストラリア最北部にある半島を指す。中央部は山がちだが海岸線は高低差の少ない地表が続く。古代のアボリジニたちが書いたといわれる岩絵が多数残る。"}],"1361":[{"rank":"2","note":"因果応報の物語","exp":"350","type":"宗教遺物","name":"分別善悪応報経","desc":"ぶんべつぜんあくおうほうきょう。仏教の経典のひとつ。人間が行う様々な悪の行いのあと、訪れる死後の世界でどのような目に遭うかを書き綴っている。その様子は、ボロブドゥール遺跡に160面のレリーフにして描かれている。"}],"6148":[{"rank":"2","note":"","exp":"243","type":"歴史遺物","name":"アルジュバロータの長弓","desc":"ポルトガル王ジョアン1世が使っていたとされる長弓。息子のエンリケに譲られ、サグレスの訓練学校に保管されていた。"}],"80":[{"rank":"1","note":"ヴェネツィア教会の天井画","exp":"80","type":"美術品","name":"最後の審判（ヴァザーリ）","desc":"ジョルジョ・ヴァザーリ作の天井画。キリスト教の最後の審判の様子が生々しく描かれている。ヴァザーリは絵だけでなく、文筆家としても知られている。"}],"6914":[{"rank":"1","note":"","exp":"","type":"植物","name":"ルリジサ","desc":"地中海の沿岸部などに分布する一年草。ボリジとも呼ばれ、星の形をした花が咲く。開花直後は桃色をしているが、次第に青色へと変化する。"}],"1755":[{"rank":"2","note":"釣り","exp":"350","type":"海洋生物","name":"ヨーロッパオオナマズ","desc":"上あごに非常に長い一対の口ヒゲをもつ巨大ナマズ。成長すると、体長が5mにもなるようだ。"}],"1942":[{"rank":"4","note":"クエスト「インカ王族の眠り方」<br/>発見物カード:360","exp":"720","type":"宗教遺物","name":"インカ王族のミイラ","desc":"インカ帝国では、王族の遺体をミイラ化し、死後もその権威を保った。そのためインカ帝国では王への反乱は少なかったようだ。ミイラは生前と同様に衣服をまとい、食事が供せられ、他の王のミイラとの交流も行ったという。"}],"5275":[{"rank":"","note":"2016/06/04<br/>発見時経験値2410　発見物カード経験値なし","exp":"2410","type":"レリック","name":"クレタ聖刻文字の印章","desc":""}],"1849":[{"rank":"3","note":"知恵の耕地","exp":"500","type":"地理","name":"段々畑","desc":"斜面の山すそに階段状に段組みされて作られた、緩やかな傾斜を持つ畑。アンデス山脈に属する高原での農作に見られる。"}],"54":[{"rank":"2","note":"イングランドの絵画","exp":"230","type":"美術品","name":"ニコラス・クラッツァーの肖像","desc":"息子のほうのハンス・ホルバイン作の絵画。極めて写実的な画法が彼の特徴である。モデルのニコラスはイングランドの宮廷に仕えた天文学者で、そのためこの肖像画にも天文学で用いる道具が描かれている。"}],"161":[{"rank":"2","note":"サンゴの海","exp":"360","type":"地理","name":"カイマン諸島","desc":"カリブ海のキューバ島南方に位置する諸島。発見当初はトルトゥーガ島（カメの意味）とも呼ばれた。ほとんどがサンゴ礁からなる、美しい島々である。"}],"6450":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"アランビック","desc":"8世紀ごろのペルシャで発達した蒸留器。イスラム圏からヨーロッパにかけて、化学者や錬金術師たちに広く用いられた。香料の材料から成分を蒸留して作られた精油は、蒸留酒と合わせて香水の原型となったとされる。"}],"1600":[{"rank":"1","note":"儀式用具の地図","exp":"150","type":"宗教遺物","name":"儀式用円筒杯","desc":"豪華な装飾・彩色がなされた円筒型の盃。儀式用に貴族や王が進呈したものと思われる。"}],"5182":[{"rank":"1","note":"到達する","exp":"39","type":"港・集落","name":"ヴィスビー","desc":"バルト海に浮かぶゴトランド島にあるハンザ同盟の都市。13世紀末頃に、バルト海での商業の覇権を争っていたリューベックとの政争に敗れ、ハンザの一員となった。"}],"5747":[{"rank":"2","note":"","exp":"","type":"植物","name":"シベリアヒナゲシ","desc":"シベリアから極東地域に分布しているケシの一種。白や黄色の花を咲かせる。寒さに非常に強く、シベリアの冬も越せる。他のケシと同様、有毒性を持つ。"}],"166":[{"rank":"2","note":"シヴァに献じられし寺院","exp":"300","type":"宗教建築","name":"ブリハディーシュヴァラ寺院","desc":"破壊神シヴァを祀る南インドの寺院。チョーラ朝のラージャラージャ1世が建てたとされる。ヴィマーナと呼ばれる非常に大きな本堂を持つ。"}],"5745":[{"rank":"5","note":"","exp":"1510","type":"地理","name":"クーンブ・アイスフォール","desc":"巨大な氷塊が散在する危険地帯。チョモランマに登頂する経路の一つであり登頂を目指すものは避けて通れない。ヒトに似た足跡が点々と残っているが、いったい誰の、いや、なんの足跡なのだろうか。"}],"6551":[{"rank":"5","note":"追究クエスト","exp":"1050","type":"歴史遺物","name":"ルーン文字の刀剣","desc":"ロンドン近くのテムズ川で発見された刀剣。ルーン文字の銘文や幾何学的な文様が刻まれたその刀身は、どこか神秘的で威厳のようなものを感じさせる。"}],"5266":[{"rank":"","note":"","exp":"","type":"レリック","name":"アトランティスの落日","desc":""}],"1861":[{"rank":"4","note":"連綿と続く文化","exp":"710","type":"宗教遺物","name":"彩色木製のマスク","desc":"木製のマスクで、アンデスの遺物としては珍しいものである。チチカカ湖付近の神殿の神像をモチーフにしているといわれている。顔の周りに太陽光のような放射状の線がある。"}],"1597":[{"rank":"1","note":"憧れの輝き","exp":"110","type":"財宝","name":"バロック真珠のペンダント","desc":"変形真珠に、彫刻的で豪華なデザインを組み合わせたペンダント。自然物、動物、神話をテーマにした図案が多い。バロックの名称は「歪んだ真珠」というポルトガル語に由来する。"}],"6931":[{"rank":"4","note":"発見物カード:390","exp":"780","type":"小型生物","name":"ブラウンバシリスク","desc":"クレストと呼ばれる、帆のようなたてがみが特徴のトカゲの一種。中南米の熱帯雨林に生息する。体は茶褐色をしており、バシリスクの仲間としては最大と言われている。"}],"5124":[{"rank":"1","note":"到達する","exp":"12","type":"港・集落","name":"ピサ","desc":"古代ローマの時代に開拓された、古い街。ピサの斜塔があることで有名。イタリア諸都市の中で最初に都市国家の宣言をした。主な産物は高級織物や大理石像などである。"}],"5114":[{"rank":"2","note":"到達する","exp":"250","type":"港・集落","name":"バルパライソ","desc":"マゼラン海峡を通ってきた船が停泊することで栄えた港街。街の名前には「天国の谷」という意味がある。"}],"2599":[{"rank":"3","note":"歴史に残る名品","exp":"460","type":"歴史遺物","name":"蒔絵の硯箱","desc":"日本で作られた、硯や筆を収める箱。蒔絵の技法が用いられた、秀逸な工芸品である。\n蒔絵とは、漆器の表面に漆で紋様を描き、漆が乾く前に金粉などの金属粉を蒔いて定着させる技法である。"}],"6109":[{"rank":"5","note":"クエスト「エデンへの憧れ」<br/>発見物カード:550","exp":"1190","type":"宗教建築","name":"フマーユーン廟","desc":"ムガール帝国の第2代皇帝フマーユーンの墓廟で、彼が都と定めたデリーの郊外にある。インドにおけるイスラム建築の精華の一つであり、後のタージ・マハルにも影響を与えたほか、インドの庭園建築の原型になったともいわれる。"}],"5571":[{"rank":"3","note":"マダガスカル沖で発見　18世紀第3期<br/><br/>発見物カード:255","exp":"510","type":"天文","name":"じょうぎ座","desc":"ラカーユが制定した南天の星座のひとつ。製図で用いる直定規と指矩（さしがね）をかたどっている。"}],"1834":[{"rank":"1","note":"曲がった武器の地図","exp":"100","type":"財宝","name":"マムルークのカトラス","desc":"カトラスとは、やや刀身が背のほうに湾曲した刀剣。小型で扱いやすく、海賊が好んで使用したことでも有名。槍術や弓術を主にしていたマムルーク騎兵も使用していたという。"}],"5884":[{"rank":"2","note":"","exp":"380","type":"海洋生物","name":"ホテイエソ","desc":"鱗のない体が特徴的な深海魚。長細い全身は真っ黒で、大きな口が上向きについている。下顎の先端からは長い髭が生えており、この髭や顎の周りを発光させることで、餌となる魚を誘い出すという。"}],"679":[{"rank":"5","note":"信じるものたちの記録","exp":"1118","type":"宗教遺物","name":"死海文書","desc":"死海写本とも言われる大量の旧約聖書の写本である。紀元前に存在した、ユダヤ教の一派であるクムラン宗団のものと思われる。ごく初期の聖書そのものであり、宗教学上の価値は計り知れない。"}],"5817":[{"rank":"5","note":"","exp":"1474","type":"財宝","name":"ケツァールの羽の王冠","desc":"幻の鳥ケツァールの羽で飾られた王冠。ただでさえ珍しい鳥なのだから、捕獲のされすぎで絶滅しないか心配である。"}],"709":[{"rank":"5","note":"水が嫌いなカバ","exp":"1040","type":"中型生物","name":"コビトカバ","desc":"西アフリカの限られた地域にしかいない、小さなカバ。カバの子供かと思われたが、同じ大きさの個体ばかりなので違う種類だと思われる。体色もカバよりかなり濃い。水の中にいることは少なく、森や湿地にいる。"}],"2113":[{"rank":"2","note":"サルベージ","exp":"270","type":"歴史遺物","name":"アブキールの難破船","desc":"カタロニアの貿易船の一隻。\nアレクサンドリアの北東に位置する、アブキール湾で沈没した。"}],"5255":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"オロシーバ兄弟のカヌー","desc":"かつてこの遺跡を作ったオロシーバ兄弟が島へ渡るのに使ったとされるカヌー。損傷の具合から、その後も島々を行き来するために使用され続けたと思われる。"}],"1206":[{"rank":"4","note":"くちばしを巡る口喧嘩","exp":"744","type":"鳥類","name":"オオハシ","desc":"黄色い大きなくちばしが特徴。大きいもので15cm以上にもなり、体重を支えきれない小枝の先の食物もとることができる。"}],"5869":[{"rank":"4","note":"ケープ　出航所役人前の桟橋　雨　たぶん夜","exp":"340","type":"気象・現象","name":"フライング・ダッチマン","desc":"喜望峰近海に出没するという幽霊船。ある嵐の日、船長が風を罵ったためその船は呪われてしまい、その結果永遠にさまようことになったという。"}],"1700":[{"rank":"5","note":"アイン・ジャールートの戦い","exp":"1144","type":"歴史遺物","name":"戦士の墓","desc":"ベイルートの郊外に埋もれていた墓。墓碑銘は刻まれているが、浸食のため読めなくなっている。周囲に錆びた武具が埋まっていたことから戦士の墓ではないかと思われる。"}],"5626":[{"rank":"1","note":"","exp":"150","type":"宗教遺物","name":"クマン人の石像","desc":"黒海やカスピ海の北部に広がる草原地帯に居住していた遊牧民族が作った石像。先祖をかたどったものではないかといわれている。"}],"6627":[{"rank":"5","note":"発見物カード580","exp":"1160","type":"地理","name":"五花海","desc":"九寨溝でも屈指の景観を誇る巨大な湖。石灰化した成分が湖底に沈んでいる。日光が差し込むと、反射によって青やオレンジ、紫などさまざまな色を放つ。"}],"3162":[{"rank":"2","note":"力強い鳥の地図","exp":"320","type":"鳥類","name":"ミサゴ","desc":"北米をはじめとして、ほぼ全地域の沿岸部に生息する大型の鳥。\n水面を低空飛行し、魚を捕食する。全体的に黒褐色だが、頭頂部は真っ白な冠羽を持つ。"}],"5509":[{"rank":"1","note":"座標　52,2492","exp":"15","type":"港・集落","name":"ロッテルダム","desc":"北海に面する街。ライン川などの複数の川が北海に流れ込む地点に位置する。16世紀頃から港湾都市として発達し、大西洋貿易の要となっている。"}],"6362":[{"rank":"1","note":"","exp":"140","type":"海洋生物","name":"ペンシルフィッシュ","desc":"南アメリカの川などで見られる淡水魚。細長い体と小さな口で水中の苔を食べる。体を斜めにしたまま水面近くを泳ぐ種がいるため、その姿を鉛筆にたとえて名付けられた。"}],"6626":[{"rank":"5","note":"レガシー　商の叡智・財貨の交易路　上","exp":"2550","type":"財宝","name":"交子","desc":"史上初の紙幣。北宋の四川にて発行された。はじめは、民間の交子舗が発行していた鉄銭の預かり手形だったが後に政府が発行するようになり、紙幣として流通するようになった。"}],"2271":[{"rank":"3","note":"誘いの甘い香り<br/><br/>発見時経験値490　発見物カード経験値245","exp":"490","type":"史跡","name":"ヤシ油製造場跡","desc":"儀式に使用されていたヤシ油を製造するための場所。石の台の上で作られたヤシ油は、使用しないときもこの場所に保管される。"}],"5226":[{"rank":"3","note":"","exp":"","type":"史跡","name":"ヴィッラ・アドリアーナ","desc":"イタリアのティヴォリにある、ハドリアヌス帝が建造した別荘。皇帝がローマ帝国の巡察にでかけ、各地で魅了されたものを再現した建築物がいくつも存在している。"}],"1705":[{"rank":"5","note":"石の記憶","exp":"1235","type":"宗教遺物","name":"十戒","desc":"旧約聖書において、モーゼが神から与えられたといわれる十の戒律を記した石板。聖書には契約の箱に納められたと記述されている。"}],"6815":[{"rank":"5","note":"発見物カード:480","exp":"960","type":"財宝","name":"ターコイズの双頭蛇","desc":"アステカ帝国で作られた工芸品。双頭の蛇をかたどっており、全身は当時アステカで貴重だったターコイズのモザイクに覆われ、口や牙は貝殻で装飾されている。儀式などで使用された胸飾りではないかと推測される。"}],"2835":[{"rank":"4","note":"唐僧玄奘の旅行記","exp":"610","type":"財宝","name":"大唐西域記","desc":"唐僧・玄奘が、西域やインドの仏教遺跡、生活などを記録した見聞録。\n全12巻に及び、後世に大きな影響を与えている。"}],"6923":[{"rank":"5","note":"発見物カード:475","exp":"950","type":"鳥類","name":"ブロンズトキ","desc":"細長く湾曲したくちばしと光沢のある羽を持つ鳥。沼や湿原に生息し、主に水生生物を餌とする。体の赤褐色と金属のような羽の光沢から、この名がついたといわれる。"}],"3687":[{"rank":"5","note":"シベリアの麝香","exp":"950","type":"中型生物","name":"シベリアジャコウジカ","desc":"麝香の元となる匂いを分泌する、シカに似た小柄の動物。角は持たない。雄は上あごの犬歯が発達した大きめの牙を持つ。"}],"5658":[{"rank":"4","note":"","exp":"620","type":"小型生物","name":"サバクキンモグラ","desc":"アフリカ南部の砂漠に生息する動物。体調は8cm程度で、体つきは丸い。前足の長い爪で穴を掘る。夜行性で、目は退化している。"}],"6625":[{"rank":"3","note":"","exp":"480","type":"鳥類","name":"タカヘ","desc":"クイナ科の空を飛べない鳥。ニワトリほどの大きさで、地上の生活に適応するために、分厚いクチバシと太い脚を持つ。羽は光に当たる角度によって青や緑に変化し、その色は成鳥になるにつれ鮮やかになる。"}],"342":[{"rank":"1","note":"医学書の最高権威","exp":"110","type":"財宝","name":"医学典範","desc":"「いがくてんぱん」。イブン・シーナー著の医学書である。アラビア医学の集大成といわれ、ペルシャからヨーロッパにかけて広く学ばれている。"}],"1568":[{"rank":"1","note":"繊細な花の地図","exp":"140","type":"植物","name":"グレヴィレア","desc":"オーストラリアに生息する常緑樹。葉も花も繊細で、赤や白の花を咲かせる。"}],"1786":[{"rank":"1","note":"書きかけの地図","exp":"150","type":"地理","name":"月の谷","desc":"アタカマ砂漠内の乾ききった岩塩地帯。草木はまったく生息しておらず、巨大な岩山が谷を形成している。空に浮かぶ月の表面に似ていると誰かが言ったことから、そう呼ばれるようになったそうだ。"}],"663":[{"rank":"2","note":"少女像の柱の地図","exp":"210","type":"美術品","name":"エレクティオンの少女像","desc":"パルテノン神殿のそばに建つ、エレクティオン神殿のカリアティド（女像柱）。6体あり優雅な雰囲気を漂わせている。"}],"1264":[{"rank":"3","note":"怠惰な世界","exp":"473","type":"美術品","name":"怠け者の天国","desc":"ピーテル・ブリューゲル（父）作。農民のいる情景を好んで描き、「農民ブリューゲル」と呼ばれる。この絵に描かれている僧侶や兵士、農民は、なにもせずに美食にありつき、ただ寝そべるだけである。"}],"3614":[{"rank":"3","note":"氷海世界","exp":"530","type":"地理","name":"氷山","desc":"北極海に浮かぶ流氷の中でも、ひときわ大きく高さのある氷塊。\n衝突した船は、沈没を避けられないだろう。"}],"3869":[{"rank":"2","note":"斑模様のクジラの地図","exp":"210","type":"海洋生物","name":"コククジラ","desc":"北米大陸やユーラシア大陸の北部沿岸を回遊する、やや小型のクジラ。黒い肌に付着した貝などが、模様のように見えるのが特徴。"}],"5254":[{"rank":"5","note":"クエスト「フランスで作られた星座」<br/>発見物カード:410","exp":"820","type":"天文","name":"ちょうこくしつ座","desc":"フランスの天文学者ラカーユによって制定された星座。ラカーユはケープに滞在し、南天の観測を行った。広さの割に明るい星が少なく探しにくい。"}],"1717":[{"rank":"2","note":"釣り","exp":"260","type":"海洋生物","name":"ノコギリザメ","desc":"目から口先までが細長く、縁に大小の突起がノコギリ状に付いているサメ。主に暖かい海の海底に生息し、泥中に細長い口先を潜らせてエサを採る。攻撃的な外見の割に、性格はおとなしい。身は大変美味。"}],"2499":[{"rank":"3","note":"当代一流の絵画とは","exp":"470","type":"美術品","name":"狩野元信の風景画","desc":"室町時代の絵師・狩野元信によって描かれた障壁画の一つ。\n唐絵に大和絵の様式を取り入れることで、それまでにない大きな画面の構成が可能となっている。"}],"3734":[{"rank":"5","note":"ダンジョン","exp":"830","type":"宗教遺物","name":"古びた天秤","desc":"太陽神ラーの天秤。\n古代エジプトの「死者の書」によると、アヌビスが死者の罪の重さを量り、魂の行く末を見定めるために用いたらしい。"}],"1897":[{"rank":"1","note":"サルベージ","exp":"130","type":"歴史遺物","name":"アン号","desc":"ペロポネソス半島沖で難破した貿易船。\nヤッファに巡礼者を送り届けた後、イングランドへの帰路で難破した。"}],"6586":[{"rank":"4","note":"","exp":"690","type":"大型生物","name":"ガウル","desc":"インドなどに生息するウシ。現存するウシの中で最も大きいといわれている。草食性で普段は温厚だが、その巨躯からトラを倒すこともある。"}],"2703":[{"rank":"3","note":"ある武人の証明","exp":"470","type":"財宝","name":"守人の帽子","desc":"朝鮮の両班が着用する特別な帽子。\n両班は文官と武官に分かれるが、この帽子は武官のものである。"}],"1214":[{"rank":"3","note":"セバルド島のさらなる調査<br/><br/>発見時経験値500　発見物カード経験値250","exp":"500","type":"海洋生物","name":"オウサマペンギン","desc":"大型のペンギン。水中に長時間潜ることができ、深いところで魚やイカなどを捕らえる。繁殖期には数千のつがいが集団となる。"}],"5537":[{"rank":"2","note":"","exp":"174","type":"気象・現象","name":"夜光虫","desc":"海に棲む小さな生物の発光で海が輝いて見える現象。波打ち際での目撃例が多いため、波の衝撃などが発生の要因と考えられる。"}],"167":[{"rank":"1","note":"シカの群れの地図","exp":"10","type":"中型生物","name":"アカシカ","desc":"温帯～亜寒帯まで、広い地域で見られる動物である。オスには大きな角があり、メスは小柄である。"}],"1652":[{"rank":"3","note":"南西端を目指せ","exp":"440","type":"地理","name":"ルーウィン岬","desc":"オーストラリア大陸の南西端にある岬。インド洋と南氷洋を一望できる景勝地である。周辺の土地は、乾燥地帯の多いオーストラリア大陸西部にありながら緑が豊かで、鉱物資源にも恵まれている。"}],"1303":[{"rank":"5","note":"謎めいた模様","exp":"910","type":"虫類","name":"シボリアゲハ","desc":"輝くような色彩と、後羽にある三本の尾に似た突起が神秘的なチョウ。黒い羽には波紋のような白模様があり後羽が赤い。"}],"1743":[{"rank":"5","note":"精霊力の源<br/><br/>発見時経験値1209　発見物カード経験値604","exp":"1209","type":"財宝","name":"マナ","desc":"マナとは神や精霊の力のこと。この石は島民が存在を口にするのも避けてきたほど非常に強いマナの力を秘めているらしい。石に触れるとほのかに温かく、触った場所から音も立てずに崩れていく。人には侵しがたい存在ということだろうか。"}],"4984":[{"rank":"3","note":"ロードス島を再調査","exp":"540","type":"史跡","name":"ロードス騎士団の城塞都市","desc":"本拠地を奪われた聖ヨハネ騎士団がロードス島に築いた要塞都市。\n街全体を囲む高さ12mの城壁は、全長4kmに及び、敵国の攻撃を幾度となく撃退したという。"}],"5022":[{"rank":"1","note":"到達する","exp":"16","type":"港・集落","name":"アントワープ","desc":"ネーデルラント南部十州の中でもっとも栄えている都市。海運が盛んで、かつては北欧交易の中心地であった。近年、アムステルダムにその地位を奪われつつある。レースや高級家具、油彩画が扱われている。"}],"3578":[{"rank":"2","note":"火を運ぶ鳥","exp":"234","type":"鳥類","name":"アラエ・ウラ","desc":"ハワイに火をもたらしたとされる伝説の鳥。「ウラ」とはハワイ語で赤色を意味し、額とクチバシの根元が鮮やかな赤色をしている。"}],"1499":[{"rank":"1","note":"獣の骨の地図","exp":"190","type":"化石","name":"かぎ爪のある巨大な獣の骨","desc":"かぎ爪を持った巨大な生物の骨。形からはクマを思わせるが、それとは比べ物にならないほどに大きい。どれほど恐ろしい生物だったのだろう。"}],"6792":[{"rank":"3","note":"視認","exp":"","type":"天文","name":"や座のガンマ星","desc":"や座で最も明るい星。位置は矢尻部分にあたり、アルファ\n星のシャムよりも明るく、３等星である。"}],"1237":[{"rank":"2","note":"俊足で獰猛な動物の像","exp":"290","type":"宗教遺物","name":"ジャガー像","desc":"ジャガーは、メソアメリカでは力強きものの象徴として、神のように崇め奉られていた。非常に獰猛でどの動物よりも強く、生物界の頂点に立つと考えられている。"}],"3645":[{"rank":"5","note":"山壁の絵","exp":"830","type":"史跡","name":"アルタイ山脈の岩刻絵群","desc":"ザナドゥの周辺で見られる、岩に刻まれた動物たちの絵。羊や馬、ヤギなどの動物や、動物を追う狩人の姿が描かれている。古代の人々の生活の様子を垣間見れる貴重な遺跡。"}],"6127":[{"rank":"3","note":"","exp":"440","type":"伝承","name":"トゥースフェアリー","desc":"抜けた乳歯を枕の下に入れておくと、いつの間にか金貨と取り換えてくれるという妖精。抜けた乳歯についての伝承は文化ごとに様々であり、この妖精にまつわる話は、主にヨーロッパのものである。"}],"6539":[{"rank":"5","note":"","exp":"1060","type":"伝承","name":"シルフ","desc":"風の精。四大元素のうち、風をつかさどるとされる精霊。大気の流れに乗って世界中を飛び回っている。細身の美少女の姿をしているらしいが、透明であるため視認できない。一説では、虚栄心が強い女性の死後の姿だともいわれる。"}],"5397":[{"rank":"3","note":"「天文学者の観測記録」<br/>発見物カード:230","exp":"460","type":"天文","name":"とびうお座","desc":"天の南極近くにある星座。星座図では、かじき座に追いかけられているように描かれることがある。"}],"3695":[{"rank":"3","note":"十字架の地図","exp":"470","type":"宗教遺物","name":"銀の十字架","desc":"スラブ民族が所持していたと思われる銀の十字架。スラブの人々は6世紀頃からバルト海沿岸、バルカン半島から黒海沿岸にまで広がった民族である。"}],"5943":[{"rank":"1","note":"クエスト「輝きの世代「<br/>発見物カード:95","exp":"193","type":"史跡","name":"未完の礼拝堂","desc":"バターリャ修道院にある礼拝堂の一つ。王族たちが永眠する場所として使うため、ドゥアルテ王子が建築計画を主導した。"}],"429":[{"rank":"1","note":"牛の群れの地図","exp":"30","type":"大型生物","name":"ヌー","desc":"アフリカに広く分布するウシのような動物。大移動をすることがあり、このときは群れが合流して数十万を超える。"}],"4849":[{"rank":"3","note":"クエスト「苦渋の決断」<br/>発見物カード:245","exp":"490","type":"天文","name":"ケフェウス座","desc":"ギリシャ神話におけるエチオピア王・ケフェウスが、天に昇ったとされる星座。カッシオペイアの夫であり、アンドロメダの父親でもある。"}],"252":[{"rank":"2","note":"バンシーの涙","exp":"310","type":"財宝","name":"バンシーの涙","desc":"ケルトの言い伝えに残る、死を告げる妖精バンシーの名を冠した宝石。魔槍ゲイボルグにはめこまれていたが、不吉を恐れて宝石だけ外され、地中深く埋められていた。"}],"6425":[{"rank":"4","note":"","exp":"","type":"中型生物","name":"夏毛のホッキョクギツネ","desc":"夏毛になったホッキョクギツネ。厳しい寒さに耐えるために冬場は厚い毛で覆われるが、夏場は灰色や褐色の毛に生え変わるという。小動物や鳥や魚。アザラシの死骸などさまざまなものを食べ、エサが乏しくなる冬でも冬眠しない。"}],"1541":[{"rank":"5","note":"マヤの王墓","exp":"1196","type":"歴史遺物","name":"パレンケの石棺","desc":"パレンケ遺跡にある、碑銘の神殿に納められた棺。蓋には、精巧なレリーフが彫られている。中には副葬品などが無数に眠っていた。"}],"3003":[{"rank":"1","note":"黄色の花の地図","exp":"170","type":"植物","name":"オオハンゴンソウ","desc":"北米原産の植物。丈は2mにも及び、黄色の大きな花を咲かせる。\n種子のほか、地下茎でも繁殖する。"}],"2561":[{"rank":"3","note":"荒地に咲くユリ","exp":"460","type":"植物","name":"タカサゴユリ","desc":"台湾島の山地で多く見かけられる、花の外側が赤く染まっている植物。\n一年ほどで開花するため、荒地などでもよく繁殖している。"}],"4844":[{"rank":"4","note":"王の図書館","exp":"780","type":"史跡","name":"ニネヴェ","desc":"アッシリア帝国が後期に首都を置いた都市。\nアッシリア中の書物が集められたアッシュールバニパルの図書館があったといわれる。"}],"2748":[{"rank":"2","note":"「書きかけの地図」<br/>発見物カード:135","exp":"270","type":"地理","name":"九竜の滝","desc":"金剛山にある滝。\n九竜とは、本来は滝つぼの名前であり、以前は衆香瀑（しゅうこうばく）と呼ばれていたらしい。しかし、いつの間にか、九竜の名が定着したという。"}],"6887":[{"rank":"5","note":"発見物カード:220","exp":"440","type":"財宝","name":"開元通宝","desc":"唐代に発行された円形方孔の貨幣。中央の穴を囲うように「開元通宝」という文字が刻まれているが、正しい文字の並びは不明。後世および周辺諸国の貨幣に大きな影響をもらたしたといわれている。"}],"5005":[{"rank":"5","note":"発見物カード:410","exp":"820","type":"天文","name":"レア","desc":"タイタンに次いで発見された土星の衛星。土星の衛星の中ではタイタンに次いで大きい。"}],"1245":[{"rank":"2","note":"珍しい翼","exp":"265","type":"鳥類","name":"ジャノメドリ","desc":"熱帯林の川辺に生息する用心深い鳥。巣に敵が近づくと、目玉模様のある翼を前に広げて威嚇する。"}],"6709":[{"rank":"4","note":"発見物カード:355","exp":"710","type":"天文","name":"アルタルフ","desc":"かに座で最も明るい星で、４等星。カニの脚の先に位置している。名はアラビア語で「終わり」を意味する。"}],"3806":[{"rank":"3","note":"書きかけの地図<br/>※5ブメして出ず、何か前提があるか？","exp":"510","type":"地理","name":"マルティニーク島","desc":"カリブ海の西インド諸島に属する火山島。起伏に富んだ地形を緑の木々が覆い、それを青い海が取り巻くという美しい島である。"}],"1287":[{"rank":"2","note":"女神の集う場所","exp":"280","type":"宗教遺物","name":"女神柱","desc":"アンコール遺跡の柱に彫られた女神の像。\nダ・ヴィンチやラファエロの母子画に見られるような温かい微笑を称えている。しかし、アンコール遺跡は砂岩という脆い建材で作られている箇所が多くこの柱も例外ではない。"}],"1905":[{"rank":"1","note":"海を塞いだ鎖","exp":"200","type":"歴史遺物","name":"金角湾の鎖","desc":"ビザンツ帝国がコンスタンティノープル攻防戦において、オスマン軍船の進入を拒むために張った太い鎖。オスマン軍はこれを破ることはできず、軍船を陸路で運ぶという奇襲を持ってビザンツ帝国に大打撃を与えた。"}],"5164":[{"rank":"1","note":"到達する","exp":"71","type":"港・集落","name":"モンバサ","desc":"アフリカ東岸の街。アフリカ・アラビア・インドの中間地点に位置するため、港湾都市として古くから栄えた。耕作が広く行われ、コーヒーなどの農産物が多く流通している。"}],"6546":[{"rank":"5","note":"追究クエスト","exp":"1150","type":"海洋生物","name":"カエルアンコウ","desc":"奇妙な姿のアンコウ。泳ぎが下手で、胸びれを前足のように使って海底を歩く。カエルを思わせるそのずんぐりとした姿は、とても愛らしい。"}],"508":[{"rank":"4","note":"古代の英雄の巨像","exp":"684","type":"美術品","name":"ダヴィデ","desc":"ミケランジェロ作の大理石像。高さ4mを超える巨大なものである。これはゴリアテを打ち倒す直前の、緊張したダヴィデである。関節や筋肉、血管などすべてがリアルで、いまにも動き出しそうだ。"}],"6441":[{"rank":"1","note":"","exp":"130","type":"宗教建築","name":"モン・サン・ミシェル","desc":"サン・マロ湾に浮かぶ小島に建設された修道院。潮の満ち引きが激しく、引き潮の時には大陸から歩いて渡ることができる。英仏百年戦争においては要塞としても利用された。\nその神秘性から「西洋の驚異」と呼ばれる。"}],"1690":[{"rank":"5","note":"幻のチョウ","exp":"1020","type":"虫類","name":"キプリスモルフォ","desc":"強烈に輝く青い羽は、空飛ぶ宝石と言っても過言ではない。前羽から後羽にかけての白い帯も、華やかさを添えている。"}],"806":[{"rank":"4","note":"大王の逸話","exp":"720","type":"歴史遺物","name":"アレクサンドロス大王の剣","desc":"マケドニアの王にして地中海からペルシャまでの巨大な版図を築いた、アレクサンドロス大王の剣。東西の技巧を凝らした、まさに王者の剣である。"}],"2881":[{"rank":"3","note":"天に花を捧げる女","exp":"520","type":"地理","name":"武陵源","desc":"独特の石柱が立ち並ぶ絶景地。\nその柱は3000本を超えるといわれる。\n地元には漢王朝の皇帝がここに住み、崩御したという伝説がある。"}],"1267":[{"rank":"5","note":"新大陸のドラゴン<br/><br/>発見時経験値1027　発見物カード経験値513","exp":"1027","type":"化石","name":"背中にとげのあるドラゴンの骨","desc":"背中に、二股に分かれたとげのような骨がある。そのまま突き出ていたのか、船の帆のように皮が張られていたのか。謎は尽きない。"}],"3809":[{"rank":"5","note":"ブードゥー教の神","exp":"510","type":"宗教遺物","name":"ブードゥー教の十字架","desc":"ブードゥー教の儀式で用いられる十字架。死や墓場を司る神であるバロン・サムディの象徴でもある。"}],"4864":[{"rank":"5","note":"最高の犬","exp":"1010","type":"中型生物","name":"サルーキ","desc":"イラクのテペ・ガウラにも彫刻が残されている世界最古の犬種のひとつ。すさりとした美しい肢体とスピードを追求して改良繁殖された狩猟犬でおる。最も速く走れる犬だという話もある。"}],"6014":[{"rank":"5","note":"『生神女』は『しょうしんじょ』と読む。","exp":"830","type":"宗教遺物","name":"生神女マリアの裏衣","desc":"正教会において、生神女と呼ばれる聖母マリアが生前着ていたとされる簡素な衣服。裏衣は「うちごろも」と読む。ビザンツ帝国時代にコンスタンティノープルの教会に納められており、そこで起こったという奇蹟が正教会には伝えられている。"}],"3255":[{"rank":"2","note":"優美な立ち姿","exp":"400","type":"鳥類","name":"ハゴロモヅル","desc":"南アフリカに生息するツルの一種。体長は約100cmで、体色は青みがかった灰色である。胸と尾の羽が長く、特に尾の方は地面まで届くほどの長さを持つ。ほっそりとした優美な立ち姿が特徴的な鳥である。"}],"5305":[{"rank":"2","note":"","exp":"250","type":"植物","name":"シアの木","desc":"サハラの南に広がるサバンナ地帯に生える、樹高7mから20mほどの樹木。降水量が少ない地域でも育つ。種子からはシアバターと呼ばれる良質の油が採れ、食用や薬として利用されている。"}],"5398":[{"rank":"2","note":"「古代エジプト遺物の地図」<br/>発見物カード:175","exp":"350","type":"財宝","name":"セネト","desc":"古代エジプトのボードゲーム。王朝誕生以前から遊ばれており、墓の壁画や副葬品として発見されている。"}],"2514":[{"rank":"1","note":"ベニモンアゲハに似たチョウ<br/><br/>発見時経験値180　発見物カード経験値90","exp":"180","type":"虫類","name":"シロオビアゲハ","desc":"中国南部からインドにかけて生息する、白い斑点がきれいに並んだ羽を持つチョウ。\n毒性がないため、ベニモンアゲハに体色を似せることで敵から身を守る。"}],"3326":[{"rank":"5","note":"大草原に住む動物<br/><br/>発見時経験値810　発見物カード経験値405","exp":"810","type":"小型生物","name":"プレーリードッグ","desc":"北米中央部の草原地帯に生息する動物。体長は30～40cm程度で、地面に深く掘った巣穴に住む。名前は、鳴き声がイヌに似ていることに由来する。"}],"5705":[{"rank":"5","note":"","exp":"1639","type":"歴史遺物","name":"蒼き狼の像","desc":"モンゴル人の祖とされる伝説の獣。『元朝秘史』の記述から、チンギス・ハンの別名として用いられることもある。妻は、白き牝鹿であったという。"}],"5360":[{"rank":"2","note":"","exp":"","type":"宗教建築","name":"エレウシス神殿","desc":"アテネ近くのエレウシスにあったデメテル神殿の遺跡。\nこの神殿で行われた秘儀の存在は古代には広く知られており、\n即位前のハドリアヌスなど有力者も参加している。"}],"5089":[{"rank":"1","note":"到達する","exp":"80","type":"港・集落","name":"タマタブ","desc":"マダガスカル島の東部に位置する街。島は山がちで、耕作の規模は小さい。しかし鉱山資源が豊富で、特に宝石の鉱脈が豊かである。"}],"2964":[{"rank":"5","note":"凶悪なウナギ","exp":"1030","type":"海洋生物","name":"ラブカ","desc":"ウナギのような細長い姿をしたサメ。深海に棲むという情報もあるが、詳細は不明。沿岸で漁をしていると網にかかることがあるという。生態など、多くのことが不明のサメである。"}],"5094":[{"rank":"2","note":"到達する","exp":"350","type":"港・集落","name":"テルナーテ","desc":"テルナーテ王国の首都で、モルッカ諸島北部に位置するテルナーテ島にある。近年、同島で産出される高価な香辛料を求め、ヨーロッパ人が進出。街を建造するに至った。"}],"566":[{"rank":"1","note":"古文書の地図","exp":"14","type":"歴史遺物","name":"パピルスの巻物","desc":"古代エジプトの書物。パピルスの茎を打ち伸ばした紙片に、古代エジプトの神聖文字・ヒエログリフが記されている。"}],"2057":[{"rank":"3","note":"奇妙な色のカエル","exp":"500","type":"小型生物","name":"トマトガエル","desc":"マダガスカル島北西部の森林に生息する。\n普段は地中や落ち葉の下などに潜っている。水かきは小さく、動きが鈍い。生息地が限られているため、個体数は少ない。"}],"6315":[{"rank":"5","note":"アフリカの巨大生物に関する伝承","exp":"1080","type":"伝承","name":"モケーレ・ムベンベ","desc":"中央アフリカの熱帯雨林に生息しているとされる幻の巨大生物。長い首と尾を持つ一方、四本の脚は短い。水辺によく姿を現すとされている。"}],"5058":[{"rank":"2","note":"到達する","exp":"370","type":"港・集落","name":"サマライ","desc":"ニューギニア島南東に位置する街。高温多湿の熱帯雨林気候。年中多雨で年間を通じて気温の年較差は少ない。"}],"362":[{"rank":"2","note":"王女の涙","exp":"300","type":"財宝","name":"王女の涙","desc":"古王国時代の副葬品と思われる耳飾り。古代エジプトの悲恋物語を追跡中に発見した。見事な細工が施されており、非常に高い身分の人物の愛用品であったことは間違いないようだ。"}],"3227":[{"rank":"5","note":"帰らぬ理由、通じぬ想い","exp":"950","type":"歴史遺物","name":"白銀の兜","desc":"ランス・オ・メドーに遺されたヴァイキングの兜。\n白銀で装飾されており一般の戦士の持ち物ではないと思われる。\n近くに白銀の産地があるか、あるいは交易で手に入れたものなのだろうか。"}],"3753":[{"rank":"4","note":"兄弟星","exp":"720","type":"天文","name":"ふたご座","desc":"黄道十二星座の1つ。アルゴ船での探検に参加した双子、カストルとポリュデウケスが天に昇った姿とされる。ギリシャ以外でも2つの星は組み合わせとされることが多く、北欧神話では巨人グーゼの目とされている。"}],"1442":[{"rank":"2","note":"追跡せよ","exp":"325","type":"中型生物","name":"ワラビー","desc":"太い尾と大きな後ろ足を持つ有袋類。袋に子を入れ、一度の跳躍で数mも移動する。夜間に果実などを食べ、大きな群れで生活する。"}],"3644":[{"rank":"2","note":"スラブ地方の木像の地図","exp":"330","type":"宗教遺物","name":"ヴェレスの木像","desc":"スラブ神話に登場する神の像。ヴェレスは家畜や富を司る神とされ庶民の崇拝を受けた。死者の霊魂にも関係したとされる。「イーゴリ遠征物語」内では、伝説の大詩人がヴェレスの孫とされている。"}],"1218":[{"rank":"5","note":"花酔い","exp":"1144","type":"財宝","name":"花酔いの石","desc":"巨大な蛍石の原石。これだけ大きなものはなかなか見ることができない。蛍石の中には、太陽光にあてると発光するものがあるが、これは非常に強く発光する。見るものに軽い酩酊感を与えるためこの名がついたようだ。"}],"6839":[{"rank":"2","note":"発見物カード:140","exp":"280","type":"植物","name":"ディエテス・ビコロル","desc":"南アフリカに生息するアヤメの一種。薄黄色の花びらに黒褐色の丸い模様が3つあるのが特徴。花数は多くつくが、花は1日ほどでしおれてしまう。乾燥に強く、日光が少なくても育つ。"}],"5039":[{"rank":"1","note":"到達する","exp":"67","type":"港・集落","name":"カリビブ","desc":"南アフリカ西岸にある街。小さな街で農業・漁業が中心だが、近辺に鉱山があり、銅や亜鉛のほかダイヤモンドが産出する。"}],"1811":[{"rank":"2","note":"釣り","exp":"250","type":"海洋生物","name":"ナイルアロワナ","desc":"ナイル川に生息するアロワナ。口が小さく黒鉄色の魚体が特徴である。"}],"2819":[{"rank":"2","note":"山水画の大家","exp":"360","type":"美術品","name":"郭煕の風景画","desc":"北宋時代の宮廷画家・郭煕が描いた絵画。\n自然に通じていた郭煕は、四季や天候による景観の微妙な変化を、巧みな筆致で表現している。"}],"1175":[{"rank":"5","note":"王の道へ…<br/><br/>発見時経験値1222　発見物カード経験値611","exp":"1222","type":"財宝","name":"エル・カミーノ・レアル","desc":"「エル・カミーノ・レアル」とは、スペイン語で「王道」という意味。真紅のフラメンコ衣装で、カール5世がミカエラを思ってデザインした。これを手放したということは、カール5世は過去との決別を決意したのだろうか…。"}],"6617":[{"rank":"5","note":"レガシー美の叡智　下","exp":"1800","type":"歴史遺物","name":"聖イシュトヴァーンの王冠","desc":"ハンガリーの初代国王イシュトヴァーン1世が、ローマ教皇から与えられた王冠。ハンガリー王国の権力を象徴する。金で出来た冠には複数のエナメル画が描かれ、宝石や真珠などの飾りもほどこされている。"}],"6442":[{"rank":"2","note":"","exp":"400","type":"歴史遺物","name":"ウルのロイヤルゲーム","desc":"メソポタミアの古代都市ウルにおいて、王や貴人たちによって遊ばれたという盤面遊戯。一説には、世界最古の盤面遊戯の一つといわれている。ルールは双六やバックギャモンに近く、それらの源流とされている。"}],"3739":[{"rank":"4","note":"のろまなサメ","exp":"800","type":"海洋生物","name":"ニシオンデンザメ","desc":"北大西洋の極北部などの寒冷な海に生息する大型のサメ。ずんぐりとした体型で、泳ぎはとても遅い。\n魚類だけでなく、アザラシといった動物も捕食する。"}],"521":[{"rank":"1","note":"古代の集落の地図","exp":"8","type":"歴史遺物","name":"家畜の骨","desc":"牛や馬など、家畜として飼われていた動物の骨。山羊や羊は多くの文明で飼われていたが馬はまったく見られない文明がある。"}],"334":[{"rank":"2","note":"悪妻にして鬼母","exp":"370","type":"歴史遺物","name":"アグリッピナの髪飾り","desc":"アグリッピナとは、古代ローマのカリグラ帝の妹であり、クラウディウス帝の妻。ネロ帝の母でもある。これは息子に暗殺されたときにつけていたものだという。"}],"6838":[{"rank":"3","note":"発見物カード:205","exp":"410","type":"美術品","name":"パッツィの聖母","desc":"ルネサンス期イタリアの彫刻家ドナテッロの作。大理石に幼いキリストを抱く聖母マリアが彫られている。薄い繊細な彫り込みで、陰影の効果を利用し、奥行きや質感を表現している。"}],"3176":[{"rank":"1","note":"硬質な木の地図","exp":"190","type":"植物","name":"クロトウヒ","desc":"北米東部から北部にかけて分布する樹木。高さは25m程度にまで伸び、円錐型に枝を広げる。材木としては堅いため、建築材として有用である。"}],"6882":[{"rank":"5","note":"発見物カード:775","exp":"1550","type":"宗教建築","name":"龍門石窟","desc":"北魏の時代に造営が始まった石窟寺院。山崖を掘って造られた石窟に数々の仏像が刻まれている。造営は王朝が変わっても続けられたという。"}],"5206":[{"rank":"1","note":"","exp":"","type":"歴史遺物","name":"トトメス1世のオベリスク","desc":"古代エジプトのファラオであるトトメス1世がアメン・ラーのために建立したとされる高さ22mのオベリスク。中心にトトメス1世、両脇にラムラス4世による碑文が刻まれている。"}],"699":[{"rank":"1","note":"神殿の守護","exp":"150","type":"宗教建築","name":"羊頭のスフィンクス","desc":"カルナック神殿の参道に並ぶ羊の頭のスフィンクス。40体ある。羊は神殿に祭られているアメン神の聖獣。アメン神は古代エジプトの国家神である。"}],"2793":[{"rank":"3","note":"三彩の伝来","exp":"510","type":"財宝","name":"唐三彩","desc":"唐代に焼成された色彩豊かな陶器。\n主に、貴族の副葬品として使われていた。\n人形や家財などをかたどったものが多く作られている。"}],"658":[{"rank":"1","note":"小さな宗教画の地図","exp":"26","type":"美術品","name":"イコン","desc":"正教会で信仰に用いられる聖像。宗教上の聖人や重要なシーンを描いたものである。"}],"5317":[{"rank":"2","note":"","exp":"","type":"虫類","name":"ヒヨケムシ","desc":"体長のおよそ3分の1を鋏角が占めるクモに似た生物。大型のものはネズミや小鳥なども捕食することがある。毒を持つという話はないが、うかつに近づかないほうがよいだろう。"}],"2816":[{"rank":"2","note":"東西宗教交流","exp":"330","type":"宗教遺物","name":"大秦景教流行中国碑","desc":"読みは「たいしんけいきょうりゅうこうちゅうごくひ」。キリスト教の教派の一つ、景教の教義と布教状況が記された碑。\n景教は唐代には広まっていたが、武宗の廃仏政策により、この碑も一緒に排斥されていたようだ。"}],"5024":[{"rank":"1","note":"到達する","exp":"50","type":"港・集落","name":"イスタンブール","desc":"かつてはビザンツ帝国の首都・コンスタンティノープルとして栄えた街。1453年、オスマントルコに占領され、首都・イスタンブールとなった。世界最大規模の都市である。ぜいたく品が扱われるほか果樹栽培なども盛んである。"}],"6762":[{"rank":"2","note":"発見物カード経験値：190","exp":"380","type":"海洋生物","name":"アコヤガイ","desc":"岩礁帯に広く生息している。体内に入った砂利などの異物を分泌物で固め、真珠を作る性質を持つ。アコヤガイの真珠は貝類の中でも特に光沢が美しいという。古代よりペルシャ湾周辺には真珠にまつわる物語が多く残されている。"}],"7011":[{"rank":"5","note":"ペルシャ湾視認","exp":"","type":"天文","name":"ロタネブ","desc":"いるか座で最も明るい4等星。アルファ星のスアロキンと同じく、天文学者のニコロ・カチャトーレのラテン語名「ベナトル」を逆から綴り名づけられた。"}],"4799":[{"rank":"2","note":"オセアニアの競技","exp":"360","type":"財宝","name":"オロ","desc":"ハワイ島で身分ある限られた人物だけが使える波乗り用の板。木製で非常に長く、6m以上あることもあり、非常に重い。他の住人は、より短い板で波乗りを楽しんでいるようだ。"}],"2106":[{"rank":"5","note":"少年が見たかったもの<br/><br/>発見時経験値1070　発見物カード経験値535","exp":"1070","type":"美術品","name":"聖母被昇天（ルーベンス）","desc":"ルーベンス作の祭壇画の一枚。聖母マリアがその生涯を終え、天国へと昇る姿を描いた。天使たちに囲まれ天へと昇る姿はまさに聖母といえるだろう。"}],"1537":[{"rank":"1","note":"書きかけの地図","exp":"110","type":"地理","name":"バンカ島","desc":"マラッカ海峡東部に位置する島。この海域の島々と同様、島の周囲には美しいサンゴ礁が広がっている。"}],"5072":[{"rank":"1","note":"到達する","exp":"127","type":"港・集落","name":"ジェッダ","desc":"アラビア半島の西岸に位置し、紅海に面した港町。イスラム教徒の聖地への巡礼の入口として古代より栄えてきた。"}],"5877":[{"rank":"5","note":"クエスト「神話なき星座」<br/>発見物カード:690","exp":"1380","type":"天文","name":"こうま座","desc":"明るい星がなく、全天でも最小に近い星座。トレミー48星座の一つだが、誰が制定したのかは定かではなく、元となる神話も伝わっていないという謎に包まれた星座である。"}],"212":[{"rank":"1","note":"テンプル騎士団長の甲冑","exp":"100","type":"宗教遺物","name":"テンプル騎士団長の甲冑","desc":"テンプル騎士団は、十字軍時代の三大騎士団の一つ。非常に強大であったが、14世紀初めにフィリップ4世に弾圧されて解散した。この甲冑はエディンバラで保管されていたもので、団長であったモレーのものと伝えられている。"}],"927":[{"rank":"1","note":"美しいつぼの地図","exp":"22","type":"財宝","name":"浮き彫りのつぼ","desc":"表面に美しいレリーフを施したつぼ。実用品ではなく、飾るためのものだろう。"}],"6543":[{"rank":"5","note":"追究クエスト","exp":"1150","type":"宗教遺物","name":"ヴァーユ像","desc":"インド神話に伝わる風の神。始まりの原人から生まれ、最初にソーマを受け取った神とされる。インドラとともに空界を治めるほどの力を持つ存在で、その姿は非常に美しいといわれる。"}],"1634":[{"rank":"5","note":"釣り","exp":"910","type":"海洋生物","name":"ブルーマーリン","desc":"クロカジキ。外洋性でカジキの種類の中で最も大きくなるという。"}],"2044":[{"rank":"2","note":"描かれた理想","exp":"300","type":"美術品","name":"アダムとエヴァ","desc":"楽園を背景に、男女と動物を描いた彫刻銅版画。デューラーの四大銅版画のうち最も早く制作された。テーマは「原罪」。\nウィトルウィウスの人体比例を用いてあり、古代彫刻の理想的形態が提示されている。"}],"2904":[{"rank":"4","note":"儀式を行う名山","exp":"680","type":"地理","name":"泰山","desc":"宗教の中心として崇められてきた山。\n秦の始皇帝以来、歴代の皇帝が、国家統一を天に報告する「封禅の儀」を行う場所で、山全体に祠や廟が点在する。"}],"1759":[{"rank":"1","note":"水位計測器の地図","exp":"180","type":"歴史遺物","name":"ナイロメーター","desc":"ナイル川の至る所に設置された、水位計測施設。ナイル川は一年に一度大氾濫を起こし、下流の農業に大打撃を与えるため、氾濫をいち早く察知する必要があった。ただし氾濫には、上流の肥沃な黒土を下流に運ぶという働きもあったという。"}],"6361":[{"rank":"2","note":"サンフランシスコの南　２分程度　10531,3347<br/>昼間　曇り空","exp":"370","type":"気象・現象","name":"白い嵐","desc":"冷えて重くなった空気が雲から一気に吐き出される現象。災害をもたらすほど強烈な突風が地上に吹きすさぶ。積乱雲の中に蓄えられた冷たい空気が、上昇気流の衰えによって地上へと急降下することで発生する。"}],"543":[{"rank":"1","note":"古代の墳墓の地図","exp":"13","type":"歴史遺物","name":"古代人の骨","desc":"古代遺跡から出土した人骨。出土したときの状況から、当時の様子がうかがわれる。"}],"2524":[{"rank":"1","note":"灰色のネズミの地図","exp":"110","type":"小型生物","name":"ジャコウネズミ","desc":"台湾島や中国など、広い地域に分布するネズミ。市街地や農耕地に生息する。\n子が、親の尾や別の子の尾をくわえ、連なって移動する姿が見られる。"}],"5061":[{"rank":"1","note":"到達する","exp":"80","type":"港・集落","name":"サンクトペテルブルク","desc":"バルト海のフィンランド湾最東端に位置するロシア帝国の港街。\n街名は「聖人ペテロ」に由来する。演劇や美術、文学が盛んな文化都市として発展した。"}],"5020":[{"rank":"1","note":"到達する","exp":"49","type":"港・集落","name":"アレクサンドリア","desc":"アレクサンドロス大王が各地に作った都市、「アレクサンドリア」の一つ。地中海とアラビアの貿易中継地点として、栄えている。ナイル沿岸の肥沃な土壌で育った農産物と、アラビア経由の香辛料や香料が扱われている。"}],"6937":[{"rank":"2","note":"発見物カード:130","exp":"260","type":"天文","name":"マルカブ","desc":"ペガスス座のアルファ星。白く輝く2等星。秋の四辺形を構成する星の1つ。名はアラビア語で「馬の肩」を意味する。"}],"5936":[{"rank":"4","note":"","exp":"720","type":"植物","name":"死んだ草","desc":"アフリカ西岸で見つけた、枯れた草。「不死の植物」を探して見つけたものだが、むしろ死んでしまっているように見える…。"}],"5883":[{"rank":"5","note":"","exp":"1400","type":"中型生物","name":"アルパカ","desc":"南米などに生息するラクダの仲間。非常に高品質の毛を収穫できるため、古来から優秀な家畜として利用されてきた。ただ、威嚇する際に非常に臭い唾液を吐き出す習性があるため注意が必要。"}],"6899":[{"rank":"3","note":"","exp":"","type":"虫類","name":"ゴライアスオオツノハナムグリ","desc":"アフリカの熱帯雨林などに生息する、コガネムシの一種。体長はおよそ10cmと同種の中では大型。幼虫は寒さに弱く、20度以下の環境では死に至ることもあるという。乾季に泥で繭を作り、雨季に繭を出て成虫となる性質を持つ。"}],"1265":[{"rank":"1","note":"トカゲの骨の地図","exp":"180","type":"化石","name":"首の長いトカゲの骨","desc":"体長10mを超える、首の長い巨大なトカゲの骨。この生物が生きていたころは、同じ大きさのトカゲが何匹も歩き回っていたのだろうか。"}],"5002":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:165","exp":"330","type":"天文","name":"こぎつね座の鉄亜鈴型の星雲","desc":"こぎつね座のやや南にある、楕円形の中央がくびれた特徴的な形をした星雲。"}],"461":[{"rank":"1","note":"銀細工の甲冑の地図","exp":"66","type":"財宝","name":"銀細工の甲冑","desc":"地金に銀で装飾を施した甲冑。銀は強度がないが、邪を退ける力があると考えられているので、祭礼などで使われたものではないかと考えられる。"}],"6030":[{"rank":"2","note":"ふさわしからぬ写本","exp":"370","type":"財宝","name":"ブラヌス写本","desc":"ドイツのベネディクト会修道院に所蔵されていた中世の写本。ラテン語を始め、ヨーロッパ各地の古語で記された聖歌や世俗詩などが収められている。特に世俗詩は、文学的なものから風刺、性や酒、賭博といった内容のものまで多岐にわたる。"}],"727":[{"rank":"5","note":"聖なる川に棲む者","exp":"910","type":"大型生物","name":"インドガビアル","desc":"細長い吻（ふん）が特徴。繁殖期になるとオスはメスを集めてハーレムをつくる。陸地に上がることはあまりなく、主に魚をエサとしている。"}],"5026":[{"rank":"1","note":"到達する","exp":"28","type":"港・集落","name":"エディンバラ","desc":"ブリテン島の北東に位置する、スコットランドの中心地。7世紀にスコットランド最初の王・エドウィンが城を築いた。街の名の由来は、このエドウィンと「城塞都市」を意味する「バラ」である。"}],"491":[{"rank":"3","note":"古代エジプトの護符","exp":"495","type":"宗教遺物","name":"金のスカラベ","desc":"スカラベとはオオタマオシコガネのことで、動物のフンを転がして玉にし、卵を産みつける習性がある昆虫のことである。古代エジプトでは、フンを転がす姿が太陽の運行を連想させるとして信仰され護符に多用された。"}],"3187":[{"rank":"3","note":"危険な海峡","exp":"530","type":"地理","name":"ベルアイル海峡","desc":"北米大陸のラブラドル半島とテラ・ノヴァの間に位置する海峡。幅は平均して18km、最大でも60kmという非常に狭い海峡である。海流も強く、霧や強風などの悪天候にも見舞われる場所であり、航海の難所とされる。"}],"1343":[{"rank":"1","note":"ハサミのある虫の地図","exp":"140","type":"虫類","name":"ギラファ","desc":"体長が10cmを超える大型の虫。頭部についた長いハサミは強力で、威嚇や攻撃に使用される。"}],"2989":[{"rank":"1","note":"桃色の鳥の地図","exp":"200","type":"鳥類","name":"ロジアテ・スプーンビル","desc":"鮮やかな桃色の羽毛を持つ鳥。平たいクチバシですくうように魚を獲る。"}],"645":[{"rank":"1","note":"書きかけの地図","exp":"180","type":"地理","name":"コスメル島","desc":"カリブ海西部に浮かぶ島。非常にサンゴ礁が美しい島で、熱帯魚もよく見られる。海の透明度は30mを超え、この世の天国のようだ。"}],"814":[{"rank":"1","note":"大帝国への道","exp":"120","type":"地理","name":"ニジェール川","desc":"西アフリカの中央部を流れる大河。大きく湾曲している。上流まで小型船で航行でき、この地方の重要な交通路である。上流には、数百年もの間栄えているトンブクトゥという都市があるというが、海洋を航行する船ではたどりつけないようだ。"}],"1879":[{"rank":"1","note":"精巧な加工の地図","exp":"160","type":"歴史遺物","name":"水晶の水差し","desc":"ファーティマ朝のカリフに贈られた、水晶の水差し。水晶だとは信じられないほど薄く加工され、精緻な彫刻が施されている。イスラムの高度な技術を窺い知ることができる。"}],"6430":[{"rank":"2","note":"インド西岸沖（3250、3990）辺り<br/>冒険経験310<br/>カード経験155<br/>視認スキル７か８が必要(６で足りず、８で観測成功のため)","exp":"310","type":"気象・現象","name":"ブルージェット","desc":"雷雲からさらに上空に向けて発生する発光現象。特に青いものをこのように呼称する。上向きの雷とよばれることもある。発光時間の短さや発生位置の高度などにより、観測例は少ない。"}],"1213":[{"rank":"2","note":"セバルド島周辺の生物","exp":"280","type":"海洋生物","name":"マカロニペンギン","desc":"大きく目立つ金色の冠毛を持つ。くちばしはオレンジ色で、その周辺にピンクの縁取りがある。とても攻撃的である。"}],"2769":[{"rank":"2","note":"ダンジョン","exp":"280","type":"宗教遺物","name":"大聖堂の地下墓所","desc":"大聖堂の地下に作られたカタコンベ。イタリア半島をはじめ、ヨーロッパの教会ではいくつかのカタコンベが見つかっている。フランスでもボルドーなど数箇所に存在することが確認された。"}],"1454":[{"rank":"2","note":"アステカの皇帝<br/><br/>発見時経験値230　発見物カード経験値115","exp":"230","type":"財宝","name":"モクテスマ2世の杖","desc":"アステカ皇帝・モクテスマ2世のものといわれている杖。彼は変革や支配強化を進めるなど、アステカの新たな道を模索する一方、イスパニア人コルテスをケツアルコアトルの再来と信じている。"}],"529":[{"rank":"1","note":"古代の道具の地図","exp":"10","type":"歴史遺物","name":"古代の石臼","desc":"穀物や豆類などを粉に挽くための、石で作られた臼。粉にすることで保存や調理が容易になる。世界各地の遺跡で出土する。"}],"2624":[{"rank":"2","note":"［勅命］[[調査における水場の確保","exp":"340","type":"地理","name":"卑南渓","desc":"台湾島東部を流れる川の一つ。\n卑南とは、先住民である卑南民族の頭目を意味する。\n複雑に削られた川の地形が、中国の黄山に似ていることから「小黄山」とも呼ばれる。"}],"1744":[{"rank":"4","note":"深緑の刃","exp":"624","type":"財宝","name":"ポウナムの斧","desc":"ポウナムとはマオリの言葉でひすいを指す。マオリの人々は鉄を知らなかったが、硬く粘りのあるひすいを長い時間をかけて削り出し斧や棍棒、首飾りなどを製作する技術を有していた。この斧はポウナムでできた刃をもつ儀式用の斧だそうだ。"}],"6848":[{"rank":"2","note":"発見物カード:130","exp":"260","type":"天文","name":"アルネブ","desc":"うさぎ座で最も明るい3等星のアルファ星。ウサギの体にあたる場所に位置し、名はアラビア語で「ウサギ」を意味する。"}],"3385":[{"rank":"3","note":"ウルクの女神","exp":"500","type":"宗教遺物","name":"イナンナ像","desc":"イナンナは、シュメールの豊穣と愛の女神とされる。ウルクの守護神として崇拝されていた。\nアッカドではイシュタルと呼ばれた。"}],"1615":[{"rank":"1","note":"小さな花の地図","exp":"140","type":"植物","name":"エリデス","desc":"しだれ状に伸びた花茎に、小さい花を穂状につける。花はピンク、白、黄色などがある。芳香が強い。"}],"982":[{"rank":"1","note":"暴帝ネロの像","exp":"50","type":"歴史遺物","name":"ネロ帝のブロンズ像","desc":"ネロは古代ローマの皇帝で、悪逆の皇帝として知られる。邪魔な血縁者を次々に葬ったが娯楽の提供に熱心だったため、民衆に人気があった。"}],"2608":[{"rank":"4","note":"蘭嶼の変わった船","exp":"650","type":"財宝","name":"タタラ船","desc":"蘭嶼島に住む台湾島先住民に伝わる、伝統的な船。ゴンドラの形をしており、不安定。\n友人同士で出漁するために使う。"}],"1999":[{"rank":"2","note":"釣り","exp":"240","type":"海洋生物","name":"オヒョウ","desc":"体長3mにもなる巨大なカレイ。北極海に生息する。"}],"5716":[{"rank":"4","note":"2017.02.07新規追加","exp":"690","type":"大型生物","name":"ヤク","desc":"高地に生息する牛のような動物。全身を長い毛でおおわれており、野生種は根の色が黒茶だが、家畜化されたものには白や赤が混ざるという。搾乳から荷物の運搬まで多くの用途に使われている。"}],"2342":[{"rank":"2","note":"あやしい人形","exp":"390","type":"歴史遺物","name":"土偶","desc":"日本で発見された、人の形をしている土製の焼き物。奇異な形状だが、どこか女性らしさが漂う。\n一部、故意に壊されたような痕跡があるが、目的は不明だ。"}],"3781":[{"rank":"4","note":"視認","exp":"610","type":"天文","name":"冬の大三角","desc":"ヨーロッパでは冬の南の空に現れる、3つの明るい星を結んで描かれる三角形。3つの星はすべて1等星で、ほぼ正三角形を描くため見つけやすい。さまざまな星座を見つける目印となる。"}],"6641":[{"rank":"2","note":"","exp":"360","type":"財宝","name":"ドン・キホーテ","desc":"イスパニアの作家ミゲル・セルバンテスの小説。騎士物語に憧れすぎて自らを騎士だと妄想してドン・キホーテと名乗る男の冒険譚。批判精神に富み、騎士道に代表される古き慣習への諷刺が読み取れる。"}],"5599":[{"rank":"2","note":"","exp":"250","type":"地理","name":"エルバート山","desc":"北米大陸西部に位置するロッキー山脈の最高峰。その標高はおよそ4400mに及ぶ。"}],"662":[{"rank":"1","note":"小型肉食獣の地図","exp":"27","type":"小型生物","name":"フェレット","desc":"別名をケナガイタチという。普通のイタチより毛足が長いため、見た目はかわいらしい。とはいえ、やはりイタチなので強烈な悪臭を放つ。船員たちに連れ帰らないよう、きつく言いつけなくては。"}],"5224":[{"rank":"2","note":"","exp":"230","type":"史跡","name":"ヌラーゲ","desc":"サルデーニャ島に見られる巨大な建造物。大きな石を塔のような形状に積み上げて作られている。先史時代に作られ、その数は当時2万ほどであったと見られている。"}],"5248":[{"rank":"1","note":"","exp":"160","type":"化石","name":"ウマのようなゾウの骨","desc":"動物の頭部の骨。顔が長く、ウマに似ているが、ゾウのような牙も持っている。"}],"1993":[{"rank":"1","note":"釣り","exp":"160","type":"海洋生物","name":"ファハカ","desc":"ナイル川に生息するフグ。淡水に生息するとは珍しいフグだ。"}],"6285":[{"rank":"5","note":"クエスト「髪飾りの謎」<br/>発見物カード:590","exp":"1180","type":"地理","name":"白砂漠","desc":"サハラ東部に位置する砂漠。白い石灰質の岩に覆われており、風で浸食された奇岩が立ち並んでいる。"}],"1212":[{"rank":"5","note":"水中を走る船","exp":"1118","type":"海洋生物","name":"巨大ピラルク","desc":"アマゾン川流域に生息するピラルクが巨大化したもの。体長は5mをゆうに超える。"}],"6271":[{"rank":"2","note":"","exp":"220","type":"地理","name":"ソロモン諸島","desc":"16世紀のスペイン人探検家、アルバロ・デ・メンダーニャ・デ・ネイラが発見した群島のひとつ。\n島の名前は、海岸で砂金を見つけたことでソロモン王の財宝の島とメンダーニャが仮定したことに由来する。"}],"504":[{"rank":"1","note":"クエスト「古代ギリシャ最高の叙事詩」<br/>発見物カード:30","exp":"60","type":"財宝","name":"オデュッセイア","desc":"ホメロス作の叙事詩。トロイの木馬の立案者であるオデュッセウスが、トロイ戦争のあと神の怒りに触れ、苦労のすえに故郷に帰り着くまでを語るもの。"}],"291":[{"rank":"2","note":"マダガスカルの東","exp":"270","type":"地理","name":"モーリシャス諸島","desc":"マダガスカル島の東に浮かぶ島々。無人島である。サンゴ礁に囲まれているが、土地は比較的肥沃で、耕作が可能だと思われる。熱帯性の気候と美しい海があいまって、楽園のようだ。"}],"1815":[{"rank":"4","note":"癒しの宝石","exp":"350","type":"財宝","name":"星の花","desc":"南米西岸で産出される桃色の宝石。インカローズとも呼ばれる。花のような優しい色彩と星の光のような輝きは見るものの疲れを癒し純朴で温かな気持ちを呼び覚ましてくれる。"}],"5090":[{"rank":"2","note":"到達する","exp":"354","type":"港・集落","name":"ダバオ","desc":"ミンダナオ島の南岸に位置する街。ミンダナオ島は気候が安定しているため、農業に最適な土地である。さらにダバオは海側に山脈を持つため、嵐の影響を受けにくい。"}],"6564":[{"rank":"5","note":"追究クエスト","exp":"1500","type":"海洋生物","name":"デンキナマズ","desc":"デンキウナギに次いで強力な電気を発生させられる魚。体から電気を放出して、小魚などを捕食したり、周囲を探ったりする。ナイル川に古くから生息するといわれ、古代の文献には雷神のように記述されている。"}],"6162":[{"rank":"2","note":"","exp":"240","type":"財宝","name":"ピサ海図","desc":"13世紀にピサで製作されたといわれる最初期の羅針儀海図。港や海岸線を写実的に描いた航海用の地図であり、14世紀までの間にかけて盛んに製作された。他の羅針儀海図の例に漏れず、地球が球体であることを考慮していない作りが特徴。"}],"3045":[{"rank":"2","note":"大きな花の地図","exp":"210","type":"植物","name":"アメリカフヨウ","desc":"陽光が当たる場所を好む、北米原産の植物。丈はおよそ1mまで成長し、20cm程度の大輪の花を咲かせる。"}],"4795":[{"rank":"2","note":"オセアニアの神像の地図","exp":"339","type":"宗教遺物","name":"カナロア像","desc":"ハワイやポリネシアで広く知られる四大神の一柱。海神であるほかに魔法と冥界の神であるともいう。イカやタコの姿で現されることが多い。タンガロアとも呼ばれる。"}],"1165":[{"rank":"5","note":"星の戦争","exp":"1183","type":"史跡","name":"パレンケ","desc":"深い森の中にたたずむマヤの古い遺跡。中心部にある宮殿のような建物の向かいには、なにやら壁にびっしりと刻まれた神殿がある。これを解読できれば、マヤについて深く知ることができるかもしれない。"}],"6352":[{"rank":"2","note":"","exp":"300","type":"歴史遺物","name":"太陽神が刻まれたコイン","desc":"古代ロードス島で製造されたコイン。島のシンボルである薔薇とともに厚い信仰をうける太陽神ヘリオスが刻まれたコインが数多く製造されたといわれる。"}],"5473":[{"rank":"2","note":"鎧に覆われた動物の地図<br/><br/>発見時経験値210　発見物カード経験値105","exp":"210","type":"中型生物","name":"オオアルマジロ","desc":"南米のサバンナや熱帯雨林に生息する動物。体長が70～100cmで、アルマジロの中で一番大きいといわれる。\n東部と背中は皮膚が硬質化した鱗甲板で覆われおり、他の部分も全部が硬い毛で覆われている。"}],"3766":[{"rank":"2","note":"クエスト「美の女神の星」<br/><br/>発見物カード:175<br/>　","exp":"350","type":"天文","name":"金星","desc":"明け方と夕方に姿を現す、太陽と月に次いで明るい惑星。古代ギリシャのピタゴラスが明けの明星と宵の明星が同じ星だと気づいたとされる。ローマ神話のヴイーナスを始め、美を司る女神の名で呼ばれることが多い。"}],"5912":[{"rank":"4","note":"","exp":"680","type":"海洋生物","name":"オオホモラ","desc":"深海に生息する大型のカニ。一番後ろの脚が甲羅の上側に曲がっており、この脚で貝殻などを背負って身を守るという。"}],"5731":[{"rank":"5","note":"2017.02.07新規追加","exp":"1440","type":"宗教遺物","name":"三賢者の贈り物","desc":"東方の三賢者がイエス誕生を祝して送ったとされる贈り物。黄金、乳香、没薬であるとされ、三つそれぞれがイエスの王権、神性、受難を表している。"}],"5603":[{"rank":"2","note":"","exp":"300","type":"気象・現象","name":"彩雲","desc":"上空の雲が赤や黄、緑などの色で彩られる現象。比較的、薄い雲で観測されることが多いため、雲の薄さが発生原因に含まれると思われる。一部地域では、吉兆と言われる。"}],"6550":[{"rank":"5","note":"","exp":"","type":"史跡","name":"在りし日の大灯台","desc":"高さ130メートル以上と伝わる巨大な灯台。紀元前3世紀ごろにプトレマイオス朝エジプトの首都、アレクサンドリア沖合にあるファロス島に建設された。最上部の灯室には巨大な鏡が置かれ、昼は陽光を反射させるのに用いられたという。"}],"3704":[{"rank":"","note":"義賊の弓<br/><br/>発見時経験値3030　発見時名声2420<br/>(合計名声2万超えによる名声半減のため、1210*2にしてあります)","exp":"3030","type":"レリック","name":"シャーウッドの森の義賊","desc":"シャーウッドの森に住んだとされる礼節深きアウトロー、ロビン・フッド。時代を超えて語り継がれ、人々に愛され続けている。"}],"6958":[{"rank":"5","note":"発見物カード:540","exp":"1080","type":"歴史遺物","name":"ファイストスの円盤","desc":"ギリシャのクレタ島で見つかった粘土製の円盤。直径15cmほどで、両面には渦巻く独特の模様が型押しされたように並んでいる。焼けて固まっている状態で発見された。これは大噴火による火災が原因なのだろうか。"}],"5780":[{"rank":"2","note":"","exp":"210","type":"地理","name":"パンゴン湖","desc":"ユーラシア大陸中央部に存在する海水と淡水が入り混じった湖。塩湖としては世界で最も高地にある。冬には１ｍに達するほどの厚い氷が張ることもある。"}],"889":[{"rank":"2","note":"毒蛇の天敵","exp":"330","type":"中型生物","name":"マングース","desc":"毒蛇を食べる動物。大きなイタチのような外見をしている。毒が効かないわけではなく、かまれれば死んでしまうそうだ。体が小さい割りに気が荒い。"}],"5144":[{"rank":"1","note":"到達する","exp":"130","type":"港・集落","name":"ホルムズ","desc":"ペルシャ湾のホルムズ海峡に面する街。海上交易の重要地点で、古くから栄えた。その重要性からたびたび支配勢力が変わった。畜産が盛んなほか、高級品のペルシャ絨毯やターコイズなどの宝石が流通している。"}],"1935":[{"rank":"4","note":"手のひらに乗るサル","exp":"700","type":"小型生物","name":"ピグミーマーモセット","desc":"とても小さなサル。手のひらに乗る大きさにまでしか成長しない。川沿いの森を好み、主に樹液を摂取して生活している。鳥のような鳴き声をしている。"}],"6816":[{"rank":"3","note":"サルベージ<br/>発見物カード:225","exp":"495","type":"歴史遺物","name":"サーチェ・リマーニ沈没船","desc":"11世紀ごろの商船。ビザンティン帝国とファティーマ朝でガラスなどの交易を行っていたとみられる。ロードス島に近いトルコ南西部のサーチェ・リマーニ湾付近で沈没した。"}],"364":[{"rank":"4","note":"黄金に彩られた民族","exp":"696","type":"宗教遺物","name":"オニャンコポン像","desc":"西アフリカのアシャンティ人の神の像。万物の創造者である。かつては地上に住んでいたが、やがて天上に住むようになったと伝えられる。"}],"2733":[{"rank":"2","note":"地域調査依頼<br/><br/>発見時経験値320　発見物カード経験値160","exp":"320","type":"歴史遺物","name":"高敞支石墓群","desc":"読みは「こちゃんしせきぼぐん」。朝鮮半島西岸にある、大規模な支石墓群。\n大小さまざまな石材で形成されており、形態もテーブル式や基盤式など多種多様。総数は400を超えるという。"}],"6254":[{"rank":"3","note":"","exp":"480","type":"宗教建築","name":"アルカディ修道院","desc":"クレタ島に造られた修道院。16世紀にヴェネツィア様式を取り入れて建造された。それより以前からあった修道院を改修したとの説もある。島に住むキリスト教徒からは「生きた修道院」と呼ばれており、精神的支柱になっているようだ。"}],"6726":[{"rank":"5","note":"","exp":"","type":"地理","name":"ピトン","desc":"カリブ海のセントルシア島にある二つの小さな火山。標高の高いものがグロピトン山、低いものがプチピトン山とされ、双子の山と呼ばれている。"}],"2823":[{"rank":"2","note":"国王の石碑","exp":"330","type":"歴史遺物","name":"高句麗王碑文","desc":"高句麗の王、長寿王の手によって建てられたとされる石碑。石碑には長寿王の父親である第19代高句麗王・広開土王の業績が記されている。"}],"2750":[{"rank":"2","note":"大きくなく小さくなく","exp":"270","type":"小型生物","name":"コウライリス","desc":"朝鮮半島の森林地帯に生息するリス。耳の先端にある、長い毛房が特徴的。\n木の芽や木の実を食べる習性は、他のリスと変わらない。"}],"3663":[{"rank":"4","note":"ダンジョン","exp":"693","type":"宗教遺物","name":"クフ王の平板石碑","desc":"葬礼に用いられたと思われる石碑。平たい石灰岩にヒエログリフが彫られ、彩色が施されている。ヒエログリフは非常に神聖視されており、特殊な目的以外には使われなかったといわれる。"}],"6602":[{"rank":"5","note":"","exp":"830","type":"大型生物","name":"アモイトラ","desc":"中国南部の山地や森の奥深くに生息するという猛獣。トラの中では比較的小さい種だが、人を襲うこともあるため、注意が必要。"}],"1353":[{"rank":"4","note":"眠り続けた遺跡","exp":"756","type":"宗教建築","name":"ボロブドゥール遺跡","desc":"ジャワ島のほぼ中央にある仏教遺跡。基壇の上に積み重ねられたピラミッド型の形状。レリーフや仏像、仏塔がおびただしいほど存在する大規模なものだ。中には釈迦の遺骨を納めた仏塔があるというが…。"}],"6298":[{"rank":"2","note":"","exp":"380","type":"地理","name":"ピオピオタヒ","desc":"ニュージーランドの南島にあり、タスマン海に面するフィヨルド。1000ｍを超える断崖絶壁に囲まれている。一年の半分以上は雨が降る土地であり、雨天時のみ形成される滝が数多くあるという。"}],"3819":[{"rank":"2","note":"美しい魚の地図","exp":"370","type":"海洋生物","name":"ノボリエビス","desc":"大西洋沿岸部の岩礁域に生息する魚。体色は銀色や赤色で、ひれが長く、目が大きい。"}],"1800":[{"rank":"2","note":"ある女傑の物語","exp":"340","type":"財宝","name":"シャールカの髪飾り","desc":"シャールカとはボヘミアの伝説に語られる女性。恋人の裏切りに遭い、男たちに復讐するが最後は再び愛に揺れる。ボヘミアの古い言い伝えでは「髪の長い女は癇癪持ちである」と言われておりシャールカの伝説と通じるところがある。"}],"540":[{"rank":"1","note":"古代の墳墓の地図","exp":"40","type":"歴史遺物","name":"黄金の棺","desc":"黄金造りの棺。古代の王族や貴族のものと思われる。みごとな装飾から、埋葬者の権力の大きさがわかる。"}],"1329":[{"rank":"4","note":"クエスト「太陽の昇る場所」<br/>発見物カード:300","exp":"624","type":"地理","name":"ニューギニア島","desc":"ティモール島のさらに東に位置する島。大陸と見紛う程の大きさである。中央には高い山脈がそびえ、高地と低地の気温差が大きい。島内の場所によって、人々の言語と文化が異なる。"}],"2842":[{"rank":"2","note":"［勅命］[[現地の信仰と山の関係調査","exp":"310","type":"地理","name":"三清山","desc":"道教の名山の一つ。道教の三大神が並んで座っているように見えることから、この名が付いたとされる。"}],"5586":[{"rank":"3","note":"","exp":"490","type":"史跡","name":"バッファロー・ジャンプ","desc":"正式名称は「ヘッド・スマッシュト・イン・バッファロー・ジャンプ」。北米北西部にある崖。周辺の草原に生息するアメリカバイソン（バッファロー）を追い込んで狩る場所として、古来より利用されており、古い矢尻なども見つかっている。"}],"6079":[{"rank":"3","note":"","exp":"510","type":"財宝","name":"袞龍袍","desc":"中国の歴代王朝において、皇帝が公の場に出る際にまとっていた宮廷用の服で「こんりゅうほう」と読む。幸福や長寿を祈る吉祥文様が全身にあしらわれ、特に皇帝だけが許された5本指の龍の刺繍が9カ所に入っている。"}],"6387":[{"rank":"5","note":"金色に関する伝承","exp":"1120","type":"伝承","name":"金色姫","desc":"養蚕の始まりとされる伝承。継母に忌み嫌われた金色姫は何度も捨てられるが、最後にとある夫婦に救われた。結局病で命を落とした金色姫は蚕となり、繭から糸を紡ぐ技術を夫婦に伝えたという。"}],"1688":[{"rank":"2","note":"釣り","exp":"240","type":"海洋生物","name":"ピラピチンガ","desc":"灰色の魚体を持つピラニアの仲間。雑食性で木の実などもよく食べるようだ。"}],"6209":[{"rank":"2","note":"例外づくめ","exp":"370","type":"中型生物","name":"スナドリネコ","desc":"東南アジア・インドの沼沢地や川沿いの森林など、水が豊富な地域に生息する猫。名前は「漁（すなど）る」に由来し、岸辺で魚を捕食する。泳ぎに長け、水に潜って魚を狙うこともある。大きさは成体でもトラの子供と変わらない。"}],"3769":[{"rank":"4","note":"古代の大彗星","exp":"610","type":"歴史遺物","name":"カエサル彗星のコイン","desc":"カエサル暗殺後に現れた彗星をかたどったコイン。カエサルの後継者オクタヴィアヌスが鋳造させた。ローマ市民はこの星を見てカエサルの魂が天に帰るのだと信じたと、スエトニウスは記している。"}],"6140":[{"rank":"1","note":"クレオパトラの息子","exp":"100","type":"歴史遺物","name":"カエサリオンの大理石像","desc":"ユリウス・カエサルとクレオパトラ7世の間に生まれた、カエサリオンの大理石像。一時はカエサルの後継者と認められたが、クレオパトラの死後、殺されたという。"}],"453":[{"rank":"2","note":"教会の宗教画の地図","exp":"215","type":"美術品","name":"洗礼者ヨハネ","desc":"レオナルド・ダ・ヴィンチ作の絵画。洗礼者ヨハネを描いている。「あの方は栄え、私は衰えなければならぬ」という言葉からくる、上を指差したポーズをとっている。不自然なような、不思議な微笑みを浮かべている…。"}],"2511":[{"rank":"4","note":"愛され尊ばれた香料","exp":"750","type":"財宝","name":"東大寺香木","desc":"東大寺正倉院に収蔵されている、極上の香木の一つ。\n正倉院には、沈香・麝香・白檀など多くの香木が収められており、香だけでなく薬としても用いられていた。"}],"479":[{"rank":"5","note":"賢者の石","exp":"1170","type":"財宝","name":"賢者の石","desc":"パラケルススがアゾートを用いて精製した、正体不明の物質。その製法は秘密とされている。錬金術では、この物質の生成に成功したら、その成果と手がかりのすべてを放棄しなくてはいけないとされている。"}],"6018":[{"rank":"5","note":"","exp":"950","type":"地理","name":"バージェス頁岩","desc":"北米大陸西部にある堆積層のひとつ。なんらかの生物の骨と思われる、奇妙な石が多数発見されている。"}],"5812":[{"rank":"3","note":"発見物カード経験：300","exp":"600","type":"海洋生物","name":"ノウサンゴ","desc":"サンゴの一種。群体が半球状となり、人間の脳のように見えることから、この名がつけられた。"}],"2060":[{"rank":"2","note":"謎に包まれた山","exp":"300","type":"地理","name":"ネムルト山","desc":"トルコ東部にそびえる標高2000mほどの山。\n頂上部には神像の彫刻が並んでいるらしい。"}],"2807":[{"rank":"1","note":"古書の地図","exp":"180","type":"財宝","name":"中秋帖","desc":"東晋時代の書家・王羲之の息子、王献之による作品。\n作品の冒頭が「中秋」で始まることから、この名で呼ばれる。\n行書を羅列した教則本である。"}],"3721":[{"rank":"5","note":"黄色の風の故郷","exp":"980","type":"地理","name":"ゴビ砂漠","desc":"モンゴルに広がる広大な砂漠地帯。\nゴビとは、モンゴル語で「乾いた土地」の意味であり、その名のとおり、乾いた風が吹きつける。"}],"823":[{"rank":"5","note":"水が嫌いなカバ","exp":"1040","type":"中型生物","name":"コビトカバ","desc":"西アフリカの限られた地域にしかいない、小さなカバ。カバの子供かと思われたが、同じ大きさの個体ばかりなので違う種類だと思われる。体色もカバよりかなり濃い。水の中にいることは少なく、森や湿地にいる。"}],"5995":[{"rank":"1","note":"ポエニ戦争の爪跡","exp":"110","type":"史跡","name":"カルタゴ遺跡","desc":"古代フェニキア人が造った都市国家の跡。第三次ポエニ戦争でローマに滅ぼされたといわれる。カエサルによって再建されたが、7世紀末に廃墟となった。"}],"5179":[{"rank":"1","note":"到達する","exp":"26","type":"港・集落","name":"ロンドン","desc":"古代ローマ人が築いた砦・ロンディニウムがもとになった街。11世紀ごろから栄え、今ではイングランドの中心地である。羊毛が豊富に取引されるほか、周辺の街の鉱物資源を背景に精錬技術の進歩が目覚ましい。"}],"6677":[{"rank":"4","note":"発見物カード:320","exp":"640","type":"天文","name":"アルフェラッツ","desc":"アンドロメダ座で最も明るい星。名はアラビア語で「馬」を意味する。別名であるシラーは「へそ」を意味し、かつてペガスス座に属し、ペガサスの腹部であったことに由来している。"}],"3927":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:140","exp":"280","type":"天文","name":"りょうけん座の親子星雲","desc":"りょうけん座にある星雲。渦巻きのような形をした、大小ふたつの星雲がつながって見える。"}],"1704":[{"rank":"5","note":"想いの行き着くところ","exp":"1248","type":"宗教遺物","name":"契約の箱","desc":"旧約聖書に登場する契約の箱とされているもの。下部の四脚や上面に乗せられた二体のケルブなど聖書の記述と一致している。だが、納められていたはずの十戒が見つからないため、真偽のほどは定かではない。"}],"7023":[{"rank":"5","note":"","exp":"","type":"植物","name":"ツチアケビ","desc":"日本の森林に分布する腐生植物。草丈は1m近くに及ぶこともある。全体は黄褐色で花は黄色。秋になると実が赤く熟し、茎も赤く変化する。乾燥させた果実は、民間薬として用いられる。"}],"2834":[{"rank":"4","note":"南海を旅した僧","exp":"650","type":"宗教遺物","name":"南海寄帰内法伝","desc":"読みは「なんかいききないほうでん」。\n唐僧・義浄が著した、インドの衣食住における戒律を伝える書物。衣の着方や飲食の決まりなどが細かく記されている。"}],"2251":[{"rank":"4","note":"白い鳥と黒い鳥<br/><br/>発見時経験値620　発見物カード経験値310","exp":"620","type":"鳥類","name":"吸血フィンチ","desc":"フィンチと呼ばれる小鳥の一種。特定の鳥の翼の付け根をつつき、流れ出る血を吸う習性がある。ガラパゴス諸島の一部の島に生息する。"}],"2563":[{"rank":"3","note":"姿の見えないイヌ","exp":"520","type":"小型生物","name":"タイワンリス","desc":"アジア全域など、広く分布する、イヌのような鳴き声で鳴くリス。前歯が鋭いため、研ぐのに用いられた木は、樹皮が削れていることが多い。\n気性が荒く、幼少期以降は単独で行動する。"}],"6125":[{"rank":"2","note":"クエスト「文献調査」<br/>発見物カード:195","exp":"390","type":"地理","name":"ハーフーン岬","desc":"アフリカ最東端に位置する岬。古代から交易拠点の一つとして栄えており、「エリュトゥラー海案内記」にもそれらしき記述が見られる。古代の遺跡が残っており、遺物が見つかることもあるという。"}],"3763":[{"rank":"5","note":"クエスト「ネクタルを飲む魚」<br/>発見物カード:475","exp":"950","type":"天文","name":"みなみのうお座","desc":"ヨーロッパでは秋の南の空に現れる星座。周りに明るい星が少ないため、魚の口にあたる1等星フォーマルハウトを目印に見つけやすい。怪物テュポンに襲われた女神アフロディテが、魚になって逃げた姿とも、うお座の親魚ともいわれる。"}],"2595":[{"rank":"2","note":"［勅命］[[献上品の産地調査","exp":"320","type":"地理","name":"金門島","desc":"かつて鄭成功の拠点となっていた島。\n貢糖と呼ばれる、砂糖とピーナッツを原料にした産物が有名。"}],"5954":[{"rank":"1","note":"黒い瞳の海獣","exp":"33","type":"中型生物","name":"アザラシ","desc":"世界中の広い海域に生息する動物。皮下脂肪が非常に厚いため、海水の冷たさに耐えられるようだ。魚をとるために海に潜り、素晴らしい速度で泳ぐ。陸上での活動は苦手だ。"}],"2542":[{"rank":"3","note":"台湾島東岸の地理調査<br/><br/>発見時経験値440　発見物カード経験値220","exp":"440","type":"地理","name":"清水断崖","desc":"台湾島の東側に連なる2000m級の高い山々からできた崖。\n延々と絶壁が続いているため、近寄る者はあまりいない。"}],"5604":[{"rank":"1","note":"「天文学者の観測記録」<br/>発見物カード:75","exp":"150","type":"天文","name":"ろ座","desc":"ラカーユが制定した星座のひとつ。フラスコを加熱する炉をモデルとしている。"}],"6498":[{"rank":"5","note":"","exp":"","type":"宗教建築","name":"バールベックの巨石","desc":"パールベックの遺跡にある巨石。遺跡はローマの神々のうち三柱を祭った3つの神殿で構成されており、そのうちの1つ、ジュピター神殿の土台となっているのが「パールベックの巨石」と呼ばれる3つの巨石である。"}],"3014":[{"rank":"4","note":"巨大な丘","exp":"640","type":"史跡","name":"カホキアの土塁","desc":"ミシシッピ川流域に住む人々が築いた、巨大な土塁。土塁の上には身分の高い人物が住んだといわれる。最大のもので、規模はおよそ縦300m、横250m、高さ30mにも及ぶ。"}],"5985":[{"rank":"1","note":"小さな空飛ぶリス","exp":"30","type":"小型生物","name":"モモンガ","desc":"頭から尾の先までが20cmあまりの、小型のリスの仲間。前足と後足の間に飛膜があり、木から木へ滑空する。黒い大きな目と長めの毛が愛らしい。"}],"1818":[{"rank":"1","note":"金細工の地図","exp":"140","type":"財宝","name":"金の器","desc":"クスコ近郊で見つかった金の器。金が豊富なこの地では、皇帝だけでなく貴族階級も、金の器や盃で食事をしていたという。さすがに一般階級ではそういうことはなさそうだが。"}],"6044":[{"rank":"2","note":"カード経験80","exp":"190","type":"財宝","name":"ペスト哀歌","desc":"モスル地方の北部に在住していた司祭によって記された詩。原典はアラム語で248編にわたって書かれている。全体を通してペストが人々を蹂躙する様子を嘆く内容だが、当時実際に流行していたのはコレラであったという説もある。"}],"5270":[{"rank":"2","note":"マヤ低地　再調査報酬","exp":"380","type":"歴史遺物","name":"パカル王のレリーフ","desc":"パレンケ王パカルが描かれたレリーフ。母サク・クックから王冠を受け取る姿を表す。わずか12歳で即位したパカル王は周囲の期待に応え、当時危機に瀕していたパレンケを見事に復興させた。"}],"2773":[{"rank":"2","note":"ダンジョン","exp":"330","type":"宗教遺物","name":"カタコンベの石版","desc":"カタコンベの奥深くで見つかった謎の石版。文字が刻まれているようだが、表面の傷みが激しいため、解読は不可能なようだ。"}],"536":[{"rank":"1","note":"古代の道具の地図","exp":"11","type":"歴史遺物","name":"青銅器の破片","desc":"古代の青銅器の破片。青銅は扱いやすいので古代からよく用いられた。"}],"6364":[{"rank":"1","note":"","exp":"150","type":"植物","name":"アスチルベ","desc":"主にアジアで咲く花。多年生植物で初夏に開花する。茎に沿ってふわふわとした花穂を咲かせる。花の色は赤、ピンク、白など。寒さに強く、湿った土で育ちやすい。"}],"6989":[{"rank":"5","note":"","exp":"","type":"財宝","name":"医心方の写本","desc":"全三十巻からなる日本最古の医学書の写本。読み方は「いしんぽう」。原本は平安時代に朝廷の典薬頭を務めた医師、丹波康頼により編纂された。唐以前の医学書の引用を主として構成されており、史料としての価値も非常に高い。"}],"959":[{"rank":"1","note":"宝石を削りだした器","exp":"115","type":"美術品","name":"船形器","desc":"ラピスラズリを削りだして作った器に、金やエマイユで装飾した調度品。石の削り出しはイタリアでなされたものだが、金属部分は何度も手直しされているようだ。"}],"470":[{"rank":"2","note":"穴を掘る動物の地図","exp":"210","type":"中型生物","name":"ツチブタ","desc":"細長い顔と長い耳にずんぐりした体の動物。動きは緩慢だが穴を掘るのは非常に素早い。舌がとても長く、これでアリを食べているようだ。"}],"2872":[{"rank":"2","note":"黄公望の弟子","exp":"350","type":"美術品","name":"王蒙の風景画","desc":"元代の画家・王蒙が描いた絵画。うねるようにそそり立つ山々が、緻密かつ壮大に表現されており、見る者を圧倒する。"}],"1209":[{"rank":"5","note":"ジャガーの瞳","exp":"1014","type":"財宝","name":"ジャガーの瞳","desc":"全てを闇に吸い込んでしまいそうな漆黒の宝石。正体は、非常に深い色合いの黒曜石だ。メソアメリカの人々はこれを「ジャガーの双眸」だといって恐れていた。"}],"643":[{"rank":"1","note":"書きかけの地図","exp":"120","type":"地理","name":"オレンジ川","desc":"アフリカ南部を東西に流れる大河。流域には豊富な鉱脈があると思われるが、途中に大きな滝があって水運は難しそうだ。"}],"3319":[{"rank":"2","note":"書きかけの地図","exp":"250","type":"地理","name":"ルイス島","desc":"ブリテン島北部。西側にある島。近辺の島の中では最大の面積を誇る。南部は別の名前でも呼ばれている。島には巨大な岩や石を使った史跡が残されているという。"}],"5289":[{"rank":"3","note":"","exp":"490","type":"小型生物","name":"ヒガシグリーンマンバ","desc":"アフリカ南東部に生息するヘビ。体が細長く、3mを超える個体もいるという。体の色は明るい緑で、常緑樹にいることが多い。ブラックマンバに比べるとおとなしく、毒も弱いが、それでもかなりの猛毒を持つ。"}],"1222":[{"rank":"2","note":"マヤの芸術","exp":"270","type":"歴史遺物","name":"ひすいの装飾花瓶","desc":"ひすいで作られた豪華な花瓶。外面中腹には陶器の装飾がついている。これだけ手の込んだ花瓶であれば、貴族の持ち物と思っていいだろう。"}],"745":[{"rank":"2","note":"聖母子像","exp":"230","type":"美術品","name":"聖母子像","desc":"作者不詳の木像。シナノキで作られた聖母子像である。かつて南ドイツの教会にあったと伝えられる。聖母は足の下に三日月を踏んでおり、黙示録の「太陽をまとい、月を踏みしく」と表される女を指していると思われる。"}],"5465":[{"rank":"1","note":"経験　:120<br/>カード:60","exp":"120","type":"海洋生物","name":"トゥクナレ","desc":"アマゾン川や、その支流で生息する魚。\n尾びれの付け根にある目玉模様からピーコックバスとも呼ばれる。\n現地では食用としてよく利用されている。"}],"5738":[{"rank":"2","note":"2017.02.07新規追加","exp":"270","type":"海洋生物","name":"ゴロミャンカ","desc":"バイカル湖に生息する深海魚ならぬ深湖魚。ウロコや浮袋を持たないが、その豊富な脂肪分によって浮くことができる。"}],"4803":[{"rank":"2","note":"岩窟遺跡の調査","exp":"260","type":"史跡","name":"クリフ・パレス","desc":"北米の先住民であるアナサジ族が築いたとみられる集落の跡。巨大な岸壁をくり抜いて造られている。"}],"1876":[{"rank":"1","note":"古代の防具の地図","exp":"140","type":"歴史遺物","name":"黄金の胸当て","desc":"カルタゴ軍がローマ軍との戦いで戦利品として得たと思われる胸当て。当時のローマ兵は精鋭でも青銅の武具しか与えられなかったので、さぞかし位の高い人物が身に着けたものだろう。"}],"122":[{"rank":"1","note":"ギリシャ火","exp":"80","type":"歴史遺物","name":"ギリシャ火","desc":"7世紀ごろ、ビザンツ帝国で使用された火炎剤。石油に硫黄や松脂を混ぜたもので、激しく発火し水では消せない火が生じるという。もともとは東方から伝わったものだそうだ。"}],"6369":[{"rank":"2","note":"","exp":"270","type":"気象・現象","name":"霧氷","desc":"濃霧が樹木などに付着して凍りつく現象。冬の山でよく見られ、凍り方によって「樹氷」「粗氷」「樹霜」などと呼び分けられる。空気を多く含んでいるため白く、触れると簡単に壊れるほどもろい。"}],"678":[{"rank":"5","note":"信じられない速度","exp":"828","type":"大型生物","name":"チーター","desc":"細長い体の猛獣。体の柔軟性が非常に高く、全速力で走ると馬などよりもずっと速い。狩りのしかたは、そっと近よってから一気に襲う。ヒョウと少し似ているが、木には登らないようだ。"}],"5309":[{"rank":"4","note":"","exp":"770","type":"小型生物","name":"リンカルス","desc":"アフリカ南部に生息するヘビ。毒を持つ上、危険を感じると敵の目に向けて毒液を吐いて飛ばす習性がある。死んだふりを得意とするため、無用心に近づくのは危険だろう。"}],"6690":[{"rank":"","note":"「天文学者の観測地図」<br/>発見物カード:190","exp":"380","type":"天文","name":"テーブルさん座","desc":"南天にある星座。おもに南半球で見ることができる。フランスの天文学者ラカーユがケープタウンのテーブル山をモチーフとして、星座の名前として設定した。"}],"1525":[{"rank":"1","note":"十字軍時代の騎士団","exp":"100","type":"財宝","name":"ヨハネ騎士団長の盾","desc":"ヨハネ騎士団は、十字軍の時代に傷病者を看護する目的で創設された。紋章は八角白十字である。現在も地中海で活動を続けている。"}],"5113":[{"rank":"1","note":"到達する","exp":"13","type":"港・集落","name":"バルセロナ","desc":"古代ローマ時代から、地中海貿易の拠点として栄えた街。製鉄技術が発達しており、大砲や銃が作られている。火器に関係する交易品が多く取引されているが、皮革製品の加工技術も有名である。"}],"5037":[{"rank":"1","note":"到達する","exp":"27","type":"港・集落","name":"カリアリ","desc":"サルデーニャ島の南部にある街。地理的に多くの勢力の争いに巻き込まれやすく、支配勢力が次々に変わった。その結果、さまざまな文化が共存する街となった。"}],"1920":[{"rank":"2","note":"釣り","exp":"340","type":"海洋生物","name":"アマゾン淡水エイ","desc":"アマゾン川に生息する小型の淡水エイ。尾には毒棘を持つ。"}],"510":[{"rank":"1","note":"古代の貨幣の地図","exp":"13","type":"歴史遺物","name":"貝貨","desc":"貨幣として扱われた、タカラガイなどの殻。古代文明の多くで使われ、各地の遺跡から出土する。"}],"6431":[{"rank":"2","note":"","exp":"280","type":"歴史遺物","name":"ガリレオの軍事コンパス","desc":"ガリレオ・ガリレイが発明した、あらゆる内径の大砲と砲弾に対して火薬量を決定できる計算機。種々の計算、分度器、天体観測などに使用できたと言われる。パドヴァ大学教授時代のガリレオはこのコンパスで収入を得ていたという。"}],"6147":[{"rank":"4","note":"","exp":"680","type":"植物","name":"サギソウ","desc":"日本など極東アジアに生息する植物で、谷などの低めの湿地に群生しやすい。\n花の開いた様子がシラサギが翼を広げたように見えるため、この名で呼ばれる。"}],"2013":[{"rank":"2","note":"クエスト「インカにそびえる石の壁」<br/>発見物カード:180","exp":"360","type":"歴史遺物","name":"インカの石壁","desc":"滑らかで、美しい形の石。これだけの大きさのものとなると、積み重ねや運搬の問題が出てくるだろうが、この石は規則正しく積み重ねられ、寸分の隙間も見られない。一体どうやって作り上げられたのだろう…。"}],"720":[{"rank":"1","note":"清楚な絵","exp":"100","type":"美術品","name":"受胎告知（アンジェリコ）","desc":"フラ・アンジェリコ作の祭壇画。鮮やかな色彩で描かれたこの絵は作者の敬虔な信仰心を如実に表している。アンジェリコの名は通称で、穏やかな修道僧であった彼を「天使のようだ」と表現したものだそうだ。"}],"3744":[{"rank":"1","note":"クエスト「星空の導き手」<br/>発見物カード:60","exp":"120","type":"天文","name":"北極星","desc":"こぐま座で最も明るい星で、天の北極にある2等星。ポラリスとも呼ばれる。周囲に明るい星がなく見つけやすい。ほとんど動かないように見えるため、北半球では夜間に方位を知るうえで重要な星である。"}],"6549":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"ユークリッド原論","desc":"アレクサンドリアの数学者であるエウクレイデス(ユークリッド)が紀元前3世紀ごろに編纂した数学書。別称は「幾何学原論」。ピタゴラスなどの先人と自らの数学理論をまとめた書物で、後世の数学理論における基礎となった。"}],"6497":[{"rank":"5","note":"","exp":"990","type":"化石","name":"大きな頭の魚の化石","desc":"大きさこそ違うが、強靭な顎を持つ巨大な生物の頭骨と同じ特徴を持った魚の化石。重厚な頭骨と異なり体の骨はもろく、死後の化石などでは頭骨のみ残っていることが多い。"}],"6888":[{"rank":"3","note":"発見物カード:280","exp":"560","type":"中型生物","name":"変色したシャムネコ","desc":"寒さで一部の毛色が濃くなったシャムネコ。熱帯気候のシャム原産のため、寒さに弱く、顔や耳、尻尾、手足など体温が下がりやすい部位の毛色は、温度が低いと濃くなるという特徴がある。"}],"1337":[{"rank":"2","note":"スマトラ南東の島","exp":"220","type":"地理","name":"ジャワ島","desc":"スマトラ島の南東に位置する島。東西に細長い地形になっている。山がちで、多くの火山を有している。古くから仏教とヒンドゥー教が広まっていたが、近年はイスラム教が拡大しているようだ。"}],"331":[{"rank":"5","note":"ロンギヌスの槍","exp":"1040","type":"宗教遺物","name":"ロンギヌスの槍","desc":"イエスがゴルゴタの丘で処刑された際に、死亡を確認するために突き刺されたという槍。ロンギヌスというのは刺した兵士の名。本物かどうか、証明する手立てはない。"}],"1115":[{"rank":"4","note":"白いコート","exp":"648","type":"中型生物","name":"ホッキョクギツネ","desc":"鼻を除いた体全体が密な毛で覆われている。ホッキョクギツネには二つの毛色があり、冬毛は雪や氷に溶け込むような純白、夏毛は冬の厚さの半分で灰色をしている。"}],"1123":[{"rank":"3","note":"動植物の楽園","exp":"533","type":"地理","name":"アマゾン川","desc":"南米大陸を横断する大河。流域には広大な森林が広がっていて、動植物の楽園となっている。そこは、航海者の心をかき立てる未知の領域といえよう。"}],"3887":[{"rank":"5","note":"紅の滝","exp":"1170","type":"地理","name":"ホーステールフォール","desc":"北米南西部に位置する滝。冬から早春の間のみ、水が流れる。ごく稀に、夕日に照らされた滝の水がマグマのように赤く見えることがある。"}],"1824":[{"rank":"2","note":"七色の財宝","exp":"290","type":"財宝","name":"貝の耳飾り","desc":"アンデス文明中期のもの。貝や鉱石を砕いてモザイク画にし、それを木の枠組みに埋め込んで作っている。素朴で美しいこの細工は他の地方でも人気があったのか、あちこちで見受けられる。何らかの手段で流通していったのだろう。"}],"6422":[{"rank":"4","note":"","exp":"","type":"大型生物","name":"獰猛なグリズリー","desc":"心のない人間によって見世物にされていた大型のクマ。獰猛な姿をしているという。しかし、クマは逃げ出してしまった。いつ街に戻り、人々を襲いはじめてもおかしくないだろう。"}],"765":[{"rank":"1","note":"赤い花の地図","exp":"49","type":"植物","name":"チューリップ","desc":"つぼのような花が咲く植物。赤や黄色などさまざまな色がある。球根で増える。最近人気が出てきており、品種改良も行われている。"}],"941":[{"rank":"5","note":"クエスト「百獣の王」<br/>発見物カード:520","exp":"1040","type":"大型生物","name":"ライオン","desc":"百獣の王として有名な大型の猛獣。オスは、顔のまわりから首にかけて豊かなたてがみがおおっている。十数頭の群れで生活するが、一つの群れにオスは1頭しかいない。狩りは主にメスがやるといわれている。"}],"5308":[{"rank":"2","note":"","exp":"280","type":"大型生物","name":"シロオリックス","desc":"サハラ周辺に生息し、後ろに反った長い角が特徴の草食動物。大きな群れで季節ごとに南北に移動する。乾燥に強く、水を飲まなくても長期間生き続けられるが、水が豊富であればよく飲むという。"}],"2826":[{"rank":"4","note":"ダンジョン","exp":"740","type":"財宝","name":"辟邪像","desc":"読みは、「へきじゃぞう」。魔除けに使われる獣像。重慶の遺跡で発見された。\n辟邪とは、悪霊を追い払うと信じられた伝説上の獣のこと。"}],"583":[{"rank":"1","note":"豪華な宝石細工の地図","exp":"18","type":"財宝","name":"壊れたブローチ","desc":"壊れているブローチ。宝石のいくつかがはずれ、留め金も壊れている。壊れる前はさぞかし素晴らしい物だったのだろう。"}],"1447":[{"rank":"4","note":"最強のモグラ","exp":"636","type":"中型生物","name":"ウォンバット","desc":"地中に掘った穴をすみかとする有袋類。土が入らないように袋は後ろ向きについている。力が強く、ときに捕食者を殺すこともある。"}],"1866":[{"rank":"2","note":"神をかたどった仮面<br/><br/>発見時経験値320　発見物カード経験値160","exp":"320","type":"歴史遺物","name":"銅製の仮面","desc":"南米の文化では金や銀の装飾がよく見られるが、それよりもさらに古くから銅は用いられていた。こういった仮面は王の持物、もしくは副葬品が主なことから、銅の価値が高かったことがうかがえる。"}],"6354":[{"rank":"","note":"トレジャーハント「古地図にまつわる伝承」","exp":"","type":"レリック","name":"灼熱の大灯皿","desc":"ロードス島の巨像が持つ巨大な炎の器。港に不当に進入する船には、この器から燃え盛る炎が降り注がれたという。"}],"1551":[{"rank":"1","note":"書きかけの地図","exp":"135","type":"地理","name":"タスマン海","desc":"オーストラリアの南東に横たわる海。付近には暖流が流れているため、沿岸の気温は暖かく過ごしやすいが、暴風地帯でもある。"}],"5713":[{"rank":"2","note":"地図上の北部にいると南東方向とでるが、実際は南西の先っちょで視認","exp":"270","type":"気象・現象","name":"紅雪","desc":"雪や氷が赤く色付く現象。この現象に言及した記録は古くから存在するが、その原因などについて確たる情報はない。一説には酸化物が関係しているとされている。"}],"913":[{"rank":"5","note":"白き神の使い","exp":"1209","type":"大型生物","name":"ホワイトタイガー","desc":"黒い縞模様を除いた部分が真っ白な毛で覆われていて、鼻と唇はピンク色、瞳は澄んだ青をしている。インドでは「神の使い」として信じられている。"}],"5307":[{"rank":"2","note":"","exp":"280","type":"小型生物","name":"サバクトゲオアガマ","desc":"サハラに棲む草食のトカゲ。全長が40cmを超えるものもいる。トゲのある鱗に覆われた太い尾を持ち、身を守る際にはこの尾で攻撃することがある。昼間に活動するが、あまり暑さが厳しいと穴に隠れてしまうようだ。"}],"160":[{"rank":"1","note":"サラマンダーを捕まえろ<br/>希少発見物らしいです。<br/>体験版では、「サラマンダーを捕まえろ」<br/>の紹介を受けれませんでした。","exp":"80","type":"小型生物","name":"マダラサラマンドラ","desc":"黒い体にオレンジの模様があるイモリ。炎がちらついている模様に見えないこともない。ヨーロッパでも似たイモリを見かけるが、まだらが黄色い。"}],"3012":[{"rank":"3","note":"顔をかたどるつぼ","exp":"540","type":"歴史遺物","name":"ヘッドポット","desc":"北米のミシシッピ川付近で発見された人間の顔をかたどったつぼ。様々な表情のものがあるが、そのほとんどが顔に刺青のような文様が刻まれ、耳には穴が開けられている。"}],"1518":[{"rank":"2","note":"大陸北西岸の基礎調査","exp":"340","type":"地理","name":"キンバリー台地","desc":"オーストラリア北西部にある台地。内陸は渓谷や切り立った山々になっており、海岸線も複雑である。"}],"5133":[{"rank":"1","note":"到達する","exp":"13","type":"港・集落","name":"ブレーメン","desc":"ヴェーゼル川河口に位置する港湾都市。9世紀に大司教座の街として興った。14世紀ごろにはハンザ同盟都市となり、商業都市として繁栄した。"}],"5929":[{"rank":"2","note":"","exp":"","type":"史跡","name":"プラハのオルロイ","desc":"神聖ローマ帝国の古都プラハで造られた天文時計。当時の天文学者たちの間で使用されていた天体測定機器（アストロラーベ）の機能と時計としての機能を併せ持っており、時間だけでなく太陽や月の位置までわかる。"}],"1493":[{"rank":"5","note":"森の悪魔","exp":"949","type":"中型生物","name":"クズリ","desc":"ずんぐりとした大きな体を持つ。強靭なあごは、凍った肉や骨も噛み砕くことができる。やわらかい雪の上でも沈むことなく素早い動きができる。"}],"6060":[{"rank":"1","note":"到達する","exp":"78","type":"港・集落","name":"イニャンバネ","desc":"アフリカの東海岸で古くから栄えた都市の一つ。かつては綿の一大産地だったが、象牙などの取引の拠点として発展した。温暖な気候で、カシューナッツをはじめ様々な作物が作られている。"}],"5151":[{"rank":"1","note":"到達する","exp":"129","type":"港・集落","name":"マスカット","desc":"ペルシャ湾とアラビア海の間に位置する街。古代から重要な港で、交易の中心地として栄え続けてきた。この地方独特の農産物のほかに、鉱石や武器も流通している。"}],"3897":[{"rank":"2","note":"クエスト「猟犬の伝説」<br/>発見物カード:120","exp":"240","type":"天文","name":"おおいぬ座","desc":"どんな獲物をも捕まえる運命と定められた猟犬ライラプスが空に上げられた姿とされる。誰にも捕まらない運命を持った狐を追ったライラプスは、大神ゼウスによって石に変えられ、天にあげられたといわれる。"}],"6128":[{"rank":"5","note":"","exp":"1100","type":"宗教遺物","name":"天国への階梯","desc":"7世紀の東ローマの修道士ヨアンネス・クリマコスが著した、修道士向けの教導書。「クリマコス」はギリシャ語ではしごを意味し、書名の「階梯」に由来した添え名。修道者としての心構えを三十段の階梯に見立てて説いている。"}],"548":[{"rank":"2","note":"古代ペルシャの大宮殿","exp":"220","type":"史跡","name":"ペルセポリス遺跡","desc":"アケメネス朝ペルシャのダレイオス1世が着工した、ペルシャの大宮殿跡。広大な敷地に多数の石柱や独特の石像、すばらしいレリーフが残る。"}],"5931":[{"rank":"2","note":"","exp":"","type":"地理","name":"サグレスの岩崖","desc":"「航海者の村」と呼ばれるサグレスの近くに位置し、ユーラシア大陸の最南西端にあたるサンヴィセンテ岬にも近い。サグレス岬を含んだこの一帯は地中海を往復する船乗りたちの間で海路の目印とされている。"}],"1603":[{"rank":"1","note":"魚の石の地図","exp":"105","type":"化石","name":"大きな魚のような石","desc":"魚によく似た形の石。ひれのようなものが確認できるが、どこか現在の魚とは違った印象を受ける。これが生きていた時代、魚はみなこのような形をしていたのだろうか。"}],"6345":[{"rank":"2","note":"","exp":"270","type":"地理","name":"ダマーヴァンド山","desc":"アジア最高峰の火山。美しい峰を持つ火山であることから、火を尊ぶゾロアスター教の聖典に登場し、山の地下深くに三頭竜アジ・ダハーカを幽閉したとされている。"}],"1872":[{"rank":"4","note":"合理的統治戦略","exp":"720","type":"歴史遺物","name":"歴代酋長の衣服","desc":"南米大陸に数多く存在している部族のうち、ある部族の酋長が酋長に就任する際に着る衣服だという。インカ帝国は広大な土地を治めたが、征服地域に統治機能が残っていれば自治を認めたため、部族の特色は失われにくかった。"}],"1311":[{"rank":"1","note":"書きかけの地図","exp":"90","type":"地理","name":"サンマティアス湾","desc":"南米南東岸にある湾。付近を流れる海流は寒流で、比較的寒い地域にあたる。北部には、水が黒い不思議な川が流れている。"}],"3291":[{"rank":"3","note":"巡礼前の下調べ","exp":"500","type":"地理","name":"スケリッグ・マイケル","desc":"アイルランドから西の沖合いにある孤島。\nアイルランドの言葉で「ミカエルの岩」を意味する。島自体が傾斜の激しい岩山であり、山頂付近には修道院がある。過去、ヴァイキングの襲来にも耐えたという。"}],"3774":[{"rank":"4","note":"天に輝く羊","exp":"790","type":"天文","name":"おひつじ座","desc":"黄道十二星座の1つ。ボイオティア王の子、プリクソスとヘレを救うためにゼウスが遣わした黄毛の牡羊が天に昇った姿とされる。後にその毛皮を求めてイアソンがアルゴ船で探検に出た。"}],"5116":[{"rank":"2","note":"到達する","exp":"323","type":"港・集落","name":"バンジェルマシン","desc":"カリマンタン島南岸の港。14世紀にはマジャパヒト王国の支配を受ける。現在はイスラム教の影響下にある。郊外には先住民のダヤク民族が住んでいる。"}],"6659":[{"rank":"5","note":"追究クエスト<br/>発見物カード:750","exp":"1500","type":"大型生物","name":"シベリアビッグホーン","desc":"シベリア北東部に生息する野生のヒツジ。別名ユキヒツジ。後ろへ大きく湾曲した双角が特徴。標高の高い山岳地帯に棲む。蹄の底が特殊な形状をしており断崖絶壁を一気に駆けられる。"}],"5136":[{"rank":"1","note":"到達する","exp":"43","type":"港・集落","name":"ベイルート","desc":"非常に古い時代から栄えていた街。内陸の都市の港として重要な街である。特に、ダマスカスから運ばれてくるダマスク織とダマスカスソードは、世界的に高く評価されている。"}],"1963":[{"rank":"2","note":"戦士の証<br/><br/>発見時経験値330　発見物カード経験値165","exp":"330","type":"財宝","name":"インカ戦士の棍棒","desc":"インカ戦士の一般的な武器。持ち手には彩色された家畜の毛が巻きつけられ、先端には石がくくりつけられている。"}],"1793":[{"rank":"5","note":"クエスト「それは皇帝の山」<br/>発見物カード:520","exp":"1040","type":"地理","name":"ポトシ銀山","desc":"膨大な埋蔵量を誇る銀山ではあるが、アンデス山脈の一角にあり、周囲には4000m級の山々が連なっている。そのため銀の採掘輸送は不可能に近いだろう。"}],"1801":[{"rank":"1","note":"書きかけの地図","exp":"160","type":"地理","name":"テワンテペク湾","desc":"中米のテワンテペク地峡南部に広がる湾。この沿岸では、古代から多くの文明が栄えたという。"}],"711":[{"rank":"1","note":"水に入らないカメ","exp":"180","type":"中型生物","name":"ホシガメ","desc":"インドを中心に生息するリクガメ。草食性でなぜか赤い植物を特に好むようだ。甲羅に放射状の模様があり、大変美しい。"}],"1845":[{"rank":"2","note":"イスラム世界が描かれた家具","exp":"330","type":"財宝","name":"アラビアの家具","desc":"幾何学模様や花柄模様のアラベスクがびっしりと施された、最高級の調度家具。クッション部分の中綿も外生地も最高級品で、イスラム文化の高度な工芸技術を感じることができる。"}],"1238":[{"rank":"2","note":"小さなヴェネツィア","exp":"380","type":"地理","name":"マラカイボ湖","desc":"ベネズエラ湾の奥にある湖。湖の周辺では杭の上に建てられた家屋が見られる。湖の沿岸には、近年イスパニア人によって建てられた街がある。"}],"6493":[{"rank":"5","note":"レガシー　女神信仰のエフェソス　左下","exp":"","type":"宗教遺物","name":"玉座のキュベレ女神像","desc":"古代アナトリアの女神キュベレの座像。キュベレはフリュギアで崇拝された大地母神で、古代ギリシャやローマでも信仰された。城壁を模した冠をかぶり獣を従えた姿は、エフェソスのアルテミス神像との関連を思わせる。"}],"1777":[{"rank":"2","note":"［勅命］[[黄金郷の信仰","exp":"310","type":"宗教遺物","name":"神官の首飾り","desc":"神官のみが着けることを許されるという首飾り。細工が細かく、美術的価値も高いが、信仰的要素が大きい。"}],"6652":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:140","exp":"280","type":"天文","name":"こじし座","desc":"小さなライオンの姿を表した星座。しし座の頭と、おおぐま座の足下にはさまれた位置にある。暗い星で形成されており、あまり目立たない。ドイツの天文学者・ケプラーが設定した。"}],"5942":[{"rank":"4","note":"","exp":"740","type":"宗教建築","name":"バターリャ修道院","desc":"正式名称は「勝利の聖母マリア修道院」カスティーリャ王国との戦勝記念に建てたられため「バターリャ（の戦い）」の名前で呼ばれる。数世紀にわたって建築が続けられ、その間にヨーロッパ各地で流行した多くの建築様式が取り入れられた。"}],"2734":[{"rank":"3","note":"新羅遺物調査協力","exp":"500","type":"歴史遺物","name":"彩色樹皮の馬具","desc":"白樺の皮で作られた、馬に装着する泥除け。よく見るとなにか描かれた形跡がある。おそらく鮮やかに彩色されていたのだろう。"}],"747":[{"rank":"1","note":"西ローマを滅ぼした者","exp":"95","type":"歴史遺物","name":"オドアケルの剣","desc":"オドアケルは、西ローマ帝国を滅ぼした、ゲルマン出身の将軍。西ローマの傭兵隊長であったが、西ローマ皇帝を追放してイタリア王を自称した。"}],"2315":[{"rank":"2","note":"［勅命］[[島国にある山の調査","exp":"270","type":"地理","name":"紀伊山地","desc":"日本の紀伊地方に存在する霊場及びその山々の総称。\n地形が険しいため、山岳仏教や修験道（しゅげんどう）を信仰する僧侶の修行の場として栄えている。"}],"6052":[{"rank":"2","note":"","exp":"","type":"宗教遺物","name":"正教勝利のイコン","desc":"ビザンツ帝国で激化した聖像破壊運動が終わるきっかけとなった、第七全地公会（第2ニカイア公会議）の決定を記念するイコン。正教会では大斎期間（復活祭の前の四十日間）最初の日曜に祈念するようになったという。"}],"3868":[{"rank":"1","note":"小型のクジラの地図","exp":"190","type":"海洋生物","name":"ミンククジラ","desc":"赤道よりも北の海で生息する小型のクジラ。外洋で生活し、広範囲を回遊する。"}],"5996":[{"rank":"1","note":"バレアレス諸島西部の調査","exp":"20","type":"地理","name":"イビサ島","desc":"バレアレス諸島の西部の島。古代から人が住み、アフリカとイスパニア間の中継点となっていた。青い空と海が美しい島である。"}],"2799":[{"rank":"1","note":"不気味な形の骨の調査","exp":"200","type":"化石","name":"カメのようなドラゴンの骨","desc":"カメのような体格をした生物の骨で、泉州近辺で見つかった。\n腹部が大きく膨れており、甲羅を背負っているように見える。"}],"3632":[{"rank":"2","note":"豪華な壁の地図","exp":"380","type":"美術品","name":"イコノスタシス","desc":"イコンで覆われた壁。聖堂内の各所に配置される。\n配置される位置によって、イコンに描かれる絵柄も異なる。"}],"1977":[{"rank":"1","note":"ネズミに似た動物の地図","exp":"135","type":"小型生物","name":"バンディクート","desc":"ネズミのような外見で長い鼻を持つ有袋類。夜行性で、昆虫を捕食する。"}],"6435":[{"rank":"5","note":"レガシー　数の叡智・世界の計算機　下","exp":"","type":"歴史遺物","name":"黒と赤の算木","desc":"算盤（そろばん）普及前に東アジア全域で使われていた。木片を並べて計算する器具。中世日本では、正の数を表す赤色と負の数を表す黒色の二色の算木を用いた。格子が描かれた布や板製の算盤（さんばん）上に並べて計算した。"}],"4977":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:160","exp":"320","type":"天文","name":"うみへび座の渦巻星雲","desc":"うみへび座のやや南にある渦巻星雲。周辺はかすかだが、中央部が明るく、三本の腕の伸びている。"}],"905":[{"rank":"1","note":"白い花の地図","exp":"51","type":"植物","name":"アイリス","desc":"紫や青紫の豪華な花が咲く植物。園芸種に適していると思われる。"}],"5338":[{"rank":"2","note":"大きな島の地図","exp":"","type":"地理","name":"トリニダード島","desc":"南米大陸の北に浮かぶ島。南側にサーペントス・マウス、北側にドラゴンズ・マウスと呼ばれる海峡があり、熱帯の自然の美しさが感じられる島である。"}],"5368":[{"rank":"4","note":"ギリシャとエジプトの神","exp":"660","type":"宗教遺物","name":"セラピス像","desc":"セラピスはギリシャ神とエジプト神を習合した神。プトレマイオス朝エジプトやローマ帝国で広く信仰された。頭には計量用のカップを乗せている。"}],"6909":[{"rank":"4","note":"","exp":"","type":"虫類","name":"アズチグモの雄","desc":"雄のアズチグモ。体長は約3mmと、雌と比べるとかなり小さい。褐色の体は、雌と異なり周囲の環境に合わせて変色することはない。雌に捕食されないよう腹部背面に乗る姿が見られる。"}],"5034":[{"rank":"1","note":"到達する","exp":"26","type":"港・集落","name":"カサブランカ","desc":"アフリカ大陸の北西に位置する小都市。かつてはベルベル人の王朝があり、交易都市として非常に栄えていた。15世紀中ごろ、ポルトガルによって破壊されたため、そのころの面影は残っていない。"}],"20":[{"rank":"4","note":"アフリカにしかいない小鳥","exp":"756","type":"鳥類","name":"テンニンチョウ","desc":"オスが長い尾を持つ、アフリカの小鳥。尾が長くなるのは繁殖期だけのようだ。オスは羽が白と黒、くちばしが赤と目立つ色だが、メスは茶色で地味だ。オスはメスの気を引くため、メスのまわりで独特の飛び方をする。"}],"5456":[{"rank":"3","note":"","exp":"540","type":"海洋生物","name":"デンキウナギ","desc":"強力な電気を起こせる魚。体から電気を放出し、小魚などを捕食する。南米北部に生息しており、この水域では食物連鎖の頂点に位置する生物の一つになっている。"}],"523":[{"rank":"1","note":"古代の集落の地図","exp":"52","type":"歴史遺物","name":"古代の敷物","desc":"古代文明で使われていた敷物。動物の毛や麻などで織られている。"}],"1960":[{"rank":"5","note":"仏教における聖遺物","exp":"1027","type":"宗教遺物","name":"仏舎利","desc":"「ぶっしゃり」。仏教の開祖である釈迦（しゃか）の遺灰だと伝えられるもの。仏教における最高の聖遺物である。語源はサンスクリット語で「身体」を意味する「シャリーラ」である。"}],"6412":[{"rank":"4","note":"追究クエスト　発見物カード：370","exp":"740","type":"史跡","name":"冥王の門","desc":"アポロン神殿の近くにある洞窟。「死の息」が吐き出され、中に入るものの命を奪うことから「冥王の門」や「地獄の門」と呼ばれる。足を踏み入れるとだんだんと苦しくなり、めまいがしてくるという。"}],"5076":[{"rank":"2","note":"到達する","exp":"350","type":"港・集落","name":"ジャンビ","desc":"スマトラ島の中央部に位置する、ジャンビ人の街。熱帯雨林に覆われ、林業が盛ん。イスラムの影響を強く受けているが、郊外には仏教の建物も見られ、歴史や文化が混在している。"}],"310":[{"rank":"3","note":"ライオン・ハーティド","exp":"528","type":"財宝","name":"獅子心王の甲冑","desc":"「しししんおうのかっちゅう」。獅子心王とは、プランタジネット朝イングランド王のリチャード1世のこと。第3回十字軍に従軍した際に身につけていた甲冑だという。"}],"259":[{"rank":"3","note":"ヒンドゥーの最高神","exp":"484","type":"宗教遺物","name":"ブラフマー像","desc":"ヒンドゥー教における最高神の像。このブラフマーは創造神であるとされ、三大神の一人である。しかし、ほかのシヴァとヴィシュヌに比べるとあまり信仰の対象とはなっていないという話だ。"}],"5792":[{"rank":"5","note":"聖女の遺体","exp":"1410","type":"宗教遺物","name":"聖エウフェミアの棺","desc":"聖エウフェミアの遺体が収められた棺。彼女は過酷な拷問にかけられたが、最期まで信仰を捨てず、自らの苦難と殉教を神に祈ったと伝えられている。"}],"34":[{"rank":"1","note":"アラビアの動物の地図","exp":"96","type":"中型生物","name":"アラビアオリックス","desc":"長い角を持つ、ウシのような動物。砂漠地帯に住む。それほど大型ではない。地面に穴を掘って座っている姿をよく見かける。おそらく体温を調整しているのだろう。"}],"2806":[{"rank":"1","note":"円形の楽器の地図","exp":"140","type":"財宝","name":"阮","desc":"読みは「げん」。漢代に製作されたと思われる楽器。\n竹林の七賢の一人・阮咸が愛用したことから武則天が阮咸と名付けた。現在では阮と呼ばれているようだ。"}],"2863":[{"rank":"5","note":"地震の多い地域","exp":"980","type":"歴史遺物","name":"感震計","desc":"後漢時代の発明家・張衡が発明した銅で作られた感震計。揺れを感じると、震源地と反対側の玉が落ちるようになっている。1000kmほど離れた場所で発生した地震も感知できたようだ。"}],"5416":[{"rank":"2","note":"","exp":"","type":"植物","name":"アサイー","desc":"南米に生息するヤシ科の植物。青紫色の小さな果実を枝に多くつける。果実は非常に栄養価が高く、現地では栄養食としても利用されているようだ。"}],"3732":[{"rank":"4","note":"ダンジョン","exp":"610","type":"財宝","name":"ラムセス2世の強弓","desc":"古代エジプトのファラオ・ラムセス2世が使用したとされる弓。常人では引けないほど強く弓が張られているため、武器としては扱えないようだ。"}],"4953":[{"rank":"2","note":"おしゃれなテーブルクロス<br/><br/>発見時経験値370　発見物カード経験値185","exp":"370","type":"財宝","name":"レフカラレース","desc":"キプロス島のレフカラ村で作られた、麻布のレース。レフカラの文化とヴェネツィアの技術が融合して、素朴でありながら上品なデザインとなっている。"}],"5782":[{"rank":"5","note":"書記官の石版","exp":"1380","type":"宗教遺物","name":"運命の石板","desc":"メソポタミア神話において、神々の書記官ナブーが所持する石版。人類の運命が刻まれているとされている。それにしては小さく見えるが、やはり人間に理解できるようなものではないのだろう。"}],"5859":[{"rank":"5","note":"","exp":"1370","type":"美術品","name":"レーマンの彫刻ガラス","desc":"ボヘミアのガラス職人レーマンが作ったガラス細工。ガラスに彫刻が施されており、宝石のように美しい。"}],"782":[{"rank":"5","note":"太りすぎのガチョウのような鳥","exp":"1105","type":"鳥類","name":"ドードー","desc":"モーリシャス諸島にしか生息しない、特殊な鳥である。ニワトリよりかなり大きく、翼は小さくて飛べない。足は太くてしっかりしているが、速く走ることはできない。島に捕食者がいないため、のんびりした鳥になったのだろう。"}],"6360":[{"rank":"2","note":"","exp":"260","type":"史跡","name":"クセルクセス門","desc":"中東の遺跡ペルセポリスにある巨大な門。人面有翼獣神像が門の両側に配置されている。クセルクセス1世により建設されたが、この門をはじめとする大規模な建築事業によって国の財政は傾き、国家の衰退にさえ繋がったとされる。"}],"6116":[{"rank":"5","note":"","exp":"940","type":"美術品","name":"至聖三者のイコン","desc":"15世紀ロシアの修道士アンドレイ・ルブリョフが、ある修道士の依頼で作成したとされるイコン。アブラハムを訪れた三天使が木の下に座っている様子が描かれ、三位一体の神を象徴していると解釈される。"}],"544":[{"rank":"1","note":"古代の墳墓の地図","exp":"30","type":"歴史遺物","name":"石棺","desc":"死者を埋葬する際に使われた石の棺。高貴な人物の棺には精巧なレリーフや彫刻が施されている。"}],"1664":[{"rank":"3","note":"虫取り草","exp":"462","type":"植物","name":"ウツボカズラ","desc":"袋がいくつもある植物である。袋の中には液体がたまっていて、中に落ちた虫が溶けてしまった。養分にしているのだろうか。これが巨大化したら、人間が溶かされるのでは…。"}],"4853":[{"rank":"2","note":"「明るい星の観測記録」<br/>発見物カード:135","exp":"270","type":"天文","name":"アルゴル","desc":"ペルセウス座に含まれる星。約三日の周期で光の強さが変わる。アルゴスは「悪魔」を意味するといわれ、星座図上ではペルセウスの携えている怪物・メデューサの首の部分に位置する。"}],"306":[{"rank":"2","note":"ヨーロッパの宝石","exp":"355","type":"鳥類","name":"カワセミ","desc":"宝石のように輝く青い羽と、長くて鋭いくちばしが特徴。自分の見張り場所から水中に飛び込み、すばやく魚を捕らえる。まれに、空中で静止した状態から飛び込むこともある。"}],"5347":[{"rank":"2","note":"セントヘレナとアセンションどちらかか両方かが前提かも。","exp":"330","type":"地理","name":"トリスタン・ダ・クーニャ諸島","desc":"南大西洋に浮かぶ火山島。16世紀の始めに島を発見した探検家の名に由来する。補給港や避難港としての利用が期待される。"}],"6898":[{"rank":"3","note":"","exp":"","type":"地理","name":"サハラの目","desc":"アフリカ北西部の砂漠にある窪地。直径は約50kmに及ぶ。高台から眺めると目のように見えることから、この名で呼ばれるようになったという。"}],"6661":[{"rank":"2","note":"東地中海　ロードス島の北","exp":"","type":"歴史遺物","name":"ウルブルン沈没船","desc":"紀元前13世紀、フェニキア文明圏の商船。カナンを始め東地中海の都市を巡り貿易を行っていたという。主な積荷は銅のインゴット。トルコの南岸付近にて沈没した。"}],"150":[{"rank":"1","note":"ケルト遺物の地図","exp":"24","type":"歴史遺物","name":"ケルトの装身具","desc":"ケルト民族が使っていた装身具。金を多用し独特の文様や形態のものがある。"}],"1944":[{"rank":"4","note":"へそを求めて","exp":"630","type":"宗教遺物","name":"タパク・ヤウリ","desc":"インカの初代皇帝がインティ神より贈られたとされる杖。インティ神は、この杖が大地に沈んだ所に太陽の神殿を建てるよう告げる。そして杖が沈んだ場所こそ、他ならぬインカ帝国の首都クスコであったという。"}],"5217":[{"rank":"2","note":"マケドニア地方　再調査報酬","exp":"","type":"歴史遺物","name":"古代マケドニアの金装飾","desc":"金の薄板で飾り付けられた豪華な装飾品。ナラの葉をかたどっている。立体的な装飾はとても繊細で古代マケドニアの技術力がうかがえる。"}],"6995":[{"rank":"2","note":"","exp":"","type":"地理","name":"洞庭湖","desc":"華南の長江中流にある淡水湖。長江と繋がっており、広大な面積を誇る。その姿は「八百里洞庭」と称えられ、古代から詩歌や神話によく登場した。長江との合流地点では、水の色がくっきりと分かれて見える。"}],"948":[{"rank":"5","note":"不滅の星<br/><br/>発見時経験値1105　発見物カード経験値552","exp":"1105","type":"財宝","name":"エターナルスター","desc":"100カラットをゆうに超える、巨大なダイヤモンド。大きなダイヤは色がついているものが多いが、これはまったくの無色である。内包物もほとんどなく、奇跡ともいえるダイヤモンドだ。"}],"1319":[{"rank":"2","note":"クエスト「列島横断航路」<br/>発見物カード:160","exp":"320","type":"地理","name":"大スンダ列島","desc":"スマトラ島、ジャワ島カリマンタン島、セレベス島で構成される列島。古くから多くの民族や王朝が変遷したため、時代や場所により文化、宗教が異なっているようだ。"}],"994":[{"rank":"1","note":"冒険者のバイブル","exp":"55","type":"財宝","name":"東方見聞録","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。"}],"2738":[{"rank":"4","note":"漢陽の宮殿","exp":"620","type":"史跡","name":"景福宮","desc":"朝鮮王朝の王宮として建築された、豪華な宮殿。\n宮の名前は、王とその子孫、国民みんなが太平盛大の福を享受するように、祈りを込めて付けられたという。"}],"612":[{"rank":"2","note":"殺人ダコ","exp":"340","type":"海洋生物","name":"ヒョウモンダコ","desc":"暖かい海に生息する小型のタコ。成体でも10cm程度である。興奮すると、青い模様が浮き出て美しい。口に毒腺があり、かまれると死亡することもある。"}],"1606":[{"rank":"2","note":"古い法典の地図","exp":"255","type":"宗教遺物","name":"中論","desc":"ちゅうろん。ナーガールジュナの著。仏教の中道について記したもの。一般的な論書というよりは、詩歌的な部分が多く、文芸作品としても素晴らしい価値がある。"}],"5609":[{"rank":"2","note":"","exp":"","type":"地理","name":"エリー湖","desc":"北米大陸北東部に位置する湖のひとつ。面積は広いが、水深は20m未満と浅い。下流は川を経て巨大な滝へと繋がっている。"}],"6879":[{"rank":"5","note":"発見物カード:605","exp":"1210","type":"植物","name":"ゴーストオーキッド","desc":"カリブ周辺にのみ分布するランの一種。葉を持たず木に着生して育つという珍しい特徴を持つ。6月から8月にかけて白い花を咲かせるが、開花している時季以外に発見することは至難の業である。"}],"2878":[{"rank":"2","note":"古代の酒器の地図","exp":"280","type":"歴史遺物","name":"爵","desc":"読みは「しゃく」。殷周時代の酒器で、祭器としても使用された。三つの脚は天・地・神を表すといわれる。\nこの爵にはトウテツと呼ばれる怪異な獣が描かれている。"}],"6800":[{"rank":"3","note":"イオニア海視認","exp":"600","type":"天文","name":"サドル","desc":"はくちょう座で2番目に明るい星。十字に並ぶはくちょう座のちょうど交点に位置する。名はアラビア語で「雌鶏の胸」を意味する。"}],"563":[{"rank":"2","note":"古代文明を育てた川","exp":"250","type":"地理","name":"チグリス川","desc":"ペルシャを流れる大河で、ユーフラテス川と合流する。この流域は非常に古くから文明が栄えていたようで、独特の遺物が発見されるそうだ。いまは乾燥地帯だが、昔は豊かな土地だったのかもしれない。"}],"367":[{"rank":"5","note":"黄色を追い求めて","exp":"1111","type":"植物","name":"ロサ・フェティダ・ペルシアーナ","desc":"ペルシャ地方原産の黄色いバラ。「ペルシャンイエロー」とも呼ばれる。\n鮮明な黄色い花びらが幾重にも折り重なっている。その小さな葉には、芳香がある。"}],"6246":[{"rank":"1","note":"清楚な絵","exp":"100","type":"美術品","name":"受胎告知（アンジェリコ）","desc":"フラ・アンジェリコ作の祭壇画。鮮やかな色彩で描かれたこの絵は作者の敬虔な信仰心を如実に表している。アンジェリコの名は通称で、穏やかな修道僧であった彼を「天使のようだ」と表現したものだそうだ。"}],"2671":[{"rank":"2","note":"朝鮮三国歴史語り","exp":"340","type":"歴史遺物","name":"三国史記","desc":"古代朝鮮の歴史がつづられた歴史書。新羅、百済、高句麗の歴史が50巻に渡って記されている。\n高麗の儒学者により、二年ほどかけて編さんされたという。"}],"2871":[{"rank":"1","note":"不気味な魚の地図","exp":"190","type":"海洋生物","name":"ワラスボ","desc":"中国や朝鮮などに生息する、細長く青紫色の体をした生物。\n生まれたばかりのころは正常な目を備えているが、成長と共に退化し、皮膚の下に埋もれてしまう。"}],"2014":[{"rank":"5","note":"伝説のカヌー","exp":"1196","type":"歴史遺物","name":"伝説のカヌー","desc":"ハワイキからアオテアロアに移住するために用いられたカヌーといわれている。相当古い状態で保存されているので、もしかすると本当にクペたちが移住するために乗ってきたカヌーかもしれない。"}],"5158":[{"rank":"2","note":"到達する","exp":"309","type":"港・集落","name":"マラッカ","desc":"イスラム教を国教とするマレー人の国であるマラッカ王国の首都。マラッカ王国は、シュリーヴィジャヤ王国の王子・パラメスワラがマジャパヒト王国の侵攻から逃れ、この地で建国したことに端を発する。"}],"6286":[{"rank":"3","note":"","exp":"600","type":"地理","name":"カボ・デ・ロス・アマンテス","desc":"グアム島の北岸に位置する岬。身分の差により結ばれることを許されなかった恋人たちが身を投げたという伝説がある。"}],"695":[{"rank":"3","note":"神の化身","exp":"484","type":"宗教遺物","name":"クリシュナ像","desc":"インド神話のヴィシュヌ神の、第8の化身といわれる英雄の像。マハーバーラタという叙事詩に登場し、五王子を補佐して導く。他にも、クリシュナにまつわる神話は数多い。"}],"6982":[{"rank":"","note":"経験値705＋352","exp":"705","type":"中型生物","name":"キルクディクディク","desc":"東アフリカに生息するレイヨウの一種。小柄かつ細身な体躯ながら脚力に優れ、非常に足が速い。一度つがうと生涯離れず、雌雄で協力して縄張りを守りながら暮らす。甲高く、独特な警戒声が名前の由来とされている。"}],"5788":[{"rank":"5","note":"","exp":"1550","type":"宗教建築","name":"スワヤンブナート","desc":"ネパール地方の仏教において重要な寺院のひとつ。寺院の中央には壮麗な仏塔がそびえ立つ。仏塔の壁面には、四方に「仏陀の目」が描かれ、森羅万象を見通すとされている。"}],"6156":[{"rank":"5","note":"","exp":"1330","type":"伝承","name":"サンダーバード","desc":"雷を操るとされる巨大な鳥。雷を自在に落とす雷の精霊として、\n北米先住民の間で広く崇拝されている。人の言葉を理解したり、\nクジラを丸ごと食べたりするなど、地域によって伝わる伝承は\n異なっているようだ。"}],"5055":[{"rank":"1","note":"到達する","exp":"41","type":"港・集落","name":"コペンハーゲン","desc":"ヨーロッパ北部のシェラン島東岸にあり急速に発展しつつある街。コペンハーゲンとはデンマークの言葉で「商人の港」を意味する。農作物や加工食品のほか、琥珀（こはく）やぜいたくな調度類が流通する。"}],"6863":[{"rank":"3","note":"発見物カード:140","exp":"280","type":"中型生物","name":"シャムネコ","desc":"シャム原産の猫。毛は短く、顔や耳、尻尾、手足など一部の毛色が濃い。シャムの王侯貴族など、限られた者のみが買うことを許されているという。"}],"3202":[{"rank":"5","note":"薬と毒薬","exp":"940","type":"財宝","name":"メディチ家処方箋","desc":"薬に関する商売を行っていたメディチ家秘蔵の処方箋。ハーブや野生の薬草、木の皮等を使った薬の調合法が記されている。"}],"744":[{"rank":"1","note":"聖人の年代記絵画","exp":"75","type":"美術品","name":"聖地で説教する聖エティエンヌ","desc":"ヴィットーレ・カルパッチオ作。聖エティエンヌの生涯を題材とした六枚の年代記絵画の一枚。描かれている街はイェルサレムで、エキゾチックで鮮やかな衣装や、石造りの美しい街並みが特徴的である。"}],"2247":[{"rank":"5","note":"幻の桃色トカゲ","exp":"930","type":"中型生物","name":"ピンクイグアナ","desc":"体長1mほどのピンク色をした大型トカゲ。\nガラパゴス諸島の特定の島の火山にしか生息しておらず、滅多に見られない。"}],"5111":[{"rank":"2","note":"到達する","exp":"266","type":"港・集落","name":"バイーア","desc":"バイーアとは「湾」の意味。大西洋に面し、トドス・オス・サントス（「諸聖人の湾」）を取り囲む半島に位置する南米の街。"}],"2867":[{"rank":"1","note":"白い花の地図","exp":"130","type":"植物","name":"エンジュ","desc":"主に中国に生息する、たくさんの白い花を咲かせる植物。\n薬用植物としても有名で、花の蕾を干したものは、止血剤として使われている。"}],"1646":[{"rank":"2","note":"奇岩島","exp":"270","type":"地理","name":"カンガルー島","desc":"オーストラリア南東部にある島。イングランドのマシュー・フリンダースにより発見された。多種多様な動物が生息している。内陸は洞窟や砂漠、一枚岩の巨石が存在するなど、変化に富んでいる。"}],"2838":[{"rank":"2","note":"科挙の勉強","exp":"240","type":"宗教遺物","name":"論語","desc":"春秋時代の思想家・孔子の言行を、弟子達が記録した書物。全20編で構成される。\n科挙の出題科目にもなっており、儒教でも重要な書物である。"}],"5589":[{"rank":"3","note":"","exp":"598","type":"気象・現象","name":"フロストフラワー","desc":"寒冷地方の湖面に発生する数cmほどの氷晶。名前は「霜の花」を意味する。湖の氷から発生した水蒸気が凍結したものと考えられる。条件さえ揃えば、川や水たまりなど、湖以外でも観測できる。"}],"1847":[{"rank":"1","note":"精巧な加工の地図","exp":"150","type":"歴史遺物","name":"貝殻","desc":"インカの主な街は高地にあり、海とは縁遠いものだった。しかしチャスキの活躍により高地にも新鮮な海産物が届けられた。また、貝を食したあとの貝殻は美しく彩色され、このような装飾品にもなった。"}],"6152":[{"rank":"5","note":"クエスト「魚かクジラか」<br/>発見物カード:620","exp":"1240","type":"海洋生物","name":"イワシクジラ","desc":"太平洋、大西洋、インド洋などに広く生息するクジラ。甲殻類や魚類などを食べる。他のクジラに比べて体が細長く、動きが敏捷であるせいか、広い海域に生息している割には目撃例が少ない。"}],"1327":[{"rank":"2","note":"ヤーデイン西の巨大湾","exp":"270","type":"地理","name":"シャム湾","desc":"ヤーデインの西に広がる巨大な湾。水深が浅く、大河が流れこむために塩気は薄い。沿岸にはマングローブの林が見られ、格好の漁場となっているようだ。"}],"5210":[{"rank":"2","note":"","exp":"","type":"宗教遺物","name":"石製の浮屠塔","desc":"宋代に作られたと見られる浮屠塔。仏塔とも呼ばれる。釈迦本人の仏舎利を納めた塚を模したとされる。五段に区切られ、それぞれの段に仏像が彫られている。"}],"1028":[{"rank":"1","note":"野生の犬の地図","exp":"59","type":"中型生物","name":"ジャッカル","desc":"犬やキツネに似た、肉食動物。キツネよりやや大きい。体色は何種類かあるようだ。"}],"1722":[{"rank":"5","note":"怪鳥再び","exp":"1222","type":"鳥類","name":"モア","desc":"アオテアロアの森に棲む飛べない鳥。見た目はダチョウに似ているが、両翼は見当たらない。中には体長4mという、鳥とは思えぬほど巨大なものもいる。以前はたくさんいたようだが、島に人が住むようになってから激減しているらしい。"}],"2348":[{"rank":"4","note":"夢のお告げと説話集","exp":"620","type":"財宝","name":"宇治拾遺物語","desc":"読みは「うじしゅういものがたり」。仏教説話や世俗説話で構成された日本の説話集。\n同様の説話集の中では教訓めいた内容が比較的少なく、滑稽な話が多い。"}],"321":[{"rank":"3","note":"ラムセス2世の神殿","exp":"600","type":"宗教建築","name":"アブ・シンベル神殿","desc":"古代エジプトのファラオ・ラムセス2世が建てた神殿。内外に多数の石像があるが、ほとんどはオシリス神の姿をした、ラムセス2世の像である。隣に小神殿がある。"}],"192":[{"rank":"5","note":"ダ・ヴィンチ＝コード","exp":"1183","type":"美術品","name":"モナリザ","desc":"レオナルド・ダ・ヴィンチ作の絵画。不思議な微笑、衣服の上品な質感、空気遠近法による背景、なにより、まるで血が通っているかのような肌。まさに理想の肖像画といえる。"}],"5836":[{"rank":"4","note":"夜　晴れ　書いている内容とは違いよく現れます。","exp":"650","type":"気象・現象","name":"レッドスプライト","desc":"雷雲からさらに上空に向けて発生する発光現象。特に赤いものをこのように呼称する。ただ、発生場所の見えにくさや発光時間の短さから観測例が少なくその詳細は謎に包まれている。"}],"2853":[{"rank":"2","note":"勉学に励む少女","exp":"310","type":"歴史遺物","name":"資治通鑑","desc":"読み方は、「しじつがん」。春秋時代から宋代までを記してある歴史書。\n「史記」や「漢書」とは違った文体で書かれており、読みやすさを重視したと考えられている。"}],"6864":[{"rank":"3","note":"発見物カード:270","exp":"540","type":"天文","name":"セギヌス","desc":"うしかい座のガンマ星で、3等星。名は「うしかい座」を意味するギリシャ語が翻訳を経ることで変化した言葉と言われる。アラビア語で「守護者」を意味するハリスという別名もある。"}],"6574":[{"rank":"5","note":"追究クエスト<br/>発見物カード:750","exp":"1500","type":"小型生物","name":"冬毛のクロテン","desc":"イタチ科の小型生物。ユーラシア大陸に広く分布するが、毛皮目的で乱獲されたため、近年はその数を減らしている。冬毛が美しく、中でも日本の北の地域にのみ生息するエゾクロテンの冬毛姿は特に麗しく愛らしい。"}],"5944":[{"rank":"3","note":"クエスト「不毛の地に根付いたもの」<br/>発見物カード:200","exp":"400","type":"地理","name":"ピコ島のブドウ畑","desc":"アゾレス諸島の一つ。不毛な火山島であったが、移住した修道士たちが溶岩の隙間にブドウを植え、溶岩の塊を積み上げて垣根を作って風から守ってきた。そうして開拓が進められた結果、独特な景観が形成された。"}],"2080":[{"rank":"3","note":"毒グモの魅惑","exp":"490","type":"虫類","name":"チリアンコモン","desc":"南米に生息するクモ。茶色い姿で地味な印象があるが、脱皮直後はとても美しい。\n比較的おとなしい性質である。"}],"5846":[{"rank":"3","note":"","exp":"490","type":"天文","name":"さいだん座","desc":"神々に生贄を捧げる祭壇をかたどった星座。ギリシャ神話の最高神ゼウスとその兄弟たちが、父クロノスの打倒を誓った祭壇とも言われている。"}],"5188":[{"rank":"2","note":"到達する","exp":"375","type":"港・集落","name":"江戸","desc":"近年急速に発展してきている、太平洋沿岸の街。入り江を埋め立てて住宅地を造成するなど、有力者の主導の下で計画的な街づくりが進められている。"}],"6665":[{"rank":"3","note":"","exp":"","type":"歴史遺物","name":"万暦号","desc":"明の貿易船。明代は貿易が盛んで、万暦号も海上貿易に従事していた。陶磁器や茶、シルクなどの交易品を積んでいたと考えられる。マレーシア沖で沈没した。"}],"5073":[{"rank":"1","note":"到達する","exp":"15","type":"港・集落","name":"ジェノヴァ","desc":"古代ローマ時代に基礎が築かれ、十字軍の時代に栄えた都市。かつてヴェネツィアと激しい勢力争いを繰り広げたが、近年は下り坂である。しかし、大都市にふさわしく、高級な商品が扱われている。"}],"1486":[{"rank":"1","note":"角のある虫の地図","exp":"130","type":"虫類","name":"ツノゼミ","desc":"頭に付いた大きな角状の突起物は、皮膚を突き刺すほど硬い。ツノゼミは卵をアリに守ってもらい、そのお礼に蜜を与える。"}],"6535":[{"rank":"3","note":"文化貢献度35<br/><br/>夏？<br/>結構長い。鯖CCしても間に合います。","exp":"480","type":"気象・現象","name":"同期発光現象","desc":"ホタルの群れに見られる発光現象。始めはバラバラに発光していたホタルの群れが、徐々にシンクロしていき、最後には同じ周期で発光するようになる。この現象には謎が多く、くわしいことはまだ分かっていない。"}],"1360":[{"rank":"5","note":"鳥と太陽の宝玉","exp":"936","type":"財宝","name":"マニックブルン","desc":"今から200年ほど前に作られたといわれているトンボ玉。非常に状態がよい。片面に鳥が浮かび上がり、その裏には、太陽光を表す模様が浮かび上がっている。深い群青色に柔らかな乳白色が映える、逸品である。"}],"3590":[{"rank":"","note":"","exp":"","type":"レリック","name":"桃源郷","desc":"武陵の山中にひそかに存在するという桃源郷。俗世に疲れ、隠遁した詩人、陶淵明の心は、かの地で癒やされたのだろうか。"}],"2681":[{"rank":"3","note":"朝鮮の宗教画","exp":"530","type":"美術品","name":"高麗仏画","desc":"高麗時代に多く描かれた仏教画。\nこの時代は、阿弥陀如来や楊柳観音、地蔵菩薩が流行したらしく、よく見かける。"}],"2850":[{"rank":"3","note":"高級織物の素材","exp":"510","type":"虫類","name":"カイコ","desc":"中国北部でよく見られる、家畜化された虫。野生には生息しない。絹や綿を生産するためのまゆを作り出す。"}],"275":[{"rank":"1","note":"ベリアルの宝玉","exp":"100","type":"財宝","name":"ベリアルの宝玉","desc":"聖書のソロモン王が、悪魔や精霊72体を封じ込めたという宝玉の一つ。この宝石にはベリアルが封じられているという。真偽の程は不明だ。\n宝玉はよく見ると傷があり、「松の島の北の街」と彫られている。"}],"6846":[{"rank":"3","note":"発見物カード:250","exp":"500","type":"天文","name":"ディアデム","desc":"かみのけ座の2番目に明るいアルファ星で、2つの5等星がお互いに公転する連星として知られる。頭に巻き付ける王冠の名であり、古代エジプトの王妃ベレニケ2世の冠という説もある。"}],"630":[{"rank":"3","note":"七変化するトカゲ","exp":"473","type":"小型生物","name":"カメレオン","desc":"50cm程度のトカゲ。まわりの色に合わせて体色を変えられる。興奮したときも変わるようである。樹上で生活しカエルのように舌を伸ばして昆虫類を捕らえる。足の指が2本ずつ向かい合っており、木にしがみつくのに便利なようだ。"}],"3183":[{"rank":"1","note":"書きかけの地図","exp":"140","type":"地理","name":"カボット海峡","desc":"北米北東部の沿岸に位置する海峡。幅はおよそ11kmであり、大西洋からセントローレンス湾内に進入できる海峡としては最も広い。"}],"2902":[{"rank":"4","note":"高貴な人への贈り物","exp":"640","type":"植物","name":"ホウサイラン","desc":"台湾島まで至る中国南部地方で自生している植物。一月から二月に咲き、正月の床飾りなどに使われる。\n観賞用としても評価が高く、上流階級の人々に好まれた。"}],"231":[{"rank":"5","note":"ニーベルンゲンの指輪","exp":"880","type":"宗教遺物","name":"ニーベルンゲンの指輪","desc":"ラインの黄金で作られた指輪。世界のすべてを持ち主に与えるという。イスパニアの王室が手に入れたものが本物かどうかは明らかではないが、伝承どおりの、美しい黄金の指輪であることは間違いない。"}],"1917":[{"rank":"1","note":"鮮やかな花の地図","exp":"150","type":"植物","name":"カルセオラリア","desc":"袋状の花弁が特徴的な低木の植物。黄、赤、オレンジ、斑点の混じるもの等、様々な色の花が存在する。主に中南米の温暖な地域に広く分布。花の名前であるカルセオラリアはラテン語で「小さな靴」の意味。"}],"1792":[{"rank":"4","note":"クエスト「砂漠と海の関係」<br/>発見物カード:370","exp":"740","type":"地理","name":"フンボルト海流","desc":"南米大陸の西岸を大陸の南端からグアヤキル湾まで北上する寒流。水流は遅く水温は非常に低いが、この海流に乗って魚群が北上するため、南米南西岸は広範囲に豊かな漁場を持つ。"}],"5597":[{"rank":"4","note":"","exp":"700","type":"気象・現象","name":"月柱","desc":"月の出、月の入りの際に、月の周囲に光の柱のようなものが見える現象。太陽柱とは異なり、光の形状は楕円に近い。月の光が強くなる半月以上のときに観測されることが多い。"}],"3528":[{"rank":"","note":"","exp":"","type":"レリック","name":"海賊女王テウタ","desc":"古代ローマの時代にアドリア海の海賊を束ねていたという伝説の女王。ローマとの戦いに敗れ、その姿は歴史の闇に消えている。"}],"1347":[{"rank":"3","note":"学者の願い","exp":"451","type":"虫類","name":"ダイオウヒラタ","desc":"がっしりとした体で、湾曲した太くて短いハサミが特徴の虫。とても凶暴である。"}],"1018":[{"rank":"1","note":"名将軍の采配","exp":"120","type":"歴史遺物","name":"ハンニバルの大理石像","desc":"ハンニバルはカルタゴの将軍で、共和制ローマを攻めて功績があった。一時はイタリア半島まで攻め込んだが、ザマの戦いで大スキピオに敗れた。"}],"6740":[{"rank":"4","note":"カード経験:450","exp":"900","type":"財宝","name":"錦衣衛の牙牌","desc":"明の皇帝直属軍の一つ「錦衣衛」で使用された、象牙製の札。身分を証明するもので、腰から下げて携行する。裏に注意書きが刻まれており、公務の際は着用義務があった。他人に貸したり、紛失した者は罪に問われたという。"}],"6407":[{"rank":"","note":"","exp":"","type":"宗教建築","name":"在りし日のマウソロス霊廟","desc":"ハリカルナッソスに建造された壮麗な霊廟。王マウソロスとその死後に女王となった妻アルテミシアが眠る。大理石の高層建築で、各段に大きな彫像が立ち並んでいた。頂上には巨大な四頭立ての戦車と馬の像が載っていたという。"}],"6867":[{"rank":"5","note":"発見物カード:425","exp":"850","type":"天文","name":"コル・カロリ","desc":"りょうけん座で最も明るいアルファ星。3等星で二つの星で構成される連星。春の大三角と共に「春のダイヤモンド」を形成する。名はラテン語で「チャールズの心臓」を意味する。"}],"6835":[{"rank":"4","note":"発見物カード:400","exp":"800","type":"鳥類","name":"ゴイサギ","desc":"世界各地に生息しており、湿地や河川、湖などの水辺で見ることができる。顔から腹が白く、頭から背中は灰色が買った紺色。夜行性で魚や虫などを食べ、昼は樹上などから動かない。成鳥には、後頭部に白く長い冠羽が生えている。"}],"6350":[{"rank":"2","note":"","exp":"300","type":"歴史遺物","name":"ヘレポリス","desc":"「ロードス包囲戦」でロードス島攻略の為、デメトリオスが送りこんだ全高40メートル、全幅20メートルにもおよぶ巨大な攻城塔。内部はいくつかの層に分かれ、各階層には様々な兵器を搭載していたとされる。"}],"2977":[{"rank":"3","note":"遥か高みより落ちる水","exp":"440","type":"地理","name":"エンジェルフォール","desc":"南米大陸の北部に位置する大滝。\n落差が1km近くあるため、流れる水のほとんどが落下途中で散ってしまう。そのため、滝つぼも存在しない。"}],"1616":[{"rank":"1","note":"メソアメリカの遺物の地図<br/><br/>発見物カード:100","exp":"200","type":"宗教遺物","name":"テオティワカンの副葬品","desc":"メキシコ中央高原に花開いたテオティワカンの副葬品。マヤやアステカの各地でもこれと同じ様式の副葬品が見つかることから、古代この地は非常に強い影響度を誇っていたのだろう。"}],"2600":[{"rank":"2","note":"・人のような動物","exp":"340","type":"美術品","name":"鳥獣人物画","desc":"擬人化された動物が描かれている、日本の絵巻物の一部。\n当時の庶民の生活の様子が、動物の姿を借りて生き生きと表現されている。"}],"1810":[{"rank":"1","note":"書きかけの地図","exp":"100","type":"地理","name":"グアヤキル湾","desc":"南米大陸北西岸に位置する湾。南岸にはトゥンベスの街を擁している。湾の沖合いは北からの暖流と南からの寒流がぶつかり、潮目を形成している。"}],"5174":[{"rank":"2","note":"到達する","exp":"265","type":"港・集落","name":"リマ","desc":"ヨーロッパ人がインカ帝国調査の足掛かりとして作った開拓地。数多くの航海士がこの街を訪れ、交易の拠点ともなっている。"}],"4970":[{"rank":"5","note":"","exp":"1060","type":"史跡","name":"エピダウロス遺跡","desc":"ペロポネソス半島東部にある遺跡。ギリシャ神話の医療の神アスクレピオスの聖地といわれている。神殿の他に劇場や宿泊所、浴場の跡が残っている。中でも劇場は円形ステージを階段状の観覧席で囲んでおり、収容人数は1万人を超える。"}],"1692":[{"rank":"5","note":"メロス島を惑わす女神","exp":"1222","type":"美術品","name":"ミロのヴィーナス","desc":"メロス島で出土した大理石の女性像。他の像と組み合わされていたと思われる。豊かな肢体の柔らかな曲線と着衣のひだが美しい。"}],"6877":[{"rank":"2","note":"発見物カード:175","exp":"350","type":"鳥類","name":"オオミズナギドリ","desc":"主に東アジアに生息する渡り鳥の一種。冬には南アジアやオセアニアへ南下する。細長く先が曲がったくちばしを持つ。飛翔力に優れているが地面から飛び立つことができない。海上を薙刀で水を切るように飛ぶことから、この名が付いた。"}],"1658":[{"rank":"1","note":"書きかけの地図","exp":"110","type":"地理","name":"ジャワ海","desc":"ジャワ島とカリマンタン島の間に広がる海。遠浅でよい漁場なため多くの地元漁船が航行する。ジャワ海に浮かぶ小島は全体的に低地で、塩田が数多く見られる。"}],"514":[{"rank":"4","note":"古代の禁書","exp":"612","type":"歴史遺物","name":"サッフォーの詩集","desc":"古代ギリシャの女流詩人であるサッフォーの詩集。もとは9集あったと伝えられるが、美しい乙女への賛歌が多いため、不道徳とされて中世に多くが失われた。"}],"6434":[{"rank":"5","note":"レガシー　数の叡智・世界の計算機　左上","exp":"","type":"歴史遺物","name":"シッカートの自動計算機械","desc":"世界初の自動計算機とされ、ドイツのテュービンゲン大学ヘブライ語教授ヴィルヘイム・シッカートが17世紀前半に作成。別名「計算する時計」。6桁の加減算や込み入った乗算ができ、天文計算に使用する想定だったといわれる。"}],"6961":[{"rank":"5","note":"発見物カード:410","exp":"820","type":"美術品","name":"卓上のヘラクレス","desc":"リュシッポスの作品を精巧に複製したブロンズ像。リュシッポスは古代ギリシャ美術の三大彫刻家の一人で、アレクサンドロス大王のためにブロンズ像を制作した。この彫像にも生き生きとした躍動感があり、原作の秀逸さをうかがえる。"}],"6769":[{"rank":"2","note":"発見物カード:105","exp":"210","type":"植物","name":"リトープス","desc":"ハマミズナ科リトープス属の多肉植物。原生地は南アフリカ。乾燥地を好み、非常に成長が遅い。岩陰など日の当たらない場所に群生する。独特な形をしており、中央の割れ目から開花するという珍しい特徴がある。"}],"2890":[{"rank":"2","note":"書きかけの地図","exp":"360","type":"地理","name":"雲南石林カルスト","desc":"重慶より更に南方に広がる、多くの奇岩が林立している地。景観と穏やかな気候に恵まれている。"}],"5306":[{"rank":"2","note":"発見時経験値270　発見物カード経験値135","exp":"270","type":"鳥類","name":"クラハシコウ","desc":"アフリカ中部から南部にかけての湿地に棲む大型の鳥。くちばしの付け根にある黄色の部分が馬の鞍を思わせる形のため、この名がついた。胸に羽毛のない部分があり、卵を温める際はそこを使うようだ。"}],"1501":[{"rank":"1","note":"ワニのような骨の地図","exp":"140","type":"化石","name":"巨大なワニのような骨","desc":"アマゾンの陸地で発見された、体長10mを超えるワニに似た巨大な生物の骨。広大な森林地帯であるこの地は、かつては水に覆われていたのかもしれない。"}],"603":[{"rank":"3","note":"最高の女神","exp":"484","type":"宗教遺物","name":"サラスバティー像","desc":"インド神話の女神の像である。サラスバティーは、三大神の一人で創造をつかさどるブラフマーの妻であり最上の女神とされる。"}],"3299":[{"rank":"3","note":"大群で渡る鳥","exp":"510","type":"鳥類","name":"リョコウバト","desc":"北米の東岸に生息する鳥。体長は約40cmで、長くとがった翼と尾羽を持つ。非常に大きな群れで渡りを行う習性があり、夏は北米北東部などで、冬は主にメキシコ湾岸で過ごす。"}],"1785":[{"rank":"2","note":"書きかけの地図","exp":"260","type":"地理","name":"オクシデンタル山脈","desc":"アンデス山脈の支脈。オクシデンタル山脈はコピアポの北でアンデス山脈より派生し、トゥンベス付近まで走っている。アンデス山脈との相違点として活発な火山を有していることが挙げられる。"}],"1997":[{"rank":"2","note":"釣り","exp":"220","type":"海洋生物","name":"ルリハタ","desc":"鮮やかな体色をもつハタの仲間。"}],"5235":[{"rank":"2","note":"","exp":"250","type":"中型生物","name":"キンイロジャッカル","desc":"黄色から薄金色の体毛をもつジャッカルの仲間。北アフリカから東南アジアまで広く分布しており、生息地域によって外見が多様に変化する。"}],"6155":[{"rank":"2","note":"","exp":"270","type":"中型生物","name":"スコグカッテル","desc":"北欧に生息する猫の一種。「森の猫」を意味する名で呼ばれ、北欧神話にもそれらしき猫の伝承があるという。今ではありふれた種類だが、11世紀にビザンツ帝国の領域からヴァイキングが持ち込んできた長毛猫が先祖だという説もある。"}],"1479":[{"rank":"5","note":"終わりなき善と悪の戦い","exp":"1053","type":"宗教遺物","name":"バロンの仮面","desc":"ジャワ島東のバリ島に伝わる、神獣バロンをかたどった仮面。バロンはバリ島では疫病を防ぐ神として信仰されている。バリでは仮面をご神体として、大切にほこらで管理している。"}],"2876":[{"rank":"3","note":"唐代皇帝への興味","exp":"530","type":"財宝","name":"蘭亭序","desc":"王羲之により書かれた行書。\n文中に何度も出てくる文字は、文脈によって形を書き分けられている。唐代の太宗皇帝がこれを気に入り、書家に模刻させたという。"}],"1896":[{"rank":"1","note":"サルベージ","exp":"150","type":"歴史遺物","name":"ピンソンの探険船","desc":"南アメリカへの航海を行ったビセンテ・ピンソンの船団に属していたキャラベル。セントロシェ岬への到達後、ウィンドワード海峡を経てパロスへ向かう途中、嵐に襲われて難破した。"}],"448":[{"rank":"2","note":"教会の祭器の地図","exp":"245","type":"美術品","name":"象牙の聖櫃","desc":"「せいひつ」。作者不明の、象牙でできた高さ30cmほどの聖櫃。自宅での礼拝などに使われたのではないだろうか。左右の板はたためるようになっている。中央の聖母子像は完全な像ではなく、浮き彫りである。"}],"802":[{"rank":"1","note":"大きな貝の地図","exp":"59","type":"海洋生物","name":"ホラガイ","desc":"40cmにもなる、大きな巻貝。インドや東洋では、この貝殻を笛として使うそうだ。低い大きな音が出て、遠くまで聞こえるという。"}],"5454":[{"rank":"2","note":"","exp":"370","type":"植物","name":"ガラナ","desc":"中南米などの地域で見られる植物。果実が赤く、熟すと黒い種子が現れる。この種子は滋養強壮に良いと信じられており、先住民の間では古くから重宝されてきた。"}],"6293":[{"rank":"5","note":"","exp":"830","type":"歴史遺物","name":"アリイのサッシュ","desc":"ハワイで「アリイ」と呼ばれる権力者が、権威の象徴として身に着ける腰巻き。真紅や黄色の鮮やかな羽根で覆われており、その羽根には自然の力が宿っているという。"}],"5524":[{"rank":"4","note":"発見時経験値740　発見物カード経験値370","exp":"740","type":"気象・現象","name":"ハロ","desc":"太陽や月に薄い雲がかかり、環状の光の帯が発生する現象。発生原因は虹に近いと考えられるが、いまだ解明はされていない。"}],"5870":[{"rank":"5","note":"","exp":"1420","type":"虫類","name":"ヒカリキノコバエ","desc":"オーストラリアなどに生息する昆虫。幼虫は洞窟の天井に生息し、発光する成分を含んだ粘液を体から垂らし、虫をおびき寄せて捕食する。"}],"6488":[{"rank":"5","note":"追究クエスト","exp":"","type":"地理","name":"グレートサンディ砂漠のクレーター","desc":"オーストラリアの北西部に広がるグレートサンディ砂漠にある巨大なクレーター。隕石の衝突によって形成されたと考えられている。その全容を把握するには、高台から望む必要があるだろう。"}],"6505":[{"rank":"5","note":"","exp":"1800","type":"地理","name":"モーリシャス島","desc":"マダガスカル島の東に浮かぶモーリシャス諸島で最も大きな島。サンゴ礁と白い砂に囲まれ、海岸近くの海はさまざまな色に見えるという。内陸部でも土の色が七色に輝く場所があるなど、美しい光景が見られる。"}],"5267":[{"rank":"1","note":"レプティス　再調査報酬","exp":"","type":"歴史遺物","name":"レプティス・マグナのヴィーナス像","desc":"レプティス・マグナ遺跡内の大浴場に飾られていたと思われる大理石製の女神像。古代の人々は女神に見守られながらの入浴を楽しんでいたのだろうか。"}],"3920":[{"rank":"1","note":"クエスト「美女の伝説」<br/>発見物カード:90","exp":"180","type":"天文","name":"はくちょう座","desc":"ゼウスがスパルタの王妃レダの元に向かう際に変身した白鳥が天に昇った姿とされる。十字を描いている中心部は、北十字星と呼ばれることもある。"}],"3850":[{"rank":"3","note":"自然への敬意","exp":"460","type":"地理","name":"スカン・グアイ","desc":"北米沿岸の島にある、先住民が暮らす村。彼らが作るトーテムポールには、シャチなどの海洋生物が模様として刻まれ、海に向けて立てられる。高さ10mにもなる巨大なトーテムポールもある。"}],"6054":[{"rank":"3","note":"","exp":"540","type":"財宝","name":"プロコピオスの戦史","desc":"東ローマ帝国の名将ベリサリウスに仕えた書記官であるプロコピオスの著作。\n当時の皇帝であったユスティニアヌス1世の治世や皇后テオドラの女傑ぶり、武将としてのベリサリウスの活躍などが記されている。"}],"6776":[{"rank":"4","note":"発見物カード経験値：380","exp":"760","type":"地理","name":"ジェイタ洞窟","desc":"ベイルートより北にある石灰岩洞窟。全長は約9km。洞窟は上下に分かれており、様々な種類の鍾乳石が確認できる。石器時代の人類の痕跡があり、青銅器などが発見された。先史時代の文明を辿るのに重要な遺跡として非常に価値が高い。"}],"1928":[{"rank":"2","note":"バイオリンを模した昆虫","exp":"350","type":"虫類","name":"バイオリンムシ","desc":"東南アジアの熱帯雨林に生息する、見た目がバイオリンに似ている昆虫。大きさは10cm程で昆虫の中では大型。特定のキノコの近くでよく見つかる。"}],"528":[{"rank":"1","note":"古代の鉄器の地図","exp":"54","type":"歴史遺物","name":"鉄の武具","desc":"古代の鉄の武具。青銅器が主流の時代に、硬い鉄器を作る技術があれば無敵といえる。ヒッタイトは製鉄技術を独占し強国となった。"}],"6170":[{"rank":"3","note":"","exp":"600","type":"宗教遺物","name":"聖ゲオルギイのイコン","desc":"聖ゲオルギイこと、竜退治の伝承で名高い聖ゲオルギウスを描いたイコン。東ヨーロッパの俗信では、狼たちが毎年捕らえることができる家畜の数を定めるという。そのため、羊と狼の守護者として崇敬されることもあるようだ。"}],"464":[{"rank":"2","note":"空を飛ぶ生物","exp":"340","type":"虫類","name":"ドルーリーオオアゲハ","desc":"アフリカで見られる非常に大きなチョウ。ひらひらと飛んでいる様子は鳥かコウモリと見間違うほどである。大型のものは羽を広げると20cm以上ある。近くで見るとぎょっとするほどの迫力だ。"}],"3301":[{"rank":"3","note":"布教の拠点","exp":"500","type":"地理","name":"アイオナ島","desc":"ブリテン島北部、西側にある、とても小さな島。一日あれば徒歩で島を一周できる。\n修道僧・コルンバによりこの島に建てられた修道院を拠点として、信者たちは布教活動を行った。"}],"4965":[{"rank":"2","note":"クエスト「ミノス王の娘」<br/>発見物カード:175","exp":"370","type":"天文","name":"かんむり座","desc":"ギリシャ神話の酒神・ディオニソスがその妃アリアドネに贈った冠の天に上がった姿とされる星座。アリアドネはクレタ王ミノスの娘でテセウスのミノタウロス退治に協力した。"}],"552":[{"rank":"1","note":"古代ローマの盾の地図","exp":"120","type":"歴史遺物","name":"古代ローマ市民兵の盾","desc":"古代ローマは、市民が軍に参加していた。参加する市民は自費で装備を整え、訓練にも参加していた。装備は青銅であった。"}],"5191":[{"rank":"2","note":"到達する","exp":"340","type":"港・集落","name":"淡水","desc":"読みは「ダンスイ」。台湾島の北部に位置する街で、近くを大きな川が流れている。鄭成功がネーデルラント人を追い出してできた街である。"}],"2722":[{"rank":"4","note":"朝鮮の美しい魚","exp":"690","type":"海洋生物","name":"シュリ","desc":"朝鮮の河川に生息する淡水魚。\nつがいの片割れが死ぬと、自分もそのあとを追って死ぬという、不思議な習性を持つ。"}],"3811":[{"rank":"2","note":"書きかけの地図","exp":"400","type":"地理","name":"エル・リモンの滝","desc":"イスパニョーラ島の北東部に位置する滝。落差は約40mで、水流は比較的穏やかである。"}],"6137":[{"rank":"1","note":"神秘的な燭台","exp":"100","type":"財宝","name":"白銀の燭台","desc":"銀は金属の中でも特に白く輝くものだが、この燭台はひときわ白く輝いている。銀に混ぜる金属の種類と割合に秘密があるというが、解明することはできないだろう…。"}],"35":[{"rank":"1","note":"アラビア航路の確保","exp":"200","type":"地理","name":"アラビア半島","desc":"ペルシャ湾と紅海にはさまれた広い半島。ほとんどが砂漠におおわれており、自然環境は非常に厳しい。しかしイスラム勢力をはじめとして、非常に栄えている地域でもある。"}],"2357":[{"rank":"2","note":"山に寄せる信仰","exp":"300","type":"宗教遺物","name":"山伏の修験道具","desc":"読みは、「やまぶしのしゅげんどうぐ」。修験道の行者が修行に用いる道具一式。\n修験道とは、山岳信仰に仏教や神道などが結び付いた日本の宗教である。行者はこれらを身に着け、山にこもって苦行を積む。"}],"6965":[{"rank":"3","note":"発見物カード:255","exp":"510","type":"財宝","name":"新羅の金製耳飾り","desc":"新羅時代の黄金の耳飾り。王族の副葬品として出土する。最上部には太い耳環、その下に中間飾、垂飾と並ぶのが特徴。金線や金粒を施した細かい文様により、非常に豪華な作りとなっている。"}],"1202":[{"rank":"3","note":"河口にある島","exp":"473","type":"地理","name":"マラジョ島","desc":"アマゾン川の河口にある島。大きさはジャマイカ島よりも大きいと思われるほど巨大。この島には、古くから人が住んでいた形跡がある。"}],"6869":[{"rank":"3","note":"","exp":"530","type":"天文","name":"イザル","desc":"うしかい座のイプシロン星。2等星の連星であり、この星座の中で2番目に明るい。牛飼いの腰の辺りに位置しており、名も「腰紐」を意味するアラビア語が由来とされている。"}],"1803":[{"rank":"1","note":"牛に似た生物","exp":"200","type":"大型生物","name":"ヨーロッパバイソン","desc":"欧州の深い森に棲む、大型の陸上動物。ウシに似ているが、体高が2m弱とウシよりも大きい。草原や水辺の多い場所、丘陵などで見られる。太古から狩猟の対象となっていた。長年の狩猟と森林伐採により、数が減少している。"}],"950":[{"rank":"2","note":"風変わりなドラゴン","exp":"300","type":"化石","name":"背びれのあるドラゴンの骨","desc":"背中に板状の突起が並んだ、大型の動物の骨のような石。こんな生物がどこかにいるのだろうか？　もしいたとしたら、それこそ悪魔の化身のように、凶暴なのに違いない。"}],"3584":[{"rank":"2","note":"繁栄を願う植物","exp":"279","type":"植物","name":"カナヴァオ","desc":"ハワイ固有種のアジサイ。実を食べると子宝に恵まれるとされ、古来より煮たり干されたりして食されている。そのため、アジサイに多く実がなると、縁起がよいと喜ばれる。"}],"1446":[{"rank":"2","note":"親の背で","exp":"330","type":"中型生物","name":"コアラ","desc":"生涯のほとんどをユーカリの木の上で過ごす有袋類。子はある程度まで成長すると、親の背中につかまって過ごす。ユーカリの葉を主食とする。"}],"1604":[{"rank":"4","note":"偉大なる王の墓","exp":"744","type":"歴史遺物","name":"アノーヤター王の剣","desc":"アノーヤター王はミャンマー人による最初の王朝・パガン王朝を開いた創始者である。国を興してからも他地域を制圧し領土を拡大。支配下に置いた地域から仏典を持ち帰り、おびただしいまでの寺院を建設する。"}],"5800":[{"rank":"5","note":"世界最大の贅沢","exp":"1400","type":"歴史遺物","name":"クレオパトラの真珠","desc":"クレオパトラの耳飾りについていた真珠。当時、世界最大といわれたものの一つ。対となる真珠は酢に溶かして飲まれたとされるが、あまりに大きく溶かす際にはかなり苦労したことだろう。"}],"5865":[{"rank":"5","note":"クエスト「流星群の元」<br/>発見物カード:680","exp":"1360","type":"天文","name":"エンケ彗星","desc":"太陽の周りを回る彗星の一つ。中でも特に周期が短いと考えられている。おうし座流星群の母彗星として、流星群の元となる物質を放出しているようだ。"}],"4816":[{"rank":"2","note":"釣り","exp":"350","type":"海洋生物","name":"ヌタウナギ","desc":"ウナギのような体をした魚だが、目らしきものがほとんど見あたらない。エラ穴が七つあり、ヤツメウナギの仲間と思われる。襲われるとヌタと呼ばれる粘液を出して身を守る。"}],"1643":[{"rank":"4","note":"とこしえの地","exp":"732","type":"地理","name":"タヒチ島","desc":"アオテアロアの北東にある島。沿岸部には黒い砂浜が見られる。この島の住人はアオテアロアの住人と同じく、精緻な文様の刺青を施している。さらに言葉まで非常に似通っているようだ。ここがハワイキなのだろうか…。"}],"1929":[{"rank":"2","note":"ラクダに似た動物<br/><br/>発見時経験値340　発見物カード経験値170","exp":"170","type":"大型生物","name":"グアナコ","desc":"南米の山岳や草原の荒地に生息。背部や側部は明るい茶褐色、首から腹部にかけては白色の柔らかな体毛をしている。おとなしい性格だが、好奇心が強い。現地では古くから荷運び用の動物として親しまれていた。"}],"2851":[{"rank":"5","note":"養蚕と蚕叢<br/><br/>発見時経験値1060　発見物カード経験値530","exp":"1060","type":"歴史遺物","name":"縦目仮面","desc":"独特な造形の仮面。\n縦の目が特徴的で、その形は伝説上の初代の蜀王・蚕叢を連想させる。"}],"1894":[{"rank":"2","note":"サルベージ","exp":"260","type":"歴史遺物","name":"サンベント号","desc":"ポルトガルの東インド貿易船。\nアフリカ南東岸沖ペドロ・ドス・パルコスの岩礁付近で沈没した。"}],"4969":[{"rank":"1","note":"「書きかけの地図」<br/>発見物カード:80","exp":"160","type":"地理","name":"ペロポネソス半島","desc":"バルカン半島の最南端に位置する半島。ギリシャ本土とはコリント海峡で繋がる。山がちで、平地は少ない。多くの遺跡があり、古くから繁栄していた半島だと思われる。"}],"1277":[{"rank":"2","note":"イスパニア縁の地","exp":"330","type":"地理","name":"ルソン島","desc":"東南アジアでも特に北東に位置している島。インド、アラブとの交易で栄えた。山がちな島ではあるが、農作物は多様で豊かである。"}],"5634":[{"rank":"3","note":"","exp":"480","type":"地理","name":"青の洞窟","desc":"イタリア南部のカプリ島にある海食洞。特異な地形の入り口から光が差し込むことで、洞窟内部が青く輝いて見える。"}],"2861":[{"rank":"3","note":"沙悟浄の原型","exp":"460","type":"海洋生物","name":"ヨウスコウワニ","desc":"長江の下流域に生息する、体長150cmほどのワニ。河川や湿地など人間の生活環境に近い場所に棲むが、穏やかな性格のため人間を襲うことは少ない。"}],"2531":[{"rank":"2","note":"移動する黄色い線","exp":"310","type":"小型生物","name":"スインホーキノボリトカゲ","desc":"台湾島にのみ生息する全長約20cmほどのトカゲ。樹幹によくくっついている。\n体の色は樹木に似ているが、背に黄色の線が入っているため、見つけることはたやすい。"}],"3818":[{"rank":"5","note":"ナッソー付近の航路調査","exp":"950","type":"地理","name":"エルーセラ島","desc":"カリブ海の西インド諸島のうち、バハマ諸島に属する島。サンゴ岩礁の島であり、細長い形をしている。"}],"5802":[{"rank":"5","note":"","exp":"1400","type":"史跡","name":"ドゥッガ","desc":"北アフリカに残るローマ、ビザンツ時代の遺跡。「防衛する」を意味する「トゥッガ」という言葉が名前の由来だとされる。神殿や浴場、劇場があった形跡もあり、当時の繁栄が窺える。"}],"2999":[{"rank":"1","note":"青い小さな花の地図","exp":"110","type":"植物","name":"ブルーボネット","desc":"北米に生息する花。密集して、青く小さな花を咲かすさまは、まるでじゅうたんのようである。"}],"5078":[{"rank":"1","note":"到達する","exp":"125","type":"港・集落","name":"スエズ","desc":"紅海の最北端にある街だ。内陸を経由する交易や、メッカに巡礼する人々の通過点として古くから栄えた。エジプトとアラビアの産物が流通している。"}],"1892":[{"rank":"2","note":"サルベージ","exp":"310","type":"歴史遺物","name":"カピタナ号","desc":"クリストバル・コロン四回目の航海「崇高な航海」で旗艦を務めたキャラベル。\nベルムーダ号との衝突で遭難して一年あまりの後、ディエゴ・メンデスに救助され、サンタグロリア湾に廃棄された。"}],"2489":[{"rank":"2","note":"クエスト「島の手掛かり収集」<br/>発見物カード:190","exp":"380","type":"地理","name":"蘭嶼島","desc":"台湾島の南東沖に浮かぶ離島。\n海水の浸食でできた大きな洞窟や、変わった形の岩など、見どころが多い。"}],"5601":[{"rank":"2","note":"","exp":"330","type":"港・集落","name":"サクラメント","desc":"北米大陸の西部に位置する街。開拓民の居留地として起こり、ゴールドラッシュを機に、開拓と交易の拠点として目覚しい発展を遂げた。"}],"5605":[{"rank":"2","note":"","exp":"210","type":"海洋生物","name":"シノノメサカタザメ","desc":"インド洋とその周辺に生息する海洋生物。見た目や泳ぎ方はサメに似ているが、エイの一種とされる。頭部が幅広く扁平なのが特徴。"}],"66":[{"rank":"2","note":"クエスト「インドの聖なる川」<br/>発見物カード:135","exp":"270","type":"地理","name":"ガンジス川","desc":"インド東部からベンガル湾に注ぐ大河。ヒンドゥー教徒にとって聖なる川だとされる。流域は非常に肥沃な土地が広がっている。古代から文明が発達していたようだ。"}],"1520":[{"rank":"2","note":"すべての道はローマに通ず","exp":"230","type":"史跡","name":"アッピア街道","desc":"共和制ローマ時代に造られた、ローマからイタリア半島南東岸に延びる街道。ローマ街道の中でもっとも歴史が古く、もっとも美しいといわれている。"}],"1933":[{"rank":"2","note":"巨大な虫の地図","exp":"210","type":"虫類","name":"タイタンオオウスバカミキリ","desc":"巨大なカミキリムシ。大人の手のひら程の大きさで、鋭い顎と爪を持つ。幼虫の体長は、その1.5倍。これほど大きなカミキリムシは他に類を見ない。南米の熱帯雨林に生息。"}],"6962":[{"rank":"2","note":"","exp":"","type":"植物","name":"シロタエギク","desc":"地中海沿岸が原産の植物。日当たりの良いところに生えている。葉は白い繊毛で覆われ、寒さに強く、冬でも美しい姿を保つ。初夏には黄色い小さな花を咲かせる。"}],"753":[{"rank":"1","note":"青い海の青いカメ","exp":"140","type":"海洋生物","name":"アオウミガメ","desc":"温暖な海に住む、青いウミガメ。水から上げると意外に茶色い体をしている。甲羅の直径が1m以上にもなる。"}],"5449":[{"rank":"3","note":"","exp":"540","type":"植物","name":"イペー","desc":"直径60cm～1m程度の比較的大きな木で、中南米に分布している。強度が非常に高く、20～30年経過しても劣化しない。また、防腐性、防虫性に優れた成分も含んでおり、外装や家具の素材として広く使用される。"}],"7016":[{"rank":"5","note":"","exp":"1200","type":"財宝","name":"青い点状装飾のガラス器","desc":"伽耶時代の古墳群から発掘された透明なガラスの器。表面には青い点状の装飾が施されている。5世紀後半頃に作られ、東西の交易を通じて新羅経由で伝来したと考えられる。"}],"6976":[{"rank":"2","note":"発見物カード:130","exp":"260","type":"化石","name":"鳥のような足跡のある石","desc":"鳥の足跡に似た痕跡がある化石。四本の指の跡がはっきりと見てとれるが、果たしてどのような姿をしていたのだろうか？"}],"5803":[{"rank":"2","note":"","exp":"250","type":"地理","name":"シャーマン岩","desc":"浜辺のシャーマン達の信仰の対象とされている岩山。その周辺で一日中祈りをささげ、翌日になっても凍死していなければ、潔白な人物であると認められることだろう。"}],"1333":[{"rank":"1","note":"書きかけの地図","exp":"155","type":"地理","name":"バンダ海","desc":"セレベス島の南東にある海。200以上の小島があるといわれる。この小島のどれかに貴重な香辛料の原産地があるのかもしれない。"}],"2987":[{"rank":"1","note":"書きかけの地図","exp":"180","type":"地理","name":"コッド岬","desc":"北米北部にある半島。全体が腕のような形をしており、夏は涼しく冬は暖かい。魚のタラがよく捕れることからケープ（岬）、コッド（タラ）と呼ばれるようになった。"}],"1875":[{"rank":"2","note":"湖に降り立つ神","exp":"300","type":"宗教遺物","name":"ヴィラコチャのレリーフ","desc":"ヴィラコチャとは、インカ帝国において信仰されている太陽神である。肌が白く顎ひげをたくわえた大柄な男性として描かれ、人々に文明をもたらした神といわれている。文明を与えた後はクスコの湖岸から水を渡り姿を消した。"}],"1513":[{"rank":"3","note":"釈迦牟尼仏像","exp":"506","type":"宗教遺物","name":"釈迦牟尼仏像","desc":"しゃかむにぶつぞう。仏教の開祖である釈迦（しゃか）の像。釈迦は名門の家に生まれたが、のちに出家した。生まれ出たときに二本の足で歩き、言葉を発したといわれる。"}],"6319":[{"rank":"2","note":"","exp":"380","type":"財宝","name":"被蓋造りの手箱","desc":"日本で作られた小箱。下の部分よりも上の蓋を大きく作ってかぶせる構造になっている。箱の表面は漆で加工され細やかな模様が描かれている。経典を入れる箱として使われることもあるという。"}],"1988":[{"rank":"1","note":"釣り","exp":"160","type":"海洋生物","name":"タマカイ","desc":"南太平洋およびインド洋に分布する、体長数メートルにも達する巨大なハタ。"}],"145":[{"rank":"4","note":"クレタ島の伝説","exp":"636","type":"歴史遺物","name":"ラブリュス","desc":"エーゲ海で栄えたクレタ文明における宗教的な象徴。両刃の斧で、さまざまな場所に刻印されている。ミノス王の宮殿は、ラビュリントスと呼ばれる。"}],"530":[{"rank":"1","note":"古代の道具の地図","exp":"51","type":"歴史遺物","name":"古代の陶器","desc":"土の素地に釉薬（ゆうやく）をかけて焼いた器。技術が発達してくると、さまざまな色の物や、彩色した物が出てくる。"}],"2408":[{"rank":"3","note":"琉球のカエル","exp":"440","type":"小型生物","name":"イシカワガエル","desc":"奄美大島及び沖縄本島に生息するカエル。\n緑地に紫色の宝石をちりばめたような体は、日本で最も美しいカエルと呼ばれるにふさわしい。"}],"4982":[{"rank":"4","note":"","exp":"630","type":"地理","name":"エーゲ海","desc":"バルカン半島とアナトリア半島に挟まれた内海。多くの島がある。エーゲ海周辺は古代ギリシャ最古の文明であるエーゲ文明の発祥の地で、古くから繁栄している海域である。"}],"3308":[{"rank":"2","note":"書きかけの地図","exp":"250","type":"地理","name":"スカイ島","desc":"ブリテン島北部、西側にある島。\n名前の由来は古代ノルド語からとった説と、北欧神話の神・スカアハの名からとった説の両方がある。時に「霧の島」とも呼ばれる。"}],"4848":[{"rank":"2","note":"巨鳥の夢","exp":"250","type":"鳥類","name":"オニアオサギ","desc":"南アフリカから西アジアにかけて生息する鳥類。サギ科最大の種であり、体長約1.5ｍ、翼長は２ｍにもと達する。"}],"5698":[{"rank":"5","note":"","exp":"1370","type":"地理","name":"クルクシェートラ平原","desc":"『マハーバーラタ』の物語において、最終決戦が行われた場所。バラタ民族にとっては、聖なる地であったようだ。"}],"971":[{"rank":"1","note":"宝物の要塞","exp":"135","type":"史跡","name":"ビブロス","desc":"古代の砦や街の遺跡。幾度も支配勢力が交替したため、複数の文明の遺構が複雑に重なり合っている。"}],"471":[{"rank":"1","note":"血に飢えた暴君","exp":"115","type":"歴史遺物","name":"コンモドゥス帝の剣","desc":"コンモドゥス帝は、最後の五賢帝マルクス・アウレリウスの息子。暴帝で自らコロッセウムに剣闘士として参加するなどしたという。"}],"748":[{"rank":"2","note":"西ローマ帝国復活","exp":"390","type":"財宝","name":"カール大帝の宝冠","desc":"東フランクの王、カール大帝が西ローマ皇帝に即位した際の宝冠。これにより西ローマが復活、帝権と教皇権の提携が確立し、ビザンツ帝国に対抗することになる。"}],"5516":[{"rank":"2","note":"","exp":"360","type":"宗教建築","name":"ラリベラの岩窟教会群","desc":"エチオピアに存在する教会堂群。石をくりぬいて作り上げた建造物は世界的に見ても非常に珍しい。具体的な建造方法はよくわかっていない。"}],"3682":[{"rank":"2","note":"丸いアザラシの地図","exp":"340","type":"中型生物","name":"ワモンアザラシ","desc":"流氷域に広く生息する小型のアザラシ。体型は丸い。\n背中側に黒と灰色の斑紋がある。"}],"2895":[{"rank":"4","note":"芸能の新しい流れ","exp":"800","type":"財宝","name":"京劇服","desc":"「京劇」と呼ばれる中国の芸能で着用する衣装。民衆の間で発展した演劇「戯曲」が都で人気を博し、「京劇」と呼ばれるようになった。演目の題材には、三国志演義や水滸伝など、大衆に人気が高かったものが多い。"}],"6766":[{"rank":"2","note":"発見物カード:165","exp":"330","type":"虫類","name":"トドノネオオワタムシ","desc":"アブラムシの一種。蝋質の分泌物を身にまとい、綿のような見た目をしている。秋の終わりに大量発生すると、群れて飛ぶ。それが雪が降るように見えることから、「雪虫」という異名を持つ。"}],"1500":[{"rank":"1","note":"山猫の地図","exp":"70","type":"中型生物","name":"ボブキャット","desc":"ヤマネコの一種。しまや斑模様がある。それほど大型ではない。頬の毛が長く、尾が短いのが特徴。"}],"5748":[{"rank":"2","note":"2017.02.07新規追加","exp":"","type":"地理","name":"アンガラ川","desc":"バイカル湖から流れ出す唯一の川。湖の南西端から北に向かって流れ、複数の川と合流したうえで最終的には北極海に流れ込む。"}],"2668":[{"rank":"3","note":"黒い顔の渡り鳥","exp":"510","type":"鳥類","name":"クロツラヘラサギ","desc":"朝鮮半島北西部でよく見られるサギの一種。全身の羽毛は白く、顔とくちばしだけが真っ黒なため、その部分が目立つ。\n夏になると、首が黄色く変化し、後頭部から黄色の冠羽が生えてくる。"}],"6251":[{"rank":"2","note":"","exp":"310","type":"歴史遺物","name":"プリニウスの博物誌","desc":"古代ローマの政治家・博物学者であった大プリニウスの著作で、全37巻にわたって地理・天文・歴史・自然を網羅している。世界七不思議とされた建造物についても述べられているほか、各地で見聞きした怪物などについての記録もある。"}],"1961":[{"rank":"2","note":"アンデスの儀式道具の地図","exp":"220","type":"宗教遺物","name":"儀式用盃","desc":"アンデスの各農村部では、この盃を酌み交わし団結を誓う儀式が執り行われる。盃の底には二頭のウシが作られており、団結を誓い合った者たちの力をさらに高めるという。"}],"1635":[{"rank":"1","note":"フィジー諸島の近海調査","exp":"100","type":"地理","name":"コロ海","desc":"フィジー諸島が囲い込む内海を指す。内海であるにも関わらず、水深が深い。しかし、諸島周辺の浅瀬はサンゴ礁に覆われており、幻想的な景観で、見る者を魅了する。"}],"3762":[{"rank":"5","note":"クエスト「宝瓶宮の調査」<br/>発見物カード:510","exp":"1020","type":"天文","name":"みずがめ座","desc":"黄道十二星座の1つ。オリンポス十二神に不死の酒ネクタルを給仕するガニュメデスの姿とされる。古代メソポタミアでは水の神エンキにつながる、水が流れ出る壷を持った男の姿で描かれ、偉大なるものという意味のグラと呼ばれていた。"}],"326":[{"rank":"1","note":"ローマ皇帝の騎乗像","exp":"75","type":"歴史遺物","name":"マルクス・アウレリウス帝騎馬像","desc":"古代ローマ五賢帝最後の一人マルクス・アウレリウス帝の青銅像。騎乗像としては最古の物だと思われる。美術作品としての価値だけにとどまらず、当時の馬具の研究材料として重要である。"}],"1170":[{"rank":"4","note":"コルテスが連れた娘","exp":"612","type":"財宝","name":"マリンチェの首飾り","desc":"マリンチェとはコルテスの妻となったアステカ人女性。ナワトル語とマヤ語に通じ、コルテスの通訳として協力した。これは西洋風のデザインで、コルテスが本国から持ち込んだネックレスを贈ったものだと思われる。"}],"1326":[{"rank":"2","note":"クエスト「列島のさらに東へ」<br/>発見物カード:165","exp":"330","type":"地理","name":"小スンダ列島","desc":"ジャワ島以東の比較的小さな島々の総称。あまりに多くの島があるため、全容を把握することは難しい。島それぞれに独自の文化がある。"}],"2375":[{"rank":"3","note":"飼いやすい愛玩犬","exp":"520","type":"中型生物","name":"チン","desc":"中国から朝鮮を通じ、日本へ伝わったといわれる犬。体高は25cmほどしかない。\n毛並みは繊細でつやがあり、性格は穏和でおとなしい。屋内での飼育に向いた愛玩犬である。"}],"1266":[{"rank":"2","note":"トカゲの骨の地図","exp":"225","type":"化石","name":"鳥のようなトカゲの骨","desc":"全体を見るとトカゲに似た形をしているが、頭の部分が鳥のくちばしのように細くなっている。だが、翼があった形跡は見られない。これは、鳥とトカゲの中間にあたる生物だったのだろうか。"}],"4973":[{"rank":"2","note":"クエスト「古代ギリシャの吟遊詩人」<br/>発見物カード:135","exp":"270","type":"天文","name":"いるか座","desc":"船乗りに殺されかけた吟遊詩人アリオンを助けたイルカが天に上った姿とされる星座。アリオンはシチリア島の音楽祭で優勝し、帰路に賞品を狙う船乗りに襲われた。"}],"1916":[{"rank":"1","note":"きらびやかな甲冑の地図","exp":"140","type":"財宝","name":"宝飾甲冑","desc":"金銀宝石で飾り立てられた甲冑。重さ、強度ともに、まったく実用的ではない。貴族が贅を凝らして作ったものである。"}],"59":[{"rank":"2","note":"インドのゾウ使い","exp":"360","type":"美術品","name":"象牙の笛","desc":"アフリカで作られた、象牙製の笛。素朴で独特の彫刻が施されており、象牙本来の美しいカーブが生かされている。装飾品ではなく、実用にされていたと思われる。"}],"1291":[{"rank":"5","note":"仏陀を護る蛇","exp":"1014","type":"宗教遺物","name":"ナーガ上の仏陀","desc":"とぐろを巻いた蛇の上に、座禅を組む仏陀の像。蛇はムチャリンダといい、瞑想に入った仏陀を七日の間風雨から守ったといわれる。"}],"3175":[{"rank":"2","note":"書きかけの地図","exp":"240","type":"地理","name":"ファーヴェル岬","desc":"グリーンランドの最南端に位置する岬。\nグリーンランドは大部分が氷雪に覆われた土地だが、夏にはこうした岬などの沿岸部で大地を目にすることができる。"}],"1285":[{"rank":"4","note":"悠久の微笑み","exp":"624","type":"宗教建築","name":"アンコール遺跡","desc":"アンコール王朝の都市遺跡。スーリヤヴァルマン2世によって建設されたアンコール・ワットと、ジャヤヴァルマン7世によって建設された、アンコール・トムが有名である。"}],"1323":[{"rank":"2","note":"巨大な湿地帯","exp":"270","type":"地理","name":"カマウ半島","desc":"ヤーデインの西にある半島。古来より北方との交易の要衝として栄えてきた地域である。広大な湿地帯のため、農業を行うには高い灌漑技術が要求される。"}],"1171":[{"rank":"5","note":"羽飾り","exp":"816","type":"鳥類","name":"オウギタイランチョウ","desc":"鮮やかな色の扇のようなとさかを持つ。オスのとさかは赤、メスのものは黄色で、ともに先端が青い。"}],"2921":[{"rank":"2","note":"ダンジョン","exp":"370","type":"歴史遺物","name":"地下墓地の骨","desc":"リマの教会地下に葬られた人骨。頭蓋骨や他の部分の骨が、絵画のように並べられている様は圧巻である。\n骨の損傷はあまりなくどれも原形を保っている。"}],"567":[{"rank":"1","note":"古文書の地図","exp":"23","type":"歴史遺物","name":"羊皮紙の古文書","desc":"羊の皮を薄く加工した羊皮紙で作られた本。安定性が高く保存によい。中世では本はすべて写本だったので、非常に高価で貴重な物だった。"}],"2562":[{"rank":"5","note":"地に張り付くチョウ","exp":"1030","type":"虫類","name":"イシガケチョウ","desc":"主に東アジアに生息する、白地に黒の細かい筋模様が複雑に入った羽を持つチョウ。\n羽を水平に開いて止まる習性を持つ。人の気配に敏感で、近付くとすぐに逃げてしまう。"}],"6745":[{"rank":"3","note":"","exp":"450","type":"鳥類","name":"モモアカノスリ","desc":"新大陸に生息する中型の猛禽類。群れを成して狩りを行うという、猛禽類では珍しい習性を持つ。人間に親しみやすく、飼育しやすい鷹として知られる。別名はハリスホーク。"}],"5166":[{"rank":"1","note":"到達する","exp":"37","type":"港・集落","name":"ヤッファ","desc":"紀元前から存在する、歴史のある街。さまざまな文明の交流点で、歴史の舞台として興味深い土地である。乾燥気味の土地に適した作物が栽培されるほか、この地方の特色である高い製鉄技術による産物が流通している。"}],"1959":[{"rank":"2","note":"古代神の復活","exp":"350","type":"宗教遺物","name":"マケマケ像","desc":"マケマケとはラパ・ヌイでモアイ以前より信仰されていた神であるようだ。マケマケの化身である鳥人（タンガタ・マヌ）の称号を得た者が島の全権を有することから、ラパ・ヌイで崇められている神の中で、中心的な存在であるといえる。"}],"3254":[{"rank":"4","note":"王者の花","exp":"700","type":"植物","name":"キング・プロテア","desc":"南アフリカに分布する花木。丈はおよそ2mまで伸び、直径30cm程度の風格のある立派な花を咲かせる。"}],"6743":[{"rank":"3","note":"","exp":"1080","type":"地理","name":"サオナ島","desc":"イスパニョーラ島のサントドミンゴから南東にある島。コロンブスの２回目の航海で発見されたという。サンゴ礁に囲まれており、鳥類や海洋生物が数多く生息している。透き通るような海と白い砂浜が美しい。"}],"1886":[{"rank":"4","note":"サルベージ","exp":"636","type":"歴史遺物","name":"サンタ・マリア号","desc":"探険家クリストバル・コロン一回目の航海で旗艦を務めたナオ。\n大西洋横断後の1492年クリスマスイブに、イスパニョーラ島の暗礁に乗り上げ、航行不能に陥った。"}],"6382":[{"rank":"3","note":"","exp":"600","type":"小型生物","name":"モルモット","desc":"南米などに生息するネズミ。性格はおとなしく、警戒心が強い。ストレスがあると食事を取らなくなることもある。群れで行動し、鳴き声でお互いの意思疎通を行う。モルモット独特の跳躍がある。"}],"3802":[{"rank":"4","note":"海洋冒険物語のネタ<br/><br/>発見時経験値680　発見物カード経験値340","exp":"680","type":"財宝","name":"ある船乗りの漂流記","desc":"スコットランド出身の航海長であるアレキサンダー・セルカークの無人島生活についての著述。自給自足の生活の様子が生々しく記されている。"}],"5632":[{"rank":"4","note":"東ベーリング海","exp":"660","type":"気象・現象","name":"穴あき雲","desc":"薄く広がり、中央部が円形に開いた雲。開いた部分には垂れ下がるように別の雲が形成されることもある。"}],"5945":[{"rank":"2","note":"","exp":"260","type":"植物","name":"ギニアショウガ","desc":"西アフリカなどに生息する植物。メレゲッタとも呼ばれる。乾燥した種子はピリッとした辛さを持つ香辛料であり、地方によってはコショウの代わりに用いられる。"}],"999":[{"rank":"1","note":"冒険者のバイブル","exp":"55","type":"財宝","name":"東方見聞録","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。"}],"4839":[{"rank":"2","note":"クエスト「バベルのモデル」<br/>発見物カード:190","exp":"380","type":"宗教建築","name":"マルウィヤ・ミナレット","desc":"アッバス朝の第8代カリフ、ムウタスィムがサーマッラーに建設した貴重な螺旋式のミナレット。絵画などに描れたバベルの塔の外見はこの塔をモデルにしたものが多い。"}],"194":[{"rank":"5","note":"ダ・ヴィンチの真筆","exp":"1105","type":"美術品","name":"岩窟の聖母（真筆）","desc":"読みは「がんくつのせいぼ」。レオナルド・ダ・ヴィンチ作の絵画である。ミラノのある聖堂の依頼で描かれた物だが、報酬で折り合わず、このオリジナルは渡されなかったという。絵には聖母子と聖ヨハネ、天使が描かれている。"}],"3329":[{"rank":"2","note":"「赤いオオカミの地図」<br/>発見物カード:155","exp":"310","type":"中型生物","name":"アメリカアカオオカミ","desc":"北米の中部および南部に生息するオオカミの一種。同様の地域にすむコヨーテと似ているが、コヨーテよりやや大型である。体色には個体差があるが、総じて赤みがかっている。"}],"5526":[{"rank":"4","note":"発見時経験値800　発見物カード経験値400","exp":"800","type":"気象・現象","name":"接線弧","desc":"太陽の周囲に弧状の光の帯が発生する現象。虹のように複数の色の帯で構成される。通常の虹と比べ目視は非常に困難であり、数年に一度観測できるかどうかである。"}],"1491":[{"rank":"1","note":"跳ねるネズミの地図","exp":"60","type":"小型生物","name":"カンガルーネズミ","desc":"非常に発達した後ろ足で跳ねるネズミ。ネズミとしては大きいほうである。"}],"5243":[{"rank":"1","note":"","exp":"200","type":"中型生物","name":"サイガ","desc":"象のような鼻を持つ奇妙な生物。地元では食料や毛皮にするため捕獲されており、角には薬としての成分が含まれるとされているが真偽は不明である。"}],"5528":[{"rank":"3","note":"サハラの川沿いの向こう側に砂嵐があられる現象。<br/>川沿いの場所は砂嵐が起きません。","exp":"220","type":"気象・現象","name":"ハブーブ","desc":"アフリカ北部の砂漠地帯などで発生する巨大な砂嵐。ときには都市ひとつをのみ込むほどの大きさになる。移動が速く、発見した際には屋内への迅速な避難が求められる。"}],"5797":[{"rank":"5","note":"暴君の杯","exp":"1340","type":"歴史遺物","name":"ネロの杯","desc":"しっかりとした作りの杯。暴君ネロがよく毒殺に用いたという噂がある。毒がしみこむはずもないが、使用するのはやはり抵抗があるだろう。"}],"2020":[{"rank":"2","note":"［勅命］[[新大陸西岸進出の先人の記録","exp":"310","type":"歴史遺物","name":"マゼラン南米冒険記","desc":"マゼランが南米で航海を中断していた時に記したと思われる書物。先住民族などについて記載されている。"}],"6516":[{"rank":"5","note":"","exp":"","type":"地理","name":"モエラキ・ボールダーズ","desc":"ニュージーランド南島にあるモエラキ海岸に転がる、巨大な球状の岩石。表面に亀甲状の割れ目がある。マオリの伝説では、沿岸に座礁した大カヌー・アライテウル号から漂着した、ヒョウタン型のウナギを入れるかごが変化したものだという。"}],"1184":[{"rank":"2","note":"クエスト「悲劇の十字軍」<br/>発見物カード:135","exp":"270","type":"宗教遺物","name":"エティエンヌの杖","desc":"少年十字軍を率いた、羊飼いの少年・エティエンヌが持っていたという杖。歴史の犠牲になった、少年少女の無念がこもっているようだ…。"}],"3871":[{"rank":"2","note":"奇妙な石の地図","exp":"240","type":"化石","name":"長いトサカを持つドラゴンの骨","desc":"北米で発見された、長いトサカを持つドラゴンの骨。頭部の大きさから類推するに、体もかなり大きいと思われる。"}],"3684":[{"rank":"2","note":"書きかけの地図","exp":"390","type":"地理","name":"チュクチ山脈","desc":"チュクチ半島の根元に広がる大きな山脈。近辺には他にも山脈が走り、周辺全体が山がちであるということが分かる。"}],"2567":[{"rank":"2","note":"金の都","exp":"370","type":"美術品","name":"洛中洛外図","desc":"日本の都である京の街中と郊外を、高い位置から見下ろした構図で描いた屏風絵。\n華美な美術品であると同時に、街や人々の様子を示す史料ともなり得る。"}],"6642":[{"rank":"5","note":"レガシー商の叡智・財貨の交易路　左上","exp":"","type":"史跡","name":"ウバール遺跡","desc":"紀元前、乳香の貿易によって栄えたオアシス都市の遺跡。残存する要塞の壁から推測するに、乳香の交易路の要衝として往時は栄えていたと考えられる。"}],"6070":[{"rank":"3","note":"伝承","exp":"420","type":"伝承","name":"世界の果て","desc":"カナリア諸島の南方にあるボジャドール岬。かつての船乗りたちにとって、その岬の先は未知の海域だった。溶岩が噴出する煮えたぎった魔の海…そんな迷信は、エンリケの勇敢な部下が岬越えを達成するまで船乗りたちを縛り続けた。"}],"5074":[{"rank":"2","note":"到達する","exp":"305","type":"港・集落","name":"ジャカルタ","desc":"ジャワ島北西岸に位置する街。もとは「スンダ・クラパ」と呼ばれた、スンダ人の小さな集落だった。スンダ人はパジャジャラン王国を築き、マジャパヒト王国の侵攻にも屈しなかった。"}],"2678":[{"rank":"2","note":"高麗の記録","exp":"270","type":"財宝","name":"高麗輿地志図書","desc":"読みは「こまよちしずしょ」。中国から訪れた使臣が、開城を訪れた際にまとめた書物とされる。\n記述では、その使臣は高麗の安和寺という寺院に立ち寄ったとのことだ。"}],"5394":[{"rank":"3","note":"発見時経験値530　発見物カード経験値265","exp":"530","type":"海洋生物","name":"スルビ","desc":"パラグアイ川上流付近に生息するナマズの仲間。黒い縦縞が特徴の大きな魚で、その身はとても美味である。"}],"787":[{"rank":"1","note":"太陽神の像","exp":"60","type":"宗教遺物","name":"アポロン像","desc":"ギリシャ神話の神の像である。アポロンは予言をよくする神で、デルフォイの神託はアポロンのものとされる。音楽、弓、スポーツなどを得意とする美しい神である。太陽神・ヘリオスと同一視されることもある。"}],"2739":[{"rank":"2","note":"朝鮮王朝政治の基準","exp":"380","type":"財宝","name":"経国大典","desc":"朝鮮王朝の政治の規範となっている法典。\n政治の他、経済、文化軍事など、各方面の規制が記されているという。過去に何度か改定が加えられた。"}],"2837":[{"rank":"3","note":"不可解な土塊","exp":"500","type":"歴史遺物","name":"封泥","desc":"読みは「ふうでい」。書物などに封をする時に使用された粘土で、後漢まで続いた。\n開封する際は、この封泥を壊さなければならなかったため、他者に開封されることを防いだ。この封泥には皇帝信璽と書かれており、皇帝の印だと分かる。"}],"2704":[{"rank":"3","note":"洋上怪物騒動","exp":"510","type":"地理","name":"竜頭岩","desc":"済州島の海岸にある、竜の頭のような形をした岩。\n白鹿潭に棲んでいた竜が海に出ようとしたところ、天帝の怒りに触れ、石にされたという伝説がある。"}],"5804":[{"rank":"3","note":"釣り発見物<br/>エディンバラの北","exp":"600","type":"海洋生物","name":"センジュエビ","desc":"深海に生息する小型のエビ。すべての脚にハサミがついており、一見するとすべての脚が手に見えることが名前の由来だと思われる。"}],"6218":[{"rank":"2","note":"","exp":"230","type":"化石","name":"巨大な鳥の骨","desc":"密林で見つかった、非常に巨大な鳥の骨。翼を閉じた状態であっても、人間より体が大きい。頑丈そうで大きな足を持っていることから、大きな魚や動物を捕らえて食べていたのかもしれない"}],"6159":[{"rank":"5","note":"","exp":"1200","type":"小型生物","name":"タルバガン","desc":"モンゴルやロシアなどに生息するげっ歯類の一種。別名、シベリアマーモット。遊牧民たちが肉や毛皮を求めて狩り、「東方見聞録」にも記述が見られるという。ペストを媒介するとされ、接触には細心の注意を払う必要がある。"}],"1716":[{"rank":"5","note":"釣り","exp":"816","type":"海洋生物","name":"地中海カジキ","desc":"地中海特有のカジキ。他のカジキと比べ、上アゴのクチバシが短いようだ。"}],"3592":[{"rank":"","note":"","exp":"","type":"レリック","name":"太陽神アテン","desc":"アテン神信仰がもたらした自由で写実的なアマルナ美術は、固定化されつつあった古代エジプト芸術に新たな息吹を吹き込んだ。"}],"511":[{"rank":"1","note":"古代の貨幣の地図","exp":"175","type":"歴史遺物","name":"古代インドの銀貨","desc":"古代インドで使われていた銀貨。古代インドの通貨は、ほとんどが銀であったという。円や角型のほか、はしを削って重量を調整した多角形のものもある。"}],"2529":[{"rank":"2","note":"一味違う街路樹","exp":"360","type":"植物","name":"タイワンモクゲンジ","desc":"主に台湾島に生息する黄色い花を咲かせる植物。桃色の房状の果実は花と見間違うほど小粒である。\n秋を告げる木ともいわれる。"}],"1782":[{"rank":"2","note":"人並みはずれた想像力","exp":"290","type":"美術品","name":"犀","desc":"アルブレヒト・デューラー作の木版画。デッサンしたかのように細部まで緻密に描かれているが、デューラー自身は犀を一度も見たことがない。ゆえに、この木版画はデューラーの並外れた想像力と表現力を証明する一枚ともいえるだろう。"}],"6461":[{"rank":"5","note":"","exp":"1650","type":"鳥類","name":"繁殖羽のクロツラヘラサギ","desc":"朝鮮半島北西部でよく見られるサギの一種。渡り鳥で広い範囲で越冬のために南下する。通常期は、全身の羽毛が白いが、夏場の繁殖期には首が黄色く変化し、後頭部から黄色の冠羽が生えてくる。"}],"911":[{"rank":"1","note":"白い鳥の地図","exp":"13","type":"鳥類","name":"ハクチョウ","desc":"優雅な長い首と美しい白い羽で知られる、大型の水鳥。渡り鳥で、半年ごとに移動する。灰色の個体も見かけるが、どうやら若鳥のようである。"}],"1478":[{"rank":"5","note":"ヴィシュヌが手を貸す美しさ","exp":"1040","type":"宗教遺物","name":"チナラート仏","desc":"スコータイ時代に作られた仏像の一つ。この時代の仏像は、ふっくらした丸い顔に、丸みを帯びた体つきが特徴である。男性像でも腰のくびれがあり、写実的な西洋像とは一線を画す。この像の制作にヴィシュヌ神が手伝ったという伝説がある。"}],"6343":[{"rank":"2","note":"","exp":"260","type":"史跡","name":"アッラーヴェルディ・ハーン橋","desc":"中東にある全長約300mの長い橋。「スィー・オ・セ橋」とも呼ばれる。33ものアーチがありイスラム建築様式のひとつであるサファヴィー建築の様式で造られている。"}],"131":[{"rank":"1","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40","type":"宗教遺物","name":"聖母のステンドグラス","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。"}],"273":[{"rank":"1","note":"ペガサスと女神の大理石像","exp":"120","type":"美術品","name":"天馬にまたがる名声の女神","desc":"高さ3mを超える、巨大な大理石像。ペガサスに乗った女神がラッパを吹き鳴らしている姿である。宮殿の水場を飾るために作られたという。"}],"723":[{"rank":"2","note":"生者の街","exp":"290","type":"宗教建築","name":"カルナック・ルクソール神殿","desc":"歴代のファラオたちが次々に増改築を繰り返した神殿群。複数の神殿があり、数多くの神像やファラオの像、大石柱が立ち並ぶ様は壮観である。"}],"2808":[{"rank":"2","note":"貴重な書物の地図","exp":"260","type":"財宝","name":"永楽大典","desc":"天文・地誌・陰陽などのさまざまな書を原本で収集した書類。明代以前の貴重な文献まで網羅している。\nしかし、二万巻以上に及ぶ膨大な書物となったため、一部しか写本になっていない。"}],"3389":[{"rank":"5","note":"天地創造の叙事詩","exp":"1400","type":"歴史遺物","name":"エヌマ・エリシュ","desc":"バビロニア神話における創世記叙事詩。数多くの神々の名が記されており、かつて栄えたバビロン帝国が他の都市に比べ優れているかが記されていると思われる。"}],"7013":[{"rank":"5","note":"北東太平洋視認","exp":"","type":"天文","name":"ルクバト","desc":"いて座のアルファ星だが、星座を構成する星としては16番目に明るい4等星。ケンタウロスの前脚の膝の位置にあたり、アラビア語で「射手の膝」を意味する。"}],"1205":[{"rank":"3","note":"銀と川","exp":"484","type":"地理","name":"ラプラタ川","desc":"南米南東岸に河口を持つ大きな川。その河口は非常に大きく、戦艦も入り込めそうなほどだが、水深が浅く、一般的な船での遡上は無理だろう。"}],"5882":[{"rank":"2","note":"","exp":"1380","type":"地理","name":"化石の森","desc":"どんな理由か、多くの樹が宝石のようになっている。高々とそびえる樹はないが、森としか形容できない場所である。"}],"5057":[{"rank":"1","note":"到達する","exp":"29","type":"港・集落","name":"サッサリ","desc":"サルデーニャ島の北部に位置する街。南部のカリアリと同じく、さまざまな文化が共存する。"}],"1315":[{"rank":"2","note":"香りたつ海","exp":"320","type":"地理","name":"モルッカ海","desc":"セレベス島の東に位置する海。多くの島があり、それぞれに独自の民族が生活しているようだ。また、貴重な香辛料を産出する島があることでも知られている。"}],"1259":[{"rank":"4","note":"海を渡るアフリカ人","exp":"636","type":"歴史遺物","name":"オルメカの巨大頭像","desc":"メソアメリカ文化の中でも古い部類とされるオルメカの巨大頭像。小さなものは成人女性の身長くらい、大きなものはその倍くらいあり、数多く見つかる。"}],"585":[{"rank":"1","note":"豪華な宝石細工の地図","exp":"19","type":"財宝","name":"めっきのはげた首飾り","desc":"美しい細工がされた首飾りだが、めっきを施した物で、それほど価値はないようだ。めっきがはげてしまい、みすぼらしい。"}],"6056":[{"rank":"5","note":"","exp":"","type":"財宝","name":"聖母マリアのカンティガ集","desc":"カスティーリャ王アルフォンソ10世が自ら手がけたといわれる聖母賛歌集。\n彼の治世は軍事や内政で失敗続きだったが、文化事業においては多大な影響を残し、この歌集はその代表作とみなされている。"}],"5547":[{"rank":"4","note":"クエスト「消える巨大カニ」<br/>発見物カード:320","exp":"640","type":"海洋生物","name":"ヤシガニ","desc":"大型の甲殻類。一見カニのように見えるが、実はヤドカリの仲間のようだ。かなりの雑食性であり、木の実から死肉まで幅広く食す。食用目的に各地で乱獲が続いており、保護が必要になる可能性もある。"}],"4792":[{"rank":"","note":"クエスト「主食にできる木の実」<br/>発見物カード:120","exp":"240","type":"植物","name":"パンノキ","desc":"オセアニアで栽培されている植物。その実は蒸し焼きや丸焼きなどにして食べられる。加工することで日持ちのする非常食にすることもできる便利な作物である。"}],"6613":[{"rank":"5","note":"レガシー美の叡智　上","exp":"1800","type":"財宝","name":"プスケント","desc":"古代エジプトのファラオのみが身につけることを許された、紅白の冠。ファラオの二重冠とも呼ばれ、上エジプト、下エジプトの二つの冠を組み合わせて作られている。"}],"807":[{"rank":"2","note":"大河に潜む獣","exp":"250","type":"大型生物","name":"ナイルワニ","desc":"ナイル川流域で多く見られるワニ。大きい個体で6mを超え、非常に凶暴で危険。古代エジプトでは神の使いとして崇拝されていたという話だ。川底で待ち伏せ、獲物を襲う。"}],"3902":[{"rank":"1","note":"学生の観測記録","exp":"100","type":"天文","name":"夏の大三角","desc":"ヨーロッパの夏の夜空でやや細長い三角形を作る三つの1等星。天の川にかかり、他の星や星座を探す目印となる。"}],"5012":[{"rank":"1","note":"到達する","exp":"110","type":"港・集落","name":"アゾレス","desc":"大西洋の中央に位置する火山島の街。15世紀前半、ポルトガルによって発見されて以来、ヨーロッパ列強各国からの移住者が、多くいる。新大陸への遠洋航海における足がかりとなっている。"}],"3017":[{"rank":"4","note":"銅板に刻まれた有翼人","exp":"660","type":"歴史遺物","name":"鳥人の銅板","desc":"独特の装飾を施された銅製の板。翼を持った人物の姿が打ち出されている。\n北米のエトワー川近辺で、身分の高い人物の副葬品として墳墓に納められていた。"}],"1417":[{"rank":"2","note":"メソアメリカの祭器の地図","exp":"290","type":"宗教遺物","name":"モザイクの円盤","desc":"ターコイズでできたモザイクの円盤。非常に高度な技術を用いて作られている。アステカでは、その色味を神聖なものとして、祭礼にターコイズを用いたようだ。"}],"5054":[{"rank":"2","note":"到達する","exp":"260","type":"港・集落","name":"コピアポ","desc":"南北に長く広がる砂漠の南に位置する、オアシスの街。降雨が少なく、水は貴重である。"}],"6260":[{"rank":"2","note":"","exp":"310","type":"歴史遺物","name":"カラフ","desc":"アイルランドに古代から伝わる獣皮船の一種で、カエサルやプリニウスなどの著作にも記述がある。船体にオークの樹皮でなめした革を張り、獣脂を塗りつけているのが特徴。\n一説ではブレンダンの航海に使われたのも同種の船だという。"}],"6403":[{"rank":"5","note":"レガシー：ハリカルナッソス","exp":"2250","type":"史跡","name":"ミンドスの門","desc":"カリアの王マウソロスがハリカルナッソスに築いた堅固な城門。アレクサンドロス大王の攻撃にも容易に落ちず防衛の要となった。しかし陥落後、ハリカルナッソスの市街地はアレクサンドロスの軍勢に破壊されてしまったという。"}],"2071":[{"rank":"2","note":"尾の長いサメ","exp":"350","type":"海洋生物","name":"ニタリ","desc":"太平洋熱帯域に生息。胴体と同じくらい長い尾が特徴で、尾をムチのように叩いて小魚を捕まえる。\nサメとしては珍しく、海面を跳ねることも。性格はわりとおとなしい。"}],"6736":[{"rank":"5","note":"発見物カード:410","exp":"820","type":"天文","name":"ゴメイサ","desc":"こいぬ座を構成する星で、小犬の首辺りに位置する。名前はアラビア語で「小さな涙ぐんだもの」を意味する。"}],"2815":[{"rank":"2","note":"古代史の資料","exp":"370","type":"歴史遺物","name":"史記","desc":"古代から漢代までを記した歴史書。\n初めは「太史公書」と名付けられたが、のちに「史記」と呼ばれるようになったという。"}],"6223":[{"rank":"1","note":"小さなイノシシの地図","exp":"200","type":"小型生物","name":"コビトイノシシ","desc":"インド北東部からヒマラヤ山脈南部にかけて生息するイノシシ。その名の通りイノシシの仲間の中では最小とされる。全身が褐色や黒褐色の体毛で覆われ、湿気の多い草地を好むという。体が小さいため、天敵も多いと推測される。"}],"1530":[{"rank":"1","note":"大きなチョウの地図","exp":"110","type":"虫類","name":"メガネトリバネアゲハ","desc":"黒い大きな模様に、黄金色がかった緑の羽を持つチョウ。羽を広げると、大人の手のひらほどもある。"}],"1987":[{"rank":"1","note":"釣り","exp":"160","type":"海洋生物","name":"スヌーク","desc":"低い体高に尖った細長い顎が特徴のスズキに似た魚。大きなものは1mを超える。"}],"3197":[{"rank":"5","note":"クラーケンの伝説","exp":"990","type":"海洋生物","name":"ダイオウイカ","desc":"巨大なイカの一種。全長は10m以上にもなるといわれる。深海に生息していると考えられており、生きている姿が見られるのは非常に稀である。"}],"3188":[{"rank":"1","note":"書きかけの地図","exp":"200","type":"地理","name":"ルイスヒルズ","desc":"北米北東部沿岸の、テラ・ノヴァ西部に位置する山。標高は814mであり、同じくロングレンジ山脈に属するグロスモーン山よりもやや高く、テラ・ノヴァで最も高い山とされる。"}],"6713":[{"rank":"5","note":"","exp":"415","type":"宗教遺物","name":"持国天像","desc":"四天王に数えられ、東方の守護神とされている仏神の像。手には宝器として琵琶を持つ。"}],"6841":[{"rank":"2","note":"発見物カード:195","exp":"390","type":"中型生物","name":"クビワペッカリー","desc":"北米、南米に広く生息するイノシシに似た動物。適応能力が高く、森林や砂漠、山などにも生息している。全身の体毛は褐色か黒色。喉元から背中にかけて帯状に白い毛が生えており、首輪をしているように見えるため、この名がついた。"}],"3378":[{"rank":"4","note":"伝説の王にまつわる遺跡","exp":"700","type":"史跡","name":"ウルク","desc":"古代メソポタミアにおいて栄えた、シュメール人の都市の一つ。古代の文字が刻まれた粘土板が多数見つかっており、かつての政治・経済の中心地であったことを物語っている。"}],"5610":[{"rank":"4","note":"発見物カード:355","exp":"710","type":"天文","name":"いて座の鳥型の星雲","desc":"いて座にある散光星雲のひとつ。不規則な形をしている。明るい星雲であり、比較的観測しやすい。"}],"372":[{"rank":"1","note":"河口付近の漁場","exp":"120","type":"地理","name":"ザンベジ川","desc":"アフリカ南東部を流れる川。アフリカでも5本の指に入るだろう。小型船が航行可能な流域が広く、この地方の重要な交通手段だ。内陸には、モシ・オア・トゥニャと呼ばれる壮大な滝があるそうだ。"}],"3747":[{"rank":"3","note":"オレンジ色の明るい星","exp":"510","type":"天文","name":"アルクトゥルス","desc":"うしかい座で最も明るい、オレンジ色の1等星。北斗七星のひしゃくの柄の部分を伸ばすように線を引いた先にある。名はギリシャ語の「熊を守るもの」という語に由来する。スピカとともに夫婦星と呼ばれることもある。"}],"5362":[{"rank":"2","note":"","exp":"380","type":"宗教建築","name":"サトゥルヌス神殿","desc":"サトゥルヌスとはローマ神殿の農耕神で、ギリシャ神話のクロノスにあたる。ローマのサトゥルヌス神殿は共和政時代に国有財産や公文書の保管庫としても用いられた。"}],"1648":[{"rank":"2","note":"ニューギニア島東の海域調査","exp":"320","type":"地理","name":"ソロモン海","desc":"ニューギニア島の東に広がる海。周囲を諸島に囲まれており、その諸島に暮らす人々は古くから交流をもっているという。雨季には突然の暴風雨に見舞われることもあるが、それ以外はサンゴ礁の発達した穏やかな海といえる。"}],"5221":[{"rank":"2","note":"エチオピア北部　再調査報酬","exp":"110","type":"歴史遺物","name":"エザナストーン","desc":"エザナ王が建立したといわれる石碑。\n王のキリスト教への改宗と、北東アフリカへの軍事遠征の記録が三つの異なる言語で刻まれている。"}],"573":[{"rank":"1","note":"紅い海","exp":"200","type":"地理","name":"紅海","desc":"アラビア半島とアフリカの間に横たわる海域である。旧約聖書の出エジプト記にも記述がある。イスラエルの民を率いたモーゼが杖を差し出すと、紅海が二つに割れ、渡れたと伝えられる。"}],"5842":[{"rank":"5","note":"","exp":"1340","type":"財宝","name":"封神演義","desc":"明代に書かれた文学作品。殷周革命時代を舞台に多くの神仙が活躍する物語。民間信仰に大きな影響を与えた。"}],"1842":[{"rank":"5","note":"精霊喪失","exp":"1040","type":"宗教遺物","name":"精霊の仮面","desc":"ニューギニアの精霊は儀式を完了した成人男性でないと見ることができないといわれている。そのため、この仮面を身につけて、女性や子供に精霊が降臨していることを伝える。"}],"6486":[{"rank":"5","note":"レガシー女神信仰の地エフェソス　下","exp":"2700","type":"歴史遺物","name":"メデューサの彫刻","desc":"メデューサをかたどった大理石彫刻。門や建物の入り口上部に掲げたと考えられる。ギリシャ神話に登場するメデューサは蛇の髪と恐ろしい顔を持つ怪物とされるが、古代アナトリアでは大地の女神だったという説もある。"}],"5204":[{"rank":"1","note":"ソールズベリー平原再調査の報酬","exp":"","type":"歴史遺物","name":"修道士のかかと","desc":"ヒール・ストーンとも呼ばれる高さ6mほどの立石。倒れないように安定させる工夫がされている。夏至の日には、ストーンヘンジ中心の祭壇石とこの石を結ぶ直線上に太陽が昇るという。"}],"5661":[{"rank":"2","note":"","exp":"220","type":"地理","name":"トドラ渓谷","desc":"アフリカ北西部に位置する雄大な渓谷。切り立った断崖が並んでおり、見事な景観を成している。"}],"5088":[{"rank":"2","note":"到達する","exp":"310","type":"港・集落","name":"タコマ","desc":"港町として栄える北米西部の街。街の東部に広大な森林が広がっており、製材業が盛んである。"}],"3589":[{"rank":"1","note":"ハワイ周辺の地理調査","exp":"115","type":"地理","name":"マウイ島","desc":"ハワイ島から一番近い島。島群の中ではハワイ島に次いで大きい。二つの小島が溶岩で繋がり、今のマウイ島になったという。"}],"191":[{"rank":"2","note":"その文字が示すもの","exp":"210","type":"地理","name":"セネガル川","desc":"アフリカ西部から大西洋に注がれる大河。乾燥地帯において豊富な水をたたえるこの河の名の由来は、ベルベル語で「川」を意味する「サナージャ」、あるいはウォロフ語で「私の舟」を意味する「スヌガル」だと言われている。"}],"5071":[{"rank":"1","note":"到達する","exp":"17","type":"港・集落","name":"シラクサ","desc":"シチリア島にある街。古代ギリシャの時代、アテナイに匹敵するほど栄えた。カルタゴに組してローマに滅ぼされて以降は、支配勢力が次々と変わった。産物は食品が中心だが、珍しい薬草が採れる。"}],"381":[{"rank":"4","note":"海中の悪魔","exp":"624","type":"海洋生物","name":"オニイトマキエイ","desc":"マンタとも呼ばれる、非常に大きなエイ。幅が5m以上にもなり、海中で優雅に羽ばたく姿は一度は見ておくべきだろう。一見すると恐ろしい姿をしているが攻撃性などはまったくなく、近づいてもゆったりと泳いでいる。"}],"1342":[{"rank":"4","note":"大きな瞳","exp":"636","type":"小型生物","name":"メガネザル","desc":"メガネのように大きな瞳が特徴のサル。目を動かせないかわりに、首を真後ろまで回転できる。"}],"6812":[{"rank":"5","note":"発見物カード経験値　475","exp":"","type":"財宝","name":"テーベの小箱","desc":"プラチナ装飾の施された純金製の小箱。古代エジプトのテーベ王朝の遺跡で見つかった。現存するなかでは、プラチナを使った最古のものとされる。"}],"6983":[{"rank":"3","note":"","exp":"","type":"宗教遺物","name":"テミス像","desc":"ギリシャ神話の法と秩序を司る女神テミスを表したとされる像。紀元前の作とされ、左手にあったと考えられる天秤は長い年月のうちに失われている。かけた右腕に剣を持っていたかどうかは定かでない。"}],"3321":[{"rank":"5","note":"黒雲渦巻く洞窟<br/><br/>発見時経験値810　発見物カード経験値405","exp":"810","type":"地理","name":"カールズバッド洞窟群","desc":"北米の南西部に位置する洞窟群。巨大な地下室や多数の鍾乳石を有する。中は無数のコウモリのすみかとなっており、日没時と夜明けには大群で出入りする様子が見られる。"}],"6809":[{"rank":"2","note":"発見物カード経験値:156","exp":"","type":"植物","name":"モニラリア","desc":"南アフリカに生息する多肉植物。モニラリア属の総称で、いくつかの種が存在する。葉は丸みを帯びて太く、長く伸びるとウサギの耳のように見える種もある。"}],"3696":[{"rank":"2","note":"毒グモの地図","exp":"340","type":"虫類","name":"ドクイトグモ","desc":"中南米に生息する、強力な毒グモ。解毒薬はなく、自然に治癒するまで痛みに耐えるしかないという。"}],"2841":[{"rank":"2","note":"古の絵画の地図","exp":"210","type":"美術品","name":"毛益の絵画","desc":"南宋時代の画家・毛益が描いた、花と動物の絵。吉祥図であると思われる。\n古い絵画でありながらほとんど色あせていない。"}],"2336":[{"rank":"1","note":"古代の集落の地図","exp":"190","type":"歴史遺物","name":"縄文人の住居跡","desc":"日本に残る、古代人の住居跡。地面を掘って床とし、そこに柱を立ててある。\nこの辺りはかつて集落だったのか、周囲には同じような跡がいくつか見られる。"}],"6636":[{"rank":"5","note":"発見物カード1,125","exp":"2250","type":"財宝","name":"アウグストゥスの硬貨","desc":"インド南部の都市にて発掘された金貨。初代ローマ皇帝・アウグストゥスの肖像が彫られている。古代インドとローマ帝国の間に貿易があったことの証とされている。"}],"5132":[{"rank":"2","note":"到達する","exp":"327","type":"港・集落","name":"ブルネイ","desc":"ブルネイ王国の中心地で、イスラム教が布教されている。石油や鉱石などを産出する、資源豊かな国である。"}],"5038":[{"rank":"1","note":"到達する","exp":"180","type":"港・集落","name":"カリカット","desc":"インド西岸にある大都市。中国～南インド～アラビア交易で栄え、富裕な商人が多い。香辛料や茶、染料、宝石など、ヨーロッパで高く売れる商品が流通している。"}],"1829":[{"rank":"3","note":"ソニュカサパ","exp":"500","type":"財宝","name":"タプ・イ・アルカ","desc":"ケチュア語で、「緑の石」を意味する、エメラルドの原石である。アンデス山脈の北部に住むチブチャ民族の族長が、祭祀を行うために祭器として用いていた。"}],"5041":[{"rank":"1","note":"到達する","exp":"17","type":"港・集落","name":"カルヴィ","desc":"ジェノヴァの南にあるコルシカ島の街。コルシカ島は、古代ローマ時代から、複数の勢力の争いの場となってきた。この街は、ジェノヴァが築いた。"}],"5602":[{"rank":"2","note":"カリブ海の入港許可があれば、上陸(発見)できます。","exp":"244","type":"港・集落","name":"ボストン","desc":"北米大陸の北東部に位置する港街。\nイングランドのピューリタンが入植し、築いた街が起こりとなっている。"}],"6715":[{"rank":"2","note":"クエスト「枯れ葉の下」<br/>発見物カード:105","exp":"210","type":"植物","name":"ハナビラタケ","desc":"カラマツなど、針葉樹の根元に自生する花のようなきのこ。湿度が高く、霧が出る場所を好む。清らかな香りと爽やかな食感を持つ。希少なきのこであるため「幻のきのこ」とも呼ばれる。"}],"1182":[{"rank":"2","note":"消えた古代人","exp":"270","type":"歴史遺物","name":"古代マヤ人の頭蓋骨","desc":"マヤの地の至るところで発掘される頭蓋骨。歯にひすいを埋めた跡があったり、扁平だったりと不気味なところがある。"}],"3185":[{"rank":"4","note":"怪物のすむ湾","exp":"720","type":"地理","name":"ファンディ湾","desc":"北米大陸東岸とノバスコシア半島の間に位置する湾。潮の干満の差が激しく、その潮位差は15mにも及ぶ。"}],"6295":[{"rank":"2","note":"","exp":"300","type":"地理","name":"バッドランズ","desc":"北米中部に位置する広大な荒地。数十万年の歳月をかけて水と風も浸食された岩山が、独特の地形を形作っている。"}],"6287":[{"rank":"2","note":"優雅な大食らい","exp":"320","type":"鳥類","name":"ケレル","desc":"アオテアロア全土に生息しているハトの一種で、別名ウッドピジョン。半神半人の英雄マウイがこの鳥によく変身したという伝説が残る。体が大きく、果実を丸呑みするほど食欲旺盛だが、発酵が進んだ果実を食べて酔うこともあるとか。"}],"2747":[{"rank":"2","note":"派生の画家","exp":"280","type":"美術品","name":"申師任堂の絵画","desc":"朝鮮の女性画家・申師任堂によって描かれた絵画。\n華麗な彩色と繊細な画風が目を引く。このように草と虫を題材にした絵は、朝鮮の画家達にとって楽しく描けるものだったようだ。"}],"128":[{"rank":"1","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40","type":"宗教遺物","name":"聖母のステンドグラス","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。"}],"2887":[{"rank":"2","note":"鮮やかな色の鳥の地図","exp":"330","type":"鳥類","name":"キンケイ","desc":"中国南西部の山地に生息する鳥。赤と、光沢のある金色を基調とした、派手な姿をしている。\nとても用心深く、身を隠すのが上手で、めったに見かけることがない。"}],"5987":[{"rank":"1","note":"五賢帝の大理石像","exp":"70","type":"歴史遺物","name":"ハドリアヌス帝の大理石像","desc":"ハドリアヌス帝は、古代ローマ五賢帝の三人目である。防衛策に徹して制度を整え、ローマを発展させた。"}],"6112":[{"rank":"5","note":"","exp":"950","type":"虫類","name":"ニシキオオツバメガ","desc":"マダガスカルにのみ生息するガの一種。成虫はガとしては珍しい昼行性。黒を基調とし、緑や黄で彩られた羽は虹や宝石のように美しく、世界を探してもこれより美しいガは見つからないかもしれない。"}],"6073":[{"rank":"5","note":"","exp":"1320","type":"伝承","name":"狐の嫁入り","desc":"日本という国においてキツネは人を化かす動物だ。そんなキツネが結婚式を挙げる時、彼らは盛大な提灯行列で祝うという。しかしその姿を人の目で捉えるのは難しく、不気味な火の玉が浮かんでいるだけに見えるのだと伝えられている。"}],"640":[{"rank":"1","note":"クエスト「十二枚の連作タペストリー」<br/>発見物カード:30","exp":"65","type":"美術品","name":"マクシミリアンの狩猟","desc":"原画はベルナールト・ファン・オルレイ。神聖ローマ帝国皇帝であるマクシミリアン1世の狩猟風景のタペストリー。12枚の連作物の七枚目で、9月と呼ばれる。縦4.5m、幅5.5mの巨大なものである。"}],"1457":[{"rank":"1","note":"赤い鳥の地図","exp":"140","type":"鳥類","name":"アカクサインコ","desc":"全身が鮮やかな赤で、頬と羽が青色の鳥。非常に目立つため、木の洞など安全な場所に巣を作る。"}],"7021":[{"rank":"2","note":"","exp":"","type":"宗教遺物","name":"マツヤの彫刻","desc":"インド神話のヴィシュヌ神がマツヤと呼ばれる魚に変身した姿が象られた彫刻。世界を呑み尽くす大洪水を予言し、人類の祖先と全ての動植物を救った場面を表しているという。"}],"811":[{"rank":"4","note":"大西洋沿岸宗教の融合","exp":"756","type":"宗教遺物","name":"ブードゥー教の祭壇","desc":"ブードゥー教とは、アフリカの宗教にキリスト教が取り入れられて発達した新しい宗教である。これはその祭壇で、ロアと呼ばれる精霊を呼び出すためのものだろう。ろうそくや鈴などが祭器として使われている。"}],"5176":[{"rank":"1","note":"到達する","exp":"73","type":"港・集落","name":"ルアンダ","desc":"ごく最近開拓されたばかりの街。十分な水深と、輸送が容易な地形に恵まれた、優れた交易港である。農作物と木材、宝石が豊富に流通する。"}],"1665":[{"rank":"3","note":"ハワイキを探して","exp":"484","type":"宗教建築","name":"ラノ・ララク","desc":"ラノは「火山」、ララクは「地面を削る」という意味。火山のすそので像を作っていた場所。付近では作りかけの像がたくさん見られる。"}],"5618":[{"rank":"2","note":"","exp":"380","type":"史跡","name":"アフィントンの白馬","desc":"およそ3000年前に描かれたとされる地上絵。長さ110mほど。"}],"1750":[{"rank":"5","note":"奇怪<br/><br/>発見時経験値1040　発見物カード経験値520","exp":"1040","type":"鳥類","name":"コトドリ","desc":"竪琴のような特殊な形の尾羽を持つ鳥。繁殖期には、さえずりながら尾を振り動かしてメスを誘う。驚くべきはその声で、鳥の鳴き声に限らずありとあらゆる音をまねることができる。"}],"683":[{"rank":"2","note":"森と水の国","exp":"360","type":"地理","name":"ジャマイカ島","desc":"カリブ海の、キューバ島の南に位置する大きな島。ほとんどが山地で、高地はかなり冷涼になる。また、海岸線が複雑で入り組んでおり、水深があるので港に適している。"}],"481":[{"rank":"1","note":"古き時代の王","exp":"90","type":"財宝","name":"勇王の王冠","desc":"イベリア半島北部にあるナバラ王国は、かつてイベリアでもっとも栄えていた。これは、初期の王家の王冠だと思われる。古いながらも丁寧で精巧な細工が施されている。"}],"2961":[{"rank":"4","note":"ワニか、魚か<br/><br/>発見時経験値720　発見物カード経験値360","exp":"720","type":"海洋生物","name":"アリゲーターガー","desc":"北米に生息する、最大で3mにもなる大型淡水魚。魚類や、エビなどの甲殻類を捕食する。水鳥や、小型哺乳類を襲うこともあるが、人を襲うことはあまりない。"}],"3918":[{"rank":"4","note":"クエスト「ポーランドで作られた星座」<br/>発見物カード:345","exp":"690","type":"天文","name":"こぎつね座","desc":"夏の大三角の中央に位置する星座。17世紀にポーランドの天文学者ヘヴェリウスが設定した。明るい星がないため、目立たない星座である。"}],"5875":[{"rank":"5","note":"クエスト「中国の天文学」<br/>発見物カード:710","exp":"1420","type":"天文","name":"東方七宿青龍","desc":"中国星座において、天の赤道を28に分割した二十八宿のうち東方の七宿をまとめたもの。おとめ座やさそり座などが含まれる。"}],"5844":[{"rank":"5","note":"","exp":"1370","type":"美術品","name":"イスラムの彫刻小箱","desc":"後ウマイヤ朝で作られた象牙細工。精緻な浮き彫りで四面に別々の場面が描かれ、四面を繋ぐように細かな文様が刻み込まれている。高貴な人物のために作られたもののようだ。"}],"307":[{"rank":"1","note":"ヨルバの神話","exp":"180","type":"宗教遺物","name":"オロルン像","desc":"アフリカのヨルバ人の最高神の像。四百一の神をまとめているといわれる。世界は最初海しかなく、オロルンが海と交わってオドゥドゥアとオバタラを作り二人に大地と人間を作らせたという。"}],"5871":[{"rank":"5","note":"","exp":"1360","type":"海洋生物","name":"ヨウジウオ","desc":"日本近海に生息する、細長い口と体が特徴の魚。細長い体は海藻などの隙間に隠れるためのものと思われる。雄が雌の代わりに出産を行う特徴がある。食用には向かない。"}],"1877":[{"rank":"2","note":"［勅命］[[黄金郷の財宝探索","exp":"310","type":"財宝","name":"黄金郷の長衣","desc":"黄金郷と思われる地に潜入した勇敢な冒険者が持ち帰ったローブ。良質な生地から作られ高い技術を有していることがわかる。"}],"6985":[{"rank":"4","note":"","exp":"","type":"虫類","name":"オオナガトゲグモ","desc":"東南アジアの熱帯雨林に生息しているクモ。赤や黄などの鮮やかな警告色の体が特徴で、雌は大きな弓形のトゲを持つ。このトゲで捕食者から身を守っていると考えられる。雄は雌に比べて非常に小柄である。"}],"4826":[{"rank":"","note":"紅毛城（上層隠し部屋）","exp":"","type":"財宝","name":"高粱酒","desc":""}],"1557":[{"rank":"1","note":"古代の武器の地図","exp":"160","type":"歴史遺物","name":"古代のブーメラン","desc":"先住民族が用いた狩猟用ブーメラン。木製で滑らかに研いであり、空気抵抗を抑えてよく飛ぶようにしてある。彼らは狩猟・採集民族としてこの大地に生きてきたといわれる。"}],"2652":[{"rank":"4","note":"自慢のイヌ","exp":"620","type":"中型生物","name":"チンドケン","desc":"朝鮮半島周辺地域によく見られる中型犬。朝鮮の珍島が発祥であるらしく、その名が付いている。\nくるんと巻かれた尾が愛らしい。"}],"1780":[{"rank":"2","note":"ローマ市民を救った証","exp":"350","type":"歴史遺物","name":"市民冠","desc":"古代ローマの報奨制度のひとつで、ローマ市民の命を救ったものが与えられる冠。他の栄誉で与えられる冠は金であったが、最高位である市民冠はオークの葉で作られていた。この栄誉に預かったもののみ金属製の市民冠を作ることが許された。"}],"3163":[{"rank":"1","note":"枝が曲がった木の地図","exp":"170","type":"植物","name":"バンクスマツ","desc":"北米北部から北東部にかけて分布する樹木。樹形は広い円錐型で、枝は不規則に曲がりながら伸びる。"}],"1632":[{"rank":"2","note":"竹を食べる者","exp":"360","type":"中型生物","name":"レッサーパンダ","desc":"インドから東南アジアの山林に生息。褐色の体毛で、四肢や腹は黒く、顔には白い模様、尾はふさふさしていて輪状の縞がある。木登りが得意で、昼は樹上で寝ている。パンダの名称は、現地の言葉の「竹を食べる者」からきている。"}],"1029":[{"rank":"1","note":"野生の犬の地図","exp":"24","type":"中型生物","name":"ハイエナ","desc":"犬に似た動物。他の肉食動物が食べのこした死体をあさるが、狩りもうまい。群れで生活している。"}],"4858":[{"rank":"2","note":"クエスト「天に昇った優れた王」<br/><br/>発見物カード:175<br/>　","exp":"350","type":"天文","name":"ぎょしゃ座","desc":"五角形の星の並びが特徴的な星座。ギリシャ神話においては、アテナイ王・エリクトニオスとも、ヘルメスの息子・ミュルティロスであるともいわれる。"}],"6870":[{"rank":"5","note":"発見物カード:615","exp":"1230","type":"歴史遺物","name":"古代エジプトのかつら","desc":"古代エジプトにて着用されていたかつら。着用者の身分を示すほか照り付ける日航から頭を守るため、日常的に身につけられていたと考えられる。"}],"6176":[{"rank":"3","note":"","exp":"520","type":"海洋生物","name":"ブリモドキ","desc":"暖かい海に広く分布する大型魚で、特徴的な縦縞模様を持つ。船や流木などについて泳ぐ習性から、古代ギリシャでは「ポムピロス」と呼ばれ、船乗りたちが自分たちの帰路を導く魚だと信じていたという。"}],"213":[{"rank":"1","note":"とある令嬢の指輪","exp":"75","type":"財宝","name":"伯爵令嬢の指輪","desc":"悲運に見舞われたある伯爵令嬢の指輪。希少価値の高い大きな青水晶が使われている。内側には、出自を証明する刻印がされている。"}],"6916":[{"rank":"3","note":"","exp":"","type":"植物","name":"ゲイソリザ・ラディアンス","desc":"南アフリカに分布する球根植物。細長く平らな葉を持ち、花茎からは中心が赤く、外側は青紫色の花が咲く。その姿はワインを注いだ盃に例えられ、ワインカップとも呼ばれている。"}],"3898":[{"rank":"2","note":"クエスト「乙女の変身譚」<br/>発見物カード:120","exp":"240","type":"天文","name":"おおぐま座","desc":"ゼウスの寵愛を受けたため、女神ヘラの怒りを買って巨大な熊に姿を変えられたカリストが天に昇った姿とされる。北米の先住民の神話でも熊が天に昇った姿とされる。"}],"6204":[{"rank":"5","note":"謎は細部に宿るか","exp":"1000","type":"財宝","name":"ピッツィガーノの海図","desc":"15世紀ヴェネツィアの地図職人ツアン・ピッツィガーノが作成した羅針儀海図。ヨーロッパ大陸の西側洋上に奇妙な島が描かれており、まるで新発見の島であることを強調するかのようにそれぞれ赤と黒に塗られている。"}],"3173":[{"rank":"3","note":"クエスト「クマ調査の協力依頼」<br/>発見物カード:225","exp":"450","type":"大型生物","name":"アメリカグマ","desc":"北米の温帯および亜寒帯地域に分布する。性格は比較的穏やかだが動作は素早く、木登りを得意とする。"}],"6175":[{"rank":"5","note":"","exp":"990","type":"史跡","name":"ヒエラポリス・パムッカレ","desc":"古代ローマの都市のひとつであったヒエラポリスの遺跡。ローマより前に栄えたペルガモン王国の時代から温泉地として名高い一方で共同墓地も数多く存在している。アポロン神殿の近くに「冥王の門」と呼ばれる洞窟があるという。"}],"1416":[{"rank":"1","note":"メソアメリカの容器の地図","exp":"150","type":"歴史遺物","name":"四脚容器","desc":"四脚のついた器型の入れ物。犬のような頭のついた蓋がある。犬はマヤ王が死後の世界に旅立つ際に供についたといわれている。"}],"6487":[{"rank":"5","note":"追究クエスト","exp":"","type":"宗教遺物","name":"ナラシンハ像","desc":"獣にも人にも殺せぬアスラ族のヒラニヤカシプを討伐するために、ヴィシュヌ神が化身した姿。獅子の頭と人の体を持ち、獣でも人でもない存在としてヒラニヤカシプを討った。ノラシンガは、ナラシンハが元となり伝わったものといわれる。"}],"832":[{"rank":"4","note":"知的美女","exp":"756","type":"歴史遺物","name":"クレオパトラの胸飾り","desc":"クレオパトラ7世が使っていたという、豪華な胸飾り。彼女はエメラルドを特に好んだと伝えられ、この胸飾りにも大粒のエメラルドがいくつも使われている。"}],"1231":[{"rank":"2","note":"闇夜に舞い降りる影<br/><br/>発見時経験値205　発見物カード経験値102","exp":"205","type":"小型生物","name":"チスイコウモリ","desc":"血液のみを餌にするコウモリ。眠っている動物に噛み付き、傷口から流れ出る血液をなめとる。昼間は洞窟などに身を潜め、闇夜になると餌を求めて活動する。"}],"2613":[{"rank":"5","note":"思い出した一言","exp":"1170","type":"歴史遺物","name":"諸葛弓弩","desc":"読みは「しょかつきゅうど」。明代に発明された連発式の弩。\n弓の上部に矢を十本収納することで連射を可能にした。三国時代の軍師・諸葛亮にちなんだ名前と思われる。"}],"6695":[{"rank":"5","note":"発見物カード:455","exp":"910","type":"天文","name":"アクルックス","desc":"みなみじゅうじ座で最も明るい星。十字架の下部にあたる。最も南に輝く1等星である。\nみなみじゅうじ座（クルックス）のアルファ星であることから、アクルックスと命名された。"}],"4788":[{"rank":"1","note":"書きかけの地図","exp":"200","type":"地理","name":"カリフォルニア半島","desc":"太平洋とカリフォルニア湾を隔てる半島。砂漠などの乾燥地帯が続いている。長い間、島だと誤解されていた。"}],"5535":[{"rank":"4","note":"","exp":"374","type":"気象・現象","name":"幻日","desc":"太陽が複数並んで見える現象。大気中の微粒子が幻影の発生に関係していると考えられるが、いまだに詳細は解明されていない。"}],"3147":[{"rank":"2","note":"クエスト「航海者・ヴァイキング」<br/>発見物カード:195","exp":"390","type":"財宝","name":"赤毛のエイリークのサガ","desc":"ヴァイキングの英雄・赤毛のエイリークを中心とした物語。\nエイリークのグリーンランド移住と、侠気のソルフィンによる西方探索が描かれている。"}],"6701":[{"rank":"5","note":"","exp":"","type":"中型生物","name":"メインクーン","desc":"家猫の一種。寒冷地に生息するため、長い体毛を持つ。体調は1m以上もあるが、温順な性格のため、ジェントルジャイアントと呼ばれている。知能が高いと言われ、器用に前足で物を持ち上げたり、戸を開けたりする。"}],"3849":[{"rank":"5","note":"精霊のクマ<br/><br/>発見時経験値1100　発見物カード経験値550","exp":"1100","type":"大型生物","name":"シロアメリカグマ","desc":"成人男性ほどの背丈を持つクマ。北米に広く生息する黒い体毛のクマの亜種にあたる、白い個体を指す。一部の先住民からは、「精霊のクマ」と呼ばれている。"}],"6657":[{"rank":"3","note":"東アジア東部　済州島北","exp":"","type":"歴史遺物","name":"新安沈船","desc":"元のころの貿易船。陶磁器や銅銭香木など大量の交易品を積んでいた。日本の博多へ向かう途中、沈没。"}],"1438":[{"rank":"3","note":"謎の多い古代神","exp":"473","type":"宗教遺物","name":"ケツアルパパロトル像","desc":"メソアメリカの古い神話に登場する。神話上の神だと考えられている。ケツアルパパロトルとは「羽毛に覆われた蝶」という意味で、どういう役割をしているのかは不明である。"}],"399":[{"rank":"1","note":"冠をかぶった鳥","exp":"140","type":"鳥類","name":"カンムリヅル","desc":"頭に美しい飾り羽があるツル。アフリカでしか見られないようだ。ツルはフラミンゴやサギに似ているが、立っているときの姿や飛び方が違うので、近い種類ではないようだ。"}],"5233":[{"rank":"3","note":"","exp":"810","type":"宗教遺物","name":"正義の女神","desc":"ローマ神話の「正義」を司る女神ユースティティアを模した彫像。手には正邪を量る天秤と力を象徴する剣を持つ。さまざまな女神と同一視されることもある。"}],"2929":[{"rank":"4","note":"雷を切り裂く刃","exp":"660","type":"財宝","name":"雷切","desc":"落ちてきた雷を切り、持ち主の身を守ったといわれる日本の刀。名匠の手により造り出された、切れ味抜群の名刀である。刀身には雷を切ったらしき痕跡が残っている。"}],"3878":[{"rank":"2","note":"ウシを追う人","exp":"280","type":"財宝","name":"カウボーイのネッカチーフ","desc":"北米西部のカウボーイが首に巻く布。装身具としての用途のほか、口もとを覆って砂埃を吸うのを防いだり、仲間への合図に使ったりするなど、実用性も兼ね備えている。"}],"1878":[{"rank":"5","note":"アステカの誇り高き勇者","exp":"1040","type":"宗教遺物","name":"ジャガー戦士の面","desc":"ジャガー戦士とは、アステカに見られた戦士である。貴族階級の精鋭のみがジャガー戦士たりえたという。この面には、名誉ある死を遂げた戦士に対する敬拝の意が込められているのだろうか。"}],"6828":[{"rank":"4","note":"発見物カード:360","exp":"720","type":"中型生物","name":"アカハナグマ","desc":"アンデス山脈の東に生息する、アライグマの一種。主に低地の森林で暮らし、果実や小動物などを餌とする。細長い鼻と黒い縞模様のある尾が特徴で、尾の長さは体と同じにまでなる。赤や茶など体毛は個体により様々である。"}],"3925":[{"rank":"4","note":"「天文学者の観測記録」<br/>発見物カード:135","exp":"270","type":"天文","name":"りょうけん座の渦巻星雲","desc":"りょうけん座にある渦巻き型の星雲。肉眼では見えないものの、望遠鏡で観測すると恒星との明確な違いに気がつく。"}],"6772":[{"rank":"2","note":"発見物カード:150","exp":"300","type":"海洋生物","name":"マナマコ","desc":"ナマコの一種。太平洋の西側沿岸の岩礁帯に広く生息している。干したものは東洋で高価な食材として流通し、華北の料理である魯菜の食材としても有名。"}],"3919":[{"rank":"4","note":"クエスト「海の化け物の調査」<br/>発見物カード:375","exp":"750","type":"天文","name":"くじら座","desc":"エチオピアの王女アンドロメダを襲った化けクジラがペルセウスによって石に変えられた後、天に上げられた姿とされる。"}],"5004":[{"rank":"2","note":"発見物カー:175","exp":"350","type":"天文","name":"こと座流星群","desc":"こと座に放射点がある流星群で、毎年4月に極大期を迎える。また非常に古くから知られており、最も古い観測記録は紀元前までさかのぼる。"}],"5801":[{"rank":"5","note":"","exp":"1370","type":"史跡","name":"エル・カズネ","desc":"ペトラ遺跡の王墓。盗賊が宝物を隠したという伝説から、宝物殿と呼ばれるようになったようだ。"}],"4866":[{"rank":"3","note":"クエスト「古代の建築指南書」<br/>発見物カード:270","exp":"540","type":"歴史遺物","name":"ボルシッパ碑文","desc":"ボルシッパの最盛期を築いたネブカドネザル２世の碑文。彼がどのようにしてナブー神を祀る「七層の神殿」を「尊いラピスラズリのレンカ」で修復したのかが刻まれている。"}],"3379":[{"rank":"4","note":"砂漠で命を繋ぐもの","exp":"700","type":"植物","name":"ナツメヤシ","desc":"中東や北アフリカに分布する木。樹高は15mを超え、3m程度の葉を付ける。\n栄養価の高い実がなることなどから、メソポタミアやエジプトなどの地域で古代より重宝されてきた。"}],"1201":[{"rank":"3","note":"オーロラの雫","exp":"533","type":"財宝","name":"オーロラの雫","desc":"色とりどりのひすいでできたサークレット。ひとつひとつが大粒で細工も非常に精巧にできている。微妙な色彩をたたえるこのサークレットを、オーロラのひとしずくだと例えたのもうなずける。"}],"1995":[{"rank":"2","note":"釣り","exp":"360","type":"海洋生物","name":"プレコストムス","desc":"南米アマゾン川に生息する淡水ナマズ。吸盤状の口で、岩や流木に生えたコケを食べる。様々な体型や体色、斑紋の種類があり、独特の美しさを持つ。見た目によらず美味。"}],"958":[{"rank":"2","note":"宝石の島","exp":"270","type":"地理","name":"セイロン島","desc":"インドの南に浮かぶ、比較的大きな島。赤道に近く熱帯に属する。高地が多く、茶の栽培が盛んだ。また、宝石の鉱脈が非常に多い島でもある。"}],"2245":[{"rank":"3","note":"サボテンの下で","exp":"490","type":"中型生物","name":"リクイグアナ","desc":"体長1mほどの、大型のトカゲ。黄褐色の体に太い尾が特徴。草食性で、主にサボテンを食べる。性質はおとなしい。"}],"2504":[{"rank":"1","note":"絵巻物の地図","exp":"200","type":"美術品","name":"寺社縁起絵巻","desc":"ある寺院と、そこに関わる仏僧についての奇跡譚がまとめられた、日本の絵巻物。\n貴賎の別なく、信仰を求める人々の様子が、表情豊かに描かれている。"}],"1899":[{"rank":"2","note":"［勅命］[[現地における思想についての調査","exp":"310","type":"宗教遺物","name":"宣教師の遺品","desc":"異国の地で教えを広めようとしていた宣教師の遺品。ヨーロッパでは見慣れた物だ。"}],"1686":[{"rank":"2","note":"川に棲むイルカの地図","exp":"255","type":"海洋生物","name":"アマゾンカワイルカ","desc":"アマゾン川に生息するイルカ。体色はピンクや灰色のまだらで、毛のはえた長いくちばしを持っている。カニやカメなどを食べる。"}],"465":[{"rank":"1","note":"軍神の像","exp":"90","type":"宗教遺物","name":"アレス像","desc":"ギリシャ神話の軍神の像である。ローマ神話ではマルス。美と愛の女神・アフロディテの愛人で、間に何人かの子をもうけている。"}],"6917":[{"rank":"5","note":"","exp":"1077","type":"史跡","name":"トルコの石灰華段丘","desc":""}],"1340":[{"rank":"2","note":"最重要監視海域","exp":"360","type":"地理","name":"スールー諸島","desc":"カリマンタン島の北東岸にある諸島。古くからイスラム教を国教とする王国が成立し、周囲の島々を支配下に置いていた。近年はイスパニアがマニラを拠点として活動し始めたため、海賊を支援し、抵抗しているようだ。"}],"2829":[{"rank":"5","note":"悪役の素顔","exp":"830","type":"美術品","name":"徽宗の花鳥画","desc":"宋代の皇帝・徽宗の作品。\n徽宗は花鳥画に長けており、この絵も気品に満ちた絵であるとして高い評価を得ている。"}],"5732":[{"rank":"4","note":"","exp":"740","type":"財宝","name":"イエティの頭皮","desc":"謎の人型生物イエティの頭皮とされ、現地で祀られていた。伝承では神の使いだとされているが、実在するのだろうか…？"}],"634":[{"rank":"1","note":"クエスト「酒の神の館」<br/>発見物カード:55","exp":"110","type":"歴史遺物","name":"ディオニソスの館のモザイク画","desc":"ポンペイの秘儀荘と呼ばれる建物の内部で発見されたモザイク画。ディオニソスを崇拝する宗派に入るための儀式を描いたものであるといわれている。"}],"1612":[{"rank":"2","note":"聖書が刻まれた十字架","exp":"220","type":"宗教遺物","name":"ケルト十字の石柱","desc":"アイルランドの遺跡に多く残る十字架。円環が付いた大きな石造りの十字架で、ケルトの紋様が全体に刻まれている。十字に円環が付くようになったのは、キリスト教がケルトに伝わった際、両文化が融合したためといわれている。"}],"6845":[{"rank":"5","note":"発見物カード:430","exp":"860","type":"財宝","name":"謎の手稿","desc":"羊皮紙に書かれた、正体不明の手稿。中世の終わり頃の作と推定されるが、未知の文字が並んでおり解読できた者はいない。文字の他に彩色された植物や天体などの図案も描かれているが、詳細は不明である。"}],"6186":[{"rank":"1","note":"跳ねる魚の地図","exp":"120","type":"海洋生物","name":"トビウオ","desc":"主に暖かい海に生息している。名前の由来は水上に飛び出し、羽根のような胸ビレを広げて滑空することから。海の表層を泳いでいるのは、マグロなどの捕食者から逃げるためといわれる。勢いあまって甲板に上がることもある。食べると美味。"}],"60":[{"rank":"3","note":"インドの炎神","exp":"","type":"宗教遺物","name":"アグニ像","desc":"インド神話の火の神である。炎のような髪に金色の歯、七枚の舌という、炎をもとにした姿を持つ。悪を滅する浄化の力を持つとされる。"}],"5138":[{"rank":"1","note":"到達する","exp":"44","type":"港・集落","name":"ベルゲン","desc":"スカンジナビア半島の南西部にある街。フィヨルドに近い高緯度地域だが、気候は比較的温暖である。寒冷地でも育つ農作物が栽培されるほか、塩や石材、木材などが豊富に産出する。"}],"4835":[{"rank":"2","note":"楽山大仏 （上層隠し部屋）","exp":"","type":"歴史遺物","name":"銅鼓","desc":"青銅で鋳造された打楽器。中国や東南アジアで広く出土している。演奏以外にも祭祀などで使用されていたようだ。"}],"2900":[{"rank":"4","note":"天空の大海","exp":"630","type":"地理","name":"黄山","desc":"道教や仏教の修行の場として多くの寺院が建てられている杭州付近の山。多数の文人が訪れ、水墨画や漢詩など独特の文化を生み出した。"}],"558":[{"rank":"2","note":"古代交易路の証","exp":"370","type":"歴史遺物","name":"ウルのスタンダード","desc":"ウル王墓から出土した用途不明の箱。軍旗や楽器の一部ではないかなどと言われている。戦争の図と、その反対に平和の図が描かれており、貝殻やラピスラズリのモザイクで飾られている。"}],"685":[{"rank":"5","note":"クエスト「森の中の巨大レイヨウ」<br/>発見物カード:520","exp":"1040","type":"中型生物","name":"ボンゴ","desc":"大きい個体では400kgにもなる、大型のレイヨウ。濃いオレンジの地に真っ白なしまが十数本ある。深い森に住み、警戒心が強く、姿をなかなか見せないため生態はほとんどわからない。"}],"2516":[{"rank":"1","note":"尾が長いサルの地図","exp":"130","type":"中型生物","name":"タイワンザル","desc":"台湾島に生息しているサル。全身は灰褐色で四肢の先端が黒い。尾は比較的長くて太い。"}],"1562":[{"rank":"1","note":"書きかけの地図","exp":"90","type":"地理","name":"サンホルヘ湾","desc":"南米南東岸にある半円形の湾。西からの強い風と寒流により、気温は年中低温である。大陸側には、荒涼とした低温地帯が広がっている。"}],"1419":[{"rank":"2","note":"雨の神","exp":"350","type":"宗教遺物","name":"トラロック像","desc":"メソアメリカの神話における古い神で、雨を司っている。トラロックが構える死後の世界は永遠の楽園で、天災や不慮の事故・伝染病などで死んだものだけが行けるという。"}],"5070":[{"rank":"1","note":"到達する","exp":"72","type":"港・集落","name":"シエラレオネ","desc":"アフリカ西海岸の街。年間を通じて気温が高く、熱帯性の農業が盛んである。また、近郊にはダイヤモンドの大規模な鉱脈があるようだ。"}],"489":[{"rank":"2","note":"古代インドの法典","exp":"280","type":"宗教遺物","name":"マヌの法典","desc":"ヒンドゥー教の法典。バラモン教・ヒンドゥー教の基本となる内容で、12章から成る。記述は法律にとどまらず生活上の儀礼や教義にまで及ぶ。"}],"1873":[{"rank":"5","note":"いつも二人で","exp":"820","type":"財宝","name":"チブチャの民の黄金衣装","desc":"黄金の国伝説の元になったといわれる民族の衣装。酋長が金粉を体にまとい、湖に飛び込む儀式を行うといわれている。これだけ金づくしの生活をしていれば、「黄金の人間が住む黄金の国がある」と思われても仕方がないだろう。"}],"2897":[{"rank":"2","note":"古い医学書の地図","exp":"260","type":"財宝","name":"黄帝内経","desc":"古くから伝わる針灸医学の規範となる書物。前漢の時代に編さんされたと思われる。\n複数の医学論文をつづり合わせたもので、著者や編集者は明らかではない。"}],"3013":[{"rank":"2","note":"先住民の土器の地図","exp":"120","type":"歴史遺物","name":"水中豹の水差し","desc":"メキシコ湾沿岸のミシシッピ川付近に居住していたと思われる民族の生活用具。これは、その民族の神話に登場する架空動物・水中豹をかたどった水差しである。"}],"6321":[{"rank":"3","note":"","exp":"530","type":"財宝","name":"赤備えの鎧","desc":"全体を赤色で統一された日本の甲冑。混戦の戦場であっても目立つことから、敵の注意を引きつけるとともに、自軍の目印にもなったという。特に武勇に優れた将や部隊が身に着けたとされる。"}],"680":[{"rank":"4","note":"クエスト「信仰の象徴」<br/>発見物カード:350","exp":"732","type":"宗教遺物","name":"聖十字架","desc":"イエスが処刑されたときにはりつけられたとされる十字架の一部。聖十字架にはさまざまな伝説があり、アダムの墓に植えられた原罪の木が、数奇なめぐり合わせで用いられたともいわれる。"}],"2682":[{"rank":"2","note":"火山のある島","exp":"340","type":"地理","name":"済州島","desc":"朝鮮半島の南に位置する島。過去に独自の王朝があったとされる。朝鮮半島では見られない文化も存在するようである。"}],"5827":[{"rank":"5","note":"","exp":"1360","type":"財宝","name":"ソロモンの盾","desc":"ソロモン王が作った金の盾。大盾が200個、小盾が300個作られたが、エジプトのファラオに奪われたという。"}],"6267":[{"rank":"5","note":"クエスト「ヘビに似た生き物の伝承」<br/>発見物カード:760","exp":"1520","type":"伝承","name":"龍神","desc":"中国や日本に伝わる霊獣。人里離れた山の中にある湖や淵の底に住み、水や雨を操るという。\n特に日本では白ヘビなどの姿になって人里に降りるという逸話が多く、神でありながら身近な存在ともいえなくもない。"}],"5180":[{"rank":"1","note":"到達する","exp":"38","type":"港・集落","name":"ローマ","desc":"紀元前から存在するイタリア最大の都。\n王制、共和制、帝制と長い歴史の中で数多の変遷を遂げ、街中にはさまざまな遺跡が存在する。\nコロッセウムもその遺跡の一つである。"}],"4857":[{"rank":"1","note":"「天文学者の観測記録」<br/>発見物カード:95","exp":"190","type":"天文","name":"りゅう座の猫の目のような星雲","desc":"りゅう座にある、猫の目のような形の星雲。かなり複雑な構造をしているとみられる。"}],"5062":[{"rank":"1","note":"到達する","exp":"79","type":"港・集落","name":"サンジョルジュ","desc":"西アフリカのギニア湾に面した街。この付近はオヨ王国やダホメー王国が栄え、交易も盛んである。内陸から運ばれてきた豊かな資源が流通している。"}],"410":[{"rank":"2","note":"奇蹟の衣","exp":"290","type":"宗教遺物","name":"聖母の衣服","desc":"聖母マリアが身につけていたとされる衣服の切れはし。絵画で描かれるものと同じ赤色に染められている。真贋（しんがん）のほどは定かでない。"}],"1864":[{"rank":"2","note":"巫女の織った服","exp":"280","type":"歴史遺物","name":"貫頭衣","desc":"アルパカやリャマなどの毛、鳥の羽を用いて作った一枚布。長方形に縫い、中央に穴を開け、そこから顔を出すように着る。胴の部分に腰紐を巻き、腕を出す。彩色は、赤、青、緑、黄などの原色で、非常に派手である。"}],"2912":[{"rank":"2","note":"ダンジョン","exp":"360","type":"歴史遺物","name":"彩色壁画の欠片","desc":"パレンケ遺跡内部に施された壁画の一部。\n欠片であるにも関わらず、繊細な彫刻が施されている。薄れてしまってはいるが、大部分に赤で彩色された跡があり、細部は緑、青、黄色で彩られている。"}],"6996":[{"rank":"2","note":"","exp":"","type":"財宝","name":"カルナイ","desc":"中央アジアの伝統的な管楽器。銅あるいは真鍮でできた、非常に長い管を持つ。形状は直線や曲線、幅の広いものがあるが、いずれも一音だけを奏で、太鼓や弦楽器など他の楽器と合わせて演奏する。"}],"109":[{"rank":"3","note":"カリブの宝石","exp":"600","type":"鳥類","name":"トパーズハチドリ","desc":"宝石のようにきらびやかな羽で覆われた鳥。空中で静止するように飛び、花蜜を吸う。"}],"5614":[{"rank":"2","note":"","exp":"","type":"化石","name":"胴が扁平なトカゲの骨","desc":"幅広な胴を持つ、巨大なトカゲのような生物の骨。胴は甲冑のように骨で覆われている。"}],"6184":[{"rank":"5","note":"理想郷に関する伝承","exp":"1660","type":"伝承","name":"見えざる街","desc":"世界中に広く伝わる、この世のどこかにあるという見えない街。戦乱に巻き込まれて滅びた、神の力によって海や湖の底に沈められた…などといった伝承が数多く残されているが、それを実際に見た者や戻ってきた者の話はついぞ聞かない。"}],"1034":[{"rank":"1","note":"野生の豚の地図","exp":"36","type":"大型生物","name":"イノシシ","desc":"ずんぐりした体に短く鋭い牙を持つ動物。気性が荒く、人間が襲われることもある。豚の祖先だと思われる。"}],"1836":[{"rank":"5","note":"神雷がもたらすもの","exp":"1144","type":"宗教遺物","name":"エメラルド仏像","desc":"ひすい製の仏像。その来歴は、落雷で破壊された仏塔から出現したといわれているが定かではない。総ひすい製だが輝きがまるでエメラルドのようなので、やがてエメラルド仏と呼ばれるようになったという。"}],"472":[{"rank":"1","note":"月の女神の像","exp":"120","type":"宗教遺物","name":"アルテミス像","desc":"ギリシャ神話の女神の像。アポロンの双子の妹で、ローマ神話ではディアナ。アルテミスは狩猟と動物、出産、豊穣の女神である。月の女神・セレネと同一視されることもある。"}],"5063":[{"rank":"2","note":"到達する","exp":"239","type":"港・集落","name":"サンティアゴ","desc":"キューバ島の南東部にある街。地形が港に適しており、付近の交易の中継点として栄えている。カリブ特有の農作物が豊富に流通している。"}],"6036":[{"rank":"4","note":"","exp":"750","type":"宗教建築","name":"アトス山の修道院群","desc":"サロニカの東にあるアトス半島とアトス山の一帯にある修道院群。規模の大きな修道院や修道士が独りで暮らす小屋が集まって成立している。生神女マリアが守護聖人だが女性の入山は認められておらず、男性しか立ち入ることができない。"}],"6205":[{"rank":"2","note":"もうひとつの信仰","exp":"370","type":"宗教建築","name":"ゴーマテーシュワラの立像","desc":"インド西部のシュラバナベラゴラの岩山にあるジャイナ教の聖者、ゴーマテーシュワラの石像。彼は「剛腕を持つ者」を意味するバーフバリの名を持ち、衣服を含む一切の私物を持たずに何年も瞑想を続けたといわれる。"}],"805":[{"rank":"1","note":"大きな木の地図","exp":"13","type":"植物","name":"ボダイジュ","desc":"大きく育つ落葉樹。各地で見かけるが、地方によって微妙に異なるようにみえる。西洋ではハーブとして葉を使うこともある。インドでは、仏陀がこの木の下で悟りを開いたと伝えられているそうだ。"}],"6420":[{"rank":"5","note":"","exp":"","type":"小型生物","name":"冬毛のオコジョ","desc":"オコジョの毛が冬になり純白に生えかわった状態。古い言い伝えでは純潔の象徴ともされている。それゆえにアーミンと呼ばれる冬毛のオコジョの毛皮や、毛皮で作られた服は、貴族や王族に好まれた。"}],"1882":[{"rank":"2","note":"［勅命］[[失踪した調査隊の追跡調査","exp":"310","type":"財宝","name":"金細工の耳飾り","desc":"本国に届けられるはずだった、金で作られた耳飾り。この地域独特の細工が施されているため、ヨーロッパでの価値は高いだろう。"}],"5288":[{"rank":"2","note":"","exp":"280","type":"虫類","name":"サバクトビバッタ","desc":"サハラ周辺に生息するバッタ。風に乗って長距離を移動でき、ヨーロッパやインドに到達することもある。大発生すると、農作物に壊滅的な打撃を与えることがあるため、農民に恐れられている。"}],"779":[{"rank":"1","note":"壮大な旅行記","exp":"110","type":"財宝","name":"三大陸周遊記","desc":"イブン・バットゥータ著のイスラム世界最大の旅行記。アフリカ、インド、中国まで踏破し、その様子をよく伝えている。"}],"238":[{"rank":"1","note":"のんびりしたクジラ","exp":"70","type":"海洋生物","name":"セミクジラ","desc":"暖かな海で見られる、動作の緩やかなクジラである。体には多数のフジツボなどが付着する。死んだあと沈まないのだが、なぜかは不明である。"}],"137":[{"rank":"1","note":"クジラの生態調査","exp":"50","type":"海洋生物","name":"マッコウクジラ","desc":"20m近くにもなる、大型のクジラ。頭部が大きく、口には硬い歯が並んでいる。巨大なイカと戦っている姿が目撃されたこともあるという。船を襲ったりはしないようだ。"}],"5328":[{"rank":"2","note":"","exp":"","type":"地理","name":"オカヴァンゴ川","desc":"アフリカ南西部の乾燥地帯を流れる川。海に流れ込まない内陸河川で、下流で巨大な湿地を形成する。流域の生物にとっては貴重な水源となっている。"}],"3426":[{"rank":"","note":"","exp":"","type":"レリック","name":"エルドラド(財宝伝説)","desc":"伝説のシボラの街といわれる、黄金と宝石に満ちあふれた神殿。水没しかけており、その美しさもいつか失われてしまうのだろうか。"}],"63":[{"rank":"2","note":"インドの宗教書の地図","exp":"260","type":"宗教遺物","name":"仏教経典","desc":"釈迦（しゃか）の教えを記したとされる本。このうちスッタニパータという経典が最も古く、釈迦の言葉に最も近いという。長い間に多くの宗派が出たため膨大な種類がある。"}],"6414":[{"rank":"5","note":"追求クエスト　発見物カード:605","exp":"1210","type":"美術品","name":"ミノタウロスの像","desc":"ギリシャ神話に登場する牛頭人身の怪物、ミノタウロスをかたどった像。ミノタウロスはミノス王の妻と白い牡牛との間に生まれた子だが、成長するに従って乱暴になり、誰の手にも負えなくなると、ミノス王命令により迷宮に閉じ込められた。"}],"6699":[{"rank":"5","note":"追究クエスト<br/>発見物カード:450","exp":"900","type":"美術品","name":"黙示録の版画","desc":"アルブレヒト・デューラーの最も有名な木版画の一つ。「黙示録」と呼ばれる聖書の一説がモチーフとなっている。木版画の裏には黙示録の文章が印刷してあり、書籍として販売された。"}],"1675":[{"rank":"2","note":"太古の舞踊","exp":"280","type":"財宝","name":"ポイ","desc":"編みこんだ亜麻に冠毛を詰めた球に紐をつけた道具。マオリ人独特の踊り「ハカ」で女性が用いる。また、このポイ自体も多産を意味する縁起のよいものとされている。"}],"3252":[{"rank":"4","note":"バラ色の湖","exp":"620","type":"地理","name":"レトバ湖","desc":"西アフリカに位置する湖。海水より塩分の濃度が高い塩湖である。ピンク色の湖水をたたえており、水量の減る乾季にはその色がより鮮やかになる。"}],"5845":[{"rank":"4","note":"クエスト「空に浮かぶ黒い筋」<br/>発見物カード:350","exp":"700","type":"天文","name":"南のコールサック","desc":"「石炭袋」の名を持つ暗黒星雲。みなみじゅうじ座の近くに見ることができる。天の川を背景にしているため、肉眼でも観測できる場合がある。"}],"3877":[{"rank":"2","note":"北米の巨牛","exp":"300","type":"大型生物","name":"アメリカバイソン","desc":"北米やカナダの西部に生息する大型のウシ。バッファローとも呼ばれる。断熱性に優れた毛皮が特徴で、先住民の生活と密接な関わりを持つ。"}],"2663":[{"rank":"2","note":"青の宝物","exp":"240","type":"財宝","name":"瑠璃製の杯","desc":"新羅に縁ある場所でよく発掘される杯。美しい瑠璃色のガラスで作られている。\n特別な装飾があるわけではないが、とても目を引く。"}],"112":[{"rank":"4","note":"カリブ海の人魚","exp":"708","type":"海洋生物","name":"マナティー","desc":"海に住む大型の動物。アザラシのように陸に上がることはない。泳ぎが遅く警戒心も弱いのは、敵の少ない海域で海草などを食べているからだろう。海面で子に乳を与える姿が人魚と間違われたり、怪物のセイレーンと間違われたりした。"}],"1260":[{"rank":"5","note":"トロイ戦争のてん末","exp":"923","type":"美術品","name":"ラオコーン（腕伸ばし）","desc":"ラオコーンはトロイの神官で、トロイの木馬を防ごうとした人である。ギリシャに肩入れするアテナが放った大蛇に襲われ、二人の子と共に命を落とした。"}],"1680":[{"rank":"5","note":"力強い肢体","exp":"1001","type":"虫類","name":"ヘラクレスオオカブト","desc":"熱帯林の広範囲に生息する、体長ほどもある二本の長い角をもった大型の虫。羽は黄褐色をしていて、黒い斑点がある。"}],"1538":[{"rank":"1","note":"メソアメリカの鉢の地図","exp":"110","type":"歴史遺物","name":"浮き彫り装飾鉢","desc":"レリーフが彫られた広口の鉢。土器でできている。この絵にはなにか物語があるのだろうか。"}],"6490":[{"rank":"5","note":"レガシー　女神信仰の地エフェソス　中央","exp":"","type":"宗教建築","name":"在りし日のアルテミス神殿","desc":"エフェソスに建てられた大理石造りの巨大神殿。女神アルテミスを祀る。破壊や炎上で失われるたびに、より壮麗に再建されてきた。エフェソスのアルテミスは小アジアの大地母神の影響を受け、ギリシャ本土とは異なる姿や性格をもつ。"}],"6924":[{"rank":"3","note":"","exp":"","type":"中型生物","name":"オットセイ","desc":"アシカに似た哺乳類。全身を覆う体毛はアシカよりきめ細かく、柔らかでつやがある。また、前足と頭の両側にある耳はアシカよりも大きい。海岸に生息し、魚やタコなどを捕食する。"}],"6291":[{"rank":"3","note":"","exp":"600","type":"植物","name":"サルスベリ","desc":"東アジアに分布する花木。長期にわたって花を咲かせるため、「百日紅」とも呼ばれる。幹が大きくなるに伴って新しい樹皮が表面に現れるため、すべすべとしているのが特徴。"}],"256":[{"rank":"1","note":"クエスト「ヒグマの生息地調査」<br/>発見物カード:70","exp":"140","type":"大型生物","name":"ヒグマ","desc":"クマの中でも特に大型で危険な種類である。オスの大きい個体は体長が2mを超える。人間の力などは問題にならない。雑食性で冬眠の習性があるため、秋の準備期間と冬眠明けの春先は特に危険。"}],"5125":[{"rank":"2","note":"到達する","exp":"370","type":"港・集落","name":"ピンジャラ","desc":"オーストラリアの南西端にほど近い街。街の名前は付近の低湿地帯を指す先住民の言葉が訛ったものである。\n南西オーストラリアの内陸部には、埋蔵量が豊富な鉄鉱石や金の鉱山が存在するため、それらの積み出し港として注目を集めている。"}],"3817":[{"rank":"4","note":"ある街の貨幣の地図<br/><br/>発見時経験値650　発見物カード経験値325","exp":"650","type":"財宝","name":"ポートロイヤルの貨幣","desc":"ポートロイヤルの造幣局で鋳造された貨幣。ポートロイヤルに大量に流入する貴金属が材料となっている。"}],"475":[{"rank":"1","note":"権威ある神託","exp":"100","type":"宗教建築","name":"デルフォイ遺跡","desc":"古代ギリシャにおいて世界の中心だと考えられた場所。アポロン神殿があり、その神託は絶対的なものだった。ソクラテスもここで神託を受けた。"}],"5616":[{"rank":"2","note":"","exp":"230","type":"小型生物","name":"ナキウサギ","desc":"北米やアジアなどの寒冷な地方に生息するウサギの一種。体長は18cm程度で、四肢は短く、耳が丸い。"}],"1445":[{"rank":"2","note":"寝床を借りに","exp":"320","type":"小型生物","name":"フクロギツネ","desc":"キツネに似た有袋類。樹上で生活し、植物の葉や花、鳥の卵などを食べる。"}],"1968":[{"rank":"5","note":"空飛ぶワニ<br/><br/>発見時経験値820　発見物カード経験値410","exp":"820","type":"虫類","name":"ユカタンビワハゴロモ","desc":"ユカタン半島に生息する昆虫。羽を広げた姿はガに似ているが、体の質感はセミに近い。異様に大きな頭が特徴で、横から見るとワニの顔のように見える。"}],"5187":[{"rank":"2","note":"到達する","exp":"345","type":"港・集落","name":"杭州","desc":"読み方は、「ハンチョウ」。マルコ・ポーロが、美しく華やかな都市だと褒め称えたといわれている街。\n文明発祥地の一つで、寺や古跡が多く立ち並ぶ。"}],"2347":[{"rank":"2","note":"江戸を支える食の基盤","exp":"290","type":"地理","name":"九十九里浜","desc":"日本の太平洋岸にある砂浜海岸。沿岸部は漁場に恵まれている。\nその名は、長々と延びた浜辺に由来する。"}],"1185":[{"rank":"5","note":"エル・パソ","exp":"1040","type":"地理","name":"マゼラン海峡","desc":"マゼランが、太平洋に出るために航行したことから、その名がついた海峡。非常に狭く、地形も複雑であるため航海の難所として有名である。"}],"5279":[{"rank":"3","note":"「天文学者の観測記録」<br/>発見物カード:220","exp":"440","type":"天文","name":"ちょうこくしつ座の渦巻星雲","desc":"ちょうこくしつ座のやや北にある渦巻き星雲。明るい星雲であるが、ヨーロッパではあまり高度が上がらないため観測が難しい。"}],"1949":[{"rank":"2","note":"人々と共にある花","exp":"330","type":"植物","name":"カントゥータ","desc":"アンデスの高地に自生する樹木。寒冷で乾燥した過酷な環境にありながら、赤や黄などの鮮やかな色をした釣鐘状の花を咲かせる。現地では、「インカの聖花」とも呼ばれる。"}],"3537":[{"rank":"","note":"","exp":"","type":"レリック","name":"エルドラド(輝く丘)","desc":"新大陸の密林の奥に隠された、黄金と宝石に満ちあふれた神殿。住人によって秘密が守られているため、訪れることは難しい。"}],"6742":[{"rank":"3","note":"発見物カード:215","exp":"430","type":"歴史遺物","name":"モコロ","desc":"南アフリカにある広大な湿地帯で使われる小舟。アフリカに広く分布しているソーセージノキの幹を焼き、中をくり抜いて作られる。入り組んだ水路において、必要不可欠な移動手段。"}],"5109":[{"rank":"2","note":"到達する","exp":"320","type":"港・集落","name":"ハワイ","desc":"絶海の島にある街。太平洋のほぼ中心に位置する。4～8世紀ごろにポリネシアから人が移住してきたと推測される。火山が多く、島の地質は凝固した溶岩から成る。"}],"6503":[{"rank":"5","note":"レガシー競技の聖地オリンピア　上","exp":"2970","type":"史跡","name":"オリンピアのフィリペイオン","desc":"オリンピアに建てられた大理石の円形建築。マケドニア王フィリッポス2世が戦勝の記念にゼウス神に捧げた。王の死後、子のアレクサンドロス大王が完成させた。王家の人々の黄金と象牙の像が立ち並んでいたと伝わる。"}],"650":[{"rank":"2","note":"書きかけの地図","exp":"260","type":"地理","name":"ポーク海峡","desc":"セイロンとインドの間にある海峡。セイロンは特産物が多く交易が盛んなので、この海峡は船の行き来がとても多い。"}],"6872":[{"rank":"2","note":"発見物カード:190","exp":"380","type":"地理","name":"済州島の溶岩石柱","desc":"済州島の海岸線に並ぶ多角形の石柱。火山から噴出した溶岩が、海に流れ込む際に冷え固まって出来たものと考えられている。"}],"6367":[{"rank":"2","note":"","exp":"210","type":"宗教建築","name":"ジュガンティーヤ","desc":"地中海に浮かぶ島にある巨大な石で作られた神殿。伝承では巨人が石を運んで造り上げたとされる。かつては扉や天井が存在した痕跡もあり、奥の祭壇では動物が生贄として捧げられたという。"}],"5530":[{"rank":"3","note":"","exp":"270","type":"気象・現象","name":"バンファイパヤーナク","desc":"川に火の玉が出現する現象。マレー半島の特定の地域でのみ観測される。火の玉は水面から上空数百メートルまで上昇し、その後消える。多い日では、1時間に数千個現れるという。"}],"3194":[{"rank":"2","note":"書きかけの地図","exp":"210","type":"地理","name":"パラティーノの丘","desc":"ローマに位置する丘の一つ。古代ローマ時代の神殿や住居の跡があり、ローマの数ある丘の中でも最も歴史が古いと見られている。"}],"6623":[{"rank":"5","note":"","exp":"830","type":"海洋生物","name":"ガラ・ルファ","desc":"通称「ドクターフィッシュ」。西アジアの河川に分布する。比較的高水温にも耐えられるため温泉にも生息している。ヒトの皮膚の角質を食べる習性があり、歯を持たないため、肌を傷つけない自然ピーリングに使われる。"}],"1425":[{"rank":"2","note":"コルテス探険記録","exp":"210","type":"財宝","name":"メキシコ征服記","desc":"コルテス軍に従軍したベルナール・ディアスの著。コルテスが本国を発ってからの足跡を綴っている。作成途中に放棄されたようで、内容は不十分だ。これが完成されて世に出されれば、後世に伝わる重要な記録となろう。"}],"6987":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"有刺利器","desc":"伽耶時代に作られた鉄器。板状に延べた鉄の側面を囲むように鳥形の装飾が取り付けられている。その独自の形状から葬儀などの儀式に使用されたと考えられる。"}],"1559":[{"rank":"1","note":"ネコに似た動物の地図","exp":"135","type":"小型生物","name":"フクロネコ","desc":"ネコに似た有袋類。夜行性で、昆虫や小動物を捕食する。"}],"1748":[{"rank":"5","note":"夢か現か<br/><br/>発見時経験値1040　発見物カード経験値520","exp":"1040","type":"虫類","name":"ミイロタイマイ","desc":"ニューギニアに生息する美しいチョウ。宝石のように輝く羽を持ち群れで空中を素早く飛び回る。"}],"262":[{"rank":"5","note":"フラガラッハ","exp":"1183","type":"歴史遺物","name":"フラガラッハ","desc":"ケルト神話の太陽神・ルーの物だといわれる魔剣。ひとたびさやから放たれると、この刃から逃れられる者はいないという。"}],"5238":[{"rank":"2","note":"","exp":"310","type":"植物","name":"イナゴマメ","desc":"10m以上の高さになる常緑高木。温暖な土地で生育し、乾燥にも耐える。その実は糖分を含んで甘く、古代より甘味料として食された。「聖ヨハネのパン」ともいわれ、聖書にも登場する。"}],"5001":[{"rank":"1","note":"コーカサス地方再調査報酬","exp":"","type":"中型生物","name":"ロシアンウルフハウンド","desc":"ロシアでオオカミ狩りの猟犬として飼育されている大型のイヌ。性格はおとなしく、知能も非常に高い。森林には野生種も生息する。"}],"886":[{"rank":"1","note":"毒貝の地図","exp":"64","type":"海洋生物","name":"イモガイ","desc":"一見ただの巻貝だが、猛毒を持つ。近くを通りかかった魚に向かって毒針を飛ばし、殺してエサにする。人間が刺されると高確率で死亡する。"}],"5030":[{"rank":"1","note":"到達する","exp":"4","type":"港・集落","name":"オポルト","desc":"ポルトワインの産地として有名な港。オポルトとは「港」の意味でポルトガル建国時はこの地方が国土の中心であった。名産のワインのほか、漁業と塩の生産が盛んである。"}],"2528":[{"rank":"1","note":"華やかな屏風絵の地図","exp":"180","type":"美術品","name":"俵屋宗達の屏風絵","desc":"江戸時代の絵師・俵屋宗達によって描かれた屏風絵。\n伝統的な大和絵の技法に加え、独特の技法と構図が取られている点が特徴的である。"}],"5367":[{"rank":"4","note":"","exp":"360","type":"史跡","name":"プント国のレリーフ","desc":"プント国は、古代エジプトと同時代にあった国で金や香料、木材などの交易で栄えていたという。レリーフにはハトシェプスト女王が送り出したとされる船団が描かれている。"}],"3882":[{"rank":"2","note":"集落の調査","exp":"370","type":"財宝","name":"アナサジフルート","desc":"北米の先住民であるアナサジ民族の縦笛。木製で長さはおよそ70cmあり、六つの穴が開いている。"}],"6221":[{"rank":"3","note":"","exp":"460","type":"気象・現象","name":"赤虹","desc":"赤い虹。霧のような雨が降ったあとに、幅が広く、色は薄いが全体的に明るい虹が出ることがある。この時に虹が朝日や夕日を浴びると、赤みを帯びて見えることが多い。"}],"2090":[{"rank":"3","note":"隠しメニューの秘訣","exp":"510","type":"地理","name":"ベンゲラ海流","desc":"アフリカ西岸を北上する寒流。\nこの海域は魚が育ちやすく、豊富に獲れるようだ。潮の流れに秘密があるのだろうか。"}],"68":[{"rank":"2","note":"インドの闘神","exp":"310","type":"宗教遺物","name":"インドラ像","desc":"古代インドの神話で、もっとも有名な神の像である。雷や嵐をつかさどる軍神で、漆黒の悪龍・ヴリトラを打ち倒した。ヒンドゥーでは地位が下がり、三大神の下に位置づけられている。"}],"2409":[{"rank":"4","note":"虫の話の真偽","exp":"620","type":"虫類","name":"ヨナグニサン","desc":"インドから東アジアにかけて幅広く分布する大型のガ。日本が分布の最北端となる。\n口を持たず、羽化したあとは食事を一切取れない。"}],"2046":[{"rank":"2","note":"レバノンの山岳","exp":"300","type":"地理","name":"レバノン山脈","desc":"ベイルート付近の山。雪が積もるため、アラム語で「白」を表すラバンからレバノンと名づけられた。\nかつては、レバノン杉がたくさん自生していたが、古代エジプトのピラミッド製造のため大量に伐採された。"}],"5149":[{"rank":"2","note":"到達する","exp":"250","type":"港・集落","name":"ポートロイヤル","desc":"カリブ海のほぼ中央に位置する港街。立地が良く、多くの船が停泊できたため、バッカニア海賊の拠点となる。街は海賊だらけだが、秩序は保たれているようだ。"}],"3253":[{"rank":"4","note":"聖なる木立","exp":"690","type":"地理","name":"オシュン・オショグボ聖林","desc":"西アフリカに位置する聖なる森。ヨルバ民族の神話における豊穣の女神・オシュンが住むとされる。"}],"3764":[{"rank":"1","note":"月の表面","exp":"100","type":"天文","name":"月面","desc":"古代から人類はさまざまな形を月の表面の模様に見出してきた。アリストテレスは月は完全な球体であるとしたが、ガリレオは望遠鏡で月を観測し、月の表面が滑らかでなく、凸凹があることを明らかにした。"}],"5080":[{"rank":"2","note":"到達する","exp":"323","type":"港・集落","name":"スラバヤ","desc":"ジャワ島北東岸に位置する街。マジャパヒト王国の支配下にあり、ヒンドゥー文化の黄金期を築いた。"}],"46":[{"rank":"2","note":"イソギンチャクと暮らす魚","exp":"260","type":"海洋生物","name":"クマノミ","desc":"暖かい海に生息する、白いしまのある魚。イソギンチャクの毒が効かないようで、敵に襲われるとイソギンチャクの触手の間に隠れてしまう。なぜ毒が効かないのかは謎だ。"}],"5583":[{"rank":"2","note":"クエスト「北米大陸を貫く山脈」<br/>発見物カード:160","exp":"320","type":"地理","name":"ロッキー山脈","desc":"北米大陸西部に位置する山脈。豊かな動植物と天然資源に恵まれている。"}],"2833":[{"rank":"5","note":"太公望の魚釣り<br/><br/>発見時経験値1060　発見物カード経験値530","exp":"1060","type":"財宝","name":"太公望の釣竿","desc":"周の時代に軍師として活躍した太公望の持ち物といわれる釣竿。\n一説によると、渭水のほとりで釣りをしていたところ、のちの文王に「祖父の太公が待ち望んだ傑物だ」と称えられ、迎えられたという。"}],"1821":[{"rank":"1","note":"珍しい腕輪の地図","exp":"150","type":"財宝","name":"金の腕輪","desc":"豊富な金を使用して作られた腕輪。貴族の持ち物だったと思っていいだろう。年代は古いものではなく、最近作られたもののようだ。"}],"3906":[{"rank":"","note":"","exp":"","type":"レリック","name":"サンジェルマン伯爵","desc":"豊富な知識と錬金術で知られたサンジェルマン伯爵。彼は本当に不死で、研究を続けているのだろうか。"}],"6051":[{"rank":"2","note":"","exp":"","type":"美術品","name":"生神女就寝のイコン","desc":"正教会で伝えられているイコンの一つで、生神女マリアが亡くなった時の出来事を描いている。\nマリアの永眠を祝う習慣は東方から始まったとされ、西ヨーロッパでは「聖母被昇天」として定着した。"}],"1844":[{"rank":"2","note":"新妻の証","exp":"230","type":"財宝","name":"新婚用サリー","desc":"一枚布を体に巻き付けるようにして着るインド女性の服。インドには、新婚の妻は赤いサリーしか身にまとってはならないというしきたりがある。"}],"6973":[{"rank":"2","note":"発見物カード:120","exp":"240","type":"美術品","name":"聖ルチアの埋葬","desc":"カラバッジオ作の油彩画。信仰を貫いて殉教した聖ルチアの埋葬の場面が描かれている。彼女の殉教地とされるシラクサの教会のために制作された。写実的な筆致が、深い悲壮感を伝えている。"}],"3004":[{"rank":"1","note":"奇妙な石の地図","exp":"200","type":"化石","name":"アゴの長いトカゲのような石","desc":"体長60cm以上の、トカゲのような石。他の石と重なるようにして見つかった。"}],"2424":[{"rank":"1","note":"釣り","exp":"130","type":"海洋生物","name":"ヤガラ","desc":"口の長さと形が特徴的な細長い体の魚。\n体は赤いが身は白く、外見からは想像できないほど美味である。\n見た目のせいか、獲れても逃がされることが多いらしい。"}],"1488":[{"rank":"1","note":"扇のある鳥の地図","exp":"135","type":"鳥類","name":"ヒオウギインコ","desc":"熱帯林に生息する鳥。興奮したり驚いたりすると、頭部全体の羽を扇状に逆立てる。"}],"99":[{"rank":"3","note":"カエサルの剣","exp":"440","type":"歴史遺物","name":"カエサルの剣","desc":"ユリウス・カエサルの剣。ガリア地方を平定しているときに、身につけていたものだとされる。ポンペイの遺跡跡から発掘され、刀身にはケルトの財宝に関する文言が記載されていた。"}],"3657":[{"rank":"2","note":"ダンジョン","exp":"374","type":"宗教遺物","name":"ローマのカタコンベ","desc":"ローマの城壁外にある地下墓地などの遺跡。ローマ帝国によるキリスト教弾圧から逃れるため、キリスト教徒たちは地下道を掘り、墓地や集会所として利用していた。その長さは20kmにも及ぶという。"}],"6053":[{"rank":"5","note":"","exp":"1040","type":"美術品","name":"聖クリストフォロスのイコン","desc":"正教会圏で伝えられている、聖クリストフォロスを描いたイコン。伝承では犬頭の巨人だが、キリスト教に帰依し、後に殉教したという。ロシアでは「異教の影響を排除する」という理由で人型に描かれているようだ。"}],"5341":[{"rank":"2","note":"","exp":"320","type":"海洋生物","name":"ハダカイワシ","desc":"夜になると海面近くまで上がってくる深海魚で、体の表面に発光器を持つ。鱗がはがれやすく、網などで船に上げるとほとんど残っていないため、この名がついた。"}],"6635":[{"rank":"5","note":"発見物カード750","exp":"1500","type":"歴史遺物","name":"銀製コショウ入れ","desc":"ローマ帝国期のコショウ入れ。貴婦人をかたどった形をしている。当時、コショウは貴重品であり、コショウ入にも金箔が施されていたという。"}],"6256":[{"rank":"1","note":"","exp":"110","type":"史跡","name":"ベルレンガの要塞","desc":"リスボンの北にあるベルレンガ・グランデ島に建てられた砦。正式名は「サン・ジョアン・バプティスタ要塞」という。海上防衛のために修道院の遺構を利用して築かれ、しばしばバルバリア海賊などの標的となった。"}],"5068":[{"rank":"1","note":"到達する","exp":"21","type":"港・集落","name":"ザダール","desc":"ヴェネツィア近郊の街である。かつてはダルマチア国の首都であった。アドリア海に面した温暖な気候である。"}],"2742":[{"rank":"3","note":"沈黙の太鼓","exp":"460","type":"財宝","name":"申聞鼓","desc":"（しんぶんこ）朝鮮王宮の門前に置かれている太鼓。民が王に謁見を願うときに叩かれるという。\n両班の衣服と似た配色の派手な彩色が施されており、目を引く。"}],"5696":[{"rank":"4","note":"クエスト「もう一つの北極星」<br/>発見物カード:315","exp":"630","type":"天文","name":"トゥバン","desc":"りゅう座を構成する星の一つ。かつては北極星だったが、歳差運動の影響で北極星ではなくなった。"}],"2289":[{"rank":"2","note":"クエスト「伝わる副葬品」<br/>発見物カード:145","exp":"290","type":"歴史遺物","name":"古代のマノ","desc":"マノとは、トウモロコシをすりつぶす道具のこと。すりつぶされたトウモロコシは、こねられ、生地にして食される。古代より、この道具によって料理が作られていたものと思われる。"}],"1451":[{"rank":"5","note":"風をはらむトルソ","exp":"1215","type":"美術品","name":"サモトラケのニケ","desc":"サモトラケ島で出土した大理石片を組み上げて作った、美しいニケ像。腕と頭部が失われているが、かえって翼の美しさが引き立っている。"}],"5826":[{"rank":"5","note":"","exp":"1410","type":"財宝","name":"シャルルマーニュの護符","desc":"シャルルマーニュが身に着けていたというペンダント状の護符。所有する者は皇帝になるという伝説がある。この護符を次に所有するのは、いったい誰になるのだろうか。"}],"2339":[{"rank":"1","note":"古代の道具の地図","exp":"140","type":"歴史遺物","name":"弥生土器","desc":"日本で発見された、薄くて堅い土器。模様や装飾が控えめで、実用的な外観を持つ。\n調理や貯蔵など多岐に渡って使われ、用途に合わせて多様な形のものが作られている。"}],"5150":[{"rank":"2","note":"到達する","exp":"332","type":"港・集落","name":"マカッサル","desc":"セレベス島の南部に位置する街。ゴワ王国、タッロ王国の時代に、交易中継港として栄えた。"}],"3005":[{"rank":"2","note":"奇妙な石の地図","exp":"220","type":"化石","name":"植物模様のある石","desc":"妙な模様や起伏がある石。シダ植物の葉のようにも見えるが…。\n古代の植物が石化したのだろうか？"}],"2041":[{"rank":"2","note":"歴史書にある生涯","exp":"370","type":"財宝","name":"歴史叢書","desc":"三部四十巻からなる、歴史家ディオドロスの著書。一巻から五巻が各国の神話をまとめたものであり、十一巻から二十巻が年代史という構成である。それ以外の巻は行方不明のようだ。"}],"1978":[{"rank":"3","note":"半分だけがシマウマ<br/><br/>発見時経験値600　発見物カード経験値300","exp":"600","type":"大型生物","name":"クアッガ","desc":"南アフリカの乾燥地域に生息。体の前半分にシマウマのような模様がある。腹部から後ろ半分は褐色で、四肢は白い。特徴的な鳴き声を模してその名が付いた。以前はサバンナを覆うほどの数がいたそうだが、開拓者の入植以降、減少している。"}],"5636":[{"rank":"1","note":"","exp":"190","type":"鳥類","name":"メガネウ","desc":"カムチャッカ半島の東方にあるベーリング島に生息している大型の鳥。目の周りには羽毛がなく、白い皮膚が露出している。"}],"586":[{"rank":"1","note":"豪華な宝石細工の地図","exp":"115","type":"財宝","name":"金象嵌の護符","desc":"「きんぞうがん」。金象嵌が施された大きな護符。かなり精密な細工が施されており、宗教的な意味はもちろん美術品としての価値も高い。"}],"6686":[{"rank":"5","note":"","exp":"1040","type":"海洋生物","name":"シロイルカ","desc":"別名ベルーガ。ベーリング海やアラスカなど北半球の高緯度海域に生息する。前頭部から多種多様な鳴き声を発生させ、餌の探知や仲間と交流に使用している。その鳴き声の美しさから「海のカナリア」とも呼ばれる。"}],"4807":[{"rank":"4","note":"紅毛城（深層隠し部屋）","exp":"","type":"歴史遺物","name":"無血開城の誓約書","desc":"紅毛城を無血開城するという誓約の際に作られたと思われる書状。イスパニア、ネーデルラント双方の印が押されている。保存状態が悪く、ところどころ破れている。"}],"6515":[{"rank":"5","note":"レガシー競技の聖地オリンピア　左上","exp":"1500","type":"歴史遺物","name":"競技者を描いたアムフォラ","desc":"古代ギリシャの競技者を描いたつぼ。黒地に赤、もしくは赤地に黒で描かれている。競技種目は徒競走、円盤投げ、槍投げ、走り幅跳びなどのほか、格闘技や拳闘、戦車競走、武装競争などがあった。競技は衣服を身につけず行われたと伝わる。"}],"5363":[{"rank":"2","note":"","exp":"300","type":"植物","name":"ヒヤシンス","desc":"西アジア原産の草花。オスマントルコで栽培された。\nギリシャ神話ではアポロンの寵愛を受ける美青年ヒュアキントスの血から生まれたとされる。"}],"6416":[{"rank":"5","note":"","exp":"","type":"宗教遺物","name":"魔王・ラーヴァナのレリーフ","desc":"ラーマーヤナに登場する魔王・ラーヴァナのレリーフ。羅刹の王であり、10の頭と20の腕を持っていたとされるラーヴァナと、ラーマ王子を助ける猿の神の軍勢が合戦をする場面を彫り込んだもののようだ。"}],"6019":[{"rank":"1","note":"","exp":"123","type":"財宝","name":"ドゥアルテの著作","desc":"ドゥアルテ王子が自ら執筆した著作。政治家としての在り方を書いたものや乗馬の心得を書いたものなどがあり様々な分野に精通していることが窺える。"}],"818":[{"rank":"1","note":"大理石の女性像の地図","exp":"108","type":"財宝","name":"大理石の女性像","desc":"大理石の女性像。丸みのあるラインがとても美しい。あまり古いものではないようだ。"}],"3160":[{"rank":"4","note":"新天地の魅惑の毛皮","exp":"630","type":"小型生物","name":"アメリカミンク","desc":"北米の川や湖の周辺に生息する動物。こげ茶色の上質な毛並みを持つ。ヨーロッパミンクよりひと回り大きい。"}],"900":[{"rank":"5","note":"覇権を賭けた大戦","exp":"962","type":"歴史遺物","name":"エジプトの和平交渉文書","desc":"ラムセス2世がヒッタイトと戦ったカデシュの戦いについて書かれた文書。エジプト優勢で終わった戦いに、ヒッタイト側から和平の申し出があり、それを受諾したことが書かれている。"}],"7002":[{"rank":"5","note":"","exp":"","type":"財宝","name":"文王の法冠","desc":"古代中国に伝わる一本角の神獣を模した冠。この神獣は正邪を見極め、悪を罰するとされた。伝説によればこの冠は楚の文王が創案し、以後法を司る官吏が正義の象徴として身につけるようになったという。"}],"282":[{"rank":"4","note":"ボッティチェリの傑作","exp":"708","type":"美術品","name":"プリマヴェーラ","desc":"ボッティチェリ作の絵画。中央にヴィーナスとキューピッド、右にはゼフュロスに息を吹きかけられた女神フローラが、左には美・貞節・愛の三女神とメルクリウスが描かれている。"}],"597":[{"rank":"2","note":"混乱をもたらす神","exp":"220","type":"宗教遺物","name":"エシュ像","desc":"アフリカのヨルバ人の神の像。月食や日食を起こす、いたずら者の神だという。"}],"1582":[{"rank":"4","note":"ヨーロッパからの依頼","exp":"720","type":"植物","name":"バンクシア","desc":"大量の花蜜を有する植物。蜜を食料とする生物の重要な食料源となっている。果実は非常に堅く、山火事などで焼かれて割れ、種子を地上に落とす。"}],"1684":[{"rank":"5","note":"豊穣神の黄金の仮面","exp":"1183","type":"宗教遺物","name":"シペ・トテックのマスク","desc":"豊穣神シペ・トテック信仰に用いられたと思われる金のマスク。メソアメリカでも比較的新しい時代になると、金属を使用した遺物が見つかるが、これだけ精巧に、かつ大量の金でできたものとなると類を見ない。"}],"5814":[{"rank":"5","note":"シベリア地方","exp":"830","type":"植物","name":"チャーガ","desc":"シベリア霊芝とも呼ばれるキノコ。煎じて飲むと病気の治療に役立つといわれる。シラカバの樹皮に生えるが、かなり珍しいようだ。"}],"14":[{"rank":"1","note":"アドリア海の出入り口","exp":"20","type":"地理","name":"オトラント海峡","desc":"イタリア半島とバルカン半島の間にある、アドリア海の出入り口。幅は狭いところで80km程度である。"}],"2821":[{"rank":"2","note":"変わった形の遺物","exp":"340","type":"宗教遺物","name":"玉蝉","desc":"読み方は、「ぎょくせん」。蝉の形をした殷代の葬玉。\n古来、遺体の穴をすべて葬玉で塞いで埋葬すると、腐敗を防げると考えられていた。"}],"6476":[{"rank":"5","note":"","exp":"","type":"史跡","name":"在りし日のロードス島の巨像頭部","desc":"ロードス島の港に立つ太陽神ヘリオスの巨大な青銅像。攻城者デメトリオスによる包囲を耐え切り、勝利した記念として建造された。頭には太陽光線を表すサークレットを付けている。顔立ちはアレクサンドロス大王を模しているともされる。"}],"6646":[{"rank":"5","note":"","exp":"830","type":"宗教建築","name":"台南孔子廟","desc":"台湾島最古の孔子廟。「鄭氏諸葛」の異名を持つ軍師・陳永華によって建てられた。学校として教育を行う役割も併せ持っている。正門前には台湾島初の学校という意味の「全臺首學」の題字が掲げられている。"}],"6351":[{"rank":"2","note":"","exp":"300","type":"歴史遺物","name":"包囲戦の古代武具","desc":"「ロードス包囲戦」での敵援軍到着により、早急な撤退を余儀なくされたデメトリオス軍は多くの武具を置きざりにして撤退したとされ、その一部は鋳潰され巨像の建材として使われたとされる。"}],"2560":[{"rank":"5","note":"台湾島の鳥調査をもう一度 ","exp":"1250","type":"鳥類","name":"サンケイ","desc":"台湾島に生息する大型の鳥。雄の体長は、約70cmほどある。\n警戒心が強く、めったに姿を現さない。"}],"2844":[{"rank":"5","note":"もうひとつの連弩","exp":"1160","type":"歴史遺物","name":"元戎","desc":"読み方は、「げんじゅう」。連弩と呼ばれる弩を改良して作られたもので、複数の矢を連射できるようになっている。\n三国時代の蜀の軍略家である諸葛亮が、魏に対抗するために発明したといわれる。"}],"3186":[{"rank":"5","note":"ぶどうの地に見た未来","exp":"1230","type":"地理","name":"テラ・ノヴァ","desc":"新大陸北部にある島。夏でも山間部で雪が残るなど、冷涼である。近年ジェノヴァ生まれの航海者カボットが到達した。その五百年前にヴァイキングが到達したと伝わっている、「ヴィンランド（ぶどうの地）」と考えられる。"}],"3793":[{"rank":"4","note":"発見物カード:325","exp":"650","type":"天文","name":"カペラ","desc":"ぎょしゃ座で最も明るい1等星で、冬のダイヤモンドの一角である黄色い星。星座図では御者が抱える雌山羊の心臓に位置する。古代バビロニアで暦を決めるのに利用されたといわれる。"}],"4872":[{"rank":"2","note":"大型のヒョウの地図","exp":"220","type":"大型生物","name":"ペルシャヒョウ","desc":"中東に生息するヒョウ科の亜種。ヒョウの亜種の中で最大である。通常のヒョウとは異なり、胸や腹にも斑点が存在する。"}],"6444":[{"rank":"1","note":"クエスト「殉教者の秘薬」","exp":"100","type":"宗教遺物","name":"ベケット・ウォーター","desc":"イングランド教会の聖人、トマス・ベケットの血液などを水で薄めて作ったという聖水。聖人の加護により万病に効くとされた。イングランド王ヘンリー2世の親友だったベケットは、教会の自立性を巡り対立。聖堂内で王の兵士に殺害された。"}],"2847":[{"rank":"2","note":"群雄割拠の物語","exp":"210","type":"財宝","name":"三国志演義","desc":"「三国志」を元に書かれた明代の歴史小説。魏、蜀、呉の三国の間で入り乱れる、軍事・政治闘争を描いた話。劉備と曹操の対立軸を中心に、物語が進んでいく。"}],"6775":[{"rank":"4","note":"発見物カード:380","exp":"760","type":"宗教建築","name":"ロスキレ大聖堂","desc":"デンマークのシェラン島にある大聖堂。ロマネスクとゴシックの混合様式で、外壁はレンガ造りになっている。10世紀にハーラル青歯王が建てた木造の教会が始まりとされ、デンマーク歴代の王の棺が安置されている。"}],"6247":[{"rank":"1","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40","type":"宗教遺物","name":"聖母のステンドグラス","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。"}],"726":[{"rank":"2","note":"聖なる花","exp":"340","type":"植物","name":"ハス","desc":"東洋で神聖な花だとされている植物。神が座る台座に描かれることが多いようだ。厚みのある上品な花弁が美しい。早朝から咲きはじめ、午後になるとつぼんでしまう。"}],"1186":[{"rank":"2","note":"大海に浮かぶ孤島","exp":"380","type":"地理","name":"セントヘレナ","desc":"アフリカ大陸の西、南大西洋にぽつりと浮かぶ島。陸から2000km以上離れている絶海の孤島である。しかし、ここに補給港ができればアフリカ航路を大きく短縮できるだろう。"}],"2969":[{"rank":"5","note":"奇想天外な植物","exp":"1190","type":"植物","name":"ウェルウィッチア","desc":"ナミブ砂漠に生息する巨大な植物。葉の幅は約1.5mで、その長さは3～4mにも及ぶ。寿命が大変長く、数百年は生きるといわれる。"}],"300":[{"rank":"3","note":"メソポタミアの石像","exp":"506","type":"歴史遺物","name":"有翼人面獣身像","desc":"古代メソポタミア文明で作られていた、独特の石像。門の脇などに置かれ、守護の意味があったと考えられる。体は牡牛であったり獅子であったりする。"}],"903":[{"rank":"2","note":"馬のような鳥","exp":"260","type":"鳥類","name":"ダチョウ","desc":"頭の高さが2.5mにもなる大型の鳥。体に比べて翼が小さく飛べないようだが、脚が非常に発達していて馬並みに走れる。蹴られれば人間など簡単に死ぬことだろう。"}],"3196":[{"rank":"4","note":"漁師の相棒","exp":"680","type":"中型生物","name":"ニューファンドランド","desc":"北米北東部沿岸の、テラ・ノヴァを原産とする犬。\n大型で寒さに強く体力もある上に、泳ぎが得意であるため、漁師の作業を手伝うなど漁業犬として活躍する。"}],"82":[{"rank":"2","note":"ウルの栄華","exp":"390","type":"歴史遺物","name":"牛頭のある女王のリラ","desc":"ウル王墓のプ・アビ女王の墓から発見されたリラ。牛頭の装飾には金が使われている。ラピスラズリや貝などもふんだんに使用されており、当時の豊かさを物語っている。"}],"6918":[{"rank":"3","note":"","exp":"","type":"財宝","name":"彫刻が施されたガラスの器","desc":"江戸時代に安閑天皇陵古墳で発見したと言われる、ガラスの椀。ササン朝時代に作られたといわれ、ガラスの表面には、円形の文様が規則的に彫られている。"}],"579":[{"rank":"1","note":"豪華な衣服の地図","exp":"113","type":"財宝","name":"貴婦人のドレス","desc":"絹や宝石をふんだんに使った、豪華な衣装。縫製も非常にていねいで、おそらく非常に身分の高い女性が身につけていたものだと思われる。"}],"3536":[{"rank":"","note":"","exp":"","type":"レリック","name":"ポトシ銀山","desc":"スペイン語で「豊かな丘」を意味する「セロ・リコ」と呼ばれる銀鉱山。銀に魅せられた人々の想いが燻ぶる地である。"}],"3044":[{"rank":"3","note":"根無し草<br/><br/>発見時経験値530　発見物カード経験値265","exp":"530","type":"植物","name":"チランジア","desc":"北米南部から中南米にかけて生息する植物。葉から水分を吸収するため乾燥に強く、根を持たない。多くの種が存在し、その姿は多様である。"}],"1832":[{"rank":"2","note":"羽根が生えた魚の仲間","exp":"350","type":"海洋生物","name":"エンドリケリ・エンドリケリ","desc":"扁平な頭部、硬い鱗に覆われた円筒形の太い胴、羽のような背びれなど、独特な姿をした魚。長寿で、10年以上生きる。ナイル川上流など、熱帯アフリカの河川に生息。"}],"5323":[{"rank":"2","note":"","exp":"320","type":"中型生物","name":"オオヨロイトカゲ","desc":"アフリカ南東部の草原に生息するトカゲ。大きいものは全長40cmほどになる。背は硬い鱗に覆われ、それが名前の由来になっている。日光浴を非常に好むようだ。"}],"6556":[{"rank":"5","note":"レガシー『英知の灯アレクサンドリア』右下","exp":"","type":"宗教建築","name":"ケルアンのミナレット","desc":"角柱型のミナレット。イスラム教の聖地の一つ、北アフリカのケルアンに建てられた。最下段はウマイヤ朝の総督が728年に建造したと伝わる。その独特の形は、ローマ時代の灯台をモデルにしたと考えられる。"}],"5172":[{"rank":"1","note":"到達する","exp":"40","type":"港・集落","name":"リガ","desc":"13世紀初めに、ドイツ騎士団によって築かれた街。バルト海に面しており、ロシア地方との重要な交易拠点。重要な産物は多種の鉱物と羽毛である。"}],"660":[{"rank":"1","note":"小さな空飛ぶリス","exp":"30","type":"小型生物","name":"モモンガ","desc":"頭から尾の先までが20cmあまりの、小型のリスの仲間。前足と後足の間に飛膜があり、木から木へ滑空する。黒い大きな目と長めの毛が愛らしい。"}],"2724":[{"rank":"4","note":"美しい水鳥","exp":"680","type":"鳥類","name":"カンムリツクシガモ","desc":"朝鮮半島から中国北東部にかけての湿地帯に生息する鳥。\n冠状の飾り羽があることから名付けられた。"}],"6172":[{"rank":"3","note":"クエスト「思わぬ出どころ」<br/>発見物カード:265","exp":"530","type":"歴史遺物","name":"オクシリンコス・パピルス","desc":"エジプト中部のオクシリンコスで発見された数千点に及ぶ\nパピルス文書のひとつ。文書の大部分は公文書や裁判記録\nなどだが、プラトンなど古代ギリシャ哲学者や詩人の著作\n当時の信仰に関係する文献や聖歌の楽譜などもある。"}],"272":[{"rank":"2","note":"クエスト「プレステ・ジョアンの石柱」<br/>発見物カード:105","exp":"210","type":"宗教遺物","name":"アクスムの石柱","desc":"一枚岩から削り出した巨大な石柱が林立している。立っているもので最高25m、倒れているものでは33mのものがある。基部に石室があることから、墓だと思われる。"}],"2801":[{"rank":"2","note":"花の涙","exp":"330","type":"植物","name":"モクレン","desc":"主に中国南西部に生息する、紫色の花を咲かせる植物で、高貴な花とされている。甘くて上品な芳香を放つ。"}],"580":[{"rank":"1","note":"豪華な甲冑の地図","exp":"125","type":"財宝","name":"象嵌細工の甲冑","desc":"「ぞうがんざいくのかっちゅう」。金や銀の象嵌細工が施された甲冑。祭礼や装飾目的のものと思われる。"}],"6508":[{"rank":"5","note":"","exp":"1120","type":"財宝","name":"蝋管式蓄音機","desc":"蝋でできた管に刻まれた溝を針でなぞり、振動を拾い上げることで音を再生する自動演奏装置。振動は針とつながったサウンドボックスと呼ばれる振動版へ伝わることで音となりその音がホーンを通して拡大される仕組みになっている。"}],"6978":[{"rank":"2","note":"発見物カード:145","exp":"290","type":"財宝","name":"ギジャーク","desc":"中央アジアの伝統的な弦楽器。弦は四本で、胴の下側に取り付けられ半円形の脚を膝にのせて弓で演奏する。ペルシャの楽器が、東西交易を通じて伝わったと考えられている。"}],"6683":[{"rank":"4","note":"発見物カード:355","exp":"710","type":"天文","name":"アルデラミン","desc":"ケフェウス座で最も明るい星。エチオピアの王ケフェウスの右肩にあたり、アラビア語で「右の前腕部」を意味する。7500年後、北極星になると予測されている。"}],"2980":[{"rank":"1","note":"水上の花の地図","exp":"190","type":"植物","name":"ヒツジグサ","desc":"東アジアや北米などに分布する水生植物。水位が安定している池などに自生する。初夏から秋にかけて、日中に白い花を咲かせる。"}],"5832":[{"rank":"5","note":"","exp":"1340","type":"美術品","name":"田舎風陶器","desc":"パリッシーという人物が作り上げた陶器。小さな動物や植物の立体的な浮き彫りが施されており、さながら陶器の上に田舎の風景が再現されているかのようである。"}],"5707":[{"rank":"4","note":"発見物カード:325","exp":"650","type":"宗教遺物","name":"ヒマヴァットの像","desc":"ヒマラヤ山脈を神格化したものとされる、ヒマヴァット神の像。その名は「凍る寒さの」という意味の言葉に由来するという。"}],"5916":[{"rank":"2","note":"アマゾン川流域  14132,4952","exp":"390","type":"海洋生物","name":"レッドテールキャット","desc":"アマゾン川に分布するナマズの仲間。赤味を帯びた尾びれを持つことから、この名で呼ばれている。大きな口と6本のヒゲが特徴で、成長すると1mを超えることがある。"}],"6134":[{"rank":"3","note":"","exp":"540","type":"鳥類","name":"オオグンカンドリ","desc":"主に太平洋やインド洋に生息する、グンカンドリの仲間。広げた翼が2mを超えるほど大きくなるが、体重は軽い。オスメス共に全身が黒いが、オスには赤い喉袋、メスは喉から胸にかけて白いという特徴があり、区別しやすい。"}],"1703":[{"rank":"5","note":"ソロモンの見た夢","exp":"1196","type":"宗教遺物","name":"ソロモンの指輪","desc":"古代イスラエルの王であり、ダヴィデの子ソロモンが持っていたといわれる指輪。この指輪をすると動物たちと会話ができるといわれている。"}],"5228":[{"rank":"1","note":"","exp":"170","type":"史跡","name":"フォロの浴場","desc":"古代ローマの都市であるポンペイにあった公共の浴場。脱衣場やさまざまな温度の浴室が設けられている。"}],"3613":[{"rank":"4","note":"人気な毒の実","exp":"730","type":"植物","name":"アキー","desc":"西アフリカが原産の樹木。赤い果実を実らせる。未熟な果実には毒があるため、原産地ではほとんど食べられないが、持ち込まれた先のジャマイカでは食材として好まれている。"}],"223":[{"rank":"1","note":"ドラゴンの骨を探せ","exp":"75","type":"化石","name":"幼いドラゴンの骨","desc":"見たこともない、巨大な骨。なかば石化している。この大きさは既知の生物ではないだろう。ドラゴンの骨ではないかと思われるが、ドラゴンにしては小さい。子供の骨だと推測される。"}],"6804":[{"rank":"5","note":"発見物カード：465","exp":"","type":"史跡","name":"テオドシウスの城壁","desc":"5世紀初頭に、東ローマ帝国皇帝テオドシウス2世によって建設された大城壁。イスタンブール旧市街の西側を囲み、コンスタンティノープル陥落の際も、破られることはなかったため、難攻不落の城壁と謳われた。"}],"2434":[{"rank":"2","note":"ダンジョン","exp":"360","type":"財宝","name":"べっこうの櫛","desc":"べっこう製の櫛。\n素材のべっこうを生かしながら、細かな装飾も施されている。\n日本の女性は髪を梳くためだけでなく、髪飾りとしても使用するらしい。"}],"117":[{"rank":"2","note":"ギリシャの競技の像","exp":"220","type":"美術品","name":"円盤投げ","desc":"古代ギリシャの彫刻家・ミュロン作といわれる男性像。原作は青銅だと伝えられるがこれは大理石製の模作である。ローマ時代の作とされる。"}],"2523":[{"rank":"2","note":"少年好みの虫探し","exp":"260","type":"虫類","name":"テナガコガネ","desc":"台湾島付近や中国に生息するコガネムシ。雄は前脚がとても長い。繁殖能力が低いため、あまり見かけることができない。"}],"888":[{"rank":"1","note":"毒魚の地図","exp":"35","type":"海洋生物","name":"ミノカサゴ","desc":"温暖な海で見られる、扇のようなヒレを持つ魚。背ビレと胸ビレが特に大きい。このヒレの先端には毒針があり人間が刺されると死ぬこともある。"}],"3184":[{"rank":"2","note":"書きかけの地図","exp":"260","type":"地理","name":"ガスペ半島","desc":"セントローレンス川河口の南側に位置する半島。\n半島の南岸部では、古代の化石が多く発掘されている。"}],"907":[{"rank":"1","note":"白い花の地図","exp":"18","type":"植物","name":"スイセン","desc":"黄色や白の花が咲く、可憐な植物。球根で増えるため、よく群生している。かわいらしい姿に似合わず、かなり強い毒をもち、食べると死ぬこともある。"}],"2718":[{"rank":"1","note":"珍しい虫の地図","exp":"170","type":"虫類","name":"ウスリーオオカミキリ","desc":"主に朝鮮半島に生息する、大型のカミキリムシ。大きなものは10cmを超える。\nアカシデという木に寄生し、夏に見られる。"}],"5544":[{"rank":"2","note":"西シベリア平原　北東大岩付近<br/>たぶん冬・夜間・晴天<br/>大岩の西側で待ち、満月がでるとok。季節は？ですが、１時間近く待ちました。雪・曇りが多い","exp":"360","type":"気象・現象","name":"真珠母雲","desc":"通常よりも高層の上空に発生する特殊な雲。日没後に太陽の光を受けて、真珠母貝と呼ばれるアコヤガイに似た色を見せる。"}],"6984":[{"rank":"","note":"経験値1530＋765","exp":"1530","type":"中型生物","name":"ビントロング","desc":"東南アジアの密林などに生息する夜行性の動物。体がクマ、頭がネコに似ているため、クマネコとも呼ばれる。独特の香ばしい体臭が特徴。太く長い尻尾は枝に巻きつけて体を支えたり、バランスを保つ役割がある。"}],"3673":[{"rank":"4","note":"ダンジョン","exp":"780","type":"歴史遺物","name":"古代エジプトの医学書","desc":"ヒエラティックと呼ばれる書体でパピルスに記された医学書。ミイラ製作で知識を得たためか、古代エジプトの医療技術は非常に優れていたといわれ、ギリシャやローマの文献でも紹介されている。"}],"1753":[{"rank":"5","note":"釣り","exp":"828","type":"海洋生物","name":"セイルフィッシュ","desc":"バショウカジキ。比較的小型であるが、立派な背ビレが特徴の美しい魚体を持つ。"}],"1570":[{"rank":"2","note":"動く針の山","exp":"280","type":"小型生物","name":"ハリモグラ","desc":"太くて固いトゲを持つモグラ。そのトゲで外敵から身を守る。地面を掘って体を沈め、背中のトゲしか見えなくなることもある。"}],"3824":[{"rank":"5","note":"コンクガイが生む真珠<br/><br/>発見時経験値1250　発見物カード経験値625","exp":"1250","type":"財宝","name":"コンクパール","desc":"コンクガイから採れる真珠の一種。主に柔らかいピンク色で、色のむらや細かい模様を持つものもある。"}],"3267":[{"rank":"4","note":"砂漠の狩猟犬","exp":"620","type":"中型生物","name":"アザワク","desc":"西アフリカに生息する犬。足や尾が細長いながらも、筋肉は発達しているらしく、身体能力は高い。"}],"2963":[{"rank":"2","note":"羽ばたく真紅","exp":"370","type":"鳥類","name":"ノーザンカーディナル","desc":"北米東部でよく見られる赤い鳥。オスは真っ赤な羽毛だが、メスは茶色だという。"}],"2972":[{"rank":"3","note":"クエスト「おっとりしたサメ」<br/>発見物カード:240","exp":"480","type":"海洋生物","name":"ウバザメ","desc":"大きなものでは12mほどにもなるサメ。比較的寒い海に生息することが多い。大きな体に似合わず、性格はおとなしく人を襲うこともない。むしろ沿岸に現れ、簡単に捕らえられてしまうこともある。"}],"6459":[{"rank":"5","note":"","exp":"2530","type":"歴史遺物","name":"カルナの黄金鎧","desc":"インドの叙事詩、「マハーバーラタ」に登場する英雄カルナの鎧。カルナは産みの母の願いにより、鎧と耳環をつけ不死身の体で誕生したとされるが、宿敵アルジュナの父であるインドラ神の策略により、黄金の鎧を手放すことになった。"}],"2081":[{"rank":"5","note":"巨大なアリ","exp":"830","type":"虫類","name":"パラポネラ","desc":"体長3cmもあるアリ。集団生活をしているが体が大きいので単独で行動する。強力な毒を持ち、刺されると死に至ることもある。\n単体としては昆虫の中で最強と目される。"}],"4964":[{"rank":"1","note":"","exp":"","type":"歴史遺物","name":"クレタ島の陶器","desc":"古代のクレタ島で作られたとみられる陶器。風化のせいで色が薄くなってはいるが、よく見ればウシの絵が描かれているのがわかる。"}],"1456":[{"rank":"1","note":"大きな植物の地図","exp":"155","type":"植物","name":"ワトル","desc":"オーストラリアの沿岸から高地にかけて生息する木。トゲがあり、成長すると10mにもなる。"}],"6337":[{"rank":"2","note":"","exp":"260","type":"宗教遺物","name":"踊る人の石碑","desc":"南アメリカ周辺で発見された石碑。踊っているような人々の絵が刻まれている。踊っているのではなく、捕虜となった人が拷問を受けている姿だという説が主流となっている。"}],"37":[{"rank":"1","note":"ある夫妻の結婚証明","exp":"180","type":"美術品","name":"アルノルフィニ夫妻の結婚","desc":"ヤン・ファン・エイク作。銀行家夫妻の結婚証明画と思われる。絵には宗教的な象徴が多く描かれ、幸せな結婚生活を祈念したものであろう。中央の凸面鏡やシャンデリアをはじめ、筆では不可能なほど細かく描き込まれている。"}],"254":[{"rank":"1","note":"ハンブルクのマイスタージンガー","exp":"150","type":"財宝","name":"孔雀石の小箱","desc":"ハンブルクの工房で作られた、宝石細工の美しい小箱。職人が、娘を助けてくれた恩人に報いるために丹念に作った、真の宝だ。"}],"3018":[{"rank":"1","note":"古代のパイプの地図<br/><br/>発見時経験値150　発見物カード経験値75","exp":"150","type":"歴史遺物","name":"アデナのパイプ","desc":"北米のオハイオ川近辺で見つかった、古代のパイプ。紀元前の農耕文化の遺物とされる。タバコが吸われていた事実を示すものとしては、かなり古いといえる。"}],"5252":[{"rank":"5","note":"","exp":"","type":"宗教遺物","name":"オリンピアのゼウス像","desc":"世界七不思議の一つであり、遠い昔、オリンピアにて祀られていたゼウス像の複製品。右手には勝利の女神ニケの像、左手には錫杖を持つ。本来遺跡に祀られていたものはかなり巨大で全長十数mはあるらしい。"}],"6501":[{"rank":"3","note":"","exp":"","type":"宗教遺物","name":"コヨルシャウキの円板","desc":"アステカの女神・コヨルシャウキの浮彫りがある巨大な石の円板。弟にあたる太陽神ウィツィロポチトリ誕生の際に戦いを挑むが倒され、体をバラバラにされたという神話の場面を描いている。女神の名は頬につけたコヨリという鈴に由来する。"}],"132":[{"rank":"1","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40","type":"宗教遺物","name":"聖母のステンドグラス","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。"}],"2715":[{"rank":"1","note":"黄色い花の地図","exp":"110","type":"植物","name":"レンギョウ","desc":"朝鮮から中国、日本にも生息する、繁殖力が強い植物。\n早春に黄色い花を咲かせ、花が散るころに鋭利な葉を出す。"}],"393":[{"rank":"2","note":"クエスト「角とたてがみを持つ動物」<br/>発見物カード:130","exp":"260","type":"大型生物","name":"ローンアンテロープ","desc":"オス、メスともに特徴的な角とたてがみを持つ。乏しい草でも生き延び、オス1匹にメス複数匹、または若いオス同士の群れで行動する。"}],"5458":[{"rank":"2","note":"","exp":"280","type":"中型生物","name":"ペッカリー","desc":"中南米に生息するイノシシに似た生物。5～15頭ほどの群れで生活する。肉食獣に襲われると、群れの中の一頭が犠牲となる間に他の仲間が逃げるという習性がある。"}],"3152":[{"rank":"3","note":"ロレンツォの収集品","exp":"540","type":"財宝","name":"ライオンとクピドのカメオ","desc":"ロレンツォが収集していたカメオの一つ。ライオンと天使が彫られている。"}],"6517":[{"rank":"5","note":"追究クエスト<br/>発見物カード:900","exp":"1800","type":"鳥類","name":"エトピリカ","desc":"大きく美しいくちばしを持ち、夏期には目の上に特徴的な長い飾りが羽が生える海鳥。一見ペンギンのような容姿ををしているがペンギンではなく、飛ぶことができる。"}],"633":[{"rank":"4","note":"社交的な画家","exp":"780","type":"美術品","name":"キリスト昇架","desc":"「しょうか」。ルーベンス作の祭壇画。イエスが打ち付けられた十字架が、立てられようとしている場面だ。波を打つような筋肉、浮き上がるイエスの白い肉体など、これまでの宗教画と異なる表現がされている。"}],"5304":[{"rank":"5","note":"南東アフリカの風習","exp":"970","type":"宗教遺物","name":"ニャウの仮面","desc":"アフリカ南東部に住むチェワ人が葬儀の際に身に着ける仮面。仮面を着けた踊り手はニャウと呼ばれる存在になり、死者の霊を祖先の世界に届ける役目を果たすという。"}],"240":[{"rank":"2","note":"バグダッドを建設した人物","exp":"290","type":"歴史遺物","name":"アッバースの剣","desc":"ウマイヤ朝を倒してアッバース朝を興したアブー・アル・アッバースが使っていた剣。アッバース朝はモンゴルのフラグに滅ぼされるまで、約5世紀の間存続した。"}],"1503":[{"rank":"1","note":"大きな赤い花の地図","exp":"70","type":"植物","name":"ダリア","desc":"幾重にもなった花びらの中心に、黄色い管状の花が付いている。大きなもので20cm以上にもなる。"}],"186":[{"rank":"3","note":"ゼノビアの小剣","exp":"451","type":"歴史遺物","name":"女王ゼノビアの小剣","desc":"ゼノビアは、ローマ帝国に反旗を翻したパルミラの女王である。一時は巨大な領土を支配したが、アウレリアヌス帝に敗れて捕らわれローマに連れていかれた。"}],"6733":[{"rank":"5","note":"発見個所　北米西岸　ジェノヴァ新規地図","exp":"","type":"中型生物","name":"キットギツネ","desc":"北米大陸の砂漠に生息する小型のキツネ。雑食で小型哺乳類、昆虫や果実などを食べる。自分で巣穴を作る以外に他の動物の古巣も利用する。"}],"246":[{"rank":"1","note":"バルト海の湾の調査","exp":"80","type":"地理","name":"フィンランド湾","desc":"リガの北にある、東西に長い湾。水深はかなり浅い。緯度の高さにくらべて、沿岸部は比較的温暖である。"}],"5214":[{"rank":"1","note":"","exp":"","type":"歴史遺物","name":"マニオの巨石","desc":"マニオと呼ばれる森の中にある高さ6.5mほどの巨大な立石。列石から離れ、ひっそりと佇む巨石にはただならぬ存在感と神秘性を感じる。"}],"2810":[{"rank":"2","note":"古書の地図","exp":"210","type":"財宝","name":"神農本草経","desc":"後漢のころ編さんされたと思われる、個々の薬の効果について記した薬物学書。300種以上の薬物が効能によって分類されている。\n神農とは、古代の伝説の人物で農耕と医学の祖であると伝わる。"}],"5098":[{"rank":"1","note":"到達する","exp":"17","type":"港・集落","name":"トリエステ","desc":"ヴェネツィアからほど近い街。アドリア海の最奥に位置し、古代ローマ時代から港町として栄えてきた。冬季には、ボラと呼ばれるすさまじい強風が吹き荒れる。"}],"5855":[{"rank":"5","note":"","exp":"1370","type":"小型生物","name":"マヌルネコ","desc":"バイカル湖周辺などに生息するネコの仲間。体毛が長く密集して生えているため、ずんぐりして見える。威嚇の際に、上唇の片端を吊り上げ、犬歯をむき出しにする特徴的な行動をとる。"}],"6464":[{"rank":"5","note":"追究クエスト<br/>発見物カード:840","exp":"1680","type":"海洋生物","name":"乾眠中のアフリカハイギョ","desc":"地中で粘液と泥の被膜に包まれた繭の状態のハイギョ。ハイギョの肺は成長に応じて発達し、呼吸の大半をエラではなく肺で行うようになる。そのため水のなくなる乾期には、泥の中で休眠して生き延びられる。"}],"6604":[{"rank":"3","note":"","exp":"500","type":"植物","name":"ヒルギダマシ","desc":"東アフリカや東南アジアの熱帯地域沿岸にマングローブ林として見られる常緑樹。塩分に強いため、乾燥して土壌の塩分濃度が高い紅海沿岸でも自生できると言われる。"}],"1554":[{"rank":"1","note":"首の長い動物の地図","exp":"140","type":"小型生物","name":"クビナガガメ","desc":"首の長い水生のカメ。長い首は甲羅に収めることができないほどである。"}],"2376":[{"rank":"2","note":"医者が探す毒蛇","exp":"330","type":"中型生物","name":"ニホンマムシ","desc":"日本全国で見られる、太くて短い体型の蛇。毒を持ってはいるが、性格はそれほど荒くはない。\n滋養強壮効果があるため、皮や身が、薬などに用いられる。"}],"3698":[{"rank":"3","note":"珍しいシカの地図","exp":"540","type":"中型生物","name":"ミクロメリクス","desc":"シベリアジャコウジカの亜種とされる動物。生態はジャコウジカとほぼ同じであるが、あまり姿を見ることがない。"}],"5837":[{"rank":"5","note":"","exp":"1400","type":"美術品","name":"アンデスのレタブロ","desc":"アンデス地方で作られる箱型の祭壇。現地の風俗や風景が盛り込まれている。色鮮やかで特徴的なデザインは、美術品として見ても一級品である。"}],"1241":[{"rank":"2","note":"鮮やかな赤","exp":"265","type":"鳥類","name":"ショウジョウトキ","desc":"全身が鮮やかな赤色の鳥。長いくちばしを水草の間に差し込み、魚やかえるなどを捕らえる。夕暮れになると、水辺の木の上に作る巣に帰る。"}],"6249":[{"rank":"2","note":"","exp":"250","type":"地理","name":"ゴロンゴーザ山","desc":"ソファラの西にあり、住民の間では神が住んでいたといわれる山。山の周辺には人が踏破しきれないほどの大自然が広がり、未発見の動物や植物も多数生息しているとみられる。"}],"5016":[{"rank":"1","note":"到達する","exp":"68","type":"港・集落","name":"アビジャン","desc":"象牙海岸沿岸の港。周辺地域の産物が集まり栄えている。ヤシや木材のほか、象牙が産物として扱われている。"}],"3230":[{"rank":"5","note":"相容れぬものが創る詩","exp":"1100","type":"歴史遺物","name":"白銀の鎧","desc":"スカンジナビア半島に遺されたヴァイキングメイル。兜と同じく白銀で装飾された、侠気のソルフィンのもの。オリガとスノッリの一族に、口伝のサガと共に代々伝えられていたようだ。"}],"5623":[{"rank":"2","note":"太古の絵画","exp":"360","type":"史跡","name":"ターヌムの岩絵群","desc":"ターヌムスヘーデという街で発見された、岩石線画の刻まれた平面岩。青銅器時代から鉄器時代にかの地で暮らした、人々の生活をうかがい知ることができる貴重なもの。"}],"3420":[{"rank":"4","note":"父のリュート","exp":"630","type":"財宝","name":"ガリレイのリュート","desc":"ガリレオの父、ヴィンチェンツォはリュート奏者として、彼独特の音楽理論を展開させていたという。不協和音すら操るという、彼のリュートはごく普通の物にも見えるが…。"}],"6910":[{"rank":"5","note":"","exp":"","type":"小型生物","name":"クアッカワラビー","desc":"オーストラリア南西部に生息するカンガルーの仲間で、クオッカとも呼ばれる。笑っているように見える口角の上がった口元が特徴。草食性で、草葉や低木の芽などを食べる。"}],"3640":[{"rank":"5","note":"大地の音色","exp":"950","type":"財宝","name":"馬頭琴","desc":"弦楽器の一種。先端部分が馬の頭の形をしていることから、この名がある。ウマの尾毛を100本束ねた弦が2本張られており、弓を用いて演奏する。四角い共鳴箱から響く音色は奥行きがある。"}],"5879":[{"rank":"1","note":"","exp":"140","type":"地理","name":"ロンブク氷河","desc":"ヒマラヤ山脈のふもとに流れる氷河。この氷河を遡上していくことで、遥かチョモランマの高みまでたどりつける...。かもしれない。"}],"5819":[{"rank":"5","note":"","exp":"1410","type":"財宝","name":"般若経の貝葉写本","desc":"ヤシの葉で作られた般若経の写本。貝葉とは貝多羅葉の略であり、南アジアや東南アジアの筆記媒体として用いられた。"}],"1639":[{"rank":"2","note":"太平洋横断航路計画","exp":"370","type":"地理","name":"パラオ諸島","desc":"ミンダナオ島の東に位置する諸島。ごく小さい島々で構成されているため、農業には適していない。諸島の住人は散在する小島の位置を正確に把握しており各島の間には物資の交流があるようだ。"}],"2534":[{"rank":"2","note":"書きかけの地図","exp":"280","type":"地理","name":"澎湖島","desc":"かつて鄭成功が台湾島へ向かう足掛かりとした島。\n海賊の影響で荒廃しているが、人類が古くから生活していたと思われる痕跡が数多く残されている。"}],"1860":[{"rank":"2","note":"珍しい笛","exp":"230","type":"歴史遺物","name":"骨製の笛","desc":"家畜の骨でできた笛。インカの祭りに使われているのだろうか。家畜用のリャマ、もしくはアルパカの骨だと思われる。"}],"2097":[{"rank":"5","note":"貴族のわがまま","exp":"820","type":"宗教遺物","name":"ダニエル書補遺","desc":"最古の推理小説ともいわれる、カトリックの正典の一部。「アザルヤの祈りと三人の若者の賛歌」「スザンナ」「ベルと竜」の3つの短編からなる。著者は不明。"}],"6930":[{"rank":"2","note":"発見物カード:165","exp":"330","type":"化石","name":"ヒトデの化石","desc":"ヒトデが五本の腕を伸ばした状態のまま化石となったもの。きれい\nな星型をしている。"}],"5344":[{"rank":"2","note":"","exp":"350","type":"地理","name":"デ・ノローニャ諸島","desc":"サンロケ岬沖に浮かぶ島々で、20の火山島からなる。\n美しい自然に恵まれている。"}],"3883":[{"rank":"2","note":"発見物カード:110","exp":"220","type":"天文","name":"大彗星","desc":"19世紀にはいくつかの彗星が観測された。中でもゴールドラッシュと同時期に現れた彗星は非常に明るく、各地に観測の記録が残る。"}],"6968":[{"rank":"5","note":"追究クエスト<br/>発見物カード:510","exp":"1020","type":"大型生物","name":"ピューマの幼体","desc":"ピューマの幼体は成体と異なり、黒い斑点模様と縞模様の尾、青色の目を持つ。成長とともに、この特徴は消えていくが、これは周囲の環境に溶け込み、危険から身を守るためのものだと考えられる。"}],"1941":[{"rank":"1","note":"リスに似た動物の地図","exp":"140","type":"小型生物","name":"フクロシマリス","desc":"体に白黒の縞模様がある有袋類。ひどい臭いの液体をまき散らすことができる。果実などを食べる。"}],"659":[{"rank":"1","note":"小さい生物の地図","exp":"15","type":"小型生物","name":"レミング","desc":"ずんぐりしたネズミの仲間。背中に黒い筋がある。何年かごとに大発生し、集団で移動する性質がある。その際に川や海、谷にぶつかると、そのまま飛び込んで大量死することがある。"}],"3635":[{"rank":"5","note":"クエスト「北東航路東端調査」<br/>発見物カード:505","exp":"1010","type":"地理","name":"ベーリング海峡","desc":"ユーラシア大陸東端と北米大陸西端の間にある海峡。\n夏を除いて流氷に覆われており、航海は困難を極める。"}],"1633":[{"rank":"3","note":"闇夜の大騒動","exp":"451","type":"小型生物","name":"ガラゴ","desc":"大きな後肢を持ち、ときには数メートルものジャンプをする。物をしっかりとつかむために、常に尿で手を湿らせている。普段は、小さな家族単位で生活している。"}],"6702":[{"rank":"5","note":"追究クエスト「アムールヒョウの追加調査」<br/>発見物カード:650","exp":"1300","type":"大型生物","name":"ユキヒョウ","desc":"中央アジアの高山地帯に生息するヒョウ。灰色に黒い斑紋の体毛が特徴。1ｍ程長い尻尾を持つため、足場の悪い山岳でもバランスがとりやすい。人が寄り付かない高山で行動するため、民間伝承や信仰では、神秘的な生物とされている。"}],"5517":[{"rank":"5","note":"クエスト「芸術が題材の星座」<br/>発見物カード:415","exp":"830","type":"天文","name":"ちょうこくぐ座","desc":"ラカーユが制定した南天の星座。彫刻の際に使用される道具が題材にされている。明るい星がなく、並びも特徴的とは言えないため、発見する際は南中したオリオン座を基準に南東を探すことで発見できる。"}],"3667":[{"rank":"4","note":"ダンジョン","exp":"700","type":"宗教遺物","name":"チャスカ像","desc":"アンデス神話に登場する夜明けと夕暮れ、金星の女神の像。若い女性と花を守護するといわれる。"}],"5640":[{"rank":"3","note":"曇りの夕方から夜間にかけて出現。","exp":"583","type":"気象・現象","name":"カタトゥンボの灯台","desc":"マライボ湖の周辺で見られる、雷を伴う激しい嵐。しかし、落雷の音は聞こえず無音だという。この雷の光は、近隣の航海士に灯台の代わりとしても活用されているようだ。"}],"458":[{"rank":"1","note":"金細工の甲冑の地図","exp":"71","type":"財宝","name":"金細工の甲冑","desc":"地金に金で装飾を施した甲冑。金は強度がないので、装飾、もしくは祭典用であろう。"}],"3691":[{"rank":"2","note":"鮮やかな色のエビの地図","exp":"320","type":"海洋生物","name":"アカシマシラヒゲエビ","desc":"カリブのサンゴ礁域に生息するエビの一種。背中にある一本の白い筋と、それを挟む二本の赤い筋が、鮮やかな縞模様になっている。"}],"5154":[{"rank":"1","note":"到達する","exp":"24","type":"港・集落","name":"マディラ","desc":"イベリア半島から南西の島にある街。近年発見され、農業を中心に発展を始めている。緯度が低くて高温多湿なので、サトウキビが栽培されている。また、ワインの製造にも向いた気候である。"}],"3153":[{"rank":"4","note":"命を守る食器","exp":"710","type":"財宝","name":"銀食器","desc":"メディチ家が所有する銀製の食器。貴族の間ではそれほど珍しいものではないらしい。毒に反応して黒く変色することから、毒殺を防止するために使用され始めたという。"}],"5573":[{"rank":"1","note":"「天文学者の観測記録」<br/>発見物カード:95","exp":"190","type":"天文","name":"しぶんぎ座流星群","desc":"しぶんぎ座の方角から飛び出すように現れる流星群。年に一度、数時間だけ活発な動きを見せる。"}],"1474":[{"rank":"2","note":"獅子の頭を持つ像","exp":"280","type":"宗教遺物","name":"ノラシンガ像","desc":"獅子の頭部に、人間の体を持つといわれる神獣。元はヒンドゥー教神話に出てくるナラシンハという神獣ではないかとされる。ナラシンハはヴィシュヌ神の変身した姿。"}],"6417":[{"rank":"5","note":"","exp":"","type":"史跡","name":"ウルルの心臓","desc":"ウルルにあるハート型のくぼみ。その形から「ウルルの心臓」とも言われる。枯れることのないムティジュル泉の近くにある。現地の人たちからは神聖な場所として大切にされている。"}],"136":[{"rank":"2","note":"クエスト「クジャク牧場計画」<br/>発見物カード:180","exp":"360","type":"鳥類","name":"クジャク","desc":"オスの尾羽が非常に美しい、大型の鳥。飼われているクジャクの様子を見ると、ニワトリにかなり近いようだ。オスは尾羽だけでなく全身の羽が鮮やかで美しいが、メスはやや地味でかわいらしい。"}],"3722":[{"rank":"3","note":"書きかけの地図","exp":"429","type":"地理","name":"アルタイ山脈","desc":"シベリア西部からモンゴルにかけて広がる山脈。古代から人が住んでいたとされ、岩に刻まれた絵が多数残っている。"}],"6981":[{"rank":"2","note":"","exp":"","type":"港・集落","name":"サマルカンド","desc":"シルクロードの要衝として栄えた都市。東西を結ぶ中継地として古くから交易と文化の交流が行われ、これにより生まれた青いタイルは、多くのモスクや霊廟を飾り、青の都とも呼ばれている。"}],"5033":[{"rank":"2","note":"到達する","exp":"355","type":"港・集落","name":"カカドゥ","desc":"オーストラリアの北岸に位置する街。ガグジュと呼ばれる民族名が名前の由来である。周囲には湿地が広がり、数多くの動植物が生息している。また、カカドゥ周辺には壁画が多く見られ、古くから人が住んでいたことが予想される。"}],"2040":[{"rank":"2","note":"［勅命］[[運河開通を見つめる像","exp":"310","type":"宗教遺物","name":"アヌケト像","desc":"ナイル川に増水をもたらすといわれている女神の像。\nパピルスの杖と羽つきの冠をかぶったこの女神の恩恵で、エジプトは古代から栄えていたのだろう。"}],"5388":[{"rank":"","note":"","exp":"2410","type":"レリック","name":"ポセイドン神殿に眠る宝","desc":""}],"341":[{"rank":"3","note":"遺されたものたち<br/><br/>発見時経験値528　発見物カード経験値264","exp":"528","type":"財宝","name":"テッサロニケの腕輪","desc":"アレクサンドロス大王の義理の妹・テッサロニケ愛用の腕輪と見られる。この腕輪は太陽のようなモチーフがついた、豪華なものである。"}],"822":[{"rank":"2","note":"ブラフマン祭官の聖典","exp":"390","type":"宗教遺物","name":"アタルヴァ・ヴェーダ","desc":"ヒンドゥー教の聖典の一つ。呪詞を集めたもので、初期には聖典とされていなかった。民間に根ざした内容で、悪魔をはらう呪文から髪を生やす呪文まで、幅広い。"}],"1251":[{"rank":"2","note":"偏った食事","exp":"280","type":"中型生物","name":"コアリクイ","desc":"長いねばねばした舌を使い、アリを絡め取って食べる。危険を感じると、立ち上がって相手を威嚇する体勢をとる。"}],"5891":[{"rank":"2","note":"カリカット北<br/>入り口から北に進み最初の三叉路の少し東側で観測。","exp":"360","type":"気象・現象","name":"ケーララの赤い雨","desc":"インド南部で発生した赤い雨。色は黄や緑の場合もあるという。その発生原因は不明であり、人体への影響もわかっていない。"}],"6678":[{"rank":"1","note":"","exp":"200","type":"鳥類","name":"タゲリ","desc":"ミューミューとネコのような声で鳴き、きれいな冠羽を持つかわいい鳥。旅鳥で、夏は北ヨーロッパで繁殖し、冬は南ヨーロッパや北アフリカで過ごす。"}],"5017":[{"rank":"1","note":"到達する","exp":"27","type":"港・集落","name":"アムステルダム","desc":"ネーデルラント北部七州の中でも、海運で特に栄えている都市。かつてはイスパニアの支配下にあったが、圧政に反発して独立した。各種産業が発展しており、特に紡績と製鉄が盛ん。"}],"228":[{"rank":"1","note":"トロイ戦争の物語","exp":"60","type":"財宝","name":"イリアス","desc":"ホメロス作の叙事詩。ギリシャ神話のトロイ戦争を題材とし、勇者アキレウスを中心に描かれる。イリアスとは「イリオスの物語」という意味である。イリオスとは、トロイの別名。"}],"2820":[{"rank":"2","note":"クエスト「三国時代の遺物」<br/>発見物カード:165","exp":"330","type":"歴史遺物","name":"虎符","desc":"主に戦国時代～漢代に使用された、虎の形の割符。徴兵の際に用いられた。\nこの割符が合致していなければ兵を動かせなかったといわれる。"}],"5862":[{"rank":"5","note":"クエスト「小さく可愛い星座」<br/>発見物カード:665","exp":"1330","type":"天文","name":"うさぎ座","desc":"オリオン座の南にある星座で、トレミー48星座の一つ。元となった神話では、人間の身勝手さが語られており、その戒めとしてウサギを星座としたとされている。"}],"5027":[{"rank":"1","note":"到達する","exp":"25","type":"港・集落","name":"オクスフォード","desc":"ロンドンの北西に位置する学問都市。\n羊毛の集散地として栄えていたが、8世紀に女子修道院が創立された。12世紀には学者たちが集まり出し、学問の都として発展した。"}],"3165":[{"rank":"2","note":"北米東部の地理調査","exp":"350","type":"地理","name":"アパラチア山脈","desc":"北米大陸の東部に位置する山脈。北東から南西に向かって延びており、その長さは2000kmを優に超える。山脈の西側は、石炭などの豊かな地下資源を有すると見られる。"}],"270":[{"rank":"1","note":"プリンシペの島","exp":"105","type":"地理","name":"プリンシペ","desc":"アフリカ西岸に浮かぶ無人島。土壌が肥沃で農業に適すると思われる。年間を通じて非常に高温である。"}],"1729":[{"rank":"5","note":"血色の宝石<br/><br/>発見時経験値1053　発見物カード経験値526","exp":"1053","type":"財宝","name":"エンジェルハート","desc":"100カラット以上ある巨大なルビー。ルビーは1カラット以上の石が非常に少ないため、この大きさだけでとてつもない価値がある。そのうえ素晴らしい色をしているため、「天使の心臓」と名づけられた。"}],"2327":[{"rank":"4","note":"四季折々の味わい","exp":"690","type":"財宝","name":"枕草子","desc":"平安時代に清少納言が著した随筆。四季折々の自然や、宮中での行事、人間模様などが題材となっている。\n機知に富んだ内容がつづられており、筆者の優れた感性が随所に表れている。"}],"2870":[{"rank":"1","note":"小さなカメの地図","exp":"170","type":"海洋生物","name":"ミナミイシガメ","desc":"中国の広い地域に分布する夜行性のカメ。日中は水底の泥や穴の中で過ごす。\n他の個体に噛み付くなど、攻撃性の強い一面が見られる。"}],"6542":[{"rank":"5","note":"追究クエスト<br/>発見物カード:575","exp":"1150","type":"史跡","name":"ボイン渓谷の羨道墳","desc":"アイルランドにある、先史時代の羨道墳。特定の時期のみ日光が差し込むその構造は、天文学的要素を用いて造られたものと考えられる。冬至に対応した遺跡以外にも、春分に対応して造られたとみられる、ノウスと呼ばれる遺跡がある。"}],"2554":[{"rank":"3","note":"ダンジョン","exp":"510","type":"財宝","name":"北投石","desc":"台北で産出される鉱石の一種。薬石として高い医療効果が期待されており、あらゆる疾病に有効であるといわれている。"}],"3746":[{"rank":"3","note":"夜空に描かれる弧<br/><br/>発見時経験値480　発見物カード経験値240","exp":"480","type":"天文","name":"春の大曲線","desc":"ヨーロッパで春の夜空の様々な星座の目印となる星群。北斗七星のひしゃくの柄の部分から弧を描くように線を引くと、いくつかの1等星が現れる。この並びを春の大曲線と呼ぶ。"}],"2960":[{"rank":"4","note":"北のペンギン","exp":"630","type":"海洋生物","name":"オオウミガラス","desc":"空を飛べない海鳥の一種。\n「ペンギン」と呼ばれるようになった、最初の生物であるともいわれているが、我々の知るペンギンとは生態が異なるようだ。"}],"5377":[{"rank":"3","note":"到達する","exp":"","type":"港・集落","name":"アクロポリス","desc":"伝説の地アトランティスの首都。円を基本とした造りで、周囲には運河が掘られ、高い城壁で守られた難攻不落の要塞都市である。"}],"5621":[{"rank":"2","note":"丸い小鳥","exp":"380","type":"鳥類","name":"エナガ","desc":"ユーラシア大陸に広く分布する鳥の一種。いくつかの亜種が存在する。体長は15cm弱と小柄で体は丸く、首が短くて尾羽は長い。"}],"5608":[{"rank":"2","note":"","exp":"","type":"地理","name":"オンタリオ湖","desc":"北米大陸北東部に位置する湖のひとつ。湖の南西には巨大な滝がある。北東からはセントローレンス川が流れ出ている。"}],"1461":[{"rank":"1","note":"猛毒のヘビの地図","exp":"165","type":"大型生物","name":"タイガースネーク","desc":"明るい黄色の縞模様が特徴のヘビ。大変強力な毒を持ち、獲物を仕留める際に使用する。"}],"1725":[{"rank":"2","note":"意志を継いだもの","exp":"230","type":"歴史遺物","name":"チャンシッター王の盃","desc":"パガン王朝の王で、アノーヤター王の跡を引き継いでシュエジゴンパゴダの建設に尽力した。シュエジゴンパゴダには釈迦（しゃか）の遺骨や遺髪、歯などが収められているという。シュエジゴンパゴダの完成をこの盃で祝ったのだろうか。"}],"6265":[{"rank":"5","note":"","exp":"1290","type":"財宝","name":"狼の牧者に関する報告書","desc":"ロシアや東ヨーロッパで広く伝わっている、聖ゲオルギイに関する伝承を集めた報告書。三十頭の狼を引き連れた「狼の牧者」ゲオルギイの説話が収められており、現地の古い信仰とキリスト教の伝承が習合する過程がまとめられている。"}],"6389":[{"rank":"2","note":"","exp":"250","type":"中型生物","name":"ハイイロギツネ","desc":"北米から南米にかけて生息するキツネ。灰色の体毛が特徴的。木登りが上手であり「キノボリギツネ」とも呼ばれる。夜行性で昼間は巣穴などで生活する。"}],"596":[{"rank":"2","note":"黒耳の獣","exp":"260","type":"中型生物","name":"カラカル","desc":"トルコ語で「黒い耳」という言葉に由来する名のとおり、飾り毛のある黒い耳が特徴。この毛により獲物の出す小さな音を聞き分けると言われている。ものすごい跳躍力で、小鳥などの獲物を叩き落して捕食する。"}],"560":[{"rank":"1","note":"古代文字の遺物の地図","exp":"28","type":"歴史遺物","name":"ルーン文字の石碑","desc":"古代の北欧で使われていたルーン文字で銘文が刻まれた石碑。多くは業績の記録や何がしかの記念碑。北欧では石碑の建立はひんぱんに行われていた。"}],"974":[{"rank":"1","note":"法学の基盤","exp":"200","type":"財宝","name":"ローマ法大全","desc":"ビザンツ帝国皇帝・ユスティニアヌス1世が作らせた法典である。「法学提要」「学説類集」「勅法類集」「新勅法類集」からなる。法学の基礎。"}],"3831":[{"rank":"5","note":"東洋占術の解説書","exp":"1230","type":"財宝","name":"占事略决","desc":"読みは「せんじりゃっけつ」。陰陽師・安倍晴明がまとめた書物の写本。式占の一種である六壬神課に関し、基本的な説明や占いの方法が記されている。"}],"6597":[{"rank":"5","note":"レガシー伝説の王都バビロン　右上","exp":"2250","type":"歴史遺物","name":"センナケリブの六角プリズム","desc":"新アッシリア帝国の王センナケリブ自身が刻んだ碑文で、王宮の庭園などを含めた建設事業と軍事に関しての治世が記録されているという。当初は円筒型のものが使われていたがより多くのことを刻むため角柱型になったといわれる。"}],"26":[{"rank":"1","note":"アフリカの神像の地図","exp":"170","type":"宗教遺物","name":"ニャメ像","desc":"西アフリカで信仰されている至高神の像。広い範囲で信仰されているため、別名が多い。ニャメは最初地上で暮らしていたが、人間を疎んじて天空に上ったという。類似の神話は数多い。"}],"2095":[{"rank":"2","note":"［勅命］[[運河開通予定場所の調査","exp":"310","type":"地理","name":"チャグレス川","desc":"カリブ海側から内陸へ続く川。この川を利用し、地峡を越えることができれば運河が開通するのだが…。"}],"4801":[{"rank":"2","note":"ハワイの変わった神","exp":"370","type":"宗教遺物","name":"カマプアア像","desc":"ハワイ神話に登場する半人半神の英雄。普段は美男子であるが、獰猛なブタや、魚に変身することができる。火山の女神ペレと結婚、子を儲けるが、ペレと争うことも多い。"}],"1177":[{"rank":"1","note":"良港の産地","exp":"80","type":"地理","name":"フィヨルド","desc":"寒冷地に見られる、複雑に入り組んだ海岸線のこと。なにか強力な浸食によるものと思われる。水ならもっとなだらかな浸食になるので、氷によるものではないだろうか。"}],"1852":[{"rank":"5","note":"アンデスにそびえる都","exp":"520","type":"史跡","name":"クスコ","desc":"インカ帝国中心都市。クスコとは現地の言葉で「へそ」という意味だという。滑らかで美しい巨石を幾重にも組んで作られ、その間には爪の先も入らないほどだ。この技術には目を見張るものがある。"}],"2695":[{"rank":"3","note":"本当に必要なもの","exp":"530","type":"歴史遺物","name":"花郎世記","desc":"読みは、「かろうせいき」。新羅の金大門が記したという書物。\n花郎とは、新羅時代に存在した、文武に長けた青年達のこと。戦時の際には先頭に立ち、国のために戦ったという。"}],"3263":[{"rank":"4","note":"知的なおしゃれ","exp":"630","type":"鳥類","name":"ヘビクイワシ","desc":"アフリカ中部から南部にかけて分布するワシの一種。\n後頭部に長い冠羽が複数あり、それらが羽根ペンのように見えるため、「書記官鳥」と呼ばれることもある。"}],"1528":[{"rank":"1","note":"釣り","exp":"150","type":"海洋生物","name":"ナイルパーチ","desc":"ナイル川流域に広く分布するスズキの仲間。大きなものは200kgにもなるようだ。"}],"277":[{"rank":"1","note":"ペルシャの海峡","exp":"200","type":"地理","name":"ホルムズ海峡","desc":"ペルシャ湾南東部にある海峡。古代からひんぱんに船が行き来するため、すぐそばにホルムズという街がある。"}],"3309":[{"rank":"2","note":"装飾された写本の地図","exp":"340","type":"財宝","name":"ダロウの書","desc":"アイルランド、及びブリテン島で制作された最古の福音書写本。ケルズの書同様に豪華な装飾が施されている。文字は「島の文字」と呼ばれる独特の書体で書かれている。"}],"5559":[{"rank":"1","note":"ハワイの鳥の地図<br/><br/>発見時経験値140　発見物カード経験値70　文化貢献度20","exp":"140","type":"鳥類","name":"ハワイガン","desc":"ハワイ近辺の島に生息する鳥。全長60cm前後まで成長する。現地では鳴き声から「ネネ」と呼ばれる。"}],"6333":[{"rank":"5","note":"","exp":"1230","type":"海洋生物","name":"リュウグウノツカイ","desc":"太平洋・インド洋・大西洋などの深海に生息する魚類。正面から見ると、体に厚みがないのが分かる。神秘的な銀色の体と赤いヒレが特徴的だが、死ぬと体色が失われる。腹のヒレで食物を探す。食用にした記録もあり、美味だという。"}],"123":[{"rank":"1","note":"ギリシャ近海の地形","exp":"70","type":"地理","name":"コリント地峡","desc":"バルカン半島とペロポネソス半島をつなぐ、幅わずか7kmの地峡。この地域は平地が少なく乾燥気味で、オリーブ栽培や牧畜が盛んである。"}],"896":[{"rank":"4","note":"南国の不思議な花","exp":"624","type":"植物","name":"アナナス","desc":"長く固い葉を持つ植物である。厚い葉にはのこぎり状のトゲがあり中心から放射状に伸びている。茎はほとんどないようだ。花は中央に穂のようになって咲き、色鮮やかである。種類が多いようだ。"}],"2711":[{"rank":"1","note":"小さな花の地図","exp":"100","type":"植物","name":"キツネノカミソリ","desc":"朝鮮と日本の明るい森林に自生する植物。早春に葉を出して球根を太らせるが、夏になると葉を落としてしまうらしい。\nかわいらしい花を咲かせるが、有毒である。"}],"2515":[{"rank":"4","note":"病弱な母への贈り物","exp":"660","type":"植物","name":"シマトネリコ","desc":"台湾島やインドに生息する、小さくて白い花を咲かせる植物。特有の芳香を持ち、葉には光沢が見られる。\n秋になると小さな実を付ける。"}],"3788":[{"rank":"4","note":"視認","exp":"650","type":"天文","name":"カストル","desc":"ふたご座で2番目に明るい星。星座図では、双子のうち、兄の頭に位置する。名はイアソン探検隊に参加した双子のカストルに由来する。カストルとポルックスの2つの星は、多くの地域で一組に扱われ、物語が作られた。"}],"4793":[{"rank":"2","note":"巨木の地図","exp":"220","type":"植物","name":"セコイア","desc":"北米西岸に生えている杉の仲間。非常に背が高くなり、中には100m近くに達するものもあるという。分厚い樹皮に囲まれており、山火事にも強いようだ。"}],"2859":[{"rank":"2","note":"燃えるキノコ","exp":"380","type":"植物","name":"カエンタケ","desc":"中国や日本に分布する猛毒のキノコ。腐敗した木々のそばに生育する。\n真っ赤なカサの色と炎のような形から、この名が付いた。"}],"2112":[{"rank":"3","note":"サルベージ","exp":"451","type":"歴史遺物","name":"ソレン号","desc":"ダンツィヒ沖で起きたポーランド・スウェーデン間の戦闘に参加した、スウェーデン艦隊の一隻。\nポーランド艦隊旗艦に襲われ、拿捕されそうになったため、自ら船を爆破し沈没した。"}],"189":[{"rank":"3","note":"ゾウの頭を持つ神","exp":"440","type":"宗教遺物","name":"ガネーシャ像","desc":"インド神話の神の像である。シヴァとパールヴァティーの子供で、頭が象である。富と幸運、学問をつかさどるため、商売の神として非常に人気がある。"}],"3310":[{"rank":"3","note":"大国の思惑<br/><br/>発見時経験値520　発見物カード経験値260","exp":"520","type":"財宝","name":"方法序説","desc":"フランスの哲学者、デカルトの著作。物事の捉え方・考え方について、デカルト本人の自伝も含めて書かれている。三十年戦争でマウリッツ伯の軍に入隊していたころの記述もある。"}],"2139":[{"rank":"2","note":"［勅命］[[運河開通場所に潜むもの","exp":"310","type":"大型生物","name":"ナイルオオトカゲ","desc":"トカゲのような生物だが、体長がヒトより大きい個体も存在する。どうやら肉食らしく、ワニの卵や幼生すらも食べてしまうという。名前にナイルとあるがナイル川周辺以外でも目撃情報が寄せられている。"}],"5552":[{"rank":"4","note":"マヤ文明の港街","exp":"630","type":"史跡","name":"トゥルム遺跡","desc":"マヤ人が造った城塞都市の遺跡。\n13世紀から15世紀の間に、貿易で繁栄したマヤ文明最後の都市のひとつである。"}],"6540":[{"rank":"2","note":"","exp":"280","type":"史跡","name":"カイト・ベイ要塞","desc":"アレクサンドリアの半島部にある要塞。七不思議の一つアレクサンドリアの大灯台が14世紀の地震で崩壊した跡地に、マムルーク朝スルタンであるカイト・ベイが建設した。崩壊した大灯台の資材も、建造に再利用されたと考えられている。"}],"3867":[{"rank":"2","note":"クエスト「ワインの作法」<br/>発見物カード:150","exp":"300","type":"天文","name":"こいぬ座","desc":"ギリシャ神話の忠犬マイラが天に昇った姿とされる。マイラは、酒神ディオニソスからワイン作りを教わったため、非業の死を遂げた主と娘の墓を死ぬまで守り続けたという。"}],"6865":[{"rank":"3","note":"マダガスカル沖で視認","exp":"","type":"天文","name":"かみのけ座の散開星団","desc":"かみのけ座の中にある星団。数多くの星が、後頭部にあたる位置に広く散らばっている。望遠鏡だけでなく肉眼でも、星々の形を捉えられる。"}],"2919":[{"rank":"2","note":"ダンジョン","exp":"310","type":"歴史遺物","name":"タイルの欠片","desc":"美しく彩色されたヨーロッパ製のタイルの欠片。元々は教会の回廊に使用されるはずのものだが、どうやら地下に紛れ込んでしまったようだ。"}],"1863":[{"rank":"5","note":"儀式と、お守りと","exp":"1100","type":"財宝","name":"金とトルコ石のペンダント","desc":"金とトルコ石を用いた簡素な作りのペンダント。トルコ石は神聖なものとして扱われていたので、このペンダントも儀式用に作られたのかもしれない。"}],"1584":[{"rank":"3","note":"赤砂の荒野","exp":"484","type":"地理","name":"ヨーク岬半島","desc":"オーストラリア北東部に突き出た半島。北端のヨーク岬は、オーストラリアの最北の地である。東にサンゴ海、西にカーペンタリア湾が広がり、珍しい動物が数多く生息する。"}],"5177":[{"rank":"2","note":"到達する","exp":"350","type":"港・集落","name":"ルン","desc":"バンダ諸島の西部に存在するルン島の街。ナツメグの産地であり、交易の中心として注目されている。"}],"1552":[{"rank":"1","note":"書きかけの地図","exp":"110","type":"地理","name":"エア半島","desc":"オーストラリア南東部に属する半島。近海ではクジラやサメがよく観測される。他にもアシカやアザラシ、イルカなども多数生息しているようだ。"}],"1645":[{"rank":"4","note":"長く白い雲","exp":"624","type":"地理","name":"アオテアロア","desc":"ニューギニア島の南東にある島。南北に巨大な島がふたつあるが、特に北の島をアオテアロアと呼ぶ。アオテアロアとは、先住民であるマオリ人の言葉で、「長く白い雲のたなびく地」という意味である。"}],"3770":[{"rank":"4","note":"夜空に輝く赤い星","exp":"640","type":"天文","name":"火星","desc":"戦火や血を思わせる赤い色から、ローマ神話のマルスを始め、各地で戦争の神の名をつけられた惑星。他の惑星に比べ、明るさが大きく変わるのが特徴で、最も明るい時期は780日ごとにやってくる。"}],"2509":[{"rank":"3","note":"ひらり揺れる尾羽","exp":"530","type":"鳥類","name":"ヤマムスメ","desc":"台湾島にのみ生息する大きな鳥。赤いくちばしと縞模様の長い尾、青い体が特徴的。飛ぶと、尾にある二枚の長い羽がひらひらと揺れる。"}],"4851":[{"rank":"","note":"","exp":"","type":"レリック","name":"空中庭園","desc":"砂嵐に隠された古の都バビロン。美しき庭園と巨大な塔のある、かの都は今も本当に存在するのだろうか。"}],"1761":[{"rank":"4","note":"時を止めた花","exp":"720","type":"海洋生物","name":"ウミユリ","desc":"海中の生物。深い海の底に根を張り、ゆらゆらと揺れる。\n姿は、海草などの海中の植物よりも、陸上の植物に近い。しかし、海中を移動することもあるため、動物である可能性が高い。"}],"6489":[{"rank":"5","note":"レガシー女神信仰の地エフェソス　右下","exp":"2550","type":"美術品","name":"大理石の彫刻円柱","desc":"巨大な白大理石の円柱の一部。エフェソスにあった巨大神殿の柱とされる。側面は神話を題材にした見事な浮彫りが施されている。鮮やかな着色がされていたようだが、年月が経て薄れたのに加え、故意に落とされた形跡もある。"}],"1304":[{"rank":"4","note":"轟音の主","exp":"720","type":"鳥類","name":"オオサイチョウ","desc":"非常に巨大な体躯をもつ鳥。羽音も大きく、他の動物の鳴き声をかき消すほどである。繁殖期になるとメスは巣穴にこもり、オスがメスとヒナの食料を単独で調達する。その過酷さは想像を絶し、まれに餓死するオスもいるようだ。"}],"1859":[{"rank":"2","note":"奇妙な絵","exp":"220","type":"歴史遺物","name":"アタカマの巨人","desc":"黒い石で輪郭を取り、内側を平らに掘って描かれた、全長約80mほどの地上絵。平らな地面ではなく、傾斜地に描かれているのには、なにか意図があるのだろうか。"}],"1468":[{"rank":"3","note":"寺院の守護者","exp":"517","type":"宗教遺物","name":"ドゥワラパラ像","desc":"ブリハディーシュヴァラ寺院の入り口に立つ一対の石像。高さが4mもあり、一枚岩から削り出されたもので、寺院の門番である。"}],"893":[{"rank":"4","note":"謎の文書","exp":"720","type":"財宝","name":"アゾート","desc":"錬金術の書物に記述されていた、謎の多い物質。ギザのピラミッドの玄室で発見された。来歴も用法も不明だが錬金術における極めて重要な物質であるらしい。"}],"5852":[{"rank":"5","note":"","exp":"1360","type":"美術品","name":"鳥のカリグラフィー","desc":"鳥の形をしたカリグラフィー。意味のある言葉で構成されているが象徴性が強く、文字として読むことは困難である。"}],"5641":[{"rank":"2","note":"発見時経験値270　発見物カード経験値135","exp":"270","type":"財宝","name":"ウラノメトリア","desc":"17世紀の初頭に、ドイツの法律家であるヨハン・バイエルが出版した星図書。全天の星座が収録されている。星図上にギリシャ文字やローマ文字の符号を添え、参照しやすくしてある。"}],"3600":[{"rank":"3","note":"夜闇に響く水音<br/><br/>発見時経験値550　発見物カード経験値275","exp":"550","type":"小型生物","name":"ウオクイコウモリ","desc":"中南米・カリブなどに生息するコウモリの一種。川や沼の小魚などを水面から捕食する。その食性のため、体臭が強いのも特徴。"}],"1444":[{"rank":"3","note":"毛のかたまり","exp":"462","type":"鳥類","name":"キーウィ","desc":"60cmほどの体に長いくちばしを持つ鳥。そのくちばしを使って、地中のミミズや昆虫を探す。口笛のような鳴き声から、その名が付けられた。"}],"5690":[{"rank":"3","note":"2017.02.07新規追加","exp":"460","type":"財宝","name":"カザンの大皿","desc":"金の大皿。「カザン」は「大皿」という意味である。かつてタタール人の王女が川に金の大皿を落としたことから、その地をカザンと呼ぶようになったという伝説がある。"}],"1622":[{"rank":"2","note":"神か怪物か","exp":"230","type":"宗教建築","name":"ギザのスフィンクス","desc":"ギザのピラミッドの側に鎮座する巨大な像。ファラオの顔とライオンの体をもつ。古代エジプトでは、ファラオの偉大さを体現した存在とされる。\n一方、ギリシャ神話では、女性の顔と獅子の体、鷲の翼をもつ怪物とされている。"}],"2355":[{"rank":"2","note":"誰もが登る山","exp":"350","type":"地理","name":"恐山","desc":"東北北部にある山。「山」と呼ばれるが、山そのものの名ではないらしい。\n地元の人々からは信仰の対象として崇められ人間の魂は死後、この山へ行くと伝えられている。"}],"6902":[{"rank":"3","note":"発見物カード:265","exp":"530","type":"植物","name":"ホウガンノキ","desc":"南米原産の樹木。蛇のようにうねった枝に、薄紅色の花が数多く咲く。果実は直径20cmほどにもなり、見た目が大砲の砲弾に似ていることから、この名がついた。"}],"6452":[{"rank":"5","note":"レガシー・香の叡智　右上","exp":"2550","type":"歴史遺物","name":"貴妃の香","desc":"古代中国で服用されていた、食べる香「体身香」。絶世の美女といわれ、牡丹の花にも例えられた楊貴妃が愛用したとも伝わる。服用を続けると体から芳香が漂うようになるという。"}],"1141":[{"rank":"5","note":"夢を結ぶ旅路は長く","exp":"1222","type":"大型生物","name":"ナマケグマ","desc":"ずんぐりとした体と、力強い四肢を持つ。長くて粗い毛に覆われていて、爪は大きく、胸に独特の白い模様がある。果実などを食べて生活している。"}],"5160":[{"rank":"1","note":"到達する","exp":"29","type":"港・集落","name":"マルセイユ","desc":"古代ギリシャ時代にマッシリアという名で築かれた街。ヴェネツィア商人も出入りし、交易が盛んである。周辺で農業が盛んなため、種々の農作物が豊富に取引される。"}],"1771":[{"rank":"2","note":"美しい島<br/><br/>発見時経験値220　発見物カード経験値110","exp":"220","type":"地理","name":"マルガリータ島","desc":"カラカスの東に浮かぶ島。コロンの第三次航海でベネズエラが発見され、イスパニアはいち早くマルガリータ島周辺に拠点の建造を始めた。島の近海では真珠が豊富に採れるため度々海賊の襲撃に見舞われた。"}],"6479":[{"rank":"5","note":"","exp":"","type":"史跡","name":"在りし日のロードス島の巨像台座","desc":"ロードス島の港に立つ太陽神ヘリオスの巨大な青銅像。攻城者デメトリオスによる包囲を耐え切り、勝利した記念として建造された。大理石製の巨大な台座の上に、両足で港の入り口をまたぐように建てられたという説もある。"}],"6933":[{"rank":"3","note":"発見物カード:225","exp":"450","type":"天文","name":"アルレシャ","desc":"うお座のアルファ星。4等星で、暗く目立たない。2匹の魚をつなぐリボンの結び目にあり、名はアラビア語で「紐」を意味する。"}],"5649":[{"rank":"4","note":"クエスト「滅びた王朝」<br/>発見物カード:315","exp":"630","type":"史跡","name":"ベニ・ハンマードの城塞","desc":"ハンマード朝の始祖が建造したという城塞都市。すでに廃墟と化して長いが、いまだ多くの史跡が残っている。"}],"5567":[{"rank":"1","note":"","exp":"200","type":"地理","name":"ナヴァイオ海岸","desc":"ギリシャ地方のザキントス島にある入江。石灰岩の絶壁に囲まれた、透き通る青い海と白い砂浜が、箱庭のように美しい。"}],"6945":[{"rank":"2","note":"発見物カード:175","exp":"350","type":"歴史遺物","name":"ダーリ","desc":"オセアニアとニューギニアの間にある海峡諸島の先住民の頭飾り。中央には真珠や亀の甲羅があしらわれ、外側には白い鳥の羽根が飾られている。儀式の舞踊に使われるという。"}],"5471":[{"rank":"1","note":"発見時経験値120　発見物カード経験値60","exp":"120","type":"鳥類","name":"シロキツツキ","desc":"パンタナル湿原でよく見られるキツツキの一種。\n垂直な木の幹に止まることができるが、キツツキ特有のドラミングをすることはない。"}],"5378":[{"rank":"1","note":"","exp":"","type":"歴史遺物","name":"クレタ島の陶器","desc":"古代のクレタ島で作られたとみられる陶器。風化のせいで色が薄くなってはいるが、よく見ればウシの絵が描かれているのがわかる。"}],"4840":[{"rank":"3","note":"クエスト「北極星を含む星座」<br/>発見物カード:230","exp":"460","type":"天文","name":"こぐま座","desc":"ギリシャ神話の中で、クマに姿を変えられていた母親を、母親だと知らずに射ようとした狩人・アルカスが、天に上げられたとされる星座。母親と同じくクマの姿となっている。"}],"2119":[{"rank":"4","note":"迫りくる音色","exp":"740","type":"財宝","name":"ズルナ","desc":"オスマントルコの伝統的な木管楽器。\n非常に大きい音を出す楽器で、軍楽や祭礼時の舞踊の伴奏に用いられる。室内での演奏には適さない。"}],"6610":[{"rank":"2","note":"","exp":"350","type":"宗教遺物","name":"グンデストルップの大釜","desc":"鉄器時代の後期に作られたと思われる銀器。ケルトの神々のさまざまな場面が描かれている。ヨーロッパ鉄器時代のものとしては、現存する最大の銀細工とされる。"}],"5582":[{"rank":"2","note":"","exp":"290","type":"植物","name":"サトウカエデ","desc":"北米原産の落葉高木。樹液を煮詰めるとメープルシロップとなる。材質は硬く、工芸品などに利用される。"}],"1463":[{"rank":"4","note":"クエスト「黄金の国から来た男」<br/>発見物カード:335","exp":"672","type":"宗教遺物","name":"ヤジロウの碗","desc":"ヤジロウとは、ザビエルをジパングに連れてきたという東洋人である。ジパングを出てマラッカに滞在していたザビエルを訪ね、ジパングでの布教を薦めたといわれる。これはヤジロウがジパングを離れる際に持ち出した、自前の碗であるという"}],"3845":[{"rank":"1","note":"まんまるネズミ","exp":"200","type":"小型生物","name":"バンクーバーマーモット","desc":"北米西岸の一部の島に生息するリスの一種。掘った巣穴の中で生活し、冬は冬眠する。"}],"6534":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"ファザーリのアストロラーブ","desc":"古代ギリシャで考案された天文観測機器。イスラム世界では8世紀の数学者ファザーリ親子が最初に製作したと伝わり、その後イスラム世界で大きく発展した。多くは真鍮製で、太陽や月、星の位置測定や予測のほか、さまざまな機能がある。"}],"861":[{"rank":"3","note":"天才の青年時代","exp":"451","type":"美術品","name":"ピエタ","desc":"ミケランジェロ作の大理石像。処刑されたイエスを抱く聖母マリアの像である。人間の肉体、衣服のひだなど、冷たい石だとは思えない出来だ。イエスに比べてマリアが若いが、これも表現方法の一つである。"}],"2410":[{"rank":"3","note":"ダンジョン","exp":"410","type":"宗教遺物","name":"トト像","desc":"古代エジプトの神の一つ。死者の審判において、アヌビスとともに死者の罪を量り、是非の判断を下す。死者の名前の一覧を持っており、神々の書記とも呼ばれる。ヒエログリフの発明者ともされる。"}],"2954":[{"rank":"2","note":"甲高い声の青い鳥","exp":"330","type":"鳥類","name":"アオカケス","desc":"北米東部に住む鳥。頭頂部や背面、尾羽が、青い羽毛で覆われている。頭頂部には冠羽と呼ばれるものがあり、勇ましく見える。"}],"6674":[{"rank":"4","note":"発見物カード:320","exp":"640","type":"天文","name":"アルフェッカ","desc":"かんむり座で最も明るい星。名はアラビア語で「欠けたものの明るいもの」を意味する。別名のゲンマはラテン語で「宝石」を意味し冠の中央で宝石のように輝いている。"}],"773":[{"rank":"1","note":"先史時代の史跡の地図","exp":"140","type":"歴史遺物","name":"先史時代の壁画","desc":"先史時代に描かれた壁画。洞窟や古墳内部に見られる。動物や人などを描いたものが多く当時の生活がうかがい知れる。"}],"6178":[{"rank":"4","note":"","exp":"780","type":"小型生物","name":"マスクラット","desc":"体長は30センチほどあり、げっ歯類としては大きめ。主に沼に生息している。新大陸北の先住民たちに伝わる創世神話によると、マスクラットが原始の海の底に飛びこんで、大地のかけらを持ってきたという。"}],"1523":[{"rank":"1","note":"競技用具の地図","exp":"110","type":"歴史遺物","name":"ヨーク","desc":"古代の球技、「トラチトリ」で用いられた防具。「トラチトリ」は時に戦闘行為として、時に神への祈祷舞踊として行なわれた。"}],"2370":[{"rank":"1","note":"水辺のカエルの地図","exp":"90","type":"小型生物","name":"モリアオガエル","desc":"日本固有のカエル。主に本州と佐渡島に分布している。\n水中に産卵するほとんどのカエルと異なり、水面上にせり出した木の枝などに卵を産み付けるのが特徴。"}],"6607":[{"rank":"5","note":"","exp":"1150","type":"美術品","name":"ポートランドの壺","desc":"古代ローマ帝国の時代に作られたカメオ・ガラスの壺。紺碧色の地の上に、白いガラスで天使などの人物が彫られている。古代のガラス細工の中でも、最も有名で代表的なもの。"}],"712":[{"rank":"4","note":"水上を走るトカゲ","exp":"720","type":"小型生物","name":"バシリスク","desc":"全長70cm程度のトカゲである。体長の半分以上は尾で、後肢がよく発達しており、2本足で走る。足の指、特に中指が非常に長く、水面を駆け抜けることができる。"}],"3816":[{"rank":"3","note":"ある民族の像の地図","exp":"490","type":"宗教遺物","name":"セミ像","desc":"カリブ地域に古くから居住するタイノ民族が作った石像。神と先祖の霊などを形づくっており、さまざまな姿のものがある。"}],"5556":[{"rank":"5","note":"","exp":"990","type":"地理","name":"シェルビーチ","desc":"オーストラリア大陸西岸のシャーク湾に面した海岸。小さな白い貝殻が堆積して浜をなしている。"}],"220":[{"rank":"5","note":"とても小さな宝石","exp":"936","type":"鳥類","name":"マメハチドリ","desc":"とても小さな鳥。体を水平に保ち、空中で静止するように飛びながら、長いくちばしで花蜜を吸う。オスはなわばりを守るために見張りをすることが多い。"}],"7012":[{"rank":"5","note":"北西太平洋海盆視認","exp":"","type":"天文","name":"スアロキン","desc":"いるか座のアルファ星で、青白い多重星。イルカの背中部分に位置する。ベータ星ロタネブと同じく、天文学者ニコロ・カチャトーレのラテン語名「ニコラス」を逆から綴って名づけられた。"}],"6970":[{"rank":"5","note":"発見物カード:430","exp":"860","type":"財宝","name":"ミツバチを模した黄金のペンダント","desc":"クレタ島の遺跡で発見された黄金のペンダント。二匹のハチが向かい合う姿がかたどられており、垂れ下がる円型の飾りは蜂蜜のしずくを表すとされる。精巧な細工から、当時の金工技術の高さがうかがえる。"}],"1672":[{"rank":"1","note":"ネズミのような動物の地図","exp":"135","type":"中型生物","name":"カピバラ","desc":"巨大なネズミのような動物。湖や川近くの森林に生息している。集団で行動することで、外敵から身を守る。"}],"2698":[{"rank":"2","note":"鉄の国の歴史","exp":"370","type":"歴史遺物","name":"鴨形土器","desc":"動物をかたどってある土器。古代朝鮮の弁韓時代のものとされる。カモやウマのような動物から、家や船の形をしたものまであり、種類は実に豊富である。主に死者と共に墓に納めるために作られたらしい。"}],"5096":[{"rank":"1","note":"到達する","exp":"173","type":"港・集落","name":"ディヴ","desc":"アラビア海に面したインド西部の街。古代から存在したが、一度廃墟となり近郊に再建された。農業が盛んで各種作物が流通するほかエメラルドや生糸なども扱われている。"}],"406":[{"rank":"1","note":"危険な海蛇の地図","exp":"68","type":"海洋生物","name":"猛毒の海蛇","desc":"熱帯の海で見られる、海に住むヘビ。猛毒を持つものが多く、かまれるとほぼ死亡する。しかし、性質はおとなしく、刺激しなければ襲ってこないようだ。"}],"5301":[{"rank":"2","note":"","exp":"220","type":"虫類","name":"サハラサバクアリ","desc":"サハラに生息する、非常に優れた方向感覚を持つアリ。回り道をしてエサを見つけても、一直線に巣に戻れる。また、砂丘の形が風で変わっても迷うことはない。"}],"5300":[{"rank":"1","note":"","exp":"130","type":"中型生物","name":"イボイノシシ","desc":"サハラ以南のアフリカで見られる動物。見た目がイノシシに似ており、目の下と頬に一対ずつのイボがあることからこの名がついた。尻尾を立てて全力疾走する姿はなんとも言えない愛嬌がある。"}],"6660":[{"rank":"2","note":"","exp":"230","type":"小型生物","name":"アフリカウシガエル","desc":"サハラ砂漠より南のアフリカに生息するカエル。体長20cm以上になるものもある。虫以外に、小動物、鳥までも捕食する。"}],"6904":[{"rank":"4","note":"","exp":"","type":"財宝","name":"虎模様の金メダル","desc":"虎の模様があしらわれた黄金のメダル。虎が下肢を反らした曲線的な姿は、ギリシャやペルシャなどの文化の影響とみられ、東西交易が盛んであった証拠ともいえる。"}],"1812":[{"rank":"1","note":"釣り","exp":"60","type":"海洋生物","name":"シビレナマズ","desc":"発電するナマズ。小さな丸い目に円筒形の体と、愛らしい姿をしているが、強力な電気を発して小魚やカニなどを麻痺させて食べる性質を持つ。北アフリカの、ナイル川や湖などの淡水域に生息。"}],"1797":[{"rank":"2","note":"書きかけの地図","exp":"220","type":"地理","name":"アスエロ半島","desc":"パナマ湾の西にある半島。半島の各所で他の地域とは異なった形状の土器や金細工が出土する。この地域は古くから人が住み、独自の文化を発展させていたようだ。"}],"95":[{"rank":"3","note":"オーロラ姫のティアラ","exp":"506","type":"美術品","name":"オーロラ姫のティアラ","desc":"眠れる森の王女の伝説で有名な、オーロラ姫のティアラ。婚礼に用いたとされる。子孫を通じてイングランドに渡るも、戦乱で紛失。このたび、イングランドの教会に寄贈されたものが発見された。美しい細工で芸術的価値が高い。"}],"5395":[{"rank":"1","note":"","exp":"","type":"歴史遺物","name":"クレタ島の陶器","desc":"古代のクレタ島で作られたとみられる陶器。風化のせいで色が薄くなってはいるが、よく見ればウシの絵が描かれているのがわかる。"}],"2373":[{"rank":"1","note":"槌に似た頭のクジラの地図","exp":"150","type":"海洋生物","name":"ツチクジラ","desc":"北太平洋の比較的暖かい海域に生息するクジラ。体長およそ10m。頭の形が槌（つち）に似ていることから、この名が付いたという。"}],"5208":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"信楽のつぼ","desc":"美しい信楽焼のつぼ。土の色が温かみを感じさせる。古来より信楽の土は焼き物に適しているとされ、茶人や文化人に茶陶信楽として重宝された。"}],"1566":[{"rank":"1","note":"書きかけの地図","exp":"185","type":"地理","name":"カンペチェ湾","desc":"ユカタン半島と大陸に囲まれた海。天然の良港として古くから知られ、新大陸の住民たちとイスパニア人の間で長く制海権を取り合っていた。"}],"1681":[{"rank":"4","note":"槍を持った虫","exp":"732","type":"虫類","name":"ネプチューンオオカブト","desc":"槍のように長い角が二本と短い角が二本、交差するように生えている大型の虫。体表は黒色で光沢がある。"}],"2510":[{"rank":"4","note":"チョウが持つ毒<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740","type":"虫類","name":"ベニモンアゲハ","desc":"中国南部からインドにかけて生息する、黒い羽に赤や白の斑点を持つチョウ。\n幼虫時に食べる草から毒を体内に取り込み、敵から身を守る。"}],"5754":[{"rank":"5","note":"2017.02.07新規追加","exp":"1340","type":"地理","name":"ジェームズ湾","desc":"北米大陸北部の、ハドソン湾南部に位置する湾。冬から春は流氷に閉ざされるものの、発達した干潟には多くの渡り鳥が飛来する。"}],"5946":[{"rank":"3","note":"","exp":"","type":"美術品","name":"アズレージョ","desc":"ポルトガルやイスパニアで生産されるタイル細工。細密に描かれた装飾が特徴。その技術はイベリア半島にイスラム国家が進出していた時代にもたらされ、ポルトガル建築に欠かせない要素となるまでに発展を遂げた。"}],"593":[{"rank":"3","note":"黒くておいしい鳥","exp":"528","type":"鳥類","name":"シチメンチョウ","desc":"オスが1mを超える大型の鳥。頭部に羽がなく垂れ下がった肉があり独特の容貌である。興奮したりすると羽がない部分の色が変わる。ニワトリの仲間のようで、飼いやすく食用になる。"}],"1526":[{"rank":"1","note":"金細工の地図","exp":"200","type":"財宝","name":"ミステカの耳飾り","desc":"中米の中腹部に存在したといわれるミステカ民族の金の耳飾り。ヨーロッパの技術と比べても劣らない高い金加工技術を持っている。やはり、これだけのものを身に付けることができるのは王族だけだろう。"}],"1974":[{"rank":"1","note":"兜をつけた動物の地図","exp":"110","type":"小型生物","name":"カブトトカゲ","desc":"骨張った三角形の頭を持つトカゲ。一匹のオスが数匹のメスと暮らし、落ち葉の中に隠れて生活する。"}],"3780":[{"rank":"4","note":"視認","exp":"740","type":"天文","name":"アンタレス","desc":"さそり座で最も明るい1等星で、赤く輝く。星座図では、サソリの心臓に位置する。名は「アレス（火星）に対抗するもの」を意味する。"}],"1817":[{"rank":"1","note":"精巧な金細工の地図","exp":"160","type":"財宝","name":"金の腕","desc":"副葬用に作られたといわれている、金細工の腕。腕に鳥や獣のような模様、甲に戦士の模様があるなど、細工は非常に細かい。金細工の深い歴史の中で、技術が研ぎ澄まされた形跡がうかがえる。"}],"6643":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:190","exp":"380","type":"天文","name":"がか座","desc":"南天の星座。主に南半球で観測できる。はと座とちょうこくぐ座の南側に位置する。ちょうこくしつ座に置いてある画架（イーゼル）の形を表した星座で、フランスの天文学者・ラカーユが設定した。"}],"2891":[{"rank":"2","note":"書きかけの地図","exp":"350","type":"地理","name":"盤山","desc":"自然の山水や仏教の寺院が有名な、黄河下流域北方にそびえる山。松の木からなる景色、美しい水の景色など、どこを見ても魅惑的な景観を有している。"}],"1788":[{"rank":"3","note":"パンとサーカス","exp":"470","type":"歴史遺物","name":"剣闘士の兜","desc":"剣闘士とは、古代ローマの闘技場などで見世物として戦っていた、競技用戦士のこと。多くは戦争で得た捕虜などが剣闘士となったが中にはローマ市民からの志願もあった。暴君と名高いコンモドゥス帝も、剣闘士に志願した一人である。"}],"121":[{"rank":"1","note":"ギリシャの神像の地図","exp":"30","type":"宗教遺物","name":"ヘルメス像","desc":"ギリシャ神話の神像。ローマ神話ではメルクリウスやマーキュリーという。商人や羊飼いの守護神である一方、盗賊の神でもある。"}],"2089":[{"rank":"4","note":"アマゾン川の吸血魚","exp":"680","type":"海洋生物","name":"カンディル","desc":"アマゾン川流域に生息する小型のナマズ。\n全長10cm程度。\n大型魚のエラに潜り、エラを食べたり、血を吸ったりする。エラ蓋には鋭いトゲがあり、かえしの役割をする。エラへの侵入を容易にするため頭部は平たくなっている。"}],"455":[{"rank":"5","note":"禁断のイチゴ","exp":"1040","type":"小型生物","name":"ヤドクガエル","desc":"極彩色のカエル。色はさまざまで、別の種類なのか個体差なのかよくわからないほどだ。いずれも毒を持ち、特に毒が強いものは粘液を矢に塗って、狩りに使うのだそうだ。"}],"6045":[{"rank":"2","note":"","exp":"","type":"歴史遺物","name":"七部法典","desc":"カスティーリャ王アルフォンソ10世の時代に編纂された法律書。古代ローマやビザンツ帝国の法典、教会法などを下敷きとして作られ、これによって先代に統合された旧レオン王国との習慣の不一致をなくすことに成功した。"}],"3807":[{"rank":"5","note":"クエスト「聖書についての相談事」<br/>発見物カード:580","exp":"1160","type":"宗教遺物","name":"創世記（宗教遺物）","desc":"旧約聖書第一の書。世界の起源や人類の創造、イスラエル民族の古い歴史の物語などで構成されている。"}],"6379":[{"rank":"5","note":"","exp":"1060","type":"財宝","name":"ピリー・レイスの地図","desc":"オスマントルコの海軍軍人、ピリー提督が作成した世界地図。地図の製作にあたり他の地図を多く参考にしたという。やがて、この地図は「征服者」の異名を持つメフメト2世の孫であるセリム1世へと献上された。"}],"1157":[{"rank":"2","note":"コンキスタドール・コルテス","exp":"330","type":"財宝","name":"エルナン・コルテスの銃","desc":"エルナン・コルテスが本国から持ち込んだといわれる銃。彼はケツアルコアトル神と間違えられ、アステカの首都テノチティトランに入れた。そのおかげでアステカが非常に高度な軍事力を持つことを知った。"}],"908":[{"rank":"1","note":"白い花の地図","exp":"49","type":"植物","name":"スノードロップ","desc":"別名、マツユキソウ。白い花弁の可憐な花をつける。雪が解けるころに咲くため、春を告げる花だとされる。"}],"241":[{"rank":"1","note":"クエスト「バベルの塔の絵画」<br/>発見物カード:85","exp":"170","type":"美術品","name":"バベルの塔","desc":"ピーテル・ブリューゲル（父）作の絵画。建築中のバベルの塔を描いている。特に大型ではないのに、建築に携わる人や工具が非常に緻密に描かれている。本来はバビロンにあった塔だが、欧州の街をモデルに描いている。"}],"5565":[{"rank":"2","note":"","exp":"270","type":"地理","name":"ハイアムスビーチ","desc":"オーストラリア大陸の南東部にある海岸。\n真っ白に輝く、きめ細やかな砂が特徴。"}],"4976":[{"rank":"2","note":"","exp":"270","type":"宗教建築","name":"ミストラ遺跡","desc":"ペロポネソス半島南部にある城塞都市遺跡。ギリシャ神話の英雄メネラオスの神殿やフレスコ画のある修道院、ビザンツ建築の聖堂など、多くの建築物が存在する。当初は単なる防衛拠点だったが、次第に発展して城塞都市を形成したようだ。"}],"6078":[{"rank":"5","note":"","exp":"1060","type":"伝承","name":"ウンディーネ","desc":"水の精。四大元素のうち、水を司るとされる精霊。美しい女性の姿をしており、人間と結婚することで魂を得るが、夫に裏切られると魂を失い、夫に復讐したのち水に還るとされている。"}],"1608":[{"rank":"1","note":"七色の鳥の地図","exp":"135","type":"鳥類","name":"ナナイロインコ","desc":"頭と首は黄色く、胸へ行くにつれて朱色の羽毛へと変わっていく。背中は緑色で、翼と細く尖った尾は様々な色をしている。十数匹の群れで生活している。"}],"6183":[{"rank":"5","note":"","exp":"1270","type":"鳥類","name":"バミューダミズナギドリ","desc":"バミューダ海域に生息している鳥で、上面は灰褐色、下面は白い体色をしている。鳴き声がとても恐ろしく鋭いことや、バミューダ海域が船乗りに「悪魔の海域」と呼ばれていたことなどから、悪魔の使いのように恐れられているらしい。"}],"6649":[{"rank":"5","note":"クエスト「百済文化の宝庫」 発見物カード:415","exp":"830","type":"史跡","name":"扶蘇山城","desc":"百済の都城。白馬川の南にある扶蘇山に築かれた。三忠祠には、百済最後の王・義慈王に仕えた三大忠臣の位牌と肖像画が祀られている。"}],"6892":[{"rank":"2","note":"","exp":"","type":"港・集落","name":"西安","desc":"読みは「シーアン」。漢や唐など複数の歴代王朝が首都とした。唐の時代には「長安」と呼ばれ、世界的大都市の１つとされていた。シルクロードの起点とも考えられている。"}],"1016":[{"rank":"2","note":"名君の記録","exp":"210","type":"歴史遺物","name":"ビストゥン碑文","desc":"「ひぶん」。ビストゥン山の断崖に彫り込まれた巨大な碑文。アケメネス朝ペルシャのダレイオス1世の戦勝記念に作られたものだという。"}],"71":[{"rank":"2","note":"インドの菩薩像の地図","exp":"260","type":"宗教遺物","name":"菩薩像","desc":"「ぼさつぞう」。仏教の菩薩の像。菩薩というのは、もともとは悟りを開く前の釈迦を指すという。その後解釈が変わり、あえて仏とならない存在をいうようになった。"}],"2556":[{"rank":"4","note":"台湾島の鳥調査","exp":"680","type":"鳥類","name":"タカサゴマシコ","desc":"山麓の森林や農耕地に生息する鳥。\n雄は鮮やかな赤い色をしており、とても目立つが、めったに見られない。台湾島では阿里山で見かけられる。"}],"2701":[{"rank":"4","note":"王子の心残り","exp":"650","type":"宗教遺物","name":"酒泉石","desc":"朝鮮の神話に登場する不思議な石。\nこの石の窪みに水を注いでおくと、いつの間にか酒に変わっているという。"}],"561":[{"rank":"3","note":"古代文明の大都市","exp":"473","type":"史跡","name":"モヘンジョ・ダロ","desc":"インダス文明の大都市遺跡。非常によく整備された街並みを持ち、下水道すら完備されている。「死の丘」などと呼ばれるのは、全体に人骨が散在するためである。"}],"25":[{"rank":"1","note":"アフリカの最西端","exp":"90","type":"地理","name":"ヴェルデ岬","desc":"アフリカ大陸の最西端である。アフリカ大陸探検の目安にされる。「ヴェルデ」はポルトガル語で「緑」の意味である。"}],"5079":[{"rank":"1","note":"到達する","exp":"47","type":"港・集落","name":"ストックホルム","desc":"13世紀中ごろ、スウェーデンのビルイェル・ヤールによって築かれた都市。14の島を橋でつないだ構成になっている。鉱物が豊富な土地柄である。"}],"3296":[{"rank":"5","note":"ケルトの盾","exp":"840","type":"歴史遺物","name":"バタシーの盾","desc":"ロンドンの近くで発見された、青銅製の盾。なかには木製のものも存在する。装飾の特徴から、おそらくケルト文化に関するものだと思われる。"}],"3382":[{"rank":"5","note":"ノアの別名<br/><br/>発見時経験値1230　発見物カード経験値615","exp":"1230","type":"歴史遺物","name":"アトラハシス叙事詩","desc":"古代メソポタミアの叙事詩。ギルガメシュ叙事詩と同様に洪水伝説の記述がある。洪水を免れ、生存した人間の名が「アトラ・ハーシス」とされている。"}],"6396":[{"rank":"5","note":"レガシー：砂漠に栄えた巨石文明","exp":"1950","type":"歴史遺物","name":"石灰モルタルが塗られた石","desc":"石灰モルタルが塗られた大きな四角い石。石灰モルタルはギザのピラミッドにも使用されている。表面を整えたり高さを合わせたりする目的で塗られたと思われるが、この技術によってピラミッドが風化せず保たれたともいわれる。"}],"6755":[{"rank":"5","note":"","exp":"","type":"美術品","name":"桃鳩図","desc":"桃の枝に止まる鳩が描かれた中国絵画。宋の皇帝であった徽宗の作と伝わる。絵の右上に痩金体という珍しい書体で記された「大観丁亥御筆」の款記と「天水」の花押があり、さらに「御書」の朱文印が押されている。"}],"3674":[{"rank":"4","note":"ダンジョン","exp":"630","type":"歴史遺物","name":"サルコファガス","desc":"ローマのカタコンベで発見した、彫刻で装飾された石棺。イタリア半島ではエトルリア人の時代から裕福な人々の石棺を彫刻で飾る伝統があった。この石棺はキリスト教に改宗した裕福な人物のものと思われる。"}],"7006":[{"rank":"4","note":"カード経験値：340","exp":"680","type":"宗教建築","name":"ワット・シーチュム","desc":"スコータイ時代に建立されたと伝わる寺院。かつて菩提樹に囲まれていたことから、この名がついた。礼拝堂には「不変なもの」という意味を持つ巨大な座像「プラ・アチャナ」が祀られている。"}],"2378":[{"rank":"2","note":"香の材料","exp":"240","type":"植物","name":"ハマゴウ","desc":"東アジアからオーストラリアの、比較的暖かい地方に広く分布する海浜植物。果実は生薬として用いられる。\n枝や葉には香りがあり香の材料としても用いられる。"}],"1515":[{"rank":"4","note":"観世音菩薩像","exp":"624","type":"宗教遺物","name":"観世音菩薩像","desc":"読みは、かんぜおんぼさつぞう。阿弥陀如来の脇侍としてそばに安置されることも多い。全てを救い、全てをかなえるといわれていることから、多くの顔と多くの腕を持つ非人間的に表現されることも多い。基本は一面ニ臂である。"}],"1731":[{"rank":"5","note":"永遠に散らぬ花<br/><br/>発見時経験値1209　発見物カード経験値604","exp":"1209","type":"財宝","name":"パパラチア","desc":"桃色とも橙色とも取れない不思議な色のサファイヤ。セイロン島のごく限られた場所からしか産出しない。パパラチアとはサンスクリット語で「蓮の花」という意味で、これはその蓮をモチーフにした非常に繊細なデザインのイヤリングである。"}],"1802":[{"rank":"3","note":"デューラーの憂鬱","exp":"480","type":"美術品","name":"メランコリア","desc":"アルブレヒト・デューラーの代表作ともいえる銅版画。この版画の中には球や多面体から砂時計や秤などの日用品に至る様々なものが描きこまれている。これらがなにを表しているのか、デューラー本人しか知りえない。"}],"1697":[{"rank":"5","note":"鳥の羽が運ぶもの","exp":"1228","type":"大型生物","name":"オランウータン","desc":"現地語で「森の人」を意味する。オスは成長するにつれて頬袋が大きくなり、あご髭が生えてくる。生活のほとんどが樹上で、食事・睡眠に加えて繁殖も樹上で行う。"}],"5410":[{"rank":"1","note":"太陽のあふれる浜辺","exp":"20","type":"地理","name":"コスタデルソル","desc":"マラガを中心とした、300kmにおよぶ海岸線を指す。意味はスペイン語で「太陽の海岸」である。1年を通して温暖な気候で、保養地には最適だ。"}],"1507":[{"rank":"1","note":"奇妙なトカゲの地図","exp":"135","type":"小型生物","name":"トッケイ","desc":"水色の体にオレンジ色の水玉模様があるトカゲ。鳴き声は「トッケイ」と聞こえる。大型の虫やネズミなどを食べる。"}],"3761":[{"rank":"4","note":"クエスト「美しい星の集まり」<br/>発見物カード:385","exp":"770","type":"天文","name":"プレアデス星団","desc":"おうし座にある青白い星が集まった星団。プレアデスとはギリシャ神話に登場する巨人アトラスの娘でアルテミスに仕える7人姉妹である。古代ギリシャでは独立した星座として扱われていた。東洋では昴と呼ばれる。"}],"6299":[{"rank":"5","note":"","exp":"1290","type":"史跡","name":"アルハンブラ宮殿","desc":"イスパニアの古都、グラナダ郊外の丘の上にある宮殿。かつてこの地を支配したムーア人が9世紀に建てた砦に由来するという。レコンキスタ後に神聖ローマ皇帝カール5世の避暑地となり、イスラムの要素を排除する方針で改築された。"}],"5257":[{"rank":"1","note":"","exp":"100","type":"地理","name":"ベッラ島","desc":"シチリア島沿岸の小さな島。シラクサの北に位置する。周囲の海の透明度や湾の形状もあいまって、美しい景観となっている。"}],"2843":[{"rank":"3","note":"イングランドの強化弓","exp":"440","type":"財宝","name":"長弓","desc":"古来から発達していた狩猟・戦争用の弓。全長が1.2ｍのものをロングボウと呼び、草原地帯の遊牧民が使っていたショートボウと区別する。クレシーの戦いでは、ロングボウ隊を山頂付近に配置し、騎兵隊を無力化させるという活躍を見せた。"}],"661":[{"rank":"1","note":"小型肉食獣の地図","exp":"45","type":"小型生物","name":"オコジョ","desc":"イタチに似た小型の動物。冬には白い毛に生えかわる。完全な肉食で、ネズミや小鳥を食べるようだ。"}],"3623":[{"rank":"3","note":"遠征叙事詩","exp":"460","type":"歴史遺物","name":"イーゴリ遠征物語","desc":"イーゴリ公による遠征記録を綴った叙事詩。キエフ大公国時代に書かれたとされる。イーゴリ公は遊牧民撃退のため遠征を行った。"}],"769":[{"rank":"1","note":"赤道直下で咲く花","exp":"150","type":"植物","name":"熱帯スイレン","desc":"熱帯地方だけで生育するスイレン。鮮やかな色とりどりの花を咲かせる。観賞用に持ち帰りたいが、気温が低いとすぐ枯れてしまうという。"}],"837":[{"rank":"2","note":"虫の図鑑","exp":"210","type":"虫類","name":"カンター","desc":"インドの奥地に生息する大型の虫。頭部に大きなハサミのようなものが付いている。明かりに寄ってくる性質があり、虚弱体質で人間の手に渡ると、すぐに弱ってしまう。"}],"3782":[{"rank":"4","note":"視認","exp":"770","type":"天文","name":"冬のダイヤモンド","desc":"冬の大三角からベテルギウスを中心として範囲を広げ、6つの1等星を繋いで描いた六角形を、冬のダイヤモンドと呼ぶ。2等星のカストルを含めて呼ぶこともある。"}],"5988":[{"rank":"1","note":"黒死病の歴史","exp":"180","type":"地理","name":"クリミア半島","desc":"黒海の北部に張り出している半島。北東の囲まれた海域はアゾフ海という。半島の南部は温暖で過ごしやすい。14世紀の黒死病の大流行は、ここから始まったのだそうだ。"}],"3873":[{"rank":"2","note":"書きかけの地図","exp":"280","type":"地理","name":"バランスロック","desc":"北米西部の内陸にある巨大な岩。長い年月を経て岩が侵食されたのか、不安定で倒れそうに見える状態で立っている。"}],"2301":[{"rank":"4","note":"王家の墓への手掛かり","exp":"740","type":"財宝","name":"王家の首飾り","desc":"コパン遺跡から発見されたヒスイの首飾り。10cmを超える棒状のヒスイには紐が通せるようになっている。中間点には外部に通じる穴があり、その部分から別のヒスイを合わせて「Ｔ」の形を作り出している。これはコパン王家を表すとされる。"}],"5848":[{"rank":"5","note":"","exp":"1330","type":"美術品","name":"ササン朝の水晶の壺","desc":"12世紀のフランス王ルイ7世が、王妃アリエノールより贈られたとされる壺。ササン朝時代に作られたと思われる水晶の壺に、フランスで金細工を施した金具が加えられ、現在の形になった。"}],"1232":[{"rank":"3","note":"果てなき荒野","exp":"495","type":"地理","name":"パタゴニア","desc":"南米南部に位置する半島の一帯を指す。マゼランが上陸した際に、この土地に住む民族を「パタゴン」と名づけたことから、「パタゴニア」と呼ばれるようになった。"}],"5752":[{"rank":"4","note":"","exp":"720","type":"海洋生物","name":"ストーンスコーピオンフィッシュ","desc":"太平洋の東部に生息するカサゴの一種。毒を持つトゲが背ビレにあるが、体色が岩礁に酷似しているため、誤って手などを刺される者も多い。"}],"5505":[{"rank":"1","note":"座標　16051,2942","exp":"16","type":"港・集落","name":"ビルバオ","desc":"イベリア半島北部に位置する街。古くから商業の中心地であり、19世紀に入ると工業も発達してきた。"}],"357":[{"rank":"2","note":"炎の大樹","exp":"280","type":"植物","name":"ホウオウボク","desc":"マダガスカル島に多く見られる落葉樹。開花時期には真っ赤な花が木をおおいつくし、まるで炎が燃え上がっているようである。"}],"6760":[{"rank":"5","note":"","exp":"","type":"史跡","name":"ベルンの塔","desc":"16世紀、リスボンのベレン地区に建てられた塔。ヴァスコ・ダ・ガマのインド航路開拓の偉業を記念して建設されたもの。大航海時代の象徴ともいえる史跡である。"}],"2054":[{"rank":"2","note":"［勅命］[[運河開通を見つめる像","exp":"310","type":"宗教遺物","name":"アヌケト像","desc":"ナイル川に増水をもたらすといわれている女神の像。\nパピルスの杖と羽つきの冠をかぶったこの女神の恩恵で、エジプトは古代から栄えていたのだろう。"}],"5701":[{"rank":"1","note":"","exp":"170","type":"地理","name":"ランタン谷","desc":"ヒマラヤ山脈にある谷の1つ。春はシャクナゲが、夏は高山植物が谷の周辺に咲き誇り、谷を囲う秀峰と共に絶景と称されている。"}],"2485":[{"rank":"3","note":"最澄という僧を知る","exp":"440","type":"宗教遺物","name":"顕戒論","desc":"読みは、「けんかいろん」。日本の仏僧・最澄が著した書。\n平安時代における仏教制度の不平等性を批判し、自らの仏教思想の正当性を説いている。"}],"1023":[{"rank":"2","note":"黙示録に語られる大河","exp":"250","type":"地理","name":"ユーフラテス川","desc":"ペルシャを流れる大河である。チグリス川と並行して流れ、下流で合流する。この川の名は、聖書にも何度か登場する。黙示録では、この川のほとりに四人の天使がつながれているという。彼らは人間の三分の一を殺すために現れるそうだ…。"}],"5364":[{"rank":"2","note":"戯曲の題材探し<br/><br/>発見時経験値380　発見物カード経験値190","exp":"380","type":"植物","name":"クワ","desc":"初夏に赤黒い実をつける、高さ15mほどの落葉樹。もともとクワの実は白かったが、ピュラモスとティズベーの悲劇によって二人の血に染まり、赤黒い実になったという伝説がギリシャ神話に伝えられている。"}],"2655":[{"rank":"2","note":"穴開き羽の奇跡","exp":"260","type":"虫類","name":"マドタテハ","desc":"朝鮮地域に生息するタテハチョウの一種。前羽の先端部分に、切り抜かれたような穴が開いているのが特徴。\nそのさまが窓のようであることから名付けられた。"}],"1569":[{"rank":"2","note":"南東の大陸にすむ大型生物<br/><br/>発見時経験値320　発見物カード経験値160","exp":"320","type":"鳥類","name":"エミュー","desc":"体高が2mにもなる大きな鳥。翼はきわめて小さく飛ぶことができない。全身が灰褐色の毛で覆われている。"}],"6344":[{"rank":"2","note":"","exp":"260","type":"歴史遺物","name":"インディオの書簡","desc":"北米の先住民族がまとめた書簡。アンデス文明やインカ帝国についての歴史、植民政策に関する記録や考えが多くの挿絵とともに記されている。"}],"6039":[{"rank":"2","note":"","exp":"340","type":"化石","name":"巨大なカメの骨","desc":"全長約4m、全幅約5mという巨大なウミガメの骨。甲羅は骨で覆われておらず、皮か何かで覆われていたものと思われる。"}],"2331":[{"rank":"1","note":"書きかけの地図","exp":"160","type":"地理","name":"阿蘇山","desc":"九州の中央部に位置する、巨大なくぼ地内にある火山群。\nこのくぼ地は、過去の火山活動で地面が陥没してできたもののようだ。付近は湧き水が豊富で、平地では農業も行われている。"}],"6195":[{"rank":"5","note":"山壁の絵","exp":"830","type":"史跡","name":"アルタイ山脈の岩刻絵群","desc":"ザナドゥの周辺で見られる、岩に刻まれた動物たちの絵。羊や馬、ヤギなどの動物や、動物を追う狩人の姿が描かれている。古代の人々の生活の様子を垣間見れる貴重な遺跡。"}],"302":[{"rank":"2","note":"サンゴの海","exp":"360","type":"地理","name":"カイマン諸島","desc":"カリブ海のキューバ島南方に位置する諸島。発見当初はトルトゥーガ島（カメの意味）とも呼ばれた。ほとんどがサンゴ礁からなる、美しい島々である。"}],"3740":[{"rank":"5","note":"グリーンランドの居住跡","exp":"1050","type":"史跡","name":"セルメルミュート","desc":"グリーンランドで最も古く、最も大きな集落の跡。大きな遺構などはなく、一見すると単なる渓谷のようだ。"}],"498":[{"rank":"1","note":"古代ギリシャの神像","exp":"60","type":"宗教遺物","name":"ヘラ像","desc":"ギリシャ神話の女神の像。ヘラは最高神・ゼウスの妻で、結婚をつかさどる女神である。ローマ神話では、ジュノーという。嫉妬深いことで知られ、ゼウスの愛人や子供を迫害する逸話が多い。"}],"2992":[{"rank":"2","note":"凶暴そうな生物の地図","exp":"220","type":"中型生物","name":"カミツキガメ","desc":"体長が40cmを超える、大型のカメ。でっぷりとしているため、さらに大きく見える。空腹時には粗暴な性格になるため、注意が必要。"}],"5512":[{"rank":"5","note":"最古の蒸気機関","exp":"1020","type":"財宝","name":"アイオロスの球","desc":"世界最古といわれる蒸気機関。アレクサンドリアのヘロンなどが記述を残している。熱を加えると、蒸気を噴射して回転する。"}],"6671":[{"rank":"3","note":"","exp":"500","type":"海洋生物","name":"オーストラリアウンバチクラゲ","desc":"属名のキロネックスの名で知られる。体は半透明で箱形。触手は長い。世界で最も強い毒性を持ち、刺されると人間ですら数分で死に至るという。そのため「殺人クラゲ」の異名で恐れられている。"}],"1471":[{"rank":"1","note":"袋のある動物の地図","exp":"190","type":"小型生物","name":"オポッサム","desc":"腹の部分に子育て用の袋を持つ動物。ネズミのような外見をしていて、毛のない尻尾を木に巻きつけてぶら下がる。危険を感じると死んだふりをする。"}],"2351":[{"rank":"4","note":"文化が集う島","exp":"700","type":"地理","name":"琉球","desc":"沖縄本島を始めとする諸島。琉球王の統治下にある。\n中国や日本との交流があり、船が頻繁に行き来する場所である。"}],"6507":[{"rank":"2","note":"","exp":"350","type":"財宝","name":"シリンダーオルゴール","desc":"ゼンマイを巻くことで音楽を再生することができる自動演奏装置。回転するシリンダーに埋め込まれたピンが櫛歯を弾くことによって音を出す。シリンダーを入れ替えることで様々な曲を演奏することが可能。"}],"358":[{"rank":"1","note":"艶のある貝の地図","exp":"10","type":"海洋生物","name":"タカラガイ","desc":"古代では貨幣の替わりに使われたという、美しい艶をもつ貝。温暖な海でよく見られる。"}],"6547":[{"rank":"5","note":"追究クエスト","exp":"1500","type":"虫類","name":"ディノポネラ","desc":"南米の熱帯雨林に生息する巨大なアリ。非常に獰猛な性格で、強力な顎と毒針を使ってさまざまな生物に襲いかかるといわれる。最強とされるパラポネラと同じか、それ以上に危険なアリといえよう。"}],"1494":[{"rank":"2","note":"生き続ける風景","exp":"280","type":"美術品","name":"デルフトの小道","desc":"フェルメール作の風景画。生涯のほとんどを過ごした故郷デルフトを描いたといわれる。レンガの継ぎ目や扉に付けられたかんぬきなど、細部にわたって写実的に描き込まれている。まるで目に映った情景を切り取ったかのようだ。"}],"6467":[{"rank":"5","note":"追究クエスト<br/>発見物カード:550","exp":"1100","type":"大型生物","name":"ウリボウ","desc":"イノシシの幼体。ずんぐりした体に短く鋭い牙を持つ。イノシシは警戒心が強く、人間を襲うこともある動物だが、幼体はとてもかわいらしく、その瓜に似た見た目からウリボウと呼ばれる。"}],"5451":[{"rank":"3","note":"人懐っこい動物<br/><br/>発見時経験値600　発見物カード経験値300","exp":"600","type":"小型生物","name":"キンカジュー","desc":"長い尾を持つサルのような生き物。生活の大半を樹上で過ごす。移動する際は長い尾を枝に巻きつけるなどして器用に木々の間を移動する。また、夜行性であるため天敵となる存在はあまりいないようである。"}],"5474":[{"rank":"4","note":"","exp":"760","type":"植物","name":"ブラジルナッツの木","desc":"アマゾン川流域原産の高木。油脂分を多く含む実がなる。殻が大きく重いため、収穫の際には注意が必要。"}],"6415":[{"rank":"5","note":"","exp":"","type":"財宝","name":"プラトンの手引きの原本","desc":"哲学者プラトンが書いた哲学書の原本。対話形式で書かれている。元はアカデメイアの学生に向けたものとの説もある。内容は、哲学に留まらず政治や教育についても深く触れられている。"}],"1155":[{"rank":"2","note":"きれいな貝の装飾品","exp":"250","type":"歴史遺物","name":"貝の装飾品","desc":"マヤでは、貝で作られた装飾品が多く見られる。これはイヤリングのようである。"}],"5386":[{"rank":"2","note":"","exp":"230","type":"歴史遺物","name":"戦術書","desc":"ギリシャのポリュアエヌスの著作。アケメネス朝ペルシャの王・カンビュセス2世がエジプトのペルシウムの街を攻略する際に、エジプト人が神聖視していたネコを巧みに利用したという逸話を伝えている。"}],"2362":[{"rank":"4","note":"美声の主","exp":"620","type":"鳥類","name":"ウグイス","desc":"東アジアに分布する小鳥。春先から夏にかけて魅力的な鳴き声を響かせるため、春を告げる鳥とも呼ばれる。\n声の美しさに反して、羽色は地味。警戒心が強いため、姿を見せることはなかなかない。"}],"6592":[{"rank":"5","note":"レガシー伝説の王都バビロン　左上","exp":"2250","type":"史跡","name":"アイト・ベン・ハッドゥ","desc":"アトラス山脈の麓、モロッコの内陸部にある要塞化された集落跡。一つしかない入口、入り組んだ構造の通路、建物1階には窓がないなど、集落は外敵から身を守る城塞のような造りになっているという。"}],"2949":[{"rank":"2","note":"北大陸の風景","exp":"250","type":"地理","name":"マウント・デザート島","desc":"入り江を挟み、左右に分かれている島。全土で、カコウ岩でできた岩肌が見られる。人があまり踏み入っていないからか、多くの動植物が生息している。"}],"3636":[{"rank":"5","note":"モンゴルの弓技術","exp":"1180","type":"財宝","name":"合成弓","desc":"複数の材料を使用して作られた小型の弓。木や竹を主として作られるが、そこに動物の骨や金属板を張り合わせることにより、射程と破壊力を増加させた。弓職人が製造法を秘しているため、詳細な製造法は分からない。"}],"5587":[{"rank":"4","note":"","exp":"","type":"史跡","name":"スウェット・ロッジ","desc":"北米の先住民族の間で広く使用されている、儀式用の小屋。薬草の香りを含んだ蒸気で室内を満たし、心身の浄化を行う。"}],"6614":[{"rank":"5","note":"レガシー美の叡智　右上","exp":"2650","type":"歴史遺物","name":"カーテナ","desc":"イングランド王家に伝わる剣。切っ先がない形状をしていることから、慈悲の剣、無鋒剣の名でも呼ばれ、戴冠宝器の一つに数えられている。"}],"721":[{"rank":"4","note":"生きているような作り物","exp":"636","type":"美術品","name":"ポセイドンのブロンズ像","desc":"昔アテネにあったという、ポセイドンの青銅像。槍投げの瞬間を詳細に模した、精巧なもの。支えにした左足の親指は少し上がり、後ろに下げた右足は踵が上がっている。今にも動き出しそうな像である。"}],"1867":[{"rank":"3","note":"古のナイフ<br/><br/>発見時経験値490　発見物カード経験値245","exp":"245","type":"財宝","name":"金のナイフ","desc":"トゥミと呼ばれるナイフ。ケチュア語で「半円の刃」という意味である。この形のナイフはほとんど持ち手が神像になっており、一般生活用ではなく、儀式用に作られたと見られる。"}],"2824":[{"rank":"2","note":"ダンジョン","exp":"320","type":"宗教遺物","name":"太極図説","desc":"道教で重んじられる太極図を踏まえて、万物生成の原理を図式化した書物。\n万物は、陰陽と五行によって作られると説いている。"}],"1946":[{"rank":"1","note":"奇妙な石の地図","exp":"160","type":"化石","name":"トカゲの卵のような石","desc":"両手のひらに乗る程の卵状の石。すぐ近くにトカゲの骨を思わせる石があるせいか、まるでトカゲの卵のように見える。"}],"5858":[{"rank":"5","note":"","exp":"1370","type":"財宝","name":"バガヴァッド・ギーター","desc":"ヒンドゥー教の聖典の一つ。叙事詩であるマハーバーラタに含まれている。クリシュナと五王子の一人アルジュナの対話形式で書かれており、各カーストのなすべきことが語られている。"}],"2423":[{"rank":"1","note":"釣り","exp":"98","type":"海洋生物","name":"クエ","desc":"ハタ科の魚の中でも大きくなる種で、1mを超えることもある。\n夜行性で、昼間は岩場に潜み、夜になると海底付近をゆったりと泳ぎながらエサとなる魚介類を探し求める。"}],"5014":[{"rank":"1","note":"到達する","exp":"34","type":"港・集落","name":"アテネ","desc":"古代ギリシャ時代から続く、長い歴史を誇る街。アクロポリスの丘にはパルテノン神殿がそびえ、かつては高さ10mのアテナ像があったという。特産品はオリーブのほか、良質の大理石も産する。"}],"6065":[{"rank":"2","note":"カード経験190","exp":"380","type":"宗教建築","name":"メンフィスの遺跡","desc":"古代エジプトの宗教都市のひとつとされたメンフィスの遺構。プタハ神を主神とするこの地はかつて「白き壁」と称されており、下エジプト最大の都市であったという。"}],"6146":[{"rank":"3","note":"","exp":"520","type":"中型生物","name":"ガボンアダー","desc":"アフリカの中南部に生息するヘビ。最大2ｍになるという。毒牙は長いもので5cmを超え、ヘビの中で最長。大人しい性質のようだが、致死性の猛毒を有するため、下手に刺激しないほうが賢明だろう。"}],"1868":[{"rank":"4","note":"小さな赤い鐘","exp":"620","type":"植物","name":"コピウエ","desc":"堅い茎のツルのような植物。下向きに大型の花を咲かせる。鮮やかな赤い花が多い。南米大陸の南西の森林地帯に広く分布。"}],"1687":[{"rank":"5","note":"アマゾンの大蛇","exp":"1170","type":"大型生物","name":"アナコンダ","desc":"アマゾン川流域に生息する大蛇。巨大なもので7mほどに成長する。夜に活動をし、水辺に来る動物を襲うほか、ワニを食べることもある。"}],"1427":[{"rank":"3","note":"火の眠る場所","exp":"506","type":"歴史遺物","name":"カック・シフの武具","desc":"テオティワカンの将軍で、ムトゥプルを勢力下に置くことに関わった、カック・シフが使用していたといわれる武具。"}],"6952":[{"rank":"5","note":"","exp":"","type":"鳥類","name":"フラミンゴの幼鳥","desc":"桃色ではなく、白い姿をしたフラミンゴの幼鳥。フラミンゴミルクと呼ばれる親から与えられる餌や、赤い色素を持つ甲殻類などを食べることで、徐々に鮮やかな色合いに変化していく。"}],"346":[{"rank":"2","note":"隠された財宝の地図","exp":"310","type":"財宝","name":"隠し財宝","desc":"貴金属や宝石などが詰められた箱。当時の貴族や金持ちが、戦争などに備えて隠したのだろうか。"}],"3002":[{"rank":"1","note":"書きかけの地図","exp":"190","type":"地理","name":"プリンスエドワード島","desc":"北米に浮かぶ島。気候は温暖で肥沃な大地を持つ。その昔、島の南側は大陸と陸続きだったといわれている。"}],"5315":[{"rank":"3","note":"","exp":"540","type":"鳥類","name":"ハシビロコウ","desc":"アフリカ中部から南部にかけての湿地に生息する大型の鳥で、巨大なくちばしが特徴。動きがゆったりとしており、しばしば彫像のように動きを止める。獲物である魚に警戒されないようにするためだと考えられる。"}],"6454":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"エジプト王女の香油","desc":"古代エジプトで愛された調合香料、キフィ。乳香や没薬、香り高い花々で作られていた。壁画の女性が頭に載せている円錐形の固形物がキフィと考えられ、溶け出して香りを放っていたとも推測されるが、詳しくは不明である。"}],"2768":[{"rank":"5","note":"夢を結ぶ旅路は長く","exp":"1222","type":"大型生物","name":"ナマケグマ","desc":"ずんぐりとした体と、力強い四肢を持つ。長くて粗い毛に覆われていて、爪は大きく、胸に独特の白い模様がある。果実などを食べて生活している。"}],"5209":[{"rank":"1","note":"","exp":"","type":"歴史遺物","name":"百合若大臣","desc":"昔から伝わる百合若という若者の英雄譚。若者は戦の帰りに家来に裏切られ、島に置き去りにされるが苦労の末に帰郷する。古代ギリシャにも似た物語があると聞くが関連はあるのだろうか。"}],"1459":[{"rank":"1","note":"アリを食べる動物の地図","exp":"160","type":"小型生物","name":"フクロアリクイ","desc":"アリを餌とする、有袋類。大きな爪のある前足でアリの巣を壊す。"}],"2107":[{"rank":"3","note":"特別製のつぼ","exp":"490","type":"歴史遺物","name":"ケルチ様式のつぼ","desc":"カッファの周辺で栄えていた王国のために作られたつぼ。\nこのつぼを輸入していた王国も、模造品を製作していたようだ。"}],"3842":[{"rank":"2","note":"立派な角を持つシカ","exp":"350","type":"大型生物","name":"ミュールジカ","desc":"北米西部に生息するシカ。ミュールとは英語でラバを表す単語で、耳がラバに似ているためこの名で呼ばれている。枝分かれする大きな角が特徴で、この角はオスしか生えない。"}],"2896":[{"rank":"2","note":"書きかけの地図","exp":"230","type":"地理","name":"武夷山","desc":"茶葉が採れる木が自生する、暖かな気温を保つ山。\n宋代の遺跡や、朱子学の開祖が使用した書院などが残っている。"}],"6793":[{"rank":"3","note":"視認","exp":"","type":"天文","name":"シャム","desc":"や座のアルファ星。名はアラビア語で矢を意味し、元々は\n星座全体を指す言葉であったという。"}],"1324":[{"rank":"3","note":"クエスト「揺れる巨島」<br/>発見物カード:236","exp":"473","type":"地理","name":"ハルマヘラ島","desc":"テルナーテ島の東に位置する島。北部がテルナーテ王国の、南部がティドレ王国の支配下にある。島は密林に覆われ、恐ろしい熱病にかかる土地でもあるため、人口は多くない。"}],"2543":[{"rank":"2","note":"子煩悩の父","exp":"310","type":"鳥類","name":"カンムリチメドリ","desc":"台湾島に生息する、全長約15cmの小さな鳥。濃い茶色の冠のような頭と、つぶらな眼が特徴である。\n人懐こく人間のすぐ近くにまで寄ってくる。"}],"6330":[{"rank":"2","note":"壊れた寺院の地図","exp":"320","type":"宗教建築","name":"エレファンタ寺院","desc":"インド洋の北西部に浮かぶエレファンタ島にある寺院。岩山を削って作られ、ヒンドゥー教のシヴァ神が祀られている。島に作られていた石像は銃の練習台に使われたため、損傷が激しい。"}],"885":[{"rank":"1","note":"毒のある虫の地図","exp":"34","type":"虫類","name":"毒サソリ","desc":"尾の先のトゲに毒を持つ虫。体の作りはエビなどに近いようだ。毒はかなり強く、人間が死ぬこともある。砂漠地帯にいると思われがちだが、意外といろいろな地域にいる。"}],"1249":[{"rank":"2","note":"白いハート","exp":"360","type":"鳥類","name":"メンフクロウ","desc":"顔がハートの形をしたフクロウ。生息域は広く、森林、草地、サバンナなど様々である。暗闇の中でも音だけで獲物の位置を正確に捕らえ、捕獲する。"}],"3380":[{"rank":"3","note":"ウルに並ぶ都市国家","exp":"510","type":"史跡","name":"ラガシュ","desc":"古代メソポタミアにおいて栄えた、シュメール人の都市の一つ。隣国・ウンマの王であるルガルザゲシの征服によって衰退した。"}],"130":[{"rank":"1","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40","type":"宗教遺物","name":"聖母のステンドグラス","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。"}],"6619":[{"rank":"2","note":"","exp":"360","type":"宗教遺物","name":"ベケットの聖遺物箱","desc":"イングランド教会の聖人トマス・ベケットの遺物が入っていたとされる製遺物箱。外側には、ベケットが騎士に襲われ殉死する場面が描かれている。"}],"4957":[{"rank":"2","note":"クエスト「兵士の条件」<br/>発見物カード:125","exp":"250","type":"天文","name":"ミザールとアルコル","desc":"ミザールは北斗七星のひしゃくの柄の先から2番目にあたる星。アルコルはミザールのすぐ脇にある4等星。昔からこの2つの星が見分けられるか否かが視力の検査に利用されてきた。"}],"5460":[{"rank":"5","note":"","exp":"930","type":"財宝","name":"アトランティスの未来","desc":"ジョン・トラデスカントが中心となってまとめた、アトランティス調査に関する書物。島が移動する仕組みの解説や、現地調査で裏付けられた滅亡の真実、思想などがまとめられている。ある一部の高等学術機関の所蔵となるそうだ。"}],"6398":[{"rank":"5","note":"レガシー：砂漠に栄えた巨石文明","exp":"2250","type":"歴史遺物","name":"クフ王の棺","desc":"クフ王の大ピラミッドの中に置かれている花崗岩の棺。途中の通路を通れない大きさのため、建築中に作られたものとされる。発見された当時から蓋はなく中身は空だった。発見前に盗掘されたとも思えないのだが…。"}],"2096":[{"rank":"1","note":"ウサギに勝つカメ","exp":"110","type":"中型生物","name":"ヘルマンリクガメ","desc":"ヨーロッパ南部に生息するリクガメ。\n乾燥した平原に生息し雑食だが、主に植物の葉や果実を食す。\n諸説あるが、イソップ寓話「ウサギとカメ」のモデルのカメといわれている。"}],"6651":[{"rank":"5","note":"","exp":"830","type":"財宝","name":"クヌート大帝の硬貨","desc":"クヌートは、11世紀、ヴァイキングとも呼ばれたデーン人の王。イングランドのほかノルウェー、スウェーデンを征服し北海帝国を築いた。彼の肖像が刻まれた硬貨はヴァイキングの貿易の広まりと共に遠くまで流通した。"}],"2255":[{"rank":"2","note":"クエスト「島の生物調査」<br/>発見物カード:180","exp":"360","type":"中型生物","name":"ゾウガメ","desc":"甲羅の直径が1mを超す大型リクガメ。岩のような姿をしている。\n長生きで、百年以上生きるものも多い。近隣に天敵がいないせいか人が近づいても警戒しない。"}],"6429":[{"rank":"5","note":"","exp":"","type":"虫類","name":"コノハムシの卵","desc":"外見が植物の葉に似ているコノハムシのメスから産み落とされる卵は、親の外見と同様に植物の種に非常によく似ており、知らなければ一見してこれが卵とは気づけない。周囲に溶け込み生存していくために得た姿なのだろう。"}],"4348":[{"rank":"2","note":"釣り","exp":"220","type":"海洋生物","name":"カラフトマス","desc":"北太平洋に生息するサケ。川で産まれ、成体になると海で生活するが、産卵期にはまた川へ戻って卵を産む。オスのみ、繁殖期に背中が山型に変形する。"}],"2491":[{"rank":"1","note":"笛のような楽器の地図","exp":"120","type":"財宝","name":"口簧琴","desc":"読みは、「こうこうきん」。台湾島の先住民の玩具。\n竹や金属などで製作される。音程の異なる複数の弁を持つ。"}],"2564":[{"rank":"5","note":"山中の危険生物","exp":"990","type":"中型生物","name":"ヒャッポダ","desc":"台湾島や中国南部に生息する、毒を持つ危険なヘビ。このヘビに噛まれると、百歩歩くうちに死ぬと伝えられ、ヒャッポダ（百歩蛇）と呼ばれるようになった。"}],"6679":[{"rank":"4","note":"発見物カード:355","exp":"710","type":"天文","name":"カフ","desc":"カシオペヤ座にある2等星。エチオピアの王妃カシオペヤの腕の付け根にある。名はアラビア語で「染めた手」を意味する。アラビアには「プレアデスの両手」という星列がありその染められた爪にあたる星だった。"}],"5075":[{"rank":"2","note":"到達する","exp":"237","type":"港・集落","name":"ジャマイカ","desc":"カリブ海の南部に浮かぶジャマイカ島にある街。全体的に山がちなので、高山に適しているコーヒーの栽培が盛んである。"}],"946":[{"rank":"1","note":"不気味な魚の地図","exp":"97","type":"海洋生物","name":"アンコウ","desc":"かなり深い海に住む、大型の魚。平べったく巨大な口を持ち、頭から生えている枝のような突起でエサをおびきよせるらしい。"}],"909":[{"rank":"1","note":"白い花の地図","exp":"11","type":"植物","name":"デージー","desc":"小さな花弁がびっしりと集まって咲く植物。分解して調べてみると花弁の一つ一つにおしべとめしべがあった。"}],"1887":[{"rank":"3","note":"サルベージ","exp":"462","type":"歴史遺物","name":"ヒローナ号","desc":"正式名称は、ラ・ヒローナ号。イングランド侵攻に出発したイスパニア艦隊の一隻。\n艦隊はイングランド海軍に敗北。ヒローナ号は敗走中にアイルランド沖で岩礁に激突し、沈没した。"}],"6650":[{"rank":"5","note":"楽の叡智・心に響く楽器　下","exp":"","type":"財宝","name":"ヴィーナ","desc":"南インドの伝統的な弦楽器。インド神話に登場する女神・サラスバティーも弾いていたと伝わる。"}],"1516":[{"rank":"4","note":"阿弥陀如来像","exp":"624","type":"宗教遺物","name":"阿弥陀如来","desc":"あみだにょらい。仏教における、如来のひとり。名前にはサンスクリット語で「無量光」「無量寿」という意味があり、世界中を妙なる光で包むといわれている。"}],"3016":[{"rank":"1","note":"よく見る貝の地図","exp":"90","type":"海洋生物","name":"ホンビノスガイ","desc":"食用にもされる、一般的な二枚貝。殻の表面はザラザラしている。比較的多くの場所で見ることができる。"}],"6631":[{"rank":"5","note":"追求クエスト","exp":"","type":"小型生物","name":"ホッキョクウサギ","desc":"北極圏などに生息するウサギ。極寒地に適応するため、体は厚い毛皮に覆われている。夏は褐色、灰色、冬は白色と、季節ごとに毛が生え変わる。これは、周囲に身を溶け込ませ天敵から隠れるためだという。"}],"2700":[{"rank":"3","note":"正義の使者を舞うために","exp":"470","type":"財宝","name":"暗行御史の変装道具","desc":"暗行御史（あんこうぎょし）とは、朝鮮王朝において地方官の監察を秘密裏に行った国王直属の官吏。派遣された地で変装し、内偵を行う。\nより多くの情報を入手するため、さまざまな変装道具を使用する。"}],"5011":[{"rank":"2","note":"到達する","exp":"300","type":"港・集落","name":"アカプルコ","desc":"太平洋に面した、山脈ふもとの街。一年を通して気温が高い、常夏の気候である。銀を用いた交易が盛んなためヨーロッパへ向かう輸送船の往来が跡を絶たない。"}],"531":[{"rank":"1","note":"古代の道具の地図","exp":"44","type":"歴史遺物","name":"古代の農具","desc":"農作業のために使われる道具。文明によってさまざまである。"}],"4960":[{"rank":"2","note":"","exp":"380","type":"中型生物","name":"ギリシャリクガメ","desc":"北アフリカやヨーロッパ南東の乾燥した土地に生息しているカメ。住む場所によって模様の色や形が異なるが、後ろ脚の付け根にトゲのような鱗がある点は共通している。\nギリシャ織のモザイク模様が、名前の由来になっている。"}],"5704":[{"rank":"4","note":"2017.02.07新規追加","exp":"750","type":"地理","name":"ワウ・アン・ナムス","desc":"サハラ中央部分に位置する古火山のカルデラ。直径は4km程度。周辺にはオアシスがあり、隊商の給水地点としても利用されている。"}],"6514":[{"rank":"5","note":"","exp":"","type":"史跡","name":"デルフォイのスタディオン","desc":"デルフォイにあった陸上競技場。名称は古代ギリシャの距離単位に由来し、1スタディオンは約180メートルだが各都市で差があったという。デルフォイではオリンピアなどと並ぶ大規模な競技大会、ビューティア大祭が行われていた。"}],"5262":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:185","exp":"370","type":"天文","name":"オリオン座流星群","desc":"毎年十月下旬に見られる、明るい流星群。オリオン座の中でもふたご座に近い位置から飛び出るように見える。ハレー彗星が母天体とされる。"}],"2974":[{"rank":"5","note":"強き者の証明","exp":"810","type":"鳥類","name":"イヌワシ","desc":"北米大陸に広く生息する、大型の鳥。\n翼を広げると2m以上にもなる。全身が暗褐色の羽毛で覆われているが、後頭部は光沢のある黄色い羽毛で覆われている。シカやキツネを襲うこともある。"}],"5514":[{"rank":"3","note":"","exp":"","type":"地理","name":"タプー島","desc":"アンダマン海に面したパンガー湾にある海食柱。石灰岩でできており、長い時間をかけて雨や波に浸食され、今の形となった。"}],"6801":[{"rank":"3","note":"サルベージ<br/>発見物カード:265","exp":"583","type":"歴史遺物","name":"ケダー・マーチャント号","desc":"インドの商船。1698年にウィリアム・キッドに略奪され、「アドベンチャー・プライズ」と名を変えて彼の船となる。キッドが捕らえられると、手下により船は焼き払われ、サントドミンゴより東のカタリーナ島付近で沈没したとされる。"}],"6294":[{"rank":"2","note":"「書きかけの地図(サンフランシスコ)」<br/>発見物カード:165","exp":"330","type":"地理","name":"マウント・マンガヌイ","desc":"ニュージーランドの北島にある死火山。マオリの神話において、神聖な地とされている。"}],"5035":[{"rank":"1","note":"到達する","exp":"45","type":"港・集落","name":"カッファ","desc":"黒海北岸にある街。古くより交易都市として栄え、13世紀にはジェノヴァが黒海沿岸の拠点として支配。最近になってオスマントルコが占領した。トルコ絨毯も流通している。"}],"2405":[{"rank":"2","note":"屋久島のサルの調査","exp":"250","type":"中型生物","name":"ヤクシマザル","desc":"屋久島に生息する、小型のサル。体毛は粗くてやや長い。\n成長した雄の頭の毛は中心から左右に分かれている。"}],"1994":[{"rank":"2","note":"釣り","exp":"260","type":"海洋生物","name":"ブラックアロワナ","desc":"稚魚は黒い魚体だが、成魚は美しい銀色をしている。オレンジ模様のヒレを持つ。"}],"3778":[{"rank":"2","note":"クエスト「エチオピア王妃の星座」<br/>発見物カード:185","exp":"370","type":"天文","name":"カシオペヤ座","desc":"北極星を見つける際の目印となる星座。高慢なエチオピア王妃カッシオペイアが天に昇った姿とされる。自らの美しさを自慢してポセイドンの怒りを買ったため、地に下りて休むことを許されないという。"}],"6757":[{"rank":"5","note":"追究クエスト<br/>発見物カード:490","exp":"980","type":"鳥類","name":"オオウロコフウチョウ","desc":"ニューギニアに生息するフウチョウの一種。翼を広げ、規則正しく左右に首を振る、求愛のダンスで知られている。雄の亜成鳥の姿が雌と非常に似ているため、雌のふりをして雄に近づき、間近で踊りを学ぶ習性がある。"}],"684":[{"rank":"4","note":"森のコーラス","exp":"630","type":"中型生物","name":"インドリ","desc":"マダガスカルの森に、数kmにわたって響き渡るほどの声で鳴く。その声は、仲間とコミュニケーションをとる手段だと思われる。若葉や果実、花などを食べる。"}],"5346":[{"rank":"5","note":"発見物カード:655","exp":"1310","type":"天文","name":"トリトン","desc":"海王星の衛星。太陽系でも屈指の大きさを誇る。\n海王星の自転方向と逆に公転しているのが特徴。\nそのため、次第に公転速度が落ちていき、遠い将来には海王星にぶつかると考えられる。"}],"5475":[{"rank":"2","note":"黒いワニの地図<br/><br/>発見時経験値270　発見物カード経験値135","exp":"270","type":"海洋生物","name":"クロカイマン","desc":"南米大陸中央部に生息する大型のワニ。全長は4～6mほどまで成長する。身体の色が黒いのが特徴。非常に獰猛で人間を襲うこともあるようだ。"}],"13":[{"rank":"5","note":"アトランティスの財宝","exp":"822","type":"歴史遺物","name":"アトランティスの財宝","desc":"伝説のアトランティス大陸に栄えた文明の遺物だと思われるもの。精巧な細工も素晴らしいが、何より興味を引くのは、見たこともないような輝きを放つ地金である。"}],"6043":[{"rank":"5","note":"クエスト「南の鳥は南の空に」<br/>発見物カード:490","exp":"980","type":"天文","name":"ふうちょう座","desc":"南天の星座の一つ。南天の星図作成に尽力した航海者ペーテル・ケイセルらの残した観測記録を元に制定され、同時代に南半球で発見されたフウチョウの名をつけられた。「ウラノメトリア」には誤植で「インドのミツバチ座」と記載された。"}],"1806":[{"rank":"2","note":"ヨハネの首を求めた娘","exp":"350","type":"財宝","name":"サロメのヴェール","desc":"聖書の一節に登場する王女のヴェールといわれるもの。このヴェールを使った美しい舞の褒美に、「預言者ヨハネの首」と答えたという。"}],"3327":[{"rank":"4","note":"サルベージ","exp":"610","type":"歴史遺物","name":"古代ギリシャ軍の三段櫂船","desc":"ペルシャ戦争において古代ギリシャ軍が使用したとみられる船。櫂が三段に配置されており、ペルシャの大艦隊を翻弄したという高い機動力がうかがえる。"}],"5290":[{"rank":"4","note":"砂漠のカメ","exp":"680","type":"中型生物","name":"ケヅメリクガメ","desc":"サハラ南部の乾燥地帯に生息する大型のリクガメ。後ろ足と尾の間に蹴爪(けづめ)のような突起があることからこの名がついた。リクガメとしてはかなり活発に動き回る。"}],"859":[{"rank":"5","note":"天井を埋め尽くす絵画","exp":"1053","type":"美術品","name":"創世記（美術品）","desc":"ミケランジェロ作の壮大な天井画。システィナ大聖堂の天井を埋め尽くしている。題材は旧約聖書の「創世記」で、アダムの創造や楽園追放、大洪水などの有名な逸話が、躍動感に満ちた素晴らしい筆致で描かれている。"}],"3148":[{"rank":"5","note":"クエスト「「ぶどうの地」に至る道」<br/>発見物カード:505","exp":"1010","type":"地理","name":"アイスランド","desc":"ブリテン島の北西に位置する島。長い間無人島だったが、10世紀前後にケルト人やスカンジナビアの人々が移住してきた。「氷の島」の呼び名のとおり氷河で覆われた土地が多いが、火山帯に属しているため、地熱が高く比較的暖かである。"}],"5562":[{"rank":"2","note":"空に浮かんだ観測機器<br/><br/>発見時経験値350　発見物カード経験値175","exp":"350","type":"天文","name":"しぶんぎ座","desc":"フランスの天文学者ラランドによって制定された星座。彼の使用した観測機器からこの名がつけられた。一月にはこの星座の近くで流星群を見ることができる。"}],"1076":[{"rank":"4","note":"王の画家にして画家の王","exp":"780","type":"美術品","name":"キリスト降架","desc":"ルーベンス作の祭壇画の一枚。処刑されたイエスを、母マリアたちが十字架から降ろす光景である。誇張された肉体とポーズ、劇的な光の使い方など、それまでの絵画とは一線を画している。"}],"6142":[{"rank":"2","note":"","exp":"320","type":"財宝","name":"二本歯のフォーク","desc":"11世紀にヴェネツィア総督夫人となったビザンツ皇女テオドラが、結婚時に持ち込んだカテラリーの一つ。当時のヨーロッパではフォークを使う習慣が廃れていたため、彼女ともども「異教徒かぶれの文物」として非難の的になった。"}],"1789":[{"rank":"1","note":"メソアメリカの像の地図","exp":"200","type":"宗教遺物","name":"ククルカン像","desc":"ククルカンとは、アステカの神・ケツアルコアトルのマヤ語名。また、高地のある民族にはクグマッツとも呼ばれる。チチェンイッツァで特に崇められた神である。"}],"6638":[{"rank":"5","note":"","exp":"1040","type":"海洋生物","name":"ダイオウクラゲ","desc":"全長10m以上にもなるクラゲ。無脊椎動物では最大級。深海に潜んでいるため目撃情報はほとんどなく、幻のクラゲとして知られる。"}],"5760":[{"rank":"5","note":"高山の危険","exp":"1340","type":"地理","name":"死の領域","desc":"呼吸ができないほど空気が薄くなる高度。チョモランマほどの高山になれば、その苛酷さは命を落とすほど。登頂間近の登山者たちが、空気の薄さに倒れることも多いに違いない。"}],"774":[{"rank":"4","note":"尖った蹄","exp":"612","type":"中型生物","name":"シタツンガ","desc":"湿地、沼などに生息する。尖った蹄、ねじれた長い角が特徴で、水中および陸上の植物を食べる。食事中は、肩まで水中に浸かっていることもある。"}],"3009":[{"rank":"1","note":"奇妙な石の地図","exp":"160","type":"化石","name":"模様のある石","desc":"石の表面に六角形の模様が多数見られる、巨大な石。この石が発見される所では石炭も出てくるというが、なにか関係があるのだろうか？"}],"1911":[{"rank":"2","note":"まんまるでふわふわ","exp":"300","type":"小型生物","name":"チンチラ","desc":"リスをひと回り大きくしたような生物。高地の寒冷地域に生息しているためか、柔らかで密度の高い体毛をしている。夜行性で、山の岩場に棲む。"}],"6774":[{"rank":"5","note":"追究クエスト<br/>発見物カード:590","exp":"1180","type":"海洋生物","name":"アルビノナマコ","desc":"まなまこの白変種。10万体のうち1体しかいないとされる希少な個体。原因は不明だが、遺伝子変異によりメラニン色素の合成が足りず、体表が白い。希少性から、白いナマコは幸運を呼ぶものとされている。"}],"3895":[{"rank":"2","note":"クエスト「叙事詩に登場する星座」<br/>発見物カード:220","exp":"440","type":"天文","name":"うしかい座","desc":"古代ギリシャの叙事詩オデュッセイアにも記述があり、古くから存在していた星座。おおぐま座を追う牛飼いといわれるが、ギリシャ神話にはっきりとした由来がない。"}],"1880":[{"rank":"2","note":"［勅命］[[運河開通予定場所の調査","exp":"310","type":"地理","name":"チャグレス川","desc":"カリブ海側から内陸へ続く川。この川を利用し、地峡を越えることができれば運河が開通するのだが…。"}],"1309":[{"rank":"1","note":"書きかけの地図","exp":"140","type":"地理","name":"ココ川","desc":"ユカタン半島の南の半島に流れる川。コロン提督がこの地に至った際も、この川の河口から上陸したという。"}],"2848":[{"rank":"5","note":"きらびやかな庭園","exp":"810","type":"史跡","name":"豫園","desc":"読みは「ゆえん」。\n四川の役人が、故郷を懐かしむ両親のために贈った庭園。\nこの名前には、平和な楽しい園という意味が込められている。"}],"5665":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:155<br/>　","exp":"310","type":"天文","name":"ガニュメデスの脚の流星群","desc":"みずがめ座の右脚にあたる部分の方角から飛び出すように現れる流星群。年に一カ月程の間、活動が見られる。同じ時期に他の流星群の活動もあり、単体としての活動は目立ちにくい。"}],"2846":[{"rank":"3","note":"小説より面白い歴史","exp":"460","type":"財宝","name":"三国志","desc":"漢代末期から三国時代にかけての興亡を記した歴史書。\n蜀の陳寿が編さんしたと伝わっている。\nこれを元にした説話も多い。"}],"5092":[{"rank":"1","note":"到達する","exp":"37","type":"港・集落","name":"ダンツィヒ","desc":"10世紀ごろに建設された都市。14世紀には、ハンザ同盟にも加入した。造船業が活発なため、造船都市としての地位を確立する。"}],"5540":[{"rank":"3","note":"","exp":"220","type":"財宝","name":"アサラト","desc":"西アフリカに伝わる打楽器。木の実の中に種を入れ、二つの木の実を紐で繋げて振って鳴らす。子どもをあやすために作られた打楽器で、現地では玩具として親しまれている。"}],"1476":[{"rank":"2","note":"ラーマを助ける猿の神<br/><br/>発見時経験値280　発見物カード経験値140","exp":"280","type":"宗教遺物","name":"ハヌマーンのレリーフ","desc":"ラーマーヤナに登場するハヌマーンのレリーフ。同じくラーマーヤナに登場する魔王・ラヴァナとの合戦の様子を彫りこんだもののようだ。"}],"5503":[{"rank":"4","note":"","exp":"","type":"財宝","name":"古代のセッケン","desc":"動物性の脂肪と灰を混ぜて作られる伝統的なセッケン。柔らかく、独特の臭いがある。"}],"1591":[{"rank":"2","note":"腹に袋を持つ動物の像","exp":"330","type":"宗教遺物","name":"オポッサム像","desc":"オポッサムとは、腹に袋を持ち袋の中で子を育てる小型のねずみ。メソアメリカでは神格化され、多くの像が作られた。"}],"3485":[{"rank":"","note":"","exp":"","type":"レリック","name":"ディドー","desc":"地中海世界でローマと覇を競ったカルタゴ。その伝説の建国者は運命に翻弄された美しき女王であったといわれる。"}],"2518":[{"rank":"1","note":"植物の生息地図","exp":"100","type":"植物","name":"ヒイラギナンテン","desc":"台湾島や中国南部などに分布する、乾燥に強い低木。筒状に集まった、小さくて黄色い花を咲かせる。\n葉の縁がギザギザになっており、先端は硬い針状である。"}],"2889":[{"rank":"2","note":"角のある大型獣の地図","exp":"280","type":"大型生物","name":"ターキン","desc":"中国南西部に生息している、湾曲した大きな角が特徴の動物。\n夏は大規模な群れを形成するが、冬には小規模な群れへと分散する習性を持つ。"}],"5796":[{"rank":"5","note":"教皇領の根拠","exp":"1360","type":"歴史遺物","name":"コンスタンティヌスの寄進状","desc":"教皇領成立の根拠として用いられた寄進状。コンスタンティヌス帝の書いたものとされているが、偽書ではないか、と疑われている。"}],"5588":[{"rank":"3","note":"ロッキー地方東のテーブル岩付近で現象は発見できるも、視認できず。テーブル岩の北方で視認できる。","exp":"530","type":"気象・現象","name":"ダイヤモンドダスト","desc":"太陽などの光源により極小の氷の粒が光り輝くように見える現象。発生には天候や気温、風向きなどが密接に関係しているため観測は困難である。"}],"6842":[{"rank":"5","note":"発見物カード:440","exp":"880","type":"地理","name":"メグナ川","desc":"ベンガル地方の東部を流れ、ベンガル湾へと注ぐ川。ガンジス川、ブラマプトラ川と合流し、広大な三角州を形成している。"}],"3908":[{"rank":"2","note":"発見物カード:120","exp":"240","type":"天文","name":"しし座流星群","desc":"しし座の方角から飛び出してくるように見える流星群。1833年に大出現し、北米東部では眠っている人が流星の明るさで目が覚めるほどだったといわれる。"}],"651":[{"rank":"1","note":"書きかけの地図","exp":"20","type":"地理","name":"ボニファシオ海峡","desc":"ジェノヴァの南に浮かぶ、コルシカ島とサルデーニャ島の間にある海峡。ナポリからバルセロナに向かうときはこの海峡を通ると近いだろう。"}],"1187":[{"rank":"2","note":"若い男の悩み","exp":"380","type":"地理","name":"アセンション","desc":"南大西洋に浮かぶ小さな島。まさに絶海の孤島で、アフリカ大陸まで2000kmはある。正確に島にたどりつくことが困難なので、ここに街を作るのは無理だと思われる。"}],"3904":[{"rank":"4","note":"発見物カード:355","exp":"710","type":"天文","name":"カシオペヤ座の新星","desc":"1572年にカシオペヤ座に現れた新星。詳細な記録を残したデンマークの天文学者ティコ・ブラーエの名にちなみティコの星とも呼ばれることもある。ティコはこの星が位置を変えないことから、大気中ではなく、宇宙で起きる現象であると唱えた。"}],"2788":[{"rank":"5","note":"華南の大仏","exp":"1080","type":"宗教建築","name":"楽山大仏","desc":"四川の山の西壁に彫られた、高さ70mほどの石刻座仏。治水と航行の安全を祈願して作られた。\n完成当初は、全身が金色で彩られていたという。"}],"6289":[{"rank":"4","note":"","exp":"620","type":"大型生物","name":"インドサイ","desc":"インド東北部の草原に生息しているサイ。\n頭部には一本の角があり。体皮は鎧のように堅固でひだ状に折れ曲がっている。\n角に薬効があると信じられ、よく狩られているが、その巨体に体当たりされて死ぬ人も多いようだ。"}],"1912":[{"rank":"2","note":"奇妙な頭蓋骨の地図","exp":"300","type":"宗教遺物","name":"飾られた頭蓋骨","desc":"メソアメリカの地で見つかった、見事な装飾の頭蓋骨。ターコイズをふんだんに使っている。元は頭蓋骨の面を全て覆っていたのだろうか。"}],"6575":[{"rank":"5","note":"","exp":"1550","type":"歴史遺物","name":"動物型土製品","desc":"日本で発見された、土製の焼き物。土偶は地母神信仰から人の女性の形をしているものが多いというのが通説だが、これらは動物の姿をしている。狩猟の儀式のために作られたものだろうか。"}],"4954":[{"rank":"3","note":"","exp":"540","type":"史跡","name":"パルテノン神殿","desc":"アテネにあるアクロポリスの丘に建てられた神殿。アテネの守護神である、女神アテナの聖域といわれている。白大理石を使用したパルテノン神殿には、細部の装飾が美しい古代ギリシャの建築様式が用いられている。"}],"6905":[{"rank":"4","note":"南東の大陸にすむワニ","exp":"624","type":"大型生物","name":"クロコダイル","desc":"細長い口先が特徴的なワニ。体長は2.5mほどで、地上をすばやく動くことができる。"}],"5907":[{"rank":"5","note":"","exp":"1480","type":"宗教建築","name":"骸骨礼拝堂","desc":"大聖堂に併設された納骨堂。周辺の修道会墓地から集められた何千柱もの骸骨が、内装として用いられている。"}],"3001":[{"rank":"2","note":"「書きかけの地図」<br/>発見物カード:110","exp":"220","type":"地理","name":"パムリコ湾","desc":"複数の岬に囲まれた、三角状の入り江。黒髭と恐れられている海賊が活動拠点にしていたといわれている。もしかすると現在も…。"}],"3168":[{"rank":"3","note":"思想の議論","exp":"480","type":"財宝","name":"プラトンの手引き","desc":"ソクラテスの弟子プラトンが書いた哲学書。コジモの侍医であるマルシリオ・フィチーノによりラテン語に翻訳され、フィレンツェに広まった。"}],"557":[{"rank":"1","note":"古代ローマ皇帝のレリーフ","exp":"70","type":"歴史遺物","name":"トラヤヌス帝のレリーフ","desc":"トラヤヌス帝は五賢帝の一人で、ローマ帝国最大の版図を築いた。このレリーフは、戦勝記念に作らせたものと言われる。"}],"1054":[{"rank":"5","note":"歴史の裏側","exp":"962","type":"歴史遺物","name":"ヒッタイトの和平交渉文書","desc":"ヒッタイトがエジプトと戦ったカデシュの戦いについて書かれた文書。エジプトと停戦に至った経緯が詳細に書かれている。ただし、エジプトで見つかった同文書とはかなり内容が食い違っている。"}],"6477":[{"rank":"5","note":"レガシー　港湾都市ロードス　右上","exp":"","type":"歴史遺物","name":"巨像の灯火皿","desc":"ロードス島の巨像が右手に掲げていたという巨大な灯火皿。伝説では精妙な機構が組み込まれ、敵に煮えたぎった油を注ぎかけて撃退したという。また巨像の頭の内部に灯火が設置され、両眼から光を発していたという説もある。"}],"5401":[{"rank":"3","note":"パラグアイ川上流。入り口右の水辺。<br/>釣りR10+1<br/><br/>発見時経験値480　発見物カード経験値240","exp":"480","type":"海洋生物","name":"ドラド","desc":"金色に輝くサケに似た大型の淡水魚。成魚は体長1mにもなる。その姿から、スペイン語で黄金を意味するドラドの名がついた。鋭い歯と強靭なあご、獰猛な性格から、川の虎とも呼ばれている。南米の河川でのみ見られる。"}],"5273":[{"rank":"2","note":"ガラパゴス奥地　再調査報酬","exp":"220","type":"歴史遺物","name":"インカの土器","desc":"インカ帝国で使われていたものとよく似た模様の土器。かつてはインカ人が島を訪れていたと思われる。この場所になにを求めて来たのだろうか。"}],"6681":[{"rank":"3","note":"","exp":"500","type":"大型生物","name":"ゴトランドポニー","desc":"スウェーデンのゴトランド島原産の馬。体高は120cmほどでポニーに分類される。石器時代には存在していたとされる古い品種で、絶滅種であるターパン馬の子孫だと考えられている。"}],"1221":[{"rank":"2","note":"マヤの気象を司る神","exp":"290","type":"宗教遺物","name":"チャック像","desc":"アステカの神・トラロックと同列とされる雨の神。雨だけでなく、様々な気象を司るといわれている。"}],"1693":[{"rank":"5","note":"ペルガモンの忘れ形見","exp":"910","type":"美術品","name":"瀕死のガリア人","desc":"ペルガモン王国の王、アッタロス1世が作らせたといわれている青銅像の模造。模造でありながら非常によい出来である。ペルガモン王国に度々侵攻したガラティア人が死に直面したときの複雑な表情を見事に表している。"}],"5700":[{"rank":"5","note":"2017.02.07新規追加","exp":"950","type":"化石","name":"海の生物の化石","desc":"チョモランマで発見された、海の生物の模様を含んだ石。山の上でこのような石が多数見つかる理由は、いまだ解明されていない。"}],"3617":[{"rank":"4","note":"クエスト「氷の地のクマ」<br/>発見物カード:365","exp":"730","type":"大型生物","name":"ホッキョクグマ","desc":"北極圏などに生息する全身が白いクマ。\n他のクマよりも頭部が小さく、首が長い。基本的には陸上で活動するが、まれに泳ぐ姿も見られる。"}],"636":[{"rank":"1","note":"宗教画の新しい流れ","exp":"60","type":"美術品","name":"人間を守るキリストの犠牲","desc":"フランス・フロリス作の宗教画。非現実的な象徴を集めた、不思議な構成になっている。フランドル地方の画家らしく、プロテスタント寄りの内容になっている。"}],"6615":[{"rank":"5","note":"レガシー美の叡智　左上","exp":"3150","type":"歴史遺物","name":"草薙剣","desc":"日本における三種の神器の一つ。ヤマトタケルが東国の征伐に赴く際、敵が火攻めした草をこの剣でなぎ払ったことから、「草薙剣」の名が与えられたという説がある。これが本当の草薙剣なのかは分からない。"}],"1049":[{"rank":"3","note":"猟犬","exp":"462","type":"中型生物","name":"サーバル","desc":"サーバルは「猟犬」という意味のポルトガル語に由来する。大きな耳と長い肢は、草たけの高い草原の中で、ウサギやネズミなどの獲物を捕らえるのに役立つ。"}],"7018":[{"rank":"3","note":"","exp":"","type":"鳥類","name":"シュモクドリ","desc":"アフリカ南部の草原や水辺に生息する鳥。全身は褐色の羽毛で覆われている。頭部が鐘を叩く撞木のように見えることが名の由来とされる。巣作りには数千本もの枝を使い、完成までに一カ月以上かかるという。"}],"6217":[{"rank":"2","note":"","exp":"260","type":"虫類","name":"ペルーオオムカデ","desc":"熱帯雨林に生息するムカデ。ギガスオオムカデという別名の通り、ムカデの中でもひときわ巨大である。昆虫類やヘビを食べるほか、洞窟の天井からぶら下がって、飛んできたコウモリを空中で捕らえることもあるという。"}],"1517":[{"rank":"1","note":"野生のシカの地図","exp":"110","type":"大型生物","name":"ミズシカ","desc":"濃い茶色の被毛で覆われたシカ。オスは長さ1m以上の三股の枝角を持つ。夜行性でさまざまな植物を餌とする。"}],"6061":[{"rank":"2","note":"","exp":"240","type":"史跡","name":"カステル・デル・モンテ","desc":"神聖ローマ皇帝フリードリヒ2世が建造した城。\n建てられた用途は定かではないが、軍事用の城塞ではなく、狩りの拠点であったという説もある。八角形を取り入れた特徴的な構造をしている。"}],"5261":[{"rank":"2","note":"コナーラク地方　再調査報酬","exp":"","type":"歴史遺物","name":"古代インドの建築技芸書","desc":"インド各地にあるといわれる建築技芸書。寺院、宮殿の建築法や周囲を彩るレリーフの造形を解説している。　この書物には著者らしき建築家の名前も書かれている。"}],"1739":[{"rank":"2","note":"頭飾りの地図","exp":"210","type":"財宝","name":"戦士の頭飾り","desc":"ニューギニアの部族間闘争の際に、戦士たちが身に着ける頭飾り。極楽鳥の体に特定の時期だけ見られる飾り羽を、ふんだんに用いて作る。この頭飾りと精霊の加護が宿った胸飾り、そして体中に施したペイントが、仲間たちの士気を高める。"}],"5036":[{"rank":"2","note":"到達する","exp":"243","type":"港・集落","name":"カラカス","desc":"南米東岸、マラカイボの東に位置する街。街の名前はこの地に住んでいたカリブ人・カラカス人に由来する。"}],"67":[{"rank":"5","note":"インドの大蛇","exp":"1118","type":"大型生物","name":"ニシキヘビ","desc":"大型のヘビで、特に大きなものは10mにもなる。毒はないが力が強く、獲物をしめつけて殺してしまう。豚が食べられたこともあるそうだ。小さな足のような突起があるが、もっと大きくなると足が生えるのだろうか。"}],"6653":[{"rank":"5","note":"追究クエスト","exp":"1100","type":"中型生物","name":"メキシコオオカミ","desc":"北米の森林部に生息するオオカミ。普通のオオカミより小型。自分たちより体格の大きな獲物を狩る際は、群れをなして行動する。"}],"2725":[{"rank":"3","note":"小さな果実<br/><br/>発見時経験値460　発見物カード経験値230","exp":"460","type":"植物","name":"スモモ","desc":"朝鮮、日本、中国と、東アジアの広範囲に分布する植物。初春に白い花を咲かせ、果実は酸味が強い。\n古くから人々に慕われてきた植物である。"}],"1651":[{"rank":"3","note":"神の投げし岩","exp":"484","type":"地理","name":"サモア諸島","desc":"フィジー諸島の東北東に位置する諸島。主要な島はサバイイ島とウポル島の二つである。両島とも火山島であり海岸線には美しいサンゴ礁が広がっている。"}],"6811":[{"rank":"5","note":"発見物カード経験値:480","exp":"","type":"財宝","name":"ドレスデン絵文書","desc":"マヤの絵文書の写本。現存する南北アメリカの本の中で、最も古いとされる。マヤの信仰や暦法をはじめ、数学や農業、祭事、予言や世界の終末などについて記されている。"}],"264":[{"rank":"1","note":"フランス北西部の海岸線","exp":"20","type":"地理","name":"サンマロ湾","desc":"コタンタン半島とブルターニュ半島に挟まれた湾。緯度が高いわりに温暖で、沿岸は保養地として古くから知られる。"}],"2344":[{"rank":"3","note":"万葉集に次ぐ和歌集","exp":"460","type":"財宝","name":"古今和歌集","desc":"読みは、「こきんわかしゅう」。帝の命で編まれた最初の和歌集。「古今」という名には昔の和歌と今の和歌を集めたという意味がある。"}],"6691":[{"rank":"4","note":"クエスト「西洋の小さな鴨」<br/>発見物カード:305","exp":"610","type":"鳥類","name":"コールダック","desc":"別名ナキアヒル。ネーデルランドでアヒルを品種改良したものといわれている。大きな鳴き声で野生の鴨を誘導するおとりとして使われていた。\n愛玩用ペットとしても人気がある。"}],"1107":[{"rank":"3","note":"体よりも長い尾","exp":"451","type":"小型生物","name":"インドオオリス","desc":"体長よりも長い巨大なふさふさした尾が特徴で、機敏な動きで枝の間を跳び回る。果実や木の実、昆虫などが主食。後肢で木につかまり、尾でバランスをとりながら、前かがみになって食事をする。"}],"1292":[{"rank":"3","note":"最後の王","exp":"539","type":"歴史遺物","name":"ナラーティハパテ王の懐剣","desc":"ナラーティハパテ王のものと思われる懐剣。ナラーティハパテ王はパガン朝最後の王である。過剰な寺院造営により国が衰えているところをフビライに攻め込まれ、パガンを放棄することとなった。"}],"819":[{"rank":"1","note":"大理石の男性像の地図","exp":"108","type":"財宝","name":"大理石の男性像","desc":"大理石の男性像。ギリシャ時代の作風を模倣したもので、肉体美をよく表している。"}],"6446":[{"rank":"2","note":"","exp":"280","type":"宗教建築","name":"サンタ・マリア・ノヴェッラ教会","desc":"フィレンツェにある教会。のちのフランス王妃がフィレンツェから嫁いだ際に持参した香水「王妃の水」は、この教会の修道士たちによって作られたとされる。ヨーロッパの香水文化はここから始まったといえるだろう。"}],"5351":[{"rank":"3","note":"","exp":"440","type":"海洋生物","name":"メンダコ","desc":"深海に棲むタコの一種で通常のタコと違って吸盤が一列しかない。\n水から出すと体が潰れてしまうほど柔らかい。\n身は非常に塩辛い上に臭いがきつく、食用には向かない。"}],"1250":[{"rank":"2","note":"不思議な貝殻","exp":"210","type":"歴史遺物","name":"貝の絵文字","desc":"貝に彫られた絵文字。なにを表しているのかはわからないが、非常に高度な技術で、美的感覚に長じていることがうかがえる。"}],"5612":[{"rank":"2","note":"経験値は補正入ってたので誤差あるかも。","exp":"381","type":"財宝","name":"クー・スティック","desc":"北米の先住民族の戦士が所持する棒。羽根などで装飾されている。戦いで「カウンティング・クー」（相手を殺さず、棒だけを当てて去る）と呼ばれる勇者の行為をするために使われるという。"}],"1683":[{"rank":"5","note":"復讐の宴","exp":"1222","type":"歴史遺物","name":"ひすいの仮面","desc":"パレンケ遺跡から見つかった石棺の中に納められていた。パレンケ最盛期の王・パカルのものではないかといわれているが、くわしくは不明。顔面部はひすいでできており、白目は貝、黒目は黒曜石でできている。"}],"6790":[{"rank":"4","note":"発見物カード:350","exp":"700","type":"鳥類","name":"シロチドリ","desc":"ヨーロッパ、アジア、アフリカなど広く生息する水鳥。渡り鳥であり、季節によって棲む場所を変える。背は灰色、首回りと腹は白い羽を持つ。砂浜や河川敷などに飛来し、水辺の昆虫などを食べる。"}],"5265":[{"rank":"2","note":"「明るい星の観測記録」<br/>発見物カード:130","exp":"260","type":"天文","name":"ハダル","desc":"ケンタウルス座にある1等星で、足にあたる位置にある。星の名はアラビア語で「大地」を意味する。"}],"2967":[{"rank":"5","note":"丘か、陵墓か","exp":"1120","type":"史跡","name":"サーペント・マウンド","desc":"北米東部にある、ヘビのような形をした丘。丘の周りは堀があり、陵墓のようでもあるが不明な部分も多い。\nヘビの形は星座に関係しているのかもしれない。"}],"5783":[{"rank":"5","note":"氷漬けの男","exp":"1400","type":"歴史遺物","name":"アイスマン","desc":"アルプス山脈で発見されたミイラ。雪の下で凍り漬けになっていたため、非常に良好な状態を保っている。発見時、周囲に彼の持ち物と思われる道具などがいくつかあった。"}],"715":[{"rank":"2","note":"世界七不思議の主","exp":"300","type":"歴史遺物","name":"クフ王の王杖","desc":"金やラピスラズリをふんだんに使った、豪華な王杖。クフ王は、エジプト最大である、ギザの第1ピラミッドを建造したファラオである。"}],"1467":[{"rank":"4","note":"クエスト「塔の並ぶ大地」<br/>発見物カード:320","exp":"648","type":"宗教建築","name":"パガン遺跡","desc":"パガン王朝時代に建設されたという寺院群。広大な敷地に無数の寺院や仏塔が建てられている。その数は400万ともいわれているが、元によって破壊され現在は3000弱しか残っていない。"}],"5997":[{"rank":"1","note":"サラマンダーを捕まえろ<br/>希少発見物らしいです。<br/>体験版では、「サラマンダーを捕まえろ」<br/>の紹介を受けれませんでした。","exp":"80","type":"小型生物","name":"マダラサラマンドラ","desc":"黒い体にオレンジの模様があるイモリ。炎がちらついている模様に見えないこともない。ヨーロッパでも似たイモリを見かけるが、まだらが黄色い。"}],"3725":[{"rank":"5","note":"海賊の象徴","exp":"1190","type":"財宝","name":"色あせた海賊旗","desc":"ある海賊船の旗のようだ。海賊旗は海賊たちにとって乗組員を識別するためのものであり誇りでもあるという。"}],"5639":[{"rank":"3","note":"ラスパルマスの西側にある島の西端。<br/>曇り限定らしい。","exp":"519","type":"気象・現象","name":"水上竜巻","desc":"洋上で発生する竜巻。強力な突風に加え、不規則な水の動きを生み出すために、まれに、船がまき込まれて沈没するといった災害も発生している。"}],"1996":[{"rank":"3","note":"釣り","exp":"528","type":"海洋生物","name":"メガネモチノウオ","desc":"頭部にあるコブが最大の特徴。ベラの仲間で体長は1mを超える。"}],"4978":[{"rank":"3","note":"","exp":"600","type":"鳥類","name":"エレオノラハヤブサ","desc":"エーゲ海の島々に生息しているハヤブサ。集団で狩りや子育てを行う。群れを成して、狩りの成功率を上げ、敵からも身を守りやすくしているようだ。"}],"1322":[{"rank":"3","note":"怪奇が潜む川","exp":"462","type":"地理","name":"メコン川","desc":"ヤーデイン近郊を流れる大河。その水源ははるか北の山岳奥地らしいが、途方もなく長い川であり調査は難航するだろう。全般的に水深が浅く、遡上には向かない河川のようだ。"}],"239":[{"rank":"1","note":"バアルの宝玉","exp":"100","type":"財宝","name":"バアルの宝玉","desc":"聖書のソロモン王が、悪魔や精霊72体を封じ込めたという宝玉の一つ。この宝石にはバアルが封じられているという。真偽の程は不明だ。\n宝玉はよく見ると傷があり、「遠浅の海」と彫られている。"}],"3683":[{"rank":"4","note":"クエスト「極北の生物調査地」<br/>発見物カード:325","exp":"650","type":"地理","name":"ウランゲリ島","desc":"チュクチ海に浮かぶ小島。\n極北の動物が多く生息し、夏の間は渡り鳥も訪れる。"}],"4797":[{"rank":"1","note":"書きかけの地図","exp":"140","type":"地理","name":"マウナ・ケア","desc":"ハワイ島の北部にある山。ハワイ諸島で最も高く、常夏の島にありながら、冬には冠雪する。非常に巨大な山体が特徴。"}],"5391":[{"rank":"5","note":"","exp":"1210","type":"宗教遺物","name":"プロメテウスの鎖","desc":"コーカサスの山中で見つかった頑丈な鎖。伝説では、天界から火を盗んで人間に与えたプロメテウスが、ヘパイストスの作った鎖で、コーカサスの山中に縛られ、生きたまま肝臓をハゲタカについばまれるという罰を受けたといわれている。"}],"5468":[{"rank":"1","note":"発見時経験値150　発見物カード経験値75","exp":"150","type":"鳥類","name":"イチモンジバト","desc":"パンタナル湿原でよく見られるハトの一種。\n羽をたたんでいると一文字の模様がはっきり見えるのが特徴。\nハトの名がついているが、実際はスズメほどの大きさだという。"}],"5666":[{"rank":"2","note":"「書きかけの地図」<br/>発見物カード:105","exp":"210","type":"地理","name":"アルシェイのゲルタ","desc":"サハラ中南部に位置する渓谷。低地に流れ出た地下水が湿地を形成しており、ワニの生息地となっている。また、古より人間も利用してきた場所であり、古代の壁画も残されている。"}],"1822":[{"rank":"2","note":"ヒッタイトの戦術兵器","exp":"360","type":"歴史遺物","name":"ヒッタイトの戦車","desc":"アナトリアの古代王国ヒッタイトで発明された戦車。二輪で六輻の車輪を備え、馬が牽く車体に乗った御者が弓を爪弾いて戦う。"}],"5651":[{"rank":"2","note":"ボルネオ島北西端付近","exp":"310","type":"海洋生物","name":"ニシキアナゴ","desc":"浅い海の底に生息する魚。太平洋やインド洋で見られる。体調は最大で40cm程度となる。黄色と白色の縞模様が特徴。"}],"6177":[{"rank":"4","note":"","exp":"630","type":"宗教建築","name":"リンディスファーン修道院跡","desc":"ブリテン諸島にキリスト教が伝来した頃からの歴史を持つ修道院の跡で、福音書の装飾写本が製作されたことで名高い。ヴァイキングの襲撃による修道士の退去と復興を経た後、数百年後のイングランド王の迫害によって完全に廃墟と化した。"}],"1823":[{"rank":"2","note":"トラキアの刀剣","exp":"350","type":"歴史遺物","name":"ロンパイア","desc":"古代トラキア人が使っていた、柄も刀身も長い刀剣。刃の方向に湾曲しており、引っ掛けるようにして切り裂く用途もあった。"}],"6569":[{"rank":"5","note":"追究クエスト<br/>発見物カード:750","exp":"1500","type":"歴史遺物","name":"アルトナ石碑","desc":"キリスト教が広がり始めた頃、スウェーデンで作られたとされる石碑。表向きはキリスト教への改宗を示す石碑だが、片側には古来信仰されていた北欧神話のトールとヨルムンガンドが戦う様子が刻まれている。"}],"6257":[{"rank":"2","note":"","exp":"310","type":"財宝","name":"聖ブレンダンの航海","desc":"正式名は「大修道院長聖ブレンダンの航海」という。クロンファートのブレンダンという修道士が七年の歳月をかけてアイルランドから西方にある「約束の地」へ渡航するまでを描いており、数百年間にわたってヨーロッパ諸国で広く読まれた。"}],"2651":[{"rank":"4","note":"臆病な動物","exp":"640","type":"中型生物","name":"キバノロ","desc":"朝鮮半島から中国北部に分布するシカ。雌雄共にツノがなく、上あごの犬歯が発達して、長く伸びている。\n警戒心が強いためか、姿を見せることはめったにない。"}],"2884":[{"rank":"5","note":"王妃さまとサル","exp":"1040","type":"中型生物","name":"キンシコウ","desc":"中国西部の寒い地域に生息するサル。橙色の長い体毛に覆われている。\n青白い顔や、潰れたような形の鼻が、大きな特徴である。"}],"6359":[{"rank":"5","note":"","exp":"1110","type":"財宝","name":"蒸留術の書","desc":"蒸留術に関する書物。ヨーロッパに伝来し、ドイツ語に翻訳されたことで、蒸留術が周知された。植物から精油を抽出する方法やその効能、保存法などが記されている。蒸留で生成された精油は、ペスト治療などにも用いられたとされる。"}],"574":[{"rank":"2","note":"紅海の透明度を守る海峡","exp":"220","type":"地理","name":"マンデブ海峡","desc":"紅海とアデン湾を区切る海峡。島があるためもっとも狭いところでは25km程度の幅しかない。海上交易上、非常に重要な海峡で、すぐそばにはアデンという街が栄えている。"}],"115":[{"rank":"1","note":"ギザのピラミッドの調査","exp":"145","type":"宗教建築","name":"ギザのピラミッド","desc":"三つ並んだ巨大なピラミッド。大きい順にクフ王、カフラー王、メンカウラー王のもの。巨大な石を正確に積み上げて造られている。現在の技術で同じものを造れるだろうか？"}],"3545":[{"rank":"","note":"","exp":"","type":"レリック","name":"カール・マルテル","desc":"カール・マルテルがトゥール・ポワティエ間の戦いに敗れていたら、ヨーロッパの歴史はどうなっていただろうか。"}],"6582":[{"rank":"1","note":"(1776, 3895)","exp":"172","type":"港・集落","name":"ヤンブー","desc":"紅海に面した港町。古代から地中海世界とエジプトなどを結ぶ。香辛料、香料の中継交易港として栄えた。街の北東は急峻な山々が広がっており、その景観は幻想的である。"}],"1448":[{"rank":"5","note":"袋を持った捕食者","exp":"936","type":"中型生物","name":"フクロオオカミ","desc":"オオカミに似た肉食の有袋類。カンガルーやウォンバットなど大型の哺乳類を捕食する。"}],"2341":[{"rank":"3","note":"聖人の杖","exp":"530","type":"宗教遺物","name":"空海の錫杖","desc":"読みは、「くうかいのしゃくじょう」。日本の仏僧である空海が所持していた杖。\n揺らすと、上部の環が互いに触れ合い、音を立てる。この音には、煩悩を消し去るなどのさまざまな効果があるといわれている。"}],"6058":[{"rank":"4","note":"","exp":"700","type":"鳥類","name":"オシドリ","desc":"東アジアから東南アジアにかけて生息している鳥で、オスの鮮やかな体色が特徴的。漢名「鴛鴦（えんおう）」のうち「鴛」がオス、「鴦」がメスを指す。中国や朝鮮半島、日本では仲睦まじい夫婦の象徴とされている。"}],"1164":[{"rank":"2","note":"植物の船","exp":"270","type":"植物","name":"オオオニバス","desc":"水に浮かぶ巨大な葉の直径が2mにもなる蓮。子供ほどの体重であれば乗ることができる。花は、日がたつと白から赤へ変化していく。"}],"6890":[{"rank":"5","note":"","exp":"","type":"鳥類","name":"アンナハチドリの雌","desc":"雌のアンナハチドリ。冠羽から喉にかけての羽色が雄と大きく異なる。また、雄の冠羽は光に反射して色が変化するが、雌の冠羽は変わらない。"}],"1017":[{"rank":"1","note":"名細工師の遺品","exp":"70","type":"財宝","name":"金とサファイヤのからくり時計","desc":"金とサファイヤで美しい細工を施したからくり時計。手のひらに乗るほどの大きさなのに定刻になると小さな人形が踊るからくりがしかけてある。"}],"1356":[{"rank":"5","note":"ドラゴンの子孫","exp":"1222","type":"大型生物","name":"コモドドラゴン","desc":"最大のもので3mを超える大型のトカゲ。重くがっしりとした体に、長くて太い尾を持つ。巨体のわりにすばやい動きでシカやイノシシを捕食する。二股に分かれた舌は、まるで火を吐いているように見える。"}],"6566":[{"rank":"5","note":"追究クエスト","exp":"1550","type":"大型生物","name":"スマトラサイ","desc":"インドネシアの熱帯雨林に生息するサイ。他のサイと比べると小柄で、全身に長い体毛が生えているのが特徴。角は2本あり、薬や工芸品目的で狩猟されることもあるという。"}],"5484":[{"rank":"3","note":"アマゾン川上流から南西の支流奥。釣りR10+1で発見。<br/>経験:480 カード:240","exp":"480","type":"海洋生物","name":"タライロン","desc":"アマゾン川や、その支流で生息する魚。古代魚の風貌に似ていることから淡水の古代シーラカンスと呼ばれている。"}],"5840":[{"rank":"5","note":"","exp":"1370","type":"美術品","name":"信貴山縁起絵巻","desc":"平安時代の巻物。異時同図法で時間の経過を表現している点が特徴的。四大絵巻物の一つと称される。"}],"2862":[{"rank":"4","note":"本を携えた男<br/><br/>発見時経験値660　発見物カード経験値330","exp":"660","type":"財宝","name":"長恨歌","desc":"唐代の玄宗皇帝と楊貴妃の逸話を歌った、長編の漢詩。時代が唐代ではなく漢代に変更されているなど、史実と異なる部分が多い。"}],"421":[{"rank":"1","note":"気味の悪い動物の地図","exp":"10","type":"小型生物","name":"巨大ヒキガエル","desc":"大型のカエル。体にイボのような突起が多くある。危険を感じると耳の後ろから白い毒液を出し、これが肌につくと痛がゆい。"}],"5340":[{"rank":"2","note":"火山の記録<br/><br/>発見時経験値380　発見物カード経験値190","exp":"380","type":"地理","name":"カメルーン山","desc":"アフリカ中部の沿岸にある火山。\n紀元前にカルタゴの航海者ハンノが\n噴火を記録した火山ではないかと考えられている。"}],"3320":[{"rank":"2","note":"装飾された写本の地図","exp":"340","type":"財宝","name":"リンディスファーンの福音書","desc":"マタイ、マルコ、ヨハネ、ルカによる福音書をまとめた手写本。ケルズの書同様に装飾写本であるが、ラテン語で書かれている。\n制作当時は宝石や貴金属で装丁されていたがヴァイキングによって失われたらしい。"}],"4868":[{"rank":"2","note":"書きかけの地図","exp":"330","type":"地理","name":"メソポタミア湿原","desc":"チグリス・ユーフラテス川の下流に広がる湿地帯。「肥沃な三日月地帯」の一部であり、古代から農業が盛んである。"}],"2371":[{"rank":"1","note":"斑模様のチョウの地図","exp":"150","type":"虫類","name":"ギフチョウ","desc":"日本にのみ生息する、黄と黒のまだら模様が鮮やかなチョウ。\n夏に成熟した幼虫が、落ち葉の下でさなぎとなり、そのまま冬を越すという特徴がある。"}],"2082":[{"rank":"5","note":"クエスト「虹色の神鳥」<br/>発見物カード:555","exp":"1110","type":"鳥類","name":"ケツァール","desc":"中南米山岳地帯の森林に生息する鳥。全長は約35cm。オスは飾り羽を持っており、それを含めると全長90cmにも達する。アステカの神の使いであり、鮮やかな濃緑色の羽が日に照らされた姿は、まさに虹色の神鳥である。"}],"2922":[{"rank":"4","note":"百済王の軌跡","exp":"800","type":"財宝","name":"百済王の太刀","desc":"百済の遺跡で発見された環頭太刀。\n柄には、龍の装飾がある。きっと百済王が使用していたのだろう。"}],"5268":[{"rank":"1","note":"ビュルサの丘　再調査報酬","exp":"","type":"歴史遺物","name":"アスタルテ像","desc":"豊穣を司る女神の像。古代ギリシャではアフロディテと同一の女神とされている。フェニキアでは古い世界を破壊し、新しい世界を創造する、死と再生の女神ともいわれる。"}],"3666":[{"rank":"3","note":"ダンジョン","exp":"510","type":"歴史遺物","name":"アンデスの織物","desc":"アンデス高原の人々がアルパカの毛や木綿を様々な手段で鮮やかに染めて作った織物。発色も素晴らしいが、織りの技術も極めて高く模様を再現することは非常に難しい。"}],"144":[{"rank":"1","note":"クレオパトラの息子","exp":"100","type":"歴史遺物","name":"カエサリオンの大理石像","desc":"ユリウス・カエサルとクレオパトラ7世の間に生まれた、カエサリオンの大理石像。一時はカエサルの後継者と認められたが、クレオパトラの死後、殺されたという。"}],"1465":[{"rank":"3","note":"南の大陸における暮らしぶり","exp":"473","type":"歴史遺物","name":"古代の釣り針","desc":"沿岸に居住していた先住民族が使っていたと思われる釣り針。木を研いで作られており、海水の中で使用したため腐食が激しいが、状態よく残っているものもある。彼らは木をうまく利用してきた民族といえよう。"}],"5291":[{"rank":"3","note":"","exp":"550","type":"史跡","name":"タッシリ・ナジェール","desc":"サハラの中央部にある台地状の山脈。侵食によってできた印象的な奇岩が並ぶ。洞窟内にはウシの群れやワニが描かれた岩がある。大昔の付近の様子を描いたと思われるが、現在の砂漠からは信じがたい風景である。"}],"5664":[{"rank":"4","note":"","exp":"700","type":"気象・現象","name":"オーロラ爆発","desc":"オーロラが放射状に広がりながら、数分間、色や形状を変化させ続ける現象。オーロラと同様に、その発生原因などは不明である。"}],"3907":[{"rank":"2","note":"書きかけの地図","exp":"230","type":"地理","name":"バフィン湾","desc":"グリーンランドの西に位置する湾。湾内には多数の氷山が浮いており、航行は困難を極める。"}],"890":[{"rank":"2","note":"謎の古代民族","exp":"310","type":"歴史遺物","name":"海の民の剣","desc":"ヒッタイト王国を滅ぼした、謎の古代民族「海の民」が使っていたと思われる鉄剣。ヒッタイトの製鉄技術を盗んだのだろうか？"}],"972":[{"rank":"2","note":"崩れゆく名画","exp":"260","type":"美術品","name":"最後の晩餐","desc":"レオナルド・ダ・ヴィンチ作。遠近法によって描かれ建物内部が奥に続いているように見える。周囲の弟子たちに比べてイエスがあっさりと描かれているのは、彼にありがちなことだが未完成なのだろう。"}],"3643":[{"rank":"3","note":"芸術的な実用品","exp":"520","type":"財宝","name":"サモワール","desc":"ロシアの湯沸かし器。円筒の外側に水を、中心部に火種を入れて湯を沸かす。ふたの上に茶器を置けば、保温の効果も得られる。寒い地域ならではの道具。"}],"3759":[{"rank":"4","note":"太陽のシミ","exp":"630","type":"天文","name":"太陽黒点","desc":"太陽の表面に現れる黒い点のような模様。太陽の光が弱まる日没時などには、まれに肉眼でも確認できることがある。東洋の各地には太陽に住む烏の神話が伝わっているが、これらは黒点を見て作られた可能性がある。"}],"6038":[{"rank":"2","note":"文化貢献度40","exp":"260","type":"化石","name":"トゲだらけの虫の石","desc":"北米北西部のバージェス頁岩から見つかった奇妙な石。トゲだらけで、虫のように見えるが、その正体は定かではない。"}],"2736":[{"rank":"1","note":"古文書の地図","exp":"140","type":"歴史遺物","name":"新羅の木簡","desc":"損傷の激しい木簡。新羅の遺物が多く発見される場所で、よく出土する。\nこの地域で過去に起きた出来事を記録したもののようだが、傷みがひどく解読できない。"}],"2535":[{"rank":"2","note":"小さなセミの地図","exp":"340","type":"虫類","name":"ホッポゼミ","desc":"台湾島にのみ生息する小さな体と赤い目が特徴的なセミ。朝や夕方によく鳴き、鳴き声は遠くまで響く。\n別名ホッポヒグラシ。"}],"370":[{"rank":"2","note":"果物かごだけの絵","exp":"380","type":"美術品","name":"果物かご","desc":"カラバッジオ作の、果物かごを描いた絵画。人物を描かない絵はこれまでの常識を打ち破るものだ。やや生気を失いかけた果物や葉が生々しく、これまでにない魅力がある。"}],"4961":[{"rank":"1","note":"天文学者の観測記録<br/>発見物カード:95","exp":"190","type":"天文","name":"おとめ座の渦巻星雲","desc":"おとめ座にある渦巻き星雲。中央部が大きく膨らみ、どことなくメキシコの帽子ソンブレロを思わせる形をしている。"}],"770":[{"rank":"1","note":"先史時代の史跡の地図","exp":"26","type":"歴史遺物","name":"骨角器","desc":"「こっかくき」。動物の骨や角を削って作った先史時代の道具。骨は刃物にできないが、矢じりや槍、針にはよい。また、護符や装飾品などにもよく用いられた。"}],"2596":[{"rank":"2","note":"サルベージ。読み方は｢めいぴん」","exp":"280","type":"財宝","name":"梅瓶","desc":"焼物の一種で、口が小さく背丈が高く、足元に対して肩が広く張っている器の総称。\n中国の古い時代から見られ、景徳鎮製のものは特に人気が高い。"}],"2822":[{"rank":"2","note":"地中に眠る竹簡","exp":"370","type":"歴史遺物","name":"焼けた竹簡","desc":"雲台山郊外で見つかった焼け跡のある竹簡。炭化が進んでおり元の内容を解読することは不能。状態から焚書の名残りであると思われる。焚書に関しては、秦の始皇帝が、宰相・李斯の提案で行ったものが有名。"}],"19":[{"rank":"3","note":"アフリカゾウの探索","exp":"462","type":"大型生物","name":"アフリカゾウ","desc":"アフリカのサバンナ地帯で広く見られるゾウである。アフリカでは最大の生物だろう。古代都市のカルタゴでは象兵がいたといわれるが、このゾウが使役されていたのだろうか。"}],"6810":[{"rank":"5","note":"発見物カード:440","exp":"880","type":"虫類","name":"クロゴケグモ","desc":"北米に生息するクモの一種。全身が黒く、丸く膨らんだ腹にはメスのみ砂時計の形をした赤い模様がある。メスが交尾後にオスを食べることから、黒い未亡人を意味する「ブラックウィドウ」と呼ばれる。強い毒を持つが攻撃性は低い。"}],"642":[{"rank":"1","note":"書きかけの地図","exp":"175","type":"地理","name":"アンダマン諸島","desc":"ベンガル湾東部に浮かぶ島々。おおよそ線上に並んでいる。島には先住民がいる。彼らは身長が140cmくらいで狩猟・採集生活を送っているようだが、他民族との接触を避けるため、くわしいことは不明。"}],"5477":[{"rank":"2","note":"クエスト「サルの生態調査」<br/>発見物カード:175","exp":"350","type":"中型生物","name":"リスザル","desc":"体長30cm、尾長40cm、体重1kgほどの小型のサル。数十頭の群れを作って生活している。温和で寂しがりな性格で、一頭だけにすると死んでしまうといわれる。"}],"87":[{"rank":"1","note":"エジプトの古文書の地図","exp":"34","type":"歴史遺物","name":"死者の書","desc":"古代エジプトで埋葬の際に一緒に棺に入れられた、死者のための呪文書。これを死者に持たせれば、死後のオシリス神の審判で無罪になると考えられた。"}],"3324":[{"rank":"2","note":"ローマ帝国の防塁の地図","exp":"320","type":"歴史遺物","name":"アントニヌスの長城","desc":"ローマ帝国の時代に、皇帝アントニヌス・ピウスの命により築かれた防塁。長さは約60kmであり、二年という短い期間で建設された。"}],"6956":[{"rank":"5","note":"","exp":"","type":"史跡","name":"ビームベートカーの岩陰遺跡群","desc":"インド中部の森の中に位置する岩陰遺跡群。数百に及ぶ岩窟と壁画が残されているが、正しい数はわかっていない。古いものは動物や狩人、時代が浅いものは幾何学模様など、さまざまなものが鮮やかに描かれている。"}],"6830":[{"rank":"5","note":"追究クエスト<br/>発見物カード:410","exp":"820","type":"鳥類","name":"サンジャク","desc":"東アジアから南アジアにかけての山地に生息する鳥。森林に棲み、樹上に巣を作る。\nヤマムスメと同じく黒い頭と赤いくちばしを持つが、腹が白い、頭の後ろの毛が白い斑点のように見えるなど、特徴は異なる。"}],"1258":[{"rank":"4","note":"大河を割る島","exp":"624","type":"地理","name":"三角州","desc":"上流から押し流された砂や泥土が河口付近に堆積してできる、河口の浅瀬部分。長い年月をかけて泥土が溜まり続ければ、いつしか浅瀬は島になるのかもしれない。"}],"1953":[{"rank":"1","note":"奇妙な形の植物の地図","exp":"170","type":"植物","name":"ビカクシダ","desc":"森林で、木の幹から生えている奇妙な植物。シカの角のように枝分かれした葉を持つ。病気になった葉かと思われたが、根で張り付いているので違う植物だと判明した。"}],"6115":[{"rank":"4","note":"","exp":"630","type":"伝承","name":"ケサラン・パサラン","desc":"動物なのか植物なのか不明、生態も不明、名前の語源も判然としないという、謎の生物。その毛玉のような外見と、所有者に幸福が訪れるという噂だけが、伝承として伝えられている。"}],"317":[{"rank":"2","note":"ラダメスとアイーダの墓石","exp":"270","type":"歴史遺物","name":"ラダメスとアイーダの墓石","desc":"古代エジプトの将軍ラダメスと女官アイーダの死をいたんで建てられたと思われる石碑。二人は共に神殿の礎として生き埋めとなったが、その最後の言葉がこの石碑に刻まれていた。"}],"6117":[{"rank":"4","note":"クエスト「植民都市のワイン商」<br/>発見物カード:370","exp":"740","type":"歴史遺物","name":"ノイマーゲンのワイン船","desc":"ノイマーゲンのワイン商の墓から出土した副葬品。ノイマーゲンはローマ帝国期よりワイン生産の盛んなモーゼル川流域の街。獣頭のガレー船にワイン樽が満載され、二人の収税人と多くの漕ぎ手が乗っている。当初は二隻構成だったようだ。"}],"1":[{"rank":"2","note":"アイルランドの遺跡","exp":"250","type":"史跡","name":"ボイン渓谷遺跡群","desc":"アイルランドにある、先史時代の遺跡群。緻密な石組みの墳墓が並ぶ。奥の墓室には冬至の前後数日のみ、朝日が差し込む。"}],"3900":[{"rank":"2","note":"「土星の観測記録」","exp":"260","type":"天文","name":"土星の環","desc":"土星を囲む環。初期の天体望遠鏡でも環の存在は見つけられたが、観測が難しかった。望遠鏡の性能が向上すると、いくつかの環の観測に成功したが、何で構成されているのかは不明である。"}],"983":[{"rank":"1","note":"暴帝の彫像","exp":"50","type":"歴史遺物","name":"カリグラ帝の大理石像","desc":"古代ローマのカリグラ帝の大理石像。カリグラという名は、本名ではない。史上1、2位を争うような暴君であったという。"}],"5889":[{"rank":"5","note":"","exp":"1340","type":"植物","name":"ローレルジンチョウゲ","desc":"ヨーロッパ全土に分布する低木の有毒植物。花や実、草部分に猛毒があり、樹液に触れると発疹などの原因になる。口にすると内臓や神経を損傷するなど、毒性は強い。"}],"3413":[{"rank":"4","note":"船の墓","exp":"700","type":"史跡","name":"サットン・フー","desc":"ブリテン島の東部にある、古代の墓所。棺の代わりに、船の中に遺体を納めてある。船には多くの副葬品も備えられており、古代の生活を今に伝えている。"}],"6457":[{"rank":"5","note":"追究クエスト<br/>発見物カード:520","exp":"1040","type":"財宝","name":"ハムサ","desc":"手をかたどり、その中央に目が描かれた、邪視から身を守るための護符。「ハムサ」とはアラビア語で数字の5を意味する。トルコのお守り「ナザール・ボンジュウ」はこの亜種だという説もある。"}],"1906":[{"rank":"3","note":"万人のための聖書","exp":"600","type":"宗教遺物","name":"七十人訳聖書","desc":"ヘブライ語からギリシャ語に訳された聖書の総称。アレクサンドロス大王の遠征によってヘブライ語を習得していないユダヤ人が増加したため、聖書のギリシャ語訳が始まったと言われている。"}],"3875":[{"rank":"4","note":"クエスト「伝説の名医」<br/>発見物カード:375","exp":"770","type":"天文","name":"へびつかい座","desc":"ギリシャ神話に登場する名医アスクレピオスが空に上った姿とされる。アスクレピオスは死者をも蘇らせることができ、これを怒った冥界の王ハデスが大神ゼウスに雷で打ち殺させたという。"}],"831":[{"rank":"1","note":"男性像の地図","exp":"120","type":"美術品","name":"モーゼ","desc":"ミケランジェロ作の大理石像。ユリウス2世の墓のために作られた像の一つである。十戒の石板を抱え、緊張した表情で遠方を見つめている。"}],"605":[{"rank":"1","note":"細密な人物画","exp":"190","type":"美術品","name":"薬剤師の肖像","desc":"フランソワ・クルーエ作の肖像画。モデルは彼の友人でピエール・キュートという。イタリアとフランドルの影響を受けた、自然で非常に写実的な絵画だ。"}],"5850":[{"rank":"5","note":"","exp":"1340","type":"美術品","name":"アフリカの仮面","desc":"アフリカの民族が祭儀に用いる仮面。民族ごとに造形や意味合いが様々に異なる。"}],"3582":[{"rank":"2","note":"ハワイの伝統楽器","exp":"233","type":"財宝","name":"ウリウリ","desc":"ハワイの伝統的楽器。木の実やひょうたんの中身をくり貫き、種などを入れて振って音を出す。鮮やかに染めた羽根が飾り付けられている。各種の儀式にも使用される。"}],"5847":[{"rank":"4","note":"","exp":"620","type":"海洋生物","name":"フシギウオ","desc":"赤道付近にのみ生息するとみられる深海魚の一種。特徴の少ない魚だが、幼体の頃のみ、体よりも長い腹ビレを持つ。ヒレの先には房状の器官がたくさんあるが、なんのためのものなのかはいまだ解明されていない。"}],"5295":[{"rank":"3","note":"","exp":"600","type":"鳥類","name":"ウシツツキ","desc":"サハラ以南のアフリカに棲む小鳥。哺乳類の皮膚に巣食う寄生虫などをエサにしているためか、大型動物の背中などによく止まっており、尻尾に追い払われず共存している。"}],"6791":[{"rank":"5","note":"視認","exp":"","type":"天文","name":"アンサー","desc":"こぎつね座で最も明るい星。キツネの頭にあたるところに\n位置し、名前はラテン語でガチョウを意味する。これわこ\nぎつね座がかつてがちょうをくわえたきつね座と呼ばれた\nことに由来する。"}],"449":[{"rank":"1","note":"教会の宗教画の地図","exp":"90","type":"美術品","name":"失楽園","desc":"マザッチョ作の壁画。礼拝堂の壁に、複数の画家が描いたものの一つである。マザッチョは線遠近法を生かし、それまでとは大きく異なる、生気にあふれた絵画を描いた。"}],"1180":[{"rank":"5","note":"遠い約束<br/><br/>発見時経験値949　発見物カード経験値474","exp":"949","type":"財宝","name":"マインエンゲル","desc":"レスカトールが使っていたギター。彼は人気闘牛士を辞めて、ミカエラのギタリスタになった。弦が多く複雑な音が出せる分、かなりの技巧がなければ扱うことは難しいだろう。"}],"1745":[{"rank":"5","note":"それぞれの誇り","exp":"910","type":"財宝","name":"アベラム民族の胸飾り","desc":"部族間闘争の際に身に着ける胸飾り。羽毛や木の葉、貝、獣の牙などで、雄雄しく飾り立て、自らの誇りの高さを周知させるという。"}],"2569":[{"rank":"5","note":"遠き地への調査依頼<br/><br/>文化貢献度50","exp":"930","type":"鳥類","name":"ゴシキドリ","desc":"中国南部から東南アジアにかけて生息する、体が五色で彩られている鳥。樹幹にくちばしで丸く出入り口を掘り巣を作る。夜はその巣で眠る。"}],"6332":[{"rank":"3","note":"","exp":"500","type":"財宝","name":"シグロス銀貨","desc":"アケメネス朝ペルシャにて発行された銀貨。表には弓と槍を持って狩りを行う王の姿が刻印され、王の権威を表している。"}],"1848":[{"rank":"1","note":"古の神像の地図","exp":"150","type":"宗教遺物","name":"ランソン像","desc":"ジャガーの頭とヘビの髪の毛、人間の体を持つ神像。インカにおいてもジャガーは神格化されているが、人間と融合した姿で描かれることはない。リマ周辺には、インカ以前から高度な文明を持った民族がいたのかもしれない。"}],"6143":[{"rank":"4","note":"クエスト「異邦へのまなざし」<br/>発見物カード:325","exp":"650","type":"財宝","name":"カタロニア地図","desc":"アラゴン王太子からフランス王シャルル6世へ贈られた地図。ユダヤ人製図家のクレスケス父子によって作成された。マルコ・ポーロやフランシスコ会修道士フリア・オドリックなどの情報を元に作成されたといわれる。"}],"2948":[{"rank":"3","note":"波間の青き宝石","exp":"600","type":"海洋生物","name":"アオミノウミウシ","desc":"5～8cm程度の小型のウミウシ。アフリカ東岸や南岸などにかけて生息する。\n青と銀の体色が鮮やかで、海の宝石ともいえる姿をしている。"}],"5527":[{"rank":"2","note":"アラフラ海　グルートアイランド島（カカドゥ東の巨大な湾の西側にある島）付近　晴天・午前","exp":"195","type":"気象・現象","name":"モーニンググローリー","desc":"世界各地で朝などに観測される巨大な帯状の雲。大きなものでは幅1000kmを越える。稀に複数発生するが、その発生原因などは不明である。"}],"1695":[{"rank":"2","note":"釣り","exp":"260","type":"海洋生物","name":"ピライーバ","desc":"アマゾン川に生息するナマズの中でも、特に大きい。体長の2倍以上もある長いヒゲをもつ。"}],"6644":[{"rank":"2","note":"","exp":"260","type":"歴史遺物","name":"ハサーの翼","desc":"ハサーは、有翼重騎兵のこと。ポーランドの華美な装いをした勇猛な騎兵で、猛禽の羽でできた大きな羽飾りを背負った。この羽飾りに風を通して音を立て敵の恐怖心を煽るのだという。"}],"1958":[{"rank":"2","note":"メソアメリカの祭器の地図","exp":"390","type":"歴史遺物","name":"祭事用の仮面","desc":"高貴な人の副葬品として、もしくは祭礼用の道具として用いられたと思われる仮面。メソアメリカではこういった仮面が多く見られ、材質は石・粘土・貝殻や宝石など、さまざまである。"}],"3808":[{"rank":"5","note":"音の正体","exp":"940","type":"小型生物","name":"コキーコヤスガエル","desc":"サンフアンが位置する島を原産地とする小型のカエル。高くよく通る鳴き声が特徴的。"}],"6462":[{"rank":"5","note":"追究クエスト「ヒョウモンダコの追加調査」発見物カード：600","exp":"1200","type":"海洋生物","name":"威嚇模様のヒョウモンダコ","desc":"暖かい海に生息する小型のタコ。興奮すると全身に、とても美しい青い輪状の模様が浮き出る。毒腺を持った口でかまれると死亡する危険があるほか、食べたり触ったりするだけでも毒を受ける可能性があるという。"}],"1626":[{"rank":"2","note":"桃色の鳥<br/><br/>発見時経験値280　発見物カード経験値140","exp":"280","type":"鳥類","name":"モモイロインコ","desc":"オーストラリア全域に群れで生息する鳥。体は桃色、翼は灰色で尾は黒い。果物、昆虫などを採食する。"}],"5637":[{"rank":"4","note":"リグリア海で発見。発見時、視認スキル、天文学スキルともに10。","exp":"800","type":"天文","name":"イアペトゥス","desc":"タイタン、レアに次いで大きな土星の衛星。\n表面が明るい部分と暗い部分にはっきり分かれており、状況によっては観測しづらい。"}],"2761":[{"rank":"4","note":"毒蛇から生まれた民族","exp":"720","type":"財宝","name":"パイワン民族の衣装","desc":"台湾島の先住民であるパイワン民族の貴族が身につける衣装。トンボ玉や、細かい刺繍が入ったきらびやかな長衣である。ヒャッポダという毒蛇と人間が結婚し、その間に生まれたのがパイワン民族だという伝説がある。"}],"6013":[{"rank":"2","note":"","exp":"345","type":"美術品","name":"愛に囚われし心の書","desc":"15世紀フランスの王族ルネ・ト・アンジューガ書いた騎士道物語の装画写本。「愛」いとり憑かれた「心」か囚われの身となった意中の女性を救出するべく旅に出るという内容。美麗な装画と詩で貴夫人たちに人気があるという。"}],"2501":[{"rank":"1","note":"民族調査の手助け","exp":"180","type":"地理","name":"雪山山脈","desc":"台湾島を南北に走る山脈。多くの古道が発見されている。\n中には、先住民のタイヤル民族が使用している通路もあるようだ。"}],"5274":[{"rank":"","note":"","exp":"","type":"レリック","name":"ポセイドンの怒り","desc":""}],"3880":[{"rank":"2","note":"積み重ねられたレンガの家","exp":"360","type":"史跡","name":"タオス・プエブロ","desc":"北米の先住民であるプエブロ民族が築いた集落。建物は赤褐色のレンガで造られ、複数の階を持つ。"}],"5100":[{"rank":"2","note":"到達する","exp":"243","type":"港・集落","name":"トルヒーヨ","desc":"カリブ海ホンジュラス湾に面した街で、クリストバル・コロンが4度目の航海で発見。「ホンジュラス」はスペイン語で「深み」を意味し、コロン提督が上陸の際、碇を下ろしたが海底まで届かなかったことに由来する。"}],"757":[{"rank":"1","note":"青銅の女性像の地図","exp":"57","type":"財宝","name":"ブロンズの女性像","desc":"青銅の女性像。それほど古いものではないようだ。ギリシャ風の美しい像である。"}],"1754":[{"rank":"3","note":"釣り","exp":"528","type":"海洋生物","name":"ベルーガ","desc":"黒海に見られる大型のチョウザメ。体長6m、重さ数トンのものもいるようだ。"}],"490":[{"rank":"1","note":"古代エジプトの建築技術","exp":"180","type":"宗教建築","name":"大列柱","desc":"カルナック神殿の大列柱室に立ち並ぶ、134本の石柱。高さ23ｍの物と15ｍの物がある。作らせたのは古代エジプトのファラオ・ラムセス2世である。"}],"1586":[{"rank":"3","note":"巨岩が屹立する聖地","exp":"484","type":"地理","name":"グレートサンディ砂漠","desc":"オーストラリア北西部に広がる砂漠。オーストラリアの内陸西部は多くが乾燥し、そのほとんどが砂漠である。年間の降水量は少なく塩湖が存在する。"}],"368":[{"rank":"5","note":"クエスト「乙女の部屋の守り手」<br/>発見物カード:550","exp":"1157","type":"宗教遺物","name":"パルテノンのアテナ像","desc":"かつてパルテノン神殿に収められていた、アテナ像の一部。高さ10m以上の木像で、肌の部分はすべて象牙でおおわれ、衣服や装飾は金細工で埋め尽くされていたという。オスマンに支配された際に分解されて売り払われたと思われる。"}],"5040":[{"rank":"1","note":"到達する","exp":"179","type":"港・集落","name":"カルカッタ","desc":"ベンガル湾に面する河口の街。東南アジアへ向かう際の重要な拠点で、中国からの商品も扱われる。高級な繊維や、宝石などが流通する。"}],"5834":[{"rank":"5","note":"","exp":"1340","type":"財宝","name":"ドンブラ","desc":"カザフ地方でよく演奏される木製の弦楽器。二本の弦を指で弾いて音を鳴らす。単独で弾いたり、叙事詩を歌う伴奏として用いられたりする。"}],"2302":[{"rank":"5","note":"異なる壁画の意味","exp":"1060","type":"歴史遺物","name":"赤く染まった骨","desc":"膨大な数の副葬品とともに発見された人骨で赤く染められている。副葬品が豪華なことや埋葬後も儀式が行われていた形跡があることから、コパン王朝の創始者またはその関係者のものである可能性も考えられる。"}],"3741":[{"rank":"5","note":"クエスト「氷の大地」<br/>発見物カード:645","exp":"1290","type":"地理","name":"グリーンランド氷床","desc":"グリーンランドの大部分を覆う、巨大な氷の塊。雪が積もって固まり、その上にまた雪が積もるのを繰り返した結果、厚い層をなしたものである。"}],"5791":[{"rank":"5","note":"蛇の創生神話","exp":"1370","type":"宗教遺物","name":"ジャブダルの像","desc":"蛇の神の像。シベリア地方に暮らすエヴェンキ民族の神話に登場する創造神のひとつ。マンモスの神が岩を積み上げて大陸を作り、この神が這いずり回って平らにしたという。"}],"5490":[{"rank":"3","note":"釣り発見物。南大西洋(16244,6205)","exp":"480","type":"海洋生物","name":"ヨシキリザメ","desc":"熱帯から温帯の海に広く分布するサメ。最大で4mほどになり人や船を襲うこともある。"}],"1587":[{"rank":"5","note":"砂漠の向こうの聖地","exp":"1027","type":"史跡","name":"ウルル","desc":"オーストラリアの先住民アボリジニにウルルと呼ばれている、一枚岩でできた巨大な岩。アボリジニにとっては聖地である。ウルルには精霊が宿っていると考えられ、儀式の際は多くのアボリジニたちが集まる。"}],"1965":[{"rank":"5","note":"魔性のダイヤモンド","exp":"1190","type":"財宝","name":"コイヌール","desc":"ペルシャ語で、「光の山」を意味する名がつけられた大きなダイヤモンド。原石は800カラットを超えたといわれている。代々、インドの王が所持していたものだが、ムガール帝国、サファヴィー朝と変遷し、消息を絶っていた。"}],"1290":[{"rank":"4","note":"アンコール朝の終焉<br/><br/>発見時経験値612　発見物カード経験値306","exp":"612","type":"宗教遺物","name":"ロケシュヴァラ像","desc":"アンコール朝後期に作られた青銅製の仏像。ジャヤヴァルマン7世の治世後、大乗仏教は民衆の支持を失ったため、この銅像は、化仏（けぶつ）と持物（じぶつ）を削り取られてシヴァに改変されている。"}],"1625":[{"rank":"2","note":"白黒はっきり<br/><br/>文化貢献度30","exp":"320","type":"鳥類","name":"キバタン","desc":"真っ白な羽で覆われた体に、黄色い冠羽を持つ鳥。興奮すると冠羽を立て、驚くほど大きな鳴き声を出す。大きな群れでは数百羽にもなる。"}],"5448":[{"rank":"3","note":"","exp":"","type":"財宝","name":"アトランティスの真実","desc":"ジョン・トラデスカントが中心となってまとめた、アトランティス調査に関する書物。解読不能の古代文字で書かれた石版を解読し、得た情報などが記載されており、学術価値は高い。"}],"2486":[{"rank":"2","note":"優れた官人の軌跡","exp":"310","type":"歴史遺物","name":"金銅製の骨蔵器","desc":"飛鳥時代以降に作られた骨蔵器の一つ。金銅製の器の中に、遺骨が納められている。\n蓋や本体に銘文が刻まれており、故人を偲ぶことができる。"}],"5165":[{"rank":"1","note":"到達する","exp":"19","type":"港・集落","name":"モンペリエ","desc":"マルセイユ近郊の小都市。古くから大学があり、特に医学の研究が盛んである。ノストラダムスもモンペリエ大学で医学を修めた。"}],"329":[{"rank":"4","note":"ローランの角笛<br/><br/>発見時経験値780　発見物カード経験値390","exp":"780","type":"歴史遺物","name":"ローランの角笛","desc":"ローランが決死の覚悟を伝えるために吹いたと伝えられる、象牙の角笛。細密な彫刻が施されており、工芸品としても価値が高い。"}],"3290":[{"rank":"4","note":"いわくつきの湖","exp":"620","type":"地理","name":"ネス湖","desc":"ブリテン島北部にある湖。湖の幅が約2kmであり、非常に細長い形状をしている。\n青黒く輝く水の色が特徴的。\n噂では、謎の生物が生息しているらしいが、真偽の程は不明。"}],"6342":[{"rank":"2","note":"","exp":"360","type":"歴史遺物","name":"モヘンジョ・ダロの像","desc":"南アジアで発見された石像。上流階級の人物をかたどっているとされる。像の片肌を出してまとった衣服には凝った模様があり、西方の文化の影響がうかがえるようだ。"}],"1281":[{"rank":"2","note":"大航海時代の先駆け","exp":"330","type":"歴史遺物","name":"鄭和艦隊の羅針盤","desc":"鄭和は明国に仕える軍人である。永楽帝の命により七度アフリカ方面まで長期航海した。当時は羅針盤の技術も発展段階であり、中国のものは磁石を水に浮かべて使った。"}],"6707":[{"rank":"4","note":"発見物カード:400","exp":"800","type":"天文","name":"アクベンス","desc":"かに座のアルファ星。\nカニの左の爪にあたる場所に位置する。名はアラビア語で「爪」を意味する。"}],"6511":[{"rank":"5","note":"レガシー競技の聖地オリンピア　右下","exp":"2805","type":"美術品","name":"オリンピアのニケ像","desc":"オリンピアのゼウス神殿にあったと思われる勝利の女神ニケの大理石像。顔と翼は失われているが、広げた両腕や翻る衣の美しい表現が特徴的。高い石柱の上に飾られていたと考えられている。"}],"4956":[{"rank":"2","note":"アフロディテの切ない花<br/><br/>発見時経験値260　発見物カード経験値130","exp":"260","type":"植物","name":"アネモネ","desc":"地中海沿岸に咲く花。花の色は鮮やかで多様である。ギリシャ神話では、女神アフロディテに愛された美少年アドニスが流した血からアネモネが生まれたといわれている。"}],"6957":[{"rank":"5","note":"発見物カード:615","exp":"1230","type":"中型生物","name":"アルビノのアライグマ","desc":"全身が真っ白なアライグマ。通常は灰褐色の体毛を持つが、遺伝子変異により、毛色は白く、赤みを帯びた目や鼻を持った個体がごく稀に生まれる。綿毛のような毛並みは非常に神秘的である。"}],"5574":[{"rank":"2","note":"「天文学者の観測記録」<br/>発見物カード:165","exp":"330","type":"天文","name":"ほ座の花のような星雲","desc":"ほ座の付近に存在する星雲。淡く暗めの星雲で、大きく広がっている。"}],"5259":[{"rank":"2","note":"バガン地方　再調査報酬","exp":"","type":"宗教遺物","name":"上座部仏教の仏典","desc":"釈迦の教えを純粋な形で保存した経典。仏教の一派で、南伝ともよばれる上座部仏教のもの。パガン王朝最初の王であるアノーヤター王が国内に広めるために使用したものと思われる。"}],"2353":[{"rank":"1","note":"能書家の書状の地図","exp":"190","type":"財宝","name":"風信帖","desc":"読みは「ふうしんじょう」。空海が最澄に宛てて送った書状。\n日本に残る唐風の名筆である。空海は能書家としても名高く、この書状は彼の最高傑作と評されている。"}],"3773":[{"rank":"3","note":"彗星の記録","exp":"490","type":"美術品","name":"バイユーのタペストリー","desc":"フランス北部の街バイユーに伝わるタペストリー。70mに及ぶ布にノルマンディー公ウィリアムによるイングランド征服の様子が刺繍されている。彗星と思われる星を見て不安がるイングランドの人々も描かれている。"}],"1667":[{"rank":"5","note":"太陽が沈む向こうに","exp":"1131","type":"宗教建築","name":"アフ・アキビのモアイ","desc":"ホツ・マツア王が、ラパ・ヌイに移動する前に先遣隊として遣わした七人の使者の像。他の像はすべて内陸の方向を向いているが、このモアイだけは海を見ている。伝説では、この像の見つめる先に彼らの故郷があるというが…。"}],"1720":[{"rank":"2","note":"釣り","exp":"250","type":"海洋生物","name":"キングクリップ","desc":"最大で2mにもなる巨大魚。南半球の深い海に生息する。イタチウオの一種。"}],"2791":[{"rank":"2","note":"鮮紅の虫探し","exp":"310","type":"虫類","name":"ヨコヅナサシガメ","desc":"中国から東南アジアにかけて分布する虫。大木の樹幹に集団で生息する。\n他の昆虫に細長い口を突き刺して体液を吸いとる。人間も刺される場合があり、注意が必要。"}],"2935":[{"rank":"5","note":"父の背中","exp":"1030","type":"財宝","name":"雲南斬馬刀","desc":"鄭成功が組織した部隊に導入されていた、刀身の長い片刃の剣。重いため、扱いが難しいが、騎兵を馬ごと切れるほどの高い破壊力を誇る。"}],"883":[{"rank":"2","note":"道具を使う鳥","exp":"350","type":"鳥類","name":"エジプトハゲワシ","desc":"大きな幅広い翼で上昇気流に乗って、何時間も飛び続ける。食事方法が変わっていて、ダチョウなどの殻の厚い卵を、石を使って割って食べる。"}],"1564":[{"rank":"1","note":"メソアメリカの土器の地図","exp":"180","type":"歴史遺物","name":"化粧された土器","desc":"色とりどりの顔料で彩色された土器。非常に高度な技術を有していたと思われる。"}],"5525":[{"rank":"4","note":"発見物カード:365","exp":"730","type":"天文","name":"レチクル座","desc":"ラカーユが制定した南天の星座のひとつ。レチクルとは、望遠鏡などを覗くと見えるレンズ上の十字の線のことである。"}],"1351":[{"rank":"5","note":"志を継ぐ者たち","exp":"1144","type":"宗教遺物","name":"高僧の衣","desc":"ある徳の高い仏教僧の衣をはぎれにして縫いつけた法衣。仏教僧は財産を持つことを禁止されており、法衣すらそれにあたる。法衣は在家からの喜捨や先輩僧からの譲渡でまかなう。"}],"5296":[{"rank":"5","note":"","exp":"810","type":"小型生物","name":"アルマジロトカゲ","desc":"アフリカ南部の岩場に褄む全長20cmほどのトカゲ。背中側の鱗は硬く、岩の隙間などに逃げ込む。逃げ場所がないと尾をくわえて体を丸め、背中の鱗を生かした防御体勢をとる。"}],"2072":[{"rank":"2","note":"［勅命］[[未知の魅力","exp":"320","type":"財宝","name":"グンデル","desc":"ジャワ島に古くからある金属楽器。バチで金属の鍵盤を叩き、手で共鳴を適度に止めて、奏でる。ワヤン・クリの伴奏として演奏されることが多いが、祭礼や儀式でも演奏されるようだ。"}],"6215":[{"rank":"2","note":"古代インドの遺物の地図","exp":"260","type":"歴史遺物","name":"カーリバンガンの印章","desc":"モヘンジョ・ダロ北東の地域で見つかる筒形の印章。インダス遺跡で見つかる印章に酷似している。特に牛の姿が刻まれており、この地域においても牛が重要な存在であったことがうかがえる。"}],"2379":[{"rank":"2","note":"雪溶かす花","exp":"270","type":"植物","name":"フクジュソウ","desc":"山林に生育する植物。初春に黄金色の花を咲かせる。\n蜜を作らず、その代わりに陽光を集めて暖かい場所を作ることで、虫を寄せて受粉する。"}],"1828":[{"rank":"2","note":"凶兆の伝達者","exp":"220","type":"歴史遺物","name":"チャスキの肩掛け袋","desc":"チャスキとは、情報を遠方へ配送する役目を負った者である。情報はインカ独特の「キープ」と呼ばれる縄と、口頭で運ばれた。チャスキは一日に200kmも走ったといわれる。恐ろしい健脚だ。"}],"5046":[{"rank":"2","note":"到達する","exp":"365","type":"港・集落","name":"クガリ","desc":"オーストラリアの東岸に位置する街。先住民の言葉で天国を意味する。南北100kmにも及ぶ砂浜や、森林地帯の内陸部に世界で最も透明度の高い湖を有するなど、天国の名を冠するに相応しい場所である。"}],"1458":[{"rank":"1","note":"小さな鳥の地図","exp":"155","type":"鳥類","name":"コキンチョウ","desc":"オーストラリアに生息する鳥。頭の色は個体によって様々で、巣にはシロアリの塚を利用する。"}],"6906":[{"rank":"5","note":"","exp":"","type":"化石","name":"巨大な角を持つシカの化石","desc":"巨大な角を持つ大きなシカの化石。角の長さは約3m、重さは約40kgにもなる。体高も人の背丈をゆうに超えていたようだ。何千年以上もの遠い昔から、この地に眠っていたのだろうか。"}],"415":[{"rank":"1","note":"奇妙な石の地図<br/>アフリカ南岸に上陸","exp":"48","type":"化石","name":"草模様の石","desc":"シダによく似た植物の模様がある石。シダとはいっても、非常に大きい。なぜ、葉が石になるのだろうか？　それとも、人為的なものなのだろうか？"}],"2036":[{"rank":"2","note":"［勅命］[[黄金郷の財宝探索","exp":"310","type":"財宝","name":"黄金郷の長衣","desc":"黄金郷と思われる地に潜入した勇敢な冒険者が持ち帰ったローブ。良質な生地から作られ高い技術を有していることがわかる。"}],"5932":[{"rank":"2","note":"","exp":"","type":"財宝","name":"ツィンク","desc":"角笛から発展した金管楽器で、リコーダーのように指で穴をふさいで音を調整する。ドイツや北欧では「ツィンク」、それ以外の地域では「コルネット」と呼ばれ、ヨーロッパ全域で広く親しまれている楽器の一つである。"}],"219":[{"rank":"1","note":"ドゴンの神話","exp":"180","type":"宗教遺物","name":"アンマ像","desc":"サハラの南に住むドゴン人の唯一神の像。アンマは星を作り、太陽と月を作った。さらに大地を作って自ら交わり、精霊を作ったといわれる。"}],"3638":[{"rank":"2","note":"書きかけの地図<br/><br/>発見時経験値390　発見物カード経験値195","exp":"390","type":"地理","name":"モンゴル高原","desc":"どこまでも続くかのような広大な草原地帯。降水量が少ないためか高原の中央部は砂漠になっている。"}],"1336":[{"rank":"2","note":"海峡の南の島","exp":"320","type":"地理","name":"スマトラ島","desc":"マレー半島の南に位置する島。マレー半島との距離は非常に近く、動植物も似通っているようだ。古くから東西交易の要衝として様々な商人が来航する島である。"}],"5555":[{"rank":"3","note":"","exp":"240","type":"地理","name":"グリーンサンドビーチ","desc":"ハワイ島南端のカウにある砂浜海岸。砂が緑色に見えるのはカンラン石（ペリドットの原石）が混じっているからだとされる。"}],"2382":[{"rank":"2","note":"変わったサメの調査","exp":"300","type":"海洋生物","name":"ネコザメ","desc":"日本付近の暖かい海に生息するサメ。その名前は、どことなくネコに似た顔に由来する。気性はおとなしく、人間を襲うことはほとんどない。"}],"3419":[{"rank":"","note":"","exp":"","type":"レリック","name":"ヘルメス主義","desc":"ヘルメス・トリスメギストスを祖とする、神秘を追究する者たちの思想。様々な学問を内包した知識の結晶ともいえる思想の総称。"}],"997":[{"rank":"1","note":"冒険者のバイブル","exp":"55","type":"財宝","name":"東方見聞録","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。"}],"3390":[{"rank":"4","note":"四方領域の王","exp":"740","type":"歴史遺物","name":"ナラム・シンの石碑","desc":"メソポタミア文明南部のバビロニアのうち、北部地域のアッカド帝国を治めたとされるナラム・シンの石碑。\nナラム・シンは大規模な遠征を繰り返し帝国の領土を拡げ、自らを神とした。"}],"2332":[{"rank":"2","note":"書きかけの地図","exp":"220","type":"地理","name":"鳥取砂丘","desc":"日本の中国地方に位置する海岸砂丘。\n見た目は小規模な砂漠のようだが、雨や雪が降り、砂丘独特の動植物も多く見られる。"}],"1623":[{"rank":"3","note":"ジョルジョーネのユディト","exp":"539","type":"美術品","name":"ユディト","desc":"ジョルジョーネ作の絵画。旧約聖書「ユディト記」を題材とした。ユディトの右手には剣足元には敵将ホロフェルネスの首。ユディトの表情や、色彩、タッチからは、臨場感は微塵も感じられないが、神聖さや静寂な空気が醸し出されている。"}],"2404":[{"rank":"4","note":"東の果てのガラパゴス","exp":"650","type":"地理","name":"屋久島","desc":"九州の南部にある島。1000mを超える山々を有し、雨が多い。\nその豊かな自然が多様な生物を育んでいる。東洋のガラパゴスともいえる島である。"}],"5585":[{"rank":"5","note":"発見物カード:410","exp":"820","type":"天文","name":"とも座","desc":"ラカーユが制定した南天の星座のひとつ。ギリシャ神話に登場するアルゴ船の船尾部分にたとえられる。"}],"3846":[{"rank":"3","note":"脚と首の長い骨の調査","exp":"470","type":"化石","name":"前脚と首の長いドラゴンの骨","desc":"体長およそ25m、体高も16mに及ぶ巨大な生物の骨。長い首と、後脚より長い前脚が特徴のようだ。"}],"5143":[{"rank":"2","note":"到達する","exp":"380","type":"港・集落","name":"ホバート","desc":"オーストラリア南部の島、ヴァン・ディーメンズ・ランドの南岸にある街。ダーウェント川の河口に位置し、立地条件の良さから、漁業基地としての機能を持つに至った。"}],"3703":[{"rank":"","note":"ブルターニュの雌獅子の剣<br/><br/>発見時経験値2260　発見時名声1800","exp":"","type":"レリック","name":"ブルターニュの雌獅子","desc":"フランス沿岸部を荒らし回り、ブルターニュの雌獅子と恐れられた女海賊ジャンヌ。彼女の復讐心は満たされたのだろうか。"}],"6922":[{"rank":"2","note":"発見物カード:195","exp":"390","type":"天文","name":"モサラー","desc":"さんかく座のアルファ星。3等星で、二等辺三角形の頂点に位置する。名はアラビア語で「三角の頭」を意味する。"}],"5896":[{"rank":"5","note":"","exp":"1360","type":"中型生物","name":"チベットスナギツネ","desc":"中央アジアに生息するキツネの仲間。草原や岩の下の隙間などに巣を作って生活する。長い鼻面と細い目が特徴的な顔は、ぼーっとしているように見えることがある。"}],"517":[{"rank":"1","note":"古代の銀細工の地図","exp":"71","type":"歴史遺物","name":"銀の装身具","desc":"銀で作られた装身具。単なる装身具ではなく護符など、特別な目的で作られた物が多いようである。"}],"995":[{"rank":"1","note":"冒険者のバイブル","exp":"55","type":"財宝","name":"東方見聞録","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。"}],"105":[{"rank":"1","note":"カラフルな魚の地図","exp":"29","type":"海洋生物","name":"チョウチョウウオ","desc":"熱帯の海で見られる美しい色の魚。平べったい体をしており、口はとがっている。さまざまな色や模様のものがいる。"}],"1547":[{"rank":"2","note":"えぐれた大地","exp":"275","type":"地理","name":"カーペンタリア湾","desc":"アーネムランドとヨーク岬半島に挟まれた、オーストラリア北東部の湾。面積は広大であるものの、全体的に水深は浅い。沿岸部はマングローブに覆われており、湾に注ぎ込む河川にはワニが生息している。港の建造は困難だろう…。"}],"6532":[{"rank":"5","note":"レガシー星の叡智　中央","exp":"2700","type":"歴史遺物","name":"ネブラの天文盤","desc":"先史時代のヨーロッパで作られた青銅製の円盤。太陽と月、星々が金を貼って表されている。両手で抱えるほどの大きさで、天体観測に使用された道具と考えられる。"}],"3680":[{"rank":"4","note":"","exp":"650","type":"地理","name":"チェリュスキン岬","desc":"ユーラシア大陸最北端の岬。\n北東航路において、航海の重要な目印となるだろう。"}],"1268":[{"rank":"4","note":"美の基準","exp":"720","type":"美術品","name":"ウルビーノのビーナス","desc":"ティツィアーノ作。前面に横たわるヴィーナスの視線はこちらに向けられ見る者を挑発するようである。足元で丸まる子犬は従順と貞節を、手に持つバラは愛を象徴している。貴族の館の洋服ダンスを探る侍女が、女神を世俗的に感じさせる。"}],"1990":[{"rank":"2","note":"釣り","exp":"350","type":"海洋生物","name":"ノコギリエイ","desc":"ノコギリのような吻を持つエイ。船底に穴を開け、溺れた人間を食べるとも言われているが…。"}],"6601":[{"rank":"3","note":"","exp":"500","type":"植物","name":"プロソピス・キネラリア","desc":"中東の乾燥地域に自生する、エンドウマメ科の植物。「ガフの木」とも呼ばれる。生命力が非常に高く、砂漠のような干ばつ地でも育つ。樹齢数百年にも及ぶ個体もあるという。"}],"3328":[{"rank":"2","note":"華やかな花木の地図","exp":"210","type":"植物","name":"ハナミズキ","desc":"北米原産の花木。晩春に白色や淡いピンク色の花を咲かせ、秋には赤い実をつける。"}],"147":[{"rank":"5","note":"ゲイボルグ","exp":"1196","type":"歴史遺物","name":"ゲイボルグ","desc":"ケルト神話の英雄・クーフーリンが、影の国の女王・スカアハから授かった魔槍。クーフーリン自身も、誓約を破ったためこの槍に貫かれて命を落としたという。"}],"6138":[{"rank":"1","note":"古代ギリシャの傑作","exp":"130","type":"美術品","name":"御者の像","desc":"デルフォイ遺跡で発見された御者の青銅像。競技会で優勝した御者の功績を讃えるために奉納されたものであろう。均整の取れたすばらしい像である。"}],"4994":[{"rank":"1","note":"サロニカの門の外、<br/>南東にある一本杉のそば。<br/>生態調査、生物学、ランク2","exp":"80","type":"小型生物","name":"ヨーロッパハタリス","desc":"ヨーロッパの北東部に生息する、体長約20cmのリス草原や牧草地にトンネル状の長い巣穴を掘って暮らす。\n植物の葉や根、種などを食べる。 食べ物を頬袋に詰め込んで運び、巣に持ち帰るようだ。"}],"1927":[{"rank":"2","note":"地に棲む鳥","exp":"330","type":"鳥類","name":"アナホリフクロウ","desc":"地中に巣がある珍しいフクロウ。主に、他の動物が掘った穴を利用して自分の巣を作る。また、長い脚でニワトリのように走る、昼に活動するなど、他のフクロウにはない特徴が多い。南北新大陸の草原に広く分布。"}],"371":[{"rank":"1","note":"果物がなる木の地図","exp":"19","type":"植物","name":"チェリー","desc":"春に薄桃色の花が咲く落葉樹。葉と花を同時につけ、花が終わったあとの実はサクランボとして食用になる。"}],"538":[{"rank":"4","note":"古代の謎","exp":"744","type":"歴史遺物","name":"ガラス状の破片","desc":"モヘンジョ・ダロで発見された、溶けてガラスのようになった陶器の破片。どうやったら陶器がこんな状態になるのだろうか？"}],"5584":[{"rank":"2","note":"堺の目の前で発見<br/>晴れの夕方から日没まで。晴れの夕方でもでないときあり。","exp":"390","type":"気象・現象","name":"渦潮","desc":"特定の海峡などで発生する渦型の潮流。最大で直径20mほどのものも見られる。どの海でも観測できるものではないことから、海中の地形などが影響していると思われる。"}],"6027":[{"rank":"2","note":"","exp":"210","type":"財宝","name":"ペドロからの手紙","desc":"ペドロ王子が兄弟に宛てた手紙の写し。各王子に、それぞれ文化、貿易、戦争、宗教について書かれた手紙を出していたようだ。エンリケ王子宛ての手紙が最も多く、ヴェネチアによる東方貿易についての資料が添付されている。"}],"6129":[{"rank":"5","note":"","exp":"1030","type":"植物","name":"ラフレシア・アルノルディイ","desc":"東南アジアに多く分布している寄生生物で、直系1m近い分厚く大きな花をつける。\nイングランドの調査隊が発見したようだが、虫を誘う酷い悪臭を放つため、近づくにも勇気が必要だったのではないだろうか…。"}],"6959":[{"rank":"5","note":"発見物カード:810","exp":"1620","type":"化石","name":"ストロマトライト","desc":"層状の化石で、地球に初めて酸素をもたらしたとされる珪藻類と、土砂などが幾重にも積み重なったもの。多くは化石だが、一部の限られた海域などでは、原生しているものを確認することができる。"}],"3754":[{"rank":"5","note":"クエスト「巨蟹宮の調査」<br/>発見物カード:465","exp":"930","type":"天文","name":"かに座","desc":"黄道十二星座の1つ。化け蟹カルキノスが、兄弟のヒュドラを助けようとしてヘラクレスに踏み潰されたのを、女神ヘラが哀れんで天に上げた姿とされる。黄道十二星座の中では他と比べて明るい星がなく、目立たない。"}],"280":[{"rank":"1","note":"ヘレニズムの王","exp":"65","type":"歴史遺物","name":"セレウコス1世の大理石像","desc":"アレクサンドロス大王の参謀にして、セレウコス朝シリア王国の建国者、セレウコス1世の大理石像。"}],"1846":[{"rank":"1","note":"「彫像の地図」<br/>発見物カード:75","exp":"150","type":"宗教遺物","name":"イラ","desc":"コノパと同じく、神への生贄になった動物の偶像である。コノパよりも小さく、簡略化されている。多くは白い石でできており、細かい装飾はないが愛らしい。こういった家畜がいかに身近であったかがうかがえる。"}],"3181":[{"rank":"5","note":"氷海がもたらした幸運","exp":"1130","type":"地理","name":"ラブラドル半島","desc":"新大陸北部にある半島で、南部ですら長期に渡り海が凍結するという厳しい気候の地域。ヴァイキングの伝説で「マルクランド（森の国）」と名づけた地と思われる。"}],"2517":[{"rank":"1","note":"金色の鳥の地図","exp":"140","type":"鳥類","name":"キンバネホイビイ","desc":"台湾島の山岳地に生息する鳥。金色の翼と、はっきりとした眉が特徴である。人懐こく、数も多いため、見かけられる機会は多い。"}],"2349":[{"rank":"4","note":"さまざまな恋の形","exp":"750","type":"財宝","name":"源氏物語","desc":"紫式部によって書かれた長編小説。平安時代の宮廷を舞台としている。\n華やかな貴族の生活と複雑な人間関係をつづった、情趣溢れる恋愛小説である。"}],"1181":[{"rank":"2","note":"最初の新大陸","exp":"360","type":"地理","name":"サンサルバドル島","desc":"1492年10月12日、イスパニアのコロンがカリブ海で最初に上陸した島である。この名称はコロンが付けたものだが、現地の住民はこの島を「グアナハニ」と呼んでいた。"}],"2702":[{"rank":"2","note":"もうひとつの宮殿","exp":"300","type":"史跡","name":"昌徳宮","desc":"景福宮の離宮。\n他の宮は、威厳を示すため、人為的に地形を作って建てられることが多いが、この離宮は自然の地形に合わせて建てられている。"}],"2482":[{"rank":"4","note":"王城の過去","exp":"720","type":"史跡","name":"熱蘭遮城","desc":"読みは「ゼーランディアじょう」。ネーデルラント人が台湾島に築城した城砦。\n石材で築かれた堅固な城で、大量の船が停泊できる大きな港を擁していた。"}],"3575":[{"rank":"","note":"","exp":"","type":"レリック","name":"ベオウルフ","desc":"叙事詩に描かれる剛勇無双の勇士ベオウルフ。体は年老いても、その心は衰えずドラゴンと死闘の末、壮絶な相打ちを遂げたという。"}],"3577":[{"rank":"1","note":"クエスト「石囲いの聖地」<br/>発見時経験値182　発見物カード経験値91","exp":"182","type":"史跡","name":"ヘイアウ","desc":"積み石で囲んだ一帯で聖域とされる。ハワイ島の随所に散在する。精霊や神々への祈りを捧げる場所であるらしく、祭神によって呼び方も異なる。"}],"5888":[{"rank":"5","note":"","exp":"1340","type":"海洋生物","name":"ボウズイカ","desc":"主に太平洋に生息するイカの一種。胴が太いため、タコと間違われることもある。深海に棲むため、眼球が大きく発達している。味はタコに近いという。"}],"4805":[{"rank":"2","note":"","exp":"290","type":"地理","name":"アリューシャン列島","desc":"北米大陸のアラスカ半島からカムチャッカ半島に延びる列島。ベーリング海と太平洋の境となっている。"}],"3881":[{"rank":"5","note":"壁画に差す光","exp":"940","type":"歴史遺物","name":"サン・ダガー","desc":"北米の内陸部にある、岩を重ねて作られた装置。天体観測に使われたとみられる。重ねられた岩の隙間から差す太陽光が、短剣状の形となって岩壁に映る仕組みとなっている。岩壁側には、夏至などの際の光の位置を示す模様が刻まれている。"}],"1276":[{"rank":"3","note":"ヒンドゥーの神像","exp":"462","type":"宗教遺物","name":"ガルーダ像","desc":"ヒンドゥー教における神鳥。ヴィシュヌを背に乗せて大空を舞うという。ヒンドゥー教圏ではガルーダを特別に信仰することが多々あるようだ。"}],"3583":[{"rank":"2","note":"女神が統べし低木","exp":"204","type":"植物","name":"マイレ","desc":"ハワイの山地に生息するツル植物。濃い緑色の葉から爽やかで強い香りを放つ。神聖な植物とされ、古代よりヘイアウの装飾や、決闘の勝利者の首にかけるレイとして利用されている。"}],"1307":[{"rank":"1","note":"角のある虫の地図","exp":"120","type":"虫類","name":"ゴホンツノカブト","desc":"突き上げるように生えた一本の長い角と、短い四本の角を持つ虫。長い肢をもち、羽の部分は茶色っぽい色をしている。"}],"5831":[{"rank":"2","note":"","exp":"320","type":"気象・現象","name":"乳房雲","desc":"雲からこぶ状の雲がいくつも垂れ下がっているように見える現象。雲の内部や底での乱気流の動きにより作り出されると考えられる。そのため、この雲を観測する際は大雨や嵐に注意が必要である。"}],"532":[{"rank":"2","note":"古代の道具の地図","exp":"390","type":"歴史遺物","name":"古代の馬具","desc":"馬を扱うための道具類である。くつわやあぶみ、鞍が発明されるまで、馬はもっぱら荷役や農耕、馬車用に使われていた。"}],"2259":[{"rank":"2","note":"髪に飾る花","exp":"210","type":"植物","name":"プルメリア","desc":"南国で見られる花。\n甘い香りとはっきりした花弁の色が特徴で、よく髪飾りなどに使用される。茎が折れやすく、そこから分泌される白色の乳液は毒にも薬にもなるらしい。"}],"5790":[{"rank":"1","note":"","exp":"","type":"歴史遺物","name":"細石刃","desc":"打製石器の一種。柄になるものと組み合わせられ、交換できる穂先として用いられた。世界各地の広い範囲で出土しているようだ。"}],"6896":[{"rank":"5","note":"発見物カード:615","exp":"1230","type":"小型生物","name":"イイズナ","desc":"北米やユーラシア大陸などに広く分布する、小型の肉食獣。可愛らしい見た目に反し、獰猛な気性を備える。行動は非常に敏捷で、自分よりも大きな獲物にも飛びついて捕食する。"}],"2727":[{"rank":"5","note":"造られた洞窟","exp":"1130","type":"宗教建築","name":"石窟庵","desc":"新羅時代の仏教遺跡。内部はドーム状になっているが、洞窟を掘ったのではなく、石材を積み上げ、その上に土を盛って建築されたという。新羅の石造建築技術は、かなり高かったようだ。"}],"1865":[{"rank":"2","note":"旅人が再び訪れる木","exp":"280","type":"植物","name":"カラファテ","desc":"南米のパタゴニアで見られる樹木。小ぶりな黄色い花をたくさん咲かせ、紫の小さな実をつける。「カラファテの実を食べた者は再びカラファテの地に帰ってくる」と言われている。"}],"373":[{"rank":"1","note":"画期的な絵画技法","exp":"95","type":"美術品","name":"ゴルゴタの丘","desc":"アンドレア・マンテーニャ作の祭壇画。ゴルゴタの丘ではりつけにされるキリストを描いたもので、ほぼ完成された遠近法を用いている。衣服や武具、馬具など、緻密な考証がされている点も評価できる。"}],"5757":[{"rank":"5","note":"2017.02.07新規追加","exp":"1340","type":"地理","name":"スメル山","desc":"ジャワ島の東部にそびえる、島の最高峰。最も活発に活動する火山の一つで、非常に噴火が多い。その名は、古代インドの世界観において世界の中心にそびえている須弥山に由来する。"}],"1348":[{"rank":"3","note":"ヒンドゥー教の支流","exp":"484","type":"地理","name":"バリ島","desc":"ジャワ島の東に位置する島。イスラム教を国教とする国が増えるなか、バリ島には独自のヒンドゥー教が広まっている。"}],"5348":[{"rank":"4","note":"発見物カード:340","exp":"680","type":"天文","name":"ピーコック","desc":"くじゃく座で最も明るい星で、２等星。\n名はオスのクジャクを意味する。"}],"5371":[{"rank":"4","note":"釣り発見：R17で確認．R15でも確認<br/>パラグアイ川上流．<br/>MAP左にある四角い橋が4か所かかっている所の左下(左上も)．<br/>□の中央に向かって釣り使用<br/><br/>発見時経験値660　発見物カード経験値330","exp":"660","type":"海洋生物","name":"ボドワード","desc":"南米の河川や湖に生息するナマズの仲間．\n成長するにつれて，皮膚が黒く，鎧のように硬くなる．"}],"6794":[{"rank":"3","note":"","exp":"","type":"天文","name":"シェリアク","desc":"こと座のベータ星。3等星であり、星の回転により明るさが変わる食変光星。名はアラビア語の「琴」が由来とされている。"}],"6135":[{"rank":"3","note":"","exp":"490","type":"地理","name":"チャシコツ岬","desc":"日本北部にある岬で、現地の地名「ウトロ」に由来するウトロチャシという砦跡がある。現地の言葉で砦や集会場を「チャシ」、その跡を「チャシコツ」と呼ぶ。初めは聖域や集会場だったものが、後に砦の機能も持つようになったようだ。"}],"6850":[{"rank":"2","note":"発見物カード:150","exp":"300","type":"天文","name":"ネカル","desc":"うしかい座のベータ星で、牛飼いの頭の部分に位置する。アラビア語で「牡牛を追う者」に由来する。"}],"454":[{"rank":"2","note":"極楽鳥花","exp":"210","type":"植物","name":"ストレリチア","desc":"アフリカに咲く花。横に吹き出すような花の姿が鳥のくちばしや尾羽のようで美しい。栽培できれば観賞用として人気が出そうだが、アフリカの植物なので難しいかもしれない。"}],"923":[{"rank":"1","note":"尾のないネズミの地図","exp":"24","type":"小型生物","name":"ゴールデンハムスター","desc":"背が赤茶色で腹が白く尾がほとんどないネズミ。動きが緩慢で地上で生活し、巣穴は自分で掘る。非常に大きな頬袋を持ち、大量のエサや巣材を運んでいる姿を見かける。"}],"6722":[{"rank":"5","note":"発見物カード:600","exp":"1200","type":"天文","name":"やまねこ座","desc":"北天の星座。おおぐま座とぎょしゃ座の間に位置する。すらりとした山猫の姿を表す。天文学者へヴェリウスが17世紀に設定した。"}],"604":[{"rank":"1","note":"彩色レンガの地図","exp":"99","type":"歴史遺物","name":"彩色レンガ","desc":"美しく彩色したレンガである。さまざまな色のレンガを組み合わせて、壁や門に模様を描くために使われる。"}],"5159":[{"rank":"1","note":"到達する","exp":"77","type":"港・集落","name":"マリンディ","desc":"アフリカ東岸に位置する港湾都市。7世紀以降、ムスリム商人が来航し、海上交易で繁栄した。"}],"6854":[{"rank":"3","note":"発見物カード:85","exp":"170","type":"植物","name":"ジャボチカバ","desc":"南米に広く分布する常緑樹。木の幹に直接花が咲き、実がなるのが特徴。白く小さな花の後には直径3センチほどの実ができる。実は柔らかく甘酸っぱいため食用にされるほか、果皮が伝統的に薬として使われている。"}],"6357":[{"rank":"4","note":"クエスト「世界の歴史に迫る」<br/>発見物カード:350","exp":"700","type":"財宝","name":"ニュルンベルク年代記","desc":"ドイツ南東部にある都市ニュルンベルクで出版された本。金属で活字を作り、紙に刷るという活版印刷の技術により広く出版された。この本では世界史を七つの年代に区分し、多くの挿絵と共に解説している。"}],"1956":[{"rank":"1","note":"星の花の地図","exp":"170","type":"植物","name":"マレシェルビア","desc":"南米南西部の乾燥地帯にのみ生息。花びらが星形に付いており、白や紫の花を咲かせる。"}],"5521":[{"rank":"2","note":"「天体学者の観測記録」<br/>発見物カード:160","exp":"320","type":"天文","name":"ほ座","desc":"南天の星座のひとつ。この星座とりゅうこつ座の一部を結ぶと十字を成すため、他の星座と間違われやすい。"}],"2059":[{"rank":"1","note":"古代の街調査の下調べ","exp":"180","type":"地理","name":"イーストラ半島","desc":"トリエステの南に位置する半島。ポレチュと呼ばれる古代ローマ時代の市街地が存在している。ポレチュには、ローマ時代に建設された聖堂や神殿が崩壊することなく残っているという。"}],"3232":[{"rank":"5","note":"ヴィンランドの詩","exp":"1360","type":"歴史遺物","name":"ミョルニル","desc":"北欧神話の雷神トールの戦槌。すさまじい破壊力を誇り、一撃で倒せなかったのはロキの子・ヨルムンガンドくらいである。\n北欧ではミョルニルをお守りとしてペンダントにしたり、儀式に用いたりする。"}],"732":[{"rank":"2","note":"聖者と獣の青銅像","exp":"300","type":"美術品","name":"聖ヒエロニムスとライオン","desc":"バルトロメオ・ベラーノ作の青銅像。聖ヒエロニムスがライオンの足に刺さったトゲを抜いている姿である。青銅像は、通常は鋳型（いがた）を使って複製できるが、この作品は蝋型で作られた1点物で、複製品がない。"}],"1295":[{"rank":"5","note":"空飛ぶネコ<br/><br/>発見時経験値949　発見物カード経験値474","exp":"949","type":"小型生物","name":"ヒヨケザル","desc":"首から手足、尾まで皮膜に覆われたサル。\n指先にある皮膜を使って木から木へ滑空し、時には100m以上もの距離を飛ぶ。"}],"3789":[{"rank":"4","note":"視認<br/><br/>発見時経験値650　発見物カード経験値325","exp":"650","type":"天文","name":"ポルックス","desc":"ふたご座で最も明るい星。星座図では、双子のうち、弟の頭に位置する。名はイアソンの探検隊に参加した双子の片割れ、ポリュデウケスに由来する。冬のダイヤモンドの一角。"}],"274":[{"rank":"3","note":"ヘビを食べる毒蛇","exp":"539","type":"小型生物","name":"コブラ","desc":"大型で非常に強い毒をもつヘビ。かまれるとまず助からないといわれている。大型のものは5mを超え、鎌首を持ち上げると成人男性の顔の高さにまでなる。威嚇（いかく）するときに、頭部を横に広げる独特の姿勢をとる。"}],"5142":[{"rank":"2","note":"到達する","exp":"246","type":"港・集落","name":"ペルナンブコ","desc":"南米大陸の東部沿岸に位置する港町。大西洋交易の拠点として発展してきた。"}],"5107":[{"rank":"1","note":"到達する","exp":"10","type":"港・集落","name":"ナント","desc":"ローマ時代から存在する、歴史ある街。ロワール川に近く、昔から交通と交易の要衝として栄えた。農作物や織物を産するほか、香料が重要な産物である。"}],"6136":[{"rank":"3","note":"","exp":"460","type":"地理","name":"ポルト・セグーロ","desc":"キリスト騎士団の騎士カブラルが発見し、上陸した地域。カブラルはガマの後任となってインド遠征隊を率い、ポルトガル人として初めて南アメリカの地を踏んだ。「安全な港」の名前に違わず良質の海岸が多く、活気のある港町もある。"}],"1889":[{"rank":"2","note":"サルベージ","exp":"320","type":"歴史遺物","name":"サン・パウロ号","desc":"ポルトガルの頑丈な大型船で、東インド貿易船の一隻。\nインドへ向かう途中、マダガスカルの東を回る航路をとったが、途中嵐に遭い、スマトラ島西岸沖まで流され、難破した。"}],"3801":[{"rank":"3","note":"島にすむカリブーの地図","exp":"530","type":"大型生物","name":"ヒガシグリーンランドカリブー","desc":"グリーンランドの東部に生息するトナカイの一種。小規模の群れで移動しつつ、苔などを食べて暮らしている。"}],"4846":[{"rank":"4","note":"バビロニアン・ロマンス","exp":"723","type":"財宝","name":"バビロニアンハープ","desc":"古代バビロニアのハーフ。多くの遺跡の壁画や石版に描かれており主に宗教的な行事で用いられていたと考えられる。大型だが座ったまま弾くのは困難で、立って演奏される。"}],"2546":[{"rank":"3","note":"四つ目鹿<br/><br/>発見時経験値480　発見物カード経験値240<br/>文化貢献度35","exp":"480","type":"中型生物","name":"キョン","desc":"台湾島や中国東部に分布するイヌに似た鳴き声が特徴的な小型のシカ。目の近くに臭腺があり、閉じた目のように見えることから、四つ目鹿とも呼ばれる。"}],"6750":[{"rank":"5","note":"","exp":"","type":"天文","name":"バタフライ星団","desc":"さそり座にある散開星団。さそりの尾にあたる位置の前端にある。羽を広げた蝶に似ていることから名付けられた。"}],"549":[{"rank":"1","note":"古代ペルシャ遺物の地図","exp":"35","type":"歴史遺物","name":"古代のレバノン杉","desc":"古代の中近東からペルシャにかけてよく使われていた木材。質がよく、建造物や船などに多用されていた。乱伐のため、現在ではほとんど見られない。"}],"2760":[{"rank":"4","note":"教えを説く者たちの証","exp":"660","type":"宗教遺物","name":"ハッチャンイ","desc":"儒教を学んだ者や儒教を教授する者が着用する、朝鮮の衣服。\n朝鮮の儒教は宗教ではなく学問であるが、多くの人々が儒教を学びその理念に基づいて行動している。"}],"5237":[{"rank":"1","note":"","exp":"","type":"植物","name":"ネトル","desc":"成人の膝ほどの高さになる多年生の植物。菱形の葉と茎には刺毛があり、刺さると強い痛みを感じる。煎じて飲むと、血行を促進しケガや疲労の回復に繋がるといわれている。"}],"6366":[{"rank":"2","note":"","exp":"280","type":"史跡","name":"ゲベル・バルカル","desc":"アフリカ北東にある砂岩の小山。アラビア語で「神聖なる山」という意味がある。崖下に広がる遺跡はエジプト第25王朝の首都ナパタとされ、エジプト文化の影響を強く受けた寺院や神殿が多くある。"}],"2338":[{"rank":"4","note":"クエスト「最古の和歌集」<br/>発見物カード:65","exp":"680","type":"財宝","name":"万葉集","desc":"約4500首を収めた和歌集。詠み手の身分や住む場所に関わらず、多様な作品が集められている。\n日本に現存する和歌集の中では、最古のものとされる。"}],"6491":[{"rank":"5","note":"追究クエスト","exp":"1200","type":"植物","name":"キメラセントポーリア","desc":"アフリカ南部の奥地でのみ見られる小型の植物セントポーリアの変異個体。通常個体と同様に、花弁は独特の光沢があり、変異体独特の縞模様もたいへん美しい。"}],"6700":[{"rank":"5","note":"追究クエスト","exp":"","type":"地理","name":"東尋坊","desc":""}],"1774":[{"rank":"2","note":"［勅命］「新大陸西岸進出への道標」<br/>リマ冒険「南米地形調査」","exp":"310","type":"地理","name":"デセアド岬","desc":"南米大陸南西岸にある岬。この周辺の地形は氷河によって造成されたフィヨルド地形であり、他の地域と大きく異なる。"}],"1563":[{"rank":"1","note":"メソアメリカの像の地図","exp":"150","type":"歴史遺物","name":"粘土細工の像","desc":"マヤ地域西部で見つかった粘土細工の像。さまざまな姿があるが、神々を模しているのだろうか。"}],"5184":[{"rank":"2","note":"到達する","exp":"256","type":"港・集落","name":"ヴェラクルス","desc":"街の名前はスペイン語で「真の十字架」の意味。16世紀初頭、エルナン・コルテスが上陸し、メキシコ湾における貿易の表玄関となっている。"}],"2406":[{"rank":"4","note":"屋久島にある魅力","exp":"660","type":"植物","name":"ジョウモンスギ","desc":"屋久島にある巨大な樹木。30m余りの高さまで伸びており、幹周りは16mにも及ぶ。\n太くうねった幹が、強い生命力を物語っている。"}],"1531":[{"rank":"1","note":"斑模様のチョウの地図","exp":"130","type":"虫類","name":"カスリタテハ","desc":"深く濃い青に、水色の斑模様が入った羽を持つ。飛ぶときに「カチカチ」という音を発する。"}],"5763":[{"rank":"2","note":"2017.02.07新規追加","exp":"320","type":"化石","name":"冷凍ライオン","desc":"冷凍されていた子どものライオン。他に同種のライオンが発見された報告はなく、いつからシベリアの地に眠っていたのかはわからない。"}],"2043":[{"rank":"2","note":"［勅命］[[運河開通事業の技術書","exp":"310","type":"財宝","name":"ダ・ヴィンチノート","desc":"ダ・ヴィンチ直筆の著書。天文学や医術に関する知識や考察から、デッサンやスケッチまで幅広く記述されている。しかし文字はすべて鏡文字で書かれており、読むことは容易ではない。"}],"6622":[{"rank":"4","note":"","exp":"710","type":"財宝","name":"三彩駱駝載楽俑","desc":"唐の時代に作られた陶器「唐三彩」の一つ。空を仰ぐラクダや胡人の男性楽団を表現した名作。美しい造形、華やかな釉薬、どちらを取っても「唐三彩」屈指の完成度である。"}],"499":[{"rank":"1","note":"古代ギリシャの槍の地図","exp":"59","type":"歴史遺物","name":"ファランクスの槍","desc":"ファランクスとは古代ギリシャの重装歩兵密集部隊のことである。このような長い槍を構え、盾と兜と脛当てで武装し、密集して敵に突入した。"}],"917":[{"rank":"2","note":"半透明の白い像","exp":"380","type":"歴史遺物","name":"エビ・イル像","desc":"メソポタミア文明の石像。材質はアラバスターで、柔らかな印象を受ける。この文明の像は、大きな目とウェーブのかかった髭が特徴である。"}],"6990":[{"rank":"2","note":"","exp":"177","type":"宗教遺物","name":"ヴィシュヌとガルーダ像","desc":"ヒンドゥー教の三神の一柱であるヴィシュヌが、神鳥ガルーダの方の上に立っている姿を表した青銅像。ガルーダはヴィシュヌの眷属で、乗り物でありアンコール美術にはこの二神を題材とした作品が多くある。"}],"222":[{"rank":"2","note":"ドラゴンの牙","exp":"370","type":"財宝","name":"ドラゴンの牙","desc":"ドラゴンの牙だと伝えられる物。黒光りした巨大な牙で、これが本当にドラゴンのものなら体長は100mを超えるだろう。本物かどうかは確かめようがないが見ていると勇気がわいてくるようだ。"}],"1858":[{"rank":"2","note":"クエスト「アンデスの大地母神」<br/>発見物カード:115","exp":"230","type":"宗教遺物","name":"パチャママ像","desc":"先住民の言葉で「母なる大地」を表す女神。豊穣を司る神であり、万物の母とされる。キリスト教の浸透以降は聖母マリアと同一視され、信仰の対象となった。"}],"5162":[{"rank":"1","note":"到達する","exp":"75","type":"港・集落","name":"モガディシオ","desc":"アフリカ北東岸の街。古代から人が住むが、気候が厳しく耕作には向かない。畜産は盛んで、主な交易品は畜産物である。それ以外には鉱物資源も産出している。"}],"527":[{"rank":"1","note":"古代の装身具の地図","exp":"34","type":"歴史遺物","name":"ガラスの装身具","desc":"装飾用の加工を施したガラス。さまざまな文明で見られ、色や形に特徴がある。ガラスは古代から用いられてきた素材の一つ。"}],"2484":[{"rank":"2","note":"神社跡の調査依頼","exp":"330","type":"宗教遺物","name":"鳥居","desc":"神社へと続く参道に配置された、門の一種。この鳥居に見られる赤い色は、厄除けの意味を持つとされている。日本では、こうした鳥居によって、聖域と俗界が区分されている。"}],"1790":[{"rank":"1","note":"珍しい腕輪の地図","exp":"160","type":"財宝","name":"銀の腕輪","desc":"南米でも最近銀細工が増えたようだ。なんでも、インカ道の南のほうには、宝の山があるとか…。"}],"2741":[{"rank":"1","note":"貴重な書物の地図","exp":"140","type":"財宝","name":"仏氏雑弁","desc":"政治家・鄭道伝による著書。鄭道伝は、朝鮮王朝の創始者である李成桂に重用された。\nこの著書によって、儒教を中心とした政策の基礎を確立させたという。"}],"1900":[{"rank":"3","note":"ニヤリと笑う昆虫","exp":"480","type":"虫類","name":"ジンメンカメムシ","desc":"東南アジアに生息するカメムシの一種。逆さから見ると体の模様が人の顔に見える。模様は様々で笑顔や泣き顔に見える個体もいる。"}],"1225":[{"rank":"4","note":"紋章文字に秘められた歴史","exp":"780","type":"歴史遺物","name":"カンシュル王の腕輪","desc":"パカル王の息子で、チャン・バラム王の弟であるカンシュル王の腕輪。緻密な彫刻と細かい彩色が施された、豪華なものである。"}],"245":[{"rank":"1","note":"バルト海の神の島","exp":"80","type":"地理","name":"ゴトランド島","desc":"バルト海最大の島。先史時代から人が住んでいたそうだ。ハンザ同盟の時代には、交易上重要な存在だった。\n「神の島」もしくは、「神の国」とも呼ばれている。"}],"6567":[{"rank":"5","note":"追究クエスト","exp":"1100","type":"歴史遺物","name":"角杯","desc":"獣の角で作られた杯。儀式で用いられていたとされ、古代の神話にも登場する。酒場マスター曰く「角杯で飲む酒は気持ちが高揚し、最高に気分が上がる」とのことだ。"}],"5719":[{"rank":"5","note":"北欧神話の芸術の神","exp":"1460","type":"宗教遺物","name":"ブラギの竪琴","desc":"北欧神話の詩の神ブラギが奏でたという黄金の竪琴。天界から冥界まで響きわたり、川や木々もその音色に聞き惚れたという。"}],"5067":[{"rank":"2","note":"到達する","exp":"330","type":"港・集落","name":"サンフランシスコ","desc":"北米西部にある街。カリフォルニアのゴールドラッシュによって爆発的に人口が増え、産業や流通業が急激に発展した。活気のある街だが、治安の悪化も懸念されている。"}],"5222":[{"rank":"1","note":"","exp":"198","type":"宗教遺物","name":"ウル・ナンム法典","desc":"ウル第三王朝の初代王ウル・ナンムによって発布された法典。古代バビロンのハンムラビ法典に影響を与えたとされる。\n損害賠償に重点が置かれた刑罰が規定されている。"}],"5108":[{"rank":"2","note":"到達する","exp":"238","type":"港・集落","name":"ハバナ","desc":"カリブ海のキューバ島北西岸に位置する街。天然の良港で、カリブ特有の産物が流通するほか、良質のタバコが扱われている。"}],"6055":[{"rank":"5","note":"これまで以上の高い犬","exp":"830","type":"中型生物","name":"ペキニーズ","desc":"「京巴(ジンバー)」と呼ばれる小型犬。中国の宮廷内で長年、愛玩されてきた。毛が黄色いものは特に珍重されるという。宮廷から持ち出せば死刑といわれるが、実際は規格外の子犬が市場に持ち込まれ、ひそかに飼っている者もいるようだ。"}],"6946":[{"rank":"3","note":"","exp":"","type":"財宝","name":"鍍金銅蚕","desc":"金めっきが施された蚕をかたどった銅製品。中国において、漢代に多く作られたとされ、シルクロードの繁栄をうかがわせる。"}],"1344":[{"rank":"1","note":"跳躍するカエルの地図","exp":"100","type":"小型生物","name":"トビガエル","desc":"他のカエルと異なり、前足にも水かきがついている。それにより、木の上から跳んだときに、かなりの距離を滑空する。四肢は長く、木に登るのに適している。"}],"930":[{"rank":"1","note":"美の女神に捧げられた街","exp":"135","type":"史跡","name":"パフォス","desc":"キプロスの丘の上にある、古代ローマの遺跡である。建物跡やモザイクの壁画などが数多く残る。キプロスは、多くの文明が交錯した土地である。"}],"4983":[{"rank":"3","note":"発見時経験値540　発見物カード経験値270","exp":"540","type":"地理","name":"ロードス島","desc":"カンディアの北東に浮かぶ島。かつてロードスの港には、ギリシャ神話に登場する太陽神ヘリオスの巨像があったといわれている。"}],"5352":[{"rank":"3","note":"","exp":"480","type":"海洋生物","name":"シギウナギ","desc":"細長い体と、長く突き出した顎が特徴の深海魚。\nこの顎を使い、甲殻類を補食していると考えられている。"}],"5194":[{"rank":"2","note":"到達する","exp":"380","type":"港・集落","name":"重慶","desc":"読み方は、「チョンチン」。長江上流に位置し、自然に囲まれている街。\n夏は酷暑だが、冬は比較的過ごしやすい。この地で、二重の慶事があったことから、この名前が付いたといわれている。"}],"5554":[{"rank":"2","note":"インドの民族楽器","exp":"350","type":"財宝","name":"プーンギー","desc":"インド発祥の楽器。\nひょうたんの先から息を吹き込むことで音を出すことができる。また、蛇使いが蛇を操る際にも演奏される。"}],"6133":[{"rank":"2","note":"","exp":"360","type":"史跡","name":"東坡赤壁","desc":"北宋の文人である蘇軾が黄州に左遷された頃に「赤壁賦」前後作を作ったとされる場所。三国志で有名な赤壁から程近い場所にある。晩唐の詩人、杜牧が詩に詠んだことで、古戦場の赤壁と混同されたといわれる。"}],"5392":[{"rank":"4","note":"","exp":"640","type":"史跡","name":"ディオニソス劇場","desc":"古代アテナイでディオニシア祭が開かれていた劇場。ディオニシア祭は悲劇の内容を競う祭りであったため、数多くのギリシャ悲劇がこの劇場で初めて上演された。"}],"6883":[{"rank":"3","note":"発見物カード:330","exp":"660","type":"地理","name":"ロフォーテン諸島","desc":"ノルウェー海に連なる島群。氷河に削られた岩山が並ぶ。北極圏に位置しているが、気候は比較的温暖。そのためか、多くの海鳥が生息している。"}],"6568":[{"rank":"5","note":"追究クエスト","exp":"1150","type":"宗教遺物","name":"ガンガーの像","desc":"ガンジス川を神格化したものとされる、女神ガンガーの像。ヒマラヤ山脈を神格化したヒマヴァット神の娘といわれ、人々に恵みを与える聖なる川のような存在として信仰されている。"}],"6697":[{"rank":"3","note":"","exp":"530","type":"気象・現象","name":"馬蹄雲","desc":"馬の蹄のようなU字型の雲。積雲が消えかけているときにできやすい。出現して数十秒で形を変えて消えてしまうことが多い。"}],"1059":[{"rank":"1","note":"楔文字の遺物の地図","exp":"60","type":"歴史遺物","name":"楔形文字の粘土板","desc":"「くさびがたもじ」。楔形文字が刻まれた粘土板。日常的に用いられていたようで、大量に出土する。まとまって出土する場所は、おそらく図書館のような施設だったのだろう。"}],"1470":[{"rank":"2","note":"時代の守護者","exp":"330","type":"財宝","name":"ジャヤヴァルマン7世の頭部","desc":"アンコール王朝の王ジャヤヴァルマン7世の像の頭部。心無い破壊に遭い頭から下は壊されてしまった。この王は勇猛果敢で知られ、王朝に多くの勝利をもたらしたが、アンコール・トムを建設するなどの信心深い一面も見られる。"}],"3784":[{"rank":"1","note":"視認","exp":"150","type":"天文","name":"宵の明星","desc":"夕暮れ時に西の空に明るく輝く惑星。古代ギリシャではヘスペロスと呼ばれた。"}],"1310":[{"rank":"1","note":"書きかけの地図","exp":"190","type":"地理","name":"マール山脈","desc":"南米南部東岸にある山脈。海からの風をさえぎるようにそびえ立っている。"}],"862":[{"rank":"3","note":"天翔ける太陽","exp":"440","type":"宗教遺物","name":"スーリヤ像","desc":"インド神話の太陽神の像である。スーリヤは暁の女神であるウシャスを妻とする。スーリヤは全身が光り輝いているため、朝日となって姿を表すと、暁であるウシャスは目がくらみ、姿を隠してしまうという。"}],"6986":[{"rank":"3","note":"","exp":"","type":"海洋生物","name":"トラフザメ","desc":"インド洋から太平洋にかけて、浅い水深のサンゴ礁に生息しているサメ。全体的に平たい姿をしており、丸く横長の顔と長い尾びれが特徴。背中に黒い斑点模様がある。おとなしい性格で、人間を襲うことはめったにないという。"}],"5611":[{"rank":"1","note":"","exp":"170","type":"化石","name":"巨大なペンギンの骨","desc":"北米中部で見つかった巨大なペンギンのような骨。通常の水鳥と異なり、くちばしに歯のようなものが付いている。"}],"6413":[{"rank":"4","note":"マケドニアの遺跡の中<br/><br/>ゲーム内のlogより<br/>ヴェルギナの黄金の副葬品からヴェルギナの黄金副葬品<br/>へ修正しました","exp":"","type":"歴史遺物","name":"ヴェルギナの黄金副葬品","desc":""}],"929":[{"rank":"1","note":"美しい木の地図","exp":"10","type":"植物","name":"ヨーロッパカエデ","desc":"冬が近づくと葉が赤や黄色に色づく落葉樹。木の数が多いと大変美しい。実には羽のようなものがついており、風に乗って飛ぶ。"}],"5749":[{"rank":"1","note":"2017.02.07新規追加","exp":"","type":"植物","name":"ワタゲトウヒレン","desc":"高山に生息するトウヒレンの一種。葉から生えた白い毛が、植物の大部分を覆っている。毛に覆われた内部の空間は、外より高温になっていて、寒い高山で植物の成長を助けているとされる。"}],"3157":[{"rank":"4","note":"スキュラとカリュブディス","exp":"700","type":"地理","name":"メッシナ海峡","desc":"イタリア半島とシチリア島の間に位置する海峡。最も狭い箇所で幅3～4kmであり、潮流が速いことで知られる。"}],"898":[{"rank":"2","note":"熱帯の王","exp":"270","type":"虫類","name":"ダイオウサソリ","desc":"尾の先端に毒を持った大型の虫。毒があるといっても人間を死に至らしめるほど強くはなく、せいぜいしびれさせる程度である。全身が硬いこうらで覆われている。"}],"5881":[{"rank":"5","note":"","exp":"1020","type":"虫類","name":"ヒョウガユスリカ","desc":"ヒマラヤ山脈の氷河に生息する蚊の一種。羽は退化しており、足で歩いて移動する。"}],"335":[{"rank":"5","note":"悪魔の使い","exp":"1196","type":"小型生物","name":"カーペットカメレオン","desc":"色とりどりに織り込まれた絨毯のような体色をしている。よく動く目で獲物を捕え、ゆっくりと近づいて、すばやく捕食する。その様子から「悪魔の使い」とも呼ばれている。"}],"1808":[{"rank":"1","note":"師弟の絵","exp":"100","type":"美術品","name":"キリストの洗礼","desc":"ダ・ヴィンチの師であるアンドレア・デル・ヴェロッキオの手による絵画。だが、この絵で背景と一番左下の天使はダ・ヴィンチが描いたとされる。師ヴェロッキオは、その天使のあまりの美しさに驚愕し、以後絵画は描かなくなったという。"}],"6278":[{"rank":"2","note":"","exp":"240","type":"宗教遺物","name":"チャンドラの仮面","desc":"インド神話の月の神であるチャンドラの顔をかたどった仮面。月光を思わせる色合いと、神話で伝えられている月の特性を表現した顔つきに作られる。仮面劇で使われたり、寺院や家庭に飾られたりするようだ。"}],"6719":[{"rank":"5","note":"楽の叡智・心に響く楽器　中央","exp":"","type":"財宝","name":"編鐘","desc":"複数の鐘からなる打楽器。春秋戦国時代に登場し、明代には金の編鐘も制作された。吊り下げられた何点もの鐘はそれぞれ音の高さが異なる。権力を象徴するものであり、宮廷の儀式で用いられた。"}],"3418":[{"rank":"4","note":"妙なる調べ","exp":"700","type":"財宝","name":"ソネット集","desc":"シェークスピアが発表した154編からなる詩集。ソネット形式で書かれている。主なテーマはさまざまな恋愛観と人間の美、そして死についてである。\nソネットとは14行で形成される定型詩で、12世紀初頭のイタリアで確立された。"}],"6637":[{"rank":"","note":"","exp":"350","type":"気象・現象","name":"赤潮","desc":"海水が赤く変色する現象。水温変化や富栄養化など発生原因は諸説ある。ヨハネ黙示録に第二の天使のラッパによって海が血の色に染まり、海の生き物の三分の一が死ぬという記述があり、古くから恐れられていた。"}],"1661":[{"rank":"1","note":"書きかけの地図","exp":"175","type":"地理","name":"バルデス半島","desc":"南米南部から大西洋に突き出した半島。沿岸ではアザラシの、南大西洋側ではクジラの姿を見ることができる、生物の楽園である。"}],"6935":[{"rank":"2","note":"発見物カード:115","exp":"230","type":"植物","name":"ツクモグサ","desc":"日本固有の高山植物。花びらのように見える薄い黄色のがく片は、外側が白い産毛に覆われている。外輪は4cmほど。晴れた日にしか開花せず、自生域も限られているため、その姿を目にするのは貴重とされる。"}],"6723":[{"rank":"5","note":"慈愛に満ちた生物<br/>発見物カード:520","exp":"1040","type":"海洋生物","name":"ザトウクジラ","desc":"体長１３ｍから１５ｍ程、大型のクジラ。普段は極圏地帯に生息しているが、夏の間は熱帯海域に移動、オキアミなどを捕食する。捕食の際、複数のクジラが泡を放出、円型の泡壁を形成し、獲物を一箇所に集中させる独特な狩りが特徴となっている。"}],"6591":[{"rank":"5","note":"レガシー伝説の王都バビロン　右下","exp":"2250","type":"歴史遺物","name":"竜骨車","desc":"低地から高地へと水をくみ上げるための揚水機。水田に水を引くために中国で発明された木製の農機具で、回転しながら移動する板が水桶の中の水を掻き揚げる。竜の骨格を思わせる見た目が、その名の由来だという。"}],"6609":[{"rank":"5","note":"文化貢献度50","exp":"830","type":"大型生物","name":"クチジロジカ","desc":"中国固有のシカで、チベットや周辺地域にある高原に生息する。唇や下顎、喉が白い体毛で覆われているのが特徴。オスは大きな角を持つ。袋角は貴重な薬材として用いられる。"}],"2492":[{"rank":"1","note":"奇妙な頭蓋骨の地図","exp":"190","type":"歴史遺物","name":"左鎮人の頭骨","desc":"読みは「さちんじんのずこつ」。遥か昔、台湾島に住んでいた人類の頭骨。\n周囲から骨角器なども見つかっており、狩猟生活をしていた時代の人類であると推察される。"}],"5940":[{"rank":"5","note":"","exp":"990","type":"植物","name":"復活草","desc":"乾季と雨季でその姿を変える珍しい植物。その驚くべき変貌ぶりから「復活草」と呼ばれており、水がなくとも数十年生き続けるという説すら存在する。"}],"140":[{"rank":"1","note":"グリーンドラゴン","exp":"150","type":"中型生物","name":"グリーンドラゴン","desc":"熱帯地方に生息する、大きな緑色の爬虫類。ドラゴンの幼生だという者もいるが、証明するには長い間育てなければならないだろう。恐ろしげな外見と裏腹に、草食性である。"}],"6900":[{"rank":"5","note":"","exp":"","type":"化石","name":"細長いクジラのような生物の化石","desc":"大きく細長いクジラのような姿をした海洋生物の化石。体長と比べて小さい頭骨には、多くの鋭い歯が並んでいる。空洞になっている椎骨を脳髄と液体で満たし、浮力を得ていたと考えられる。"}],"887":[{"rank":"1","note":"毒魚の地図","exp":"21","type":"海洋生物","name":"ゴンズイ","desc":"ドジョウやナマズに似た海水魚。背中に毒針を持つ。釣り上げたときにうっかり握ると大変なことになる。幼魚は群れて生活するため成魚より危険である。"}],"1924":[{"rank":"1","note":"這う花の地図","exp":"140","type":"植物","name":"チュパチュパ","desc":"真っ直ぐな茎の先に、明るい赤やオレンジの管状の花が咲く植物。ツタのように、地面や壁を這って成長する。育ちが早く、温暖な地域では越冬する。"}],"1766":[{"rank":"1","note":"凝った装飾の地図","exp":"150","type":"財宝","name":"銀とルビーのイヤリング","desc":"ある交易商が妻に贈ったといわれるイヤリング。銀もルビーもヨーロッパでは手に入りにくいもので、さぞかし裕福な豪商の手によって作成を依頼されたものなのだろう。"}],"3313":[{"rank":"4","note":"目指すは自由の大平原","exp":"730","type":"地理","name":"グレートプレーンズ","desc":"北米の中西部に位置する、台地状の平原。丈の短い草が広く自生している。雨量が少なく乾燥した気候である。"}],"5935":[{"rank":"3","note":"クエスト「喜劇の妖精王」<br/>発見物カード:240","exp":"480","type":"天文","name":"オベロン","desc":"天王星の衛星の一つ。妖精の王オベロンの名を冠している。クレーターには「マクベス」や「ハムレット」などシェークスピアの作品に登場する人物の名前が付けられている。"}],"452":[{"rank":"1","note":"教会の宗教画の地図","exp":"150","type":"美術品","name":"聖母戴冠（リッピ）","desc":"フラ・フィリッポ・リッピ作の祭壇画。彼はそれまでにない独特の色使いで、表情豊かな作品を生み出した。ボッティチェリやダ・ヴィンチなど、多くの画家に多大な影響を及ぼしたという。"}],"5839":[{"rank":"5","note":"","exp":"1410","type":"美術品","name":"クラダリング","desc":"アイルランドのクラダ村出身の若者が作った指輪。ハート、両手、王冠がデザインとして使われている。"}],"6558":[{"rank":"5","note":"","exp":"","type":"歴史遺物","name":"ヒュドラウリス","desc":"水圧を用いて空気を送り、音を奏でる水オルガン。紀元前2世紀ごろにアレクサンドリアの学者クテシビオスが製作したという。のちに弟子とされるヘロンらが改良し、地中海近辺に広まった。"}],"649":[{"rank":"1","note":"書きかけの地図","exp":"180","type":"地理","name":"パイン諸島","desc":"キューバの北の島々。東西に並んでいる。サンゴが美しい遠浅の海で年中暖かい。美しい白い砂浜は、サンゴの骨格が砕けたもののようだ。"}],"5264":[{"rank":"2","note":"「明るい星の観測記録」<br/>発見物カード:115","exp":"230","type":"天文","name":"リギル・ケンタウルス","desc":"ケンタウルス座にある1等星。ケンタウルス座の足にあたる位置にあり、星の名も「ケンタウロスの足」を意味する。"}],"5102":[{"rank":"1","note":"到達する","exp":"68","type":"港・集落","name":"ドゥアラ","desc":"大西洋のギニア湾に面する港町。広大な平地が広がるが、北西部には山岳地帯がそびえている。"}],"257":[{"rank":"3","note":"ヒッタイトの古文書","exp":"528","type":"歴史遺物","name":"ヒッタイト法典","desc":"ヒッタイト王国の法典である。200カ条から成り、粘土板二枚に楔（くさび）形文字で記される。"}],"1758":[{"rank":"3","note":"荒くれ騎士の列伝","exp":"600","type":"歴史遺物","name":"ゲクランの馬上槍","desc":"百年戦争初期に活躍したフランス軍人が使ったという槍。ゲクランは、ブルターニュ地方の城主の息子として生まれた。幼少期は戦争ごっこや馬上槍試合が好きな荒くれ者だったが、後に傭兵を用いた機動的な戦術でイングランド軍を翻弄した。"}],"1730":[{"rank":"5","note":"いまだ見ぬ青","exp":"804","type":"財宝","name":"ブルーフレイム","desc":"まばゆいばかりの見事な輝きを持つサファイヤ。大きさは1000カラット近くあり、並みの研磨技術ではこのような輝きは出せないという。吸い込まれるような美しいブルーで品質も最高クラスだ。"}],"1174":[{"rank":"5","note":"君に贈るレトラ<br/><br/>発見時経験値1170　発見物カード経験値585","exp":"1170","type":"財宝","name":"レスカトールの手記","desc":"「ミカエラ、僕は明日妹の元へ行く。僕はもう逃げないつもりだ。…ミカエラ。君ももう逃げないで。これからの君を彩るのはカリブの大地と翠玉色の海。もう僕のギターがなくても、君は一人で踊っていけるよ」手記はそこで終わっている。"}],"833":[{"rank":"1","note":"地の果ての岬","exp":"20","type":"地理","name":"ランズエンド岬","desc":"ブリテン島南西端の岬である。意味は英語で「地の果て」。細長い岬で対岸が見えないため、このように呼ばれるのだろう。"}],"3231":[{"rank":"5","note":"ヴァイキングの戦地","exp":"1210","type":"歴史遺物","name":"金銀の光弓","desc":"金や銀で彩られたきらびやかな大弓。見た目の美しさに反してかなり重く、操るには相当な筋力が必要。\nヴァイキングは海戦で弓を活用しており、弓の名手の存在が、戦いの勝敗を分けることもあったという。"}],"914":[{"rank":"2","note":"白と黒の縞模様","exp":"205","type":"中型生物","name":"ワオキツネザル","desc":"長い尾が白と黒のしま模様になっている。昼行性で、5～30頭の群れで集団生活をする。群れの全員が木の枝に集まって、ひなたぼっこや毛づくろいをしたりする。"}],"2319":[{"rank":"2","note":"［勅命］[[調査における水場の確保","exp":"340","type":"地理","name":"卑南渓","desc":"台湾島東部を流れる川の一つ。\n卑南とは、先住民である卑南民族の頭目を意味する。\n複雑に削られた川の地形が、中国の黄山に似ていることから「小黄山」とも呼ばれる。"}],"3787":[{"rank":"4","note":"視認","exp":"730","type":"天文","name":"レグルス","desc":"しし座で最も明るい1等星。名はラテン語で小さな王を意味する。古代の占星術では王や王家を象徴する星とされていた。コル・レオニスという別名がありこちらは獅子の心臓を意味する。"}],"7015":[{"rank":"3","note":"バミューダ諸島沖視認","exp":"","type":"天文","name":"カウス・アウストラリス","desc":"いて座で最も明るい2等星。ケンタウロスが構える弓の南側に位置し、「弓」を意味するアラビア語と「南」を意味するラテン語を組み合わせて名づけられた。"}],"5118":[{"rank":"2","note":"","exp":"290","type":"港・集落","name":"パナマ","desc":"北米と南米の境に位置する港街。「魚が豊富な場所」という意味の名のとおり、漁業が盛んである。街の周辺に広がる熱帯雨林には、様々な生物が生息している。"}],"587":[{"rank":"1","note":"豪華な宝石細工の地図","exp":"38","type":"財宝","name":"宝石をちりばめた小箱","desc":"色とりどりの宝石をちりばめた、美しい箱。高貴な婦人の宝石箱ではないだろうか。"}],"126":[{"rank":"1","note":"ギリシャ神話の成り立ち","exp":"55","type":"宗教遺物","name":"神統記","desc":"「しんとうき」。ヘシオドス著の、ギリシャ神話の系譜。カオスから世界の生成と神々の誕生、英雄たちの冒険譚を描く。これまでまとめられていなかったギリシャ神話をまとめたものである。"}],"5730":[{"rank":"1","note":"2017.02.07新規登録","exp":"","type":"化石","name":"サメの歯の石","desc":"サメの歯が固まったように見える石。魔除けや装身具として加工されることもある。"}],"1279":[{"rank":"2","note":"石集め","exp":"310","type":"歴史遺物","name":"土器製ローラー","desc":"土器でできた、紋様をつけるための道具。焼き物の紋様づけに使ったり、印としても用いられたようである。"}],"3544":[{"rank":"","note":"発見時経験値3340","exp":"3340","type":"レリック","name":"最後のローマ人","desc":"ホノリウス帝の命令で刑場の露と消えた勇将スティリコ。西ローマ帝国の滅亡はこの時に決定づけられたといえよう。"}],"6606":[{"rank":"5","note":"","exp":"1180","type":"歴史遺物","name":"トゥシュトラの小像","desc":"先古典期後期に製作され、アヒルのような嘴と翼を持つ卵形の怪人像。ラ・モハーラの遺跡で発見されたものと\n同じ文字が彫られている。胸から腹にかけて長期暦の日付が刻まれ\nていることでも知られる。"}],"6798":[{"rank":"3","note":"視認","exp":"","type":"天文","name":"スラファト","desc":"こと座に位置する３等星。名はアラビア語で亀を意味し、亀の\n甲羅に弦を張り、琴がつくられていたことに由来しているとい\nる。"}],"4789":[{"rank":"1","note":"悲恋の花","exp":"200","type":"植物","name":"オヒアレフア","desc":"ハワイ島で伝統的な儀式を行う際に身につけられるレイに使われる花。火山の女神によって引き裂かれた恋人たちが身を変えた花だとの伝説が残る。"}],"5660":[{"rank":"2","note":"","exp":"230","type":"小型生物","name":"スナネコ","desc":"サハラからアジア西南部にかけての砂漠に生息する小型の動物。体長は50cm程度。耳が大きく、その内側は砂が入り込むのを防ぐために毛で覆われている。"}],"1985":[{"rank":"2","note":"釣り","exp":"240","type":"海洋生物","name":"ジャウー","desc":"人食いナマズとも言われる、貪欲で巨大なナマズ。"}],"3870":[{"rank":"1","note":"沿岸のアザラシの地図","exp":"200","type":"中型生物","name":"ゼニガタアザラシ","desc":"太平洋、大西洋の北部に生息するアザラシ。体表に、中央がくり貫かれた円のような模様を持つ。岩場や岩礁で生活する。"}],"1128":[{"rank":"5","note":"瓶詰めの思い出<br/><br/>発見時経験値1014　発見物カード経験値507","exp":"1014","type":"財宝","name":"ガラスの香水瓶","desc":"装飾がふんだんに施された、豪華なガラス製の香水瓶。ふたには二羽の鷲の頭が彫られている。\n底には「いつか乗り越えるべき大きなもの。その剣は重く、その心はフランドルの土より広く優しい」とある。"}],"3757":[{"rank":"4","note":"天に輝くサソリ","exp":"650","type":"天文","name":"さそり座","desc":"黄道十二星座の1つ。女神ヘラの命で傲慢なオリオンを殺した、サソリが天に昇った姿とされる。天の川にS字を描き、アンタレスを始めとして明るい星が多く、見つけやすい星座である。"}],"1280":[{"rank":"2","note":"生きた伝説","exp":"330","type":"歴史遺物","name":"ナレースワン王の像","desc":"アユタヤ王朝21代目の王。幼少期はミャンマーで人質として育ったが、ミャンマーがアユタヤを掌握しナレースワンの父が形式的な王となると、ナレースワンの姉と引き換えに呼び戻された。その後アユタヤの軍隊を鍛え、独立へと尽力した。"}],"6453":[{"rank":"2","note":"ストックホルム港前。夜。たぶん冬（冬になった直後の夜に観測）<br/>発見物カード:130","exp":"260","type":"気象・現象","name":"ライトピラー","desc":"地面から空に向かって光の柱が伸びているように見える現象。寒い地域で、遠くにある地上の光が上空に漂う氷の結晶を含んだ薄い雲に反射することで柱のように見える。"}],"6214":[{"rank":"4","note":"サルベージ","exp":"700","type":"歴史遺物","name":"エンカルナシオン号","desc":"イスパニアの商船。新大陸へ物資を供給するために建造された。パナマのチャグレス川河口で嵐に遭い、沈没した。"}],"3967":[{"rank":"5","note":"発見物カード:410","exp":"820","type":"天文","name":"ミラ","desc":"約332日の周期で2等星から10等星まで明るさを変えるくじら座の恒星。名はラテン語で不思議なものを意味し、1779年には1等星まで明るくなった。"}],"6335":[{"rank":"5","note":"伝説の霊長に関する伝承","exp":"1020","type":"伝承","name":"鸞鳥","desc":"中国の伝説で語り継がれる霊鳥。読みは「らんちょう」。社会が安定すると現れるといわれている。五音の声を持ち、粘り気のある血液は弓や琴を作るための接着剤として最適だというが…。"}],"2380":[{"rank":"2","note":"小さなトンボ","exp":"240","type":"虫類","name":"オジロサナエ","desc":"日本の特産種である、小型で細身のトンボ。山地や丘陵地の渓流に生息する。\n雄の尾部の先が白いことから、この名が付いた。"}]};